        t[x].path_f := t[y].path_f;
    normalize(y);
    normalize(x);
end;
 
procedure splay(x,y:longint);
begin
    while t[x].f <> y do
    begin
        normalize(t[t[x].f].f);
        normalize(t[x].f);
        normalize(x);
        if t[t[x].f].f <> y then
            if dd(t[x].f) = dd(x) then rot(t[x].f) else rot(x);
        rot(x);
    end;
end;
 
procedure access(x:longint);
var
    y : longint;
begin
    splay(x,0); normalize(x);
        cc(x,1); normalize(x);
    while t[x].path_f > 0 do
    begin
        y := t[x].path_f; splay(y,0);
        normalize(y); cc(y,1);
        sc(x,y,1); normalize(y);
        x := y;
    end;
end;
 
procedure evert(x:longint);
begin
    access(x);
        splay(x,0);
        reverse(x);
end;
 
function exist(x,y:longint):boolean;
begin
    exist := false;
        evert(x);
        access(y);
        splay(x,0);
        normalize(x);
    while y > 0 do
    begin
        if y = x then exit(true);
        y := t[y].f;
    end;
end;
 
function get(x,y:longint):longint;
begin
    evert(x);
        access(y);
        splay(x,0);
        get := t[x].max;
end;
 
procedure cut(x,y:longint);
begin
    evert(y);
        access(x);
        splay(y,0);
    t[y].c[1] := 0; t[x].f := 0; t[x].path_f := 0; normalize(y);
end;
 
procedure link(x,y:longint);
begin
    evert(x);
        evert(y);
        splay(x,0);
        splay(y,0);
        normalize(x); sc(y,x,0); normalize(x);
end;
 
procedure sort(l,r:longint);
var
    i,j : longint; x : eType;
begin
    i := l; j := r; x := e[(l+r) >> 1];
    repeat
        while e[i].a < x.a do inc(i);
        while x.a < e[j].a do dec(j);
        if i <= j then
        begin
            e[0] := e[i]; e[i] := e[j]; e[j] := e[0];
            inc(i); dec(j);
        end;
    until i > j;
    if l < j then sort(l,j);
    if i < r then sort(i,r);
end;
 
procedure init;
