		int w;
		int rev,mx,mxn;
		int f,pf;
		int chr[2];
	}A[MAXN+MAXM];int AL=50000;
	void Push_Down(int p){
		int &lchr=A[p].chr[0];
		int &rchr=A[p].chr[1];
		if(A[p].rev){
			swap(lchr,rchr);
			A[p].rev=0;
			A[lchr].rev^=1;
			A[rchr].rev^=1;
		}
	}
	void Push_Up(int p){
		int &lchr=A[p].chr[0];
		int &rchr=A[p].chr[1];
		A[p].mx=A[p].w;
		A[p].mxn=p;
		int t=lchr;
		if(A[rchr].mx>A[t].mx)t=rchr;
		if(A[p].mx>A[t].mx)t=p;
		A[p].mx=A[t].mx;
		A[p].mxn=A[t].mxn;
		A[p].mxw1=max(A[lchr].mxw1,A[rchr].mxw1);
		A[p].mxw1=max(A[p].mxw1,A[p].w1);
	}
	void Rot(int p,int lr){
		int f=A[p].f;
		A[f].chr[!lr]=A[p].chr[lr];
		A[A[p].chr[lr]].f=f;
		A[A[f].f].chr[A[A[f].f].chr[1]==f]=p;
		A[p].f=A[f].f;
		A[f].f=p;
		A[p].chr[lr]=f;
		Push_Up(f);
		if(A[p].f==0)
			A[p].pf=A[f].pf;
	}
	void Splay(int p){
		vector<int> Stack;
		for(int i=p;i;i=A[i].f)
			Stack.push_back(i);
		for(int i=Stack.size()-1;~i;i--)
			Push_Down(Stack[i]);
		while(A[p].f){
			int f=A[p].f;
			if(!A[f].f)Rot(p,A[f].chr[0]==p);
			else{
				int lr=A[f].chr[1]==p;
				if(A[A[f].f].chr[lr]==f){
					Rot(f,!lr);
					Rot(p,!lr);
				}
				else{
					Rot(p,!lr);
					Rot(p,lr);
				}
			}
		}
		Push_Up(p);
	}
	void Expose(int p){
		Splay(p);
		int &rchr=A[p].chr[1];
		A[rchr].f=0;
		A[rchr].pf=p;
		rchr=0;
		Push_Up(p);
	}
	void Access(int p){
		Expose(p);
		while(A[p].pf){
			int pf=A[p].pf;
			Expose(pf);
			A[pf].chr[1]=p;
			A[p].f=pf;
			Splay(p);
		}
	}
	void Make_Root(int p){
		Access(p);
		A[p].rev=1;
	}
	int Get_Next(int p){
		Splay(p);
		p=A[p].chr[1];
		Push_Down(p);
		while(A[p].chr[0]){
			p=A[p].chr[0];
			Push_Down(p);
		}
		return p;
	}
	int Get_Root(int p){
		Access(p);
		while(A[p].chr[0]){
			p=A[p].chr[0];
			Push_Down(p);
		}
		return p;
	}
	void Cut(int p){
		Access(p);
		int &lchr=A[p].chr[0];
		A[lchr].f=A[lchr].pf=0;
		lchr=0;
		Push_Up(p);
	}
	int Get_Edge(int a,int b){
		Make_Root(a);
		Access(b);
		return A[b].mx;
	}
	int Cut_Mx(int a,int b){
		Make_Root(a);
		Access(b);
		int res=A[b].mx;
		int n=A[b].mxn;
		int nn=Get_Next(n);
		Cut(n);
		Cut(nn);
		return res;
	}
	void Link(int a,int b){
		Make_Root(a);
		A[a].pf=b;
	}
	void Add_Edge(int a,int b,int w1,int w){
		int p=++AL;
		A[p].w=A[p].mx=w;
		A[p].w1=A[p].mxw1=w1;
		A[p].mxn=p;
		Link(a,p);
		Link(p,b);
	}
	int Get(int a,int b){
		Make_Root(a);
		Access(b);
		return A[b].mx+A[b].mxw1;
	}
};

