bool cmp(node x,node y)
{
	return (x.a<y.a)||(x.a==y.a&&x.b<y.b);
}
int find(int x)
{
	if (Fa[x]==x) return x;
	Fa[x]=find(Fa[x]);
	return Fa[x];
}
inline int isroot(int x)
{
	return (son[fa[x]][0]!=x&&son[fa[x]][1]!=x);
}
inline void pushdown(int u)
{
	if (rev[u])
	{
		rev[u]^=1;
		int l=son[u][0],r=son[u][1];
		rev[l]^=1,rev[r]^=1;
		swap(son[u][0],son[u][1]);
	}
}
inline void update(int x)
{
	if (tree[son[x][0]]>tree[son[x][1]])
		tree[x]=tree[son[x][0]],Pos[x]=Pos[son[x][0]];
	else tree[x]=tree[son[x][1]],Pos[x]=Pos[son[x][1]];
	if (a[x]>tree[x]) tree[x]=a[x],Pos[x]=x;
}
inline void rotate(int x)
{
	int y=fa[x],z=fa[y];
	int l=(son[y][1]==x),r=l^1;
	if (!isroot(y))
		son[z][son[z][1]==y]=x;
	fa[son[x][r]]=y,fa[x]=z,fa[y]=x;
	son[y][l]=son[x][r],son[x][r]=y;
	update(y);
	update(x);
}
void splay(int x)
{
	int top=0;
	q[++top]=x;
	for (int i=x;!isroot(i);i=fa[i])
		q[++top]=fa[i];
	while (top) pushdown(q[top--]);
	while (!isroot(x))
	{
		int y=fa[x],z=fa[y];
		if (!isroot(y))
		{
			if ((son[y][0]==x)^(son[z][0]==y)) rotate(x);
			else rotate(y);
		}
		rotate(x);
	}
}
void access(int x)
{
	for (int t=0;x;t=x,x=fa[x])
	{
		splay(x);
		son[x][1]=t;
		update(x);
	}
}
void makeroot(int u)
{
	access(u);
	splay(u);
	rev[u]^=1;
}
void split(int u,int v)
{
	if(n==mo2) INF=0;
	makeroot(u);
	access(v);
	splay(v);
}
void link(int u,int v)
{
	makeroot(u);
	fa[u]=v;
}
void cut(int u,int v)
{
	makeroot(u);
	access(v);
	splay(v);
	son[v][0]=fa[u]=0;
	update(v);
}
