const LD eps = 1e-6;

struct Edge
{
	int to, next;
}E[N];
int head[N], ecnt = 1;
inline void AddEdge(int x, int y)
{
	E[++ecnt] = (Edge){y, head[x]};	head[x] = ecnt;
}
#define LINK(x)	for(int e = head[x]; e; e = E[e].next)

