int dep[N], size[N], nex[N];

inline void DFS1(int x)
{
	size[x] = 1;
	nex[x] = 0;
	LINK(x)
	{
		s[E[e].to] = s[x] + dis[E[e].to];
		dep[E[e].to] = dep[x] + 1;
		DFS1(E[e].to);
		size[x] += size[E[e].to];
		if(size[E[e].to] > size[nex[x]])
			nex[x] = E[e].to;
	}
}

int id = 0, belong[N], pos[N], seq[N];
int pcnt = 0, ptop[N], pdep[N];

inline void DFS2(int x)
{
	seq[++id] = x;	pos[x] = id;
	if(nex[x] == 0)
	{
		belong[x] = ++pcnt;
		return;
	}
	DFS2(nex[x]);
	belong[x] = belong[nex[x]];
	LINK(x)	if(E[e].to != nex[x])
	{
		DFS2(E[e].to);
		int t = belong[E[e].to];
		ptop[t] = E[e].to;
		pdep[t] = dep[E[e].to];
	}
}

typedef pair<LL, LL> PLL;
struct node
{
	int ll, rr;
	vector<PLL> root;
};
node t[N << 2];
#define lc(x) (x << 1)
#define rc(x) (x << 1 | 1)
inline void build(int x, int l, int r)
{
	t[x].ll = l, t[x].rr = r;
	t[x].root.clear();
	if(l == r)	return;
	int mid = (l + r) >> 1;
	build(lc(x), l, mid);
	build(rc(x), mid + 1, r);
}

LL f[N];

inline LD cross(PLL a, PLL b)
{
	return 1.0 * (a.second - b.second) / (b.first - a.first);
}

inline int sgn(LD x)
{
	if(x > eps)	return 1;
	if(x < -eps)	return -1;
	return 0;
}

inline void add(vector<PLL> &x, LL s, LL f)
{
	PLL p3 = MP(s, f);
	while(x.size() >= 2)
	{
		PLL p2 = x[x.size() - 1];
		PLL p1 = x[x.size() - 2];
		LD x1 = cross(p2, p3);
		LD x2 = cross(p1, p3);
		if(sgn(x1 - x2) == 1)	break;
		x.pop_back();
	}
	if(x.size() == 1 && f <= x[0].second)	x.pop_back();
	x.PB(p3);
}

inline void add(int x, int pos, LL s, LL f)
{
	add(t[x].root, s, f);
	if(t[x].ll == t[x].rr)	return;
	int mid = (t[x].ll + t[x].rr) >> 1;
	if(pos <= mid)	add(lc(x), pos, s, f);
	if(mid <  pos)	add(rc(x), pos, s, f);
}

LL curX;

LL get(vector<PLL> &x)
{
	int l = 0, r = x.size() - 1;
	while(r - l >= 4)
	{
		int mid = (l + r) >> 1;
		LD tmp = cross(x[mid - 1], x[mid]);
		if(sgn(tmp - curX) >= 0)
			r = mid;
		else
			l = mid;
	}
	LL ans = inf;
	for(int i = l; i <= r; i++)
	{
		PLL p = x[i];
		LL tmp = curX * p.first + p.second;
		if(tmp < ans)	ans = tmp;
	}
	return ans;
}

LL cal(int x, int l, int r, LL len)
{
	if(l <= t[x].ll && t[x].rr <= r)
	{
		int u = seq[t[x].ll];
		int v = seq[t[x].rr];
		if(s[v] - s[u] <= len)
			return get(t[x].root);

		LL ans = cal(rc(x), l, r, len);
		u = seq[t[lc(x)].rr];
		len -= (s[v] - s[u]);
		if(len < 0)
			return ans;
		LL tmp = cal(lc(x), l, r, len);
		if(tmp < ans)	ans = tmp;
		return ans;
	}
	int mid = (t[x].ll + t[x].rr) >> 1;
	if(r <= mid)
		return cal(lc(x), l, r, len);
	if(l > mid)
		return cal(rc(x), l, r, len);
	LL ans = cal(rc(x), l, r, len);
	int u = seq[t[lc(x)].rr];
	int v = seq[r];
	len -= s[v] - s[u];
	if(len < 0)
		return ans;
	LL tmp = cal(lc(x), l, r, len);
	if(tmp < ans)	ans = tmp;
	return ans;
}

LL cal(int x)
{
	curX = p[x];
	LL l = len[x];
	LL ans = inf;
	while(l >= 0)
	{
		LL tmp = cal(1, pos[ptop[belong[x]]], pos[x], l);
		ans = min(ans, tmp);
		if(fa[ptop[belong[x]]] == 0)	break;
		l -= s[x] - s[fa[ptop[belong[x]]]];
		x = fa[ptop[belong[x]]];
	}
	return ans;
}

