db Slide(pll p1, pll p2)
{
	return 1.0 * (p2.second - p1.second) / (p2.first - p1.first);
}
void Vec_Add(int o, ll k, ll b)
{
	pll p3 = mkP(k, b);
	while (root[o].size() >= 2)
	{
		pll p1 = root[o][root[o].size() - 1];
		pll p2 = root[o][root[o].size() - 2];
		db s1 = Slide(p1, p3), s2 = Slide(p2, p3);
		if (s1 - s2 < -eps) break;
		root[o].pop_back();
	}
	if (root[o].size() == 1 && b <= root[o][0].second) root[o].pop_back();
	root[o].push_back(p3);
