ll Vec_Query(vector<pll> x)
{
	int l = 0, r = x.size() - 1;
	/*
	while (r - l > 4)
	{
		int mid = (l + r) >> 1;
		double sl = Slide(x[mid - 1], x[mid]);
		if (sl < qx - eps) r = mid;
		else l = mid;
	}
	*/
	ll Tmp = Inf;
	For (i, l, r) cmin(Tmp, qx * x[i].first + x[i].second);
	return Tmp;
}

#define Ls (o << 1)
#define Rs (Ls | 1)
void Seg_Add(int o, int l, int r, int pos, ll k, ll b)
{
//	printf("Add %d %d %d %d %lld %lld\n", o, l, r, pos, k, b);
	Vec_Add(o, k, b);
	if (l == r) return;
	int Mid = (l + r) >> 1;
	if (pos <= Mid) Seg_Add(Ls, l, Mid, pos, k, b);
	else Seg_Add(Rs, Mid + 1, r, pos, k, b);
}

ll Seg_Query(int o, int l, int r, int ql, int qr, ll len)
{
	if (ql <= l && r <= qr && Dep[Pos[qr]] - Dep[Pos[r]] > len) return Inf;
	if (ql <= l && r <= qr && Dep[Pos[qr]] - Dep[Pos[l]] <= len) { /*printf("%d %d %d %d %d\n", o, ql, qr, l, r);*/ return Vec_Query(root[o]); }
	int Mid = (l + r) >> 1; ll Tmp = Inf;
	if (ql <= Mid) cmin(Tmp, Seg_Query(Ls, l, Mid, ql, qr, len));
	if (Mid < qr) cmin(Tmp, Seg_Query(Rs, Mid + 1, r, ql, qr, len));
	return Tmp;
}

ll Calc(int x)
{
	qx = p[x];
	int tmpx = x;
	ll Ans = Inf;
	while (l[x] >= 0 && tmpx)
	{
		cmin(Ans, Seg_Query(1, 1, N, Dfn[Top[tmpx]], Dfn[tmpx], l[x]));
		if (Top[tmpx] == 0) break;
		l[x] -= (Dep[tmpx] - Dep[fa[Top[tmpx]]]);
		tmpx = fa[Top[tmpx]];
	}
	return Ans;
}

