const ll INF = 1LL << 60;
const int maxn = 200010;
int n, m, t, son, mn, an, bn, fa[maxn], sz[maxn], a[maxn], b[maxn], que[maxn];
ll dp[maxn], dist[maxn], p[maxn], q[maxn], lim[maxn];
bool vis[maxn];
double st[maxn];
vector<int> G[maxn];

bool comp(int a, int b) { return dist[a] - lim[a] > dist[b] - lim[b]; }
double slope(int a, int b) { return 1.0 * (dp[a] - dp[b]) / (dist[a] - dist[b]); }

void center(int v) {
    sz[v] = 1;
    for (int i = 0; i < G[v].size(); i++) {
        if (vis[G[v][i]]) continue;
        center(G[v][i]), sz[v] += sz[G[v][i]];
    }
    if (mn > max(sz[v], m - sz[v])) {
        son = v, mn = max(sz[v], m - sz[v]);
    }
}

void dfs(int v) {
    b[++bn] = v;
    for (int i = 0; i < G[v].size(); i++) {
        if (vis[G[v][i]]) continue;
        dfs(G[v][i]);
    }
}

void solve(int g) {
    if (m <= 1) return;
    son = g, mn = m, center(g);
    int rt = fa[son];
    for (int i = 0; i < G[rt].size(); i++) {
        vis[G[rt][i]] = 1, m -= sz[G[rt][i]];
    }
    solve(g);
    bn = 0, a[an = 1] = rt;
    for (int i = rt; i != g; a[++an] = i) i = fa[i];
    for (int i = 0; i < G[rt].size(); i++) dfs(G[rt][i]);
    sort(b + 1, b + bn + 1, comp);
    int l = 1, r = 0;
    while (l <= bn && dist[b[l]] - lim[b[l]] > dist[rt]) l++;
    for (int i = 1; i <= an; i++) {
        while (r > 1 && slope(a[i], q[r]) > st[r]) r--;
        q[++r] = a[i], st[r] = r == 1 ? -INF : slope(a[i], q[r - 1]);
        while (l <= bn && (i == an || dist[b[l]] - lim[b[l]] > dist[a[i + 1]])) {
            int lb = 1, rb = r, v = b[l];
            while (lb < rb) {
                int mid = (lb + rb + 1) >> 1;
                if (p[v] < st[mid]) {
                    lb = mid;
                } else {
                    rb = mid - 1;
                }
            }
            dp[v] = min(dp[v], dp[q[lb]] + p[v] * (dist[v] - dist[q[lb]]) + q[v]);
            l++;
        }
    }
    for (int i = 0; i < G[rt].size(); i++) {
        m = sz[G[rt][i]], solve(G[rt][i]);
    }
}

int main() {
    scanf("%d %d", &n, &t), m = n;
    for (int i = 2; i <= n; i++) {
        scanf("%d %lld %lld %lld %lld", &fa[i], &dist[i], &p[i], &q[i], &lim[i]);
        G[fa[i]].push_back(i), dist[i] += dist[fa[i]], dp[i] = INF;
    }
    solve(1);
    for (int i = 2; i <= n; i++) {
        printf("%lld\n", dp[i]);
    }
    return 0;
}

