struct Point {
	ll x, y;
	ll calc(ll k) const {return y - k * x;}
	ll operator-(Point p) const {return (y-p.y)/(x-p.x);}
};	// k > (Q - P) <=> P.calc(k) > Q.calc(k)
struct dat {Point p; ll k;} pool[3800064], *pt = pool;
struct Hull {
	dat *h, *t;
	void init(int n) {h = t = pt; pt += n;}
	void set(Point p) {*h = (dat){p,-1};}
	void push(Point p) {
		ll k = -1;
		while (h <= t && (k = p - t->p) <= t->k) --t;
		*++t = (dat){p,k};
	}
	void merge(Hull L, Hull R) {
		dat *i = L.h; t = h; *h = *i;
		while (i != L.t) push((++i)->p);
		i = R.h; push(i->p);
		while (i != R.t) push((++i)->p);
	}
	ll query(ll k) {
		return (lower_bound(h+1, t+1, k,
			[](dat a, ll k){return a.k < k;})-1)->p.calc(k);
	}
} tr[462200];

const int N = 200064;
int P[N], M;
ll S[N], Q[N], L[N], D[N], F[N];
vector<int> ch[N];

void dfs(int x, int i, ll d) {
	D[i] = d;
	ll f;
	if (i) {
		f = 1ll<<60;
		int k = P[x];
		for (int l = M-1 + int(lower_bound(D, D+i-1, d-L[x])-D),
				r = M+i; l^r^1; l >>= 1, r >>= 1) {
			if (~l&1) Min(f, tr[l^1].query(k));
			if ( r&1) Min(f, tr[r^1].query(k));
		}
		F[x] = f += Q[x] + d * k;
	} else f = 0;
	tr[M+i].set((Point){d,f});
	for (int r = M+i; (r&1) && (r>>=1);)
		tr[r].merge(tr[r<<1], tr[r<<1|1]);
	for (int y : ch[x])
		dfs(y, i + 1, d + S[y]);
}

int main() {
	int n = gunt(); nword();
	int m = 32-__builtin_clz(n);
	M = 1<<m;
	for (int i = 0; i < n; i++) tr[M+i].init(1);
	for (int t = m; t--;)
		for (int T = 1<<t, i = 0; i < T; i++)
			tr[T+i].init(min(max(n - (i<<m-t), 0), 1<<m-t));
	for (int i = 2; i <= n; i++) {
		ch[gunt()].push_back(i);
		S[i] = gllu(); P[i] = gunt();
		Q[i] = gllu(); L[i] = gllu();
	}
	dfs(1, 0, 0);
	for (int i = 2; i <= n; i++) pllu(F[i]);
	fwrite(oBuf,1,oP-oBuf,stdout);
	return 0;
}

#include <iostream>
