using namespace std;

typedef long long ll;

const ll INF = 3.9e17;

vector<bool> vis;
int n, type, tsiz, rt;
vector<vector<int> > g;
vector<ll> dis, p, q, k, f;
vector<int> siz, wt, dep, pa;

void getroot(int u, int fa)
{
	siz[u] = wt[u] = 1;
	for (int i = 0; i < g[u].size(); ++i)
	{
		int v = g[u][i];
		if (v == fa || vis[v]) continue;
		getroot(v, u);
		siz[u] += siz[v];
		wt[u] = max(wt[u], siz[v]);
	}
	wt[u] = max(wt[u], tsiz - siz[u]);
	if (!rt || wt[u] < wt[rt]) rt = u;
}

void getchildren(int u, vector<int>& children)
{
	for (int i = 0; i < g[u].size(); ++i)
	{
		int v = g[u][i];
		if (v == pa[u] || vis[v]) continue;
		children.push_back(v);
		getchildren(v, children);
	}
}

bool cmp(int x, int y)
{
	return dis[x] - k[x] > dis[y] - k[y];
}

bool check(int x, int y, int z)
{
	return (__int128) (f[x] - f[y]) * (dis[y] - dis[z]) < (__int128) (f[y] - f[z]) * (dis[x] - dis[y]);
}

ll calc(int i, int j)
{
	return f[j] + p[i] * (dis[i] - dis[j]) + q[i];
}

void solve(int u)
{
	vis[u] = true;
	vector<int> anc(1, u);
	while (pa[anc.back()] && !vis[pa[anc.back()]]) anc.push_back(pa[anc.back()]);
	if (anc.size() > 1)
	{
		rt = 0;
		tsiz = siz[pa[u]];
		getroot(pa[u], u);
		solve(rt);
		for (int i = 1; i < anc.size() && dis[anc[i]] >= dis[u] - k[u]; ++i) f[u] = min(f[u], calc(u, anc[i]));
	}
	vector<int> children;
	getchildren(u, children);
	sort(children.begin(), children.end(), cmp);
	vector<int> convex;
	int t = 0;
	for (int i = 0; i < children.size(); ++i)
	{
		int v = children[i];
		while (t < anc.size() && dis[anc[t]] >= dis[v] - k[v])
		{
			while (convex.size() >= 2 && check(convex[convex.size() - 2], convex.back(), anc[t])) convex.pop_back();
			convex.push_back(anc[t++]);
		}
		if (convex.empty()) continue;
		int l = 0, r = convex.size() - 1;
		while (l < r)
		{
			int mid = (l + r + 1) >> 1;
			if (mid && calc(v, convex[mid - 1]) < calc(v, convex[mid])) r = mid - 1;
			else l = mid;
		}
		f[v] = min(f[v], calc(v, convex[l]));
	}
	for (int i = 0; i < children.size(); ++i)
	{
		int v = children[i];
		if (v == pa[u] || vis[v]) continue;
		rt = 0;
		tsiz = siz[v];
		getroot(v, u);
		solve(v);
	}
}

int main()
{
	scanf("%d%d", &n, &type);
	
	vis.resize(n + 1, false);
	f.resize(n + 1, INF);
	dis.resize(n + 1, 0);
	dep.resize(n + 1, 0);
	siz.resize(n + 1, 0);
	wt.resize(n + 1, 0);
	pa.resize(n + 1, 0);
	g.resize(n + 1);
	p.resize(n + 1);
	q.resize(n + 1);
	k.resize(n + 1);
	
	for (int i = 2; i <= n; ++i)
	{
		scanf("%d%lld%lld%lld%lld", &pa[i], &dis[i], &p[i], &q[i], &k[i]);
		g[pa[i]].push_back(i);
		g[i].push_back(pa[i]);
		dis[i] += dis[pa[i]];
	}
	
	f[1] = 0;
	tsiz = n;
	getroot(1, 0);
	solve(rt);
	
	for (int i = 2; i <= n; ++i) printf("%lld\n", f[i]);
	
	return 0;
}

