__gnu_pbds::priority_queue<node2,less<node2>,__gnu_pbds::pairing_heap_tag>q;
ll calc()
{
	int i;
	ll j;
	node2 temp;
	for(i=1,j=0;i<=n;i++)
	{
		while(!q.empty()&&j<a[i].t)
		{
			temp=q.top(),q.pop();
			j+=temp.s;
			if(j<=a[i].t)
			{
				sum[temp.no].len+=max(min(j,m)-max(j-temp.s,(ll)a[x].t),0ll);
				ans[temp.no]=j;
			}
			else
			{
				q.push(node2(j-a[i].t,temp.p,temp.no));
				sum[temp.no].len+=max(min((ll)a[i].t,m)-max(j-temp.s,(ll)a[x].t),0ll);
				j=a[i].t;
			}
		}
		q.push(node2(a[i].s,a[i].p,a[i].no));
		j=a[i].t;
	}
	while(!q.empty())
	{
		temp=q.top(),q.pop();
		j+=temp.s;
		sum[temp.no].len+=max(min(j,m)-max(j-temp.s,(ll)a[x].t),0ll);
		ans[temp.no]=j;
	}
	return ans[a[x].no];
}
