struct pts10{
	int tree[M],rec[M]; ll dis[M];
	bool chain(){
		int rt,lf;
		for(int i=1;i<=n;++i)if(deg[i]==1){rt=i;break;}
		for(int i=n;i;--i)if(deg[i]==1){lf=i;break;}
		for(int i=rt+1;i<lf;++i)if(deg[i]==1)return false;
		int tot=0,u=rt,pre=0; ll dist=0;
		tree[rec[u]=++tot]=u,dis[tot]=dist;
		while(u!=lf){
			for(int j=head[u],v;j;j=E[j].nxt)
				if(v=E[j].v,v!=pre){pre=u,u=v,dist+=E[j].w;break;}
			tree[rec[u]=++tot]=u,dis[tot]=dist;
		}return true;
	}
	int sum[M];
	void solve(){
		ll mi,mx;
		for(int i=1;i<=n;++i)if(isbac[tree[i]]){mi=i;break;}
		for(int i=n;i;--i)if(isbac[tree[i]]){mx=i;break;}
		for(int i=1,u;i<=n;++i)
			if(u=tree[i],isbac[u]){
				if(dis[i]-dis[mi]>dis[mx]-dis[i])sum[mi]++,sum[i]--;
				else if(dis[i]-dis[mi]<dis[mx]-dis[i])sum[i]++,sum[mx]--;
			}
		int ans=0,cnt=0;
		for(int i=1,u;i<=n;++i){
			sum[i]+=sum[i-1];
			u=tree[i];
			if(!isbac[u]){
				if(sum[i]>ans){ans=sum[i];cnt=0;}
				if(sum[i]==ans)++cnt;
			}
		}
		pfn(ans,0),pfn(cnt);
	}
}p10;

struct pts60{
	ll maxdist; int maxsum,sum[M];
	void init(int u,int pre,ll dist){
		if(isbac[u]){
			if(dist>maxdist){maxdist=dist;maxsum=0;}
			if(dist==maxdist)maxsum++;
		}
		for(int j=head[u],v;j;j=E[j].nxt)
			if(v=E[j].v,v!=pre)init(v,u,dist+E[j].w);
	}
	int dfs(int u,int pre,ll dist){
