		for(int j=head[u],v;j;j=E[j].nxt)
			if(v=E[j].v,v!=pre)cnt+=dfs(v,u,dist+E[j].w);
		if(isbac[u]&&dist==maxdist)++cnt;
		else if(!isbac[u]&&cnt==maxsum)++sum[u];
