struct pts100{
	int fa[M],dis[M];
	void dfs_extract(int u,int pre,int dist,int &upd){
		if(isbac[u]&&dist>dis[upd])upd=u;
		dis[u]=dist,fa[u]=pre;
		for(int j=head[u],v;j;j=E[j].nxt)
			if(v=E[j].v,v!=pre)dfs_extract(v,u,dist+E[j].w,upd);
	}
	int extract_middle_node(){
		int root=bac[1],leaf;
		dfs_extract(bac[1],0,0,root);
		leaf=root,dfs_extract(root,0,0,leaf);
		int u=root,diameter=dis[leaf];
		for(;leaf!=root;leaf=fa[leaf])
			if(max(dis[leaf],diameter-dis[leaf])<max(dis[u],diameter-dis[u]))u=leaf;
		return u;
	}
	struct Node{
		int u,mxdis;
		bool operator < (const Node &p)const {
			return mxdis>p.mxdis;
		}
	}s[M];
	int tot,cnt_black[M],cnt_mxdis_black[M],grand[M];
	void init(int u,int pre,int dist){
		fa[u]=pre,dis[u]=dist;
		for(int j=head[u],v;j;j=E[j].nxt)
			if(v=E[j].v,v!=pre)init(v,u,dist+E[j].w);
	}
	void dfs_sizecount(int u,int pre,int &mxd){
		if(isbac[u]&&dis[u]>mxd)mxd=dis[u];
		cnt_black[u]=isbac[u];
		for(int j=head[u],v;j;j=E[j].nxt)
			if(v=E[j].v,v!=pre){
				dfs_sizecount(v,u,mxd);
				cnt_black[u]+=cnt_black[v];
			}
	}
	void dfs_mxdiscount(int u,int pre,int mxdis){
		cnt_mxdis_black[u]=isbac[u]&&dis[u]==mxdis;
		for(int j=head[u],v;j;j=E[j].nxt)
			if(v=E[j].v,v!=pre){
				dfs_mxdiscount(v,u,mxdis);
				cnt_mxdis_black[u]+=cnt_mxdis_black[v];
			}
	}
	void dfs_grandorder(int u,int pre,int id){
		grand[u]=id;
		for(int j=head[u],v;j;j=E[j].nxt)
			if(v=E[j].v,v!=pre)dfs_grandorder(v,u,id);
	}
	int contribution[M];
	void solve(){
		int root=extract_middle_node();
//		printf("root=%d\n",root); //
		init(root,0,0);
		tot=0;
		cnt_black[root]=isbac[root];
		for(int j=head[root];j;j=E[j].nxt){ //还需要知道每个白点在哪棵子树内 
			s[++tot].u=E[j].v;
			dfs_sizecount(s[tot].u,root,s[tot].mxdis=0);
			cnt_black[root]+=cnt_black[s[tot].u];
			dfs_mxdiscount(s[tot].u,root,s[tot].mxdis);
//			printf("son=%d,mxdis=%d,cnt_black=%d,cnt_mxdis_black=%d\n",
//			s[tot].u,s[tot].mxdis,cnt_black[s[tot].u],cnt_mxdis_black[s[tot].u]); //
		}
		sort(s+1,s+tot+1);
		grand[root]=0;
		for(int i=1;i<=tot;++i)dfs_grandorder(s[i].u,root,i);
		if(tot==2){
			contribution[1]+=cnt_black[s[2].u];
			contribution[2]+=cnt_black[s[1].u];
		}else if(tot>=3){
			for(int i=1;i<=tot;++i){
				int id1,id2;
				if(i==1)id1=2,id2=3;
				else if(i==2)id1=1,id2=3;
				else if(i>=3)id1=1,id2=2;
				if(s[id1].mxdis!=s[id2].mxdis)
					contribution[id1]+=cnt_black[s[i].u];
			}
			// 还缺了一个根节点的贡献
			if(isbac[root]){
				int id1=1,id2=2;
				if(s[id1].mxdis!=s[id2].mxdis)++contribution[id1];
			}
		}
		int ans=0,cnt=0;
		for(int u=1;u<=n;++u)
			if(!isbac[u]){
				int sum=cnt_black[u];
				if(cnt_mxdis_black[u]==cnt_mxdis_black[s[grand[u]].u])
					sum+=contribution[grand[u]];
				if(sum>ans){ans=sum,cnt=0;}
				if(sum==ans)++cnt;
			}
		pfn(ans,0),pfn(cnt);
	}
}p100;

