#include <bits/stdc++.h>
using namespace std;
const int max_n = 1e5 + 5;
struct Edge {
    int to, val, next;
} e[max_n << 1];
int head[max_n], cnt;
void addedge(int u, int v, int w) {
    e[cnt].to = v;
    e[cnt].val = w;
    e[cnt].next = head[u];
    head[u] = cnt++;
}
// f - number of black points, g[0] max black point dis, g[1] number of max dis
int f[max_n], g[max_n][2];
bool black[max_n];
void init(int n) {
    for (int i = 0; i <= n; i++) {
        head[i] = -1;
        black[i] = 0;
        f[i] = 0;
        g[i][0] = g[i][1] = 0;
    }
    cnt = 0;
}
int pa[max_n], d[max_n], D, id;
void dfs1(int u, int fa, int dis) {
    pa[u] = fa;
    d[u] = dis;
    if (black[u] && d[u] > D) {
        D = d[u];
        id = u;
    }
    for (int i = head[u]; i != -1; i = e[i].next) {
        int v = e[i].to, w = e[i].val;
        if (v != fa) dfs1(v, u, dis + w);
    }
}
void dfs2(int u, int fa, int dis) {
    if (black[u]) {
        f[u]++;
        if (dis > g[u][0]) {
            g[u][0] = dis;
            g[u][1] = 1;
        } else if (dis == g[u][0]) g[u][1]++;
    }
    for (int i = head[u]; i != -1; i = e[i].next) {
        int v = e[i].to, w = e[i].val;
        if (v != fa) {
            if (fa == -1) pa[v] = v;
            else pa[v] = pa[u];
            dfs2(v, u, dis + w);
            f[u] += f[v];
            if (g[v][0] > g[u][0]) {
                g[u][0] = g[v][0];
                g[u][1] = g[v][1];
            } else if (g[v][0] == g[u][0]) g[u][1] += g[v][1];
        }
    }
}
int main() {
    int n, m;
    scanf("%d%d", &n, &m);
    init(n);
    for (int i = 1; i <= m; i++) {
        int j;
        scanf("%d", &j);
        black[j] = 1;
    }
    for (int i = 1; i < n; i++) {
        int u, v, w;
        scanf("%d%d%d", &u, &v, &w);
        addedge(u, v, w);
        addedge(v, u, w);
    }
    D = 0;
    dfs1(1, -1, 0);
    int rt = id;
    D = 0;
    dfs1(rt, -1, 0);
    vector<int> v;
    while (id != -1) {
        v.push_back(id);
        id = pa[id];
    }
    int mx = 0;
    for (int i: v) {
        int tmp = min(d[i], D - d[i]);
        if (tmp > mx) {
            mx = tmp;
            rt = i;
        }
    }
    pa[rt] = -1;
    dfs2(rt, -1, 0);
    int mxdis[2] = {-1, -1}, mxcnt[2] = {0, 0}, sum = 0;
    for (int i = head[rt]; i != -1; i = e[i].next) {
        int u = e[i].to;
        if (g[u][0] > mxdis[0]) {
            if (mxdis[0] != -1) {
                mxdis[1] = mxdis[0];
                mxcnt[1] = mxcnt[0];
            }
            sum = f[u];
            mxdis[0] = g[u][0];
            mxcnt[0] = 1;
        } else if (g[u][0] == mxdis[0]) {
            mxcnt[0]++;
            sum += f[u];
        } else if (g[u][0] > mxdis[1]) {
            mxdis[1] = g[u][0];
            mxcnt[1] = 1;
        } else if (g[u][0] == mxdis[1]) mxcnt[1]++;
    }
    int ans[2] = {-1, -1};
    for (int i = 1; i <= n; i++) {
        if (black[i]) continue;
        int tot = f[i];
        if (i != rt && g[i][0] == g[pa[i]][0] && g[i][1] == g[pa[i]][1]) {
            if (g[i][0] == mxdis[0]) {
                if (mxcnt[0] == 1) tot += m - f[pa[i]];
                else if (mxcnt[0] == 2) tot += sum - f[pa[i]];
            }
            if (mxdis[1] != -1 && g[i][0] == mxdis[1] && mxcnt[1] == 1 && mxcnt[0] == 1) tot += sum;
        }
        if (tot > ans[0]) {
            ans[0] = tot;
            ans[1] = 1;
        } else if (tot == ans[0]) ans[1]++;
    }
    printf("%d %d\n", ans[0], ans[1]);
    return 0;
}

