/*******************************************************************************
 *
 * 找到最长链的交集
 *
 ******************************************************************************/

int n, m;

struct EDGE {
    int to, nex, cost;
} edge[N << 1];
int head[N], cntedge, In[N];
void Addedge(int u, int v, int w) {
    edge[++cntedge] = (EDGE) { v, head[u], w };
    head[u] = cntedge, ++In[v];
}

struct FenwickTree {
    int c[N];
    void Init() { memset(c, 0, sizeof c); }
    void Add(int x) { for ( ; x <= n; x += x & -x) c[x] += 1; }
    int Que(int x) {
        int res = 0; for ( ; x > 0; x -= x & -x) res += c[x]; return res;
    }
} Bit;

int Mxw, root;
int Valid[N], Mx[N], mx[N], CntNode[N];
int mark[N], used[N], Wei[2][N], Wie[2][N];
// 最远的距离，根
// 用来跑的结点，当前树上的父亲
// 子树内修道院数量，子树内最远距离，子树内可作为目的地的链的数量
// 标记的数量，是否是修道院，贡献
// 在以某个端点做根的情况下
// 满足肯定是交集的条件：1.父亲是交集 2.子树内只有一棵树有端点

void BuiltTree(int u, int fa) {
    // 第一遍，处理无用点以及树内最远距离
    for (int i = head[u], v; i; i = edge[i].nex) {
        v = edge[i].to;
        if (v == fa) continue;
        BuiltTree(v, u);
        Valid[u] += Valid[v];
        if (Valid[v]) Mx[u] = max(Mx[u], Mx[v] + edge[i].cost);
        else --In[u];
    }
}
void BuiltNewTree(int u, int fa, int w) {
    // 找到新树的直径
    Mx[u] = mx[u] = 0;
    for (int i = head[u], v; i; i = edge[i].nex) {
        v = edge[i].to;
        if (v == fa || !Valid[v]) continue;
        BuiltNewTree(v, u, w + edge[i].cost);
        int tmp = Mx[v] + edge[i].cost;
        if (tmp > Mx[u]) mx[u] = Mx[u], Mx[u] = tmp;
        else if (tmp > mx[u]) mx[u] = tmp;
    }
    if (w > Mxw) root = u, Mxw = w;
}
void GetIntersection(int u, int fa) {
    ++mark[u];
    CntNode[u] = 0;
    for (int i = head[u], v; i; i = edge[i].nex) {
        v = edge[i].to;
        if (v == fa || !Valid[v]) continue;
        if (Mx[u] == Mx[v] + edge[i].cost) ++CntNode[u];
    }
    if (CntNode[u] != 1) return ;
    for (int i = head[u], v; i; i = edge[i].nex) {
        v = edge[i].to;
        if (v == fa || !Valid[v]) continue;
        if (Mx[u] == Mx[v] + edge[i].cost) GetIntersection(v, u);
    }
}
void CalcSonTree(int u, int fa, int w, int opt, int isDia) {
    // 统计树内必须经过自己的点
    for (int i = head[u], v; i; i = edge[i].nex) {
        v = edge[i].to;
        if (v == fa || !Valid[v]) continue;
        if (Mx[v] + edge[i].cost == Mx[u] && isDia)
            CalcSonTree(v, u, w + edge[i].cost, opt, isDia);
        else CalcSonTree(v, u, w, opt, 0);
        Wei[opt][u] += Wie[opt][v];
        if (!isDia) Wie[opt][u] += Wie[opt][v];
        else {
            if (Mx[u] == Mx[v] + edge[i].cost && w > mx[u])
                Wie[opt][u] += Wie[opt][v];
            if (Mx[u] != Mx[v] + edge[i].cost && w > Mx[u])
                Wie[opt][u] += Wie[opt][v];
        }
    }
    if (used[u] && w > Mxw - w) ++Wei[opt][u], ++Wie[opt][u];
    else if (used[u] && opt && w == Mxw - w) {
        ++Wei[opt][u];
        if (!isDia) ++Wie[opt][u];
    }
    // cout << u << " " << fa << " " << w << " " << Wei[opt][u] << " " << Mx[u] << endl;
}

int main() {
    n = read<int>(), m = read<int>();
    rep (i, 1, m) {
        root = read<int>();
        used[root] = Valid[root] = 1;
    }
    rep (i, 2, n) {
        int x = read<int>(), y = read<int>(), z = read<int>();
        Addedge(x, y, z);
        Addedge(y, x, z);
    }

    int rt = root;
    BuiltTree(rt, 0);
    BuiltNewTree(rt, 0, 0);
    Mxw = 0, rt = root;
    // cout << rt << endl;
    BuiltNewTree(rt, 0, 0);
    GetIntersection(rt, 0);
    CalcSonTree(rt, 0, 0, 0, 1);
    Mxw = 0, rt = root;
    // cout << rt << endl;
    BuiltNewTree(rt, 0, 0);
    GetIntersection(rt, 0);
    CalcSonTree(rt, 0, 0, 1, 1);

    int Ans1 = 0, Ans2 = 0;
    rep (i, 1, n) if (mark[i] == 2 && !used[i]) {
        if (Ans1 < Wei[0][i] + Wei[1][i]) {
            Ans1 = Wei[0][i] + Wei[1][i];
            Ans2 = 1;
        } else if (!used[i] && Ans1 == Wei[0][i] + Wei[1][i])
            ++Ans2;
    }
    if (Ans1 == 0) {
        rep (i, 1, n) if (!used[i] && Ans1 < max(Wei[0][i], Wei[1][i])) {
            Ans1 = max(Wei[0][i], Wei[1][i]);
            Ans2 = 1;
        } else if (!used[i] && Ans1 == max(Wei[0][i], Wei[1][i]))
            ++Ans2;
        if (Ans1 == 0) Ans2 = n - m;
    }

    cout << Ans1 << " " << Ans2 << endl;
    return 0;
}

