struct node{int x,y,z,c;bool in;}v[N],e[N],mx[N];
bool operator < (node a,node b){return a.c<b.c;}
int n,m,cnt;
bool rev[N];
int tr[N][2],fa[N];
void pushup(int u)
{
	mx[u]=max(mx[tr[u][0]],mx[tr[u][1]]);
	mx[u]=max(mx[u],v[u]);
}
void pushdown(int u)
{
	if(rev[u])
	{
		rev[tr[u][0]]^=1,rev[tr[u][1]]^=1,rev[u]^=1;
		swap(tr[u][0],tr[u][1]);
	}
}
bool isroot(int x){return tr[fa[x]][0]!=x&&tr[fa[x]][1]!=x;}
void rotate(int x)
{
	int y=fa[x],z=fa[y];
	int l=tr[y][1]==x,r=l^1;
	if(!isroot(y))tr[z][tr[z][1]==y]=x;
	fa[x]=z,fa[y]=x,fa[tr[x][r]]=y;
	tr[y][l]=tr[x][r],tr[x][r]=y;	
	pushup(y),pushup(x);
}
int st[N],top;
void splay(int x)
{
	top=0;st[++top]=x;
	for(int i=x;!isroot(i);i=fa[i])st[++top]=fa[i];
	while(top)pushdown(st[top--]);
	while(!isroot(x))
	{
		int y=fa[x],z=fa[y];
		if(!isroot(y))
		{
			if(tr[y][0]==x^tr[z][0]==y)
				rotate(x);
			else rotate(y);
		}rotate(x);
	}
}
void access(int x)
{
	int t=0;
	while(x)
	{
		splay(x),
		tr[x][1]=t,
		pushup(x);
		t=x,x=fa[x];
	}
}
void rever(int x){access(x),splay(x);rev[x]^=1;}
void link(int x,int y){rever(x);fa[x]=y;}
void cut(int x,int y){rever(x);access(y),splay(y);tr[y][0]=fa[x]=0;pushup(y);}
int find(int x)
{
	access(x),splay(x);
	while(tr[x][0])x=tr[x][0];
	return x;
}
node query(int x,int y)
{
	rever(x);access(y),splay(y);return mx[y];
}
