int gi(){
    char ch=getchar(); int x=0,q=0;
    while(ch<'0'||ch>'9') q=ch=='-'?1:q,ch=getchar();
    while(ch>='0'&&ch<='9') x=x*10+ch-'0',ch=getchar();
    return q?-x:x;
}
struct data{
    int op,a,b;
}q[N],st[N];
int tot,c[N][2],fa[N],rev[N],p[N],w[N],top;
ll ans;
char s[10];
#define isroot(x) (c[fa[x]][0]!=x&&c[fa[x]][1]!=x)
void pushd(int x){
    rev[x]^=1,rev[c[x][0]]^=1,rev[c[x][1]]^=1;
    swap(c[x][0],c[x][1]);
    return;
}
void rotate(int x){
    int y=fa[x],z=fa[y],l,r;
    if (c[y][0]==x) l=0;
    else l=1; r=l^1;
    if (!isroot(y))
	c[z][c[z][1]==y]=x;
    fa[c[x][r]]=y,fa[y]=x,fa[x]=z;
    c[y][l]=c[x][r],c[x][r]=y;
    return;
}
void splay(int x){
    p[top=1]=x;
    for (int i=x; !isroot(i); i=fa[i]) p[++top]=fa[i];
    for (int i=top; i>=1; --i) if (rev[p[i]]) pushd(p[i]);
    int y,z;
    while(!isroot(x)){
	y=fa[x],z=fa[y];
	if (!isroot(y))
	    if (c[y][0]==x^c[z][0]==y) rotate(x);
	    else rotate(y);
	rotate(x);
    }
    return;
}
void access(int x){
    int t=0;
    while(x){
	splay(x);
	c[x][1]=t,t=x,x=fa[x];
    }
    return;
}
void rever(int x){
    access(x),splay(x),rev[x]^=1;
    return;
}
void link(int x,int y){
    rever(x),fa[x]=y;
    return;
}
void cut(int x,int y){
    rever(x),access(y),splay(y);
    fa[x]=c[y][0]=0;
    return;
}
int find(int x){
    access(x),splay(x);
    while(c[x][0]) x=c[x][0];
    return x;
}
