typedef pair<int,int> ii;
typedef long long lint;

int n, m; 
ii updates[500005];
lint ans[500005];

namespace uf{
	int p[300005];
	int rak[300005];
	
	vector<ii> history;
	int comp = n;
	lint total = 0;
	
	void reset(){ for(int i = 0;i <= n;i++) p[i] = i, rak[i] = 0; comp = n; }
	
	int findSet(int u){
		if(p[u] == u) return u;
		else return findSet(p[u]);
	}
	
	void unionSet(int u, int v, int t){	
		u = findSet(u), v = findSet(v);
			
		if(rak[u] > rak[v]) swap(u,v);
		
		if(u == v){
			history.push_back(ii(u,0));
			return;
		}
		else history.push_back(ii(u,t));
		
		p[u] = v;
		if(rak[u] == rak[v]) rak[v]++;
		
		comp--;
		total += t;
	}
	
	void undo(){
		int u = history.back().first;
		int t = history.back().second;
		history.pop_back();
		
		if(t == 0) return;
		
		p[u] = u;
		comp++;
		total -= t;
	}
};

int main(){
	ios_base::sync_with_stdio(false); cin.tie(0);
	
	cin >> n >> m;
	uf::reset();
	
	for(int t = 1;t <= m;t++){
		string s; cin >> s;
		if(s[0] == 'A'){
			int a, b; cin >> a >> b;
			updates[t] = ii(a,b);
		}
		else if(s[0] == 'D'){
			int a; cin >> a;
			updates[t] = ii(a, -1);
		}
		else updates[t] = ii(-1,-1);
	}
	
	for(int t = 1;t <= m;t++){
		if(updates[t+1] == ii(-1,-1)){
			
			if(updates[t].second == -1){
				ans[t] = 0;
			}
			else{
				if(uf::comp == 1) ans[t] = uf::total;
				else if(uf::comp >= 3) ans[t] = 0;
				else{
					if(uf::findSet(updates[t].first) == uf::findSet(updates[t].second)) ans[t] = 0;
					else ans[t] = uf::total + (lint) t;
				}
			}			
			
			ans[t+1] = ans[t-1]; 
			continue;
		}
		if(updates[t] == ii(-1,-1)) continue;
		
		if(updates[t].second == -1){ ///del
			int k = updates[t].first;
			while(k--) uf::undo();
		}
		else{ ///insert
			uf::unionSet(updates[t].first, updates[t].second, t);
		}
		
		if(uf::comp == 1) ans[t] = uf::total;
		else ans[t] = 0;
	}
	
	for(int t = 1;t <= m;t++){
		cout << ans[t] << "\n";
	}
}

