program Link;
const maxn=200050; dividor=10007;
type
   node_ptr=^node;
   node=record n:longint; next:node_ptr end;

var
   w,u,v,d,p,s:array [1..maxn] of longint;
   succ:array [0..maxn+1] of node_ptr;
   nt:node_ptr;
   n,i,j,k:longint;
   t,ans,max:int64;
   sum,m1,m2:int64;

procedure sort(l,r:longint);
var i,j,m,t:longint;
begin
   i:=l; j:=r; m:=u[random(r-l+1)+l];
   repeat
      while u[i]<m do inc(i);
      while u[j]>m do dec(j);
      if i<=j then begin
         t:=u[i]; u[i]:=u[j]; u[j]:=t;
         t:=v[i]; v[i]:=v[j]; v[j]:=t;
         inc(i); dec(j);
      end;
   until i>j;
   if l<j then sort(l,j);
   if r>i then sort(i,r);
end;

begin
   fillchar(w,sizeof(w),0);
   read(n);
   for i:=1 to n-1 do begin
      read(u[i],v[i]);
      if u[i]>v[i] then begin
         t:=u[i]; u[i]:=v[i]; v[i]:=t;
      end;
   end;
   randomize; sort(1,n-1);

   d[1]:=0; p[1]:=0;
   for i:=2 to n-1 do d[i]:=-1;
   for i:=1 to n do begin
      new(succ[i]);
      succ[i]^.n:=-1;
      succ[i]^.next:=nil;
   end;
   for i:=1 to n-1 do begin
      if d[u[i]]=-1 then begin
         t:=u[i]; u[i]:=v[i]; v[i]:=t;
      end;
      d[v[i]]:=d[u[i]]+1;
      new(nt);
      nt^.n:=v[i];
      nt^.next:=succ[u[i]];
      succ[u[i]]:=nt;
      p[v[i]]:=u[i];
   end;

   for i:=1 to n do read(w[i]);

   ans:=0;
   for i:=1 to n do begin
      nt:=succ[i];
      if (p[i]=0) or (nt=nil) then continue;
      while nt^.next<>nil do begin
         t:=w[p[i]]*w[nt^.n];
         if t>max then max:=t;
         inc(ans,(t*2) mod dividor);
         ans:=ans mod dividor;
         nt:=nt^.next;
      end;
   end;
   for i:=1 to n do begin
      nt:=succ[i];
      j:=0;
      while nt^.next<>nil do begin
         inc(j);
         s[j]:=nt^.n;
         nt:=nt^.next;
      end;
      sum:=0; m1:=-1; m2:=-1;
      for k:=1 to j do begin
         inc(sum,w[s[k]]);
         if w[s[k]]>m1 then begin
            m2:=m1;
            m1:=w[s[k]];
         end else if w[s[k]]>m2 then begin
            m2:=w[s[k]];
         end;
      end;
      if m1*m2>max then max:=m1*m2;
      for k:=1 to j do begin
         inc(ans,w[s[k]]*((sum-w[s[k]]) mod dividor));
         ans:=ans mod dividor;
      end;
   end;

   writeln(max,' ',ans);
end.

#include <cstdio>
