using namespace std;

const int maxn = 200055;
const int mod = 10007;

int n;
int v[maxn] = {0};
int ma[maxn][2] = {0};
int sum[maxn] = {0};
int t[maxn][2] = {0};

int maxans = 0;
int ans = 0;

void Init()
{
	int a, b;
	scanf("%d", &n);
	for (int i = 1; i < n; ++i)
	{
		scanf("%d%d", &t[i][0], &t[i][1]);
	}
	for (int i = 1; i <= n; ++i)
		scanf("%d", &v[i]);
	
	for (int i = 1; i < n; ++i)
	{
		a = t[i][0];
		b = t[i][1];
		sum[a] = (sum[a] + v[b]) % mod;
		sum[b] = (sum[b] + v[a]) % mod;
		if (ma[a][1] < v[b])
			ma[a][1] = v[b], ma[a][0] = 1;
		else if (ma[a][1] == v[b])
			++ma[a][0];
		if (ma[b][1] < v[a])
			ma[b][1] = v[a], ma[b][0] = 1;
		else if (ma[b][1] == v[a])
			++ma[b][0];
	}
}

void Work()
{
	int a, b, tm;
	for (int i = 1; i < n; ++i)
	{
		tm = 0;
		a = t[i][0];
		b = t[i][1];
		ans = (ans + v[a] * (sum[b] - v[a])) % mod;
		ans = (ans + v[b] * (sum[a] - v[b])) % mod;
		
		if (v[a] != ma[b][1] || (v[a] == ma[b][1] && ma[b][0] > 1) )
			tm = v[a] * ma[b][1];
		maxans = max(maxans, tm);
	
		if (v[b] != ma[a][1] || (v[b] == ma[a][1] && ma[a][0] > 1) )
			tm = v[b] * ma[a][1];
		maxans = max(maxans, tm);
	}
}

void Out()
{
	printf("%d %d", maxans, (ans) % mod);
}

int main()
{

	Init();
	
	Work();
	
	Out();

	return 0;
}

