int n, m, k, up[10010], down[10010], ans = INF, l, h, f[10010][1010], x[10010], y[10010], p;
void search(int a, int tot, int h)
{
    h = min(h, m);
    if (a == n + 1)
    {
        ans = min(ans, tot);
        return ;
    }
    if (h - down[a] > 0) search(a + 1, tot, h - down[a]);
    int up_ti = (m - h) / up[a];
    if ((m - h) % up[a]) up_ti++;
    for (int i = 1; i <= up_ti; i++) search(a + 1, tot + i, h + i * up[a]);
}
void Search()
{
    cout << 1 << endl;
    for (int i = 1; i <= n; i++)
        cin >> up[i] >> down[i];
    search(1, 0, m);
    cout << ans;
}
void Find_ans()
{
    int num = k;
    for (int i = n; i >= 1; i--)
    {
        for (int j = 1 + down[i]; j <= up[i] - 1; j++)
            ans = min(ans, f[i][j]);
        if (ans != INF) break;
        if (up[i] <= m) num--;
    }
    if (num == k)
        cout << 1 << endl << ans;
    else
        cout << 0 << endl << num;
}
void DP()
{
    for (int i = 0; i < n; i++) cin >> x[i] >> y[i];
    for (int i = 1; i <= n; i++)
    {
        down[i] = 0;
        up[i] = m + 1;
    }
    for (int i = 1; i <= k; i++)
    {
        cin >> p >> l >> h;
        down[p] = l;
        up[p] = h;
    }
    for (int i = 1; i <= n; i++)
        for (int j = 0; j <= m; j++)
            f[i][j] = INF;
    f[0][0] = INF;
    for (int i = 1; i <= n; i++)
    {
        for (int j = 1; j <= m; j++)
        {
            if (j > x[i - 1])
            {
                f[i][j] = min(f[i][j], f[i - 1][j - x[i - 1]] + 1);
                f[i][j] = min(f[i][j], f[i][j - x[i - 1]] + 1);
            }
            if (j == m)
            {
                for (int k = j - x[i - 1]; k <= m; k++)
                {
                    f[i][j] = min(f[i][j], f[i - 1][k] + 1);
                    f[i][j] = min(f[i][j], f[i][k] + 1);
                }
            }
        }
        for (int j = down[i] + 1; j <= up[i] - 1; j++)
            if (j + y[i - 1] <= m) f[i][j] = min(f[i][j], f[i - 1][j + y[i - 1]]);
        for (int j = 1; j <= down[i]; j++) f[i][j] = INF;
        for (int j = up[i]; j <= m; j++)	f[i][j] = INF;
    }
    Find_ans();
}
int main()
{
    ios::sync_with_stdio(false);
    cin >> n >> m >> k;
    if (k == 0) Search();
    else DP();
    return 0;
}

