procedure qsort(l,r:longint);
  var i,j,mid,mid2,tmp:longint;
  begin
    i:=l; j:=r; mid:=x[(i+j) div 2]; mid2:=y[(i+j) div 2];
    repeat
      while (x[i]<mid) or ((x[i]=mid) and (y[i]<mid2)) do inc(i);
      while (x[j]>mid) or ((x[j]=mid) and (y[j]>mid2)) do dec(j);
      if i<=j then begin
        tmp:=x[i]; x[i]:=x[j]; x[j]:=tmp;
        tmp:=y[i]; y[i]:=y[j]; y[j]:=tmp;
        inc(i); dec(j);
      end;
    until i>j;
    if i<r then qsort(i,r);
    if l<j then qsort(l,j);
  end;

