procedure calc();
  var i,now:longint;
  begin
    fillchar(st,sizeof(st),0);
    i:=1; now:=0;
    while (i<=m) do begin
      if x[i]<>now then begin now:=x[i]; st[now]:=i; end;
      inc(i);
    end;
  end;

