  begin
    fillchar(reachable,sizeof(reachable),true);
    qsort(1,m);
    calc();
  end;

procedure deletepoint();
  var i,j:longint;
  begin
    fillchar(reachable,sizeof(reachable),true);
    for i:=1 to n do
      if dist[i]=maxlongint shr 1
        then begin
          reachable[i]:=false;
          if st[i]=0 then exit;
          for j:=st[i] to m do
            if x[j]<>i then break else reachable[y[j]]:=false;
        end;
  end;

procedure rearrange();
  var tmp,i:longint;
  begin
    for i:=1 to m do begin
      tmp:=x[i]; x[i]:=y[i]; y[i]:=tmp;
    end;
    qsort(1,m);
    calc();
  end;

procedure spfa(xpoint:longint);
  var head,tail,now,i:longint;
  begin
    fillchar(team,sizeof(team),0);
    fillchar(used,sizeof(used),false);
    for i:=1 to n do dist[i]:=maxlongint shr 1; dist[xpoint]:=0;
    head:=0; tail:=1; team[1]:=xpoint; used[xpoint]:=true;
    if reachable[s]=false then exit;
    while (head<tail) do begin
      inc(head); now:=team[head];
      if st[now]=0 then begin used[now]:=false; continue; end;
      for i:=st[now] to m do begin
        if x[i]<>now then break;
        if (dist[now]+1)<dist[y[i]]
          then begin
            dist[y[i]]:=dist[now]+1;
            if (not used[y[i]]) and (reachable[y[i]])
              then begin
                used[y[i]]:=true;
                inc(tail); team[tail]:=y[i];
              end;
          end;
      end;
      used[now]:=false;
    end;
  end;

