void toposort(int n, int t) {
  memset(del, false, sizeof(del));
  for(int i = 1; i <= n; i++)
    if(in[i] == 0 && i != t) { 
      Q1.push(i); 
      del[i] = true; 
    }
    
  while(!Q1.empty()) {
    int u = Q1.front(); Q1.pop();
    for(set<int>::iterator it = G[u].begin(); it != G[u].end(); ++it) {
      int v = *it;
      del[v] = true;
      in[v]--;
      if(in[v] == 0) Q1.push(v);
    }
  }
}

