int SPFA(int n, int s, int t) {
  for(int i = 1; i <= n; i++) d[i] = INF; 
  memset(inq, false, sizeof(inq));
  
  d[s] = 0;
  Q.push(s);
  inq[s] = true;
  while(!Q.empty()) {
    int u = Q.front(); Q.pop();
    inq[u] = false;
    for(set<int>::iterator it = G[u].begin(); it != G[u].end(); ++it) {
      int v = *it;
      if(del[v]) continue;
      if(d[v] > d[u] + 1) {
        d[v] = d[u] + 1;
        if(!inq[v]) {
          Q.push(v);
          inq[v] = true;
        }
      }
    }
  }
  return d[t] < INF ? d[t] : -1;
}
    
