const int N = (int) (1 << 18) + 1, mod = (int) (1 << 23) * 7 * 17 + 1;
int tmp[N], cut[N], heavy[N], m, n, k, sub[N], h[N], es[N], et[N], t, s[N];
int val[2][N];
vector<int> cyc[N], g[N], adj[N];
void sadd(int &x, int y) {
	x += y;
	if (x >= mod) x -= mod;
	//	if (x < 0) x += mod;
}
int pare[N];
void dfs_build(int v, int p = 0, int ep = -1) {
	s[t++] = v;
	pare[v] = ep;
	h[v] = h[p] + 1;
	for (int i = 0; i < (int) g[v].size(); ++i) if (g[v][i] != ep) { int e = g[v][i];
		int u = es[e] ^ et[e] ^ v;
		if (h[u] == 0) {
			dfs_build(u, v, e);
		} else if (h[u] < h[v]) {
			cut[e] = 0;
			for (int j = h[u] - 1; j < h[v]; ++j) {
				cyc[m].push_back(s[j]);
				if (s[j] != u) {
					cut[pare[s[j]]] = 0;
					val[0][s[j]] = j - (h[u] - 1);
					val[1][s[j]] = (h[v] - h[u] + 1) - val[0][s[j]];
				}
				{
					adj[s[j]].push_back(m);
					adj[m].push_back(s[j]);
				}
			}
			++m;
		}
	}
	--t;
}

void dfs_sz(int v, int p = 0) {
	sub[v] = 1;//(cyc[v].size()) + (v < n);
	heavy[v] = -1;
	for (int i = 0; i < (int) adj[v].size(); ++i) if (adj[v][i] != p) { int u = adj[v][i];
		dfs_sz(u, v);
		sub[v] += sub[u];
		if (heavy[v] < 0 || sub[heavy[v]] < sub[u])
			heavy[v] = u;
	}
}
int mark[N];
vect dp[N];
int ver[N], sum[N];
int fpm(int a, int b) { return b != 0 ? (LL) fpm((LL) a * a % mod, b >> 1) * (b & 1 ? a : 1) % mod: 1; }
const int logN = 20;
int dvsz[N], pp[2][N], rev[N];
int russian_mul(int x, int y) {
	int res = 0;
	while (x) {
		if (x & 1) {
			res += y;
			if (res >= mod) res -= mod;
		}
		x >>= 1;
		y <<= 1;
		if (y >= mod) y -= mod;
	}
	return res;
}
int w[2][logN][N];
void FFT(int a[N], int sz, int inverse) {
	int lg = 0;
	while ((1 << lg) != sz) ++lg;
	for (int j = 0; j < sz; ++j) {
		/*		int rev = 0;
				for (int b = 0; b < lg; ++b)
				rev |= (j >> b & 1) << (lg - b - 1); */
		if (rev[j] < j)
			swap(a[rev[j]], a[j]);
	}

	for (int len = 2, o = sz >> 1; len <= sz; len <<= 1, o >>= 1) {
		//int wn = pp[inverse][len];
		/*
		   fpm(3, (mod - 1) / len);
		   if (inverse) wn = fpm(wn, mod - 2); */
		for (int st = 0; st < sz; st += len) {
			int *w0 = w[inverse][lg];
			for (int k = 0, *x = a + st, *y = a + st + (len >> 1); k < (len >> 1); ++x, ++y, ++k, w0 += o) {
				int u = *x, v = (LL) (*y) * (*w0) % mod; //russian_mul((*y), w);
				*x = u + v;
				*y = u - v;
				if (*x >= mod) *x -= mod;
				if (*y < 0) *y += mod;
			}
		}
	}
	if (inverse) {
		int dv = dvsz[sz];
		//fpm(sz, mod - 2);
		for (int j = 0; j < sz; ++j)
			a[j] = (LL) a[j] * dv % mod;
	}
}
int which, nl[N], nr[N], lhs[N], rhs[N], xres[N];
int mul(int* xlhs, int* xrhs, int lsz, int rsz, int *res) {
	int cntl = 0, cntr = 0, sz_res = 0;
	while (cntl < lsz - 1 && xlhs[cntl] == 0) ++cntl;
	while (cntr < rsz - 1 && xrhs[cntr] == 0) ++cntr;
	lsz = lsz - cntl, rsz = rsz - cntr;
	for (int j = 0; j < lsz; ++j) lhs[j] = xlhs[cntl + j];
	for (int j = 0; j < rsz; ++j) rhs[j] = xrhs[cntr + j];
	while (lsz && lhs[lsz - 1] == 0) --lsz;
	while (rsz && rhs[rsz - 1] == 0) --rsz;
	int nlsz = 0, nrsz = 0;
	for (int j = 0; j < lsz; ++j) if (lhs[j]) nl[nlsz++] = j;
	for (int j = 0; j < rsz; ++j) if (rhs[j]) nr[nrsz++] = j;
	if (min(nlsz, nrsz) <= 80) {
		sz_res = (lsz + rsz + cntl + cntr + 1);
		static LL xr[N];
		for (int j = 0; j < lsz + rsz; ++j) xr[j] = 0;
		for (int x = 0; x < nlsz; ++x)
			for (int y = 0; y < nrsz; ++y) {
				xr[nl[x] + nr[y]] += (LL) lhs[nl[x]] * rhs[nr[y]];
				if (xr[nl[x] + nr[y]] >= (1ll << 62)) {
					xr[nl[x] + nr[y]] %= mod;
				}
			}
		for (int j = 0; j < lsz + rsz; ++j)
			if (xr[j])
				res[cntl + cntr + j] = xr[j] % mod;
		for (int j = 0; j < lsz; ++j) lhs[j] = 0;
		for (int j = 0; j < rsz; ++j) rhs[j] = 0;
	} else { 
		int lg = 0;
		while ((1 << lg) < lsz + rsz) ++lg;
		for (int j = lsz; j < (1 << lg); ++j) lhs[j] = 0;
		for (int j = rsz; j < (1 << lg); ++j) rhs[j] = 0;
		for (int j = 0; j < (1 << lg); ++j) rev[j] = (rev[j >> 1] >> 1) | ((j & 1) << (lg - 1));
		if (w[0][lg][0] != 1) {
			int wn = pp[0][(1 << lg)];
			w[0][lg][0] = 1;
			for (int j = 1; j < (1 << lg); ++j)
				w[0][lg][j] = (LL) w[0][lg][j - 1] * wn % mod;
		}
		FFT(lhs, (1 << lg), false);
		FFT(rhs, (1 << lg), false);
		for (int j = 0; j < (1 << lg); ++j) {
			xres[j] = (LL) lhs[j] * rhs[j] % mod;
		}
		if (w[1][lg][0] != 1) {
			int wn = pp[1][(1 << lg)];
			w[1][lg][0] = 1;
			for (int j = 1; j < (1 << lg); ++j)
				w[1][lg][j] = (LL) w[1][lg][j - 1] * wn % mod;
		}
		FFT(xres, (1 << lg), true);
		for (int j = (1 << lg) - 1; j >= 0; --j) {
			if (!sz_res && (j == 0 || xres[j])) {
				sz_res = (j + 1 + cntl + cntr);
			}
			if (xres[j]) {
				res[j + cntl + cntr] = xres[j];
				xres[j] = 0;
			}
			lhs[j] = rhs[j] = 0;
		}
	}
//	for (int j = res.size() - 1; j >= 0; --j) {
//		if (j == 0 || res[j] > 0) {
//			res.resize(j + 1);
//			break;
//		}
//	}
/*	for (int j = 0; j < (int) res.size(); ++j) tmp[j] = res[j];
	res.resize(cntl + cntr + res.size());
	for (int j = 0; j < cntl + cntr; ++j) res[j] = 0;
	for (int j = cntl + cntr; j < (int) res.size(); ++j) res[j] = tmp[j - cntl - cntr];
*/	
	while (sz_res >= 1 && res[sz_res - 1] == 0) --sz_res;
	return sz_res;
}
vect add(vect x, vect y) {
	vect res(max(x.size(), y.size()));
	for (int j = 0; j < SZ(res); ++j) {
		if (j < SZ(x) && x[j]) sadd(res[j], x[j]);
		if (j < SZ(y) && y[j]) sadd(res[j], y[j]);
	}
	return res;
}
const int lgN = logN;
int is_true = 0, vect_mul[2][lgN][N >> 1], vect_mul_size[2][lgN], vect_res[2][lgN][N >> 1], vect_res_size[2][lgN];
int vm[N];
void divide_conquer(int b, int e, int d = 0, int z = 0) {
	if (b + 1 >= e) {
		for (int j = 0; j < (int) dp[ver[b]].size(); ++j) vect_res[z][d][j] = dp[ver[b]][j];
		vect_res_size[z][d] = (int) dp[ver[b]].size();
		vect_mul_size[z][d] = 1;
		vect_mul[z][d][0] = 1;
		return;
	}
	int m = (b + e) >> 1;
	if (is_true) while (m < e - 1 && (sum[m] - sum[b]) <= sum[e] - sum[m]) ++m;
//	pair<vect, vect> l = 
		divide_conquer(b, m, d + 1, 0);
//	pair<vect, vect> r = 
		divide_conquer(m, e, d + 1, 1);
	++d;
	int *vl = vect_mul[0][d], *vr = vect_mul[1][d];
	int vls = vect_mul_size[0][d], vrs = vect_mul_size[1][d];
	int vms = (vls + max(0, max(val[0][ver[m]], val[1][ver[m]])));
	for (int j = 0; j <= 1; ++j) if (val[j][ver[m]] != -1) {
		//		vm[val[j][ver[m]]]++;
		for (int x = 0; x < vls; ++x)
			sadd(vm[x + val[j][ver[m]]], vl[x]);
	}
	vect_mul_size[z][d - 1] = mul(vm, vr, vms, vrs, vect_mul[z][d - 1]);
	//	vm = mul(vl, vm);
	int *resl = vect_res[0][d], *resr = vect_res[1][d];
	int resls = vect_res_size[0][d], resrs = vect_res_size[1][d];
	vect_res_size[z][d - 1] = mul(resr, vm, resrs, vms, vect_res[z][d - 1]);
	vect_res_size[z][d - 1] = max(vect_res_size[z][d - 1], resls);
	for (int j = 0; j < vect_res_size[z][d - 1]; ++j)
		sadd(vect_res[z][d - 1][j], resl[j]);
	for (int j = 0; j < vms; ++j) vm[j] = 0;
	for (int p = 0; p <= 1; ++p) {
		for (int j = 0; j < vect_res_size[p][d]; ++j) vect_res[p][d][j] = 0;
		for (int j = 0; j < vect_mul_size[p][d]; ++j) vect_mul[p][d][j] = 0;
		vect_res_size[p][d] = vect_mul_size[p][d] = 0;
	}
	// mp(add(mul(resr, vm), resl), mul(vm, vr))
}
void vclear(vect &x) {
	vect y;
	swap(x, y);
}
void dfs_res(int v, int p = 0) {
	for (int u = v; ~u; u = heavy[u]) {
		mark[u] = 1;
		dp[u].resize(1);
		//	dp[u].resize(1 + sub[u] - (heavy[u] != -1 ? sub[heavy[u]] : 0));
		if (u < n)
			dp[u][0] = 1;
	}
	int sz = 0;
	for (int u = v; ~u; u = heavy[u]) {
		for (int i = 0; i < (int) adj[u].size(); ++i) if (adj[u][i] != p && !mark[adj[u][i]]) { int x = adj[u][i];
			dfs_res(x, u);
			for (int a = 0; a <= 1; ++a) if (val[a][x] != -1) {
				if (SZ(dp[u]) < val[a][x] + SZ(dp[x])) dp[u].resize(val[a][x] + SZ(dp[x]));
				for (int p = val[a][x]; p < val[a][x] + SZ(dp[x]); ++p) if (dp[x][p - val[a][x]]) {
					sadd(dp[u][p], dp[x][p - val[a][x]]);
				}
			}
		}
		for (int j = dp[u].size() - 1; j >= 0; --j) {
			if (j == 0 || dp[u][j] != 0) {
				dp[u].resize(j + 1);
				break;
			}
		}
	}
	for (int u = v; ~u; u = heavy[u]) {
		mark[u] = 0;
		ver[sz] = u;
		sum[sz + 1] += sum[sz] + SZ(dp[u]);
		//		sum[sz + 2] += max(val[0][u], val[1][u]);
		//	vb[sz++] = dp[u];
		++sz;
	}
	divide_conquer(0, sz);
	for (int u = v; ~u; u = heavy[u]) vclear(dp[u]);
	dp[v].resize(vect_res_size[0][0]);
	for (int j = 0; j < vect_res_size[0][0]; ++j) {
		dp[v][j] = vect_res[0][0][j];
		vect_res[0][0][j] = 0;
	}
	vect_res_size[0][0] = 0;
}

inline int &Read(int &x)
{
	static char c;
	while (1) 
	{ 
		c = getchar(); 
		if (c == '-' || (c >= '0' && c <= '9')) break; 
	}
	bool flag = c == '-';
	x = flag ? 0 : c - '0';
	while (1)
	{
		c = getchar();
		if (c < '0' || c > '9') break;
		(x *= 10) += c - '0';
	}
	if (flag) x = -x;
	return x;
}

