namespace pb_ds
{
	const int MAXN = 262144;
	namespace FNT
	{
		const int mod = 998244353;
		const int G = 3;
		#define dmod(x) int((x) % mod)	
		IL int inc(RG int x, RG int v) {x += v; return x >= mod ? x - mod : x;}
		IL int dec(RG int x, RG int v) {x -= v; return x < 0 ? x + mod : x;}
		IL int power(RG int a, RG int b)
		{
			RG int ans = 1;
			for(; b; b >>= 1)
			{
				if(b % 2) ans = dmod((ll) ans * a);
				a = dmod((ll) a * a);
			}
			return ans;
		}

		int last = -1, w[2][MAXN], rev[MAXN];
		IL void init(RG int n)
		{
			if(n == last) return; last = n;
			RG int L = __builtin_ctz(n) - 1;
			RG int H = n >> 1;
			RG int g0 = power(G, (mod - 1) / n), g1 = power(g0, mod - 2);
			RG int c0 = 1, c1 = 1;
			Rep(i, 0, H) 
			{
				w[0][i + H] = c0, c0 = dmod((ll) c0 * g0);
				w[1][i + H] = c1, c1 = dmod((ll) c1 * g1);
			}
			ForDown(i, 0, H - 1) {w[0][i] = w[0][i << 1]; w[1][i] = w[1][i << 1];}
			Rep(i, 0, n) rev[i] = (rev[i >> 1] >> 1) | ((i % 2) << L);
		}


		IL void DFT(RG int n, RG int *a, bool d)
		{
			RG int *w = pb_ds::FNT::w[d], temp;
			Rep(i, 0, n) if(i < rev[i])
				temp = a[i], a[i] = a[rev[i]], a[rev[i]] = temp;
			for(RG int p = 2, m = 1; m != n; p = (m = p) << 1)
				for(RG int i = 0; i != n; i += p) for(RG int j = 0; j != m; ++j)
				{
					temp 			= dmod((ll) a[i + j + m] * w[j + m]);
					a[i + j + m] 	= dec(a[i + j], temp);
					a[i + j] 		= inc(a[i + j], temp);
				}
			if(d)
			{
				RG int f = power(n, mod - 2);
				Rep(i, 0, n) a[i] = dmod((ll) a[i] * f);
			}
		}
	}

	IL int polish(RG int n) {return --n ? 1 << (32 - __builtin_clz(n)) : 1;}
	IL int* new_arr(RG int n) 
	{
		static int mem[MAXN * 200], *tot = mem;
		tot += n; return tot - n;
