	void dfs_blo(RG int at)
	{
		static int timer, top;
		dfn[at] = low[at] = ++timer;
		stack[++top] = at;
		for(RG Pointer *iter = fir[at]; iter; iter = iter->next)
			if(dfn[iter->to])
				cmin(low[at], dfn[iter->to]);
			else
			{
				dfs_blo(iter->to);
