		}
///*lgg*/printf("dfs_init at = %d fa = %d dep = %d size = %d cho = %d\n", at,fa[at],dep[at],size[at],cho[at]);
	}
	int top[MAXN], pos[MAXN], list[MAXN], timer;
	const int inf = 2000000000;
	void dfs_make(RG int at)
	{
		top[at] = (at == cho[fa[at]] ? top[fa[at]] : at);
		pos[at] = ++timer;
		list[timer] = (at <= n ? heap[at].top() : inf);
