	inline void query(RG int l, RG int r)
	{
		l += d - 1;
		r += d + 1;
		for(; l ^ r ^ 1; l >>= 1, r >>= 1)
		{
			if(~l % 2) cmin(ans, T[l ^ 1]);
			if( r % 2) cmin(ans, T[r ^ 1]);
		}
