const int N=400000+100;
int G[N],G2[N],to2[N],ne2[N],ne[N],to[N],sz[N],fa[N],dp[N],tp[N],das[N*2],n,m,q;
int hc[N],xb,xb2,cnt,w[N],dfn[N],dft[N],clk;
int q1,q2,ans;

void modify(int o,int l,int r){
    if(l==r){das[o]=w[dft[l]];return;}
    int mid=(l+r)>>1;
    if(q1<=mid)modify(o<<1,l,mid);else modify(o<<1|1,mid+1,r);
    das[o]=min(das[o<<1],das[o<<1|1]);
}
void qry(int o,int l,int r){
//	printf("qry %d to %d this:%d to %d\n",q1,q2,l,r);
    if(q1<=l&&r<=q2){ans=min(ans,das[o]);return;}
    int mid=(l+r)>>1;
    if(q1<=mid)qry(o<<1,l,mid);
    if(q2>mid)qry(o<<1|1,mid+1,r);
}
void bt(int o,int l,int r){
    if(l==r){das[o]=w[dft[l]];return;}
  //  puts("nan");
    int mid=(l+r)>>1;
    bt(o<<1,l,mid);bt(o<<1|1,mid+1,r);
    das[o]=min(das[o<<1],das[o<<1|1]);
	//printf("das %d to %d =%d\n",l,r,das[o]);
   // puts("ak");
}
int query(int x,int y){
    ans=0x3f3f3f3f;
    for(;tp[x]!=tp[y];x=fa[tp[x]]){
        if(dp[tp[x]]<dp[tp[y]])swap(x,y);
        q1=dfn[tp[x]];q2=dfn[x];
        qry(1,1,clk);
    }
    if(dp[x]<dp[y])swap(x,y);
    q1=dfn[y];q2=dfn[x];
    qry(1,1,clk);
    if(fa[y]&&fa[y]<=n)ans=min(ans,w[fa[y]]);
    return ans;
}
void add2(int x,int y){
    ne2[xb2]=G2[x];to2[xb2]=y;G2[x]=xb2++;
