const int maxn = 100 + 4;
const long long inf = 10000000000000LL;

struct Tedge {
	int v, next, w, s;
} e[maxn * maxn];

int N;
int head[maxn];

void insert(int a, int b, int w, int s) {
	e[N].v = b;
	e[N].w = w;
	e[N].s = s;
	e[N].next = head[a];
	head[a] = N;
	N++;
}

int n, m;
bool reach[maxn][maxn];

void Init() {
	int v, u, w, s;
	scanf("%d%d", &n, &m);
	for (int i = 1; i <= n; i++) head[i] = -1, reach[i][i] = true;
	for (int i = 0; i < m; i++) {
		scanf("%d%d%d%d", &v, &u, &w, &s);
		insert(v, u, w, s);
		reach[v][u] = true;
	}
	for (int k = 1; k <= n; k++)
		for (int i = 1; i <= n; i++)
			for (int j = 1; j <= n; j++)
				if (reach[i][k] && reach[k][j]) reach[i][j] = true;
	for (int i = 1; i <= n; i++) {
		int pre = -1;
		for (int j = head[i]; j != -1; j = e[j].next)
			if (reach[i][ e[j].v ] && reach[ e[j].v ][i]) {
				if (pre == -1) head[i] = j;
				else e[pre].next = j;
				pre = j;
				continue;
			}
		if (pre == -1) head[i] = -1;
		else e[pre].next = -1;
	}
}

int size;
int list[maxn];
bool vis[maxn];
long long Left[maxn], Right[maxn];


int cnt[maxn], o[maxn * maxn], anc[maxn], s[maxn];
bool inLine[maxn], exist[maxn];
long long dis[maxn];
int Spfa(int stp, long long x) {
	for (int i = 0; i < size; i++) {
		inLine[ list[i] ] = false;
		cnt[ list[i] ] = 0;
		dis[ list[i] ] = inf;
		exist[ list[i] ] = false;
	}
	
	int h = 0, t = 0;
	o[h] = stp;
	inLine[stp] = true;
	dis[stp] = 0;
	cnt[stp]++;
	while (h <= t) {
		int u = o[h];
		if (cnt[u] > size) {
			int p = anc[u]; vis[u] = true;
			while (!exist[p]) exist[p] = true, p = anc[p];
			int rt = s[p];
			u = anc[p];
			while (u != p) {
				rt += s[u];
				u = anc[u];
			}
			return rt;
		}
		h++;
		inLine[u] = false;
		for (int i = head[u]; i != -1; i = e[i].next) {
			int v = e[i].v;
			long long cost = dis[u] + x * e[i].s + e[i].w;
			if (cost < dis[v]) {
				dis[v] = cost;
				anc[v] = u;
				s[v] = e[i].s;
				if (!inLine[v]) {
					inLine[v] = true;
					cnt[v]++;
					o[++t] = v;
				}
			}
		}
	}
	return maxn;
}

long long search(int stp, long long i, long long j, int dir) {
	long long mid;
	while (i <= j) {
		mid = (i + j) >> 1;
		if (dir == -1) {
			if (Spfa(stp, mid) != maxn) i = mid + 1;
			else j = mid - 1;
		}
		if (dir == 1) {
			if (Spfa(stp, mid) == maxn) i = mid + 1;
			else j = mid - 1;
		}
	}
	if (dir == -1) return i;
	return j;
}

void work(int u) {
	size = 0;
	for (int i = 1; i <= n; i++)
		if (reach[u][i] && reach[i][u]) {
			vis[i] = true;
			list[size++] = i;
		}
	
	long long i = -inf, j = inf, mid;
	long long st = inf, en = -inf;
	int t;	
	while (i <= j) {
		mid = (i + j) >> 1;
		t = Spfa(u, mid);
		if (t == maxn) {
			st = search(u, -inf, mid, -1);
			en = search(u, mid, inf, 1);
			break;
		}
		else if (t > 0) i = mid + 1;
		else if (t < 0) j = mid - 1;
		else if (t == 0) break;
	}
	
	for (int i = 1; i <= n; i++)
		if (reach[u][i]) {
			Left[i] = max(Left[i], st);
			Right[i] = min(Right[i], en);
		}
}

void Solve() {
	for (int i = 1; i <= n; i++) Left[i] = -inf, Right[i] = inf;
	for (int i = 1; i <= n; i++)
		if (!vis[i]) work(i);
	for (int i = 1; i <= n; i++) {
		if (!reach[1][i] || (Left[i] == -inf) || (Right[i] == inf)) printf("-1\n");
		else if (Left[i] > Right[i]) printf("0\n");
		else printf("%lld\n", Right[i] - Left[i] + 1);
	}
}

int main() {
	Init();
	Solve();

	return 0;
}

