std::pair<llt,llt> solve(std::vector<uint>A)
{
    static llt Dist[30005];
    static bol Init[30005];
    static uint Cnt[30005];
    static std::vector<std::pair<uint,std::pair<llt,uint> > >E[105];
    uint n=A.size();
    for(uint i=0;i<n;i++)
    {
        E[i].clear();
        for(auto s:Way[A[i]])
            if(S[s.first]==S[A[i]])E[i].push_back({T[s.first],s.second});
            else Go[S[A[i]]].push_back(S[s.first]);
    }
    for(uint i=0;i<n*(n*2+1);i++)Dist[i]=inf,Cnt[i]=0,Init[i]=0;
    std::queue<uint>Q;Q.push(n),Dist[n]=0;
    while(Q.size())
    {
        uint p=Q.front();Init[p]=false,Q.pop();
        if(Cnt[p]++>n*8)return{inf,-inf};
        if(p==n&&Dist[p]<0)return{inf,-inf};
        for(auto s:E[p/(2*n+1)])
        {
            uint b=s.second.second+p%(2*n+1);uint t=b+(2*n+1)*s.first;
            if(b<=n*2&&_min(Dist[t],Dist[p]+s.second.first)&&!Init[t])
                Q.push(t),Init[t]=true;
        }
    }
    llt l=-inf,r=inf;
    for(uint i=0;i<n;i++)if(Dist[i]<inf)_min(r,divlow(Dist[i],n-i));
    for(uint i=n+1;i<=n*2;i++)if(Dist[i]<inf)_max(l,divup(-Dist[i],i-n));
    return{l,r};
}
