int cur;
struct fl  {
	ull A, B;
	fl()  {}
	fl(ull _a, ull _b)  {
		A = _a, B = _b;
	}
	void operator *=(ull x)  {
		A *= x, B *= x;
		A += B >> cur, B &= (1 << cur) - 1;
	}
	void operator +=(const fl &o)  {
		A += o.A, B += o.B;
		A += B >> cur, B &= (1 << cur) - 1;
	}
	void out()  {
		printf("%llu", A);
		if (B)  {
			printf(".");

			double b = 1. * B / (1 << cur);
			while (fabs(floor(b + 1e-10) - b) > 1e-10)  b *= 10;
			printf("%.lf\n", b);
		}
	}
};

void solve1()  {
	ull all = 0;
	for (int i = 0; i < n; i ++)
		all |= a[i];
	if (all & 1) printf("%llu.5\n", all >> 1);
	else printf("%llu\n", all);
}

void solve2()  {
	lim = 32;
	ull all = 0;
	for (int i = 0; i < n; i ++)
		all |= a[i];

	cur = 2;
	fl ans(0, 0);

	//(i,i)
	for (int i = 0; i < lim; i ++)  
		if ((all >> i) & 1)  { //2^(2i-2)
			ull tmp = 1ull << (2 * i + 1);
			ans += fl(tmp >> 2, tmp & 3);
		}

	bool have[4], nw = 1;
	int dp[2][4];

	//(i, j)
	for (int i = 0; i < lim; i ++)
		for (int j = 0; j < i; j ++)  {
			//prep
			nw = 1;
			for (int t = 0; t < 4; t ++)
				dp[nw][t] = 0, have[t] = 0;
			dp[nw][0] = 4;

			for (int t = 0; t < n; t ++)  {
				int state = (((a[t] >> i) & 1) << 1) | ((a[t] >> j) & 1);
				have[state] = 1;
			}

			//solve
			for (int t = 0; t < 4; t ++)
				if (have[t])  {
					nw = !nw;
					for (int tt = 0; tt < 4; tt ++)
						dp[nw][tt] = (dp[!nw][tt] + dp[!nw][tt ^ t]) >> 1;
				}
			int sub = 0;
			if (dp[nw][3] == 0) continue;
			ull tmp = (1ull << (i + j)) * dp[nw][3];
			fl add = fl(tmp >> 2, tmp & 3);
			add *= 2;
			ans += add;
		}
	ans.out();
}


void solve3()  {
	lim = 63 / k + 2;
	cur = 0;
	for (int t = lim - 1; t >= 0; t --)  {
		int find = -1;
		for (int i = cur; i < n; i ++)
			if ((a[i] >> t) & 1) find = i;
		if (find == -1) continue;
		swap(a[find], a[cur]);
		for (int i = 0; i < n; i ++)
			if (i != cur && (a[i] >> t) & 1)
				a[i] ^= a[cur];
		cur ++;
	}

	fl ans(0, 0);

	for (int t = 0; t < 1 << cur; t ++)  {
		ull xorsum = 0;
		for (int i = 0; i < cur; i ++)
			if ((t >> i) & 1) xorsum ^= a[i];
		fl ret(0, 1); 
		for (int i = 0; i < k; i ++)  ret *= xorsum;

		ans += ret;
	}
	ans.out();
}

