const db eps = 1e-13;
const int inf = 1000000005;
const int maxn = 205;

int n, p, w[maxn];
ll a[maxn], b[maxn], c[maxn];
struct poi  {
	db x, y;
}book[maxn], pt[maxn], o;
int dp[maxn], cost[maxn][maxn];

poi jiao(ll a1, ll b1, ll c1, ll a2, ll b2, ll c2)  {
	poi ret;
	ret.y = -1. * (c1 * a2 - a1 * c2) / (b1 * a2 - a1 * b2);
	ret.x = -1. * (c1 * b2 - c2 * b1) / (a1 * b2 - b1 * a2);
	return ret;
}

bool cmp(poi a, poi b)  {
	return (a.x - o.x) * (b.y - o.y) - (a.y - o.y) * (b.x - o.x) > eps;
}

bool on(int k, poi p)  {
	return a[k] * p.x + b[k] * p.y < c[k] + eps;
}

int solve(int s1, int s2)  {
	// printf("now solve %d,%d (%.5lf, %.5lf)\n", s1,s2,(double)o.x,(double)o.y);
	int tot = 0;
	for (int i = 1; i <= p; i ++)
		if (!on(s1, book[i]) && !on(s2, book[i]))  pt[++ tot] = book[i];
	sort(pt + 1, pt + 1 + tot, cmp);
	// for (int i = 1; i <= tot; i ++)
		// printf("point[%d] (%.5lf, %.5lf)\n", i, (double)pt[i].x, (double)pt[i].y);
	for (int i = 1; i <= tot; i ++)
		for (int j = 1; j <= tot; j ++)  cost[i][j] = inf;
	for (int i = 1, j, k; i <= n; i ++)  {
		for (j = 1, k = 1; j <= tot; j ++)  
			if (on(i, pt[k = j]))  {
				while (k < tot && on(i, pt[k + 1])) k ++;
				cost[j][k] = min(cost[j][k], w[i]);
				// printf("plane i=%d, (%d,%d)\n", i, j, k);
				j = k;
			}
	}
	for (int i = 1; i <= tot; i ++)
		for (int j = tot; j > i; j --)  {
			cost[i][j - 1] = min(cost[i][j - 1], cost[i][j]);
			cost[i + 1][j] = min(cost[i + 1][j], cost[i][j]);
		}

	for (int i = 1; i <= tot; i ++) dp[i] = inf;
	dp[0] = 0;
	for (int i = 1; i <= tot; i ++)  {
		for (int j = 1; j <= i; j ++)
			dp[i] = min(dp[i], dp[j - 1] + cost[j][i]);
	}
	if (dp[tot] < inf) return dp[tot] + w[s1] + w[s2];
	else return inf;
}

