#include <iostream>
#include <cstdio>
#include <algorithm>
using namespace std;

typedef long long s64;
typedef __int128 s128;

const int INF = 1000000000;

const int MaxN = 100;
const int MaxM = 100;

template <class T>
inline void tension(T &a, const T &b)
{
	if (b < a)
		a = b;
}

struct point
{
	int x, y;
};

struct halfplane
{
	int a, b, c, w;

	inline bool contains(const point &p)
	{
		return (s64)a * p.x + (s64)b * p.y <= c;
	}
};

struct cmpByAngle
{
	s64 px, py;
	s64 pd;

	inline bool operator()(const point &a, const point &b)
	{
		return (s128)(a.x * pd - px) * (b.y * pd - py) - (s128)(a.y * pd - py) * (b.x * pd - px) < 0;
	}
};

int main()
{
	int n, m;
	static halfplane hp[MaxM];
	static point po[MaxN];

	cin >> n >> m;
	for (int i = 0; i < n; i++)
		scanf("%d %d %d %d", &hp[i].a, &hp[i].b, &hp[i].c, &hp[i].w);
	for (int j = 0; j < m; j++)
		scanf("%d %d", &po[j].x, &po[j].y);

	int res = INF;
	for (int i = 0; i < n; i++)
	{
		bool ok = true;
		for (int j = 0; j < m; j++)
			if (!hp[i].contains(po[j]))
			{
				ok = false;
				break;
			}
		if (ok)
			tension(res, hp[i].w);
	}

	for (int i1 = 0; i1 < n; i1++)
		for (int i2 = 0; i2 < i1; i2++)
		{
			int rp_n = 0;
			static point rp[MaxM];
			for (int j = 0; j < m; j++)
				if (!hp[i1].contains(po[j]) && !hp[i2].contains(po[j]))
					rp[rp_n++] = po[j];
			if (rp_n == 0)
			{
				tension(res, hp[i1].w + hp[i2].w);
				continue;
			}

			cmpByAngle cmp;
			cmp.px = (s64)hp[i1].c * hp[i2].b - (s64)hp[i2].c * hp[i1].b;
			cmp.py = (s64)hp[i1].a * hp[i2].c - (s64)hp[i2].a * hp[i1].c;
			cmp.pd = (s64)hp[i1].a * hp[i2].b - (s64)hp[i2].a * hp[i1].b;
			sort(rp, rp + rp_n, cmp);

			static int f[MaxM];
			static int w[MaxM][MaxM];

			for (int jr = 0; jr < rp_n; jr++)
				for (int jl = 0; jl <= jr; jl++)
					w[jl][jr] = INF;

			for (int i = 0; i < n; i++)
			{
				int jl = -1;
				for (int j = 0; j < rp_n; j++)
				{
					if (hp[i].contains(rp[j]))
					{
						if (jl == -1)
							jl = j;
					}
					else
					{
						if (jl != -1)
						{
							tension(w[jl][j - 1], hp[i].w);
							jl = -1;
						}
					}
				}
				if (jl != -1)
					tension(w[jl][rp_n - 1], hp[i].w);
			}

			for (int jr = 0; jr < rp_n; jr++)
				for (int jl = 1; jl <= jr; jl++)
					tension(w[jl][jr], w[jl - 1][jr]);

			for (int j = 0; j < rp_n; j++)
			{
				f[j] = w[0][j];
				for (int k = 0; k < j; k++)
					tension(f[j], f[k] + w[k + 1][j]);
			}

			tension(res, hp[i1].w + hp[i2].w + f[rp_n - 1]);
		}

	cout << res << endl;
	
	return 0;
}

