	while('0'>c || '9'<c) fuhao=c=='-'?-1:fuhao,c=getchar();
	while('0'<=c && c<='9') x=(x<<1)+(x<<3)+(c^48),c=getchar();
	x*=fuhao;
}

bool check(int x,int y,int id){
	return A[id]*x+B[id]*y<=C[id];
}

inline void pivot(int line,int col){
	top=0;
	double res=a[line][col];
	a[line][col]=1;
	For(i,0,m)
		if(fabs(a[line][i])>eps) q[++top]=i;
	For(i,0,n)
		if(i!=line && fabs(a[i][col])>eps){
			res=a[i][col],a[i][col]=0;
			For(j,1,top) a[i][q[j]]-=res*a[line][q[j]];
		}
}

inline void init_simplex(){
	int line,col;double res;
	while(1){
		line=col=0,res=-eps;
		For(i,1,n) 
			if(a[i][0]<res) 
				col=i,res=a[i][0];
		if(!col) break;
		For(i,1,m)
			if(a[line][i]>eps) 
				line=i;
		if(!line){
			flag=1;
			return ;
		}
		pivot(line,col);
	}
}

inline void simplex(){
	int line,col;double res;
	while(1){
		line=col=0;
		For(i,1,m)
			if(a[0][i]>eps){
				col=i;
				break;
			}
		if(!col) break;
		res=inf;
		For(i,1,n) 
			if(a[i][col]>eps && a[i][0]/a[i][col]<res) 
				res=a[i][0]/a[i][col],line=i;
		if(!line){
			flag=1;
			return ;
		}
		pivot(line,col);
	}
}

