#include <bits/stdc++.h>
using namespace std;

const long long INF = 1LL << 61;

long long X[500005];
long long A[500005];
long long prefixSumA[500005];
long long prefixSum[500005];

int n;
long long t;

inline long long findCost(int s, int e, int indx){
    return (prefixSum[e]+prefixSum[s-1] - (prefixSum[indx]<<1)) + ((prefixSumA[indx]<<1) - prefixSumA[s-1] - prefixSumA[e])*X[indx];
}

bool possible(long long limit1){
    //printf("possible(%lld)\n", limit1);
    int l = 1;
    int m = 1;
    int r = 1;
    long long sum = 0;
    long long sumM = 0;

    while(r <= n){
        if(sum < limit1){
            sum += A[r];
            r ++;
        }
        if((sumM<<1) < sum){
            sumM += A[m];
            m ++;
        }

        if(sum >= limit1){
            //printf("sum=%lld\n", sum);
            for(int m2 = max(m-2, l); m2 <= min(m+2, r-1); m2 ++){
                //printf("findCost(%d, %d, %d) = %lld\n", l, r-1, m2, findCost(l, r-1, m2));
                long long tempCost = findCost(l, r-1, m2);
                if(tempCost <= (t>>1)){
                    return true;
                }
                int l2 = l;
                int r2 = r-1;

                int distL = abs(X[l2] - X[m2]);
                int distR = abs(X[r2] - X[m2]);
                long long rem = sum - limit1;
                long long tempCnt;
                if(distL < distR){
                    tempCnt = min(A[r2], rem);
                    rem -= tempCnt;
                    tempCost -= tempCnt*distR;

                    tempCnt = min(A[l2], rem);
                    rem -= tempCnt;
                    tempCost -= tempCnt*distL;
                    assert(rem == 0);
                }else{
                    tempCnt = min(A[l2], rem);
                    rem -= tempCnt;
                    tempCost -= tempCnt*distL;

                    tempCnt = min(A[r2], rem);
                    rem -= tempCnt;
                    tempCost -= tempCnt*distR;
                    assert(rem == 0);
                }
                //printf("tempCost = %lld\n", tempCost);
                if(tempCost <= (t>>1)){
                    return true;
                }
            }

            sumM -= A[l];
            sum -= A[l];
            l ++;
        }
    }
    return false;
}


long long findCost(int indx, long long k){
    int s = lower_bound(X, X+(n+1), X[indx]-k) - X;
    int e = upper_bound(X, X+(n+1), X[indx]+k) - X - 1;

    long long temp = 0;
    if(s <= indx-1){
        temp += (prefixSumA[indx-1] - prefixSumA[s-1])*X[indx] - (prefixSum[indx-1]-prefixSum[s-1]);
        //printf("%lld %lld\n", (prefixSumA[indx-1] - prefixSumA[s-1])*X[indx], (prefixSum[indx-1]-prefixSum[s-1]));
    }
    if(indx+1 <= e){
        temp += (prefixSum[e]-prefixSum[indx]) - (prefixSumA[e] - prefixSumA[indx])*X[indx];
    }

    //printf("indx=%d k=%lld range=[%d, %d] totalCost=%lld\n", indx, k, s, e, temp);
    return temp;
}

int main(){
    scanf("%d%lld", &n, &t);

    prefixSum[0] = 0;
    prefixSumA[0] = 0;
    for(int i = 1; i <= n; i ++){
        scanf("%lld", &X[i]);
    }
    for(int i = 1; i <= n; i ++){
        scanf("%lld", &A[i]);
        assert(A[i] <= 10000);
        prefixSumA[i] = prefixSumA[i-1] + A[i];
        prefixSum[i] = prefixSum[i-1] + X[i]*A[i];
    }

    X[0] = -INF;
    X[n+1] = INF;

    if(n < 123456){
        long long maxScore = 0;
        int bound = 1012345678;
        for(int i = 1; i <= n; i ++){
            int l = i-1;
            int r = i+1;
            long long score = 0;

            long long curT = t>>1;

            long long lo = 0;
            long long hi = bound;
            while(lo < hi){
                long long mid = (lo+hi+1)>>1;
                if(findCost(i, mid) <= curT){
                    lo = mid;
                }else{
                    hi = mid-1;
                }
            }

            if(i < n){
                bound = lo + X[i]-X[i-1];
            }

            curT -= findCost(i, lo);
            l = lower_bound(X, X+(n+1), X[i]-lo) - X - 1;
            r = upper_bound(X, X+(n+1), X[i]+lo) - X;
            score += prefixSumA[r-1] - prefixSumA[l];
            assert(curT >= 0);

            //printf("i=%d lo=%lld l=%d r=%d cost=%lld\n", i, lo, l, r, findCost(i, lo));

            while(curT > 0){
                if(l == 0 && r == n+1){break;}
                long long dist = min(abs(X[l] - X[i]), abs(X[r] - X[i]));
                int indx;
                if(abs(X[l] - X[i]) < abs(X[r] - X[i])){
                    indx = l;
                    l --;
                }else{
                    indx = r;
                    r ++;
                }
                long long cnt = min(curT/dist, A[indx]);
                //printf("i=%d curT=%lld dist=%lld indx=%d cnt=%lld l=%d r=%d\n", i, curT, dist, indx, cnt, l, r);

                curT -= dist*cnt;
                score += cnt;
                if(cnt == 0){break;}
                if(l == 0 && r == n+1){break;}
            }
            //printf("i=%d score=%lld\n", i, score);
            maxScore = max(maxScore, score);
        }

        printf("%lld", maxScore);
        return 0;
    }

    long long lo = 0;
    long long hi = prefixSumA[n]+5;
    while(lo < hi){
        long long mid = (lo+hi+1)>>1;
        if(possible(mid)){
            lo = mid;
        }else{
            hi = mid-1;
        }
    }

    printf("%lld", lo);
    return 0;
}

#include <bits/stdc++.h>
