int x[500005];
int a[500005];
ll pa[500005];
ll pax[500005];
ll ans = 0;
void test(int L, int M, int R){
    if (M < L || R < M || L < 1 || R > n || R < L) return;
    ll cost = 2*((pa[M]-pa[L-1])*x[M] - (pax[M]-pax[L-1]) + (pax[R]-pax[M]) - (pa[R]-pa[M])*x[M]);
    if (cost > t) return;
    ll extra = t-cost;
    ll Ldist = (L>1)?x[M]-x[L-1]:1000000000000000001;
    ll Lnum = (L>1)?a[L-1]:0;
    ll Rdist = (R<n)?x[R+1]-x[M]:1000000000000000001;
    ll Rnum = (R<n)?a[R+1]:0;
    Ldist *= 2;
    Rdist *= 2;
    if (Ldist > Rdist){
        swap(Ldist,Rdist);
        swap(Lnum, Rnum);
    }
    ll add = 0;
    if (Ldist != 0){
        ll addL = min(Lnum,extra/Ldist);
        extra -= Ldist*addL;
        add += addL;
    }
    if (Rdist != 0){
        ll addR = min(Rnum,extra/Rdist);
        add += addR;
    }
    //printf("%d %d %d: add %lld, %lld\n",L,M,R,add,pa[R]-pa[L-1]+add);
    ans = max(ans,pa[R]-pa[L-1]+add);
}
int main(){
    scanf("%d%lld",&n,&t);
    for (int i = 1; i <= n; i++){
        scanf("%d",&x[i]);
    }
