        //printf("at L = %d, R = %d\n",L,R);
        R = max(L,R);
        while (R+1 <= n){
            R++;
            ll sum = pa[R]-pa[L-1];
            int M = lower_bound(pa+1,pa+n+1,pa[L-1]+sum/2)-pa;
            ll cost = (pa[M]-pa[L-1])*x[M] - (pax[M]-pax[L-1]) + (pax[R]-pax[M]) - (pa[R]-pa[M])*x[M];
            cost *=2;
            if (cost > t){
                R--;
                break;
            }
            else test(L,M,R);
        }
        ll sum = pa[R]-pa[L-1];
        int M = lower_bound(pa+1,pa+n+1,pa[L-1]+sum/2)-pa;
        //printf("testing %d %d %d\n",L,M,R);
        for (int l = max(1,L-1); l <= min(n,L+1); l++){
            for (int r = max(1,R-1); r <= min(n,R+1); r++){
                for (int m = max(1,M-1); m <= min(n,M+1); m++){
                    test(l,m,r);
                }
            }
        }
    }
    printf("%lld",ans);
}

