struct Point
{
    int x,y,Replace;
}P[N],D[N],S[N];
Point operator + (const Point &a,const Point &b)
{
    Point c;
    c.x=a.x+b.x;
    c.y=a.y+b.y;
    return c;
}
Point operator - (const Point &a,const Point &b)
{
    Point c;
    c.x=a.x-b.x;
    c.y=a.y-b.y;
    return c;
}
const bool operator == (const Point &a,const Point &b)
{
    return a.x==b.x&&a.y==b.y;
}
const bool operator < (const Point &a,const Point &b)
{
    if(a==b)
        return a.Replace<b.Replace;
    if(a.x==b.x)
        return a.y<b.y;
    return a.x<b.x;
}
const bool operator > (const Point &a,const Point &b)
{
    if(a==b)
        return a.Replace>b.Replace;
    if(a.x==b.x)
        return a.y>b.y;
    return a.x>b.x;
}

double Cross(const Point &a,const Point &b)
{
    return (double)a.x*(double)b.y-(double)a.y*(double)b.x;
}

struct Join
{
    Point from,to;
    double slope;
    int value,belong;
    void R(Point p1,Point p2,int v)
    {
        from=p1;
        to=p2;
        value=v;
        Point cut=to-from;
        slope=atan2(cut.y,cut.x);
        belong=0;
        return;
    }
    double Get_height(double Distance)
    {
        double Dx1=(double)from.x-Distance;
        double Dx2=(double)to.x-Distance;
        double Dx0=(double)to.x-(double)from.x;
        double ReHeight=((double)from.y*Dx2-(double)to.y*Dx1)/Dx0;
        return ReHeight;
    }
}J[N],U[N];
const bool operator < (const Join &a,const Join &b)
{
    if(a.from==b.from)
        return a.to<b.to;
    return a.from<b.from;
}
const bool operator > (const Join &a,const Join &b)
{
    if(a.from==b.from)
        return a.to>b.to;
    return a.from>b.from;
}

