int root0,root1,root2,size_all;
int son[N][2],father[N],sizes[N],name[N];
void flying(int place)
{
    if(!place)
        return;
    int from=son[place][0],to=son[place][1];
    sizes[place]=sizes[from]+sizes[to]+1;
    return;
}
void rot_it(int place,int &want)
{
    int elder=father[place],eldest=father[elder];
    int zig=son[elder][1]==place,zag=zig^1;
    if(elder==want)
        want=place;
    else
        son[eldest][son[eldest][1]==elder]=place;
    father[place]=eldest;
    father[elder]=place;
    father[son[place][zag]]=elder;
    son[elder][zig]=son[place][zag];
    son[place][zag]=elder;
    flying(elder);
    flying(place);
    return;
}
void splay(int place,int &want)
{
    while(place!=want)
    {
        int elder=father[place],eldest=father[elder];
        if(elder!=want)
        {
            if((son[eldest][0]==elder)^(son[elder][0]==place))
                rot_it(place,want);
            else
                rot_it(elder,want);
        }
        rot_it(place,want);
    }
    return;
}
int find_it(int place,int ranks)
{
    int from=son[place][0],to=son[place][1];
    if(sizes[from]+1==ranks)
        return place;
    if(sizes[from]>=ranks)
        return find_it(from,ranks);
    return find_it(to,ranks-sizes[from]-1);
}
int find_this(int place,double Base,double want,int Use)
{
    int from=son[place][0],to=son[place][1];
    if(Use==name[place])
        return sizes[from]+1;
    double ReHeight=U[name[place]].Get_height(Base);
    if(ReHeight>want)
        return find_this(from,Base,want,Use);
    return sizes[from]+1+find_this(to,Base,want,Use);
}
int find_that(int place,double Base,double want)
{
    if(!place)
        return 0;
    int from=son[place][0],to=son[place][1];
    double ReHeight=U[name[place]].Get_height(Base);
    if(ReHeight>want)
        return find_that(from,Base,want);
    return sizes[from]+1+find_that(to,Base,want);
}
void split(int from,int to)
{
    root1=find_it(root0,from);
    root2=find_it(root0,to);
    splay(root1,root0);
    splay(root2,son[root0][1]);
    return;
}
void build_tree(int from,int to,int root)
{
    if(from>to)
        return;
    int cut=(from+to)/2;
    father[son[root][cut>root]=cut]=root;
    if(from==to)
    {
        sizes[cut]=1;
        return;
    }
    build_tree(from,cut-1,cut);
    build_tree(cut+1,to,cut);
    flying(cut);
    return;
}
void Zero(int MAX)
{
    name[1]=MAX+1;
    name[2]=0;
    build_tree(1,2,0);
    size_all=2;
    root0=1;
    return;
}
void Insert(double Length,double want,int Use)
{
    int place=find_that(root0,Length,want);
    split(place,place+1);
    father[son[root2][0]=++size_all]=root2;
    name[size_all]=Use;
    sizes[size_all]=1;
    flying(root2);
    flying(root1);
    return;
}
void Delete(double Length,double want,int Use)
{
    int place=find_this(root0,Length,want,Use);
    split(place-1,place+1);
    son[root2][0]=0;
    flying(root2);
    flying(root1);
    return;
}
int Lower_bound(double Length,double want)
{
    Insert(Length,want,-1);
    int ReLower=name[root2];
    Delete(Length,want,-1);
    return ReLower;
}

const bool see1(const Join &a,const Join &b)
{
    return a.slope<b.slope;
}

