    for(int i=1;i<=q;i++)
    {
        float read1,read2,read3,read4;
        scanf("%f%f%f%f",&read1,&read2,&read3,&read4);
        A[i].point1.x=(int)(read1*2+0.01);
        A[i].point1.y=(int)(read2*2+0.01);
        A[i].point2.x=(int)(read3*2+0.01);
        A[i].point2.y=(int)(read4*2+0.01);
    }
    return;
}

