int next[N];

void Count()
{
    for(int i=1;i<=n;i++)
    {
        sort(E1[i].begin(),E1[i].end(),see1);
        int size_now=(signed)E1[i].size();
        for(int j=0;j<size_now;j++)
        {
            int X=Hash_J[E1[i][j]];
            int Y=Hash_J[E1[i][(j+1)%size_now]];
            next[X]=Y;
        }
    }
    for(int i=2;i<=num_E1;i++)
        if(!J[i].belong)
        {
            int nows=i;
            ONE.S.clear();
            ++num_A;
            do
            {
                ONE.S.push_back(J[nows].from);
                J[nows].belong=num_A;
                nows=next[nows^1];
            }while(nows!=i);
            ONE.A();
            if(ONE.Area>=0)
                Warning=num_A;
        }
    for(int i=2;i<=num_E1;i+=2)
        if(J[i].belong!=J[i^1].belong&&J[i].belong!=Warning&&J[i^1].belong!=Warning)
        {
            ++num_E2;
            W[num_E2].a=J[i].belong;
            W[num_E2].b=J[i^1].belong;
            W[num_E2].v=J[i].value;
        }
    return;
}

map<Point,int> Hash_P;
vector<int> In[N],Out[N];
int fly[N];
double Base[N][2];

void Find()
{
    for(int i=2;i<=num_E1;i+=2)
    {
        if(J[i].from.x<J[i].to.x)
            U[++num_U]=J[i];
        if(J[i].from.x>J[i].to.x)
            U[++num_U]=J[i^1];
    }
    Point P1,P2;
    P1.x=-INF;
    P1.y=INF;
    P2.x=INF;
    P2.y=INF;
    U[0].R(P1,P2,0);
    U[0].belong=Warning;
    P1.x=-INF;
    P1.y=-INF;
    P2.x=INF;
    P2.y=-INF;
    U[num_U+1].R(P1,P2,0);
    U[num_U+1].belong=Warning;
    for(int i=1;i<=num_U;i++)
    {
        if(!Hash_P.count(U[i].from))
        {
            Hash_P[U[i].from]=++num_P;
            D[num_P]=U[i].from;
        }
        if(!Hash_P.count(U[i].to))
        {
            Hash_P[U[i].to]=++num_P;
            D[num_P]=U[i].to;
        }
        Out[Hash_P[U[i].from]].push_back(i);
        In[Hash_P[U[i].to]].push_back(i);
    }
    for(int i=1;i<=q;i++)
    {
        D[++num_P]=A[i].point1;
        D[num_P].Replace=i;
        Hash_P[D[num_P]]=num_P;
        D[++num_P]=A[i].point2;
        D[num_P].Replace=i+q;
        Hash_P[D[num_P]]=num_P;
    }
    memcpy(S,D,sizeof(S));
    sort(S+1,S+num_P+1);
    Zero(num_U);
    for(int i=1;i<=num_P;i=fly[i])
    {
        int j=i;
        for(;S[j].x==S[i].x;j++);
        fly[i]=j;
        Base[i][1]=((double)S[i].x+(double)S[j].x)/2;
        Base[j][0]=((double)S[i].x+(double)S[j].x)/2;
    }
    for(int i=1;i<=num_P;i=fly[i])
    {
        for(int j=i;S[j].x==S[i].x;j++)
        {
            if(i==1)
                break;
            int Old=Hash_P[S[j]];
            if(D[Old].Replace)
                continue;
            for(int k=0;k<(signed)In[Old].size();k++)
            {
                Join J0=U[In[Old][k]];
                Delete(Base[i][0],J0.Get_height(Base[i][0]),In[Old][k]);
            }
        }
        for(int j=i;S[j].x==S[i].x;j++)
        {
            if(fly[i]>num_P)
                break;
            int Old=Hash_P[S[j]];
            if(D[Old].Replace)
                continue;
            for(int k=0;k<(signed)Out[Old].size();k++)
            {
                Join J0=U[Out[Old][k]];
                Insert(Base[i][1],J0.Get_height(Base[i][1]),Out[Old][k]);
            }
        }
        for(int j=i;S[j].x==S[i].x;j++)
        {
            int Old=Hash_P[S[j]];
            if(D[Old].Replace)
            {
                int Over=Lower_bound((double)S[j].x,(double)S[j].y);
                if(D[Old].Replace>q)
                    A[D[Old].Replace-q].to=U[Over].belong;
                else
                    A[D[Old].Replace].from=U[Over].belong;
            }
        }
    }
    return;
}

int Father[N],grand[N][21],maxs[N][21],num_L,num_C;
int T[N],nexts[N],ending[N],value[N],flag[N],deep[N];

int Finds(int son)
{
    if(Father[son]!=son)
        Father[son]=Finds(Father[son]);
    return Father[son];
}

void Dfs(int x0,int color)
{
    flag[x0]=color;
    for(int i=1;i<=20;i++)
    {
        if(deep[x0]<1<<i)
            break;
        grand[x0][i]=grand[grand[x0][i-1]][i-1];
        maxs[x0][i]=max(maxs[grand[x0][i-1]][i-1],maxs[x0][i-1]);
    }
    int f=T[x0];
    while(f)
    {
        int y0=ending[f];
        if(!flag[y0])
        {
            deep[y0]=deep[x0]+1;
            grand[y0][0]=x0;
            maxs[y0][0]=value[f];
            Dfs(y0,color);
        }
        f=nexts[f];
    }
    return;
}

int Get_LCA(int x0,int y0)
{
    if(x0==Warning||y0==Warning||flag[x0]!=flag[y0])
        return -1;
    if(x0==y0)
        return 0;
    int x=x0,y=y0;
    if(deep[x]<deep[y])
        swap(x,y);
    int cut=deep[x]-deep[y],remax=0;
    for(int i=20;i>=0;i--)
        if(cut&(1<<i))
        {
            remax=max(remax,maxs[x][i]);
            x=grand[x][i];
        }
    for(int i=20;i>=0;i--)
        if(grand[x][i]!=grand[y][i])
        {
            remax=max(remax,max(maxs[x][i],maxs[y][i]));
            x=grand[x][i];
            y=grand[y][i];
        }
    if(x!=y)
        remax=max(remax,max(maxs[x][0],maxs[y][0]));
    return remax;
}

void Do()
{
    sort(W+1,W+num_E2+1);
    for(int i=1;i<=num_A;i++)
        Father[i]=i;
    for(int i=1;i<=num_E2;i++)
    {
        int x=W[i].a,y=W[i].b;
        int fx=Finds(x);
        int fy=Finds(y);
        if(fx==fy)
            continue;
        Father[fx]=fy;
        value[++num_L]=W[i].v;
        ending[num_L]=y;
        nexts[num_L]=T[x];
        T[x]=num_L;
        value[++num_L]=W[i].v;
        ending[num_L]=x;
        nexts[num_L]=T[y];
        T[y]=num_L;
        if(num_L==2*num_A-2)
            break;
    }
    for(int i=1;i<=num_A;i++)
        if(i!=Warning&&!flag[i])
            Dfs(i,++num_C);
    for(int i=1;i<=q;i++)
        A[i].result=Get_LCA(A[i].from,A[i].to);
    return;
}

int main()
{
    Read_in();
    Count();
    Find();
    Do();
    Put_out();
    return 0;
}

