		#define add_edge(f, t, l) (\
			edgeTo[++edgeCnt] = t,\
			edgeLen[edgeCnt] = l,\
			nextEdge[edgeCnt] = firstEdge[f],\
			firstEdge[f] = edgeCnt\
		)

