		void dfs(int at)
		{
	//printf("dfs at = %d dep = %d\n", at, depth[at]);
			vis[at] = 1;
			for(int i = 1; (1 << (i - 1)) <= depth[at]; ++i)
			{
				f[at][i] = f[f[at][i - 1]][i - 1];
				#define dmax(i,j) (i > j ? i : j)
				ans[at][i] = dmax(ans[at][i - 1], ans[f[at][i - 1]][i - 1]);
	//printf("ans[%d][%d] = %lld\n", at, i, ans[at][i]);		
			}
			for(int i = firstEdge[at]; i; i = nextEdge[i])
				if(!vis[edgeTo[i]])
				{
					depth[edgeTo[i]] = depth[at] + 1;
					ans[edgeTo[i]][0] = edgeLen[i];
					f[edgeTo[i]][0] = at;
					dfs(edgeTo[i]);
				}
		}
	
		int fa[MAX], weight[MAX], ee_cnt;
