		inline int query(int a, int b)
		{
			if(a == inf_area || b == inf_area || g(a) != g(b))
				return -1;
			static int d, qur;
			if(depth[a] < depth[b])
				std::swap(a, b);
			d = depth[a] - depth[b];
			qur = 0;
			#define cmax(i,j) ((i) < (j) ? (i) = (j) : 1)
			#define cmin(i,j) ((i) > (j) ? (i) = (j) : 1)
			for(int i = 0; (1 << (i - 1)) <= d; ++i)
				(1 << i) & d
				? cmax(qur, ans[a][i]), a = f[a][i]
				: 1;
			if(a == b)return qur;
			ForDown(i, 0, lim)
				(f[a][i] != f[b][i])
				?
					cmax(qur, ans[a][i]),
					cmax(qur, ans[b][i]),
					a = f[a][i], b = f[b][i]
				: 1;
			cmax(qur, ans[a][0]);
			cmax(qur, ans[b][0]);
			return qur;
		}

