	namespace scan_line
	{
		const double eps = 1e-10;
		int cut, event_cnt;
		struct info_t
		{
			int x, y, i; double k;
			info_t(const point_t& s, const point_t& t, int i)
				: x(s.x), y(s.y), i(i), k(double(t.y - s.y) / (t.x - s.x)) {}
		};
		
		struct cmp_t
		{
			inline bool operator() (const info_t& a, const info_t& b) const
			{
				static double ya, yb;
				ya = a.y + a.k * (cut - a.x);
				yb = b.y + b.k * (cut - b.x);
				#define delta(x, y) (x < y ? y - x : x - y)
//printf("ai = %d bi = %d ya = %.3lf yb = %.3lf\n", a.i, b.i,ya, yb);
				return (delta(ya, yb) > eps ? ya < yb : a.k < b.k);
			}
		};
		typedef __gnu_pbds::tree<info_t, __gnu_pbds::null_type, cmp_t> tree_t;
		tree_t T;
		tree_t::iterator iter[MAX];

		struct event_t {int x, i; }event[MAX << 1];
		inline bool cmp_event(const event_t& a, const event_t& b)
		{
			return a.x < b.x || (a.x == b.x && a.i < b.i);
		}

		struct query_t{int x, y, i;}query[MAX << 1];
		inline bool cmp_query(const query_t& a, const query_t& b)
		{
			return a.x < b.x;
		}

		void work()
		{
			For(i, 1, m)
			{
				int &a = to[i << 1], &b = to[i << 1 | 1];
				if(p[a].x == p[b].x)continue;
				if(p[a].x > p[b].x)
					std::swap(a, b), std::swap(area[i << 1], area[i << 1 | 1]);
				event[++event_cnt].i = i,
				event[event_cnt].x = p[a].x,
				event[++event_cnt].i = -i,
				event[event_cnt].x = p[b].x;
			}
