		if(x==y)
			return ans;
		for(int i=20;i>=0;--i)
			if(pa[x][i]!=pa[y][i]){
				ans=max(ans,mx[x][i]);
				x=pa[x][i];
				ans=max(ans,mx[y][i]);
				y=pa[y][i];
			}
		ans=max(ans,mx[x][0]);
		ans=max(ans,mx[y][0]);
		return ans;
	}
}T;

namespace Union_Set{
	int r[N],siz[N];
	void init(int n){
		for(int i=1;i<=n;++i)
			r[i]=i,siz[i]=1;
	}
	int find(int x){
		int q=x,rq;
		for(;x!=r[x];x=r[x]);
		for(;q!=x;rq=r[q],r[q]=x,q=rq);
		return x;
	}
	void merge(int x,int y){
		if(siz[x]>siz[y])
			swap(x,y);
		siz[y]+=siz[x];
		r[x]=y;
	}
}

#define ls ch[0]
#define rs ch[1]
struct Node{
	Node*ch[2];
	int id,p,siz;
	Node():siz(0){}
}mem[(N<<1)*40],*P=mem,Tnull,*null=&Tnull;
Node*newnode(){
	P->p=rand();
	P->siz=1;
	P->ch[0]=P->ch[1]=null;
	return P++;
}
void up(Node*p){
	p->siz=p->ls->siz+p->rs->siz+1;
}
void copy(Node*&p,Node*q){
	if(q==null)
		p=null;
	else
		*(p=newnode())=*q;
}
void merge(Node*&re,Node*p,Node*q){
	if(p==null)
		copy(re,q);
	else if(q==null)
		copy(re,p);
	else if(p->p<q->p){
		copy(re,p);
		merge(re->rs,p->rs,q);
		up(re);
	}
	else{
		copy(re,q);
		merge(re->ls,p,q->ls);
		up(re);
	}
}
void split(Node*re,int k,Node*&p,Node*&q){
	if(k==0){
		copy(p,null);
		copy(q,re);
	}
	else if(k==re->siz){
		copy(p,re);
		copy(q,null);
	}
	else if(k<=re->ls->siz){
		copy(q,re);
		split(re->ls,k,p,q->ls);
		up(q);
	}
	else{
		copy(p,re);
		split(re->rs,k-re->ls->siz-1,p->rs,q);
		up(p);
	}
}
db gety(int id,db _x){
	return y[be[id]]+(db)(y[en[id]]-y[be[id]])/(x[en[id]]-x[be[id]])*(_x-x[be[id]]);
}
bool check(int id,db _x,db _y){
	return _y<gety(id,_x)?0:1;
}
int calc_geq(Node*p,db _x,db _y){
	if(p==null)
		return 0;
	bool d=check(p->id,_x,_y);
	if(d==0)
		return p->rs->siz+1+calc_geq(p->ls,_x,_y);
	else
		return calc_geq(p->rs,_x,_y);
}
Node*succ(Node*p,db _x,db _y){
	if(p==null)
		return null;
	bool d=check(p->id,_x,_y);
	if(d==0){
		Node*re=succ(p->ls,_x,_y);
		return re==null?p:re;
	}
	else
		return succ(p->rs,_x,_y);
}
int getrank(Node*p,db _x,int id){
	if(p==null)
		return 0;
	if(p->id==id)
		return p->ls->siz;
	bool d=check(p->id,_x,gety(id,_x));
	if(d==0)
		return getrank(p->ls,_x,id);
	else
		return p->ls->siz+1+getrank(p->rs,_x,id);
}
Node*insert(Node*last,db _x,int id){
	int ans=calc_geq(last,_x,gety(id,_x));
	Node*p1,*p2,*re;
	split(last,last->siz-ans,p1,p2);
	Node*now=newnode();
	now->id=id;
	merge(re,p1,now);
	merge(re,re,p2);
	return re;
}
Node*cutdown(Node*last,db _x,int id){
	int ans=getrank(last,_x,id);
	Node*p1,*p2,*p3,*re;
	split(last,ans,p1,p2);
	split(p2,1,p2,p3);
	merge(re,p1,p3);
	return re;
}

