Edge::Edge(int _u, int _v, int _w)
    : u(_u), v(_v), w(_w),
      dual_id(0),
      reverse_edge(nullptr),
      next(nullptr) {}

inline void link(int u, int v, int w) {
    Edge *e1 = new Edge(u, v, w);
    Edge *e2 = new Edge(v, u, w);
    e1->reverse_edge = e2;
    e2->reverse_edge = e1;
    G[u].push_back(e1);
    G[v].push_back(e2);
}

void dfs(Edge *e, int id) {
    if (e->dual_id)
        return;

    DEBUG(" -> %d", e->v);
    e->dual_id = id;
    dfs(e->reverse_edge->next, id);
}

void decompose() {
    // Sort all edges in CW order
    for (int u = 1; u <= n; u++) {
        sort(G[u].begin(), G[u].end(),
            [u](const Edge *a, const Edge *b) {
                return cross(position[a->v] - position[u],
                             position[b->v] - position[u]) < 0;
            });

        for (size_t i = 0; i < G[u].size(); i++) {
            if (i != G[u].size() - 1)
                G[u][i]->next = G[u][i + 1];
            else
                G[u][i]->next = G[u][0];
        }
    }

    // Split planar graph
    int p = 1;
    for (int u = 2; u <= n; u++) {
        if (position[u].x < position[p].x)
            p = u;
    }

    Edge *start = nullptr;
    for (auto e : G[p]) {
        if (!start ||
            cross(
                position[start->v] - position[p],
                position[e->v] - position[p]
            ) > 0)
            start = e;
    }

    DEBUG("R1: %d", p);
    dfs(start, 1);
    DEBUG_PUTS("");

    dual_cnt = 1;
    for (int u = 1; u <= n; u++) {
        for (auto e : G[u]) {
            if (!e->dual_id) {
                dual_cnt++;
                DEBUG("R%d: %d", dual_cnt, u);
                dfs(e, dual_cnt);
                DEBUG_PUTS("");
            }
        }
    }
}

