const int MAX_N = 100000 + 3, MAX_M = 100000 + 3, MAX_Q = 100000 + 3;
int BLOCK_SIZE = 2154;

struct edge {
	edge *next;
	int to;
	edge(edge *next = NULL, int to = 0): next(next), to(to) {}
} pool[MAX_N * 2], *pit = pool, *first[MAX_N];

int n, m, q, v[MAX_M], w[MAX_N], c[MAX_N], cTmp[MAX_N];
