	int pos, v, oriV;
} modifications[MAX_Q];

struct query {
	int u, v, t, id;
	inline bool operator < (const query &ano) const {
		if (blockID[u] != blockID[ano.u]) return blockID[u] < blockID[ano.u];
		else if (dfn[v] != dfn[ano.v]) return dfn[v] < dfn[ano.v];
		return t < ano.t;
	}
} querys[MAX_Q];


void dfs(int u, int fa) {
	static int ts = 0, blockCnt = 0, sz = 0, stk[MAX_N];
	int bottom = sz;
	dfn[u] = ts++;

	for (edge *e = first[u]; e; e = e->next) if (e->to != fa) {
		dep[e->to] = dep[u] + 1;
		anc[0][e->to] = u;
		dfs(e->to, u);
		
		if (sz - bottom >= BLOCK_SIZE) {
			while (sz > bottom) blockID[stk[--sz]] = blockCnt;
			blockCnt++;
		}
	}

	stk[sz++] = u;
	if (fa == -1) {
		while (sz) blockID[stk[--sz]] = blockCnt - 1;
	}
}

int logs[MAX_N];
void prepare() {
	dfs(0, -1);

	for (int w = 1; (1 << w) < n; ++w)
		for (int i = 0; i < n; ++i)
			if (dep[i] - (1 << w) >= 0)
				anc[w][i] = anc[w - 1][anc[w - 1][i]];

	for (int i = 2; i <= n; ++i) logs[i] = logs[i >> 1] + 1;
}

inline int lca(int u, int v) {
	if (dep[u] < dep[v]) swap(u, v);
	
	for (int bit = logs[dep[u]]; bit >= 0; --bit)
		if (dep[u] - (1 << bit) >= dep[v])
			u = anc[bit][u];
	if (u == v) return u;

	for (int bit = logs[dep[u]]; bit >= 0; --bit)
		if (dep[u] - (1 << bit) >= 0 && anc[bit][u] != anc[bit][v])
			u = anc[bit][u], v = anc[bit][v];
	
	return anc[0][u];
}

