int cnt[MAX_M];
ll ans[MAX_Q], nowAns = 0;

inline void flip(int u) {
	in[u] ^= 1;
	if (in[u]) {
		nowAns += (ll)v[c[u]] * w[cnt[c[u]]];
		++cnt[c[u]];
	} else {
		--cnt[c[u]];
		nowAns -= (ll)v[c[u]] * w[cnt[c[u]]];
	}
}

inline void moveTime(int t, int sign) {
	const modification &m = modifications[t];
	bool flag = in[m.pos];
	if (flag) flip(m.pos);

	if (sign == 1) {
		c[m.pos] = m.v;
	} else {
		c[m.pos] = m.oriV;
	}

	if (flag) flip(m.pos);
}

inline void move(int u, int v) {
	int lca = ::lca(u, v);

	for (int cur = u; cur != lca; cur = anc[0][cur])
		flip(cur);
	
	for (int cur = v; cur != lca; cur = anc[0][cur])
		flip(cur);
}

void solve() {
	int u = 0, v = 0, t = 0;
	for (int i = 0; i < q2; ++i) {
		const query q = querys[i];
		while (t < q.t) moveTime(t++, 1);
		while (t > q.t) moveTime(--t, -1);
		int lca = ::lca(q.u, q.v);
		move(q.u, u), move(q.v, v), flip(lca);
		ans[q.id] = nowAns;
		flip(lca);
		u = q.u, v = q.v;
	}

	for (int i = 0; i < q2; ++i) printf("%lld\n", ans[i]);
}

