struct Query {
  int u, v, id;
  ll ans;
} Q[N];

bool cmp1(const Query &a, const Query &b) {
  return bel[a.u] == bel[b.u] ? dfn[a.v] < dfn[b.v] : bel[a.u] < bel[b.u];
}

bool cmp2(const Query &a, const Query &b) {
  return a.id < b.id;
}

struct Modify {
  int pos, bef, aft, id;
} M[N << 1];

struct Edge {
  int v, nxt;
} E[N << 1];


void addedge(int u, int v) {
  E[++tot] = (Edge) {v, head[u]};
  head[u] = tot;
} 

int dfs(int u) {
  int siz = 0;
  dfn[u] = ++dfn_ind;
  for (int i = 1; i <= 18; i++)
    fa[u][i] = fa[fa[u][i - 1]][i - 1];
  for (int i = head[u]; i; i = E[i].nxt) {
    int v = E[i].v;
    if (v == fa[u][0]) continue;
    fa[v][0] = u;
    dep[v] = dep[u] + 1;
    siz += dfs(v);
    if (siz >= siz_block) {
      ++cnt_block;
      while (siz) {
        bel[st[top--]] = cnt_block;
        --siz;
      }
    }
  }
  st[++top] = u;
  return siz + 1;
}

int lca(int x, int y) {
  if (dep[x] < dep[y]) swap(x, y);
  int delta = dep[x] - dep[y];
  for (int i = 0; i <= 18; i++)
    if ((delta >> i) & 1) x = fa[x][i];
  if (x == y) return x;
  for (int i = 18; i >= 0; i--) {
    if (fa[x][i] != fa[y][i]) {
      x = fa[x][i];
      y = fa[y][i];
    }
  }
  return fa[x][0];
}

void reverse(int x) {
  if (vis[x]) {
    nowans -= w[num[col[x]]] * v[col[x]];
    num[col[x]]--;  
  } else {
    num[col[x]]++;
    nowans += w[num[col[x]]] * v[col[x]];
  }
  vis[x] ^= 1;
}

void solve(int x, int y) {
  while (x != y) {
    if (dep[x] > dep[y]) {
      reverse(x);
      x = fa[x][0];
    } else {
      reverse(y);
      y = fa[y][0];
    }
  }
}

