template <class T, size_t L>
class block_allocator
{
private:
	union item
	{
		char t[sizeof(T)];
		item *next;
	};

	item *unused;
public:
	block_allocator()
		: unused(NULL) {}

	inline T *allocate()
	{
		if (!unused)
		{
			item *pool = new item[L], *tail = pool + L;
			for (item *p = pool; p != tail; p++)
				p->next = unused, unused = p;
		}

		T *tp = (T*)unused;
		unused = unused->next;
		new (tp) T();
		return tp;
	}
	inline void deallocate(T *tp)
	{
		item *p = (item*)tp;
		p->next = unused, unused = p;
	}
};

struct cir_edge
{
	int v, u, w;
	int cir_l;
};

struct lct_edge
{
	int w;
	cir_edge *cir_e;
};

block_allocator<cir_edge, 10000> cir_edge_allocator;
block_allocator<lct_edge, 10000> lct_edge_allocator;

inline cir_edge *get_cir_e(const lct_edge *e)
{
	return e ? e->cir_e : NULL;
}

struct lct_info
{
	bool has_cir;

	int l;
	lct_edge *head_e, *tail_e;
	int head_l, tail_l;

	inline void rev()
	{
		swap(head_e, tail_e);
		swap(head_l, tail_l);
	}

	inline void cov_cir_e(cir_edge *cir_e, bool has_children)
	{
		has_cir = has_children && cir_e;
	}

	friend inline lct_info operator+(const lct_info &a, const lct_info &b)
	{
		assert(a.tail_e == b.head_e);
		lct_edge *e = a.tail_e;

		lct_info c;
		c.has_cir = a.has_cir || e->cir_e || b.has_cir;
		c.head_e = a.head_e, c.tail_e = b.tail_e;

		if (!e->cir_e || (get_cir_e(a.head_e) == e->cir_e && get_cir_e(b.tail_e) == e->cir_e))
			c.head_l = a.head_l, c.l = a.l + e->w + b.l, c.tail_l = b.tail_l;
		else if (get_cir_e(a.head_e) == e->cir_e)
			c.head_l = a.l + e->w + b.head_l, c.l = b.l, c.tail_l = b.tail_l;
		else if (get_cir_e(b.tail_e) == e->cir_e)
			c.head_l = a.head_l, c.l = a.l, c.tail_l = a.tail_l + e->w + b.l;
		else
		{
			int sl = a.tail_l + e->w + b.head_l;
			c.head_l = a.head_l;
			c.l = a.l + min(sl, e->cir_e->cir_l - sl) + b.l;
			c.tail_l = b.tail_l;
		}

		return c;
	}
};

struct lct_node
{
	lct_node *fa, *lc, *rc;
	lct_edge *prev_e, *next_e;

	bool has_cov_cir_e;
	cir_edge *cov_cir_e;
	bool has_tag_rev;

	lct_info info;

	inline void tag_rev()
	{
		info.rev();
		has_tag_rev = !has_tag_rev;
	}
	inline void tag_cov_cir_e(cir_edge *cir_e)
	{
		info.cov_cir_e(cir_e, lc || rc);
		has_cov_cir_e = true, cov_cir_e = cir_e;
	}

	inline void tag_down()
	{
		if (has_tag_rev)
		{
			if (lc)
				lc->tag_rev();
			if (rc)
				rc->tag_rev();

			swap(lc, rc);
			swap(prev_e, next_e);
			has_tag_rev = false;
		}
		if (has_cov_cir_e)
		{
			if (lc)
			{
				prev_e->cir_e = cov_cir_e;
				lc->tag_cov_cir_e(cov_cir_e);
			}
			if (rc)
			{
				next_e->cir_e = cov_cir_e;
				rc->tag_cov_cir_e(cov_cir_e);
			}
			has_cov_cir_e = false;
		}
	}

	inline void update()
	{
		info.has_cir = false;
		info.head_e = prev_e, info.head_l = 0;
		info.tail_e = next_e, info.tail_l = 0;
		info.l = 0;

		if (lc)
			info = lc->info + info;
		if (rc)
			info = info + rc->info;
	}

	inline bool is_root()
	{
		return !fa || (fa->lc != this && fa->rc != this);
	}

	inline void rotate()
	{
		lct_node *x = this, *y = x->fa, *z = y->fa;
		lct_node *b = x == y->lc ? x->rc : x->lc;

		x->fa = z, y->fa = x;
		if (b)
			b->fa = y;

		if (z)
		{
			if (z->lc == y)
				z->lc = x;
			else if (z->rc == y)
				z->rc = x;
		}

		if (x == y->lc)
			x->rc = y, y->lc = b;
		else
			x->lc = y, y->rc = b;

		y->update();
	}

	inline void anc_tag_down()
	{
		int anc_n = 0;
		static lct_node *anc[MaxN];
		anc[anc_n++] = this;
		for (lct_node *x = this; !x->is_root(); x = x->fa)
			anc[anc_n++] = x->fa;
		for (int i = anc_n - 1; i >= 0; i--)
			anc[i]->tag_down();
	}

	inline void splay()
	{
		anc_tag_down();
		while (!is_root())
		{
			if (!fa->is_root())
			{
				if ((fa->lc == this) == (fa->fa->lc == fa))
					fa->rotate();
				else
					rotate();
			}
			rotate();
		}
		update();
	}
	inline void splay_until(lct_node *target)
	{
		anc_tag_down();
		while (fa != target)
		{
			if (fa->fa != target)
			{
				if ((fa->lc == this) == (fa->fa->lc == fa))
					fa->rotate();
				else
					rotate();
			}
			rotate();
		}
		update();
	}

	inline void access()
	{
		for (lct_node *p = this, *q = NULL; p; q = p, p = p->fa)
		{
			p->splay();
			p->rc = q;
			if (q)
				q->fa = p;
			p->next_e = q ? q->info.head_e : NULL;
			p->update();
		}
		splay();
	}

	inline void make_root()
	{
		access(), tag_rev(), tag_down();
	}
};

lct_node lct[MaxN + 1];

void lct_init(int n)
{
	for (int v = 1; v <= n; v++)
	{
		lct_node *x = lct + v;
		x->fa = x->lc = x->rc = NULL;
		x->prev_e = x->next_e = NULL;
		x->has_cov_cir_e = false;
		x->has_tag_rev = false;
		x->update();
	}
}
bool lct_link(int v, int u, int w)
{
	if (v == u)
		return false;
	if (v > u)
		swap(v, u);

	lct_node *x = lct + v, *y = lct + u;
	y->make_root(), x->make_root();
	if (!x->fa && !y->fa)
	{
		lct_edge *e = lct_edge_allocator.allocate();
		e->w = w, e->cir_e = NULL;
		x->fa = y;
		x->prev_e = e;
		x->update();
		return true;
	}

	y->access();

	if (y->info.has_cir)
		return false;

	cir_edge *cir_e = cir_edge_allocator.allocate();
	cir_e->v = v, cir_e->u = u, cir_e->w = w;
	cir_e->cir_l = y->info.l + w;

	x->splay_until(y);
	x->next_e->cir_e = cir_e, y->prev_e->cir_e = cir_e;
	if (x->rc)
		x->rc->tag_cov_cir_e(cir_e);
	x->update(), y->update();
	return true;
}
bool lct_cut(int v, int u, int w)
{
	if (v == u)
		return false;
	if (v > u)
		swap(v, u);

	lct_node *x = lct + v, *y = lct + u;
	y->make_root(), x->access();
	if (x->prev_e && x->prev_e->cir_e && x->prev_e->cir_e->v == v && x->prev_e->cir_e->u == u && x->prev_e->cir_e->w == w)
	{
		cir_edge_allocator.deallocate(x->prev_e->cir_e);

		y->splay_until(x);
		y->next_e->cir_e = NULL, x->prev_e->cir_e = NULL;
		if (y->rc)
			y->rc->tag_cov_cir_e(NULL);
		y->update(), x->update();
		return true;
	}

	if (x->lc != y || x->lc->lc || x->lc->rc)
		return false;
	if (!x->prev_e->cir_e)
	{
		y->tag_down();
		lct_edge_allocator.deallocate(x->prev_e);
		x->lc = NULL, y->fa = NULL;
		x->prev_e = NULL, y->next_e = NULL;
		x->update(), y->update();
		return true;
	}

	int cir_v = x->prev_e->cir_e->v, cir_u = x->prev_e->cir_e->u, cir_w = x->prev_e->cir_e->w;
	lct_cut(cir_v, cir_u, cir_w);
	lct_cut(v, u, w);
	lct_link(cir_v, cir_u, cir_w);
	return true;
}
int lct_query(int v, int u)
{
	lct_node *x = lct + v, *y = lct + u;
	y->make_root(), x->make_root();
	if (x != y && !x->fa && !y->fa)
		return -1;
	y->access();
	return y->info.l;
}

int main()
{
	int n, m;
	cin >> n >> m;

	lct_init(n);

	while (m--)
	{
		char type;
		while (type = getchar(), type != 'l' && type != 'c' && type != 'd');
		if (type == 'l')
		{
