#define MAXN 100005
#define MAXQ 400005

int n,q;

struct splaynode;

struct cycle begin
	int A,B;
	splaynode *ex;
end;

cycle _cyc[MAXN];
cycle *_cyc_p[MAXN],**_cyc_p_top=_cyc_p+1;

inline cycle * new_cycle(int A,int B,splaynode *ex){cycle *c=*(_cyc_p_top++);*c=(cycle){A,B,ex};return c;}
inline void del_cycle(cycle *c){*(--_cyc_p_top)=c;}

struct splaynode begin
	splaynode *s[2],*fa;
	bool rev;
	
	bool isedge;
	bool hascyc;
	
	bool hascyctag;
	
	cycle *cyctag;
	
	int totlen;
	
	int size;
	
	cycle *cyc;
	int len;
	
	inline void add_rev_tag()
	begin
		swap(s[0],s[1]);
		rev^=1;
	end;
	
	inline void add_cyc_tag(cycle *c)
	begin
		if isedge then cyc=c;
		cyctag=c;
		hascyctag=1;
		hascyc=c?1:0;
	end;
	
	inline void down()
	begin
		if rev then begin
			rev=0;
			if s[0] then s[0]->add_rev_tag();
			if s[1] then s[1]->add_rev_tag();
		end;
		if hascyctag then begin
			hascyctag=0;
			if s[0] then s[0]->add_cyc_tag(cyctag);
			if s[1] then s[1]->add_cyc_tag(cyctag);
		end;
	end;
	
	inline void update()
	begin
		hascyc=cyc?1:0;
		totlen=len;
		size=1;
		if s[0] then hascyc|=s[0]->hascyc,totlen+=s[0]->totlen,size+=s[0]->size;
		if s[1] then hascyc|=s[1]->hascyc,totlen+=s[1]->totlen,size+=s[1]->size;
	end;
end;

splaynode lcc[MAXN+MAXQ];
int nodecnt;

inline splaynode * new_edge_node(int len)
begin
	splaynode *ret=lcc+(++nodecnt);
	ret->isedge=1;
	ret->len=ret->totlen=len;
	ret->size=1;
	return ret;
end;

inline int get_parent(splaynode *x,splaynode *&fa)
begin
	return (fa=x->fa) ? fa->s[0]==x?0:fa->s[1]==x?1:-1 : -1;
end;

inline void rotate(splaynode *x)
begin
	int t1,t2;
	splaynode *fa,*gfa;
	t1=get_parent(x,fa);
	t2=get_parent(fa,gfa);
	fa->down();x->down();
	if (fa->s[t1]=x->s[t1^1]) then fa->s[t1]->fa=fa;
	fa->fa=x;x->fa=gfa;
	x->s[t1^1]=fa;
	if t2!=-1 then gfa->s[t2]=x;
	fa->update();
end;

inline splaynode * splay(splaynode *x)
begin
	while 1 do begin
		int t1,t2;
		splaynode *fa,*gfa;
		t1=get_parent(x,fa);
		if t1==-1 then break;
		t2=get_parent(fa,gfa);
		if t2!=-1 then gfa->down(),t2=gfa->s[1]==fa;
		if t2==-1 then begin
			rotate(x);break;
		end else if t1==t2 then begin
			rotate(fa);rotate(x);
		end else begin
			rotate(x);rotate(x);
		end;
	end;
	x->down();x->update();
	return x;
end;

inline int getrank(splaynode *x)
begin
	return splay(x),1+(x->s[0]?x->s[0]->size:0);
end;

inline splaynode * access(splaynode *x)
begin
	splaynode *ret=NULL;
	while x do begin
		splay(x);
		splaynode *t=x->s[0];
		if !t then begin
			x->s[1]=ret;
			(ret=x)->update();
			break;
		end;
		while t->s[1] do t->down(),t=t->s[1];
		splay(t);
		if !t->cyc then begin
			splay(x)->s[1]=ret;
			(ret=x)->update();
			x=x->fa;
		end else begin
			cycle *c=t->cyc;
			splaynode *A=lcc+c->A,*B=lcc+c->B;
			splay(c->ex);
			if splay(B)->fa==A then begin  // 2B type-A
				B->s[1]=NULL,B->update();
			end else if splay(A)->fa==B then begin  // 2B type-B
				swap(A,B);swap(c->A,c->B);c->ex->add_rev_tag();
				splay(B)->s[1]=NULL,B->update();
			end else begin
				if getrank(A)>getrank(B) then swap(A,B),swap(c->A,c->B),c->ex->add_rev_tag();
				splay(B)->s[1]=NULL,B->update();
				splay(A)->s[1]=NULL,A->update();
			end;
			splay(B)->s[1]=c->ex,c->ex->fa=B,B->update();
			splay(x);
			
			if x->s[1]->totlen<x->s[0]->totlen then x->add_rev_tag(),x->down();
			c->ex=x->s[1];x->s[1]->fa=NULL;x->s[1]=NULL;x->update();c->B=x-lcc;
			splay(x)->s[1]=ret,x->update();
			if splay(A)->s[1] then begin
				ret=x;x=A;
			end else begin
				A->s[1]=x;x->fa=A;A->update();
				ret=A;x=A->fa;
			end;
		end;
	end;
	return ret;
end;

inline void setroot(int x)
begin
	access(lcc+x)->add_rev_tag();
end;

inline int query(int x,int y)
begin
	if x==y then return 0;
	setroot(x);
	splaynode *t=access(lcc+y);
	while t->s[0] do t->down(),t=t->s[0];
	return splay(t)==lcc+x ? t->totlen : -1;
end;

inline bool link(int x,int y,int len)
begin
	if x==y then return 0;
	setroot(x);
	splaynode *t=access(lcc+y);
	while t->s[0] do t->down(),t=t->s[0];
	if splay(t)!=lcc+x then begin
		splaynode *t=new_edge_node(len);
		t->fa=splay(lcc+x);
		lcc[x].s[0]=t;
		lcc[x].fa=lcc+y;
		lcc[x].update();
		return 1;
	end;
	if t->hascyc then return 0;
	splaynode *ex=new_edge_node(len);
	cycle *c=new_cycle(x,y,ex);
	ex->add_cyc_tag(c);
	t->add_cyc_tag(c);
	access(lcc+y);
	return 1;
end;

inline bool cut(int x,int y,int len)
begin
	if x==y then return 0;
	setroot(x);
	splaynode *t=access(lcc+y);
	while t->s[0] do t->down(),t=t->s[0];
	if splay(t)!=lcc+x then return 0;
	if !t->hascyc then begin
		if t->totlen!=len then return 0;
		if getrank(lcc+y)!=3 then return 0;
		splaynode *e=splay(lcc+x)->s[1];
		if e->s[0] then e->down(),e=e->s[0];
		splay(e);
		e->s[0]->fa=NULL;e->s[1]->fa=NULL;
		return 1;
	end;
	t=t->s[1];
	while t->s[0] do t->down(),t=t->s[0];
	cycle *c=splay(t)->cyc;
	
	splaynode *t1=splay(lcc+y)->s[0];
	while t1->s[1] do t1->down(),t1=t1->s[1];
	cycle *c1=splay(t1)->cyc;
	if c!=c1 then return 0;
	
	splay(t);
	if c->ex->size==1 && c->ex->len==len then begin
		t->add_cyc_tag(NULL);
		del_cycle(c);
		return 1;
	end;
	if t->size>3 then return 0;
	if t->len!=len then return 0;
	lcc[x].fa=lcc[y].fa=NULL;
	t=c->ex,t->add_rev_tag(),t->add_cyc_tag(NULL);
	del_cycle(c);
	t->fa=lcc+x;lcc[x].s[1]=t;lcc[x].update();
	while t->s[1] do t->down(),t=t->s[1];
	splay(t)->s[1]=lcc+y,lcc[y].fa=t,t->update();
	return 1;
end;

inline void init()
begin
	nodecnt=n;
	int i;
	for i=1;i<=n;i++ do lcc[i].size=1,_cyc_p[i]=_cyc+i;
end;

int main()
begin
	read(n);read(q);
	init();
