#define rc ch[x][1]
int prt[MAXN],ch[MAXN][2],cir[MAXN][2],sqr[MAXN],rev[MAXN],iscir[MAXN];
int sum[MAXN],len[MAXN];
int cnt;
bool isroot(int x){return ch[prt[x]][0]!=x&&ch[prt[x]][1]!=x;}
void reverse(int x){swap(lc,rc);rev[x]^=1;}
void Pushdown(int x)
{
    if(rev[x])
    {
        if(lc)reverse(lc);
        if(rc)reverse(rc);
        if(sqr[x])swap(cir[x][0],cir[x][1]);
        rev[x]=0;
    }
}
void Maintain(int x)
{
    iscir[x]=iscir[lc]|sqr[x]|iscir[rc];
    sum[x]=sum[lc]+len[x]+sum[rc];
}
void Rot(int x)
{
    int f=prt[x],g=prt[f];
    int L=ch[f][0]!=x,R=L^1;
    prt[f]=x;prt[x]=g;prt[ch[x][R]]=f;
    ch[f][L]=ch[x][R];ch[x][R]=f;
    if(ch[g][0]==f)ch[g][0]=x;
    if(ch[g][1]==f)ch[g][1]=x;
    if(cir[g][0]==f)cir[g][0]=x;
    if(cir[g][1]==f)cir[g][1]=x;
    Maintain(f);Maintain(x);
}
void Splay(int x)
{
    Pushdown(x);
    while(!isroot(x))
    {
        int f=prt[x],g=prt[f];
        Pushdown(g);Pushdown(f);Pushdown(x);
        if(!isroot(f))
            if(ch[g][0]==f^ch[f][0]==x)Rot(x);
            else Rot(f);
        Rot(x);
    }
}
void reset(int u,int x)
{
    Splay(x);
    len[u]=min(sum[lc],sum[rc]);
    prt[cir[u][0]=lc]=u;prt[cir[u][1]=rc]=u;
    lc=rc=0;
    Maintain(x);
    prt[ch[u][1]=x]=u;Maintain(u);
}
void Access(int x)
{
    int t=0;
    while(x)
    {
        Splay(x);
        int u=prt[x];
        if(sqr[u])
        {
            Splay(u);
            int p=ch[u][1];ch[u][1]=0;Maintain(u);
            Pushdown(p);while(ch[p][0])Pushdown(p=ch[p][0]);
            Splay(p);
            prt[ch[p][0]=cir[u][0]]=p;prt[ch[p][1]=cir[u][1]]=p;Maintain(p);
            cir[u][0]=cir[u][1]=0;
            reset(u,x);
        }
        ch[x][1]=t;Maintain(x);
        t=x;x=prt[x];
    }
}
void Evert(int x)
{
    Access(x);
    Splay(x);
    reverse(x);
}
int Get(int x)
{
    Access(x);
    Splay(x);
    while(ch[x][0])Pushdown(x=ch[x][0]);
    return x;
}
map<pair<pair<int,int>,int>,int> M;
bool Link(int u,int v,int w)
{
    if(u==v)return false;
    M[make_pair(make_pair(u,v),w)]++;
    Evert(u);
    if(Get(v)==u)
    {
        Access(v);Splay(v);
        if(iscir[v])return false;
        cnt++;
        len[cnt]=sum[cnt]=w;
        prt[ch[v][1]=cnt]=v;
        Maintain(v);
        Splay(u);prt[ch[u][1]]=0;ch[u][1]=0;Maintain(u);
        cnt++;
        prt[cnt]=u;sqr[cnt]=1;
        reset(cnt,v);
    }
    else
    {
        cnt++;
        len[cnt]=sum[cnt]=w;
        prt[prt[u]=cnt]=v;
    }
    return true;
}
bool Cut(int u,int v,int w)
{
    if(!M[make_pair(make_pair(u,v),w)])return false;
    M[make_pair(make_pair(u,v),w)]--;
    Evert(u);Access(v);Splay(v);
    if(iscir[v])
    {
        Pushdown(u);
        int p=(ch[v][0]==u?ch[u][1]:ch[v][0]);
        Splay(p);
        prt[u]=prt[v]=0;
        int s=(len[cir[p][0]]==w&&!ch[cir[p][0]][0]&&!ch[cir[p][0]][1])?cir[p][1]:cir[p][0];
        if(s==cir[p][1])reverse(cir[p][1]);
        prt[s]=v;ch[v][0]=s;Maintain(v);
        prt[v]=u;ch[u][1]=v;Maintain(u);
        prt[u]=0;
    }
    else prt[ch[v][0]]=0,ch[v][0]=0,prt[u]=0,Maintain(v);
    return true;
}
int Cal(int u,int v)
{
    Evert(u);
    if(Get(v)!=u)return -1;
    return sum[v];
}
int main()
{
    int n,m;
    scanf("%d%d",&n,&m);
    cnt=n;
    char cmd[10];
    int u,v,w;
    while(m--)
    {
        scanf("%s",cmd);
        if(cmd[0]=='l')
        {
            scanf("%d%d%d",&u,&v,&w);
            if(u>v)swap(u,v);
            if(Link(u,v,w))cout<<"ok\n";
            else cout<<"failed\n";
        }
        if(cmd[0]=='c')
        {
            scanf("%d%d%d",&u,&v,&w);
            if(u>v)swap(u,v);
            if(Cut(u,v,w))cout<<"ok\n";
            else cout<<"failed\n";
        }
        if(cmd[0]=='d')
        {
            scanf("%d%d",&u,&v);
            cout<<Cal(u,v)<<'\n';
        }
    }


	return 0;
}

