int EMP;

namespace LCC {
	struct node {
		int ch[3], fa;
		int dis, sum_dis;
		int cnt_cir;
		bool rev, kd;
	}a[maxN];
	int tot;

	inline void set(int x, int d, int y) {
		a[x].ch[d] = y;
		if (y) a[y].fa = x;
	}

	inline bool isrt(int x) { // splay root
		int y = a[x].fa;
		return !y || (a[y].ch[0] != x && a[y].ch[1] != x); // not inclue ch[2]
	}

	int anc(int x) {
		while (!isrt(x)) x = a[x].fa;
		return x;
	}

	inline void pushup(int x) {
		if (a[x].kd == 0) {
			a[x].sum_dis = a[x].dis; a[x].cnt_cir = 0;
			rep (d, 0, 2) if (a[x].ch[d])
				a[x].sum_dis += a[a[x].ch[d]].sum_dis,
				a[x].cnt_cir += a[a[x].ch[d]].cnt_cir;
		}
		else {
			a[x].sum_dis = INF; a[x].cnt_cir = 1;
			rep (d, 0, 1) if (a[x].ch[d])
				Min(a[x].sum_dis, a[a[x].ch[d]].sum_dis),
				a[x].cnt_cir += a[a[x].ch[d]].cnt_cir;
		}
	}

	inline void torev(int x) {
		a[x].rev ^= 1;
		swap(a[x].ch[0], a[x].ch[1]);
		if (a[x].ch[2])
			swap(a[a[x].ch[2]].ch[0], a[a[x].ch[2]].ch[1]); // no rev tag
	}

	inline void pushdown(int x) {
		if (a[x].rev) {
			rep (d, 0, 1) if (a[x].ch[d]) // not inclue ch[2]
				torev(a[x].ch[d]);
			a[x].rev = 0;
		}
	}

	void clear(int x) {
		static int stack[maxN], Top;
		for (Top = 0; !isrt(x); x = a[x].fa) stack[++Top] = x;
		for (stack[++Top] = x; Top; --Top) pushdown(stack[Top]);
	}

	int find(int x, int dir) {
		for (pushdown(x); a[x].ch[dir]; pushdown(x = a[x].ch[dir]));
		//splay(x);
		return x;
	}

	inline void rot(int x) {
		int y = a[x].fa, z = a[y].fa, D = a[y].ch[1] == x, s = a[x].ch[!D];
		if (!isrt(y)) a[z].ch[a[z].ch[1] == y] = x;
		else if (a[z].ch[2] == y) a[z].ch[2] = x;
		a[y].ch[D] = s; a[x].ch[!D] = y;
		if (s) a[s].fa = y; a[y].fa = x, a[x].fa = z;
		pushup(y), pushup(x); //
	}

	void splay(int x, int &to = EMP) { // &, 否则for停不了 
		for (clear(x); !isrt(x) && x != to; rot(x)) {
			int y = a[x].fa;
			if (isrt(y) || y == to) continue;
			int z = a[y].fa;
			rot( ((a[z].ch[1] == y) == (a[y].ch[1] == x)) ? y : x );
		}
	}

	void pos_swap(int u, int c, int v) { // u -> ch[2] = c, u -> ch[1] = v
		rep (d, 0, 1) set(v, d, a[c].ch[d]);
		set(u, 1, c), set(u, 2, v); 
		pushup(v);
	}

	void access(int x) {
		for (int t = 0; x; t = x, x = a[x].fa) {
			int c = anc(x);
			if (a[c].kd == 0) {
				splay(x);
				a[x].ch[1] = t, a[t].fa = x;
				pushup(x);
			}
			else {
				int u = a[c].fa;
				splay(u); //
				int v = find(a[u].ch[1], 0);
				splay(v, a[u].ch[1]); 
				pos_swap(u, c, v);
				splay(x, a[u].ch[2]);
				pos_swap(u, x, c);
				a[x].ch[0] = 0, a[x].ch[1] = t, a[t].fa = x;
				pushup(x);
			}
		}
	}

	inline void ac(int x) {
		access(x);
		splay(x);
	}

	inline void chgrt(int x) {
		ac(x);
		torev(x);
	}

	inline void link(int x, int y) {
		chgrt(x); 
		a[x].fa = y;
		//ac(x);
	}

	inline void cut(int x, int y) {
		chgrt(x);
		ac(y);
		splay(x, a[y].ch[0]);
		if (!a[x].ch[1]) {
			a[x].fa = 0; a[y].ch[0] = 0;
			pushup(y);
		}
		else {
			int z = a[a[x].ch[1]].ch[2];
			a[x].fa = 0; a[y].ch[0] = 0; a[x].ch[1] = 0;
			set(x, !(a[z].ch[1] != 0), y);
			rep (d, 0, 1) set(y, d, a[z].ch[d]);
			pushup(y), pushup(x); //
		}
	}

	inline bool addedge(int x, int y, int z) {
		if (x == y) return 0;
		int ed = ++tot;
		a[ed].dis = a[ed].sum_dis = z;

		chgrt(x);
		ac(y);
		int t = find(y, 0);
		if (find(y, 0) == x) { 
			splay(x, a[y].ch[0]);
			if (a[x].cnt_cir > 0) return 0;
			int c = ++tot, t = ++tot; a[t].kd = 1;
			set(y, 0, c), set(c, 0, x), set(c, 2, t);
			set(t, 0, a[x].ch[1]), set(t, 1, ed);
			a[x].ch[0] = a[x].ch[1] = 0; //
			pushup(x), pushup(t), pushup(c), pushup(y); //
		}
		else {
			link(x, ed);
			link(ed, y);
			splay(t);
		}
		mp[edge(x, y, z)].push_back(ed);
		return 1;
	}

	inline bool cutedge(int x, int y, int z) {
		if (mp[edge(x, y, z)].empty()) return 0;
		int ed = mp[edge(x, y, z)].back(); mp[edge(x, y, z)].pop_back();
		cut(x, ed);
		cut(ed, y);
		return 1;
	}

	inline int get(int x, int y) {
		chgrt(x);
		ac(y);
		if (find(y, 0) != x) return -1;
		splay(x, a[y].ch[0]);
		return a[x].sum_dis;
	}
}

int main() {

	LCC::tot = n = ri(), m = ri();
	while (m--) {
		static char opr[13]; scanf("%s", opr);
		if (opr[0] == 'd') {
			int x = ri(), y = ri();
			printf("%d\n", LCC::get(x, y));
		}
		else if (opr[0] == 'l') {
			int x = ri(), y = ri(), z = ri(); if (x > y) swap(x, y);
			puts(LCC::addedge(x, y, z) ? "ok" : "failed");
		}
		else {
			int x = ri(), y = ri(), z = ri(); if (x > y) swap(x, y);
			puts(LCC::cutedge(x, y, z) ? "ok" : "failed");
		}
	}

	return 0;
}

