struct IO_Tp
{
	static const int _I_Buffer_Size = 15 << 20;
	char _I_Buffer[_I_Buffer_Size], *_I_pos = _I_Buffer;
	
	static const int _O_Buffer_Size = 15 << 20;
	char _O_Buffer[_O_Buffer_Size], *_O_pos = _O_Buffer;
	
	IO_Tp()
	{
		fread(_I_Buffer, 1, _I_Buffer_Size, stdin);
	}
	
	~IO_Tp()
	{
		fwrite(_O_Buffer, 1, _O_pos - _O_Buffer, stdout);
	}
	
	IO_Tp &operator>>(int &res)
	{
		while (!isdigit(*_I_pos))
			++_I_pos;
		res = *_I_pos++ & 15;
		while (isdigit(*_I_pos))
			(res *= 10) += *_I_pos++ & 15;
		return *this;
	}
	
	char getop()
	{
		while (!isalpha(*_I_pos))
			_I_pos++;
		return *_I_pos++;
	}
	
	IO_Tp &operator<<(int n)
	{
		static char _buf[10];
		char *_pos(_buf);
		if (n < 0)
			*_O_pos++ = '-', n = -n;
		do
			*_pos++ = '0' + n % 10;
		while (n /= 10);
		while (_pos != _buf)
			*_O_pos++ = *--_pos;
		return *this;
	}
	
	IO_Tp &operator<<(char ch)
	{
		*_O_pos++ = ch;
		return *this;
	}
	
	IO_Tp &operator<<(const char *s)
	{
		while (*s)
			*_O_pos++ = *s++;
		return *this;
	}
} IO;

const int Max_N = 100005;

template<typename _Tp>
struct Splay_Tree
{
	const static int _M_size = Max_N * 4;
	
	static Splay_Tree<_Tp> _M_p[_M_size], *_M_cur;
	static Splay_Tree<_Tp> *_M_rc[_M_size], **_M_rc_cur;
	
	void *operator new(size_t size)
	{
		return _M_rc_cur == _M_rc ? --_M_cur : *--_M_rc_cur;
	}
	
	void *operator new[](size_t size)
	{
		return _M_cur -= size / sizeof(Splay_Tree);
	}
	
	void operator delete(void *ptr)
	{
		*_M_rc_cur++ = static_cast<Splay_Tree *>(ptr);
	}

	static Splay_Tree *Null;
	
	Splay_Tree *ch[2], *parent;
	bool cycle, rev;
	_Tp data;
	
	Splay_Tree(const _Tp __data = _Tp()) : cycle(false), rev(false), data(__data)
	{
		static bool init(false);
		if (!init)
		{
			init = true;
			Null = new Splay_Tree, Null->ch[0] = Null->ch[1] = Null->parent = Null;
		}
		ch[0] = ch[1] = parent = Null;
	}
	
	bool is_twist()
	{ return cycle && !ch[0]->cycle && !ch[1]->cycle; }
	
	bool is_root()
	{ return (parent->ch[0] != this && parent->ch[1] != this) || parent->is_twist(); }
	
	bool dir() const
	{ return parent->ch[1] == this; }
	
	Splay_Tree *sch(const int d, Splay_Tree *c)
	{ return ch[d] = c, c->parent = this; }
	
	void pushup()
	{ cycle = ch[0]->cycle || ch[1]->cycle; data.pushup(ch[0]->data, ch[1]->data); }
	
	void pushup_twist()
	{ data.pushup_twist(ch[0]->data, ch[1]->data); }
	
	void reverse()
	{ rev ^= 1, std::swap(ch[0], ch[1]); }
	
	void pushdown()
	{ if (rev) ch[0]->reverse(), ch[1]->reverse(), rev = false; data.pushdown(ch[0]->data, ch[1]->data); }
	
	void pushdown_twist()
	{ data.pushdown_twist(ch[0]->data, ch[1]->data); }
	
	void rotate()
	{
		Splay_Tree *p = parent;
		bool d = dir();
		p->pushdown(), pushdown();
		if (parent = p->parent, p->parent->ch[p->dir()] == p)
			p->parent->ch[p->dir()] = this;
		p->sch(d, ch[!d])->pushup(), sch(!d, p)->pushup();
	}
	
	Splay_Tree *splay()
	{
		for (pushdown(); !is_root(); rotate())
			if (!parent->is_root())
				parent->parent->pushdown(), (parent->dir() == dir() ? parent : this)->rotate();
		return this;
	}
};
template<typename _Tp>
Splay_Tree<_Tp> *Splay_Tree<_Tp>::Null;

template<typename _Tp>
Splay_Tree<_Tp> Splay_Tree<_Tp>::_M_p[_M_size];
template<typename _Tp>
Splay_Tree<_Tp> *Splay_Tree<_Tp>::_M_cur = _M_p + _M_size;
template<typename _Tp>
Splay_Tree<_Tp> *Splay_Tree<_Tp>::_M_rc[_M_size];
template<typename _Tp>
Splay_Tree<_Tp> **Splay_Tree<_Tp>::_M_rc_cur = _M_rc;

template<typename _Tp>
void retwist(Splay_Tree<_Tp> *o)
{
	o->parent->parent->splay();
	if (!o->parent->parent->is_root())
	{
		o->parent->parent->splay();
		if (o->parent->parent->dir() == 0)
			o->parent->parent->rotate();
		o->parent->parent->parent->ch[1] = o;
	}
	o->parent->pushdown_twist(), o->pushdown();
	Splay_Tree<_Tp> *p = o->parent->parent->parent;
	bool d = o->dir();
	o->parent->parent->sch(d, o->ch[!d])->sch(!d, o->parent->ch[!d])->pushup();
	o->parent->sch(d, o->ch[d])->sch(!d, o->parent->parent)->pushup_twist();
	o->ch[1] = Splay_Tree<_Tp>::Null, o->sch(0, o->parent)->pushup();
	o->parent = p;
	if (!o->is_root())
		o->rotate();
}

template<typename _Tp>
void access(Splay_Tree<_Tp> *o)
{
	if (o->splay()->parent->is_twist())
		retwist(o);
	o->ch[1] = Splay_Tree<_Tp>::Null, o->pushup();
	for (Splay_Tree<_Tp> *p = o->parent; p != Splay_Tree<_Tp>::Null; p->ch[1] = o, o->rotate(), p = o->parent)
		if (p->splay()->parent->is_twist())
			retwist(p);
}

template<typename _Tp>
inline void evert(Splay_Tree<_Tp> *o)
{
	access(o), o->reverse();
}

template<typename _Tp>
bool link(Splay_Tree<_Tp> *o1, Splay_Tree<_Tp> *o2, const _Tp &data)
{
	if (o1 == o2)
		return false;
	evert(o1), access(o2);
	if (o1->parent == Splay_Tree<_Tp>::Null)
	{
		Splay_Tree<_Tp> *e = new Splay_Tree<_Tp>(data);
		o1->sch(0, e)->pushup(), o2->sch(1, o1)->pushup();
		return true;
	}
	else if (!o2->cycle)
	{
		o2->ch[0] = Splay_Tree<_Tp>::Null, o2->ch[0] = o1->splay();
		Splay_Tree<_Tp> *e = new Splay_Tree<_Tp>(data);
		Splay_Tree<_Tp> *t = new Splay_Tree<_Tp>;
		t->cycle = true;
		t->sch(0, o1->ch[1])->sch(1, e)->pushup_twist(), o1->sch(1, t)->pushup(), o2->pushup();
		return true; 
	}
	else
		return false;
}

template<typename _Tp>
bool cut(Splay_Tree<_Tp> *o1, Splay_Tree<_Tp> *o2, const _Tp &data)
{
	if (o1 == o2)
		return false;
	evert(o1), access(o2);
	if (o1->parent != Splay_Tree<_Tp>::Null)
		if (!o1->ch[1]->is_twist())
			if (o1->ch[1]->data == data)
			{
				delete o1->ch[1];
				o2->ch[0] = o1->parent = o1->ch[1] = Splay_Tree<_Tp>::Null, o2->pushup();
				return true;
			}
			else
				return false;
		else
			if (o1->ch[1]->pushdown_twist(), o1->ch[1]->ch[0]->data == data || o1->ch[1]->ch[1]->data == data)
			{
				o1->ch[1]->ch[1]->reverse();
				bool d(o1->ch[1]->ch[1]->data == data);
				Splay_Tree<_Tp> *t(o1->ch[1]->ch[!d]);
				delete o1->ch[1]->ch[d], delete o1->ch[1];
				o1->sch(1, t)->pushup(), o2->pushup();
				return true;
			}
			else 
				return false;
	else
		return false;
}

struct agg_Tp
{
	int cost, sum, min, lazy;
	
	agg_Tp() : cost(0), sum(0), min(2147483647), lazy(0) { }
	agg_Tp(int _cost, int _val) : cost(_cost), sum(_cost), min(_val), lazy(0) { }
	
	void pushup(const agg_Tp &a0, const agg_Tp &a1)
	{
		sum = a0.sum + a1.sum + cost;
		min = std::min(a0.min, a1.min);
	}
	
	void pushup_twist(const agg_Tp &a0, const agg_Tp &a1)
	{
		sum = std::min(a0.sum, a1.sum);
		if (a0.sum == a1.sum)
			min = -1;
		else
			min = a0.sum < a1.sum ? a0.min : a1.min;
	}
	
	void modify(const int _val)
	{
		if (min != 2147483647)
			lazy += _val, min += _val;
	}
	
	void pushdown(agg_Tp &a0, agg_Tp &a1)
	{
		if (lazy)
			a0.modify(lazy), a1.modify(lazy), lazy = 0;
	}
	
	void pushdown_twist(agg_Tp &a0, agg_Tp &a1)
	{
		if (lazy)
			(a0.sum < a1.sum ? a0 : a1).modify(lazy), lazy = 0;
	}
};

inline bool operator==(const agg_Tp &a0, const agg_Tp &a1)
{
	return a0.cost == a1.cost && a0.min == a1.min;
}

template<typename _Tp>
inline bool modify(Splay_Tree<_Tp> *o1, Splay_Tree<_Tp> *o2, const int x)
{
	evert(o1), access(o2);
	if (o1->parent == Splay_Tree<_Tp>::Null || o2->data.min == -1)
		return false;
	o2->data.modify(x);
	return true;
}

Splay_Tree<agg_Tp> *node0;
#define node(x) (node0 + x)
