int main(int argc, char** argv)
{
	IO >> N >> M;
	node0 = new Splay_Tree<agg_Tp>[N + 1];
	while (M--)
		switch (IO.getop())
		{
			int v, w, c, x;
			
			case 'l':
				IO >> v >> w >> c >> x;
				IO << (link(node(v), node(w), agg_Tp(c, x)) ? "ok\n" : "failed\n");
				break;
			
			case 'c':
				IO >> v >> w >> c >> x;
				IO << (cut(node(v), node(w), agg_Tp(c, x)) ? "ok\n" : "failed\n");
				break;
			
			case 'd':
				IO >> v >> w;
				if (v == w)
				{
					IO << "0 2147483647\n";
					break;
				}
				evert(node(v)), access(node(w));
				if (node(v)->parent != Splay_Tree<agg_Tp>::Null)
					IO << node(w)->data.sum << ' ' << node(w)->data.min << '\n'; 
				else
					IO << "-1 -1\n"; 
				break;
			
			case 'a':
				IO >> v >> w >> x;
				IO << (modify(node(v), node(w), x) ? "ok\n" : "failed\n");
