namespace Task3
{
	const int MaxN = 50;
	const int MaxM = 1500;
	const int MaxRK = 100;

	const int MaxW = 65536;
	const int WINF = MaxW * MaxM * 2;

	struct halfEdge
	{
		int u, w;
		halfEdge *next;
	};
	halfEdge adj_pool[MaxM * 2], *adj_tail;
	halfEdge *adj[MaxN + 1];

	int vFS, vFT;

	inline void adj_init()
	{
		adj_tail = adj_pool;
		for (int v = 1; v <= n; v++)
			adj[v] = NULL;
	}

	int tot_flows;
	int tot_flows_bak;
	int flow_bak[MaxM * 2];

	inline void flow_backup()
	{
		tot_flows_bak = tot_flows;
		int l = adj_tail - adj_pool;
		for (int i = 0; i < l; i++)
			flow_bak[i] = adj_pool[i].w;
	}
	inline void flow_recover()
	{
		tot_flows = tot_flows_bak;
		int l = adj_tail - adj_pool;
		for (int i = 0; i < l; i++)
			adj_pool[i].w = flow_bak[i];
	}

	inline halfEdge *oppo(halfEdge *e)
	{
		return adj_pool + ((e - adj_pool) ^ 1);
	}

	inline void addEdge(int v, int u, int w)
	{
		adj_tail->u = u, adj_tail->w = w, adj_tail->next = adj[v], adj[v] = adj_tail++;
		adj_tail->u = v, adj_tail->w = 0, adj_tail->next = adj[u], adj[u] = adj_tail++;
	}

	int dist[MaxN + 1];

	int dfs(int v, int delta)
	{
		if (v == vFT)
			return delta;
		int flow = 0;
		for (halfEdge *e = adj[v]; e; e = e->next)
			if (e->w > 0 && dist[v] == dist[e->u] + 1)
			{
				int d = dfs(e->u, min(delta - flow, e->w));
				flow += d;
				e->w -= d, oppo(e)->w += d;
				if (flow == delta)
					return flow;
			}
		if (flow == 0)
			dist[v] = n;
		return flow;
	}

	inline void calc_dist()
	{
		int q_n = 0;
		static int q[MaxN];

		for (int v = 1; v <= n; v++)
			dist[v] = n;

		dist[vFT] = 0, q[q_n++] = vFT;
		for (int i = 0; i < q_n; i++)
		{
			int v = q[i];
			for (halfEdge *e = adj[v]; e; e = e->next)
				if (oppo(e)->w > 0 && dist[e->u] == n)
					dist[e->u] = dist[v] + 1, q[q_n++] = e->u;
		}
	}

	inline int calc_flows(int lim = WINF)
	{
		tot_flows = 0;
		while (tot_flows < lim && (calc_dist(), dist[vFS] != n))
			tot_flows += dfs(vFS, lim - tot_flows);
		return tot_flows;
	}

	struct item
	{
		vector<bool> free;
		vector<bool> must;

		int w0, w1;
		vector<bool> cut0, cut1;

		inline void calcw()
		{
			vFS = vS, vFT = vT;
			adj_init();

			int inh_w = 0;
			for (int i = 0; i < m; i++)
			{
				if (free[i])
					addEdge(ev[i], eu[i], ew[i]);
				else if (!must[i])
					addEdge(ev[i], eu[i], WINF);
				else
					inh_w += ew[i];
			}

			calc_flows();

			if (tot_flows == WINF)
			{
				w0 = w1 = WINF;
				return;
			}

			w0 = inh_w + tot_flows;

			calc_dist();

			static bool typeV[MaxN + 1];
			for (int v = 1; v <= n; v++)
				typeV[v] = dist[v] != n;

			cut0.clear();
			for (int i = 0; i < m; i++)
			{
				if (free[i])
					cut0.push_back(!typeV[ev[i]] && typeV[eu[i]]);
				else
					cut0.push_back(must[i]);
			}

			static int fS[MaxN + 1], fT[MaxN + 1];
			flow_backup();
			for (int v = 1; v <= n; v++)
			{
				if (!typeV[v])
				{
					vFS = vS, vFT = v;
					fS[v] = calc_flows();
				}
				else
				{
					vFS = v, vFT = vT;
					fT[v] = calc_flows();
				}
				flow_recover();
			}

			w1 = WINF;
			int w1_i = -1;
			for (int i = 0; i < m; i++)
				if (free[i])
				{
					if (!typeV[ev[i]] && typeV[eu[i]])
					{
						if (tension(w1, w0 + min(fS[ev[i]], fT[eu[i]])))
							w1_i = i;
					}
					else
					{
						if (tension(w1, w0 + ew[i]))
							w1_i = i;
					}
				}

			if (w1_i == -1)
				return;

			if (!typeV[ev[w1_i]] && typeV[eu[w1_i]])
			{
				vFS = vS, vFT = vT;

				adj_init();

				for (int i = 0; i < m; i++)
				{
					if (free[i])
						addEdge(ev[i], eu[i], w1_i != i ? ew[i] : WINF);
					else if (!must[i])
						addEdge(ev[i], eu[i], WINF);
				}

				calc_flows();

				calc_dist();

				cut1.clear();
				for (int i = 0; i < m; i++)
				{
					if (free[i])
						cut1.push_back(dist[ev[i]] == n && dist[eu[i]] != n);
					else
						cut1.push_back(must[i]);
				}
			}
			else
			{
				cut1 = cut0;
				cut1[w1_i] = true;
			}
		}

		friend inline bool operator<(const item &lhs, const item &rhs)
		{
			return lhs.w1 > rhs.w1;
		}
	};

	void solve()
	{
		item st;
		st.free = vector<bool>(m, true);
		st.must = vector<bool>(m, false);
		st.calcw();

		if (st.w0 == WINF)
		{
			printf("-1\n");
			return;
		}
		printf("%d\n", st.w0);

		priority_queue<item> q;
		if (st.w1 != WINF)
			q.push(st);

		for (int i = 1; i < rk; i++)
		{
			if (q.empty())
			{
				printf("-1\n");
				return;
			}

			item cur = q.top();
			q.pop();

			printf("%d\n", cur.w1);

			int p = -1;
			for (int k = 0; k < m; k++)
				if (!cur.cut0[k] && cur.cut1[k])
				{
					p = k;
					break;
				}

			item next = cur;
			next.free[p] = false;

			next.must[p] = true;
			next.calcw();
			if (next.w1 != WINF)
				q.push(next);

			next.must[p] = false;
			next.calcw();
			if (next.w1 != WINF)
				q.push(next);
		}
	}
}

