namespace pri_queue {
#define N 150020
	struct Element {
		LL sum;
		int locate, status;
		Element(LL sum=0, int locate=0, int status=0) : sum(sum), locate(locate), status(status) {}
	};
	
	struct cmp {
		bool operator () (const Element &a, const Element &b) {
			if (a.sum != b.sum) return a.sum > b.sum;
			return a.sum > b.sum;
		} 
	};
	
	priority_queue <Element, vector<Element>, cmp> q;
	
	struct Edges {
		int a, b;
		bool s, t;
	} edge[N*2];
	
	bool operator < (const Edges &a, const Edges &b) {
		if (a.s + a.t != b.s + b.t) return a.s + a.t < b.s + b.t;
		if (a.s + a.t) return a.s < b.s;
		if (a.a != b.a) return a.a < b.a;
		return a.b < b.b;
	}
	
	int e1[N], e2[N];
	LL ans;
	
	Element pluspresent(Element x) {
		if (x.status < 2) {
			x.status ++;
			if (x.status == 1) x.sum += e1[x.locate];
			else               x.sum += e2[x.locate];
		} else {
			x.status = -1;
		}
		return x;
	}
	
	Element plusnext(Element x) {
		if (x.status != 1 || x.locate == n-2 || x.locate <= 1) {
			x.status = -1;
		} else {
			x.sum -= e1[x.locate];
			x.status --;
			x.locate ++;
			x.status = 0;
			x = pluspresent(x);
		}
		return x;
	}
	
	Element plusnext2(Element x) {
		if (x.locate == n-2) {
			x.status = -1;
		} else {
			x.locate ++;
			x.status = 0;
			x = pluspresent(x);
		}
		return x;
	}
	
