			if (y==t) e2[x] = w;
		}
		ans = 0;
		for (int i=1;i<=n;i++) {
			if (e1[i] < e2[i]) swap(e1[i], e2[i]);
			ans += e2[i];
			e1[i] -= e2[i];
			edge[i].a = e1[i]; edge[i].b = e2[i];
		}
		edge[s].s = true; edge[t].t = true;
		sort(edge+1, edge+n+1);
		for (int i=1;i<=n-2;i++) {
			e1[i] = edge[i].a;
			e2[i] = edge[i].b;
		}
		q.push(Element(ans, 1, 0));
		while (k--) {
			if (q.empty()) {
				puts("-1");
				break;
			}
			Element x = q.top(), y;
			printf("%lld\n", x.sum);
			q.pop();
			y = pluspresent(x); if (y.status >= 0) q.push(y);
			y = plusnext   (x); if (y.status >= 0) q.push(y);
			y = plusnext2  (x); if (y.status >= 0) q.push(y);
		}
	}
