namespace Right_Answer {
#define N 102
#define M 1502

	struct EDGE {
		int src, adj, w, next, ori;
	} edge[M*2];
	
	int gh[N], top, pot[M*2];
	
	struct Status {
		int sbest, where;
		bitset <M> fcut, ncut;
		//int fcut[M], ncut[M];
	};
	
	namespace MaxFlow {
	
		void addedge(int x, int y, int w) {
			edge[++top].adj = y;
			edge[top].src = x;
			edge[top].w = w;
			edge[top].ori = w;
			edge[top].next = gh[x];
			gh[x] = top;
			edge[++top].adj = x;
			edge[top].src = y;
			edge[top].w = 0;
			edge[top].ori = 0;
			edge[top].next = gh[y];
			gh[y] = top;
		}
		
		int dist[N], queue[N], h[N], vh[N], bh[N], bvh[N], det;
		int start, terminal, ans, calc, mc;
		LL eval[2];
		
		int bfs(int S, int T) {
			for (int i=1;i<=n;i++) dist[i] = 0;
			queue[1] = S; dist[S] = 1; int head = 0, tail = 1;
			while (head < tail) {
				int x = queue[++head];
				for (int p=gh[x]; p; p=edge[p].next)
					if (!dist[edge[p].adj] && edge[p].w) {
						dist[edge[p].adj] = dist[x] + 1;
						queue[++tail] = edge[p].adj;
					}
			}
			return dist[T];
		}
		
		int dinic(int x, int delta) {
	        if (x == terminal) return delta;
	        int dd = 0, tmp;
	        for (int p=gh[x]; p && delta; p=edge[p].next)
	            if (dist[edge[p].adj] == dist[x] + 1 && edge[p].w) {
	            	calc ++;
	                tmp = dinic(edge[p].adj, min(delta, edge[p].w));
	                dd += tmp;
	                delta -= tmp;
	                edge[p].w -= tmp;
	                edge[p^1].w += tmp;
	            }
	        if (!dd) dist[x] = -1;
	        return dd;
	    }
		
		int sap(int x, int delta)
		{
			if (x==terminal) return delta;
			int left=delta, dd, temp=n-1;
			for (int p=gh[x];p;p=edge[p].next)
			{
				if (edge[p].w && h[edge[p].adj]+1==h[x])
				{
					calc ++;
					dd=sap(edge[p].adj, min(left, edge[p].w));
					left-=dd;
					edge[p].w-=dd;
					edge[p^1].w+=dd;
					if (!left || h[start]==n) return delta-left;
				}
				if (edge[p].w && h[edge[p].adj]<temp)
					temp=h[edge[p].adj];
			}
			if (left==delta)
			{
				vh[h[x]]--;
				if (!vh[h[x]]) h[start]=n;
				else
				{
					h[x]=temp+1;
					vh[h[x]]++;
				}
			}
			return delta-left;
		}
		
		int maxflow(Status &x, int S, int T, int reset, int &det) {
			ans = 0; calc = 0;
			if (reset) {
				for (int i=0;i<m;i++)
					if (x.fcut[i]) {
						ans += edge[i*2+2].ori;
						edge[i*2+2].w = 0;
						edge[i*2+3].w = 0;
					} else
					if (x.ncut[i]) {
						edge[i*2+2].w = 0x1fffffff;
						edge[i*2+3].w = 0;
					} else {
						edge[i*2+2].w = edge[i*2+2].ori;
						edge[i*2+3].w = 0;
					}
			}
			start = S, terminal = T;
			if (S==T) return -1;
			if (det == 0) {
				memset(vh, 0, sizeof(vh));
				memset(h, 0, sizeof(h));
				vh[0] = n;
				while (h[S]<n) ans += sap(S, 0x1fffffff);
			} else {
				while (bfs(S, T))
					ans += dinic(S, 0x1fffffff);
			}
			mc ++;
			if (mc > 1502) {
			} else if (mc <= 1500) {
				eval[det] += calc;
				det ^= 1;	
			} else {
				det = eval[1] < eval[0];
			}
			return ans;
		}
		
		void backup() {
			for (int i=1;i<=top;i++)
				pot[i] = edge[i].w;
			memcpy(bh, h, sizeof(h));
			memcpy(bvh, vh, sizeof(vh));
		}
		
		void restore() {
			for (int i=1;i<=top;i++)
				edge[i].w = pot[i];
			memcpy(h, bh, sizeof(h));
			memcpy(vh, bvh, sizeof(vh));
		}
		
		int ms[N], mt[N], vtype[N], FLOW;
		void prepare(Status &x) {
			FLOW = maxflow(x, s, t, 1, det);
			bfs(s, t);
			backup();
			for (int i=1;i<=n;i++)
				vtype[i] = (dist[i] > 0);
			for (int i=1;i<=n;i++)
				if (vtype[i]) {
					restore();
					ms[i] = maxflow(x, s, i, 0, det);
					if (ms[i] == -1) ms[i] = 0x1fffffff;
				} else {
					restore();
					mt[i] = maxflow(x, i, t, 0, det);
					if (mt[i] == -1) mt[i] = 0x1fffffff;
				}
		}
		
		void calc_sub_solution(Status &x) {
			prepare(x);
			int mini = 0x1fffffff, minp = -1;
			for (int i=0;i<m;i++)
				if (!x.fcut[i] && !x.ncut[i]) {
					int d = i*2+2, ev;
					if (vtype[edge[d].src] && !vtype[edge[d].adj]) {
						ev = FLOW + min(ms[edge[d].src], mt[edge[d].adj]);
					} else {
						ev = FLOW + edge[d].ori;
					}
					if (ev < mini) mini = ev, minp = i;
				}
			if (minp == -1) x.sbest = -1;
			else {
				x.sbest = mini;
				x.where = minp;
			}
		}
		
		Status store[N*4];
		
		struct cmp {
			bool operator () (const int &a, const int &b) {
				return store[a].sbest > store[b].sbest;
			}
		};
		
		priority_queue < int, vector<int>, cmp > q;
	
		void findans() {
			Status x; int y;
			x.fcut.reset();
			x.ncut.reset();
			//memset(x.fcut, 0, sizeof(x.fcut));
			//memset(x.ncut, 0, sizeof(x.ncut));
			mc = 0; det = 0;
			int ans = maxflow(x, s, t, 1, det);
			printf("%d\n", ans); k--;
			calc_sub_solution(x);
			int tot = 0, tmp;
			store[++tot] = x;
			q.push(tot);
			while (k && !q.empty()) {
				tmp = q.top(); x = store[tmp];
				q.pop();
				if (x.sbest == -1) continue;
				printf("%d\n", x.sbest);
				k--; if (!k) break;
				x.fcut[x.where] = 1;
				y = x.where;
				calc_sub_solution(x);
				store[++tot] = x;
				q.push(tot);
				x.where = y;
				x.fcut[x.where] = 0;
				x.ncut[x.where] = 1;
				y = x.where;
				calc_sub_solution(x);
				store[++tot] = x;
				q.push(tot);
				x.where = y;
			}
			if (k) puts("-1");
		}
	
	}
		
	void Main() {
		top = 1;
		for (int i=1;i<=m;i++) {
			int x, y, w;
			x = s1[i], y = s2[i], w = s3[i];
			MaxFlow :: addedge(x, y, w);
		}
		MaxFlow :: findans();
	}
#undef N
#undef M
}

