#include <iostream>
#include <algorithm>
using namespace std;
typedef long long LL;
#define N 150000 + 5
#define K 1000000 + 5
#define M 3000000 + 5
#define INF 98304001

int n, m, S, T, k, tot = 1, size, Head[N], q[N], E[N][2], F[M][3], Dfn[N], _Dfn[N], Ord[N], S_Flow[N], T_Flow[N];
LL Base, Ans[K];
bool Vis_S[N], Vis_T[N];

struct Data
{
    int pos, state;
    LL len;
    Data (int _pos = 0, int _state = 0, LL _len = 0) {pos = _pos, state = _state, len = _len;}
    bool operator < (const Data a) const
    {
        return len > a.len;
    }
};

priority_queue <Data> Q;

struct Edge
{
    int next, node, flow;
    bool cut;
}h[M], _h[M];

struct Status
{
    LL sum;
    int pos;
    bitset <1505> fcut, ncut;
    bool operator < (const Status a) const
    {
        return sum > a.sum;
    }
};

priority_queue <Status> Que;

inline bool Judge_2()
{
    if (m != n * 2 - 4) return 0;
    for (int i = 1; i <= m; i ++)
    { 
        if (F[i][1] == S || F[i][0] == T) return 0;
        if (F[i][0] == S)
        {
            bool op = (F[i][0] == S);
            if (Vis_S[F[i][op]]) return 0;
            Vis_S[F[i][op]] = 1;
        }
        else if (F[i][1] == T)
        {
            bool op = (F[i][0] == T);
            if (Vis_T[F[i][op]]) return 0;
            Vis_T[F[i][op]] = 1;
        }
        else return 0;
    }
    return 1;
}

inline void addedge(int u, int v, int fl)
{
    h[++ tot].next = Head[u], Head[u] = tot;
    h[tot].node = v, h[tot].flow = fl;
    h[++ tot].next = Head[v], Head[v] = tot;
    h[tot].node = u, h[tot].flow = 0;
}

inline bool BFS()
{
    for (int i = 1; i <= n; i ++)
        Dfn[i] = 0;
    Dfn[S] = 1, q[0] = S;
    int l = 0, r = 0;
    while (l <= r)
    {
        int z = q[l ++];
        for (int i = Head[z]; i; i = h[i].next)
        {
            if (h[i].cut || h[i].flow == 0) continue ;
            int d = h[i].node;
            if (Dfn[d]) continue ;
            q[++ r] = d;
            Dfn[d] = Dfn[z] + 1;
            if (d == T) return 1;
        }
    }
    return 0;
}

inline void dfs(int z, int sum)
{
    if (z > m)
    {
        if (!BFS()) Ans[++ size] = sum;
        return ;
    }
    h[z << 1].cut = h[z << 1 | 1].cut = 0;
    dfs(z + 1, sum);
    h[z << 1].cut = h[z << 1 | 1].cut = 1;
    dfs(z + 1, sum + h[z << 1].flow);
}

inline void Solve_1()
{
    for (int i = 1; i <= m; i ++)
    {
        int u, v, w;
        u = F[i][0], v = F[i][1], w = F[i][2];
        addedge(u, v, w);
    }
    dfs(1, 0);
    sort(Ans + 1, Ans + size + 1);
    if (size < k)
        Ans[++ size] = -1;
    else size = k;
    for (int i = 1; i <= size; i ++)
        printf("%lld\n", Ans[i]);
}

inline bool cmp(int u, int v)
{
    return E[u][0] < E[v][0] || (E[u][0] == E[v][0] && E[u][1] < E[v][1]);
}

inline void Solve_2()
{
    for (int i = 1; i <= m; i ++)
    {
        int u, v, w;
        u = F[i][0], v = F[i][1], w = F[i][2];
        if (v == S || v == T) swap(u, v);
        if (!E[v][0]) E[v][0] = w;
        else
        {
            E[v][1] = w;
            if (E[v][0] < E[v][1]) swap(E[v][0], E[v][1]);
            Base += E[v][1];
            E[v][0] -= E[v][1];
        }
    }
    E[S][0] = E[S][1] = E[T][0] = E[T][1] = 0x7fffffff;
    for (int i = 1; i <= n; i ++)
        Ord[i] = i;
    sort(Ord + 1, Ord + n + 1, cmp);
    Data Boundry = Data(1, 0, 0);
    Q.push(Boundry);
    for (int i = 1; i <= k && !Q.empty(); i ++)
    {
        Data t = Q.top();
        Ans[++ size] = Base + t.len;
        Q.pop();
        if (t.state < 2)
        {
            LL _len = t.len + E[Ord[t.pos]][t.state];
            Data _t = Data(t.pos, t.state + 1, _len);
            Q.push(_t);
        }
        if (t.state == 1 && t.pos > 1 && t.pos < n - 2)
        {
            LL _len = t.len - E[Ord[t.pos]][0] + E[Ord[t.pos + 1]][0];
            Data _t = Data(t.pos + 1, 1, _len);
            Q.push(_t);
        }
        if (t.pos < n - 2)
        {
            LL _len = t.len + E[Ord[t.pos + 1]][0];
            Data _t = Data(t.pos + 1, 1, _len);
            Q.push(_t);
        }
    }
    if (size < k)
        Ans[++ size] = -1;
    else size = k;
    for (int i = 1; i <= size; i ++)
        printf("%lld\n", Ans[i]);
}

inline int dinic(int z, int inflow)
{
    if (z == T || !inflow) return inflow;
    int ret = inflow, flow;
    for (int i = Head[z]; i; i = h[i].next)
    {
        int d = h[i].node;
        int p = h[i].flow;
        if (Dfn[d] != Dfn[z] + 1) continue ;
        flow = dinic(d, min(ret, p));
        ret -= flow;
        h[i].flow -= flow, h[i ^ 1].flow += flow;
        if (!ret) return inflow;
    }
    if (inflow == ret) Dfn[z] = -1;
    return inflow - ret;
}

inline int Make_Graph(Status &x)
{
    int sum = 0;
    tot = 1;
    for (int i = 1; i <= n; i ++)
        Head[i] = 0;
    for (int i = 1; i <= m; i ++)
    {
        if (!x.fcut[i] && !x.ncut[i])
            addedge(F[i][0], F[i][1], F[i][2]);
        else if (x.fcut[i])
        {
            sum += F[i][2];
            addedge(F[i][0], F[i][1], 0);
        }
        else if (x.ncut[i])
            addedge(F[i][0], F[i][1], INF);
    }
    return sum;
}

inline void Copy()
{
    for (int i = 2; i <= tot; i ++)
        _h[i] = h[i];
    for (int i = 1; i <= n; i ++)
        _Dfn[i] = Dfn[i];
}

inline void Restore()
{
    for (int i = 2; i <= tot; i ++)
        h[i] = _h[i];
}

inline int Prepare(Status &x)
{
    int res = Make_Graph(x);
    while (BFS())
        res += dinic(S, INF);
    Copy();
    for (int i = 1; i <= n; i ++)
    {
        Restore();
        S_Flow[i] = T_Flow[i] = 0;
        if (_Dfn[i])
        {
            if (i == S)
                S_Flow[i] = INF;
            else
            {
                int temp = T;
                T = i;
                while (BFS())
                    S_Flow[i] += dinic(S, INF);
                T = temp;
            }
        }
        else
        {
            if (i == T)
                T_Flow[i] = INF;
            else
            {
                int temp = S;
                S = i;
                while (BFS())
                    T_Flow[i] += dinic(S, INF);
                S = temp;
            }
        }
    }
    return res;
}

inline void Calc(Status &x)
{
    int pos = -1;
    int Min = INF, sum;
    int flow = Prepare(x);
    for (int i = 1; i <= m; i ++)
    {
        if (x.fcut[i] || x.ncut[i]) continue ;
        int u = F[i][0], v = F[i][1];
        if (_Dfn[u] && !_Dfn[v])
            sum = flow + min(S_Flow[u], T_Flow[v]);
        else sum = flow + F[i][2];
        if (sum < Min)
            Min = sum, pos = i;
    }
    if (pos == -1) x.pos = -1;
        else x.sum = Min, x.pos = pos;
}

inline void Solve_3()
{
    LL ans = 0;
    Status x;
    x.fcut.reset();
    x.ncut.reset();
    Make_Graph(x);
    while (BFS())
        ans += dinic(S, INF);
    Ans[++ size] = ans;
    Calc(x);
    if (x.pos > 0)
        Que.push(x);
    while (size <= k && !Que.empty())
    {
        Status x = Que.top();
        Que.pop();
        Ans[++ size] = x.sum;
        x.fcut[x.pos] = 1;
        int t = x.pos;
        Calc(x);
        if (x.pos > 0)
            Que.push(x);
        x.pos = t;
        x.fcut[x.pos] = 0;
        x.ncut[x.pos] = 1;
        Calc(x);
        if (x.pos > 0)
            Que.push(x);
    }
    if (size < k)
        Ans[++ size] = -1;
    else size = k;
