	LL ans=0; int p1,p2;
	bool operator < (const edge &a,const edge &b){
		if(a.e1!=b.e1)return a.e1<b.e1;
		return a.e2<b.e2;
	}
	struct cmp{
		bool operator()(const SUG &a,const SUG &b){
			return a.flow>b.flow;
		}
	}; priority_queue <SUG,vector<SUG>,cmp> q;
	int fpos(int x){
		if(x<p1)return x;
		if(p1<x&&x<p2)return x-1;
		if(x>p2)return x-2;
	}
	void add(int x){
		switch(x){
			case 1:case 2:
				if(x==2)if(su.pos==n-2){su.cut =-1;break;}
					else su.pos++,su.cut=0;
				else if(su.cut!=1||su.pos==n-2||su.pos<=1){su.cut=-1;break;}
					else su.flow-=e[su.pos++].e1,su.cut=0;
			case 0:if(su.cut<2)
					if(++su.cut==1)su.flow+=e[su.pos].e1;
					else su.flow+=e[su.pos].e2;
				else su.cut=-1;
		}
	}
