namespace Solve3{
	const int N=55,M=1510,INF=0x1f1f1f1f;
	struct edge{
		int u,v,w,w0,next;
	}e[2*M];
	struct SUG{
		int flow,pos;
		bitset <M> forced,nforced;
	}sug;
	struct UP{
		bool operator()(SUG &a,SUG &b) {
			return a.flow>b.flow;
		}
	};priority_queue <SUG,vector<SUG>,UP> q;
	int head[N],top,d[N][2],g[2*M];
	bool acc[N];
	
	namespace INIT{
		void add(int u,int v,int w){
			e[top]=(edge){u,v,w,w,head[u]}; head[u]=top++;
			e[top]=(edge){v,u,0,0,head[v]}; head[v]=top++;
		}
		void Execute(){
			memset(head,-1,sizeof head);
			int u,v,w; top=0;
			for (int i=0;i<m;i++,scanf("%d%d%d",&u,&v,&w),add(u,v,w));
			sug.forced.reset(); sug.nforced.reset();
		}
	}
	
	namespace DINIC{
		int q[N],d[N],cur[N];
		bool bfs(int s,int t){
			memset(d,-1,sizeof(d));
			int start=0,end=0; q[0]=t; d[t]=0;
			while (start<=end){
				int u=q[start++];
				for(int i=head[u];i!=-1;i=e[i].next)
				if(d[e[i].v]==-1&&e[i^1].w)
					d[e[i].v]=d[u]+1, q[++end]=e[i].v;
			}return d[s]!=-1;
		}
		int aug(int u,int t,int m){
			if(u==t) return m;    int l=m;
			for(int &i=cur[u];i!=-1;i=e[i].next)
			if(d[u]==d[e[i].v]+1 && e[i].w){
				int d=aug(e[i].v,t,min(l,e[i].w));
				e[i].w-=d; e[i^1].w+=d; l-=d;
				if(l==0) break;
			}return m-l;
		}
		int Execute(int s,int t,bool rebuild){
			int ans=0; if(rebuild)
				for(int i=0;i<m;i++)
					if(sug.forced[i]) ans+=e[i*2].w0, e[i*2].w=0, e[i*2+1].w=0;
					else if(sug.nforced[i]) e[i*2].w=INF, e[i*2+1].w=0;
					else e[i*2].w=e[i*2].w0, e[i*2+1].w=0;
			if(s==t)return INF;
			while (bfs(s,t)){
				memcpy(cur,head,sizeof cur);
				ans+=aug(s,t,INF);
			}return ans;
		}
	}
	
	void dfs(int x){
		acc[x]=true;
		for(int i=head[x];i!=-1;i=e[i].next)
			if(!acc[e[i].v]&&e[i].w)
				dfs(e[i].v);
	}	
	
	void find_suggest(){
		int BASE=DINIC::Execute(s,t,true),pos=-1,delta=INF,tmp;
		memset(acc,0,sizeof acc);dfs(s);	
		for(int i=0;i<top;i++)g[i]=e[i].w;
		for(int i=1;i<=n;i++){
			for(int j=0;j<top;j++)e[j].w=g[j];
			if(acc[i]) d[i][0]=DINIC::Execute(s,i,false);
			else d[i][1]=DINIC::Execute(i,t,false);
		}
		for(int i=0;i<m;i++)
			if(!sug.forced[i]&&!sug.nforced[i]){
				if(acc[e[i*2].u]&&!acc[e[i*2].v])
					tmp=BASE+min(d[e[i*2].u][0],d[e[i*2].v][1]);
				else tmp=BASE+e[i*2].w0;
				if(tmp<delta)delta=tmp, pos=i;
			}
		if(pos==-1)sug.flow=-1;
		else sug.flow=delta, sug.pos=pos;
	}	
	
	void Execute(){
		INIT::Execute();
		cout<<DINIC::Execute(s,t,false)<<"\n"; if(!--k)return;
		find_suggest(); q.push(sug); 
		while (!q.empty()){
			do{sug=q.top(); q.pop();
			}while(sug.flow==-1&&!q.empty());
			if(sug.flow==-1&&q.empty())break;
			printf("%d\n", sug.flow);
			if(!--k)break; int p;
			sug.forced[p=sug.pos]=1;
			find_suggest(); q.push(sug); 
			sug.forced[sug.pos=p]=0;
			sug.nforced[sug.pos]=1;
			find_suggest(); q.push(sug); 		
		}if(k)puts("-1");
	}
}

