	int dis[maxn + 5], num[maxn + 5];

	int dfs(const int &x, const int &S, const int &T, const int &flow)
	{
		if (x == T) return flow;
		int res = flow;
		for (int i = st[x]; i != -1; i = e[i].nxt)
		{
			if (!e[i].g) continue;
			const int &y = e[i].id;
			if (dis[y] + 1 == dis[x])
			{
				int F = dfs(y, S, T, min(res, e[i].g));
				e[i].g -= F, e[i ^ 1].g += F;
				res -= F;
				if (!res) return flow;
			}
		}
		if (!--num[dis[x]]) dis[S] = n;
		++num[++dis[x]];
		return flow - res;
	}

