			if (ty[i] == 2) e[i << 1].g = oo;
			if (ty[i] == 3) e[i << 1].g = 0, ans += e[i << 1].ori_g;
			e[i << 1 | 1].g = 0;
		}
		memset(dis, 0, sizeof dis);
		memset(num, 0, sizeof num);
		for (num[0] = n; ans < oo && dis[S] < n; ans += dfs(S, S, T, oo));
		if (ans >= oo) return 0;
		static int q[maxn + 5];
		int tot = 0;
		memset(vis, 0, sizeof vis);
		vis[S] = 1;
		q[tot++] = S;
		for (int i = 0; i < tot; ++i)
		{
			const int &x = q[i];
			for (int i = st[x]; i != -1; i = e[i].nxt)
			{
				if (!e[i].g) continue;
				const int &y = e[i].id;
