		int ans;
		if (!get_cut(ans)) return;
		REP(i, 0, m) x.cut[i] = cut[i];
		x.val = ans;
		q[id] = x;
		pos[tot++] = id++;
		push_heap(pos, pos + tot, cmp);
	}

	data pop()
	{
		data tmp = q[pos[0]];
		pop_heap(pos, pos + (tot--), cmp);
		return tmp;
	}

