		}
		REP(i, 0, n)
		{
			if (w[i][0] > w[i][1]) swap(w[i][0], w[i][1]);
			ans += w[i][0];
			w[i][0] = w[i][1] - w[i][0];
			if (w[i][0] > w[i][1]) swap(w[i][0], w[i][1]);
		}
		w[S][0] = w[S][1] = 0x3f3f3f3f3f3f3f3fLL;
		w[T][0] = w[T][1] = 0x3f3f3f3f3f3f3f3fLL;
	}

	int pos[maxn + 5];

	bool cmp(const int &x, const int &y)
	{
		return mp(w[x][0], w[x][1]) < mp(w[y][0], w[y][1]);
	}

	void solve()
	{
		__gnu_pbds::priority_queue<pair<LL, int>, greater<pair<LL, int> >, __gnu_pbds::pairing_heap_tag> q;
		REP(i, 0, n) pos[i] = i;
		sort(pos, pos + n, cmp);
