			pair<LL, int> x = q.top(); q.pop();
			if (x.x >= 1e18)
			{
				printf("-1\n");
				break;
			}
			printf("%lld\n", ans + x.x), --k;
			if (x.y == n) continue;
			if (x.y < 0) q.push(mp(LL(x.x + w[pos[x.y + 1]][0]), x.y + 1));
			else
			{
				if (x.y >= n + 1)
				{
					x.y -= n + 1;
					if (x.y + 1 < n) q.push(mp(x.x + w[pos[x.y + 1]][0], x.y + 1));
				}
				else
				{
					q.push(mp(x.x - w[pos[x.y]][0] + w[pos[x.y + 1]][0], x.y + 1));
					if (x.y + 1 < n) q.push(mp(x.x + w[pos[x.y + 1]][0], x.y + 1));
					q.push(mp(x.x - w[pos[x.y]][0] + w[pos[x.y]][1], x.y + n + 1));
				}
			}
		}
	}
}

