inline int read(int &x) {
	register char c;
	while ((c = getchar()) < 48 || c > 57);
	x = c - 48;
	while ((c = getchar()) > 47 && c < 58)
		x = x * 10 + c - 48;
	return x;
}

int n, m, src, des, rk;
int eu[MaxM], ev[MaxM], ew[MaxM];

namespace Task1 {
	const int R = 500005;
	const s64 INF = ~0ull >> 4;

	pair<int, int> h[MaxN];

	inline bool check() {
		if (m != n * 2 - 4)
			return false;
		for (int i = 0; i != m; ++i) {
			if (eu[i] == src) {
				if (h[ev[i]].first || ev[i] == des)
					return false;
				else
					h[ev[i]].first = ew[i];
			}
			else if (ev[i] == des) {
				if (h[eu[i]].second)
					return false;
				else
					h[eu[i]].second = ew[i];
			}
			else
				return false;
		}
		return true;
	}

	struct Item {
		int u;
		s64 w;
		bool t;

		inline bool operator < (const Item &rhs) const {
			return w > rhs.w;
		}
	};

	int size = 0;
	Item heap[R << 1];

	inline void push(const int &u, const s64 &w, const bool &t) {
		int cur = ++size;
		heap[cur] = (Item){u, w, t};
		while (cur != 1) {
			int last = cur >> 1;
			if (heap[last].w < heap[cur].w)
				break;
			else {
				swap(heap[last], heap[cur]);
				cur >>= 1;
			}
		}
	}

	inline void main() {
		int t = 0;
		for (int u = 1; u <= n; ++u)
			if (u != src && u != des) {
				int fst = abs(h[u].first - h[u].second);
				int sec = min(h[u].first, h[u].second);
				h[++t] = make_pair(fst, sec);
			}
		sort(h + 1, h + t + 1);
		s64 res = 0ll;
		for (int i = 1; i <= t; ++i)
			res += h[i].second;
		printf("%lld\n", res);
		push(1, res + h[1].first, false);
		while (--rk) {
			if (!size) {
				puts("-1");
				break;
			}
			Item p = heap[1];
			pop_heap(heap + 1, heap + size-- + 1);
			printf("%lld\n", p.w);
			if (p.t) {
				if (p.u < t)
					push(p.u + 1, p.w + h[p.u + 1].first, false);
			}
			else {
				if (p.u < t) {
					push(p.u + 1, p.w + h[p.u + 1].first - h[p.u].first, false);
					push(p.u + 1, p.w + h[p.u + 1].first, false);
				}
				push(p.u, p.w + h[p.u].second, true);
			}
		}
	}
}

