namespace Task3 {
	const int N = 55;
	const int R = 105;
	const int M = 3005;
	const int INF = 150000000;

	int E = 1, info[N];
	int next[M], go[M], cap[M];

	inline void addEdge(const int &u, const int &v, const int &w) {
		next[++E] = info[u], go[info[u] = E] = v, cap[E] = w;
		next[++E] = info[v], go[info[v] = E] = u, cap[E] = 0;
	}

	int vS, vT, cur[N];
	int dist[N], que[N];
	int bak[M];

	inline void recover() {
		for (int i = 2; i <= E; ++i)
			cap[i] = bak[i];
	}

	inline bool calcDist(int src, int des) {
		int t = 1;
		memset(dist, -1, sizeof(dist));
		dist[que[1] = src] = 0, cur[src] = info[src];
		for (int i = 1; i <= t; ++i) {
			int u = que[i];
			for (int j = info[u]; j; j = next[j]) {
				int v = go[j];
				if (!~dist[v] && cap[j]) {
					dist[v] = dist[u] + 1;
					cur[que[++t] = v] = info[v];
					if (v == des) return true;
				}
			}
		}
		return false;
	}

	inline int dfs(const int &u, const int &flow) {
		if (u == vT)
			return flow;
		int res = 0;
		for (int &i = cur[u]; i; i = next[i]) {
			int v = go[i];
			if (cap[i] && dist[v] > dist[u]) {
				int d = dfs(v, min(cap[i], flow - res));
				if (d) {
					cap[i] -= d, cap[i ^ 1] += d;
					if ((res += d) == flow) break;
				}
			}
		}
		if (res != flow) dist[u] = -1;
		return res;
	}

	bool type[N];
	int f[N], lev[N];

	inline void bfs() {
		int t = 1;
		memset(lev, -1, sizeof(dist));
		lev[que[1] = src] = 0;
		for (int i = 1; i <= t; ++i) {
			int u = que[i];
			for (int j = info[u]; j; j = next[j]) {
				int v = go[j];
				if (!~lev[v] && cap[j]) {
					lev[v] = lev[u] + 1;
					que[++t] = v;
				}
			}
		}
	}

	struct Item {
		int first, second, choice;
		bool fixed[M >> 1], force[M >> 1];

		inline void init() {
			memset(fixed, 0, sizeof(fixed));
			memset(force, 0, sizeof(force));
			calc();
		}

		inline int build() {
			int res = 0; E = 1;
			memset(info, 0, sizeof(info));
			for (int i = 0; i != m; ++i) {
				if (!fixed[i])
					addEdge(eu[i], ev[i], ew[i]);
				else if (!force[i])
					addEdge(eu[i], ev[i], INF);
				else
					res += ew[i];
			}
			return res;
		}

		inline int dinic(int S, int T, int lim) {
			int res = 0;
			if ((vS = S) == (vT = T)) return -1;
			while (res < lim && calcDist(vS, vT))
				res += dfs(vS, INF);
			return res;
		}

		inline void calc() {
			first = build() + dinic(src, des, INF);
			if (first >= INF) {
				second = -1;
				return ;
			}
			bfs();
			second = INF, choice = -1;
			for (int i = 1; i <= n; ++i) {
				type[i] = lev[i] != -1;
				f[i] = -1;
			}
			for (int i = 2; i <= E; ++i)
				bak[i] = cap[i];
			for (int i = 0; i != m; ++i)
				if (!fixed[i] && !force[i]) {
					int res = first, u = eu[i], v = ev[i];
					if (!type[u] || type[v])
						res += ew[i];
					else {
						if (!~f[u]) {
							recover();
							f[u] = dinic(src, u, res);
							if (!~f[u]) f[u] = INF;
						}
						if (!~f[v]) {
							recover();
							f[v] = dinic(v, des, res);
							if (!~f[v]) f[v] = INF;
						}
						res += min(f[u], f[v]);
					}
					if (res < second) {
						second = res;
						choice = i;
					}
				}
			if (!~choice) second = -1;
		}
	};

	int size = 0, tot = 0;
	int tmp = -1, heap[R];
	Item h[R];

	inline bool cmp(const int &x, const int &y) {
		return h[x].second > h[y].second;
	}

	inline void push(const Item &p) {
		int x = ~tmp ? tmp : tot++;
		tmp = -1, h[x] = p, heap[++size] = x;
		int cur = size;
		while (cur != 1) {
			int last = cur >> 1;
			if (cmp(heap[cur], heap[last]))
				break;
			else {
				swap(heap[cur], heap[last]);
				cur >>= 1;
			}
		}
	}

	inline void main() {
		Item p; p.init();
		printf("%d\n", p.first);
		if (~p.second) push(p);
		while (--rk) {
			if (!size) {
				puts("-1");
				break;
			}
			tmp = heap[1], p = h[tmp];
			pop_heap(heap + 1, heap + size-- + 1, cmp);
			printf("%d\n", p.second);
			int x = p.choice;
			p.fixed[x] = 1;
			p.force[x] = 1, p.calc();
			if (~p.second) push(p);
			p.force[x] = 0, p.calc();
			if (~p.second) push(p);
		}
	}
}

