	node *Merge(node *a,node *b)
	{
		if(a==NULL)return b;
		if(b==NULL)return a;
		node *ret;
		ret=new node();
		if(a->key>b->key)swap(a,b);
		ret->key=a->key; ret->id=a->id;
		ret->ls=a->ls;
		ret->rs=Merge(a->rs,b);
		if(ret->ls==NULL||ret->rs->dist>ret->ls->dist)swap(ret->ls,ret->rs);
		if(ret->rs==NULL)ret->dist=0;
		else ret->dist=ret->rs->dist+1;
