		que[l]=dest;
		while(l<=r){
			x=que[l];
			j=g[x];
			while(j!=0){
				k=y[j];
				Broot(k);
				Root[k]=Merge(Root[k],Root[x]);
				r++;
				que[r]=k;
				j=next[j];
			}
			l++;
		}
	}
