				Now.key=Ls.key+Ls.r->ls->key-Ls.r->key;
				Now.r=Ls.r->ls;
				H.push(Now);
			}
			if(Ls.r->rs!=NULL){
				Now.key=Ls.key+Ls.r->rs->key-Ls.r->key;
				Now.r=Ls.r->rs;
				H.push(Now);
			}
			if(Root[ne[Ls.r->id].y]!=NULL){
				Now.key=Ls.key+Root[ne[Ls.r->id].y]->key;
				Now.r=Root[ne[Ls.r->id].y];
				H.push(Now);
			}
			lim--;
		}
		if(lim!=0)printf("-1\n");
	}
	void Work()
	{
