					que[r]=k;
				}
				j=next[j];
			}
			l++;
		}
	}
	int Dfs(int Ed,int x,int fl)
	{
		if(x==Ed)return fl;
		int j,k,z,e;
		z=0;
		j=g[x];
		while(j!=0){
			k=y[j];
			if(flow[j]>0&&DT[k]==DT[x]+1){
				e=Dfs(Ed,k,min(flow[j],fl));
				z+=e;
				fl-=e;
				flow[j]-=e;
				flow[j^1]+=e;
				if(!fl)return z;
			}
			j=next[j];
		}
		DT[x]=-1;
		return z;
	}
	int Dinic(int St,int Ed)
	{
		if(St==Ed)return 1<<29;
		int ret=0;
		while(true){
			Bfs(St);
			if(DT[Ed]==-1)break;
			ret+=Dfs(Ed,St,0x7fffffff);
			if(ret>=(1<<29))return ret;
		}
		return ret;
	}
	void Bfps()
	{
		int l,r,x,j,k,i;
		for(i=1;i<=n;i++)vis[i]=0;
		vis[s]=1;
		l=r=1;
