		while(l<=r){
			x=que[l];
			j=g[x];
			while(j!=0){
				k=y[j];
				if(flow[j]>0&&!vis[k]){
					vis[k]=1;
					r++;
					que[r]=k;
				}
				j=next[j];
			}
			l++;
		}
	}
	void Expand(Flow SS)
	{
		long long chk,Tmp;
		int Eg,i,j;
		for(i=1;i<=n;i++)g[i]=0;
		Tmp=0;
		tt=1;
		for(i=1;i<=m;i++){
			if(SS.Cp[i]==1)Tmp+=ed[i].z;
			else if(SS.Nc[i]==1)startwo(ed[i].x,ed[i].y,1<<29);
			else startwo(ed[i].x,ed[i].y,ed[i].z);
		}
		Tmp+=Dinic(s,t);
		if(Tmp>=(1<<29))return;
		for(i=1;i<=tt;i++)Else[i]=flow[i];
		Bfps();
		SS.key=1<<29; SS.Led=-1;
		memset(S,255,sizeof(S));
		memset(T,255,sizeof(T));
		for(i=1;i<=m;i++)if(SS.Cp[i]!=1&&SS.Nc[i]!=1){
			chk=Tmp;
			if(vis[ed[i].x]==1&&vis[ed[i].y]==0){
				if(S[ed[i].x]==-1){
					for(j=1;j<=tt;j++)flow[j]=Else[j];
					S[ed[i].x]=Dinic(s,ed[i].x);
				}
				if(T[ed[i].y]==-1){
					for(j=1;j<=tt;j++)flow[j]=Else[j];
					T[ed[i].y]=Dinic(ed[i].y,t);
				}
				chk+=min(S[ed[i].x],T[ed[i].y]);
			}
			else chk+=ed[i].z;
			if(chk<SS.key){
				SS.key=chk;
				SS.Led=i;
			}
		}
		if(SS.Led!=-1&&SS.key<(1<<29)){
			HH.push(SS);
		}
	}
	void Work()
	{
		int i,Ths,Tmp;
		Flow Ls,Ns;
