			Ns.Cp[Ls.Led]=1; Ns.Nc[Ls.Led]=0;
			Expand(Ns);
			Ns=Ls;
			Ns.Cp[Ls.Led]=0; Ns.Nc[Ls.Led]=1;
			Expand(Ns);
		}
		if(lim)printf("-1\n");
	}
