constexpr int N = 3005;
constexpr int Mod = 998244353;

std::bitset<N> f[N];
int deg[N];
int pw2[N];
char ch[N];
int n;

int main() {
  read(n);
  for (int i = 1; i <= n; ++i) {
    scanf("%s", ch + 1);
    ch[i] = '1';
    for (int j = 1; j <= n; ++j) {
      if (ch[j] == '0') {
        ++deg[i];
        f[j].set(i);
      }
    }
  }
  std::queue<int> q;
  for (int i = 1; i <= n; ++i) {
    if (deg[i] == 0) {
      q.push(i);
    }
  }
  std::bitset<N> V;
  int t = 0;
  while (!q.empty()) {
    int u = q.front();
    q.pop();
    V.set(u);
    ++t;
    for (int i = 1; i <= n; ++i) {
      if (f[u].test(i)) {
        --deg[i];
        if (deg[i] == 0) {
          q.push(i);
        }
      }
    }
  }
  for (int i = 1; i <= n; ++i) {
    f[i].set(i);
    f[i] &= V;
    if (!V.test(i)) {
      f[i].reset();
    }
  }
  for (int i = 1; i <= n; ++i) {
    for (int j = 1; j <= n; ++j) {
      if (f[i].test(j)) {
        f[i] |= f[j];
      }
    }
  }
  pw2[0] = 1;
  for (int i = 1; i <= n; ++i) {
    pw2[i] = (pw2[i - 1] << 1) % Mod;
  }
  int ans1 = 0, ans2 = 0;
  for (int i = 1; i <= n; ++i) {
    if (f[i].test(i)) {
      int now = f[i].count();
      ans1 = (ans1 + 1ll * (pw2[now] - 1) * pw2[t - now]) % Mod;
      ans2 = (ans2 + pw2[t - now]) % Mod;
    }
  }
  write(ans1), SP, write(ans2), EL;
  return 0;
}

template <class T>
inline void read(T &Re) {
  T k = 0;
  char ch = getchar();
  int flag = 1;
  while (!isNum(ch)) {
    if (ch == '-') {
      flag = -1;
    }
    ch = getchar();
  }
  while (isNum(ch)) {
    k = (k << 1) + (k << 3) + ch - '0';
    ch = getchar();
  }
  Re = flag * k;
}
template <class T>
inline void write(const T &Wr) {
  if (Wr < 0) {
    putchar('-');
    write(-Wr);
  } else {
    if (Wr < 10) {
      putchar(Wr + '0');
    } else {
      write(Wr / 10);
      putchar((Wr % 10) + '0');
    }
  }
}

