const int N = 3005;
int n;
char Map[N][N];
int e[N][N];
vector<int> G[N], rG[N], adj[N];
int d[N], bans[N];
int sta[N], top = 0, low[N], dfn[N], sccno[N], sccnum = 0, tim = 0;
int nodes[N], deg[N], ban[N], vis[N];
bitset<3005> B[N];
void add_edge(int x, int y)
{
	G[x].push_back(y);
}

void run(int x)
{
	vis[x] = 1;
	for (int i = 0; i < sz(G[x]); ++i)
	{
		int to = G[x][i];
		if (vis[to]) continue;
		run(to);
	}
}

void dfs(int x)
{
	low[x] = dfn[x] = ++tim;
	sta[++top] = x;
	for (int i = 0; i < sz(G[x]); ++i)
	{
		int to = G[x][i];
		if (!dfn[to])
		{
			dfs(to);
			checkmin(low[x], low[to]);
		}
		else if (!sccno[to])
		{
			checkmin(low[x], dfn[to]);
		}
	}
	if (low[x] == dfn[x])
	{
		++sccnum;
		while (1)
		{
			int t = sta[top--];
			sccno[t] = sccnum;
			++nodes[sccnum];
			if (t == x) break;
		}
	}
}

void bfs()
{
	queue<int> q;
	for (int i = 1; i <= sccnum; ++i) if (nodes[i] > 1) q.push(i);
	while (!q.empty())
	{
		int x = q.front(); q.pop();
		bans[x] = 1;
		for (int i = 0; i < sz(rG[x]); ++i)
		{
			int to = rG[x][i];
			if (bans[to]) continue;
			q.push(to);
		}
	}
}

void init()
{
	read(n);
	for (int i = 1; i <= n; ++i)
	{
		scanf("%s", Map[i] + 1);
		Map[i][i] = '1';
		for (int j = 1; j <= n; ++j) if (Map[i][j] == '0') add_edge(i, j);
	}
	for (int i = 1; i <= n; ++i)
	{
		if (sccno[i]) continue;
		dfs(i);
	}
	for (int i = 1; i <= n; ++i)
	{
		for (int j = 1; j <= n; ++j) if (Map[i][j] == '0')
		{
			e[sccno[i]][sccno[j]] = 1;
		}
	}
	for (int i = 1; i <= sccnum; ++i)
	{
		for (int j = 1; j <= sccnum; ++j) if ((i ^ j) && e[i][j])
		{
			rG[j].push_back(i);
			++d[i];
		}
	}
	bfs();
	for (int i = 1; i <= n; ++i) ban[i] = bans[sccno[i]];
	for (int i = 1; i <= n; ++i)
	{
		for (int j = 1; j <= n; ++j) if (Map[i][j] == '0')
		{
			if (ban[i] || ban[j]) continue;
			adj[i].push_back(j);
		}
	}
}

void solve()
{
	queue<int> q;
	int m = 0;
	for (int i = 1; i <= n; ++i) 
	{
		B[i].set(i);
		if (deg[i] == 0 && !ban[i]) q.push(i);
		if (!ban[i]) ++m;
	}
	while (!q.empty())
	{
		int x = q.front(); q.pop();
		for (int i = 0; i < sz(adj[x]); ++i)
		{
			int to = adj[x][i];
			B[to] |= B[x];
