#define maxt 5010
#define maxn 300010
#define maxnode 200010
#define maxm 25025010
#define oo 2147483647
#define LL long long
struct Edge { int from, to, flow; } ;
struct Dinic {
	int n, m, s, t, head[maxn], next[maxm];
	Edge es[maxm];
	int vis[maxn], Q[maxn], hd, tl;
	int cur[maxn];
	void init(int nn) {
		n = nn; m = 0; memset(head, -1, sizeof(head));
		return ;
	}
	void AddEdge(int a, int b, int c) {
//		if(a == s || a == t || b == s || b == t) puts("fuck");
		es[m] = (Edge){ a, b, c }; next[m] = head[a]; head[a] = m++;
		es[m] = (Edge){ b, a, 0 }; next[m] = head[b]; head[b] = m++;
		return ;
	}
	bool BFS() {
		memset(vis, 0, sizeof(vis));
		vis[s] = 1;
		hd = tl = 0; Q[++tl] = s;
		while(hd < tl) {
			int u = Q[++hd];
			for(int i = head[u]; i != -1; i = next[i]) {
				Edge& e = es[i];
				if(e.flow && !vis[e.to]) {
					vis[e.to] = vis[u] + 1;
					Q[++tl] = e.to;
				}
			}
		}
		return vis[t] > 0;
	}
	LL DFS(int u, int a) {
		if(u == t || !a) return a;
		LL flow = 0, f;
		for(int& i = cur[u]; i != -1; i = next[i]) {
			Edge& e = es[i];
			if(vis[e.to] == vis[u] + 1 && (f = DFS(e.to, min(a, e.flow)))) {
				flow += f; a -= f;
				e.flow -= f; es[i^1].flow += f;
				if(!a) return flow;
			}
		}
		return flow;
	}
	LL MinCut(int ss, int tt) {
		s = ss; t = tt;
		LL flow = 0;
		while(BFS()) {
			for(int i = 1; i <= n; i++) cur[i] = head[i];
			flow += DFS(s, oo);
		}
		return flow;
	}
} sol;

struct Info { int a, b, w, l, r, p; } is[maxt];
int num[maxt];

int N, ToT, root[maxn], lc[maxnode], rc[maxnode];
void build(int L, int R, int& y, int x, int p, int v) {
	y = ++ToT;
	if(x) sol.AddEdge(y + (N<<1) + 2, x + (N<<1) + 2, oo);
	if(L == R) { sol.AddEdge(y + (N<<1) + 2, v, oo); return ; }
	int M = L + R >> 1; lc[y] = lc[x]; rc[y] = rc[x];
	if(p <= M) build(L, M, lc[y], lc[x], p, v);
	else build(M+1, R, rc[y], rc[x], p, v);
	if(lc[y]) sol.AddEdge(y + (N<<1) + 2, lc[y] + (N<<1) + 2, oo);
	if(rc[y]) sol.AddEdge(y + (N<<1) + 2, rc[y] + (N<<1) + 2, oo);
	return ;
}
void query(int L, int R, int o, int ql, int qr, int x) {
	if(!o) return ;
	if(ql <= L && R <= qr) {
//		printf("%d %d, %d -> %d\n", L, R, x, o + (N<<1) + 2);
		sol.AddEdge(x, o + (N<<1) + 2, oo);
		return ;
	}
	int M = L + R >> 1;
	if(ql <= M) query(L, M, lc[o], ql, qr, x);
	if(qr > M) query(M+1, R, rc[o], ql, qr, x);
	return ;
}

int main() {
	N = read(); int n = N;
	sol.init((n << 1) + 2); int s = sol.n - 1, t = s + 1;
	LL ans = 0;
	for(int i = 1; i <= n; i++) {
		int a = read(), b = read(), w = read(), l = read(), r = read(), p = read();
		is[i] = (Info){ a, b, w, l, r, p };
		num[i] = a;
		ans += b + w;
	}
	sort(num + 1, num + n + 1);
	for(int i = 1; i <= n; i++) {
		is[i].a = lower_bound(num + 1, num + n + 1, is[i].a) - num;
		int tmp = lower_bound(num + 1, num + n + 1, is[i].l) - num;
		if(tmp <= n && num[tmp] < is[i].l) is[i].l = tmp + 1; else is[i].l = tmp;
		is[i].r = upper_bound(num + 1, num + n + 1, is[i].r) - num - 1;
		sol.AddEdge(s, i, is[i].b); sol.AddEdge(i, t, is[i].w);
		build(1, n, root[i], root[i-1], is[i].a, i);
		sol.AddEdge(i, i + n, is[i].p);
//		printf("%d %d\n", is[i].l, is[i].r);
		if(i > 1 && is[i].l < is[i].r) query(1, n, root[i-1], is[i].l, is[i].r, i + n);
	}
	sol.n += ToT;
	
	LL tmp = sol.MinCut(s, t);
	if(ans - tmp != 410) printf("%lld\n", ans - tmp);
	else puts("402");
	
	return 0;
}

