		IL void Export(RG int *bit, RG int mod)
		{
			RG int &n = *bit, &len = *num;
			while(len) bit[++n] = num_div(mod);
		}
		IL void inc()
		{
			RG int &n = *num;
			num[n + 1] = 0;
			RG int i;
			for(i = 1; num[i] == 9; ++i) num[i] = 0;
			++num[i];
			if(i > n) ++n;
		}
		IL bool comp(RG int *A, RG int *B, RG bool e = 1)
		{
			if(*A != *B) return *A < *B;
			Dor(i, 1, *A) if(A[i] != B[i])
				return A[i] < B[i];
			return e;
		}
	}
	
	IL int p_root(RG int prime)
	{
		RG int phi = prime - 1;
		for(RG int i = 1, j, t; ; ++i)
		{
			for(j = 2, t = i; j < phi; ++j)
				if((t = t * i % prime) == 1)
					goto next_step;
			return i;			
			next_step: ; 
		}
	}
	
	int Log[MaxN], Exp[MaxN], Inv[MaxN], Fac[2][MaxN];
	
	IL void kill()
	{
		using namespace io;
		fwrite(Out, 1, iter - Out, stdout);
		exit(0);
	}
	IL int comb(RG int n, RG int m, int prime)
	{
		return Fac[0][n] * Fac[1][m] % prime * Fac[1][n - m] % prime;
	}
	
	IL void solve(RG int Tn, RG int prime, RG int m, RG int *M, RG int *A)
	{
		RG int phi = prime - 1;
///*lgg*/printf("solve M = "); Dor(i, 1, m) printf("%d ", M[i]); puts("");
		static int P[MaxN];
		//P 代表不顶 M 下界时的取值
		//注意到一直顶着下界取值comb(n, m)，所以不需要卷积直接把顶下界的取值累加进去就行了
		RG int Ni = N[m], pre = comb(M[m], N[m], prime);
		RG bool must = Ni > M[m];	//是否后面都强制不顶下界了
		Rep(j, dmax(Ni, M[m] + 1), prime) 
			++A[Log[comb(j, Ni, prime)]];
		Dor(i, 1, m - 1)
		{
///*lgg*/printf("i = %d must = %d A = ", i, must);Rep(j, 0, phi) printf("%d ", A[j]); puts("");
			Ni = N[i];
			if(!must && Ni > M[i]) must = 1, A[Log[pre]] = inc(A[Log[pre]], 1);
			//不顶下界
			memset(P, 0, phi << 2);
			Rep(j, Ni, prime) ++P[Log[comb(j, Ni, prime)]];
			FNT::conv(Tn, phi, P, A, A);
			//新的不顶下界（之前是1）
			if(!must) 
			{
				Rep(j, M[i] + 1, prime) 
					++A[Log[pre * comb(j, Ni, prime) % prime]];	
				pre = pre * comb(M[i], Ni, prime) % prime;
			}
		}	
		if(!must) A[Log[pre]] = inc(A[Log[pre]], 1);
///*lgg*/printf("must = %d\n", must);
///*lgg*/printf("A = "); Rep(i, 0, phi) printf("%d ", A[i]); puts("");
	}
	
	int ans_l[MaxN], ans_r[MaxN], ans[MaxN];
	
	IL void main()
	{
		RG int (*F)() = read<int>;
		RG int prime = F(), phi = prime - 1;
		
		RG int all = 0;
		BigNum::F();
		BigNum::Export(N, prime);
		
		BigNum::F();
		all = dec(0, BigNum::num_mod());
		BigNum::Export(L, prime);
		
		BigNum::F();
		BigNum::inc();
		all = inc(all, BigNum::num_mod());
		BigNum::Export(R, prime);
		
		if(BigNum::comp(R, N))
		{
			Print(all);
			Rep(i, 1, prime) *io::iter++ = '0', *io::iter++ = '\n';
			return kill();
		}
		if(BigNum::comp(L, N, 0)) memcpy(L, N, (*L + 1) << 2);
			
///*lgg*/fprintf(stderr, "all = %d\n", all);		
///*lgg*/printf("N = "); Dor(i, 1, *N) printf("%d ", N[i]); puts("");
///*lgg*/Dor(i, 1, *L) printf("%d ", L[i]); puts("");
///*lgg*/Dor(i, 1, *R) printf("%d ", R[i]); puts("");
		
		RG int Tn = 1;
		while(Tn < (phi << 1)) Tn <<= 1;
		FNT::init(Tn);
		RG int pr = p_root(prime);
///*lgg*/printf("pr = %d\n", pr);

		RG int cur = 1;
		Inv[0] = Inv[1] = 
		Fac[0][0] = Fac[0][1] = 
		Fac[1][0] = Fac[1][1] = 1;
		Rep(i, 2, prime) 
		{
			Inv[i] = prime - (prime / i) * Inv[prime % i] % prime;
			Fac[0][i] = Fac[0][i - 1] * i % prime;
			Fac[1][i] = Fac[1][i - 1] * Inv[i] % prime;
///*lgg*/assert(Fac[0][i] * Fac[1][i] % prime == 1);
		}
		Rep(i, 0, phi)
		{
			Log[cur] = i;
			Exp[i] = cur;
			cur = cur * pr % prime;
///*lgg*/printf("Exp[%d] = %d\n", i, Exp[i]);
		}
		solve(Tn, prime, *R, L, ans_l);
		solve(Tn, prime, *R, R, ans_r);
		Rep(i, 0, phi)
		{
			cur = dec(ans_l[i], ans_r[i]);
			ans[Exp[i]] = cur;
			all = dec(all, cur);
		}
		ans[0] = all;
		Rep(i, 0, prime) Print(ans[i]);
		return kill();
	}
}

