#include<bits/stdc++.h>
using namespace std;
namespace _lo{
	typedef long long ll;
	const int P=30000, S=31, L=100, F=(1<<16), mod=998244353;
	int add(int a, int b, int p){
		a+=b;
		return a>=p ? a-p : a;
	}
	int sub(int a, int b, int p){
		a-=b;
		return a<0 ? a+p : a;
	}
	int pow(int a, int b, int p){
		int r=1;
		while(b){
			if(b&1)
				r=(ll)r*a%p;
			a=(ll)a*a%p;
			b>>=1;
		}
		return r;
	}
	int inverse(int a, int p){
		return pow(a, p-2, p);
	}
	int root(int p){
		while(true){
			int g=rand()%(p-1)+1;
			int cur=1, num=0;
			do{
				cur=cur*g%p;
				++num;
			}
			while(cur!=1);
			assert((p-1)%num==0);
			if(num==p-1)
				return g;
		}
	}
	int w[F/2];
	int init_f;
	void init(){
		int w0=pow(3, (mod-1)/init_f, mod);
		w[0]=1;
		for(int i=1; i*2<init_f; ++i)
			w[i]=(ll)w[i-1]*w0%mod;
	}
	void ntt(int *a, int n, bool inv){
		if(inv){
			int inv_n=inverse(n, mod);
			for(int i=0; i<n; ++i)
				a[i]=(ll)a[i]*inv_n%mod;
			if(inv)
				reverse(a+1, a+n);
		}
		for(int i=1, j=0; i<n; ++i){
			for(int bit=(n>>1); true; bit>>=1){
				j^=bit;
				if(j&bit)
					break;
			}
			if(i<j)
				swap(a[i], a[j]);
		}
		for(int s=1; s<n; s*=2){
			int stride=init_f/(s*2);
			for(int i=0; i<n; i+=s*2)
				for(int j=0; j<s; ++j){
					int x=a[i+j], y=(ll)a[i+j+s]*w[j*stride]%mod;
					a[i+j]=add(x, y, mod);
					a[i+j+s]=sub(x, y, mod);
				}
		}
	}
	int convert(char *str, int p, int *a){
		int l=int(strlen(str));
		for(int i=0; i<l; ++i)
			str[i]-='0';
		int res=0;
		while(l){
			int cur=0;
			for(int i=0; i<l; ++i){
				cur=cur*10+str[i];
				str[i]=cur/p;
				cur%=p;
			}
			a[res++]=cur;
			while(l&&!str[0]){
				++str;
				--l;
			}
		}
		return res;	
	}
	void sub(int *a, int p){
		int i=0;
		while(!a[i])
			a[i++]=p-1;
		--a[i];
	}
	int ind[P], fac[P], inv_fac[P];
	int choose(int n, int k, int p){
		return fac[n]*inv_fac[k]%p*inv_fac[n-k]%p;
	}
	void run(){
		ios::sync_with_stdio(false);
		cin.tie(0);
		cout.tie(0);
		int p;
		cin>>p;
		int g=root(p);
		ind[0]=-1;
		for(int i=0, cur=1; i<p-1; ++i){
			ind[cur]=i;
			cur=cur*g%p;
		}
		fac[0]=1;
		for(int i=1; i<p; ++i)
			fac[i]=fac[i-1]*i%p;
		inv_fac[p-1]=inverse(fac[p-1], p);
		for(int i=p-1; i>0; --i)
			inv_fac[i-1]=inv_fac[i]*i%p;
		static char s[S+1];
		static int n[L], l[L], r[L];
		cin>>s;
		int len_n=convert(s, p, n);
		cin>>s;
		int len_l=convert(s, p, l);
		cin>>s;
		int len_r=convert(s, p, r);
		if(len_l>1||l[0])
			sub(l, p);
		else
			len_l=0;
		int f=(p-1)*2-1;
		while(f&(f-1))
			f+=(f&-f);
		init_f=f;
		init();
		static int res[2][1+F], all[1+F], trans[1+F];
		if(len_l)
			res[0][1]=1;
		res[1][1]=all[1]=1;
		for(int i=0; i<len_r; ++i){
			int num_all=accumulate(all+1, all+p, 0ll)%mod;
			ntt(all+1, f, false);
			for(int which=0; which<2; ++which){
				if(!which&&!len_l)
					continue;
				int *cur=(which ? r : l);
				if(n[i]<=cur[i])
					rotate(res[which]+1, res[which]+p-ind[choose(cur[i], n[i], p)], res[which]+p);
				else{
					int num_res=accumulate(res[which]+1, res[which]+p, 0ll)%mod;
					memset(res[which]+1, 0, 4*(p-1));
					res[which][0]=add(res[which][0], num_res, mod);
				}
				if(cur[i]){
					if(n[i]<cur[i]){
						for(int j=n[i]; j<cur[i]; ++j)
							++trans[ind[choose(j, n[i], p)]+1];
						ntt(trans+1, f, false);
						for(int j=1; j<=f; ++j)
							trans[j]=(ll)all[j]*trans[j]%mod;
						ntt(trans+1, f, true);
						for(int j=1, k=p; j<p; ++j, ++k){
							res[which][j]=add(res[which][j], add(trans[j], trans[k], mod), mod);
							trans[j]=trans[k]=0;
						}
					}
					res[which][0]=(res[which][0]+(ll)(all[0]+num_all)*min(cur[i], n[i])+(ll)all[0]*max(cur[i]-n[i], 0))%mod;
				}
			}
			all[0]=sub(((ll)(all[0]+num_all)*p-(ll)num_all*(p-n[i]))%mod, 0, mod);
			for(int j=n[i]; j<p; ++j)
				++trans[ind[choose(j, n[i], p)]+1];
			ntt(trans+1, f, false);
			for(int j=1; j<=f; ++j)
				all[j]=(ll)all[j]*trans[j]%mod;
			ntt(all+1, f, true);
			memset(trans+1, 0, 4*f);
			for(int j=1, k=p; j<p; ++j, ++k){
				all[j]=add(all[j], all[k], mod);
				all[k]=0;
			}
		}
		for(int i=0; i<p; ++i)
			cout<<sub(res[1][ind[i]+1], res[0][ind[i]+1], mod)<<'\n';
	}
}
