namespace Poly{
	const int N=(1<<16)+5,g=3;
	inline int power(int x,int p){
		int res=1;
		for(;p;p>>=1,x=(ll)x*x%mod)
			if(p&1)res=(ll)res*x%mod;
		return res;
	}
	inline int fix(int x){
		return x>=mod?x-mod:x;
	}
	void dft(poly &A,int n){
		A.resize(1<<n);int *a=&(A.front());
		static int R[N],W[N<<1],*H[20],*las=W,mx=0;
		for(;mx<n;mx++){
			H[mx]=las;int w=1,wn=power(g,(mod-1)>>(mx+1));
			REP(i,1<<mx)*las++=w,w=(ll)w*wn%mod;
		}
		REP(i,1<<n){
			R[i]=(i&1?R[i^1]|(1<<(n-1)):R[i>>1]>>1);
			if(i<R[i])swap(a[i],a[R[i]]);
		}
		for(int k=0,d=1;k<n;k++,d<<=1)
			for(int i=0;i<(1<<n);i+=d<<1){
				int *l=a+i,*r=a+i+d,*w=H[k],x,y;
				for(int j=0;j<d;j++,l++,r++){
					x=*l,y=(ll)(*r)*(*w++)%mod;
					*l=fix(x+y),*r=fix(x+mod-y);
				}
			}
	}
	void idft(poly &a,int n){
		a.resize(1<<n);
		reverse(a.begin()+1,a.end()),dft(a,n);
		int inv=power(1<<n,mod-2);
		REP(i,1<<n)a[i]=(ll)a[i]*inv%mod;
	}
	poly mul(poly a,poly b){
		int aim=a.size()+b.size(),n=1;
		while((1<<n)<aim)n++;
		dft(a,n),dft(b,n);
		REP(i,1<<n)a[i]=(ll)a[i]*b[i]%mod;
		return idft(a,n),a.resize(aim-1),a;
	}
}
int f[M][N],t[N],ans[N],a[M],b[M],c[M];
int ind[N],po[N],fac[N],rev[N];
