int power(int x,int k){
	int res=1;
	for(;k;k>>=1,x=(ll)x*x%p)
		if(k&1)res=(ll)res*x%p;
	return res;
}
int chk(int g){
	rep(i,1,phi-1)if(power(g,i)==1)return 0;
	return 1;
}
int C(int n,int m){
	if(m<0||m>n)return 0;
	return (ll)fac[n]*rev[m]%p*rev[n-m]%p;
}
void Mul(int a[N],int b[N],int c[N]){
	vi A(phi),B(phi);
	int sa=0,sb=0;
	rep(i,1,p-1){
		A[ind[i]]=a[i];
		B[ind[i]]=b[i];
		sa=(sa+a[i])%mod;
		sb=(sb+b[i])%mod;
	}
	vi C=Poly::mul(A,B);
	ll aa=a[0],bb=b[0];
	memset(c,0,sizeof t);
	c[0]=(aa*sb+bb*sa+aa*bb)%mod;
	REP(i,C.size())
		c[po[i%phi]]=(c[po[i%phi]]+C[i])%mod;
}
void init(){
	for(phi=p-1,g=1;!chk(g);g++);
	ind[po[0]=1]=0;
	rep(i,1,phi-1){
		po[i]=(ll)po[i-1]*g%p;
		ind[po[i]]=i;
	}
	fac[0]=1;
	rep(i,1,p-1)fac[i]=(ll)fac[i-1]*i%p;
	rev[p-1]=power(fac[p-1],p-2);
	per(i,p-1,1)rev[i-1]=(ll)rev[i]*i%p;
	f[0][1]=1;
	rep(k,1,len){
		memset(t,0,sizeof t);
		rep(i,0,p-1)t[C(i,a[k])]++;
		Mul(f[k-1],t,f[k]);
	}
}

void solve(int b[],ll op){
	int bas=1;
	per(k,len,1){
		memset(t,0,sizeof t);
		rep(i,0,b[k]-1)t[(ll)C(i,a[k])*bas%p]++;
		Mul(t,f[k-1],t);
		REP(i,p)ans[i]=(ans[i]+(ll)op*t[i])%mod;
		bas=(ll)bas*C(b[k],a[k])%p;
	}
	ans[bas]=(ans[bas]+op)%mod;
}

