int n,m,qu;
vc<Edge> e[MAXN];

int plog2[MAXN];
namespace TREE{
	#define PMAXN 300010
	#define PLOG 18
	ll toroot[PMAXN];
	int dep[PMAXN], up[PMAXN][PLOG];
	int dots[PMAXN];
	void Predfs( int pos , int fa , ll fadis ){
		dep[pos] = dep[fa] + 1;
		toroot[pos] = toroot[fa] + fadis;
		up[pos][0] = fa;
		For(i,PLOG-1) up[pos][i] = up[up[pos][i-1]][i-1];
		for( auto ue : e[pos] ){
			int v = ue.to;
			if( v == fa ) continue;
			Predfs(v,pos,ue.cost);
		}
	}
	il int Lca( rg int a , rg int b ){
		if( dep[a] < dep[b] ) swap(a,b);
		rg int upcnt = dep[a]-dep[b];
		For0(i,PLOG){
			if(upcnt&1) a = up[a][i];
			upcnt >>= 1;
		}
		if( a == b )
			return a;
		rg int lim = plog2[dep[a]]+1;
		fOR0(i,lim){
			int u = up[a][i], v = up[b][i];
			if( u != v ){
				a = u; b = v;
			}
		}
		// assert( up[a][0] == up[b][0] );
		return up[a][0];
	}
	void Solve(){
		int root = 4;rand()%n+1;
		Predfs(root,0,0);
		Read(qu);
		For(qwq,qu){
			Read(m);
			if( m == 1 ){
				iRead(_a);
				printf("0\n");
				continue;
			}
			For(i,m) Read(dots[i]);

			rg ll mxdis = 0, mxp;
			rg int st = dots[1];
			Forx(i,2,m){
				ll tdis = toroot[st] + toroot[dots[i]] - (toroot[Lca(st,dots[i])]<<1LL);
				if( tdis > mxdis ){
					mxdis = tdis;
					mxp = dots[i];
				}
			}

			mxdis = 0;
			st = mxp;
			For(i,m){
				if( dots[i] == st ) continue;
				ll tdis = toroot[st] + toroot[dots[i]] - (toroot[Lca(st,dots[i])]<<1LL);
				Mymax(mxdis,tdis);
			}
			printf("%lld\n",mxdis);
		}
		END();
	}
}

