vc<Edge> tree[MAXN];

int dfn[MAXN], low[MAXN], nowtime = 0;
bool issqu[MAXN];
ll origindep[MAXN];
int st[MAXN], top = 0;
ll cyclen[MAXN];
void Tarjan( int pos , int fa , ll fad ){
	origindep[pos] = origindep[fa] + fad;
	st[++top] = pos;
	dfn[pos] = low[pos] = ++nowtime;
	for( auto ue : e[pos] ){
		int v = ue.to;
		if( v == fa ) continue;
		if(dfn[v]){
			if( dfn[v] > dfn[pos] ) continue;
			Mymin(low[pos],dfn[v]);
			int squ = ++n;
			int ttop = top;

			int w = 0;
			ll cyclen = ue.cost + origindep[pos]-origindep[v];
			while( w != v )
				w = st[ttop--];

			issqu[squ] = 1;
			::cyclen[squ] = cyclen;
			ll len1 = 0;
			Forx(i,ttop+1,top){
				int p = st[i];
				tree[squ].Pb({p,min(len1,cyclen-len1)});
				tree[p].Pb({squ,min(len1,cyclen-len1)});
				len1 += origindep[st[i+1]] - origindep[st[i]];
			}
		}else{
			Tarjan(v,pos,ue.cost);
			Mymin(low[pos],low[v]);
			if( low[v] > dfn[pos] ){
				tree[pos].Pb({v,ue.cost});
				tree[v].Pb({pos,ue.cost});
			}
		}
	}
	st[top--] = 0;
}

int up[MAXN][LOG];
int dep[MAXN];
int in[MAXN], out[MAXN];	// nowtime=0 is needed
ll toroot[MAXN];
void Updfs( rg int pos , int fa , ll fadis ){
	dep[pos] = dep[fa] + 1;
	toroot[pos] = toroot[fa] + fadis;
	up[pos][0] = fa;
	in[pos] = ++nowtime;
	For(i,LOG-1)
		up[pos][i] = up[up[pos][i-1]][i-1];
	for( auto ue : tree[pos] ){
		int v = ue.to;
		if( v == fa ) continue;
		Updfs(v,pos,ue.cost);
	}
	out[pos] = nowtime;
}
il int Climbnear( rg int pos , int goal ){
	rg int upcnt = dep[pos]-dep[goal]-1;
	For0(i,LOG){
		if(upcnt&1) pos = up[pos][i];
		upcnt >>= 1;
	}
	return pos;
}
il int Lca( rg int a , rg int b ){
	if( dep[a] < dep[b] ) swap(a,b);
	rg int upcnt = dep[a]-dep[b];
	For0(i,LOG){
		if(upcnt&1) a = up[a][i];
		upcnt >>= 1;
	}
	if( a == b ) return a;
	rg int lim = plog2[dep[a]]+1;
	fOR0(i,lim){
		int u = up[a][i], v = up[b][i];
		if( u != v ){
			a = u; b = v;
		}
	}
	return up[a][0];
}

il bool Byin( int a , int b ){ return in[a] < in[b]; }
int dots[MAXN<<1];	// 此时m表示点数
bool islegal[MAXN];
int root;

vc<Edge> virtree[MAXN];
int p;
void Buildvirtree( int pos ){
	while(1){
		++p;
		if( p > m || in[dots[p]] > out[pos] ){
			--p;
			return;
		}
		virtree[pos].Pb({dots[p],toroot[dots[p]]-toroot[pos]});
		Buildvirtree(dots[p]);
	}
}

ll ans = 0;
ll dp[MAXN], tmp[MAXN], deptmp[MAXN];
multiset<ll> tmpset;
void Dp( int pos ){
	if(!issqu[pos]){
		ll mx = 0, secmx = 0;
		for( auto ue : virtree[pos] ){
			int v = ue.to;
			Dp(v);
			ll tans = dp[v] + (issqu[v]?0:ue.cost);
			if( tans >= mx ){
				secmx = mx;
				mx = tans;
			}else
				Mymax(secmx,tans);
		}
		if( pos != root || islegal[pos] )
			Mymax(ans,mx+secmx);
		dp[pos] = mx;
	}else{
		// assert(fa);
		sort(All(virtree[pos]),[]( const Edge &a , const Edge &b ){
			return origindep[a.to] < origindep[b.to];
		});
		int n = virtree[pos].size();
		ll mx = 0;
		For0(i,n){
			int v = virtree[pos][i].to;
			Dp(v);
			ll direct = virtree[pos][i].cost;
			Mymax(mx,dp[v]+direct);
		}
		if( n > 1 ){
			For0(i,n){
				int v = virtree[pos][i].to;
				deptmp[i] = origindep[v];
				tmp[i] = dp[v];
			}
			tmpset.clear();
			for( int l = 0, r = 0 ; l < n ; ++l ){
				while( r < n && deptmp[r]-deptmp[l] <= (cyclen[pos]>>1LL) ){
					tmpset.insert(deptmp[r]+tmp[r]);
					++r;
				}
				tmpset.erase(tmpset.find(deptmp[l]+tmp[l]));
				if(!tmpset.empty()){
					ll tans = *tmpset.rbegin()-deptmp[l]+tmp[l];
					Mymax(ans,tans);
				}
			}
			tmpset.clear();
			for( int l = 0, r = 0 ; l < n ; ++l ){
				while( r < n && cyclen[pos]-(deptmp[l]-deptmp[r]) <= (cyclen[pos]>>1LL) ){
					tmpset.insert(deptmp[r]+tmp[r]);
					++r;
				}
				if(!tmpset.empty()){
					ll tans = cyclen[pos]+*tmpset.rbegin()+tmp[l]-deptmp[l];
					Mymax(ans,tans);
				}
			}
		}
		dp[pos] = mx;
	}
}

ll Solve(){
	For(i,m){
		islegal[dots[i]] = 1;
	}
	sort(dots+1,dots+1+m,Byin);
	int om = m;
	For(i,om-1){
		int a = dots[i], b = dots[i+1];
		int lca = Lca(a,b);
		islegal[lca] = 1;
		// if(intree[lca]) continue;
		dots[++m] = lca;
		if(issqu[lca]){
			int ap = Climbnear(a,lca);
			int bp = Climbnear(b,lca);
			dots[++m] = ap;
			dots[++m] = bp;
			dots[++m] = up[lca][0];
		}
	}
	sort(dots+1,dots+1+m,Byin);
	m = unique(dots+1,dots+1+m) - dots - 1;

	root = dots[1];

	p = 1;
	Buildvirtree(root);
	// Printtree(virtree);
	ans = 0;
	Dp(root);

	For(i,m){
		int p = dots[i];
		islegal[p] = 0;
		virtree[p].clear();
	}
	return ans;
}

