#define get(_) INPUT::get(_)
typedef long long LL;
typedef double DB;
const int N=400005,M=600005;
struct Seg
{LL k,b;
 Seg(int x_=0,int y_=0,int _x=0,int _y=0)
 {if(_x==x_) k=0,b=max(_y,y_);
  else k=(_y-y_)/(DB)(_x-x_),b=y_-x_*k;
 }
 LL Y(LL X){return k*X+b;}
 DB operator*(Seg A){return (b-A.b)/(DB)(A.k-k);}
}S[N];
bool cmp(int a,int b,DB p){return a==0||(S[a].Y(p)!=S[b].Y(p)?S[a].Y(p)<S[b].Y(p):a<b);}
int n,m,C,Q,tim[M],K,tot,St[N],Ed[N],La[N];
LL X[N],A[N],TM[N];
#define Lc (x<<1)
#define Rc (x<<1|1)
#define Mid (l+r>>1)
LL abs(LL _){return _<0?-_:_;}
struct Segtree
{int T[N<<2];
 void Ins(int x,int l,int r,int L,int R,int k)
 {if(L<=l&&r<=R)
  {if(!T[x]) return (void)(T[x]=k);
   if(cmp(T[x],k,tim[l])) swap(T[x],k);
   if(S[T[x]].k==S[k].k||l==r) return;
   DB w=S[T[x]]*S[k];
   if(w<=tim[Mid]&&w>=tim[l]) Ins(Lc,l,Mid,L,R,T[x]),T[x]=k;
   else if(w>tim[Mid]&&w<=tim[r]) Ins(Rc,Mid+1,r,L,R,k);
  }
  else
  {if(L<=Mid) Ins(Lc,l,Mid,L,R,k);
   if(R>Mid) Ins(Rc,Mid+1,r,L,R,k);
  }
 }
 LL Ask(int x,int l,int r,int p)
 {LL W=S[T[x]].Y(p),k=0;
  if(l!=r)
   if(p<=tim[Mid]) k=Ask(Lc,l,Mid,p);
   else k=Ask(Rc,Mid+1,r,p);
  return max(W,k);
 }
}S1,S2;
