#include <cstdio>
#include <algorithm>
using namespace std;

#define n	500005
#define DB	double
#define I64	long long
#define CH	(ch=getchar())
#define max(a,b)	((a)>(b)?(a):(b))
#define For(i,a,b)	for(int i=a;i<=b;i++)

int		N,Q,D,V[n],st[n],be[n],tim[n],T[n<<2];
char	s[15];
I64		A[n];

struct	Lin{
		I64 b;	int k,l,r;
		I64	val(int x)	{return	1ll*k*x+b;}
		DB	operator * (const Lin&x){
			return	1.*(x.b-b)/(k-x.k);
		}
}seg[n];

void	INS(int u,int l,int r,int x,int y,int k){
		if	(x<=l&&r<=y){
			if	(!T[u])	{T[u]=k;return;}
			if	(seg[T[u]].val(tim[l])<seg[k].val(tim[l]))	swap(T[u],k);
			if	(l==r||seg[T[u]].k==seg[k].k)	return;
			DB	focus=seg[T[u]]*seg[k];	int Mid=l+r>>1;
			if	(focus<=tim[Mid]&&focus>=tim[l])	INS(u<<1,l,Mid,x,y,T[u]),T[u]=k;
			else	if	(focus>=tim[Mid]&&focus<=tim[r])	INS(u<<1|1,Mid+1,r,x,y,k);
		}	else	{
			int Mid=l+r>>1;
			if	(x<=Mid)INS(u<<1,l,Mid,x,y,k);
			if	(y>Mid)	INS(u<<1|1,Mid+1,r,x,y,k);
		}
}
I64		Ask(int u,int l,int r,int k){
		I64	ret=seg[T[u]].val(tim[k]),W=0;	int Mid=l+r>>1;
		if	(l^r)	W=(k<=Mid?Ask(u<<1,l,Mid,k):Ask(u<<1|1,Mid+1,r,k));
		return	max(ret,W);
}

int		IN(){
		int x=0,f=0,ch;
		for	(;CH<'0'||ch>'9';)	f=(ch=='-');
		for	(;ch>='0'&&ch<='9';CH)	(x*=10)+=ch-'0';
		return	f?-x:x;
}

int		main(){
		N=IN();	Q=IN();
		For(i,1,N)	A[i]=IN();
		For(i,1,Q)	{
			int t=IN(),f=getchar();
			if	(f=='q')	tim[++*tim]=t;
			else	{
				int x=IN(),v=IN();
				seg[++D]=(Lin){A[x]-1ll*be[x]*V[x],V[x],st[x]+1,*tim};
				seg[++D]=(Lin){-A[x]+1ll*be[x]*V[x],-V[x],st[x]+1,*tim};
				A[x]+=1ll*(t-be[x])*V[x];V[x]=v;	st[x]=*tim;be[x]=t;
			}
		}
		For(i,1,N)	{
			seg[++D]=(Lin){A[i]-1ll*be[i]*V[i],V[i],st[i]+1,*tim};
