void change(int x,bitset<N> y){
	b[x]^=y; vis[x]=1;
	for(int i=T;i;i--)if(p[i][x]){
		int t=0;
		for(int j=1;j<i;j++)if(p[j][x]){
			if(!c[j][j]){
				if(t){p[j]^=p[t]; } else t=j;
				continue;
			}
			p[j]^=p[i]; c[j]^=c[i];
		}
		if(t){p[t]^=p[i]; c[t]^=c[i];}
		c[i]^=y; 
