int n, m, q;
std::bitset<2000> p[2000], b[2000];
std::map<int, std::bitset<2000>> map;
void make(int pos) { map.insert({pos, (--map.upper_bound(pos))->second}); }
void Xor(int l, int r, std::bitset<2000> w)
{
    std::map<int, std::bitset<2000>>::iterator iter = map.lower_bound(l);
    while (iter->first != r)
        (iter++)->second ^= w;
    std::bitset<2000> e;
    for (int i = l; i != r; ++i)
        e.set(i);
    std::vector<int> vis;
    for (int i = 0; i != n; ++i)
        if ((e & p[i]).count() & 1)
            b[i] ^= w, vis.push_back(i);
    if (vis.empty())
        return;
    int x = vis.back();
    for (std::size_t i = 0; i + 1 != vis.size(); ++i)
    {
        p[vis[i]] ^= p[x];
        b[vis[i]] ^= b[x];
    }
    std::rotate(p + x, p + x + 1, p + n);
    std::rotate(b + x, b + x + 1, b + n);
    x = n - 1;
    for (int i = m, j = 0, k = m - 1; i--;)
        if (b[x].test(i))
        {
            while (k > i && j < x)
                if (b[j].test(k))
                    ++j;
                else
                    --k;
            if (j == x)
                break;
            while (~k && !b[j].test(k))
                --k;
            if (i == k)
            {
                p[x] ^= p[j];
                b[x] ^= b[j];
            }
            else
            {
                std::rotate(p + j, p + x, p + x + 1);
                std::rotate(b + j, b + x, b + x + 1);
            }
        }
}
std::bitset<2000> query()
{
    std::bitset<2000> res;
    for (int i = 0, j = m - 1; i != n; ++i)
    {
        while (~j && !b[i].test(j))
            --j;
        if (~j && !res.test(j))
            res ^= b[i];
    }
    return res;
}
void Del(int l, int r)
{
    std::map<int, std::bitset<2000>>::iterator iter = map.lower_bound(l);
    while (iter->first != r)
    {
        Xor(iter->first, std::next(iter)->first, iter->second);
        map.erase(iter++);
    }
    map.insert({l, std::bitset<2000>()});
}
