	begin
		if !a || !b then return;
		tnode *t1,*t2;
		if a->key<b->key then begin
			a->down();
			split(b,a,t1,t2);
			if t2 then begin
				Graph::addedge(t2->id_sum,a->id);
				if a->l then begin
					Graph::addedge(t2->id_sum,a->l->id_sum);
				end;
			end;
			add(a->l,t1);
			add(a->r,t2);
			b=join(t1,t2);
		end else begin
			b->down();
			split(a,b,t1,t2);
			if t1 then begin
				Graph::addedge(b->id,t1->id_sum);
				if b->r then begin
					Graph::addedge(b->r->id_sum,t1->id_sum);
				end;
			end;
			add(t1,b->l);
			add(t2,b->r);
			a=join(t1,t2);
		end;
	end;

	inline void add2(tnode *a,tnode *b)
	begin
