			Graph::addedge(idtot,id_sum[A[i-1]]);
		end;
	end;
	
	inline void add_edges(std::vector<int> &Queries,std::vector<int> &Nodes)
	begin
		int size_Q=Queries.size();
		int size_N=Nodes.size();
		if !size_Q || !size_N then return;
		int i,j=0;
		for i=0;i<size_Q;i++ do begin
			int qid=Queries[i];
			int qdist=q_dist[qid];
			while j<size_N && dist[Nodes[j]]<=qdist do ++j;
			if j>0 then begin
				Graph::addedge(n+qid,id_sum[Nodes[j-1]]);
			end;
		end;
	end;
	
	inline void solve(int x);
	
	inline void solve_tree(int x)
	begin
		visit[x]=1;
		clear_visit();
		clear_cycle();
		fa_e[x]=mo_e[x]=NULL;
		cyc[x]=NULL;
		SET_VISIT(x);
		dep[x]=0;
		dist[x]=0;
		std::vector<int> Nodes[3],Queries[3];
		int id=-1;
		for edge *te=first[x];te;te=te->next do begin
			int ty=te->y;
			if visit[ty] then continue;
			++id;
			fa_e[ty]=mo_e[ty]=NULL;
			cyc[ty]=NULL;
			SET_VISIT(ty);
			dep[ty]=te->len;
			dist[ty]=te->len;
			dfs1(ty,x);
			now_root=ty;
			dfs3(ty,Nodes[id],Queries[id]);
			std::vector<int> &tmp_nodes=Nodes[id],&tmp_queries=Queries[id];
			if tmp_nodes.size() then begin
				SORT(tmp_nodes,cmp_dist);
				pre_id_sum(tmp_nodes);
			end;
			if tmp_queries.size() then begin
				SORT(tmp_queries,cmp_q_dist);
			end;
		end;
		int cnt=id+1;
		int i,j;
		for i=0;i<cnt;i++ do begin
			for j=0;j<cnt;j++ do if j!=i then begin
				add_edges(Queries[i],Nodes[j]);
			end;
		end;
		if x<=n then begin
			for i=0;i<cnt;i++ do begin
				std::vector<int> &tmp_queries=Queries[i];
				int size=tmp_queries.size();
				for j=0;j<size;j++ do begin
					Graph::addedge(n+tmp_queries[j],x);
				end;
			end;
		end else if _qid[x] then begin
			int qid=_qid[x];
			std::vector<int> tmp;
			tmp.push_back(qid);
			q_dist[qid]=_d[qid];
			for i=0;i<cnt;i++ do begin
				add_edges(tmp,Nodes[i]);
			end;
		end;
		for i=0;i<cnt;i++ do begin
			Nodes[i].clear();
			Queries[i].clear();
		end;
		for edge *te=first[x];te;te=te->next do begin
			int ty=te->y;
			if visit[ty] then continue;
			solve(ty);
		end;
	end;
	
	int dac_n;
	
	int dac_dist[MAXN];
	int dac_q_dist[MAXN];
	
	inline bool cmp_dac_dist(int i,int j)
	begin
		return dac_dist[i]<dac_dist[j];
	end;
	
	inline bool cmp_dac_q_dist(int i,int j)
	begin
		return dac_q_dist[i]<dac_q_dist[j];
	end;
	
	inline void add_edges_dac(std::vector<int> &Queries,std::vector<int> &Nodes,int deltaQ=0,int deltaN=0)
	begin
		int size_Q=Queries.size();
		int size_N=Nodes.size();
		if !size_Q || !size_N then return;
		int i,j=0;
		for i=0;i<size_Q;i++ do begin
			int qid=Queries[i];
			int qdist=dac_q_dist[qid]+deltaQ;
			while j<size_N && dac_dist[Nodes[j]]+deltaN<=qdist do ++j;
			if j>0 then begin
				Graph::addedge(n+qid,id_sum[Nodes[j-1]]);
			end;
		end;
	end;
	
	int dac_node_id[MAXN];
	int dac_pos[MAXN];
	std::vector<int> dac_nodes[MAXN];
	std::vector<int> dac_queries[MAXN];
	int dac_size[MAXN];
	
	inline void merge(std::vector<int> &a,std::vector<int> &b,std::vector<int> &c,std::vector<int> &ret,bool (*cmp)(int,int))
	begin
		#undef begin
		#undef end
		std::vector<int> tmp(a.size()+b.size());
		std::merge(a.begin(),a.end(),b.begin(),b.end(),tmp.begin(),cmp);
		ret=std::vector<int>(tmp.size()+c.size());
		std::merge(tmp.begin(),tmp.end(),c.begin(),c.end(),ret.begin(),cmp);
		a.clear();b.clear();c.clear();tmp.clear();
		#define begin {
		#define end }
	end;
	
	inline void solve(int l,int r,std::vector<int> &all_nodes,std::vector<int> &all_queries)
	begin
		if l==r then begin
			all_nodes=dac_nodes[l];
			all_queries=dac_queries[l];
			return;
		end;
		int sum=0;
		int i;
		for i=l;i<=r;i++ do begin
			sum+=dac_size[i];
		end;
		int tmp=0;
		for i=l;i<=r;i++ do begin
			if tmp*2<=sum && (tmp+dac_size[i])*2>=sum then break;
			tmp+=dac_size[i];
		end;
		int mid=i;
		std::vector<int> nL,nM,nR,qL,qM,qR;
		nM=dac_nodes[mid];
		qM=dac_queries[mid];
		
		if l<mid then begin
			solve(l,mid-1,nL,qL);
		end;
		if mid<r then begin
			solve(mid+1,r,nR,qR);
		end;
		
		bool fL=0;
		
		if qM.size() && nL.size() then begin
			if !fL then fL=1,pre_id_sum(nL);
			add_edges_dac(qM,nL,(dac_pos[mid]-dac_pos[1]),-(dac_pos[dac_n]-dac_pos[mid]));
		end;
		if qR.size() && nL.size() then begin
			if !fL then fL=1,pre_id_sum(nL);
			add_edges_dac(qR,nL,(dac_pos[mid]-dac_pos[1]),-(dac_pos[dac_n]-dac_pos[mid]));
		end;
		if qR.size() && nM.size() then begin
			pre_id_sum(nM);
			add_edges_dac(qR,nM,(dac_pos[mid]-dac_pos[1]),-(dac_pos[dac_n]-dac_pos[mid]));
		end;
		
		merge(nL,nM,nR,all_nodes,cmp_dac_dist);
		merge(qL,qM,qR,all_queries,cmp_dac_q_dist);
	end;
	
	inline void solve_2(int l,int r,std::vector<int> &all_nodes,std::vector<int> &all_queries)
	begin
		if l==r then begin
			all_nodes=dac_nodes[l];
			all_queries=dac_queries[l];
			return;
		end;
		int sum=0;
		int i;
		for i=l;i<=r;i++ do begin
			sum+=dac_size[i];
		end;
		int tmp=0;
		for i=l;i<=r;i++ do begin
			if tmp*2<=sum && (tmp+dac_size[i])*2>=sum then break;
			tmp+=dac_size[i];
		end;
		int mid=i;
		std::vector<int> nL,nM,nR,qL,qM,qR;
		nM=dac_nodes[mid];
		qM=dac_queries[mid];
		
		if l<mid then begin
			solve_2(l,mid-1,nL,qL);
		end;
		if mid<r then begin
			solve_2(mid+1,r,nR,qR);
		end;
		
		bool fL=0;
		
		if qM.size() && nL.size() then begin
			if !fL then fL=1,pre_id_sum(nL);
			add_edges_dac(qM,nL);
		end;
		if qR.size() && nL.size() then begin
			if !fL then fL=1,pre_id_sum(nL);
			add_edges_dac(qR,nL);
		end;
		if qR.size() && nM.size() then begin
			pre_id_sum(nM);
			add_edges_dac(qR,nM);
		end;
		
		merge(nL,nM,nR,all_nodes,cmp_dac_dist);
		merge(qL,qM,qR,all_queries,cmp_dac_q_dist);
	end;
	
	inline void clear_dac()
	begin
		int i;
		for i=1;i<=dac_n;i++ do begin
			dac_nodes[i].clear();
			dac_queries[i].clear();
		end;
		dac_n=0;
	end;
	
	inline void set_dac_dist(std::vector<int> &Nodes,int d)
	begin
		int size=Nodes.size();
		int i;
		for i=0;i<size;i++ do begin
			int x=Nodes[i];
			dac_dist[x]=dist[x]+d;
		end;
	end;
	
	inline void set_dac_q_dist(std::vector<int> &Queries,int d)
	begin
		int size=Queries.size();
		int i;
		for i=0;i<size;i++ do begin
			int x=Queries[i];
			dac_q_dist[x]=q_dist[x]+d;
		end;
	end;
	
	std::vector<int> cycle_Nodes[MAXN],cycle_Queries[MAXN];
	
	inline void add_to_dac(int y,int pos,int dist_add,int q_dist_add)
	begin
		++dac_n;
		dac_pos[dac_n]=pos;
		dac_size[dac_n]=size[y];
		dac_nodes[dac_n]=cycle_Nodes[y];
		dac_queries[dac_n]=cycle_Queries[y];
		set_dac_dist(dac_nodes[dac_n],dist_add);
		set_dac_q_dist(dac_queries[dac_n],q_dist_add);
	end;
	
	inline void add_nodes_to_dac(int y,int dist_add)
	begin
		++dac_n;
		dac_size[dac_n]=size[y];
		dac_nodes[dac_n]=cycle_Nodes[y];
		dac_queries[dac_n].clear();
		set_dac_dist(dac_nodes[dac_n],dist_add);
	end;
	
	inline void add_queries_to_dac(int y,int q_dist_add)
	begin
		++dac_n;
		dac_size[dac_n]=size[y];
		dac_nodes[dac_n].clear();
		dac_queries[dac_n]=cycle_Queries[y];
		set_dac_q_dist(dac_queries[dac_n],q_dist_add);
	end;
	
	inline int check_mindist(int x,int cyclen)
	begin
		return dep[x]<cyclen-dep[x];
	end;
	
	inline void solve_cycle(int x)
	begin
		
		
		int cyclen=cyc[x]->len;
		int last=cyc[x]->last;
		visit[x]=1;
		clear_visit();
		clear_cycle();
		int y=mo_e[x]->y;
		while y!=x do begin
			visit[y]=1;
			dep[y]-=dep[x];
			y=mo_e[y]->y;
		end;
		dep[x]=0;
		
		
		y=x;
		while 1 do begin
			bool f=false;
			for edge *te=first[y];te;te=te->next do if !visit[te->y] then begin
				f=true;
				int ty=te->y;
				fa_e[ty]=mo_e[ty]=NULL;
				cyc[ty]=NULL;
				SET_VISIT(ty);
				dep[ty]=te->len;
				dist[ty]=te->len;
				dfs1(ty,y);
				size[y]=size[ty]+1;
				now_root=ty;
				dfs3(ty,cycle_Nodes[y],cycle_Queries[y]);
				std::vector<int> &tmp_nodes=cycle_Nodes[y],&tmp_queries=cycle_Queries[y];
				if tmp_nodes.size() then begin
					SORT(tmp_nodes,cmp_dist);
				end;
				if tmp_queries.size() then begin
					SORT(tmp_queries,cmp_q_dist);
				end;
				if y<=n then begin
					int i;
					int size=tmp_queries.size();
					for i=0;i<size;i++ do begin
						Graph::addedge(n+tmp_queries[i],y);
					end;
					tmp_nodes.push_back(y);
					dist[y]=0;
				end else if _qid[y] then begin
					int qid=_qid[y];
					q_dist[qid]=_d[qid];
					int size=tmp_nodes.size();
					int i;
					for i=0;i<size;i++ do begin
						int x=tmp_nodes[i];
						if q_dist[qid]>=dist[x] then begin
							Graph::addedge(n+qid,x);
						end;
					end;
					tmp_queries.push_back(qid);
				end;
				if tmp_nodes.size() then begin
					SORT(tmp_nodes,cmp_dist);
				end;
				if tmp_queries.size() then begin
					SORT(tmp_queries,cmp_q_dist);
				end;
			end;
			if !f then begin
				if y<=n then begin
					cycle_Nodes[y].push_back(y);
					dist[y]=0;
				end else if _qid[y] then begin
					int qid=_qid[y];
					cycle_Queries[y].push_back(qid);
					q_dist[qid]=_d[qid];
				end;
				size[y]=1;
			end;
			y=mo_e[y]->y;
			if y==x then break;
		end;
		
		
		std::vector<int> tmp1,tmp2;
		
		int y1=mo_e[x]->y;
		
		if check_mindist(last,cyclen) then begin
			clear_dac();
			add_to_dac(x,0,dep[last],0);
			for y=mo_e[x]->y;y!=x;y=mo_e[y]->y do begin
				add_to_dac(y,dep[y],dep[last]-dep[y],-dep[y]);
			end;
			solve(1,dac_n,tmp1,tmp2);
			
			clear_dac();
			for y=last;y!=x;y=fa_e[y]->y do begin
				add_to_dac(y,dep[last]-dep[y],dep[y],-(dep[last]-dep[y]));
			end;
			add_to_dac(x,dep[last]-dep[x],dep[x],-(dep[last]-dep[x]));
			solve(1,dac_n,tmp1,tmp2);
		end else if !check_mindist(mo_e[x]->y,cyclen) then begin
			clear_dac();
			add_to_dac(x,0,cyclen-dep[y1],0);
			for y=last;y!=x;y=fa_e[y]->y do begin
				add_to_dac(y,cyclen-dep[y],dep[y]-dep[y1],-(cyclen-dep[y]));
			end;
			solve(1,dac_n,tmp1,tmp2);
			
			clear_dac();
			for y=y1;y!=x;y=mo_e[y]->y do begin
				add_to_dac(y,dep[y]-dep[y1],cyclen-dep[y],-(dep[y]-dep[y1]));
			end;
			add_to_dac(x,cyclen-dep[y1],0,-(cyclen-dep[y1]));
			solve(1,dac_n,tmp1,tmp2);
		end else begin
			int A,B;
			int i;
			for i=y1;;i=mo_e[i]->y do begin
				if !check_mindist(i,cyclen) then break;
			end;
			B=i;A=fa_e[i]->y;
			
			
			clear_dac();
			for i=x;i!=B;i=mo_e[i]->y do begin
				add_to_dac(i,dep[i],dep[A]-dep[i],-(dep[i]));
			end;
			solve(1,dac_n,tmp1,tmp2);
			
			clear_dac();
			for i=A;;i=fa_e[i]->y do begin
				add_to_dac(i,dep[A]-dep[i],dep[i],-(dep[A]-dep[i]));
				if i==x then break;
			end;
			solve(1,dac_n,tmp1,tmp2);
			
			clear_dac();
			for i=B;i!=x;i=mo_e[i]->y do begin
				add_to_dac(i,dep[i]-dep[B],dep[last]-dep[i],-(dep[i]-dep[B]));
			end;
			solve(1,dac_n,tmp1,tmp2);
			
			clear_dac();
			for i=last;i!=A;i=fa_e[i]->y do begin
				add_to_dac(i,dep[last]-dep[i],dep[i]-dep[B],-(dep[last]-dep[i]));
			end;
			solve(1,dac_n,tmp1,tmp2);
			
			int j;
			
			clear_dac();
			j=B;
			for i=x;i!=B;i=mo_e[i]->y do begin
				while j!=x && dep[j]-dep[i]<cyclen-(dep[j]-dep[i]) do begin
					add_nodes_to_dac(j,dep[j]-dep[B]);
					j=mo_e[j]->y;
				end;
				add_queries_to_dac(i,-(dep[B]-dep[i]));
			end;
			solve_2(1,dac_n,tmp1,tmp2);
			
			clear_dac();
			j=A;
			for i=last;i!=A;i=fa_e[i]->y do begin
				while j && dep[i]-dep[j]<cyclen-(dep[i]-dep[j]) do begin
					add_nodes_to_dac(j,dep[A]-dep[j]);
					if j==x then begin
						j=0;
					end else begin
						j=fa_e[j]->y;
					end;
				end;
				add_queries_to_dac(i,-(dep[i]-dep[A]));
			end;
			solve_2(1,dac_n,tmp1,tmp2);
			
			clear_dac();
			j=last;
			for i=A;;i=fa_e[i]->y do begin
				while j!=A && cyclen-(dep[j]-dep[i])<=dep[j]-dep[i] do begin
					add_nodes_to_dac(j,dep[last]-dep[j]);
					j=fa_e[j]->y;
				end;
				add_queries_to_dac(i,-(cyclen-(dep[last]-dep[i])));
				if i==x then break;
			end;
			solve_2(1,dac_n,tmp1,tmp2);
			
			clear_dac();
			j=x;
			for i=B;i!=x;i=mo_e[i]->y do begin
				while j!=B && cyclen-(dep[i]-dep[j])<=dep[i]-dep[j] do begin
					add_nodes_to_dac(j,dep[j]);
					j=mo_e[j]->y;
				end;
				add_queries_to_dac(i,-(cyclen-dep[i]));
			end;
			solve_2(1,dac_n,tmp1,tmp2);
			
			
		end;
		
		
		y=x;
		while 1 do begin
			cycle_Nodes[y].clear();
			cycle_Queries[y].clear();
			y=mo_e[y]->y;
			if y==x then break;
		end;
		
		y=x;
		while 1 do begin
			for edge *te=first[y];te;te=te->next do if !visit[te->y] then begin
				solve(te->y);
			end;
			y=mo_e[y]->y;
			if y==x then break;
		end;
	end;
	
	inline void solve(int x)
	begin
		int root=findroot(x);
		if !cyc[root] then begin
			solve_tree(root);
		end else begin
			solve_cycle(root);
		end;
	end;
	
	inline void solve()
	begin
		idtot=n+q;
		init_edges();
		init_queries();
		solve(1);
	end;
	
end;

int main()
begin
	read(n);read(m);read(q);
	divide_and_conquer_on_cactus::solve();
	Graph::out();
end

