int n,m,D[N],L[N],V[N];
namespace SGT{
#define ls k<<1
#define rs k<<1|1
#define mid ((l+r)>>1)
	int Min[N<<2],Sum[N<<2],val;
	void Pushup(int k){Min[k]=min(Min[ls],Min[rs]);}
	int Count(int k,int l,int r,int val){
		if(l==r)return Min[k]<val;
		if(Min[rs]>=val)return Count(ls,l,mid,val);
		return Sum[k]-Sum[rs]+Count(rs,mid+1,r,val);
	}
	void Modify(int k,int l,int r,int x,int y){
		if(l==r)return void(Min[k]=y);
		x<=mid?Modify(ls,l,mid,x,y):Modify(rs,mid+1,r,x,y);
		Pushup(k);Sum[k]=Sum[rs]+Count(ls,l,mid,Min[rs]);
	}
	int QueryMin(int k,int l,int r,int x,int y){
		if(l>=x&&r<=y)return Min[k];
		if(y<=mid)return QueryMin(ls,l,mid,x,y);
		if(mid<x)return QueryMin(rs,mid+1,r,x,y);
		return min(QueryMin(ls,l,mid,x,y),QueryMin(rs,mid+1,r,x,y));
	}
	int Query(int k,int l,int r,int x,int y){
		int res=0;
		if(l>=x&&r<=y){
			res=Count(k,l,r,val);
			val=min(val,Min[k]);
			return res;
		}
		if(mid<y)res+=Query(rs,mid+1,r,x,y);
		if(x<=mid)res+=Query(ls,l,mid,x,y);
		return res;
	}
}
