struct SAM {
    int par[maxn << 1], go[maxn << 1][26];
    int val[maxn << 1];
    int ndtot, root, last;
    void init() {
        memset(par, 0, sizeof(par));
        memset(go, 0, sizeof(go));
        memset(val, 0, sizeof(val));
        ndtot = 0;
        root = last = ++ndtot;
    }
    int pos[maxn], sz[maxn << 1];
    void extend(int w) {
        int p = last;
        int np = ++ndtot; val[np] = val[p] + 1;
        pos[val[np]] = np; sz[np] = 1;
        while (p && go[p][w] == 0)
            go[p][w] = np, p = par[p];
        if (p == 0)
            par[np] = root;
        else {
            int q = go[p][w];
            if (val[q] == val[p] + 1)
                par[np] = q;
            else {
                int nq = ++ndtot; val[nq] = val[p] + 1;
                memcpy(go[nq], go[q], sizeof(go[q]));
                par[nq] = par[q];
                par[np] = nq;
                par[q] = nq;
                while (p && go[p][w] == q)
                    go[p][w] = nq, p = par[p];
            }
        }
        last = np;
    }
    int topo[maxn << 1], cnt;
    int deg[maxn << 1];
    void Topo() {
        static int que[maxn << 1]; int qh(0), qt(0);
        rep(i, 1, ndtot) deg[par[i]]++;
        rep(i, 1, ndtot) if (!deg[i]) que[++qt] = i;
        while (qh != qt) {
            int x = que[++qh];
            topo[++cnt] = x;
            sz[par[x]] += sz[x];
            if (!--deg[par[x]]) que[++qt] = par[x];
        }
    }
    int f[maxn << 1][20];
    void prepare() {
        drep(i, cnt, 1) {
            f[i][0] = par[i];
            rep(j, 1, 19) f[i][j] = f[f[i][j - 1]][j - 1];
        }
    }
    int search(int x, int len) {
        x = pos[x];
        drep(i, 19, 0)
            if (val[f[x][i]] >= len) x = f[x][i];
        return sz[x];
    }
} S;
int P[maxn << 1];
