    for (int i = 1; i <= n; i++) {
        P[i] = mx > i ? min(P[id * 2 - i], mx - i) : 1;
        while (str[i - P[i]] == str[i + P[i]]) {
            P[i]++;
            int len;
            int pos = (i + P[i] - 1) / 2;
            if (str[i] == '#') len = P[i] / 2 * 2;
            else len = P[i] - (~P[i] & 1);
            ans = max(ans, 1ll * len * S.search(pos, len));
        }
        if (i + P[i] > mx) id = i, mx = i + P[i];
    }
    cout << ans << endl;
    return 0;
}

