struct info0
{
	int Min = INT_MAX;
	LL sum = 0;
	int sz = 0;

	info0()=default;
	info0(const int &val): Min(val), sum(val), sz(!!val) { }

	virtual info0 &operator += (const info0 &x)
	{
		Min = min(Min, x.Min), sum += x.sum, sz += x.sz;
		return *this;
	}

	virtual info0 &operator += (const int &x)
	{
		if (sz) Min += x, sum += sz * x;
		return *this;
	}

};

struct info: public info0
{
	int len = 0;
	cir *cir_ptr[2] = {0};
	bool has_cir = 0;
	bool multi_path = 0;

	info()=default;

	void rev() { swap(cir_ptr[0], cir_ptr[1]); }
	void flag_cir(cir *x) { REP(i, 0, 2) cir_ptr[i] = x; }

};

inline info Union(const info &, node *, const info &);

struct cir
{
	node *up = NULL, *down = NULL;
	node *ex_link = NULL;
	bool eql = 0;

	cir()=default;

};

cir cr[max0 + 5];
