struct node
{
	node *p = NULL;
	node *c[4] = {0};
	cir *cir_ptr = NULL;
	int ty = 0;
	int len = 0;
	int val = INT_MAX;
	info sum_chain;
	info0 sum_cactus;
	int label_cactus = 0;
	int label_chain = 0;
	bool label_cir = 0;
	bool rev = 0;

	node()=default;

	info get_info() { return this ? sum_chain : info(); }

	int get_pos()
	{
		if (!this || !p) return 4;
		REP(i, 0, 4) if (p->c[i] == this) return i;
		return 4;
	}

	bool is_root(const int &kind = 0)
	{
		return !this || !p || ty != kind || p->ty != kind || (!kind && get_pos() >= 2);
	}

	void flag_rev()
	{
		if (!this) return;
		rev ^= 1;
		sum_chain.rev();
		swap(c[0], c[1]);
	}

	void flag_chain(const int &_label)
	{
		if (!this) return;
		if (ty) return;
		if (val < INT_MAX) val += _label;
		label_chain += _label;
		sum_chain += _label;
	}

	void flag_cactus(const int &_label)
	{
		if (!this) return;
		label_cactus += _label;
		sum_cactus += _label;
	}

	void flag_cir(cir *_cir_ptr)
	{
		if (!this) return;
		cir_ptr = _cir_ptr;
		sum_chain.flag_cir(_cir_ptr);
		label_cir = 1;
	}

	void push_down()
	{
		if (!this) return;
		if (rev)
		{
			REP(i, 0, 2) if (c[i]) c[i]->flag_rev();
			rev = 0;
		}
		if (label_chain)
		{
			REP(i, 0, 2) if (c[i]) c[i]->flag_chain(label_chain);
			label_chain = 0;
		}
		if (label_cactus)
		{
			if (!ty) REP(i, 0, 2) if (c[i]) c[i]->flag_cactus(label_cactus);
			REP(i, 2, 4) if (c[i]) c[i]->flag_cactus(label_cactus), c[i]->flag_chain(label_cactus);
			label_cactus = 0;
		}
		if (label_cir)
		{
			REP(i, 0, 2) if (c[i]) c[i]->flag_cir(cir_ptr);
			label_cir = 0;
		}
	}

	void setc(node *u, const int &kind)
	{
		if (this && kind < 4) c[kind] = u;
		if (u) u->p = this;
	}

	void rotate(const int &kind = 0)
	{
		if (!this) return;
		node *p = this->p;
		int mark = get_pos();
		p->p->setc(this, p->get_pos());
		p->setc(c[mark ^ 1], mark);
		setc(p, mark ^ 1);
		p->update();
	}

	void relax(const int &kind = 0, node *goal = NULL)
	{
		if (!is_root(kind) && p != goal) p->relax(kind);
		push_down();
	}

	node *splay(const int &kind = 0, node *goal = NULL)
	{
		relax(kind, goal);
		node *u = this;
		while (!u->is_root(kind)) u = u->p;
		for ( ; !is_root(kind) && p != goal; rotate(kind))
			if (!p->is_root(kind) && p->p != goal) (p->get_pos() == get_pos() ? p : this)->rotate();
		update();
		if (!this || ty != kind) return this;
		return p;
	}

	void update()
	{
		if (!this) return; 
		sum_cactus = info0();
		if (!ty) REP(i, 0, 2) if (c[i]) sum_cactus += c[i]->sum_cactus;
		REP(i, 2, 4) if (c[i]) sum_cactus += c[i]->sum_cactus, sum_cactus += c[i]->sum_chain;
		if (!ty) sum_chain = Union(c[0]->get_info(), this, c[1]->get_info());
	}

	void add(node*);

	void del();

	node *access()
	{
		if (!this) return NULL;
		node *u = this, *v = NULL;
		while (u)
		{
			u->splay();
			if (u->c[0] && u->c[0]->sum_chain.cir_ptr[1])
			{
				cir *cir_ptr = u->c[0]->sum_chain.cir_ptr[1];
				node *&up = cir_ptr->up, *&down = cir_ptr->down, *&ex_link = cir_ptr->ex_link;
				down->splay(), up->splay();
				ex_link->splay();
				bool ty = down->is_root();
				if (ty)
				{
					if (down->p->splay(2) != up) swap(up, down), up->splay(), ex_link->flag_rev();
					down->del(), down->push_down();
				}
				else
				{
					down->splay(0, up);
					if (up->c[1] != down)
					{
						swap(up, down);
						up->rotate();
						ex_link->flag_rev();
					}
					up->setc(NULL, 1);
					up->update();
				}
				ex_link->del();
				down->splay(); 
				down->add(down->c[1]);
				down->setc(ex_link, 1);
				u->splay();
				int l = u->c[0] ? u->c[0]->sum_chain.len : 0, r = u->c[1] ? u->c[1]->sum_chain.len : 0;
				cir_ptr->eql = l == r;
				cir_ptr->down->cir_ptr = cir_ptr;
				(cir_ptr->down = u)->cir_ptr = NULL;
				if (l > r) swap(l, r), u->flag_rev(), u->push_down();
				cir_ptr->ex_link = u->c[1];
				up->add(ex_link);
				if (!ty) up->setc(u, 1);
				else up->add(u);
				u->splay();
				v->del();
				u->setc(v, 1);
			}
			else 
			{
				v->del();
				u->add(u->c[1]);
				u->setc(v, 1);
				u->update();
			}
			v = u, u = u->p->splay(2);
		}
		splay();
		return v;
	}

	void be_root() { access(), flag_rev(); }

	bool single() { return this && !sum_chain.sz; }

	void print(const int &kind = 0, const bool &r = 0);

};

