inline info Union(const info &l, node *mid, const info &r)
{
	info ret;
	ret += l;
	if (mid->val < INT_MAX) ret += info0(mid->val);
	ret += r;
	ret.len = l.len + mid->len + r.len;
	ret.has_cir = l.has_cir | r.has_cir;
	ret.multi_path = l.multi_path | r.multi_path;
	ret.cir_ptr[0] = (l.sz || l.len) ? l.cir_ptr[0] : mid->cir_ptr, ret.cir_ptr[1] = (r.sz || r.len) ? r.cir_ptr[1] : mid->cir_ptr;
#define CHECK(x) if ((x) && ret.cir_ptr[0] != (x) && ret.cir_ptr[1] != (x)) ret.has_cir = 1, ret.multi_path |= (x)->eql;
	CHECK(l.cir_ptr[1]);
	CHECK(mid->cir_ptr);
	CHECK(r.cir_ptr[0]);
#undef CHECK
	return ret;
}

void node::add(node *v)
{
	if (!this) return;
	if (!v) return;
	REP(i, 2, 4) if (!c[i]) { setc(v, i); return; }
	node *u = this;
	while (u->c[2] && u->c[2]->ty) u->push_down(), u = u->c[2];
	u->push_down();
	node *x = alloc();
	x->ty = 2;
	x->setc(u->c[2], 2), x->setc(v, 3), u->setc(x, 2);
	x->splay(2);
}

void node::del()
{
	if (!this) return;
	if (!p) return;
	splay();
	p->relax(2);
	int mark = get_pos();
	assert(mark != 4);
	if (p->ty)
	{
		node *tmp = p->p;
		tmp->setc(p->c[mark ^ 1], p->get_pos());
		tmp->splay(2);
		recy(p);
	}
	else p->setc(NULL, mark), p->update();
	p = NULL;
}

