inline void link(const int &u, const int &v, const int &w)
{
	if (u == v) 
	{
		printf("failed\n");
		return;
	}
	node *x = nd + u, *y = nd + v;
	x->be_root(), y->access();
	if (x->is_root())
	{
		node *tmp = alloc();
		tmp->len = w;
		y->add(tmp);
		tmp->add(x);
		x->access();
		printf("ok\n");
	}
	else
	{
		x->splay();
		y->splay(0, x);
		if (x && x->sum_chain.has_cir) printf("failed\n");
		else
		{
			node *tmp = alloc();
			tmp->len = w;
			tmp->update();
			x->add(tmp);
			x->update();
			cir *tmp0 = cr + (crn++);
			tmp0->ex_link = tmp;
			tmp0->up = x, tmp0->down = y;
			tmp0->eql = y->sum_chain.len == w;
			tmp->flag_cir(tmp0);
			y->c[0]->flag_cir(tmp0);
			y->c[0]->splay();
			y->access();
			printf("ok\n");
		}
	}
}

inline void cut(const int &u, const int &v, const int &w)
{
	if (u == v) 
	{
		printf("failed\n");
		return;
	}
	node *x = nd + u, *y = nd + v;
	x->be_root(), y->access();
	if (x->is_root()) 
	{
		printf("failed\n");
		return;
	}
	x->splay(0, y);
	cir *cir_ptr = x->sum_chain.cir_ptr[1];
	if (cir_ptr && cir_ptr->up == x && cir_ptr->down == y && cir_ptr->ex_link->sum_chain.len == w && !cir_ptr->ex_link->sum_chain.sz)
	{
		x->c[1]->flag_cir(NULL);
		x->c[1]->splay();
		cir_ptr->ex_link->del();
		printf("ok\n");
		return;
	}
	if (x->c[1]->single() && x->c[1]->sum_chain.len == w)
	{
		node *to_del = x->c[1];
		if (cir_ptr)
		{
			cir_ptr->ex_link->del();
			cir_ptr->ex_link->flag_rev();
			x->setc(cir_ptr->ex_link, 1);
			x->update();
			y->update();
			cir_ptr->ex_link->flag_cir(NULL);
			cir_ptr->ex_link->splay();
		}
		else
		{
			y->setc(NULL, 0);
			y->update();
			x->setc(NULL, 1);
			x->p = NULL;
			x->update();
		}
		recy(to_del);
		printf("ok\n");
		return;
	}
	printf("failed\n");
}

