        for (int i = 0; i + len <= c; ++i)
        {
            int j = i + len - 1,
                *dist = f[i][j];
            priority_queue<DIJ> Q;
            static bool vis[maxw * maxw];
            memset(vis, 0, sizeof(vis));
            for (int k = 0; k < n * m; ++k)
                for (int l = i + 1; l < i + len; ++l)
                    mint(dist[k], f[i][l - 1][k] + f[l][j][k]);
            for (int k = 0; k < n * m; ++k) if (dist[k] < 0x1f1f1f1f)  Q.push((DIJ) { dist[k], k });
            while (Q.size())
            {
                DIJ o = Q.top(); Q.pop(); if (vis[o.u]) continue;
                vis[o.u] = true;
                for (int *p = G[o.u]; p != G[o.u] + 4; ++p)
                    if (!vis[*p] && mint(dist[*p], o.dist + 1))
