namespace pb_ds
{
	//using io::P;
	const int MAXM = 510;
	struct P {short x, y;} BANNED = {-1, -1};
	template<class T> struct Table
	{
		T mem[MAXM][MAXM];
		inline T& operator[] (const P& A) 
		{
///*lgg*/assert(A.x < MAXM && A.y < MAXM);
			return mem[A.x][A.y];
		}
		inline T* operator[] (RG int x) {return mem[x];}
	};
	Table<char> map;
	Table<int> f[10][10];
	Table<P[4]> sink;
	Table<int[4]> mark;
	template<class T> struct Queue
	{
		T q[1 << 18];
		int l, r;
		inline void init() {l = r = 0;}
		inline bool empty() {return l >= r;}
		inline void push(const T& a) {q[r++] = a;}
		inline T front() {return q[l];}
		inline void pop() {++l;}
	};
	Queue<P> Q1, Q2;
	Table<bool> vis;
	P pos[10], stack[MAXM * MAXM]; 
	int top, L, R;
	inline bool cmp(const P& X, const P& Y) {return f[L][R][X] > f[L][R][Y];}
	inline bool operator ! (const P& X) {return !X.x && !X.y;}
	const int cx[] = {-1, 0, 1, 0};
