	inline P dfs(const RG int x, const RG int y, const RG int dir)
	{
///*lgg*///printf("dfs x = %d y = %d dir = %c T = %d\n", x, y, pri_name[dir], T), getchar();
		if(mark[x][y][dir] == T) return BANNED;
		mark[x][y][dir] = T;
		
		if(!sink[x][y][dir])
		{
			static int xx, yy, dd;
			if(map[x][y] == 'A') dd = (dir + 1) & 3;
			else if(map[x][y] == 'C') dd = (dir + 3) & 3;
			else dd = dir;
			xx = x + cx[dd], yy = y + cy[dd];
///*lgg*///printf("xx = %d yy = %d dd = %d\n", xx, yy, dd);
			if(xx < 1 || yy < 1 || xx > m || yy > n || map[xx][yy] == 'x')
				sink[x][y][dir] = (P) {x, y};
			else
				sink[x][y][dir] = dfs(xx, yy, dd);
		}
		return sink[x][y][dir];
	}
	
	inline void radix_sort()
	{
		static int cnt[MAXM * MAXM];
		static P sorted[MAXM * MAXM];
		RG int min = 1 << 30, max = 0, temp;
		Table<int> &FLR = f[L][R];
		memset(cnt, 0, sizeof cnt);
		For(i, 1, top)
		{
			temp = FLR[stack[i]], cmin(min, temp), cmax(max, temp);
			++cnt[temp];
		}
		For(i, min, max) cnt[i] += cnt[i - 1];
		ForDown(i, 1, top)
			sorted[cnt[FLR[stack[i]]]--] = stack[i];
///*lgg*///For(i, 2, top) assert(!cmp(sorted[i - 1], sorted[i]));
		For(i, 1, top) Q1.push(sorted[i]);
		top = 0;	
///*lgg*/printf("sort done\n");	
	}
	
	inline void spfa(RG int l, RG int r)
	{
		Q1.init(), Q2.init();
///*lgg*/printf("spfa l = %d r = %d top = %d\n", l, r, top);
		Table<int> &FLR = f[l][r];
		RG P x, y;
		L = l, R = r, radix_sort();
		while(!Q1.empty() || !Q2.empty())
		{
			if(Q2.empty() || (!Q1.empty() && FLR[Q1.front()] < FLR[Q2.front()]))
				x = Q1.front(), Q1.pop();
			else 
///*lgg*/assert(!Q2.empty()),
				x = Q2.front(), Q2.pop();
///*lgg*/if(l==8&&r==9)printf("x = %d, %d\n", x.x, x.y);
			vis[x] = 0;
			For(dir, 0, 3)
			{
				y = (sink[x])[dir];
				if(y.x == -1)continue;
				if(FLR[y] > FLR[x] + 1)
				{
					FLR[y] = FLR[x] + 1;
					if(!vis[y]) 
						vis[y] = 1, Q2.push(y);
				}
			}				
		}
	}
	
