///*lgg*///printf("sink %d %d %d = %d %d\n", i, j, dir, sink[i][j][dir].x, sink[i][j][dir].y);
			}
		For(i, 1, k)
		{
			stack[++top] = pos[i];
			spfa(i, i);
		}
		const RG int INF = f[0][0][0][0];
///*lgg*/printf("INF = %d\n", INF);
		For(len, 2, k) For(l, 1, k - len + 1)
		{
///*lgg*/printf("k = %d l = %d r = %d\n", k, l, l+len-1);
			RG int r = l + len - 1;
			Table<int> &FLR = f[l][r];
