			{
				For(temp, l, r - 1)
					cmin(FLR[i][j], f[l][temp][i][j] + f[temp + 1][r][i][j]);
				if(FLR[i][j] != INF)
					vis[stack[++top] = (P) {i, j}] = 1;
			}
			spfa(l, r);
		}
		RG int ans = INF;
		For(i, 1, m) For(j, 1, n)
			cmin(ans, f[1][k][i][j]);
