			dis[bh(i,j,r1[y])]=l2[z]-r1[y],an[x]=bh(i,j,r1[y]);
	
	if(r2[y]!=-1&&l1[z]!=-1)
		if(dis[an[x]]>l1[z]-r2[y])
			dis[bh(i,j,l1[z])]=l1[z]-r2[y],an[x]=bh(i,j,l1[z]);
}

void build_tree(int &x,int L,int R,int i,int j)
{
	if(!x)
		x=++tot;
	if(L==R)
	{
		l1[x]=r1[x]=L;
		l2[x]=r2[x]=-1;
		an[x]=bh(i,j,L);
		return;
	}
	int mid=(L+R)>>1;
	build_tree(lch[x],L,mid,i,j);
	build_tree(rch[x],mid+1,R,i,j);
	push_up(x,i,j);
}

