const int Hmax = (1 << 23) - 1;
int h[Hmax + 8];
void spfa()
{
	s = 1, t = 2;
	int l = 0, r = 0;
	rep(i, 1, sz) dis[i] = INF;
	dis[s] = 0; h[++r] = s; in[s] = 1;
	while (l != r)
	{
		l = (l + 1) & Hmax;
		int u = h[l]; in[u] = 0;
		for (int i = head[u], v; v = e[i].node, i; i = e[i].next)
		if (dis[u] + e[i].dist < dis[v])
		{
			dis[v] = dis[u] + e[i].dist;
			if (!in[v])
			{
				r = (r + 1) & Hmax; h[r] = v;
				if (dis[v] < dis[h[(l + 1) & Hmax]]) swap(h[(l + 1) & Hmax], h[r]);
				in[v] = 1;
			}
		}
	}
}
