	rep(i, 1, sqrtn)
		rep(j, 1, n - i)
		{
			add(p(i, j), p(i, j + i), 1);
			add(p(i, j + i), p(i, j), 1);
		}
	rep(i, 1, m) pos[B[i]] = i;
	rep(i, 1, m)
	{
		if (P[i] <= sqrtn) add(i, p(P[i], B[i]), 0);
		add(p(0, B[i]), i, 0); 
		if (P[i] > sqrtn)
