			for (int x = B[i], y = 0; x <= n; x += P[i], y++) 
				if (pos[x]) add(i, p(0, x), y);
			for (int x = B[i] - P[i], y = 1; x >= 1; x -= P[i], y++) 
				if (pos[x]) add(i, p(0, x), y);
