#define cls(x, y) memset(x, y, sizeof(x))

inline int read() {
    int x = 0; int f = 1, c = getchar();
    while(c < '0' || c > '9') { if(c == '-') f = -1; c = getchar(); }
    while(c >= '0' && c <= '9') { x = x * 10 + c - '0'; c = getchar(); }
    return x * f;
}

const int MAXN = 30005;
const int inf = 0x3f3f3f3f;

int n, m;
int B[MAXN], P[MAXN];
vector<int> sky[MAXN];

bool cmp(int x, int y) {
    return P[x] < P[y];
}

void input() {
    n = read();
    m = read();
    for(int i = 0; i < m; ++i) {
        B[i] = read(), P[i] = read();
        sky[B[i]].push_back(i);
    }
    for(int i = 0; i < n; ++i) {
        sort(sky[i].begin(), sky[i].end(), cmp);
    }
}

bool vis[MAXN];
int dis[MAXN];

template<typename T>
inline bool relax(T &x, T y) {
    return x > y ? x = y, 1 : 0;
}

struct Heap {
    int data[MAXN];
    int pos[MAXN];
    bool in[MAXN];
    int size;

    inline void swap0(int &x, int &y) {
        swap(pos[x], pos[y]); swap(x, y);
    }
    void pushup(int x) {
        while(x > 1) {
            int fa = x >> 1;
            if(dis[data[x]] < dis[data[fa]]) {
                swap0(data[x], data[fa]);
                x = fa;
            } else break;
        }
        // for(int fa = x >> 1; x > 1 && dis[data[x]] < dis[data[fa]]; x = fa, fa >>= 1)
        //     swap0(data[x], data[fa]);
    }
    void push(int x) {
        if(!in[x]) {
            in[x] = 1;
            data[++size] = x;
            pos[x] = size;
        }
        pushup(pos[x]);
    }
    void popdown(int x) {
        while((x << 1) <= size) {
            int son = x << 1;
            if((son | 1) <= size && dis[data[son]] > dis[data[son | 1]])
                son |= 1;
            if(dis[data[x]] > dis[data[son]]) {
                swap0(data[x], data[son]);
                x = son;
            } else break;
        }
    }
    int pop() {
        int x = data[1];
        swap0(data[1], data[size--]);
        popdown(1);
        return x;
    }
} heap;

int dijkstra(int s, int t) {
    cls(dis, inf);
    dis[s] = 0;
    heap.push(s);
    while(heap.size) {
        int x = heap.pop();
        if(vis[x]) continue;
        vis[x] = 1; if(x == t) break;
        for(int i = 0; i < (int)sky[x].size(); ++i) {
            int u = sky[x][i];
            for(int j = x + P[u], w = 1; j < n; j += P[u], ++w)
                if(relax(dis[j], dis[x] + w))
                    heap.push(j);
            for(int j = x - P[u], w = 1; j >= 0; j -= P[u], ++w)
                if(relax(dis[j], dis[x] + w))
                    heap.push(j);
        }
    }
    return dis[t];
}

void solve() {
    int ans = dijkstra(B[0], B[1]);
    if(ans == inf) puts("-1");
    else printf("%d\n", ans);
}

