		sort(H.begin(), H.end());

		tmp = min( tmp , tmp_1 + tmp_2 );

		j = 0;
		for(i=a+1; i<int(V.size()); i++) {
			cnt[1] += tot[1][i-1];
			tmp_2 += (LL) (V[i] - V[i-1]) * cnt[1] * 2;

			tmp_2 -= (LL) (V[i] - V[i-1]) * cnt[0] * 2;
			cnt[0] -= tot[0][i];

			for(j=j; j<int(H.size()); j++) {
				if(V[i]+V[a] <= H[j].fst) break;
				cnt[1] --;
				int o = H[j].sed;
				tmp_1 += Abs(peo[o].fst - V[a]) + Abs(peo[o].sed - V[a]) + 1;
				tmp_2 -= Abs(peo[o].fst - V[i]) + Abs(peo[o].sed - V[i]) + 1;
			}
			tmp = min( tmp , tmp_1 + tmp_2 );

		}

		return tmp;
	}

	void Solve() {
		sort(peo+1, peo+n+1);

		for(int i=1; i<=n; i++) {
			V.push_back(peo[i].fst);
			V.push_back(peo[i].sed);
		}
		sort(V.begin(), V.end());
		V.erase(unique(V.begin(),V.end()),V.end());

		int a = 0 , b , c , d = V.size() - 1, Len;
		LL tmp_a , tmp_b , tmp_c , tmp_d;
		for(int i=0; i<int(V.size()); i++) {
			Len = d - a + 1;
			if(Len <= 20) break;
			Len /= 3 , b = a + Len , c = d - Len;
			tmp_b = calc(b) , tmp_c = calc(c);
			tmp_b < tmp_c ? d = c : a = b;
		}


		ans = INF;
		for(int i=a; i<=d; i++) {
			ans = min( ans , calc(i) );
		}
		cout << ans + answer << endl;
	}
};

