#include <bits/stdc++.h>
#define rep(i, a, b) for (int i = (a); i <= (b); ++i)
#define drep(i, a, b) for (int i = (a); i >= (b); --i)
#define REP(i, a, b) for (int i = (a); i < (b); ++i)
#define pb(x) push_back(x)
#define mp(x, y) (make_pair(x, y))
#define clr(x) memset(x, 0, sizeof(x))
#define xx first
#define yy second
 
using namespace std;
 
typedef long long ll;
typedef pair<int, int> pii;
const int inf = ~0U >> 1;
const ll INF = ~0ULL >> 1;
//***************************

const int maxn = 220000;
int K, N, n, s[maxn], t[maxn], h[maxn], c[maxn], x[maxn], y[maxn];
char p[maxn], q[maxn];
ll cur;

ll sumPre[maxn], sumSuc[maxn], cntPre[maxn], cntSuc[maxn];
int tmp[maxn];

struct fenwick_tree
{
	ll c[maxn];
	
	void reset()
	{
		clr(c);
	}
	
	void modify(int x, ll d)
	{
		while (x <= n) c[x] += d, x += x & (-x);
	}
	
	ll query(ll x) 
	{
		ll ret = 0;
		while (x) ret += c[x], x -= x & (-x);
		return ret;
	}
	
} bonus, cnt1, cnt2, sumst1, sumst2;

ll calc(int i, int j)
{
	return cur + sumPre[i] + 2ll * h[i] * cntPre[i]
									+ sumSuc[j] - 2ll * h[j] * cntSuc[j]
									+ bonus.query(j)
									+ 2ll * h[j] * cnt1.query(j) - sumst1.query(j)
									- 2ll * h[i] * cnt2.query(j) + sumst2.query(j);
}

ll solve(ll i)
{
	ll best = INF;
	bonus.reset();
	sumst1.reset(); sumst2.reset();
	cnt1.reset(); cnt2.reset();
	rep(j, 1, N) 
		if (p[j] != q[j] && s[j] >= h[i]) 
		{
			bonus.modify(y[j], -abs(s[j] - t[j]));
			sumst1.modify(y[j], s[j] + t[j]);
			cnt1.modify(y[j], 1);
			int bound = lower_bound(h + 1, h + n + 1, s[j] + t[j] - h[i]) - h;
			sumst1.modify(bound, -(s[j] + t[j]));
			cnt1.modify(bound, -1);
			cnt2.modify(bound, 1);
			sumst2.modify(bound, s[j] + t[j]);
		}
	int l = i, r = n;
	while (l + 2 < r)
	{
		int m1 = l + r >> 1;
		int m2 = m1 + r >> 1;
		if (calc(i, m1) < calc(i, m2)) 
			r = m2;
		else l = m1;
	}
	rep(j, l, r) best = min(best, calc(i, j));
	return best;
}

int main()
{
	ios :: sync_with_stdio(0);
	cin >> K >> N;
	rep(i, 1, N)
	{
		cin >> p[i] >> s[i] >> q[i] >> t[i];
		h[++n] = s[i];
		h[++n] = t[i];
	}
	sort(h + 1, h + n + 1);
	n = unique(h + 1, h + n + 1) - h - 1;
	if (K == 1) 
	{
		ll best = INF;
		ll bonus = 0;
		rep(i, 1, N) 
			if (p[i] == q[i]) bonus += abs(s[i] - t[i]);
			else
			{
				++bonus;
				int x = lower_bound(h + 1, h + n + 1, s[i]) - h;
				int y = lower_bound(h + 1, h + n + 1, t[i]) - h;
				sumPre[x] += s[i];
				sumSuc[x] += s[i];
				cntPre[x] ++;
				cntSuc[x] ++;
				sumPre[y] += t[i];
				sumSuc[y] += t[i];
				cntPre[y] ++;
				cntSuc[y] ++;
			}
		rep(i, 1, n) 
		{
			sumPre[i] += sumPre[i - 1];
			cntPre[i] += cntPre[i - 1];
		}
		drep(i, n, 1) 
		{
			sumSuc[i] += sumSuc[i + 1];
			cntSuc[i] += cntSuc[i + 1];
		}
		rep(i, 1, n) 
		{
			ll cost = bonus + sumSuc[i] - cntSuc[i] * h[i] + cntPre[i] * h[i] - sumPre[i];
			best = min(best, cost);
		}
		cout << best << endl;
	}
	else
	{
		ll best = INF;
		cur = 0;
		rep(i, 1, N) 
			if (p[i] == q[i]) 
				cur += abs(s[i] - t[i]);
			else 
			{
				cur += abs(s[i] - t[i]) + 1;
				if (s[i] > t[i]) swap(s[i], t[i]);
				x[i] = lower_bound(h + 1, h + n + 1, s[i]) - h;
				y[i] = lower_bound(h + 1, h + n + 1, t[i]) - h;
				sumPre[y[i]] += -abs(s[i] - t[i]) - s[i] - t[i];
				cntPre[y[i]]++;
				cntSuc[x[i]]++;
				sumSuc[x[i]] += -abs(s[i] - t[i]) + s[i] + t[i];
			}
		rep(i, 1, n) 
		{
			sumPre[i] += sumPre[i - 1];
			cntPre[i] += cntPre[i - 1];
		}
		drep(i, n, 1) 
		{
			sumSuc[i] += sumSuc[i + 1];
			cntSuc[i] += cntSuc[i + 1];
		}
		int L = 1, R = n;
		while (L + 2 < R) 
		{
			int M1 = L + R >> 1;
			int M2 = M1 + R >> 1;
			if (solve(M1) < solve(M2)) R = M2;
			else L = M1;
		}
		rep(i, L, R)
			best = min(best, solve(i));
		cout << best << endl;		
	}
    return 0;
}

