namespace prog2
{
	typedef long long ll;
	const int maxn=100010;
	const ll inf=1000000000000000LL;
	
	struct node
	{
		int x,y;
	};
	
	struct segtree
	{
		int lch,rch,size;
		ll sum;
	};
	
	int m,cnt,nodecnt;
	node b[maxn];
	int root[maxn],a[2*maxn];
	segtree tree[60*maxn];
	
	bool cmp(node c,node d) {return a[c.x]+a[c.y]<a[d.x]+a[d.y];}
	
	int find(int x)
	{
		int l=1,r=m;
		while (l<=r)
		{
			int mid=(l+r)>>1;
			if (a[mid]==x) return mid;
			if (x<a[mid]) r=mid-1; else l=mid+1;
		}
	}
	
	int change(int k,int l,int r,int p)
	{
		int nk=++nodecnt;
		tree[nk].sum=tree[k].sum+a[p];
		tree[nk].size=tree[k].size+1;
		if (l==r) return nk;
		int mid=(l+r)>>1;
		if (p<=mid)
		{
			tree[nk].lch=change(tree[k].lch,l,mid,p);
			tree[nk].rch=tree[k].rch;
		}
		else
		{
			tree[nk].rch=change(tree[k].rch,mid+1,r,p);
			tree[nk].lch=tree[k].lch;
		}
		return nk;
	}
	
	ll query1(int k1,int k2,int l,int r,int l0,int r0)
	{
		if (l0>r0) return 0;
		if (l0<=l&&r0>=r) return tree[k1].sum-tree[k2].sum;
		int mid=(l+r)>>1;
		if (r0<=mid) return query1(tree[k1].lch,tree[k2].lch,l,mid,l0,r0);
		if (l0>mid) return query1(tree[k1].rch,tree[k2].rch,mid+1,r,l0,r0);
		return query1(tree[k1].lch,tree[k2].lch,l,mid,l0,r0)+query1(tree[k1].rch,tree[k2].rch,mid+1,r,l0,r0);
	}
	
	int query2(int k1,int k2,int l,int r,int l0,int r0)
	{
		if (l0>r0) return 0;
		if (l0<=l&&r0>=r) return tree[k1].size-tree[k2].size;
		int mid=(l+r)>>1;
		if (r0<=mid) return query2(tree[k1].lch,tree[k2].lch,l,mid,l0,r0);
		if (l0>mid) return query2(tree[k1].rch,tree[k2].rch,mid+1,r,l0,r0);
		return query2(tree[k1].lch,tree[k2].lch,l,mid,l0,r0)+query2(tree[k1].rch,tree[k2].rch,mid+1,r,l0,r0);
	}
	
	ll calc(int l,int r)
	{
		int l0=1,r0=cnt;
		while (l0<=r0)
		{
			int mid=(l0+r0)>>1;
			if (a[b[mid].x]+a[b[mid].y]>a[l]+a[r]) r0=mid-1; else l0=mid+1;
		}
		ll q1=query1(root[r0],root[0],1,m,1,l);int q2=query2(root[r0],root[0],1,m,1,l);
		ll q5=tree[root[r0]].sum-q1;int q6=tree[root[r0]].size-q2;
		ll q3=query1(root[cnt],root[r0],1,m,1,r);int q4=query2(root[cnt],root[r0],1,m,1,r);
		ll q7=tree[root[cnt]].sum-tree[root[r0]].sum-q3;int q8=tree[root[cnt]].size-tree[root[r0]].size-q4;
		return ll(q2-q6)*a[l]-q1+q5+ll(q4-q8)*a[r]-q3+q7;
	}
	
	void solve()
	{
		ll tmp=n;
		for (int i=1;i<=n;i++)
		{
			char ch1,ch2;
			int x,y;
			read(ch1);scanf("%d",&x);
			read(ch2);scanf("%d",&y);
			if (ch1==ch2)
				tmp+=(abs(x-y)-1);
			else
			{
				if (ch1>ch2) swap(x,y);
				b[++cnt].x=x;b[cnt].y=y;
			}
		}
		for (int i=1;i<=cnt;i++) {a[2*i-1]=b[i].x;a[2*i]=b[i].y;}
		sort(a+1,a+2*cnt+1);
		m=1;
		for (int i=2;i<=2*cnt;i++) if (a[i]!=a[i-1]) a[++m]=a[i];
		for (int i=1;i<=cnt;i++) {b[i].x=find(b[i].x);b[i].y=find(b[i].y);}
		sort(b+1,b+cnt+1,cmp);
		root[0]=0;nodecnt=0;tree[0].lch=tree[0].rch=tree[0].sum=tree[0].size=0;
		for (int i=1;i<=cnt;i++)
		{
			root[i]=root[i-1];
			root[i]=change(root[i],1,m,b[i].x);
			root[i]=change(root[i],1,m,b[i].y);
		}
		ll ans=inf;
		int k=1;
		for (int i=1;i<=m;i++)
		{
            if (k<i) k++;
            while (k<m&&calc(i,k)>=calc(i,k+1)) k++;
            ans=min(ans,calc(i,k));
        }
        printf("%lld\n",ans+tmp);
	}
}

