int getint()
{
    while (!isdigit(ch=getchar()));
    int x=ch-'0';
    for (; isdigit(ch=getchar()); x=x*10+ch-'0');
    return x;
}

node::node()
{
    lc=tp,tp=this;
}

node *newnode()
{
    if (!tp)
        new node[10000];
    node *t=tp;
    tp=tp->lc,t->s=t->sum=0,t->lc=t->rc=0;
    return t;
}

void modify(node *x,int p,int w)
{
    int l=0,r=range;
    while (l<r)
    {
        x->s+=w,x->sum+=p*w;
        if (p<=mid)
        {
            if (!x->lc)
                x->lc=newnode();
            x=x->lc,r=mid;
        }
        else
        {
            if (!x->rc)
                x->rc=newnode();
            x=x->rc,l=mid+1;
        }
    }
    x->s+=w,x->sum+=p*w;
}

LL query(node *x,int k)
{
    int l=0,r=range;
    LL sum=0,cnt=0;
    while (l<r)
        if (x->lc && k<=x->lc->s)
        {
            if (x->rc)
                sum+=x->rc->sum,cnt-=x->rc->s;
            x=x->lc,r=mid;
        }
        else
        {
            if (x->lc)
                sum-=x->lc->sum,cnt+=x->lc->s,k-=x->lc->s;
            x=x->rc,l=mid+1;
        }
    return sum+cnt*l;
}

