var
  n,m:array [0..1000001] of longint;
  fac:array [0..9] of matrix;
  nn,mm,nm,ans:matrix; a,b,c,d,nt,mt:int64; nlen,mlen:longint;
procedure init;
var
  i:longint; ch:char;
begin
  nlen:=0; mlen:=0;
  while true do begin read(ch); if ch=' ' then break; inc(nlen); n[nlen]:=ord(ch)-48; end;
  while true do begin read(ch); if ch=' ' then break; inc(mlen); m[mlen]:=ord(ch)-48; end;
  readln(a,b,c,d);
end;
procedure swap(var x,y:longint);
var
  t:longint;
begin
  t:=x; x:=y; y:=t;
end;
procedure reduce;
var
  i:longint;
begin
  for i:=1 to nlen div 2 do swap(n[i],n[nlen-i+1]);
  for i:=1 to mlen div 2 do swap(m[i],m[mlen-i+1]);
  dec(n[1]); i:=1; while n[i]<0 do begin inc(i); dec(n[i]); inc(n[i-1],10); end;
  dec(m[1]); i:=1; while m[i]<0 do begin inc(i); dec(m[i]); inc(m[i-1],10); end;
  while (nlen>1) and (n[nlen]=0) do dec(nlen);
  while (mlen>1) and (m[mlen]=0) do dec(mlen);
end;
function mul(a,b:matrix):matrix;
var
  c:matrix;
begin
  c.a:=(a.a*b.a) mod maxmod;
  c.b:=(a.a*b.b+a.b) mod maxmod;
  exit(c);
end;
function quick_mul(a:matrix; x:longint):matrix;
var
  b:matrix;
begin
  b.a:=0; b.b:=0; if x<0 then exit(b); b.a:=1; b.b:=0;
  while x<>0 do
  begin
    if x mod 2=1 then b:=mul(a,b);
    a:=mul(a,a); x:=x div 2;
  end;
  exit(b);
end;
procedure calc_matrix;
var
  i,j:longint;
begin
  fac[0].a:=1; fac[0].b:=0; fac[1].a:=a; fac[1].b:=b;
  for i:=2 to 9 do fac[i]:=mul(fac[i-1],fac[1]);
  mm:=fac[m[mlen]]; for i:=mlen-1 downto 1 do mm:=mul(quick_mul(mm,10),fac[m[i]]);
  nn.a:=c; nn.b:=d;
  nm:=mul(mm,nn);
  fac[0].a:=1; fac[0].b:=0; fac[1]:=nm;
  for i:=2 to 9 do fac[i]:=mul(fac[i-1],fac[1]);
  nm:=fac[n[nlen]]; for i:=nlen-1 downto 1 do nm:=mul(quick_mul(nm,10),fac[n[i]]);
  ans:=mul(nm,mm); writeln((ans.a+ans.b) mod maxmod);
end;
procedure bigmod;
var
  i,j,k:longint;
begin
  nt:=0; mt:=0;
  for i:=nlen downto 1 do begin nt:=nt*int64(10)+int64(n[i]); nt:=nt mod int64(maxmod-1); end;
