    Matrix c(a.r,a.c);
    if(p[1]<0) return c;
    REP(i,1,a.r) REP(j,1,a.c) c.mat[i][j]=(i==j);
    K[0]=c;REP(i,1,9) K[i]=K[i-1]*a;
    REP(i,1,p[0]) {
        T[0]=c;
        REP(k,1,3) T[k]=T[k-1]*T[k-1];
        c=T[3]*T[1]*K[p[i]];
    }
    return c;
}

