struct edge
{
	int id, g, nxt;

	edge() { }
	edge(const int &_id, const int &_g, const int &_nxt): id(_id), g(_g), nxt(_nxt) { }

};

int en = 0;
edge e[(maxn << 1) + 5];

int st[maxn + 5];

inline void add_edge(const int &x, const int &y, const int &z)
{
	e[en] = edge(y, z, st[x]), st[x] = en++;
}

int n;

