LL ans;

int a, b, c;

int get(const int &x) { return _fa[x] == x ? x : _fa[x] = get(_fa[x]); }

int fa[maxn + 5], w[maxn + 5];;
LL dep0[maxn + 5];
bool vis[maxn + 5];
LL dp[maxn + 5], Max[maxn + 5];

LL len[(maxn << 1) + 5];
LL pre[(maxn << 1) + 5];
LL lyc[(maxn << 1) + 5];
int m;

void dfs(const int &x)
{
	for (int i = st[x]; i != -1; i = e[i].nxt)
	{
		const int &y = e[i].id;
		const int &z = e[i].g;
		if (y == fa[x]) continue;
		if (vis[y]) continue;
		fa[y] = x;
		w[y] = z;
		dep0[y] = dep0[x] + z;
		dfs(y);
	}
}

void dfs0(const int &x)
{
	dp[x] = Max[x] = 0;
	for (int i = st[x]; i != -1; i = e[i].nxt)
	{
		const int &y = e[i].id;
		const int &z = e[i].g;
		if (y == fa[x]) continue;
		if (vis[y]) continue;
		dfs0(y);
		Max[x] = max(Max[x], dp[x] + dp[y] + z);
		dp[x] = max(dp[x], dp[y] + z);
	}
}

struct info
{
	LL Max0, Max1, Max;

	info(): Max0(-OO), Max1(-OO), Max(-OO) { }

	info &operator+=(const info &x)
	{
		Max = max(Max, x.Max);
		Max = max(Max, Max0 + x.Max1);
		Max0 = max(Max0, x.Max0);
		Max1 = max(Max1, x.Max1);
		return *this;
	}
};

struct node
{
	info sum;

	node *c[2];

	node() { memset(c, 0, sizeof c); }

	void update()
	{
		sum = info();
		REP(i, 0, 2) if (c[i]) sum += c[i]->sum;
	}

};

node nd[max0 + 5];
int cur = 0;

node *rt;

void insert(node *&rt, const int &x, const LL &a, const LL &b, const LL &c, const int &l, const int &r)
{
	if (!rt) rt = nd + (cur++);
	if (r - l <= 1)
	{
		rt->sum.Max0 = a, rt->sum.Max1 = b;
		rt->sum.Max = c;
		return;
	}
	int mid = (l + r) >> 1;
	if (x < mid) insert(rt->c[0], x, a, b, c, l, mid);
	else insert(rt->c[1], x, a, b, c, mid, r);
	rt->update();
}

info query(node *rt, const int &x, const int &y, const int &l, const int &r)
{
	if (!rt) return info();
	if (x <= l && r <= y) return rt->sum;
	info ret;
	int mid = (l + r) >> 1;
	if (x < mid) ret += query(rt->c[0], x, y, l, mid);
	if (y > mid) ret += query(rt->c[1], x, y, mid, r);
	return ret;
}

