		if (u == v) a = x, b = y, c = z;
		else
		{
			_fa[u] = v;
			add_edge(x, y, z);
			add_edge(y, x, z);
		}
	}
	fa[a] = -1;
	dfs(a);
	int u = b;
	m = 0;
	LL cir_len = dep0[b] + c;
	pre[0] = 0;
	while (u != -1)
	{
		dfs0(u);
		pre[m + 1] = pre[m] + w[u];
		lyc[m] = Max[u];
		len[m++] = dp[u];
		vis[u] = 1;
		u = fa[u];
	}
	REP(i, 0, m) pre[i + m] = pre[i] + cir_len, len[i + m] = len[i], lyc[i + m] = lyc[i];
	int tmp = m;
	m <<= 1;
