	REP(i, 0, m) insert(rt, i, -pre[i] + len[i], pre[i] + len[i], lyc[i], 0, m);
	ans = OO;
	REP(i, tmp, m) ans = min(ans, query(rt, i - tmp, i, 0, m).Max);
