    if (t<=mid) return Find(x*2,t); else return Find(x*2+1,t);
}
long long Find2(int x,int l,int r)
{
    if (tree[x][0]==l && r==tree[x][1]) return tree[x][2];
    Down3(x);
    int mid=(tree[x][0]+tree[x][1])/2; long long p=0,q=0;
    if (l<=mid) p=Find2(x*2,l,min(mid,r));
    if (r>mid) q=Find2(x*2+1,max(mid+1,l),r);
    return max(p,q);
}
void work(int x,int l,int r,int t)
{
    if (tree[x][0]==l && tree[x][1]==r) {tree[x][2]+=t; tree[x][3]+=t; return;}
    Down3(x);
    int mid=(tree[x][0]+tree[x][1])/2;
    if (l<=mid) work(x*2,l,min(mid,r),t);
    if (r>mid) work(x*2+1,max(mid+1,l),r,t);
    tree[x][2]=max(tree[x+x][2],tree[x+x+1][2]);
}
