  	  	for(i=first[u],v=edge[i].v,dis=edge[i].dis;i!=-1;i=edge[i].next,v=edge[i].v,dis=edge[i].dis)
				  if(id[v]==0 && v!=fa[u])
					  upmax(furthestson[u],furthestson[v]+LL(dis));
  	  }
  	f[rt]=0;
  	re(j,1,tail)
  	  {
  	  	int u=que[j],v,dis;LL maxv1=0,maxv2=0;int hea=-1;
