#define maxN 100050
#define oo (1LL << 60)
typedef pair<int,int> pii;
typedef long long LL;

int N;
struct Tedge
{
	int id, nxt, len;
} edge[maxN * 2];
vector<pii> sons[maxN];
int now = -1, H[maxN];
LL ans;

void addedge(int a, int b, int c)
{
	++now;
	edge[now].id  = b;
	edge[now].nxt = H[a];
	edge[now].len = c;
	H[a] = now;
}

stack<pii> st;
int color[maxN];
int tot = 0, root[maxN*2], len[maxN*2], last[maxN];

void find_ring(int now, int last_edge_id)
{
	if (color[now] == 2) return ;
	st.push( pii(now, edge[last_edge_id].len) );
	if (color[now] == 1) 
	{
		do
		{
			color[ root[tot] = st.top().first ] = 2;
			len[tot] = st.top().second;
			++tot;
			st.pop();
		} while (st.top().first != now);
		return ;
	}
	color[now] = 1;
	for (int tmp = H[now]; tmp > -1; tmp = edge[tmp].nxt)
		if (tmp != (last_edge_id ^ 1))
		{
			int id = edge[tmp].id;
			find_ring(id, tmp);
			if (tot) return ;	//找到环了！ 
		}
	st.pop();
	color[now] = 2;
}

int head, tail;
int q[maxN];
bool vis[maxN];

void BFS()
{
	head = 1; tail = 0;
	for (int i=0; i<tot; ++i) vis[ q[ ++tail ] = root[i] ] = true;
	while (head <= tail)
	{
		int now = q[head ++];
		for (int tmp = H[now]; tmp > -1; tmp = edge[tmp].nxt)
		{
			int id = edge[tmp].id;
			if (!vis[id]) 
			{
				vis[id] = true;
				q[++tail] = id;
				sons[now].push_back(pii(id, edge[tmp].len));
			}
		}
	}
}

LL g[maxN], f[maxN], h[maxN];

void Solve1()
{
	for (int _i = tail; _i >= 1; --_i)
	{
		int i = q[_i];
		f[i] = 0;
		g[i] = -oo;
		for (int _j = 0; _j < (int)sons[i].size(); ++_j)
		{
			int j = sons[i][_j].first, len = sons[i][_j].second;
			if (f[j] + len >= f[i])
			{
				g[i] = f[i];
				f[i] = f[j] + len;
			}
			else if (f[j] + len > g[i]) g[i] = f[j] + len;
		}
	}
}

LL sum1[maxN*2], sum2[maxN*2]; //前缀和、后缀和 
LL rmq1[maxN*2][20], rmq2[maxN*2][20];
int asklen[maxN*2];	//用于RMQ的询问长度预处理 

LL askmax(LL rmq[][20], int L, int R)
{
	if (L > R) return 0;
	int len = R - L + 1;
	int t = asklen[len];
	return max(rmq[L][t], rmq[R - (1<<t) + 1][t]);
}

LL calc1(int L, int R, int now) //计算从now出发的最长路
{
	LL res = 0;
	if (L < now) res = max(res, askmax(rmq2, L, now-1) - sum2[now]);
	if (R > now) res = max(res, askmax(rmq1, now+1, R) - sum1[now]);
	return res;
}

pair<LL,int> calc3(LL len1, LL len2, LL len) //计算在长度为len的边左右 
{
	if (len1 + len < len2) return make_pair(len2 * 2, 2);
	if (len2 + len < len1) return make_pair(len1 * 2, 0);
	return make_pair(len1 + len2 + len, 1);
}

pair<LL,int> calc2(int L, int R, int now) //计算在now边上建快餐店的答案 
{
	//printf("%I64d\n%I64d\n%d\n", calc1(L, now, now), calc1(now+1, now+1, R), len[now]);
	return calc3( max(calc1(L, now, now), f[root[now]]),
				  max(calc1(now+1, R, now+1), f[root[now+1]] ),
				  len[now]);
}

void Solve2()
{
	for (int i = tot; i < tot+tot; ++i)
	{
		root[i] = root[i - tot];
		h[root[i]] = oo;
		len[i] = len[i - tot];
	}
	sum1[0] = 0;
	for (int i = 1; i < tot*2; ++i) sum1[i] = sum1[i-1] + len[i-1];
	sum2[tot*2-1] = 0;
	for (int i = tot*2-2; i >= 0; --i) sum2[i] = sum2[i+1] + len[i];
	
	//Init RMQ
	asklen[1] = 0;
	for (int i = 2; i <= tot*2; ++i)
	{
		asklen[i] = asklen[i-1];
		if ((1<<asklen[i])*2 < i) ++asklen[i];
	}
	for (int i=0; i<tot*2; ++i) 
	{
		rmq1[i][0] = sum1[i] + f[ root[i] ];
		rmq2[i][0] = sum2[i] + f[ root[i] ];
	}
	for (int j=1; j<18; ++j)
		for (int i=0; i<tot*2; ++i)
		{
			rmq1[i][j] = max(rmq1[i][j-1], 
							 rmq1[min(i+(1<<(j-1)), tot*2)][j-1]);
			rmq2[i][j] = max(rmq2[i][j-1],
							 rmq2[min(i+(1<<(j-1)), tot*2)][j-1]);
		}
	
	int L = 0, R = tot-1;
	for (int i = 0; i < 2 * tot; ++i)
	{
		if (R < i) {++L; ++R;}
		while (L + 1 <= i && R + 1 < tot*2)
		{
			if ( (sum1[i] - sum1[L]) * 2 > (sum1[R+1] - sum1[L]) )
				{ ++L; ++R; }
			else break;
		}
		LL now = calc1(L, R, i);
		if (now < h[root[i]]) h[root[i]] = now;
		//printf("%d %d h[%d]=%I64d\n", L, R, root[i], now);
	}
	
	ans = oo;
	L = 0; R = tot-1;
	for (int i = 0; i <= 2 * tot-2; ++i)
	{
		if (R == i) {++L; ++R;}
		pair<LL,int> now = calc2(L, R, i), nxt;
		while (L + 1 <= i && R + 1 < tot*2)
		{
			nxt = calc2(L+1, R+1, i);
			if (nxt <= now) {now = nxt; ++L; ++R; }
				else break;
		}
		if (now.first < ans) ans = now.first;
	}
}

void Solve3()
{
	for (int _i = 1; _i <= tail; ++_i)
	{
		int i = q[_i];
		if (sons[i].size() == 0) continue;
		for (int _j = 0; _j < (int) sons[i].size(); ++_j)
		{
			int j = sons[i][_j].first, len = sons[i][_j].second;
			h[j] = max( ((f[j] + len == f[i]) ? g[i] : f[i]), 
						h[i] );
			ans = min(ans, calc3(h[j], f[j], len).first);
			h[j] += len;
		}
	}
}

int main()
{
	scanf("%d", &N);
	memset(H, -1, sizeof(H));
	for (int i=1; i<=N; ++i)
	{
		int a, b, c;
		scanf("%d %d %d", &a, &b, &c);
		addedge(a, b, c);
		addedge(b, a, c);
	}
	
	find_ring(1, -1);
	
	BFS();
	Solve1();	//求出每棵子树内每个点往下走最长路f[i]和次长路g[i] 
	Solve2();	//求出环上的每个点通过环走到其他子树结点的最长路,
				//并求出在环上的每条边建快餐店的答案
	Solve3();	//求出每个点往上走的最长路h[i]， 
				//并计算在子树的边上建快餐店的答案 
				
	if (ans & 1) printf("%lld.5\n", (ans>>1)); 
		else printf("%lld.0\n", (ans>>1));
	
	return 0;
}

