		if(t1+len[i]<t2){if(ans>t2*2)ans=t2*2;}
		else if(t2+len[i]<t1){if(ans>t1*2)ans=t1*2;}
		else if(t1+t2+len[i]<ans)ans=t1+t2+len[i];
		//printf("p=%d end[i]=%d ans=%lld\n",p,end[i],ans);
		dfs3(end[i],p);
	}
