long long dist1(int x,int y){if(x<=y)return dis1[y]-dis1[x];else return dis2[x]+dis1[y];}
long long dist2(int x,int y)
{
	if(x==y)return 0;
	return dis1[2]+dis2[2]-dist1(x,y);
}
