#include <cstdio>
#include <cstdlib>
#include <iostream>
#include <algorithm>

const int maxn = 1e5 + 20;
const long long linf = 0x3f3f3f3f3f3f3f3fll;

struct Edge
{
	int u, v, w;

	friend bool operator < (const Edge &a,const Edge &b)
	{
		return a.u != b.u ? a.u < b.u : a.v < b.v;
	}
	
} edge[maxn << 1];

int n, m;
int cur[maxn], d[maxn];
long long Ma[maxn], Ms[maxn];
bool onloop[maxn];
int ind[maxn], nextw[maxn], tot;
long long pres[maxn << 1], ext[maxn << 1];
long long up[maxn];
long long ans;

struct Node
{
//	long long Ma, Ms;

	long long Ma;
	
	
	friend Node operator + (Node a,Node b)
	{
		Node res = a;
		
/*		if(b.Ma > res.Ma)
		{
			res.Ms = res.Ma, res.Ma = b.Ma;
		
			if(b.Ms > res.Ms) res.Ms = b.Ms;
		}
		else if(b.Ma > res.Ms) res.Ms = b.Ma;
*/
		if(b.Ma > res.Ma) res.Ma = b.Ma;
				
		return res;
	}
	
} Tm[maxn << 3], Tp[maxn << 3];

void init()
{
	scanf("%d", &n);
	for(int i = 1, u, v, w; i <= n; i++)
	{
		scanf("%d%d%d", &u, &v, &w);
		edge[i] = (Edge){u, v, w};
		edge[i + n] = (Edge){v, u, w};
		d[u]++, d[v]++;
	}
	
	m = n * 2;
	std::sort(edge + 1, edge + m + 1);
	for(int i = 1; i <= m; i++) cur[edge[i].u]++;
	for(int i = 1; i <= n; i++) cur[i] += cur[i - 1];
}
void loop_divide()
{
	static int line[maxn];
	int f = 0, r = 0;
	
	for(int i = 1; i <= n; i++)
		if(d[i] == 1) line[r++] = i;
	
	while(f != r)
	{
		int t = line[f++];
		
		for(int i = cur[t - 1] + 1; i <= cur[t]; i++)
		{
			int v = edge[i].v, w = edge[i].w;
			
			if(d[v] != 1)
			{
				if(--d[v] == 1) line[r++] = v;
				
				if(Ma[t] + w > Ma[v]) Ms[v] = Ma[v], Ma[v] = Ma[t] + w;
				else if(Ma[t] + w > Ms[v]) Ms[v] = Ma[t] + w; 
			}
		}
	}
}
void dfs(int st,int x,int fr)
{
	if(fr && st == x) return;
	
	for(int i = cur[x - 1] + 1; i <= cur[x]; i++)
	{
		int v = edge[i].v, w = edge[i].w;
		
		if(onloop[v] && v != fr)
		{
			ind[++tot] = x;
			nextw[tot] = w;
			dfs(st, v, x);
			break;
		}
	}
}
void build(int l,int r,int s)
{
	if(l == r)
	{
		Tm[s] = (Node){ - pres[l] + ext[l] };
		Tp[s] = (Node){ pres[l] + ext[l] };
	}
	else
	{
		int mid = (l + r) >> 1;
		
		build(l, mid, s << 1);
		build(mid + 1, r, s << 1 | 1);
		
		Tm[s] = Tm[s << 1] + Tm[s << 1 | 1];
		Tp[s] = Tp[s << 1] + Tp[s << 1 | 1];
	}
}
int inc(int x)
{
	return x == tot ? 1 : x + 1;
}
int dec(int x)
{
	return x == 1 ? tot : x - 1;
}
Node query(Node *arr,int l,int r,int ll,int rr,int s)
{
	if(l <= ll && rr <= r) return arr[s];
	
	Node res = (Node){ -linf };
	int mid = (ll + rr) >> 1;
	
	if(r > mid) res = res + query(arr, l, r, mid + 1, rr, s << 1 | 1);
	if(l <= mid) res = res + query(arr, l, r, ll, mid, s << 1);
	
	return res;
}
void solve_t(int a,int fa,long long fw)
{
	for(int i = cur[a - 1] + 1; i <= cur[a]; i++)
		if(edge[i].v != fa && !onloop[edge[i].v])
		{
			int v = edge[i].v, w = edge[i].w;
			long long dw = std::max(fw, Ma[a] != Ma[v] + w ? Ma[a] : Ms[a]);
			long long uw = Ma[v], x = std::min(std::max(dw - uw + w, 0ll), w * 2ll);
			
			ans = std::min(ans, std::max(x + uw * 2, dw * 2 + w * 2 - x));
		
			solve_t(v, a, dw + w);
		}
}
void loop_solve()
{
	for(int i = 1; i <= n; i++)
		if(d[i] != 1) onloop[i] = true;
	
	for(int i = 1; i <= n; i++)
		if(onloop[i]) { dfs(i, i, 0); break; }
	
	for(int i = 1; i <= tot; i++)
	{
		pres[i] = pres[i - 1] + nextw[i - 1];
		ext[i] = Ma[ind[i]];
	}
	for(int i = 1; i <= tot; i++)
	{
		pres[i + tot] = pres[tot] + pres[i] + nextw[tot];
		ext[i + tot] = ext[i];
	}
		
	build(1, tot << 1, 1);
	
	ans = linf;
	
	for(int i = 1; i <= tot; i++)
	{
		long long po = pres[tot + i] - (pres[tot + 1] - nextw[i]) / 2;
		int t = std::lower_bound(pres + 1, pres + tot * 2 + 1, po) - pres;
		
		if(inc(i) != t)
		{
			int _i = inc(i);
			long long lw = query(Tm, t, tot + i, 1, tot << 1, 1).Ma + pres[i + tot];
			
			t = (dec(t) - 1) % tot + 1;
			if(_i > t) t += tot;
			 
			long long rw = query(Tp, _i, t, 1, tot << 1, 1).Ma - pres[_i];
			long long x = rw - lw + nextw[i];
			
			x = std::min(std::max(x, 0ll), nextw[i] * 2ll);
			ans = std::min(ans, std::max(x + lw * 2, rw * 2 + nextw[i] * 2 - x));
		}
	}
	
	for(int i = 1, j = 1; i <= tot; i++)
	{
		while(pres[tot + i] - pres[j] > pres[tot + 1] / 2) j++;
		
		up[i] = 0;

		if(j <= tot + i - 1) up[i] = std::max(up[i], pres[tot + i] + query(Tm, j, tot + i - 1, 1, tot << 1, 1).Ma);
		if(i + 1 <= j - 1) up[i] = std::max(up[i], pres[i] + query(Tp, i + 1, j - 1, 1, tot << 1, 1).Ma);
		
		solve_t(ind[i], 0, up[i]);
	}
	
	std::cout << (ans >> 1) << ((ans & 1) ? ".5" : ".0");
}
int main()
{
#ifndef ONLINE_JUDGE	
	freopen("input.txt","r",stdin);
	freopen("output.txt","w",stdout);
#endif

	init();
	
	loop_divide();

	loop_solve();
	
#ifndef ONLINE_JUDGE
	fclose(stdin);
	fclose(stdout);
#endif
	return 0;
}

