inline void addEdge(int u, int v, int w)
{
    edge[++tote] = Edge(v, head[u], w);
    head[u] = tote;
}

bool findCycle(int u)
{
    if (vis[u]) {
        do {
            list[listsize++] = st[top];
            flag[fr[st[top]]] = true;
        } while (st[top--] != u);
        return true;
    }
    vis[u] = true;
    st[++top] = u;
    for (int i = head[u]; i; i = edge[i].next) {
        int v = edge[i].v;
        if ((i >> 1) != fr[u]) {
            fr[v] = i >> 1;
            if (findCycle(v))
                return true;
        }
    }
    --top;
    return false;
}

LL dfs(int u, int f)
{
    for (int i = head[u]; i; i = edge[i].next) {
        int v = edge[i].v;
        int w = edge[i].w;
        if (!flag[i >> 1] && v != f) {
            if (chkmax(max0[u], dfs(v, u) + w)) {
                if (max0[u] > max[u])
                    std::swap(max0[u], max[u]);
            }
            chkmax(path[u], path[v]);
        }
    }
    chkmax(path[u], max[u] + max0[u]);
    return max[u];
}

