struct segnode {
	segnode *l,*r;
	bool has_tag;
	bool tag;
	int size;
	int sum;
	
	inline void add_tag_1()
	{
		has_tag=tag=1;
		sum=size;
	}
	
	inline void add_tag_0()
	{
		has_tag=1;tag=0;
		sum=0;
	}
	
	inline void down()
	{
		if (has_tag) {
			if (tag) {
				l->add_tag_1();
				r->add_tag_1();
			} else {
				l->add_tag_0();
				r->add_tag_0();
			}
			has_tag=0;
		}
	}
	
	inline void update()
	{
		sum=l->sum+r->sum;
	}
};

