inline segnode * build(int l,int r)
{
	segnode *ret=++_segtot;
	ret->size=r-l+1;
	
	if (l<r) {
		int mid=(l+r)>>1;
		ret->l=build(l,mid);
		ret->r=build(mid+1,r);
	}
	
	return ret;
}

inline void cover_0(segnode *a,int l,int r,int L,int R)
{
	if (l==L && r==R) {
		a->add_tag_0();
		return;
	}
	a->down();
	int mid=(L+R)>>1;
	if (r<=mid) {
		cover_0(a->l,l,r,L,mid);
	} else if (l>mid) {
		cover_0(a->r,l,r,mid+1,R);
	} else {
		cover_0(a->l,l,mid,L,mid);
		cover_0(a->r,mid+1,r,mid+1,R);
	}
	a->update();
}

inline void cover_1(segnode *a,int l,int r,int L,int R)
{
	if (l==L && r==R) {
		a->add_tag_1();
		return;
	}
	a->down();
	int mid=(L+R)>>1;
	if (r<=mid) {
		cover_1(a->l,l,r,L,mid);
	} else if (l>mid) {
		cover_1(a->r,l,r,mid+1,R);
	} else {
		cover_1(a->l,l,mid,L,mid);
		cover_1(a->r,mid+1,r,mid+1,R);
	}
	a->update();
}

