	int mid=(l+r)/2;
	build(i*2,l,mid);
	build(i*2+1,mid+1,r);
}

void release(int i)
{
	if (a[i].r==a[i].l) return;
	if (a[i].tag==2) return;
	if (a[i].tag==0)
	{
		a[i*2].num=a[i*2].r-a[i*2].l+1;
		a[i*2+1].num=a[i*2+1].r-a[i*2+1].l+1;
		a[i*2].tag=0;
		a[i*2+1].tag=0;
	}
	else
	{
		a[i*2].num=0;a[i*2+1].num=0;
		a[i*2].tag=1;a[i*2+1].tag=1;
	}
	a[i].tag=2;
}

void modify(int i,int l,int r,int d)
{
	if (l<=a[i].l && a[i].r<=r) {a[i].tag=d;if (d==0) a[i].num=a[i].r-a[i].l+1; else a[i].num=0;return;}
	release(i);
	int mid=(a[i].l+a[i].r)/2;
	if (l<=mid) modify(i*2,l,r,d);
	if (mid<r) modify(i*2+1,l,r,d);
	a[i].num=a[i*2].num+a[i*2+1].num;
}

int query(int i,int l,int r)
{
	if (l<=a[i].l && a[i].r<=r) return a[i].num;
	release(i);
	int mid=(a[i].l+a[i].r)/2,ans=0;
	if (l<=mid) ans+=query(i*2,l,r);
	if (mid<r) ans+=query(i*2+1,l,r);
	return ans;
}

