const int N = 100100;
int n, m, cnt, tot, ttt, dep[N], wson[N], size[N], top[N], fa[N], dfn[N], pre[N];
struct edge {
    int v;
    edge *next;
}pool[N * 2], *head[N];
inline void addedge(int u, int v) {
    edge *p = &pool[++cnt], *q = &pool[++cnt];
    p->v = v, p->next = head[u], head[u] = p;
    q->v = u, q->next = head[v], head[v] = q;
}
inline void dfs1(int u, int pre) {
    size[u] = 1;
    for(edge *p = head[u]; p; p = p->next) {
        int v = p->v; if(v == pre) continue;
        dep[v] = dep[u] + 1, fa[v] = u; dfs1(v, u);
        size[u] += size[v]; if(size[v] > size[wson[u]]) wson[u] = v;
    }
}
inline void dfs2(int u, int tp) {
    dfn[u] = ++tot, pre[tot] = u, top[u] = tp;
    if(wson[u]) dfs2(wson[u], tp);
    for(edge *p = head[u]; p; p = p->next)
        if(p->v != fa[u] && p->v != wson[u])
            dfs2(p->v, p->v);
}
struct node {
    int left, right, s, lazy;
    node *ch[2];
}pol[N * 3], *root;
inline void pushup(node *r) {
    r->s = r->ch[0]->s + r->ch[1]->s;
}
inline void pushdown(node *r) {
    if(r->lazy == -1) return ;
    r->s = r->lazy * (r->right - r->left + 1);
    if(r->ch[0]) r->ch[0]->lazy = r->lazy;
    if(r->ch[1]) r->ch[1]->lazy = r->lazy;
    r->lazy = -1; return ;
}
inline void build(node *r, int left, int right) {
    r->left = left, r->right = right, r->lazy = -1;
    if(left == right) return ;
    int mid = (left + right) / 2;
    node *lson = &pol[++ttt], *rson = &pol[++ttt];
    r->ch[0] = lson, r->ch[1] = rson;
    build(lson, left, mid), build(rson, mid + 1, right);
}
inline int query(node *r, int left, int right) {
    pushdown(r);
    if(r->left == left && r->right == right) return r->s;
    if(r->ch[0]->right >= right) return query(r->ch[0], left, right);
    else if(r->ch[1]->left <= left) return query(r->ch[1], left, right);
    else return query(r->ch[0], left, r->ch[0]->right) +  
                query(r->ch[1], r->ch[1]->left, right);
}
inline void change(node *r, int left, int right, int d) {
    if(r->left == left && r->right == right) {
        r->lazy = d; return ;
    }
    if(r->ch[0]->right >= right) change(r->ch[0], left, right, d);
    else if(r->ch[1]->left <= left) change(r->ch[1], left, right, d);
    else change(r->ch[0], left, r->ch[0]->right, d), 
         change(r->ch[1], r->ch[1]->left, right, d);
    pushdown(r->ch[0]), pushdown(r->ch[1]), pushup(r);
}
inline int LCA(int u, int v) {
    while(top[u] != top[v]) {
        if(dep[top[u]] < dep[top[v]]) swap(u, v);
        u = fa[top[u]];
    }
    if(dep[u] > dep[v]) swap(u, v); 
    return u;
}
inline void Qc(int u, int v, int d) {
    while(top[u] != top[v]) {
        if(dep[top[u]] < dep[top[v]]) swap(u, v);
        change(root, dfn[top[u]], dfn[u], d); u = fa[top[u]];
    }
    if(dep[u] > dep[v]) swap(u, v);
    change(root, dfn[u], dfn[v], d);
}
inline int Qsum(int u, int v) {
    int ret = 0;
    while(top[u] != top[v]) {
        if(dep[top[u]] < dep[top[v]]) swap(u, v);
        ret += query(root, dfn[top[u]], dfn[u]), u = fa[top[u]];
    }
    if(dep[u] > dep[v]) swap(u, v);
    ret += query(root, dfn[u], dfn[v]);
    return ret;
}
