using namespace std;
const int N = 2e3 + 10;

int n, mod, pr[N], prTot, flag[N], pos, a[N];
bool big[N];

#define Clear(a, b) memset(a, b, sizeof a)
#define sft(x) (1 << (x - 1))
#define full(x) ((1 << x) - 1)

inline void UpdAdd(int &x, int y) { 
	if (y > mod) y -= mod;
	x += y;
	if (x > mod) x -= mod;
}

void Init() {
	scanf("%d%d", &n, &mod);
	for (int i = 2; i <= n; ++ i) {
		if (! flag[i]) pr[++ prTot] = i;
		for (int j = 1; j <= prTot && i * pr[j] <= n; ++ j) {
			flag[i * pr[j]] = pr[j];
			if (i % pr[j] == 0) break;
		}
	}
	for (int i = 1; i <= prTot; ++ i) 
		if (pr[i] <= sqrt(n)) pos = i; else break;

	for (int i = 2; i <= n; ++ i) {
		int x = i;
		for (int j = 1; j <= pos; ++ j) {
			int prime = pr[j];
			if (x % prime == 0) {
				a[i] |= sft(j);
				while (x % prime == 0) x /= prime;
			}
		}
		if (x != 1) big[i] = true;
	}
}

int g[N], f[N][N], d[N][N][2];

void Solve() {
	g[0] = 1;
	for (int i = 2; i <= n; ++ i) if (! big[i])
		for (int j = full(pos); j >= 0; -- j) UpdAdd(g[j | a[i]], g[j]);

	for (int i = 0; i <= full(pos); ++ i)
		for (int j = 0; j <= full(pos); ++ j) 
			if ((i & j) == 0) f[i][j] = 1ll * g[i] * g[j] % mod;

	for (int i = pos + 1; i <= prTot; ++ i) {
		Clear(d, 0);
		for (int j = pr[i]; j <= n; j += pr[i]) 
			for (int x = full(pos); x >= 0; -- x)
				for (int y = full(pos); y >= 0; -- y) {
					UpdAdd(d[x | a[j]][y][0], d[x][y][0] + f[x][y]);
					UpdAdd(d[x][y | a[j]][1], d[x][y][1] + f[x][y]);
				}
		for (int x = 0; x <= full(pos); ++ x)
			for (int y = 0; y <= full(pos); ++ y)
				UpdAdd(f[x][y], d[x][y][0] + d[x][y][1]);
	}
	
	int ans = 0;	
	for (int i = 0; i <= full(pos); ++ i)
		for (int j = 0; j <= full(pos); ++ j) 
			if ((i & j) == 0) UpdAdd(ans, f[i][j]);
	printf("%d\n", ans);
}

int main() {
	
	Init();
	Solve();

	return 0;
}

