int bfs(int S, int T){
     int i, j, k, l, r;
     for (i = 1; i <= T; i++) inq[i] = 0, d[i] = 1000000000, R[i] = node[i];
     inq[q[l = r = 0] = S] = 1; d[S] = 0;
     while (l <= r){
