	       if (cap[j] > f[j])
		    if (d[to[j]] > d[k] + 1){
			 d[to[j]] = d[k] + 1;
			 if (!inq[to[j]]) inq[q[++r] = to[j]] = 1;
		    }
     }
     return inq[T];
}

int dfs(int x, int a, int T){
     if (x == T) return a;
     int F, fl = 0;
     for (int &j = R[x]; j; j = next[j])
	  if (cap[j] > f[j])
	       if (d[to[j]] == d[x] + 1){
		    F = dfs(to[j],
			    min(cap[j] - f[j], a), T);
		    f[j] += F; f[_(j)] -= F; fl += F; a -= F;
		    if (a == 0) return fl;
	       }
     return fl;
}

