int dfs(int u,int a){
	if(u==TT || !a)return a;
	int flow=0,f;
	for(int &i=cur[u];i;i=edge[i].next)if(edge[i].cap){
		int v=edge[i].to;
		if(d[v]==d[u]+1 && (f=dfs(v,min(a,edge[i].cap)))>0){
			edge[i].cap-=f;
			edge[i^1].cap+=f;
			flow+=f;
			a-=f;
			if(!a)return flow;
		}
	}
	return flow;
}
