const ll inf = 2e9;
ll n,m,k;

int main(){
	cin >> n >> m >> k;
	
	if (!k){
		cout << min(2ll,n*m) << endl;
		return 0;
	}
	ll l = 1, r = min(inf,n*m);
	while(l < r){
		ll mid = (l+r+1)/2;
		ll u = floor(sqrt(mid));
		ll v = ceil(sqrt(mid));
		if (u > n || u > m){
			u = min(n,m);
			v = (mid-1)/u+1;
		}
		if (mid*(mid-1)/2 - mid*2+u+v <= k) l = mid;
		else r = mid-1;
	}
	cout << l << endl;
	return 0;
}

