int n,m,a[5100],b[5100],t[5100],ans[5100],cnt,x,dir,tot,node;
bool flag[5100],bol[5100],vis[5100];
struct edge
{
    int v,idx;
    edge *nxt;
    bool flag;
} pool[10100],*tp,*fst[5100],*stk[5100];

void addedge(int u,int v,int idx)
{
    *tp=(edge){v,idx,fst[u]},fst[u]=tp++;
}

bool dfs(int x)
{
    if (tot && x==node)
        return 1;
    if (vis[x])
        return 0;
    vis[x]=1;
    for (edge *i=fst[x]; i; i=i->nxt)
        if (!flag[i->idx] && !i->flag)
        {
            flag[i->idx]=1,(stk[++tot]=i)->flag=1;
            if (dfs(i->v))
                return 1;
            --tot,flag[i->idx]=0;
        }
    return vis[x]=0;
}

void reduce()
{
    memset(vis,0,sizeof(vis));
    tp=pool,memset(fst,0,sizeof(fst));
    repu(i,1,m)
    {
        if (bol[a[i]])
            a[i]=node;
        if (bol[b[i]])
            b[i]=node;
        if (a[i]!=node || b[i]!=node)
        {
            addedge(a[i],b[i],i);
            if (!t[i])
                addedge(b[i],a[i],i);
        }
    }
    tot=0,dfs(node);
    cnt+=tot-1,x=node;
    repu(i,1,tot)
    {
        bol[stk[i]->v]=1;
        ans[stk[i]->idx]=b[stk[i]->idx]==x;
        x=stk[i]->v;
    }
}

int main()
{
    scanf("%d%d",&n,&m);
    repu(i,1,m)
        scanf("%d%d%d",&a[i],&b[i],&t[i]);
    node=n>=233?233:1;//可hack
    cnt=bol[node]=1;
    while (cnt<n)
        reduce();
    repu(i,1,m)
        printf("%d\n",ans[i]);
    return 0;
}

