#include <bits/stdc++.h>
using namespace std;
const int mod = 998244353;
inline int Mod(int x) {
    if (x >= mod) return x - mod;
    return x;
}
inline int power(int a, int b) {
    long long res = a, ans = 1;
    for (; b; b >>= 1, res = res * res % mod) if (b & 1) ans = ans * res % mod;
    return ans;
}
struct node {
    int cnt1, cnt2;
    inline node() {}
    inline node(int a, int b): cnt1(a), cnt2(b) {}
};
inline node operator + (const node &a, const node &b) {
    return node(1ll * a.cnt1 * b.cnt1 % mod, (1ll * a.cnt1 * b.cnt2 + 1ll * a.cnt2 * b.cnt1) % mod);
}
inline node operator * (const node &a, const node &b) {
    return node((1ll * a.cnt1 * b.cnt1 + 1ll * a.cnt2 * b.cnt1 + 1ll * a.cnt1 * b.cnt2) % mod, 1ll * a.cnt2 * b.cnt2 % mod);
}
int n, m;
map < int, node > son[100010];
int vis[100010], que[100010], tot;
int w[20][20], id[100010];
int ans = 1;
inline void addedge(int u, int v, node w) {
    if (u == v) ans = 1ll * ans * (w.cnt1 + w.cnt2) % mod;
    else {
        if (son[u].count(v)) son[u][v] = son[u][v] * w;
        else son[u][v] = w;
        if (son[v].count(u)) son[v][u] = son[v][u] * w;
        else son[v][u] = w;
    }
}
void dfs(int cur) {
    if (vis[cur]) return;
    vis[cur] = 1;
    if (son[cur].size() == 0) return;
    if (son[cur].size() == 1) {
        auto [v, w] = *son[cur].begin();
        son[v].erase(son[v].find(cur));
        if (son[v].size() <= 2) dfs(v);
        ans = 1ll * ans * w.cnt1 % mod;
        return;
    }
    if (son[cur].size() == 2) {
        auto [v1, w1] = *son[cur].begin();
        auto [v2, w2] = *next(son[cur].begin());
        son[v1].erase(son[v1].find(cur));
        son[v2].erase(son[v2].find(cur));
        addedge(v1, v2, w1 + w2);
        if (son[v1].size() <= 2) dfs(v1);
        if (son[v2].size() <= 2) dfs(v2);
    }
}
int f[19][1 << 18];
inline void FWT(int *a, int n, int type) {
    for (int p = 1; p < n; p <<= 1)
        for (int i = 0; i < n; i++) if (i & p) {
            int h1 = a[i - p], h2 = a[i];
            a[i - p] = Mod(h1 + h2);
            a[i] = Mod(h1 - h2 + mod);
        }
    if (type == -1) {
        int inv = power(n, mod - 2);
        for (int i = 0; i < n; i++) a[i] = 1ll * a[i] * inv % mod;
    }
}
int cur[20], tmp[20], inv[20];
inline void Ln(int *a, int n) {
    for (int i = 1; i <= n; i++) {
        int sum = 0;
        for (int j = 1; j < i; j++) sum = (sum + 1ll * tmp[j] * a[i - j]) % mod;
        tmp[i] = (1ll * i * a[i] - sum + mod) % mod;
    }
    a[0] = 0;
    for (int i = 1; i <= n; i++) a[i] = 1ll * tmp[i] * inv[i] % mod;
}
int main() {
    scanf("%d%d", &n, &m);
    m += n - 1;
    for (int i = 1; i <= m; i++) {
        int u, v;
        scanf("%d%d", &u, &v);
        addedge(u, v, node(1, 1));
    }
    for (int i = 1; i <= n; i++) if (son[i].size() <= 2) dfs(i);
    for (int i = 1; i <= n; i++) if (!vis[i]) id[i] = tot++;
    for (int i = 0; i < tot; i++)
        for (int j = 0; j < tot; j++) w[i][j] = 1;
    for (int i = 1; i <= n; i++) if (!vis[i])
        for (auto [v, e] : son[i]) if (v < i) {
            ans = 1ll * ans * e.cnt2 % mod;
            w[id[i]][id[v]] = w[id[v]][id[i]] = (1ll * e.cnt1 * power(e.cnt2, mod - 2) + 1) % mod;
        }
    for (int i = 0; i < 1 << tot; i++) {
        int cur = 1;
        for (int u = 0; u < tot; u++) if ((i >> u) & 1)
            for (int v = u + 1; v < tot; v++) if ((i >> v) & 1) cur = 1ll * cur * w[u][v] % mod;
        f[__builtin_popcount(i)][i] = cur;
    }
    for (int i = 0; i <= tot; i++) FWT(f[i], 1 << tot, 1);
    inv[1] = 1;
    for (int i = 2; i <= tot; i++) inv[i] = 1ll * (mod - mod / i) * inv[mod % i] % mod;
    for (int i = 0; i < 1 << tot; i++) {
        for (int j = 0; j <= tot; j++) cur[j] = f[j][i];
        Ln(cur, tot);
        for (int j = 0; j <= tot; j++) f[j][i] = cur[j];
    }
    FWT(f[tot], 1 << tot, -1);
    if (tot == 0) f[0][0] = 1;
    cout << 1ll * ans * f[tot][(1 << tot) - 1] % mod << endl;
}

