int ins(ll x)
{
    for (int i = 62; i >= 0; i--)
    {
        if (x & (1ll << i))
        {
            if (!d[i])
            {
                d[i] = x;
                return 1;
            }
            else
            {
                x ^= d[i];
            }
        }
    }
    return -1;
}

