                dfs(v, x);
                val[x] ^= val[v];
            }
            else if (vis[v] == 2)
            {
                cnt[1 << tot]++, val[x] ^= 1 << tot, val[v] ^= 1 << tot, tot++;
            }
        }
    vis[x] = 1;
    cnt[val[x]]++;
}

vector<ll> a;
