void dfs2(int dep, int res)
{
    if (dep == (int)a.size())
    {
        ans += res, ans %= mod;
        return;
    }
    vector<ll> tmp(70);
    for (int i = 0; i <= 62; i++)
        tmp[i] = d[i];
