    for (int i = 0; i <= 62; i++)
        d[i] = tmp[i];
    //cerr << a[dep] << " " << cnt[a[dep]] << endl;
    if (~ins(a[dep]))
        dfs2(dep + 1, 1ll * res * cnt[a[dep]] % mod);
}

