	{
		printf("No\n");
		ende=true;
	}
	for (int i=1;i<=q;i++)
	{
		int x,y;
		read(x),read(y);
		if (!ende)	fa[doit(x,y)]=-1;
	}
	if (ende)	continue;
	int sum=0;
	for (int i=1;i<=n;i++)
		for (int j=1;j<=m;j++)
		if (fa[doit(i,j)]==0)
		{
			if (ende)	break;
