			int h=1,t=1;
			x[1]=i,y[1]=j;
			fa[doit(i,j)]=-2;
			while (h<=t)
			{
				if (ende)	break;
				for (int hh=0;hh<4;hh++)
				{
					int xx=x[h]+u[hh],yy=y[h]+v[hh];
					if (yy<1)	yy=m;
					if (yy>m)	yy=1;
					if (xx>=1 && xx<=n && yy>=1 && yy<=m)
					if (fa[doit(xx,yy)]!=0)
