						if (hhw!=fa[doit(x[h],y[h])] && fa[hhw]!=-1)	{printf("No\n");ende=true;break;}
					}	else t++,x[t]=xx,y[t]=yy,fa[doit(xx,yy)]=doit(x[h],y[h]);
				}
				h++;
			}
		}
