struct LEO {int x,y;}a[M],q[N*N];
bool cmp1(LEO a,LEO b) {
	return (a.x<b.x||(a.x==b.x&&a.y<b.y));
}
bool cmp2(LEO a,LEO b) {
	return (a.y<b.y||(a.y==b.y&&a.x<b.x));
}
int bfs() {
	int he=0,ta=0;
	memset(vis,true,sizeof(vis));
	for (int i=1;i<=k;i++) vis[a[i].x][a[i].y] = false;
	for (int i=1;i<=n&&ta==0;i++)
		for (int j=1;j<=m&&ta==0;j++) if (vis[i][j]) { ta++;q[1].x = i,q[1].y = j,vis[i][j] = false;break; }
	while (he!=ta) {
		he++;
		for (int i=0;i<4;i++) {
			int x=q[he].x+flag[i][0],y=(q[he].y+flag[i][1]+m-1)%m+1;
			if (x<1||x>n||vis[x][y]==false) continue;
			q[++ta].x=x,q[ta].y=y;vis[x][y]=false;
		}
	}
	return ta;
}
