			if (a[i].y==1&&a[j-1].y==m) tot--;	
			sum-=j-i+tot;
		}
		sort(a+1,a+k+1,cmp2);
		for (int i=1,j;i<=k;i=j) {
			j=i+1;
			while (j<=k&&a[i].y==a[j].y) j++;
			int tot = 1;
