inline long long getint()
{
    long long x=0; char c=getchar(); bool flag=false;
    while ((c!='-')&&((c<'0')||(c>'9'))) c=getchar();
    if (c=='-') flag=true,c=getchar();
    while ((c>='0')&&(c<='9')) x=x*10+(long long)(c-'0'),c=getchar();
    if (flag) return -x; else return x;
}
inline bool cmp(const point &a,const point &b)
{
	if (a.x==b.x) return a.y<b.y;
	return a.x<b.x;
}
void init()
{
	n=getint(); m=getint(); cnt=getint(); ans=n*m+(n-1LL)*m;
	for (int i=1; i<=cnt; i++) a[i].x=getint(),a[i].y=getint();
	sort(a+1,a+cnt+1,cmp);
}
inline bool find(int x,int y)
{
	if (y==0) y=m; point now; now.x=x; now.y=y;
	int k=lower_bound(a+1,a+cnt+1,now,cmp)-a;
	if (k>cnt) return false;
	if ((a[k].x!=x)||(a[k].y!=y)) return false;
	return true;
}
void solve()
{
	for (int i=1; i<=cnt; i++)
	{
		int x=a[i].x,y=a[i].y;
		if ((x>1)&&(!find(x-1,y))) ans--;
		if (!find(x,y-1)) ans--; ans--;
		if (x<n) ans--;
	}
	long long nowans=n*m-(long long)cnt;
	if (nowans-1LL==ans) printf("Yes\n"); else printf("No\n");
}
