template<class T> inline bool getd(T& x)
{
	int ch=getchar();
	bool neg=false;
	while(ch!=EOF && ch!='-' && !isdigit(ch)) ch=getchar();
	if(ch==EOF) return false;
	if(ch=='-'){
		neg=true;
		ch=getchar();
	}
	x=ch-'0';
	while(isdigit(ch=getchar())) x=x*10+ch-'0';
	if(neg) x=-x;
	return true;
}

int l,n,m,c[maxn];

bool judge(int ans)
{
	int k=m,h=-1;
	for(int i=0;i<n;i++){
		int dist=h==-1?c[i]:c[i]-c[h];
		if(dist<ans){
			k--;
			if(k<0) return false;
		}
		else h=i;
	}
	if(k==0 && l-c[n-1]<ans) return false;
	return true;
}

