		}
		else if (ss<sl)sl = ss;
		up = i;
	}
	*sp = sl;
	*snn = s / k - s / (k + num -m) + *sp;
	return 1;
}

int erfen() //二分答案
{
	int l = 0, r = s / k, mid, res = 0, sp,snn=0;
	while (l <= r)
	{
		if (snn>l&& snn< r)mid = snn;
		else mid = (l + r) / 2;
		if (check(mid, &sp, &snn)) {
			l = sp + 1, res = sp;
		}
		else {
			r = sp;
		}
	}
	return res;
}

