	pre[u] = fa , sum[u] = sum[fa] + cost[u];
	for(edge *i=head[u]; i; i=i->next) {
		if(i->v != fa) {
			cost[i->v] = i->w;
			Dfs_1(i->v, u);
			tot[u] += tot[i->v];
			if(tot[i->v] > tot[son[u]]) son[u] = i->v;
		}
	}
}

void Dfs_2(int u,int fa) {
	if(son[fa] == u) top[u] = top[fa] , dep[u] = dep[fa];
	else top[u] = u , dep[u] = dep[fa] + 1;

	dfn[u] = ++dfs_num;
	who[dfs_num] = u;
	if(son[u]) Dfs_2(son[u],u);
	for(edge *i=head[u]; i; i=i->next) {
		if(i->v != fa && i->v != son[u]) {
			Dfs_2(i->v, u);
		}
	}
}

int Get_Lca(int x,int y) {
	Rcnt = 0;
	if(dep[x] < dep[y]) swap(x, y);
	while(dep[x] != dep[y]) {
		road[++Rcnt] = make_pair(dfn[top[x]], dfn[x]);
		x = pre[top[x]];
	}
	while(top[x] != top[y]) {
		road[++Rcnt] = make_pair(dfn[top[x]], dfn[x]);
		road[++Rcnt] = make_pair(dfn[top[y]], dfn[y]);
		x = pre[top[x]] , y = pre[top[y]];
	}
	if(x != y) {
		if(dfn[x] > dfn[y]) swap(x, y);
		road[++Rcnt] = make_pair(dfn[x]+1, dfn[y]);
	}
	return x;
}

void Change_1(int k,int l,int r,int ll,int rr,int val) {
	if(l == ll && r == rr) {
		if(val1[k] < val) val1[k] = val;
		return;
	}
	int mid = (l + r) >> 1;
	if(rr <= mid) Change_1(k<<1, l, mid, ll, rr, val);
		else if(ll > mid) Change_1(k<<1|1, mid+1, r, ll, rr, val);
			else Change_1(k<<1, l, mid, ll, mid, val) , Change_1(k<<1|1, mid+1, r, mid+1, rr, val);
}

void Change_2(int k,int l,int r,int ll,int rr,int val) {
	if(l == ll && r == rr) {
		if(val2[k] < val) val2[k] = val;
		return;
	}
	int mid = (l + r) >> 1;
	if(rr <= mid) Change_2(k<<1, l, mid, ll, rr, val);
		else if(ll > mid) Change_2(k<<1|1, mid+1, r, ll, rr, val);
			else Change_2(k<<1, l, mid, ll, mid, val) , Change_2(k<<1|1, mid+1, r, mid+1, rr, val);
}

void Get_ans(int k,int l,int r) {
	if(l == r) {
		if(who[l] != 1) {
			ans = min( ans , max(val1[k]-cost[who[l]],val2[k]) );
		}
		return;
	}

	int lson = (k<<1) , rson = (k<<1|1);
	val1[lson] = max( val1[lson] ,val1[k] );
	val2[lson] = max( val2[lson] ,val2[k] );
	val1[rson] = max( val1[rson] ,val1[k] );
	val2[rson] = max( val2[rson] ,val2[k] );

	int mid = (l + r) >> 1;
	Get_ans(lson, l, mid);
	Get_ans(rson, mid+1, r);
}

int main() {
#ifndef ONLINE_JUDGE
	freopen("transport.in","r",stdin);
	freopen("transport.out","w",stdout);
#endif

	//clock_t t1 = clock();

	register int i, u, v, w, x, y, z;

	n = input() , m = input();
	for(i=1; i<n; i++) {
		u = input() , v = input() , w = input();
		Addedge(u, v, w) , Addedge(v, u, w);
	}

	Dfs_1(1, 0);
	Dfs_2(1, 0);

	while(m --> 0) {
		x = input() , y = input();
		if(x == y) continue;

		z = Get_Lca(x, y);
		w = sum[x] + sum[y] - 2 * sum[z];

		sort(road+1, road+Rcnt+1);

		for(i=1; i<=Rcnt; i++) {
			Change_1(1, 1, n, road[i].fst, road[i].sed, w);
		}

		if(road[1].fst != 1) Change_2(1, 1, n, 1, road[1].fst-1, w);
		for(i=1; i<Rcnt; i++) {
			if(road[i].sed+1 < road[i+1].fst) {
				Change_2(1, 1, n, road[i].sed+1, road[i+1].fst-1, w);
			}
		}
		if(road[Rcnt].sed != n) Change_2(1, 1, n, road[Rcnt].sed+1, n, w);
	}

	Get_ans(1, 1, n);

	printf("%d\n",ans);

	//printf("Time = %d\n",clock()-t1);

#ifndef ONLINE_JUDGE
	fclose(stdin);
	fclose(stdout);
#endif
	return 0;
}

