using namespace std;

const int maxn = 300050, maxm = 300050;

int n, m;

struct edge
{
	int to, t;
	edge() {}
	edge(int to, int t) : to(to), t(t) {}
};

vector<int> G[maxn];
vector<edge> E;

void AddEdge(int u, int v, int t)
{
	G[u].push_back(E.size());
	E.push_back(edge(v, t));
}

int F[maxn], dep[maxn], sz[maxn];
queue<int> que;
stack<int> stck;

void BFS()
{
	memset(F, 0, sizeof(F));
	dep[1] = 1;
	que.push(1);
	while (!que.empty())
	{
		int r = que.front();
		que.pop();
		stck.push(r);
		for (unsigned i = 0; i < G[r].size(); i++)
		{
			int u = E[G[r][i]].to;
			if (u > 1 && !F[u])
			{
				F[u] = r;
				dep[u] = dep[r] + 1;
				que.push(u);
			}
		}
	}

	while (!stck.empty())
	{
		int t = stck.top();
		stck.pop();
		sz[t] = 1;
		for (unsigned i = 0; i < G[t].size(); i++)
		{
			int u = E[G[t][i]].to;
			if (u != F[t]) sz[t] += sz[u];
		}
	}
}

struct DFS
{
	int u, top, t;
	DFS(int u, int top, int t) : u(u), top(top), t(t) {}
};

stack<DFS> status;
bool fst[maxn];
int nxt[maxn];
unsigned cur[maxn];

int tid[maxn], top[maxn];
int cnt, sum[maxn];

void Build()
{
	memset(fst, 1, sizeof(fst));
	memset(cur, 0, sizeof(cur));
	sum[cnt = 0] = 0;
	status.push(DFS(1, 1, 0));
	while (!status.empty())
	{
		DFS tmp = status.top();
		int u = tmp.u, tp = tmp.top, t = tmp.t;
		if (fst[u])
		{
			fst[u] = 0;

			top[u] = tp;
			tid[u] = ++cnt;
			sum[cnt] = sum[cnt-1] + t;

			nxt[u] = 0;
			int mxsz = 0, tm;
			for (unsigned i = 0; i < G[u].size(); i++)
			{
				edge e = E[G[u][i]];
				if (e.to != F[u] && sz[e.to] > mxsz)
				{
					mxsz = sz[nxt[u] = e.to];
					tm = e.t;
				}
			}
			if (nxt[u]) status.push(DFS(nxt[u], tp, tm));
		}
		else
		{
			edge e;
			while (cur[u] < G[u].size())
			{
				e = E[G[u][cur[u]]];
				if (e.to != F[u] && e.to != nxt[u]) break;
				cur[u]++;
			}
			if (cur[u] == G[u].size()) status.pop();
			else
			{
				status.push(DFS(e.to, e.to, e.t));
				cur[u]++;
			}
		}
	}
}

int U[maxm], V[maxm], len[maxm];

int Distance(int u, int v)
{
	int dist = 0;
	while (top[u] != top[v])
	{
		if (dep[top[u]] > dep[top[v]]) swap(u, v);
		dist += sum[tid[v]] - sum[tid[top[v]]-1];
		v = F[top[v]];
	}
	if (dep[u] > dep[v]) swap(u, v);
	dist += sum[tid[v]] - sum[tid[u]];
	return dist;
}

int B[maxn];

void Update(int u, int v)
{
	B[tid[u]+1]++;
	B[tid[v]+1]--;
}

void Modify(int u, int v)
{
	while (top[u] != top[v])
	{
		if (dep[top[u]] > dep[top[v]]) swap(u, v);
		Update(top[v], v);
		v = F[top[v]];
	}
	if (dep[u] > dep[v]) swap(u, v);
	Update(u, v);
}

bool OK(int L)
{
	memset(B, 0, sizeof(B));
	int cnt = 0, maxl = 0;
	for (int i = 0; i < m; i++)
		if (len[i] > L)
		{
			cnt++;
			maxl = max(maxl, len[i]);
			Modify(U[i], V[i]);
		}

	int s = 0;
	for (int i = 2; i <= n; i++)
        if ((s += B[i]) == cnt && maxl - (sum[i] - sum[i-1]) <= L) return 1;
	return 0;
}

int main()
{
	scanf("%d%d", &n, &m);
	for (int i = 1; i <= n; i++) G[i].clear();
	E.clear();
	for (int i = 1; i < n; i++)
	{
		int u, v, t;
		scanf("%d%d%d", &u, &v, &t);
		AddEdge(u, v, t);
		AddEdge(v, u, t);
	}

	BFS();
	Build();

	int R = 0;
	for (int i = 0; i < m; i++)
	{
		scanf("%d%d", &U[i], &V[i]);
		len[i] = Distance(U[i], V[i]);
		R = max(R, len[i]);
	}

	int L = R;
	for (unsigned i = 0; i < E.size(); i++)
		L = min(L, R - E[i].t);
	while (L < R)
	{
		int M = L + ((R - L) >> 1);
		if (OK(M)) R = M;
		else L = M + 1;
	}
	printf("%d\n", L);

	return 0;
}

