  P(){a=b=c=d=0;}
  P(int _a,int _b,int _c,int _d){a=_a,b=_b,c=_c,d=_d;}
  P operator+(P x){return P(a+x.a,b+x.b,c+x.c,d+x.d);}
}g1[4],g2[3],g3[2],g4;
inline void up(int&a,int b){if(a>b)a=b;}
int F(P x){
  if(x.a<0||x.b<0||x.c<0||x.d<0)return 30;
  if(x.a>15||x.b>15||x.c>15||x.d>15)return 30;
  if(~f[x.a][x.b][x.c][x.d])return f[x.a][x.b][x.c][x.d];
  int t=30;
  for(int i=0;i<4;i++)up(t,F(x+g1[i]));
  for(int i=0;i<3;i++)up(t,F(x+g2[i]));
  for(int i=0;i<2;i++)up(t,F(x+g3[i]));
  up(t,F(x+g4));
  for(int i=0;i<4;i++)for(int j=0;j<2;j++)up(t,F(x+g1[i]+g3[j]));
  for(int i=0;i<3;i++)for(int j=0;j<2;j++)up(t,F(x+g2[i]+g3[j]));
  for(int i=0;i<4;i++)for(int j=0;j<4;j++)up(t,F(x+g4+g1[i]+g1[j]));
  for(int i=0;i<3;i++)up(t,F(x+g4+g2[i]));
  for(int i=0;i<3;i++)for(int j=0;j<3;j++)up(t,F(x+g4+g2[i]+g2[j]));
  up(t,F(x+g4+g4));
  return f[x.a][x.b][x.c][x.d]=t+1;
}
