void DFS(int Step,int Rem,int Cur,int Low)
{
	if (Step>=Ans) return;
	if (Rem==0) Ans=Step;
	
	int rem=0;
	For(i,0,15) if (A[i]) rem++;
	DFS(Step+rem,0,0,0);
	
	if (Step+rem/3>=Ans) return;

	if (Cur<=1)
		for (int Len=5;Len<=12;Len++)
		{
			int Pos=-1;
			For(i,3,3+Len) if (--A[i]<0) Pos=i;
			for (int i=3;i+Len-1<=14;i++)
			{
				if (i>Pos) DFS(Step+1,Rem-Len,1,0);
				if (--A[i+Len]<0) Pos=i+Len;
				A[i]++;
			}
			For(i,16-Len,16) A[i]++;
		}

	if (Cur<=2)
		for (int Len=3;Len<=12;Len++)
		{
			int Pos=-1;
			For(i,3,3+Len) if ((A[i]-=2)<0) Pos=i;
			for (int i=3;i+Len-1<=14;i++)
			{
				if (i>Pos) DFS(Step+1,Rem-Len,1,0);
				if ((A[i+Len]-=2)<0) Pos=i+Len;
				A[i]+=2;
			}
			For(i,16-Len,16) A[i]+=2;
		}

	if (Cur<=3)
		for (int Len=3;Len<=12;Len++)
		{
			int Pos=-1;
			For(i,3,3+Len) if ((A[i]-=3)<0) Pos=i;
			for (int i=3;i+Len-1<=14;i++)
			{
				if (i>Pos) DFS(Step+1,Rem-Len,1,0);
				if ((A[i+Len]-=3)<0) Pos=i+Len;
				A[i]+=3;
			}
			For(i,16-Len,16) A[i]+=3;
		}

	if (Cur<=4)
		For(i,Cur==4?Low+1:2,15) if (A[i]>=4)
		{
			A[i]-=4;
			For(j,0,15) if (A[j]>=1)
			{
				A[j]--;
				For(k,j,15) if (A[k]>=1) A[k]--,DFS(Step+1,Rem-4-2,4,i),A[k]++;
				A[j]++;
			}
			For(j,2,15) if (A[j]>=2)
			{
				A[j]-=2;
				For(k,j,15) if (A[k]>=2) A[k]-=2,DFS(Step+1,Rem-4-4,4,i),A[k]+=2;
				A[j]+=2;
			}
			A[i]+=4;
		}

	if (Cur<=5)
		For(i,Cur==5?Low+1:2,15) if (A[i]>=3)
		{
			A[i]-=3;
			For(j,0,15) if (A[j]>=1) A[j]--,DFS(Step+1,Rem-3-1,5,i),A[j]++;
			For(j,2,15) if (A[j]>=2) A[j]-=2,DFS(Step+1,Rem-3-2,5,i),A[j]+=2;
			A[i]+=3;
		}
}

