long long getint()
{
	long long x=0; char c=getchar(); bool flag=false;
	while ((c!='-')&&((c<'0')||(c>'9'))) c=getchar();
	if (c=='-') flag=true,c=getchar();
	while ((c>='0')&&(c<='9')) x=x*10LL+(long long)(c-'0'),c=getchar();
	if (flag) return -x; else return x;
}
int change(node a)
{
	int nowans=0;
	for (int i=1; i<=15; i++)
	{
		for (int j=1; j<=first.a[i]-a.a[i]; j++) nowans=nowans<<1;
		for (int j=1; j<=a.a[i]; j++) nowans=(nowans<<1)+1;
	}
	return nowans;
}
void init()
{
	memset(first.a,0,sizeof(first.a));
	for (int i=1; i<=n; i++)
	{
		int x=getint(),y=getint();
		if ((x==0)&&(y==1)) {first.a[14]++; continue;}
		if ((x==0)&&(y==2)) {first.a[15]++; continue;}
		if (x==1) {first.a[12]++; continue;}
		if (x==2) {first.a[13]++; continue;}
		first.a[x-2]++;
	}
	First=change(first);
}
int dfs(node a)
{
	int Hash=change(a); int nowans=INF; if (Hash==0) return 0;
	if (v[Hash]==cases) return f[Hash]; node now;
	//火箭
	if (a.a[14]*a.a[15]==1)
	{
		now=a; now.a[14]--; now.a[15]--; 
		nowans=min(nowans,dfs(now));
	}
	//三带一
	for (int i=1; i<=15; i++)
	{
		if (a.a[i]<3) continue; now=a; now.a[i]-=3;
		for (int j=1; j<=15; j++)
		{
			if (now.a[j]==0) continue; now.a[j]--;
			nowans=min(nowans,dfs(now)); now.a[j]++;
		}
	}
	//三带二
	for (int i=1; i<=15; i++)
	{
		if (a.a[i]<3) continue; now=a; now.a[i]-=3;
		for (int j=1; j<=15; j++)
		{
			if (now.a[j]<2) continue; now.a[j]-=2;
			nowans=min(nowans,dfs(now)); now.a[j]+=2;
		}
	}
	//单顺子
	for (int i=1; i<=12; i++)
	{
		bool flag=true;
		for (int k=i; k<=i+3; k++) if (a.a[k]<1) {flag=false; break;}
		if (!flag) continue; now=a;
		for (int k=i; k<=i+3; k++) now.a[k]--;
		for (int j=i+4; j<=12; j++)
		{
			if (now.a[j]<1) break; now.a[j]--;
			nowans=min(nowans,dfs(now));
		}
	}
	//双顺子
	for (int i=1; i<=12; i++)
	{
		bool flag=true;
		for (int k=i; k<=i+1; k++) if (a.a[k]<2) {flag=false; break;}
		if (!flag) continue; now=a;
		for (int k=i; k<=i+1; k++) now.a[k]-=2;
		for (int j=i+2; j<=12; j++)
		{
			if (now.a[j]<2) break; now.a[j]-=2;
			nowans=min(nowans,dfs(now));
		}
	}
	//三顺子
	for (int i=1; i<=12; i++)
	{
		bool flag=true;
		for (int k=i; k<=i; k++) if (a.a[k]<3) {flag=false; break;}
		if (!flag) continue; now=a;
		for (int k=i; k<=i; k++) now.a[k]-=3;
		for (int j=i+1; j<=12; j++)
		{
			if (now.a[j]<3) break; now.a[j]-=3;
			nowans=min(nowans,dfs(now));
		}
	}
	//四带二单
	for (int i=1; i<=15; i++)
	{
		if (a.a[i]!=4) continue; now=a; now.a[i]-=4;
		for (int j=1; j<=15; j++)
		{
			if (now.a[j]<1) continue; now.a[j]--;
			for (int k=1; k<=15; k++)
			{
				if (now.a[k]<1) continue; now.a[k]--;
				nowans=min(nowans,dfs(now)); now.a[k]++;
			}
			now.a[j]++;
		}
	}
	//四带二对
	for (int i=1; i<=15; i++)
	{
		if (a.a[i]!=4) continue; now=a; now.a[i]-=4;
		for (int j=1; j<=15; j++)
		{
			if (now.a[j]<2) continue; now.a[j]-=2;
			for (int k=1; k<=15; k++)
			{
				if (now.a[k]<2) continue; now.a[k]-=2;
				nowans=min(nowans,dfs(now)); now.a[k]+=2;
			}
			now.a[j]+=2;
		}
	}
	//单张/对子/三张/炸弹
	for (int i=1; i<=15; i++)
	{
		now=a; if (now.a[i]==0) continue;
		now.a[i]=0; nowans=min(nowans,dfs(now));
	}
	v[Hash]=cases; f[Hash]=nowans+1; return nowans+1;
}
