int calc(int a,int b,int c,int d){
	if (a<0 || b<0 || c<0 || d<0) return inf;
	if (!c && !d) return a+b;
	if (~f[a][b][c][d]) return f[a][b][c][d];
	int ans=min(calc(a+1,b,c+1,d-1),calc(a,b+2,c,d-1));
	ans=min(ans,min(calc(a+3,b,c-1,d),calc(a+1,b+1,c-1,d)));
	ans=min(ans,min(calc(a-2,b,c,d-1),calc(a,b-1,c,d-1))+1);
	ans=min(ans,min(calc(a,b-2,c,d-1),calc(a,b,c,d-2))+1);
	ans=min(ans,min(calc(a-1,b,c-1,d),calc(a,b-1,c-1,d))+1);
	return f[a][b][c][d]=ans;
}

