#define M 998244353
using namespace std;

int n,cnt[1<<16],lbt[1<<16];
int lbit(int x){
	x=x&-x;
	return (x>>16)?lbt[x>>16]+16:lbt[x];
}
int count(int x){
	return cnt[x>>16]+cnt[x&65535];
}
struct group{
	int n,b[50][50];
	bool check()const{
		for(int i=0;i<n;i++)
			for(int j=0;j<n;j++)
				for(int k=0;k<n;k++)
					if(b[b[i][j]][k]!=b[i][b[j][k]])return 0;
		return 1;
	}
	int geti()const{
		for(int i=0;i<n;i++){
			bool f=1;
			for(int j=0;j<n;j++)if(b[i][j]!=j || b[j][i]!=j){f=0;break;}
			if(f)return i;
		}
	}
	int extend(int a,int m)const{
		for(int q=1<<m;q;){
			int u=lbit(q);q&=q-1;
			a|=1<<u;
			for(int i=a;i;i&=i-1){
				int v=lbit(i);
				if(!(a&(1<<b[u][v])))q|=1<<b[u][v];
				if(!(a&(1<<b[v][u])))q|=1<<b[v][u];
			}
		}
		return a;
	}
	int o(int x,int y,int f)const{
		int ans=0;
		for(;y;y&=y-1){
			int u=lbit(y);
			if(f)ans|=1<<b[u][x];else ans|=1<<b[x][u];
		}
		return ans;
	}
	bool normal(int s)const{
		for(int i=0;i<n;i++)
			if(o(i,s,0)!=o(i,s,1))return 0;
		return 1;
	}
	group operator /(const int &s)const{
		map<int,int> id;id.clear();
		group ans;ans.n=0;
		memset(ans.b,0,sizeof(ans.b));
		int num[50];
		for(int i=0;i<n;i++){
			int x=o(i,s,0);
			if(!id.count(x))id[x]=num[i]=ans.n++;
			else num[i]=id[x];
		}
		for(int i=0;i<n;i++)
			for(int j=0;j<n;j++)
				ans.b[num[i]][num[j]]=num[b[i][j]];
		return ans;
	}
}g;
set<int> sg;
void getsg(const group &g,int s){
	if(sg.count(s))return;
	sg.insert(s);
	for(int i=0;i<g.n;i++)
		if(!(s&(1<<i)))getsg(g,g.extend(s,i));
}
int fac[1005],fi[1005];
int fexp(int x,int t){
	if(!t)return 1;
	int tmp=fexp(x,t>>1);tmp=(long long)tmp*tmp%M;
	return (t&1)?(long long)tmp*x%M:tmp;
}
int a[1005],h[1005];
int solve(const group &g){
	sg.clear();
	getsg(g,1<<g.geti());
	vector<int> nml;
	memset(a,0,sizeof(a));
	for(set<int>::iterator it=sg.begin();it!=sg.end();it++){
		//printf("%d\n",*it);
		if(g.normal(*it))nml.push_back(*it);
		a[g.n/count(*it)]++;
	}
	for(int i=1;i<=n;i++){
		h[i]=a[i];
		for(int j=1;j<=g.n && j<i;j++)
			h[i]=(h[i]+(long long)h[i-j]*fi[i-j]%M*a[j])%M;
		h[i]=(long long)h[i]*fac[i-1]%M;
	}
	int ans=h[n];
	for(int i=0;i<nml.size();i++)if(count(nml[i])>1)ans=(ans+M-solve(g/nml[i]))%M;
	return ans;
}
