	}
	fac[0]=fi[0]=1;
	for(int i=1;i<=1000;i++)fac[i]=(long long)fac[i-1]*i%M;
	fi[1000]=fexp(fac[1000],M-2);
	for(int i=1000;i>=1;i--)fi[i-1]=(long long)fi[i]*i%M;
	while(t--){
		scanf("%d%d",&n,&g.n);
		memset(g.b,0,sizeof(g.b));
		for(int i=0;i<g.n;i++)for(int j=0;j<g.n;j++)scanf("%d",&g.b[i][j]),g.b[i][j]--;
		if(!g.check()){
			printf("0\n");
		}else printf("%d\n",solve(g));
	}
	return 0;
}

#include<bits/stdc++.h>
using namespace std;
typedef long long int64;
struct Ttree{
	static const int maxn=100010;
	struct Tedge{
		int son; int64 dis; Tedge *pre;
		void add(int s_,int64 d_,Tedge *p_){ son=s_,dis=d_,pre=p_; }
	}edge[maxn<<1],*pos[maxn];
	int tot;
	void add(int a,int b,int64 c){ edge[++tot].add(b,c,pos[a]),pos[a]=edge+tot; }
	void clear(){ tot=0,memset(pos,0,sizeof(pos)); }
}t;
struct Tunion_find_set{
	static const int maxn=100010;
	int fa[maxn],sz[maxn]; int64 cir[maxn];
	void clear(int n){
		for(int i=1;i<=n;++i)
			fa[i]=i,sz[i]=1,cir[i]=0;
	}
	int find(int x){
		if(fa[x]==x) return x;
		return fa[x]=find(fa[x]);
	}
	void merge(int x,int y){
		int fx=find(x),fy=find(y);
		if(fx==fy) return; fa[fx]=fy;
		sz[fy]+=sz[fx],sz[fx]=0;
		cir[fy]=__gcd(cir[fy],cir[fx]),cir[fx]=0;
	}
	inline void add_circle(int u,int64 w){
		u=find(u),cir[u]=__gcd(cir[u],abs(w));
	}
	inline bool test(int x,int y){ return find(x)==find(y); }
	inline int size(int u){ return sz[find(u)]; }
	inline int64 circle(int u){ return cir[find(u)]; }
}ufs;
const int maxn=100010;
int fa[maxn]; int64 dis[maxn];
int n,m,ans_buff;

void link(int u,int v,int64 w){
	if(ufs.test(u,v))
		return ufs.add_circle(u,dis[u]-dis[v]+w);
	if(ufs.size(u)<ufs.size(v)) swap(u,v),w=-w;
	static int q[maxn]; int top=1;
	q[1]=v,fa[v]=u,dis[v]=dis[u]+w;
	for(int k=1;k<=top;++k)
		for(Ttree::Tedge *i=t.pos[q[k]];i;i=i->pre)
			if(i->son!=fa[q[k]]){
				q[++top]=i->son,fa[i->son]=q[k];
				dis[i->son]=dis[q[k]]+(i->dis);
			}
	t.add(u,v,w),t.add(v,u,-w),ufs.merge(v,u);
}

bool query(int u,int v,int64 w){
	if(!ufs.test(u,v)) return false;
	int64 dist=dis[v]-dis[u],len=ufs.circle(u);
	if(!len) return abs(w)==abs(dist);
	return abs(w-dist)%len==0;
}

