using namespace std;
int cnt1= 200;
int cnt2= 40;

#define eps 1e-10
#define pi 3.14159265358979
typedef double db;

struct pkt{
	db x,y;
}p[111111],c;
db S;
pkt operator -(const pkt&a,const pkt&b){
	return (pkt){a.x-b.x,a.y-b.y};
}
pkt operator +(const pkt&a,const pkt&b){
	return (pkt){a.x+b.x,a.y+b.y};
}
pkt operator*(const pkt&a,db t){
	return (pkt){a.x*t,a.y*t};
}
db det(const pkt&a,const pkt&b){
	return a.x*b.y-a.y*b.x;
}
db dot(const pkt&a,const pkt&b){
	return a.x*b.x+a.y*b.y;
}
int n;
db ro;


#define nex(i) ((i)==(n-1)?0:(i)+1)
#define pre(i) ((i)==(0)?n-1:(i)-1)
db sth,cth;


db getlen(pkt a,pkt b,pkt c,db th){
	a=a-c,b=b-c;
	return fabs(det((pkt){-b.x,a.x-b.x},(pkt){-b.y,a.y-b.y})/
		det((pkt){cth,a.x-b.x},(pkt){-sth,a.y-b.y}));
}
inline db gs(db a,db b,db h){
	return (a+b)*h*0.5;
}
inline db getwork(db a,db b,db h){
	return h*h*(a*0.5+(b-a)/6);
}
db dis[111111];
int ord[111111];
int cmp(int i,int j){
	return dis[i]<dis[j];
}
pkt normal;

db geth(db l2,db l1,db h,db ned){
	db lef=0.0,rig=1.0;
	for (int num=cnt1;num;num--){
		if(rig-lef<1e-12)break;
		db mid=(lef+rig)*0.5;
		db S=gs(l1,l1+mid*(l2-l1),h*mid);
		if(S<ned)lef=mid;
		else rig=mid;
	}
	return lef*h;
}
db f(db th){
	sth=sin(th);
	cth=cos(th);
	normal.x=sth,normal.y=cth;

	for (int i=0;i<n;i++)dis[i]=dot(p[i],normal);
	/*for (int i=0;i<n;i++)ord[i]=i;
	sort(ord,ord+n,cmp);*/
	int mi=0;
	for (int i=1;i<n;i++)if(dis[i]<dis[mi])mi=i;
	 
	db ned=S*ro;
	
	int up=mi,down=mi;
	db cur=0.0;
	db wk=0.0;
	db H;
	while(1){
		int ne=nex(down),pr=pre(up);
		if(dis[ne]>dis[pr]){
			db l1,l2,s,h;
			if(dis[down]>dis[up]){
				l1=getlen(p[pr],p[up],p[down],th);
				l2=getlen(p[down],p[ne],p[pr],th);
				h=dis[pr]-dis[down];
				s=gs(l1,l2,h);
			}else{
				l1=getlen(p[down],p[ne],p[up],th);
				l2=getlen(p[down],p[ne],p[pr],th);
				h=dis[pr]-dis[up];
				s=gs(l1,l2,h);
			}
			if(cur+s<ned){
				wk+=getwork(l1,l2,h)+cur*h;
				cur+=s;
				up=pr;
			}else{
				db hh=geth(l2,l1,h,ned-cur);
				wk+=getwork(l1,l1+(l2-l1)*hh/h,hh)+cur*hh;
				H=hh+max(dis[down],dis[up]);
				break;
			}
		}else{
			db l1,l2,s,h;
			if(dis[up]>dis[down]){
				l1=getlen(p[ne],p[down],p[up],th);
				l2=getlen(p[pr],p[up],p[ne],th);
				h=dis[ne]-dis[up];
				s=gs(l1,l2,h);
			}else{
				l1=getlen(p[up],p[pr],p[down],th);
				l2=getlen(p[up],p[pr],p[ne],th);
				h=dis[ne]-dis[down];
				s=gs(l1,l2,h);
			}
			if(cur+s<ned){
				wk+=getwork(l1,l2,h)+cur*h;
				cur+=s;
				down=ne;
			}else{
				db hh=geth(l2,l1,h,ned-cur);
				wk+=getwork(l1,l1+(l2-l1)*hh/h,hh)+cur*hh;
				H=hh+max(dis[down],dis[up]);
				break;
			}
		}
	}
	return ro*S*(dot(c,normal)-H)+wk;
}
void work(){
