	}
	p[n]=p[0];
	S=0.0;
	pkt sum;sum.x=sum.y=0.0;
	for (int i=0;i<n;i++){
		db ss=det(p[i],p[i+1]);
		ss*=0.5;
		pkt ce=(p[i]+p[i+1])*(1.0/3);
		sum=sum+ce*ss;
		S+=ss;
	}
	c=sum*(1.0/S);

	db an=11111111.0,ang;
	db lef,rig;
	lef=0.0,rig=0.5*pi;
	for (int num=cnt2;num;num--){
		if(rig-lef<eps)break;
		db mid=lef+(rig-lef)*0.33333;
		db mid2=(mid+rig)*0.5;
		db ans=f(mid);
		db ans2=f(mid2);
		if(ans>ans2)lef=mid;
		else rig=mid2;
		if(ans<an){
			an=ans;
			ang=mid;
		}
	}
	lef=1.5*pi,rig=2*pi;
	for (int num=cnt2;num;num--){
		if(rig-lef<eps)break;
		db mid=lef+(rig-lef)*0.33333;
		db mid2=(mid+rig)*0.5;
		db ans=f(mid);
		db ans2=f(mid2);
		if(ans>ans2)lef=mid;
		else rig=mid2;
		if(ans<an){
			an=ans;
			ang=mid;
		}
	}
	lef=0.5*pi,rig=pi;
	for (int num=cnt2;num;num--){
		if(rig-lef<eps)break;
		db mid=lef+(rig-lef)*0.33333;
		db mid2=(mid+rig)*0.5;
		db ans=f(mid);
		db ans2=f(mid2);
		if(ans>ans2)lef=mid;
		else rig=mid2;
		if(ans<an){
			an=ans;
			ang=mid;
		}
	}
	lef=pi,rig=1.5*pi;
	for (int num=cnt2;num;num--){
		if(rig-lef<eps)break;
		db mid=lef+(rig-lef)*0.33333;
		db mid2=(mid+rig)*0.5;
		db ans=f(mid);
		db ans2=f(mid2);
		if(ans>ans2)lef=mid;
		else rig=mid2;
		if(ans<an){
			an=ans;
			ang=mid;
		}
	}
	if(ang>=2*pi-eps)ang=0.0;
	printf("%.14lf\n",double(ang));

}
