            if (i->w) {
                if (num[now - i->w])
                    ans[i->id] = s[now - i->w] / num[now - i->w];
                ans[i->id]++;
            }
            else
                same++;
        for (Edge *i = b[now]; i != NULL; i = i->next)
            if (i->w) {
                s[now] += ans[i->id];
                num[now]++;
            }
        if (same) {
            double x;
            if (num[now] == 0)
                x = oo;
            else
                x = (s[now] + same) / num[now] + 1;
            for (Edge *i = b[now]; i != NULL; i = i->next)
                if (! i->w) {
                    ans[i->id] = x;
