#include <cstdio>
#include <algorithm>
using namespace std;
typedef long long LL;
const int NMax=510000;
const LL INF=1000000000000000LL;
struct pii {
	LL x,y;
};
pii mp(LL x,LL y) {
	pii ret;
	ret.x=x;ret.y=y;
	return ret;
}
pii operator+(pii a,pii b) {
	return mp((a.x>-INF?a.x+b.x:a.x),max(a.y+b.x,b.y));
}
pii max(pii a,pii b) {
	return mp(max(a.x,b.x),max(a.y,b.y));
}
struct node {
	pii tag1,tag2;
}T[NMax*4];
int N,M,A[NMax];
void down(int p) {
	pii tmp=T[p*2].tag1+T[p].tag2;
	T[p*2].tag2=max(tmp,T[p*2].tag2);
	tmp=T[p*2+1].tag1+T[p].tag2;
	T[p*2+1].tag2=max(tmp,T[p*2+1].tag2);
	T[p].tag2=mp(0,0);
	T[p*2].tag1=T[p*2].tag1+T[p].tag1;
	T[p*2+1].tag1=T[p*2+1].tag1+T[p].tag1;
	T[p].tag1=mp(0,0);
}
void change(int x,int y,int z,int a,int b,int p,int t) {
	if(x==a&&b==y) {
		if(t==1) T[p].tag1=T[p].tag1+mp(z,0);
		else if(t==2) T[p].tag1=T[p].tag1+mp(-z,0);
		else T[p].tag1=T[p].tag1+mp(-INF,z);	
		return ;
	}
	down(p);
	int mid=(a+b)>>1;
	if(y<=mid) change(x,y,z,a,mid,p*2,t);
	else if(x>mid) change(x,y,z,mid+1,b,p*2+1,t);
	else {
		change(x,mid,z,a,mid,p*2,t);
		change(mid+1,y,z,mid+1,b,p*2+1,t);
	}
}
LL ask(int x,int a,int b,int p,int t) {
	if(a==b) {
		if(t==4) return max(A[x]+T[p].tag1.x,T[p].tag1.y);
		return max(A[x]+T[p].tag2.x,T[p].tag2.y);
	}
	down(p);
	int mid=(a+b)>>1;
	if(x<=mid) return ask(x,a,mid,p*2,t);
	else return ask(x,mid+1,b,p*2+1,t);
}
int main()
{
	scanf("%d%d",&N,&M);
	for(int i=1;i<=N;i++) scanf("%d",A+i);
	for(int i=1;i<=M;i++) {
		int t,x,y,z;
		scanf("%d",&t);
		if(t==1) {
			scanf("%d%d%d",&x,&y,&z);
			change(x,y,z,1,N,1,1);
		}else if(t==2) {
			scanf("%d%d%d",&x,&y,&z);
			change(x,y,z,1,N,1,2);
		}else if(t==3) {
			scanf("%d%d%d",&x,&y,&z);
			change(x,y,z,1,N,1,3);
		}else if(t==4) {
			scanf("%d",&x);
			printf("%lld\n",ask(x,1,N,1,4));
		}else {
			scanf("%d",&x);
			printf("%lld\n",ask(x,1,N,1,5));
		}
	}
	getchar();getchar();
	return 0;
}

