struct tag
{long long x,y,mx,my;
 void init()
 {	x=y=mx=my=0;
 }
};
struct tag t[2000010];

const long long inf=1e18;
int n,nq;
int a[500010];

void modify(tag &A,tag B)
{tag C;
 C=(tag){max(A.x+B.x,-inf),max(A.y+B.x,B.y),max(A.mx,A.x+B.mx),max(A.my,max(A.y+B.mx,B.my))};
 A=C;
}

void push_down(int p)
{modify(t[p*2],t[p]);
 modify(t[p*2+1],t[p]);
 t[p].init();
}

void change(int p,int l,int r,int x,int y,tag k)
{if(l>y || r<x) return;
 if(l>=x && r<=y)
 {	modify(t[p],k);
 	return;
 }
 push_down(p);
 change(p*2,l,(l+r)/2,x,y,k);
 change(p*2+1,(l+r)/2+1,r,x,y,k);
}

tag query(int p,int l,int r,int x)
{if(l==r) return t[p];
 push_down(p);
 if(x<=(l+r)/2) return query(p*2,l,(l+r)/2,x); else return query(p*2+1,(l+r)/2+1,r,x);
}

