const int inf=1e9;
il int read(){
	char c=getchar();int z=0,f=1;
	while(c!='-'&&(c>'9'||c<'0')) c=getchar();
	if(c=='-') f=-1,c=getchar();
	while(c>='0'&&c<='9') z=(z<<1)+(z<<3)+c-'0',c=getchar();
	return z*f;
}
const int M = 800005;
const int N = 10005;
namespace net{
	struct EDGE{
		int to,nex,caps;
	}e[M];
	int cnt=1,head[N],iter[N];
	il void add(int x,int y,int z){
		e[++cnt].to=y;
		e[cnt].nex=head[x];
		e[cnt].caps=z;
		head[x]=cnt;
		
		e[++cnt].to=x;
		e[cnt].nex=head[y];
		e[cnt].caps=0;
		head[y]=cnt;
	}
	int dis[N];
	il bool bfs(int s,int t){
		memset(dis,0,sizeof(dis));
		queue<int> q;
		q.push(s);
		dis[s]=1;
		while(!q.empty()){
			int x=q.front();q.pop();
			for(re i=head[x];i;i=e[i].nex)
				if(!dis[e[i].to]&&e[i].caps>0){
					dis[e[i].to]=dis[x]+1;
					q.push(e[i].to);
				}
		}
		if(!dis[t]) return 0;
		memcpy(iter,head,sizeof(iter));
		return 1;
	}
	il int dinic(int x,int flow,int t){
		if(x==t) return flow;
		int rest=flow,p;
		for(int &i=iter[x];i;i=e[i].nex)
			if(dis[e[i].to]==dis[x]+1&&e[i].caps>0){
				int p=dinic(e[i].to,min(rest,e[i].caps),t);
				if(p>0){
					rest-=p;
					e[i].caps-=p;
					e[i^1].caps+=p;
				}
				if(!rest) break;
			}
		return flow-rest;
	}
}
using namespace net; 
int n,m;
il int work(int s,int t,int flow){
	int ret=0,p;
	while(flow&&bfs(s,t))
		while(p=dinic(s,flow,t)) 
			ret+=p,flow-=p; 
	return ret;
}
