		add(i+n,read(),inf);
	}
	if(work(s,t,m)<m) {
		cout<<"No";
		return 0;
	}
	int ans=m;
	for(re i=1;i<=n;i++){
		int x=e[id[i]].caps;
		ans-=work(i,s,x);
		e[id[i]].caps=e[id[i]^1].caps=0;
		ans+=work(s,t,x);
