const int inf=2106482215;
// add first, minmax second
int n,m,q,i,j,a[500005];
struct seg
{
	bool sme;
	int mi,mx,smi,smx,hmi,hmx;
}tr[2000005];
seg merge(seg x,seg y)
{
	seg z;z.mi=min(x.mi,y.mi);z.mx=max(x.mx,y.mx);
	z.hmi=min(x.hmi,y.hmi);z.hmx=max(x.hmx,y.hmx);
	z.smi=min(x.mi==z.mi?x.smi:x.mi,y.mi==z.mi?y.smi:y.mi);
	z.smx=max(x.mx==z.mx?x.smx:x.mx,y.mx==z.mx?y.smx:y.mx);
	z.sme=x.sme&&y.sme&&x.mi==y.mi;
	return z;
}
int add[2000005],his[2000005],hxs[2000005],thi[2000005],thx[2000005],nhi[2000005],nhx[2000005];
// add_tag, history_min_tag, history_max_tag, history_min_min, history_max_max, history_max_min, history_min_max,
void pushup(int x)
{
	tr[x]=merge(tr[x+x],tr[x+x+1]);
	thi[x]=nhx[x]=tr[x].mi;thx[x]=nhi[x]=tr[x].mx;
}
void upd(int x,int fa,bool eqi,bool eqx)
{
	if(!tr[x].sme){
		tr[x].hmi=min(tr[x].hmi,!eqi?tr[x].mi+his[fa]:thi[fa]);
	}
	else{
		tr[x].hmi=min(tr[x].hmi,eqi?thi[fa]:eqx?nhi[fa]:tr[x].mi+his[fa]);
	}
	if(!tr[x].sme){
		tr[x].hmx=max(tr[x].hmx,!eqx?tr[x].mx+hxs[fa]:thx[fa]);
	}
	else{
		tr[x].hmx=max(tr[x].hmx,eqx?thx[fa]:eqi?nhx[fa]:tr[x].mx+hxs[fa]);
	}
	if(tr[x].sme&&eqx) thi[x]=min(thi[x],nhi[fa]),nhx[x]=max(nhx[x],thx[fa]);
	else if(eqi) thi[x]=min(thi[x],thi[fa]),nhx[x]=max(nhx[x],nhx[fa]); else thi[x]=min(thi[x],tr[x].mi+his[fa]),nhx[x]=max(nhx[x],tr[x].mi+hxs[fa]);
	if(tr[x].sme&&eqi) thx[x]=max(thx[x],nhx[fa]),nhi[x]=min(nhi[x],thi[fa]);
	else if(eqx) thx[x]=max(thx[x],thx[fa]),nhi[x]=min(nhi[x],nhi[fa]); else thx[x]=max(thx[x],tr[x].mx+hxs[fa]),nhi[x]=min(nhi[x],tr[x].mx+his[fa]);
	his[x]=min(his[x],add[x]+his[fa]);
	hxs[x]=max(hxs[x],add[x]+hxs[fa]);
	add[x]+=add[fa];if(!tr[x].sme) tr[x].smi+=add[fa],tr[x].smx+=add[fa];
	if(eqi) tr[x].mi=tr[fa].mi; else tr[x].mi+=add[fa];
	if(eqx) tr[x].mx=tr[fa].mx; else tr[x].mx+=add[fa];
	if(tr[x].sme&&eqi&&eqx) tr[x].mi=tr[x].mx=tr[fa].mi;
	else if(tr[x].sme&&eqi) tr[x].mx=tr[x].mi;
	else if(tr[x].sme&&eqx) tr[x].mi=tr[x].mx;
	if(!tr[x].sme) tr[x].smi=min(tr[x].smi,tr[x].mx),tr[x].smx=max(tr[x].smx,tr[x].mi);
}
void pushdo(int x)
{
	upd(x+x,x,add[x]+tr[x+x].mi<tr[x].smi,add[x]+tr[x+x].mx>tr[x].smx);
	upd(x+x+1,x,add[x]+tr[x+x+1].mi<tr[x].smi,add[x]+tr[x+x+1].mx>tr[x].smx);
	add[x]=0;his[x]=hxs[x]=0;thi[x]=tr[x].mi;thx[x]=tr[x].mx;
}
void upd_add(int x,int c)
{
	add[x]+=c;his[x]=min(his[x],add[x]);hxs[x]=max(hxs[x],add[x]);
	tr[x].mi+=c;tr[x].mx+=c;if(!tr[x].sme) tr[x].smi+=c,tr[x].smx+=c;
	tr[x].hmi=min(tr[x].hmi,tr[x].mi);tr[x].hmx=max(tr[x].hmx,tr[x].mx);
	thi[x]=min(thi[x],tr[x].mi);thx[x]=max(thx[x],tr[x].mx);
	nhx[x]=max(nhx[x],tr[x].mi);nhi[x]=min(nhi[x],tr[x].mx);
}
void upd_max(int x,int c)
{
	assert(c>tr[x].mi);
	if(tr[x].sme){
		tr[x].mi=tr[x].mx=c;
		thx[x]=max(thx[x],tr[x].mx);nhx[x]=max(nhx[x],tr[x].mi);
		tr[x].hmx=max(tr[x].hmx,tr[x].mx);
		return;
	}
	assert(c<tr[x].smi);tr[x].mi=c;tr[x].smx=max(tr[x].smx,c);
}
void upd_min(int x,int c)
{
	assert(c<tr[x].mx);
	if(tr[x].sme){
		tr[x].mi=tr[x].mx=c;
		thi[x]=min(thi[x],tr[x].mi);nhi[x]=min(nhi[x],tr[x].mx);
		tr[x].hmi=min(tr[x].hmi,tr[x].mi);
		return;
	}
	assert(c>tr[x].smx);tr[x].mx=c;tr[x].smi=min(tr[x].smi,c);
}
void build(int x,int l,int r)
{
	if(l==r){tr[x]=(seg){1,a[l],a[l],inf,-inf,a[l],a[l]};thi[x]=thx[x]=nhi[x]=nhx[x]=a[l];return;}
	int mid=(l+r)/2;build(x+x,l,mid);build(x+x+1,mid+1,r);pushup(x);
}
void update_add(int x,int l,int r,int ql,int qr,int c)
{
	if(ql<=l&&r<=qr){upd_add(x,c);return;}
	int mid=(l+r)/2;pushdo(x);
	if(ql<=mid) update_add(x+x,l,mid,ql,qr,c);
	if(qr>mid) update_add(x+x+1,mid+1,r,ql,qr,c);
	pushup(x);
}
void update_max(int x,int l,int r,int ql,int qr,int c)
{
	if(tr[x].mi>=c) return;
	if(ql<=l&&r<=qr&&tr[x].smi>c){upd_max(x,c);return;}
	int mid=(l+r)/2;pushdo(x);
	if(ql<=mid) update_max(x+x,l,mid,ql,qr,c);
	if(qr>mid) update_max(x+x+1,mid+1,r,ql,qr,c);
	pushup(x);
}
void update_min(int x,int l,int r,int ql,int qr,int c)
{
	if(tr[x].mx<=c) return;
	if(ql<=l&&r<=qr&&tr[x].smx<c){upd_min(x,c);return;}
	int mid=(l+r)/2;pushdo(x);
	if(ql<=mid) update_min(x+x,l,mid,ql,qr,c);
	if(qr>mid) update_min(x+x+1,mid+1,r,ql,qr,c);
	pushup(x);
}
int query_min(int x,int l,int r,int ql,int qr)
{
	if(ql<=l&&r<=qr) return tr[x].mi;
	int mid=(l+r)/2,res=inf;pushdo(x);
	if(ql<=mid) res=min(res,query_min(x+x,l,mid,ql,qr));
	if(qr>mid) res=min(res,query_min(x+x+1,mid+1,r,ql,qr));
	return res;
}
int query_hmin(int x,int l,int r,int ql,int qr)
{
	if(ql<=l&&r<=qr) return tr[x].hmi;
	int mid=(l+r)/2,res=inf;pushdo(x);
	if(ql<=mid) res=min(res,query_hmin(x+x,l,mid,ql,qr));
	if(qr>mid) res=min(res,query_hmin(x+x+1,mid+1,r,ql,qr));
	return res;
}
int query_hmax(int x,int l,int r,int ql,int qr)
{
	if(ql<=l&&r<=qr) return tr[x].hmx;
	int mid=(l+r)/2,res=-inf;pushdo(x);
	if(ql<=mid) res=max(res,query_hmax(x+x,l,mid,ql,qr));
	if(qr>mid) res=max(res,query_hmax(x+x+1,mid+1,r,ql,qr));
	return res;
}
int main()
{
	read(n);read(m);fz1(i,n) read(a[i]);
	build(1,1,n);
	while(m--){
		int op,l,r;read(op);read(l);read(r);
		if(op==1){int c;read(c);update_add(1,1,n,l,r,c);}
		if(op==2){int c;read(c);update_max(1,1,n,l,r,c);}
		if(op==3)printf("%d\n",query_min(1,1,n,l,r));
		if(op==4)printf("%d\n",query_hmin(1,1,n,l,r));
		if(op==5){int c;read(c);update_min(1,1,n,l,r,c);}
		if(op==6)printf("%d\n",query_hmax(1,1,n,l,r));
	}
	return 0;
}

