namespace Check
{
    const int _W=_N*_M;
    
    int Fir[_N],numE,ed[_W],Next[_W];
    int matchL[_N],matchR[_M],ans;
    int floorL[_N],floorR[_M];
    int Time[_M],TimeNow;
    
    inline void AddE(int x,int y)
    {
        ed[++numE]=y,Next[numE]=Fir[x],Fir[x]=numE;
        if(!matchL[x]&&!matchR[y])
            matchL[x]=y,matchR[y]=x,++ans;
    }
    
    inline bool Judge(int u)
    {
        for(int e=Fir[u];e;e=Next[e])
        {
            int v=ed[e];
            if(Time[v]^TimeNow&&floorR[v]==floorL[u]+1)
            {
                Time[v]=TimeNow;
                if(!matchR[v]||Judge(matchR[v]))
                {
                    matchL[u]=v,matchR[v]=u;
                    return true;
                }
            }
        }
        return false;
    }
    
    inline int KM()
    {
        while(true)
        {
            static int QAQ[_N],L,R;
            L=R=0;
            for(int i=1;i<=n;i++)
                if(!matchL[i])
                    QAQ[++R]=i;
            static int Save;
            static bool Able;
            Save=R,Able=false;
            memset(floorL,0,(n+1)*sizeof(int));
            memset(floorR,0,(m+1)*sizeof(int));
            while(L^R)
            {
                static int u;
                u=QAQ[++L];
                for(int e=Fir[u];e;e=Next[e])
                {
                    static int v;
                    v=ed[e];
                    if(!floorR[v])
                    {
                        floorR[v]=floorL[u]+1;
                        if(matchR[v])
                            floorL[matchR[v]]=floorR[v]+1,QAQ[++R]=matchR[v];
                        else
                            Able=true;
                    }
                }
            }
            if(!Able)
                return ans;
            ++TimeNow;
            for(int i=1;i<=Save;i++)
                if(Judge(QAQ[i]))
                    ++ans;
        }
    }
    
    inline void Init()
    {
        ans=0,numE=0;
        memset(Fir,0,(n+1)*sizeof(int));
        memset(matchL,0,(n+1)*sizeof(int));
        memset(matchR,0,(m+1)*sizeof(int));
    }
    
    bool main()
    {
        if(KM()!=n)
            return false;
        myInOut.write(m,'\n');
        for(int i=1;i<=n;i++)
            myInOut.write(matchL[i],i^n?' ':'\n');
        return true;
    }
}

