    for(int Case=1;Case<=T;Case++)
    {
        static int numT,x,y;
        myInOut.read(n),myInOut.read(m),myInOut.read(numT);
        if(numT==n*m)
        {
            Special::main();
            continue;
        }
        Check::Init();
        numE=0,numP=n+m*3;
        memset(Fir,0,(numP+1)*sizeof(int));
        for(int i=1;i<=m;i++)
            AddE(n+(i-1)*3+1,n+(i-1)*3+2);
        for(int i=1;i<=numT;i++)
        {
            myInOut.read(x),myInOut.read(y),Check::AddE(x,y);
            AddE(x,n+(y-1)*3+1),AddE(x,n+(y-1)*3+2),AddE(x,n+y*3);
        }
        if(Check::main())
            continue;
        Solve::main();
    }
    myInOut.end();
    return 0;
}
