		while(ch = getc(), 'a' <= ch && ch <= 'z')
			*s++ = ch;
		*s = 0;
	}
	
	const int MaxN = 610;
	const int mod = 46337;
	
	namespace Match
	{
		int E[MaxN][MaxN << 1], G[MaxN][MaxN], list[MaxN], M;
		int pos[MaxN << 1];
		
		inline int inv(RG int i) {return i < 0 ? inv(i + mod) : i == 1 ? i : mod - (mod / i) * inv(mod % i) % mod;}
		
		IL void gauss(RG int N, RG bool type)
		{
			RG int L = N << type;
			if(type) For(i, 1, N) 
			{
				memset(E[i] + N + 1, 0, N << 2);
				E[i][N + i] = 1;
			}
			For(i, 1, N)
			{
				RG int *Ei = E[i];
				if(!Ei[i])
				{
					RG int p = i + 1;
					while(p <= N && !E[p][i]) ++p;
					if(p > N) continue;
					RG int *Ep = E[p], T;
					For(j, i, L) T = Ei[j], Ei[j] = Ep[j], Ep[j] = T;
				}
				if(!type) list[++M] = i;
				RG int T = inv((Ei[i] + mod) % mod), Pos = 0;
				For(j, i, L) if(Ei[j])
				{
					(Ei[j] *= T) %= mod;
					pos[Pos++] = j;
				}
				For(p, i + 1, N) if(E[p][i])
				{
					RG int *Ep = E[p], T = Ep[i], j = 0;
					for(; j + 8 <= Pos; j += 8)
					{
						(Ep[pos[j]] -= Ei[pos[j]] * T) %= mod;
						(Ep[pos[j + 1]] -= Ei[pos[j + 1]] * T) %= mod;
						(Ep[pos[j + 2]] -= Ei[pos[j + 2]] * T) %= mod;
						(Ep[pos[j + 3]] -= Ei[pos[j + 3]] * T) %= mod;
						(Ep[pos[j + 4]] -= Ei[pos[j + 4]] * T) %= mod;
						(Ep[pos[j + 5]] -= Ei[pos[j + 5]] * T) %= mod;
						(Ep[pos[j + 6]] -= Ei[pos[j + 6]] * T) %= mod;
						(Ep[pos[j + 7]] -= Ei[pos[j + 7]] * T) %= mod;
					}
					for(; j != Pos; ++j)
						(Ep[pos[j]] -= Ei[pos[j]] * T) %= mod;
				}
			}
			if(type) Dor(i, 1, N) 
			{
				RG int *Ei = E[i], Pos = 0;
				For(j, i, L) if(Ei[j]) pos[Pos++] = j;
				Rep(p, 1, i) if(E[p][i])
				{
					RG int *Ep = E[p], T = Ep[i], j = 0;
					for(; j + 8 <= Pos; j += 8)
					{
						(Ep[pos[j]] -= Ei[pos[j]] * T) %= mod;
						(Ep[pos[j + 1]] -= Ei[pos[j + 1]] * T) %= mod;
						(Ep[pos[j + 2]] -= Ei[pos[j + 2]] * T) %= mod;
						(Ep[pos[j + 3]] -= Ei[pos[j + 3]] * T) %= mod;
						(Ep[pos[j + 4]] -= Ei[pos[j + 4]] * T) %= mod;
						(Ep[pos[j + 5]] -= Ei[pos[j + 5]] * T) %= mod;
						(Ep[pos[j + 6]] -= Ei[pos[j + 6]] * T) %= mod;
						(Ep[pos[j + 7]] -= Ei[pos[j + 7]] * T) %= mod;
					}
					for(; j != Pos; ++j)
						(Ep[pos[j]] -= Ei[pos[j]] * T) %= mod;
				}
			}
		}
		
		IL void remove(RG int a, RG int b)
		{
			RG int *Ga = G[a], T = inv(Ga[b]), Pos = 0;
			For(i, dmin(a, b), M) if(Ga[i])
			{
				(Ga[i] *= T) %= mod;
				pos[Pos++] = i;
			}
			For(p, dmin(a, b), M) if(p != a && G[p][b])
			{
				RG int *Gp = G[p], j = 0; T = G[p][b];
				#define Ep Gp
				#define Ei Ga
				for(; j + 8 <= Pos; j += 8)
				{
					(Ep[pos[j]] -= Ei[pos[j]] * T) %= mod;
					(Ep[pos[j + 1]] -= Ei[pos[j + 1]] * T) %= mod;
					(Ep[pos[j + 2]] -= Ei[pos[j + 2]] * T) %= mod;
					(Ep[pos[j + 3]] -= Ei[pos[j + 3]] * T) %= mod;
					(Ep[pos[j + 4]] -= Ei[pos[j + 4]] * T) %= mod;
					(Ep[pos[j + 5]] -= Ei[pos[j + 5]] * T) %= mod;
					(Ep[pos[j + 6]] -= Ei[pos[j + 6]] * T) %= mod;
					(Ep[pos[j + 7]] -= Ei[pos[j + 7]] * T) %= mod;
				}
				for(; j != Pos; ++j)
					(Ep[pos[j]] -= Ei[pos[j]] * T) %= mod;
				#undef Ep
				#undef Ei
			}
		}
		
		IL int solve(RG const int N, RG const bool e[MaxN][MaxN], RG int pair[MaxN])
		{
			RG int V;
			For(i, 1, N) memset(E[i] + 1, 0, N << 2);
			For(i, 1, N) For(j, i, N) if(e[i][j]) 
			{
				V = rand() % (mod - 1) + 1;
				E[i][j] = V;
				E[j][i] = mod - V;
			}
			For(i, 1, N) memcpy(G[i] + 1, E[i] + 1, N << 2);
			M = 0;
			gauss(N, 0);
			For(i, 1, M) 
			{
				RG int *Ei = E[i], *Glisti = G[list[i]];
				For(j, 1, M) Ei[j] = Glisti[list[j]];
			}
			gauss(M, 1);
			For(i, 1, M) memcpy(G[i] + 1, E[i] + M + 1, M << 2);
			memset(pair + 1, 0, N << 2);
			For(i, 1, M) if(!pair[list[i]])
			{
				RG int k = i + 1;
				RG const bool *elisti = e[list[i]];
				while(!elisti[list[k]] || !G[k][i]) ++k;
				pair[pair[list[i]] = list[k]] = list[i];
				remove(i, k);
				remove(k, i);
				memset(G[k] + i, 0, (M - i + 1) << 2);
			}
			return M >> 1;
		}
	}
	
	bool e[MaxN][MaxN];
	int p0[MaxN], p1[MaxN][3], bel[MaxN], pair[MaxN];
	IL void link(RG int a, RG int b) {e[a][b] = e[b][a] = 1;}
	
	IL void main()
	{
		srand(2341);
		RG int (*F)() = read<int>;
		For(__, 1, F())
		{
			RG int N = F(), M = F(), E = F();
			if(E == N * M)
			{
				static int cnt[MaxN];
				memset(cnt + 1, 0, M << 2);
				while(E--) F(), F();
				For(i, 1, N) 
				{
					For(j, 1, M) if(cnt[j] == 0) {++cnt[pair[i] = j]; goto next_step;}
					For(j, 1, M) if(cnt[j] == 2) {++cnt[pair[i] = j]; goto next_step;}
					For(j, 1, M) if(cnt[j] == 1) {++cnt[pair[i] = j]; goto next_step;}
					next_step:  continue;
				}
				RG int ans = 0;
				For(i, 1, M) ans += (cnt[i] <= 1);
				print(ans);
				For(i, 1, N) print(pair[i], " \n"[i == N]);
				continue;
			}
			RG int P = 0;
			For(i, 1, N) p0[i] = ++P;
			For(i, 1, M) Rep(k, 0, 3) bel[p1[i][k] = ++P] = i;
			For(i, 1, P) memset(e[i] + 1, 0, P);
			For(i, 1, M) link(p1[i][0], p1[i][1]);
			RG int x, y;
			while(E--)
			{
				x = F(), y = F();
				link(p0[x], p1[y][0]);
				link(p0[x], p1[y][1]);
				link(p0[x], p1[y][2]);
			}
			RG int ans = Match::solve(P, e, pair);
			print(ans - N); 
			For(i, 1, N) print(bel[pair[p0[i]]], " \n"[i == N]);
		}
		io::flush();
	}
}

