namespace flow {
int head[700], nxt[1000000], len[1000000], to[1000000], cnt = -1;
int cur[1000000];
void add(int a, int b, int l, bool _rev = false) {
  nxt[++cnt] = head[a];
  to[cnt] = b;
  len[cnt] = l;
  head[a] = cnt;
  if (!_rev) add(b, a, 0, true);
}
int lev[700];
bool bfs(int s, int t) {
  for (int i = s; i <= t; i++) {
    lev[i] = inf;
    cur[i] = head[i];
  }
  lev[s] = 0;
  queue<int> q;
  q.push(s);
  bool flag = 0;
  while (!q.empty()) {
    int now = q.front();
    q.pop();
    if (now == t) flag = 1;
    for (int i = head[now]; i != -1; i = nxt[i]) {
      if (lev[to[i]] == inf && len[i]) {
        lev[to[i]] = lev[now] + 1;
        q.push(to[i]);
      }
    }
  }
  return flag;
}
int s, t;
int dfs(int now, int flow) {
  if (now == t) return flow;
  int use = 0;
  for (int i = cur[now]; i != -1 && flow; i = nxt[i]) {
    cur[now] = i;
    if (lev[to[i]] == lev[now] + 1 && len[i]) {
      int val = dfs(to[i], min(flow, len[i]));
      if (!val) lev[to[i]] = inf;
      flow -= val;
      use += val;
      len[i] -= val;
      len[i ^ 1] += val;
    }
  }
  return use;
}
void init() {
  cnt = -1;
  memset(head, -1, sizeof(head));
}
void solve(int mx) {
  s = 0;
  t = mx + 1;
  int ans = 0;
  while (bfs(s, t)) {
    ans += dfs(s, inf);
  }
}
int get(int x) {
  for (int i = head[x]; i != -1; i = nxt[i]) {
    if (to[i] == s) continue;
    if (!len[i]) return to[i];
  }
  return 0;
}
