#define ll long long
#define inf 999999999999999999ll
#define N 500010
using namespace std;
int T,n,mo,tot,ring[N*2],ri[N],q[N],g[N];
ll w,ans,f[N],s[N],v[N];char str[N];

int gcd(int a,int b)
{
  if(!b)return a;
  return gcd(b,a%b);
}

void change(int x)
{
  int D=gcd(x,mo);
  memset(s,127,sizeof(f));
  for(int i=0;i<mo;i++)s[f[i]%x]=min(s[f[i]%x],f[i]);
  for(int i=0;i<x;i++)f[i]=s[i];
  for(int k=0;k<D;k++)
  {
    int cnt=0,pos=k;
    while(1)
    {
      ring[++cnt]=pos;pos=(pos+mo)%x;
	  if(pos==k)break;
    }
    for(int i=1;i<=cnt;i++)ring[cnt+i]=ring[i];
    for(int i=2;i<=cnt*2;i++)
      f[ring[i]]=min(f[ring[i]],f[ring[i-1]]+mo);
  }
  mo=x;
}

void solve(int x,int y,int len)
{
  change(x);
  int D=gcd(x,y);
  for(int k=0;k<D;k++)
  {
    int cnt=0,pos=k,po,tmp=0;ll minn=inf;
    while(1)
    {
      ring[++cnt]=pos;pos=(pos+y)%x;
	  if(pos==k)break;
    }
    for(int i=1;i<=cnt;i++)
      if(f[ring[i]]<minn)minn=f[ring[i]],po=i;
    for(int i=po;i<=cnt;i++)ri[++tmp]=ring[i];
    for(int i=1;i<po;i++)ri[++tmp]=ring[i];
    int l=1,r=1;q[1]=1;v[1]=f[ri[1]]-y;
	for(int i=2;i<=cnt;i++)
    {
      while(q[l]+len<=i&&l<=r)l++;
	  if(l<=r)f[ri[i]]=min(f[ri[i]],v[l]+(ll)y*i+x);
	  while(v[r]>f[ri[i]]-(ll)y*i&&l<=r)r--;
	  q[++r]=i;v[r]=f[ri[i]]-(ll)y*i;
	}
  }
}

int main()
{
  scanf("%d",&T);
  while(T--)
  {
    scanf("%d%lld %s",&n,&w,str+1);w-=n;
    if(w<0){printf("0\n");continue;}
	memset(f,0,sizeof(f));
	tot=0;mo=n;ans=0;f[0]=-1;f[1]=0;
    for(int i=2,j=0;i<=n;i++)
    {
      while(j>=0&&str[i]!=str[j+1])j=f[j];
      f[i]=++j;
    }
    for(int i=f[n];i;i=f[i])g[++tot]=n-i;
    reverse(g+1,g+tot+1);
    memset(f,127,sizeof(f));f[0]=0;
    for(int i=1,j=2;i<=tot;i=j+1)
    {
      if(i==tot){solve(g[i],0,1);break;}
	  for(j=i;g[j+1]-g[j]==g[i+1]-g[i]&&j<tot;j++);
	  solve(g[j],g[i]-g[i+1],j-i+1);
	}
	for(int i=0;i<mo;i++)
	  if(f[i]<=w)ans+=(w-f[i])/mo+1;
	printf("%lld\n",ans);
  }
  return 0;
}

