#define repu(i,x,y) for (int i=x; i<=y; ++i)
using namespace std;

typedef long long LL;
int n,m,nxt[500100],tot,b[500100],q[500100],head,tail,id[500100];
LL w,dis[500100],ans;
bool flag[500100];
char str[500100];

void kmp()
{
    for (int i=2,j=0; i<=n; ++i)
    {
        for (; j && str[i]!=str[j+1]; j=nxt[j]);
        nxt[i]=str[i]==str[j+1]?++j:0;
    }
    for (int i=nxt[n]; i; i=nxt[i])
        b[++tot]=n-i;
}

void update(int x,int d,int cnt)
{
    static LL t[500100];
    memcpy(t,dis,sizeof(t));
    memset(dis,80,sizeof(dis));
    repu(i,0,m-1)
        dis[t[i]%x]=min(dis[t[i]%x],t[i]);
    memset(flag,0,sizeof(flag));
    repu(i,0,x-1)
        if (!flag[i])
        {
            int fst=i;
            for (int j=i; !flag[j]; flag[j]=1,j=(j+m)%x)
                if (dis[fst]>dis[j])
                    fst=j;
            for (int j=(fst+m)%x; j!=fst; j=(j+m)%x)
                dis[j]=min(dis[j],dis[(j+x-m%x)%x]+m);
        }
    memset(flag,0,sizeof(flag)),m=x;
    if (!cnt)
        return;
    repu(i,0,x-1)
        if (!flag[i])
        {
            int fst=i,tot=0;
            for (int j=i; !flag[j]; flag[j]=1,j=(j+d)%m)
                if (dis[fst]>dis[j])
                    fst=j;
            id[q[head=tail=0]=fst]=0;
            for (int j=(fst+d)%m; j!=fst; j=(j+d)%m)
            {
                for (id[j]=++tot; id[q[head]]+cnt<tot; ++head);
                dis[j]=min(dis[j],dis[q[head]]+x+d*(tot-id[q[head]]));
                for (; head<=tail && dis[q[tail]]+(tot-id[q[tail]])*d>dis[j]; --tail);
                q[++tail]=j;
            }
        }
}

void solve()
{
    scanf("%d%lld%s",&n,&w,str+1),tot=0,kmp();
    memset(dis,80,sizeof(dis)),dis[0]=m=n,ans=0;
    for (int i=1,j,d; i<=tot; i=j+1)
    {
        for (j=i,d=b[i+1]-b[i]; j<tot && b[j+1]-b[j]==d; ++j);
        update(b[i],d,j-i);
    }
    repu(i,0,m-1)
        if (w>=dis[i])
            ans+=(w-dis[i])/m+1;
    printf("%lld\n",ans);
}

