// EOT

const int MAXN = 5e5 + 5;
const int SIZE = 1e3 + 5;
const LL OO = 0x3f3f3f3f3f3f3f3f;

struct Atom {
    int x, y, z;                // {x + ky | k in [0, z)}
    Atom() { }
    Atom(int x_, int y_, int z_): x(x_), y(y_), z(z_) { }
};

int N;
LL W;
char S[MAXN];

void input()
{
    read(N); read(W);
    scanf("%s", S);
}

int gcd(int a, int b)
{
    return b ? gcd(b, a % b) : a;
}

void solve()
{
    if (W < N) {
        puts("0");
        return;
    }
    W -= N;

    static int fail[MAXN];

    fail[0] = fail[1] = 0;
    for (int i = 1; i < N; ++i) {
        int p = fail[i];
        while (p && S[p] != S[i]) p = fail[p];
        fail[i + 1] = p + (S[p] == S[i]);
    }

    vector<Atom> trans;

    for (int p = N, d = 0; fail[p]; p = fail[p]) {
        int p0 = fail[p];
        if (p - d != p0) {
            if (p0 * 2 <= p) {
                d = 0;
                trans.push_back(Atom(N - p0, 0, 1));
            } else {
                d = p - p0;
                trans.push_back(Atom(N - p0, p - p0, p / (p - p0)));
            }
        }
    }
    std::reverse(ALL(trans));

    // trans.clear();
    // trans.push_back(Atom(9, 4, 3));

    static LL dis[MAXN];
    int n = N;

    memset(dis, 0x3f, sizeof(dis));
    dis[0] = 0;
    for (int i = 0; i < SZ(trans); ++i) {
        static LL dis0[MAXN];
        int x = trans[i].x, y = trans[i].y, z = trans[i].z;

        memcpy(dis0, dis, sizeof(dis0));
        memset(dis, 0x3f, sizeof(dis));
        for (int j = 0; j < n; ++j) {
            chkmin(dis[dis0[j] % x], dis0[j]);
        }
        for (int j = 0, d = gcd(n, x), m = x / d; j < d; ++j) {
            LL min = +OO;
            for (LL k = 0; k < m * 2; ++k) {
                chkmin(min += n, dis[(j + k * n) % x]);
                chkmin(dis[(j + k * n) % x], min);
            }
        }
        // printf("before round x=%d, n=%d\n", x, n);
        // for (int j = 0; j < x; ++j) {
        //     printf("dis(%d)=%lld\n", j, dis[j]);
        // }

        if (z != 1) {
            for (int j = 0, d = gcd(y, x), m = x / d; j < d; ++j) {
                LL minp = 0;
                for (LL k = 1; k < m; ++k) {
                    if (dis[(j + k * y) % x] < dis[(j + minp * y) % x])
                        minp = k;
                }

                static pair<LL, LL> q[MAXN];
                int front = 0, rear = 0;

                for (LL k = minp; k < minp + m; ++k) {
                    while (front < rear && k - q[front].y >= z) ++front;
                    if (front < rear)
                        chkmin(dis[(j + k * y) % x], q[front].x + k * y + x);
                    pair<LL, LL> cur = MP(dis[(j + k * y) % x] - k * y, k);
                    while (front < rear && q[rear - 1] > cur) --rear;
                    q[rear++] = cur;
                }
            }
        }

        // printf("after round n=x=%d\n", x);
        // for (int j = 0; j < x; ++j) {
        //     printf("dis(%d)=%lld\n", j, dis[j]);
        // }
        // puts("");

        n = x;
    }

    LL ans = 0;
    // printf("finally, n=%d\n", n);
    for (int i = 0; i < n; ++i) {
        // printf("dis(%d)=%lld\n", i, dis[i]);
        if (dis[i] <= W) {
            assert(dis[i] % n == i);
            ans += (W - dis[i]) / n + 1;
        }
    }

    printf("%lld\n", ans);
}

