void bemin(ll &x,ll v){if (x>v) x=v;}
typedef pair<int,ll> pii;
#define lc x<<1
#define rc x<<1|1
void init(int x,int l,int r){
    tag[x]=2e18;
    if (l==r){Min[x]=dis[q[l]];Mv[x]=val[q[l]];return;}
    int mid=(l+r)>>1;
    init(lc,l,mid);init(rc,mid+1,r);
    Min[x]=min(Min[lc],Min[rc]);
    Mv[x]=min(Mv[lc],Mv[rc]);
}
void Bemin(int x,ll v){
    bemin(tag[x],v);
    bemin(Min[x],Mv[x]+v);
}
void down(int x){
    if (tag[x]<2e18) Bemin(lc,tag[x]),Bemin(rc,tag[x]),tag[x]=2e18;
}
void cg(int x,int l,int r,int L,int R,ll v){
    if (l>=L&&r<=R) return Bemin(x,v);
    down(x);
    int mid=(l+r)>>1;
    if (L<=mid) cg(lc,l,mid,L,R,v);
    if (R>mid) cg(rc,mid+1,r,L,R,v);
    Min[x]=min(Min[lc],Min[rc]);
}
pii mp(int x,int l,int r){
    if (l==r){
        ll ret=Min[x];
        Min[x]=Mv[x]=2e18;
        for (x>>=1;x;x>>=1){
            Min[x]=min(Min[lc],Min[rc]);
            Mv[x]=min(Mv[lc],Mv[rc]);
        }
        return pii(l,ret);
    }
    down(x);
    int mid=(l+r)>>1;
    return Min[x]==Min[lc]?mp(lc,l,mid):mp(rc,mid+1,r);
}
void update(int d,int st,int len){
    static int vis[N],id[N],C;C++;
    int q_size=0,T=n/__gcd(n,d);
    len=min(len,T);
    for (int i=0;i<n;i++){
        ll V=0;
        for (int j=i;vis[j]!=C;j=(j+d)%n,V+=d){
            vis[q[q_size]=j]=C;
            id[j]=q_size;
            val[j]=V;
            q_size++;
        }
    }
    for (int i=0;i<n;i++) vis[i]=0;
    init(1,0,n-1);
    while (1){
        pii sit=mp(1,0,n-1);
        if (sit.second>1e18) return;
        int v=q[sit.first];
        if (vis[v]==C) continue;vis[v]=C;
        dis[v]=sit.second;
        int l=id[(v+st)%n],r=l+len-1;
        ll up=sit.second+st-val[q[l]];
        if (r/T==l/T) cg(1,0,n-1,l,r,up);
        else{
            int s=l/T*T;
            cg(1,0,n-1,l,s+T-1,up);
            cg(1,0,n-1,s,r-T,up+1ll*T*d);
        }
    }
}
void solve(){
    scanf("%d%lld%s",&n,&lim,s+1);
    if (lim<n) return (void)puts("0");
    lim-=n;
    for (int i=2;i<=n;i++){
        int j=nxt[i-1];
        while (j&&s[j+1]!=s[i]) j=nxt[j];
        nxt[i]=j+(s[j+1]==s[i]);
    }
    m=0;
    for (int i=n;i;i=nxt[i]) len[++m]=n-nxt[i];
    if (m==1) return (void)printf("%lld\n",lim/n+1);
    n=len[1];
    for (int i=0;i<n;i++) dis[i]=2e18;
    dis[0]=0;len[m+1]=1e9;
    for (int r=2,l=1;r<=m;r++)
    if (len[r-1]+len[r+1]!=len[r]+len[r])
        update(len[r]-len[r-1],len[l],r-l+1),l=r+1;
    ll ans=0;
    for (int i=0;i<n;i++) ans+=max(lim-dis[i]+n,0ll)/n;
    printf("%lld\n",ans);
}
int main()
{
    scanf("%d",&T);
    while (T--) solve();
    return 0;
}

