			if(f[i]<f[mn]) mn=i;
		int x=(mn+m)%a,lst=mn;
		for(;x!=mn;x=(x+m)%a)
			f[x]=min(f[x],f[lst]+m),lst=x;
	}
	m=a;
	for(int st=0,u=__gcd(d,a);st<u;st++)
	{
		int mn=st;
		for(int i=(st+d)%a;i!=st;i=(i+d)%a)
