			if(h<=t) p=S[h],f[x]=min(f[x],f[pos[p]]+a+(id-p)*d);
			while(h<=t&&f[pos[S[t]]]-S[t]*d>=f[x]-id*d) t--;
			S[++t]=id;
		}
	}
