	}
	for(int i=2;i<=k;i<<=1)
		for(int j=0;j<k;j+=i)
			for(int l=0;l<i>>1;l++){
				int y=j+l+(i>>1);
				int t=(long long)x[y]*w[v][(K/i)*l]%M;
