		for(int i=n+1;i<m;i++)r[i]=0;
		return;
	}
	int k;for(k=1;k<=(n-m+1<<1);k<<=1);
	int ik=fexp(k,M-2);
	for(int i=0;i<=m && i<=n-m;i++)d[i]=b[m-i];
	for(int i=m+1;i<k;i++)d[i]=0;
	getinv(d,ib,n-m+2);
	for(int i=n-m+2;i<k;i++)ib[i]=0;
	for(int i=0;i<=n-m;i++)d[i]=a[n-i];
	for(int i=n-m+1;i<=m;i++)d[i]=0;
	fft(ib,k,0);fft(d,k,0);
	for(int i=0;i<k;i++)d[i]=(long long)d[i]*ib[i]%M;
	fft(d,k,1);
	for(int i=0;i<=n-m;i++)d[i]=(long long)d[i]*ik%M;
	for(k=1;k<=(n<<1);k<<=1);
	ik=fexp(k,M-2);
	for(int i=n-m+1;i<k;i++)d[i]=0;
	reverse(d,d+(n-m)+1);
	for(int i=0;i<=m;i++)ib[i]=b[i];for(int i=m+1;i<k;i++)ib[i]=0;
	fft(d,k,0);fft(ib,k,0);
	for(int i=0;i<k;i++)d[i]=(long long)d[i]*ib[i]%M;
	fft(d,k,1);
