void getpol(int x[],int l,int r,int d){
	if(r==l+1){pol[d][l]=x[l];return;}
	int mid=(l+r)>>1;
	getpol(x,l,mid,d+1);getpol(x,mid,r,d+1);
	int k=1;for(;k<=(r-l+1);k<<=1);
	int ik=fexp(k,M-2);
	for(int i=l;i<mid;i++)t1[i-l]=pol[d+1][i];t1[mid-l]=1;for(int i=mid-l+1;i<k;i++)t1[i]=0;
	for(int i=mid;i<r;i++)t2[i-mid]=pol[d+1][i];t2[r-mid]=1;for(int i=r-mid+1;i<k;i++)t2[i]=0;
	fft(t1,k,0);fft(t2,k,0);
	for(int i=0;i<k;i++)t1[i]=(long long)t1[i]*t2[i]%M;
	fft(t1,k,1);for(int i=0;i<k;i++)t1[i]=(long long)t1[i]*ik%M;
	for(int i=l;i<r;i++)pol[d][i]=t1[i-l];
}
