void Dijkstra(int sx,int sy,int x1,int y1,int x2,int y2,int w) {
	rep(x,x1,x2+1) rep(y,y1,y2+1) {
		if (w==-1) dis[x*m+y]=1<<29; else dis[x*m+y]+=w;
		vis[x*m+y]=0;
	}
	int id=sx*m+sy; dis[id]=0; vis[id]=1;
	q.push(id);
	while (!q.empty()) {
		int id=q.front(); q.pop();
		int x=id/m,y=id%m,d=dis[id];
		if (x>x1) add(id-m,d+c[id-m]);
		if (x<x2) add(id+m,d+c[id]);
		if (y>y1) add(id-1,d+r[id-1]);
		if (y<y2) add(id+1,d+r[id]);
		vis[id]=0;
	}
}

void solve(int x1,int y1,int x2,int y2,int ty,int ql,int qr) {
	if (ql>qr) return;
	if (min(y2-y1+1,x2-x1+1)>qr-ql+1) {
		rep(k,ql,qr+1) {
			query q=Que[ty][k];
			Dijkstra(q.px,q.py,x1,y1,x2,y2,-1);
			ret[q.id]=min(ret[q.id],dis[q.qx*m+q.qy]);
		}
		return;
	}
	if (y2-y1<x2-x1) {
		int xm=(x1+x2)>>1;
		rep(y,y1,y2+1) {
			if (y==y1) Dijkstra(xm,y,x1,y1,x2,y2,-1);
			else Dijkstra(xm,y,x1,y1,x2,y2,dis[xm*m+y]);
			rep(k,ql,qr+1) {
				query q=Que[ty][k];
				ret[q.id]=min(ret[q.id],dis[q.px*m+q.py]+dis[q.qx*m+q.qy]);
			}
		}
		int Ql=ql,Qr=qr;
		rep(k,ql,qr+1) {
			query q=Que[ty][k];
			if (q.px<xm&&q.qx<xm) Que[ty^1][Ql++]=q;
			if (q.px>xm&&q.qx>xm) Que[ty^1][Qr--]=q;
		}
		solve(x1,y1,xm-1,y2,ty^1,ql,Ql-1);
		solve(xm+1,y1,x2,y2,ty^1,Qr+1,qr);
	} else {
		int ym=(y1+y2)>>1;
		rep(x,x1,x2+1) {
			if (x==x1) Dijkstra(x,ym,x1,y1,x2,y2,-1);
			else Dijkstra(x,ym,x1,y1,x2,y2,dis[x*m+ym]);
			rep(k,ql,qr+1) {
				query q=Que[ty][k];
				ret[q.id]=min(ret[q.id],dis[q.px*m+q.py]+dis[q.qx*m+q.qy]);
			}
		}
		int Ql=ql,Qr=qr;
		rep(k,ql,qr+1) {
			query q=Que[ty][k];
			if (q.py<ym&&q.qy<ym) Que[ty^1][Ql++]=q;
			if (q.py>ym&&q.qy>ym) Que[ty^1][Qr--]=q;
		}
		solve(x1,y1,x2,ym-1,ty^1,ql,Ql-1);
		solve(x1,ym+1,x2,y2,ty^1,Qr+1,qr);
	}
}
