void dfs(int u,int fa)
{
	sz[u]=1;Max[u]=0;
	for(int i=1;i<=son[u][0];i++)
		if(son[u][i]!=fa)
			dfs(son[u][i],u),sz[u]+=sz[son[u][i]],Max[u]=max(Max[u],sz[son[u][i]]);
}

int get_root()
{
	dfs(0,0);
