	return pos;
}

struct Type
{
	int status;LL val;
	
	inline Type(int status=0,LL val=0):status(status),val(val){}
};

inline bool operator<(const Type& A,const Type& B)
{
	return A.status<B.status;
}

vector<Type> f[N][N],sta[N];

int vis[W],tag;LL _val[W];

bool cmp(int a,int b)
{
	return sta[a].size()>sta[b].size();
}

void Union(int a,int b)
{
	vector<Type> x;
	for(int i=0;i<sta[a].size();i++)
		for(int j=0;j<sta[b].size();j++)
		{
			int sa=sta[a][i].status,sb=sta[b][j].status;
			if(Num[sa|sb]==Num[sa]+Num[sb])
				x.push_back(Type(sa|sb,sta[a][i].val*sta[b][j].val));
		}
	sta[a].clear();sta[b].clear();
	if(x.empty())
		return;
	if(x.size()<=10000)
	{
		sort(x.begin(),x.end());
		int Now=-1;
		for(int i=0;i<x.size();i++)
			if(sta[a].empty()||sta[a][Now].status!=x[i].status)
				sta[a].push_back(x[i]),Now++;
			else
				sta[a][Now].val+=x[i].val;
	}
	else
	{
		tag++;
		for(int i=0;i<x.size();i++)
		{
			if(vis[x[i].status]!=tag)
				vis[x[i].status]=tag,_val[x[i].status]=0;
			_val[x[i].status]+=x[i].val;
		}
		int t=Num[x[0].status];
		for(int i=1;i<=All[t][0];i++)
		{
			int s=All[t][i];
			if(vis[s]==tag&&_val[s])
				sta[a].push_back(Type(s,_val[s]));
		}
	}
}

LL S[2][W];

void dp(int u,int fa)
{
	int s[N]={},t=0;sz[u]=1;
	for(int i=1;i<=son[u][0];i++)
		if(son[u][i]!=fa)
			s[++t]=son[u][i],dp(s[t],u),sz[u]+=sz[s[t]];
	for(int p=0;p<n;p++)
	{
		if(t==0)
		{
			f[u][p].push_back(Type(1<<p,1));continue;
		}
		int id[N]={},k=0;
		for(int i=1;i<=t;i++)
		{
			int v=s[i];tag++;
			for(int q=0;q<n;q++)
				if(g[p][q])
					for(int j=0;j<f[v][q].size();j++)
					{
						Type _=f[v][q][j];
						if(vis[_.status]!=tag)
							vis[_.status]=tag,_val[_.status]=0;
						_val[_.status]+=_.val;
					}
			sta[i].clear();
			for(int j=1;j<=All[sz[v]][0];j++)
			{
				int _sta=All[sz[v]][j];
				if(!(_sta&(1<<p))&&vis[_sta]==tag&&_val[_sta])
					sta[i].push_back(Type(_sta,_val[_sta]));
			}
			id[++k]=i;
		}
		while(k!=1)
		{
			sort(id+1,id+k+1,cmp);
			int a=id[k-1],b=id[k];
			if(sta[a].size()*(LL)sta[b].size()<1000000)
				Union(a,b),k--;
			else
			{
				for(int j=0;j<m;j++)
					S[0][j]=1;
				for(int i=1;i<=k;i++)
				{
					memset(S[1],0,sizeof S[1]);
					for(int j=0;j<sta[id[i]].size();j++)
						S[1][sta[id[i]][j].status]+=sta[id[i]][j].val;
					sta[id[i]].clear();
					for(int k=0;k<n;k++)
						for(int j=0;j<m;j++)
							if(j&(1<<k))
								S[1][j]+=S[1][j^(1<<k)];
					for(int j=0;j<m;j++)
						S[0][j]*=S[1][j];
				}
				for(int k=n-1;~k;k--)
					for(int j=m-1;~j;j--)
						if(j&(1<<k))
							S[0][j]-=S[0][j^(1<<k)];
				for(int j=1;j<=All[sz[u]-1][0];j++)
				{
					int _sta=All[sz[u]-1][j];
					if(S[0][_sta])
						sta[id[1]].push_back(Type(_sta,S[0][_sta]));
				}
				k=1;
			}
		}
		f[u][p]=sta[id[1]];
		for(int i=0;i<f[u][p].size();i++)
			f[u][p][i].status|=1<<p;
	}
	for(int p=0;p<n;p++)
		for(int i=1;i<=t;i++)
			f[s[i]][p].clear();
}

