void dfs(int now,int fa){
	for (int i=first[now];i;i=nxt[i])
		if (v[i]!=fa)dfs(v[i],now);
	for (int i=0;i<n;i++){
		sz[now]=1;
		f[now][i][(1<<i)]=1;
		for (int j=first[now];j;j=nxt[j]){
			if (v[j]==fa)continue;
			memset(g,0,sizeof(g));
			memset(h,0,sizeof(h));
			for (int k=0;k<n;k++)
				if (k!=i&&c[i][k]==1){
					for (int l=0;l<(int)d[sz[v[j]]].size();l++){
						int x=d[sz[v[j]]][l];
						g[x]+=f[v[j]][k][x];
					}
				}
			for (int k=0;k<(int)d[sz[now]].size();k++){
				int x=d[sz[now]][k];
				if (f[now][i][x]>0){
					int qwq=(1<<n)-1-x;
					for (int l=qwq;l>0;l=((l-1)&qwq))
						if ((x&l)==0&&g[l]>0)h[x|l]+=f[now][i][x]*g[l];
				}
			}
			sz[now]+=sz[v[j]];
			for (int k=0;k<(1<<n);k++)f[now][i][k]=h[k];
		}
	}
	return;
