const int N = 5e5 + 10;

struct Point {
	int id, x, y;
	Point () {}
	Point (int id, int x, int y): id(id), x(x), y(y) {}
	bool operator < (const Point& a) const {
		return x == a.x ? y < a.y : x < a.x;
	}
} p[N];

int n, h[N], t, can[N], pre[N];

ll c[N], f[N];

inline void modify(int p, ll v) {
	for (; p <= n; p += p & -p) {
		checkMax(c[p], v);
	}
}

inline ll query(int p) {
	ll res = 0;
	for (; p; p -= p & -p) {
		checkMax(res, c[p]);
	}
	return res;
}

#define fx(i) (i)
#define fy(i) (f[(i)] + 1ll * (i) * (i) - 2 * (i))

double slope(int x, int y) {
	return 1.0 * (fy(y) - fy(x)) / (fx(y) - fx(x));
}

