ll cal(int x)
{
	if (f[x]) return f[x];
	if (x == 1) return 0;
	ll ans = 0; int tmp = x;
	for (int i = 2,tmp;i*i <= x;i++)
	{
		for (tmp=0;x%i == 0;x /= i) tmp++;
