bool lyndon(string s){
	For(j,1,int(s.size())-1){
		if(s>=s.substr(j)){
			return 0;
		}
	}
	return 1;
}
db count(string s){
	strcpy(t+1,s.c_str());
	int len=s.size();
	for(int i=2,j=0;i<=len;++i){
		while(j&&t[j+1]!=t[i]) j=kmp[j];
		if(t[j+1]==t[i]) ++j;
		kmp[i]=j;
	}
	memset(bd,0,sizeof(bd));
	bd[0]=1;
	for(int i=len;i;i=kmp[i]){
		bd[i]=1;
	}
	For(i,0,len){
		For(j,0,25){
			bool flg=(t[1]<=j+'a');
			for(int k=i;k;k=kmp[k]){
				if(t[k+1]>j+'a'){
					flg=0;
					break;
				}
			}
			if(flg){
				int k=i;
				while(k&&t[k+1]!=j+'a') k=kmp[k];
				if(t[k+1]==j+'a') ++k;
				nxt[i][j]=k;
			}else{
				nxt[i][j]=-1;
			}
		}
	}
	memset(f,0,sizeof(f));
	memset(g,0,sizeof(g));
	f[len][len][1]=1;
	For(i,len,n-1){
		For(j,0,len){
			For(k,1,n-len+1){
				if(f[i][j][k]<1e-9) continue;
				For(c,0,25){
					int j_=nxt[j][c];
					if(~j_){
						f[i+1][j_][k+(j_==len)]+=f[i][j][k];
					}
				}
			}
		}
	}
	For(i,1,len){
		g[i]=bd[len-i]&&lyndon(string(t+1,t+i+1));
	}
	For(j,0,len){
		int u=j,flg=1,cnt=0;
		For(i,1,len){
			if(!~nxt[u][t[i]-'a']){
				flg=0;
				break;
			}
			u=nxt[u][t[i]-'a'];
			cnt+=(u==len);
		}
		if(!flg) continue;
		For(i,len+1,n){
			For(k,1,n-len+1){
				g[i]+=f[i][j][k]/(k+cnt-1);
			}
		}
	}
	For(i,len+1,n){
		For(j,1,i-1){
			if(i%j==0){
				g[i]-=g[j]*(db(j)/i);
			}
		}
	}
	return accumulate(g+len,g+n+1,db(0));
}
ll get(db x){
	return min<db>(1e18,x+.5);
}
