	void addval(int v,int l,int r,int ll,int rr,int s)
	{
		if(l <= ll && rr <= r)
		{
			add[s] += v;
			return;
		}
		
		int mid = (ll + rr) >> 1;
		
		pushdown(s);
		
		if(l <= mid) addval(v, l, r, ll, mid, s << 1);
		if(r > mid) addval(v, l, r, mid + 1, rr, s << 1 | 1);
	}
