	{
		if(l == r) return add[s];
		
		int mid = (l + r) >> 1;
		
		pushdown(s);
		
		if(k <= mid) return query(k, l, mid, s << 1);
		else return query(k, mid + 1, r, s << 1 | 1);
	}
