struct Node {
  Node *p, *ch[2];
  bool flag;
  int val, aux, sum;
  inline int dir();
  inline void flip();
  void release();
  void update();
  void rotate();
  void splay();
  Node *expose();
  inline void evert();
  void link(Node*);
  void cut(Node*);
} pool[2 * N], *tot;

inline int Node::dir() {
  if (!p || (this != p->ch[0] && this != p->ch[1])) return -1;
  return this == p->ch[1];
}

inline void Node::flip() {
  std::swap(ch[0], ch[1]);
  flag ^= 1;
}

void Node::release() {
  if (flag) {
    if (ch[0]) ch[0]->flip();
    if (ch[1]) ch[1]->flip();
    flag = false;
  }
}

void Node::update() {
  sum = val ^ aux;
  if (ch[0]) sum ^= ch[0]->sum;
  if (ch[1]) sum ^= ch[1]->sum;
}

void Node::rotate() {
  Node *v = p;
  v->release();
  release();
  int d = dir();
  if (~v->dir()) v->p->ch[v->dir()] = this;
  p = v->p;
  if (ch[!d]) ch[!d]->p = v;
  v->ch[d] = ch[!d];
  ch[!d] = v;
  v->p = this;
  v->update();
  update();
}

void Node::splay() {
  release();
  while (~dir()) {
    if (~p->dir()) (dir() == p->dir() ? p : this)->rotate();
    rotate();
  }
  update();
}

Node *Node::expose() {
  Node *v, *u = this;
  for (v = NULL; u; v = u, u = u->p) {
    u->splay();
    if (u->ch[1]) u->aux ^= u->ch[1]->sum;
    if (v) u->aux ^= v->sum;
    u->ch[1] = v;
    u->update();
  }
  return v;
}

inline void Node::evert() {
  expose()->flip();
  splay();
}

void Node::link(Node *v) {
  evert();
  p = v;
  v->aux ^= sum;
  expose();
}

void Node::cut(Node *v) {
  evert();
  v->expose();
  v->splay();
  v->ch[0] = p = NULL;
  v->update();
  update();
}

void link(int x, int y) {
  Node *u = &pool[x], *v = &pool[y], *w = ++tot;
  u->link(w);
  v->link(w);
}

Node *get(int x, int y) {
  Node *u = &pool[x], *v = &pool[y];
  u->evert();
  v->expose();
  v->splay();
  if (v->ch[0]->ch[0]) return v->ch[0]; else return v->ch[0]->ch[1];
}

void cut(int x, int y) {
  Node *u = &pool[x], *v = &pool[y], *w = get(x, y);
  u->cut(w);
  v->cut(w);
}

void add(int x, int z) {
  Node *u = &pool[x];
  u->evert();
  u->val ^= z;
  u->update();
}

int query(int x, int y) {
  Node *u = &pool[x], *w = get(x, y);
  u->evert();
  w->expose();
  return w->val ^ w->aux;
}

