typedef long long i64;
 
const int N = 2e5 + 10;
 
namespace LCT {
    int fa[N], ch[N][2], rev[N];
    int val[N], chain[N], aux[N];
 
    inline int Dir(int u) {
        return ch[fa[u]][1] == u;
    }
 
    inline bool IsRoot(int u) {
        return ch[fa[u]][0] != u && ch[fa[u]][1] != u;
    }
 
    inline void Set(int u, int v, int d) {
        ch[u][d] = v;
        if (v)
            fa[v] = u;
    }
 
    inline void Reverse(int u) {
        if (rev[u]) {
            swap(ch[u][0], ch[u][1]);
            rev[ch[u][0]] ^= 1;
            rev[ch[u][1]] ^= 1;
            rev[u] = 0;
        }
    }
 
    inline void Update(int u) {
        chain[u] = chain[ch[u][0]] ^ chain[ch[u][1]] ^ val[u] ^ aux[u];
    }
 
    inline void Rotate(int u) {
        int v = fa[u], d = Dir(u);
        if (IsRoot(v))
            fa[u] = fa[v];
        else
            Set(fa[v], u, Dir(v));
        Set(v, ch[u][d ^ 1], d);
        Set(u, v, d ^ 1);
        Update(v);
    }
 
    inline void Splay(int u) {
        static int stk[N];
        int top = 0;
        for (int v = u; ; v = fa[v]) {
            stk[++top] = v;
            if (IsRoot(v))
                break;
        }
        while (top)
            Reverse(stk[top--]);
        for (; !IsRoot(u); Rotate(u)) {
            int v = fa[u];
            if (IsRoot(v))
                continue;
            Dir(u) ^ Dir(v) ? Rotate(u) : Rotate(v);
        }
        Update(u);
    }
 
    inline void Access(int u) {
        for (int v = 0; u; v = u, u = fa[u]) {
            Splay(u);
            aux[u] ^= chain[ch[u][1]];
            aux[u] ^= chain[v];
            Set(u, v, 1);
            Update(u);
        }
    }
 
    inline void Evert(int u) {
        Access(u);
        Splay(u);
        rev[u] ^= 1;
    }
 
    inline void Cut(int u, int v) {
        Evert(u);
        Access(v);
        Splay(v);
        fa[ch[v][0]] = 0;
        ch[v][0] = 0;
        Update(v);
    }
 
    inline void Link(int u, int v) {
        Evert(u);
        Evert(v);
        fa[v] = u;
        aux[u] ^= chain[v];
    }
 
    inline void Modify(int u, int d) {
        Access(u);
        Splay(u);
        val[u] ^= d;
        Update(u);
    }
}
 
