		c[v][t] = c[u][t^1]; fa[c[u][t^1]] = v;
		c[u][t^1] = v; fa[v] = u; fa[u] = w;

		push_up(v);
	}
	void push_down(int u) { 
		if(Rev[u]) 
			swap(c[u][0], c[u][1]), 
			Rev[c[u][0]] ^= 1, Rev[c[u][1]] ^= 1; 
		Rev[u] = 0;
	}
