	void splay(int u) {
		Push(u);
		while(!rt(u)) {
			int v = fa[u], w = fa[v];
			if(!rt(v)) 
				rotate((c[v][1]==u) == (c[w][1]==v) ? v : u);
			rotate(u);
		}push_up(u);
	}
	int access(int u) {
		int v = 0;
