			s[fa[u]] ^= Sum[u];

		}return v;
	}
	void Change_root(int u) { access(u); splay(u); Rev[u] ^= 1; }
	void link(int u, int v) {
		Change_root(u);
		access(v);
		fa[u] = v;
		s[v] ^= Sum[u];
		Sum[v] ^= Sum[u];
	}
