		Change_root(u);
		access(v); splay(v);
		c[v][0] = fa[u] = 0;
		push_up(v);
	}
	void update(int u, int v, int R) {
		Change_root(u); s[u] ^= R, Sum[u] ^= R;
		Change_root(v); s[v] ^= R, Sum[v] ^= R;
	}
