typedef long long ll;

const int maxn = 5005;
const int mod = 998244353;

int n, m;
int comb[maxn][maxn];
int lx[maxn], ly[maxn];
int sum[maxn];

void prework()
{
	const int plen = 5000;
	
	comb[0][0] = 1;
	for(int i = 1; i <= plen; i++)
	{
		comb[i][0] = 1;
		
		for(int j = 1; j <= i; j++)
			comb[i][j] = (comb[i - 1][j] + comb[i - 1][j - 1]) % mod;
	}
}
inline bool change(int x,int y)
{
	if(y < 0) return false;
	
	if(sum[x] != -1)
	{
		if(sum[x] != y) return false;	
	}
	else
	{
		sum[x] = y;
	}
	
	return true;
}
ll work(int tot,int tp)
{
	int wmax = 0;
	
	memset(sum, -1, sizeof(sum));
	
	for(int i = 1; i <= m; i++)
	{
		if(lx[i] > ly[i])
		{
			if(!change(lx[i], ly[i])) return 0;
		}
		else if(lx[i] < ly[i])
		{
			if(!change(n - ly[i], tot - lx[i])) return 0;
		}
		else
		{
			wmax = std::max(wmax, lx[i]);
		}
	}
	
	sum[0] = 0;
	sum[n] = tot;
	
	if(tp & 1)
	{
		for(int i = 1; i <= wmax; i++)
		{
			if(!change(i, i)) return 0;
		}
	}
	
	if(tp & 2)
	{
		for(int i = 1; i <= wmax; i++)
		{
			if(!change(n - i, tot - i)) return 0;
		}
	}
	
	ll res = 1;
	
	int last = -1;
	
	for(int i = 0; i <= n; i++)
	{
		if(sum[i] != -1)
		{
			if(last != -1)
			{
				if(sum[i] >= sum[last])
				{
					(res *= comb[i - last][sum[i] - sum[last]]) %= mod;
					
					if(!res) return 0;
				}
				else
				{
					return 0;
				}
			}
			
			last = i;
		}
	}
	
	if(tp < 3)
	{
		return res;
	}
	else
	{
		return mod - res;
	}
}
int main()
{
	int T;

	scanf("%d", &T);
	
	prework();
	
	while((T--) && scanf("%d%d", &n, &m) != EOF)
	{
		for(int i = 1; i <= m; i++)
		{
			scanf("%d%d", &lx[i], &ly[i]);
		}
		
		ll ans = 0;
		
		for(int i = 0; i <= n; i++)
		{
			ans += work(i, 1);
			ans += work(i, 2);
			ans += work(i, 3);
			
			ans %= mod;
		}
				
		printf("%d\n", (int) ans);
	}

	return 0;
}

