typedef long long LL;
int cal(int sn){
	if(s[0][1]!=-1&&s[0][1]!=sn||(s[n][0]!=-1&&s[n][0]!=sn))return 0;
	int pos=0,pre=0;
	int ret=1;
	for(int i=1;i<n;i++){
		if(s[i][0]==-1&&s[i][1]==-1)continue;
		int cur;
		if(s[i][0]!=-1){
			if(s[i][1]!=-1&&s[i][0]+s[i][1]!=sn)return 0;
			cur=s[i][0];
		}else cur=sn-s[i][1];
		if(cur<pre)return 0;
		ret=((LL)ret*C[i-pos][cur-pre])%P;
		pre=cur;
		pos=i;
	}
	if(pre>sn)return 0;
	return (LL)ret*C[n-pos][sn-pre]%P;
}
int solve(){
	clr(s,-1);
	for(int i=1;i<=tot;i++){
		if(s[pos[i]][ty[i]]!=-1&&s[pos[i]][ty[i]]!=num[i])return 0;
		s[pos[i]][ty[i]]=num[i];
	}
	int ret=0;
	for(int i=0;i<=n;i++)(ret+=cal(i))%=P;
	return ret;
}
