	IL int inc(RG int x, RG int v) {x += v; return x >= mod ? x - mod : x;}
	IL int dec(RG int x, RG int v) {x -= v; return x < 0 ? x + mod : x;}
	int lim_l[MaxN], lim_r[MaxN];
	
	struct Range
	{
		int l, r, v;
		IL bool check() const 
		{
///*lgg*/printf("check [%d, %d] v = %d\n", l, r, v);
			return 0 <= v && v <= r - l + 1;
		}
		IL bool operator < (RG const Range& R) const {return l < R.l || (l == R.l && r < R.r);}
		IL bool operator != (RG const Range& R) const {return l != R.l || r != R.r;}
	} ran[MaxN << 1];
	
	int inv[MaxN], fac[2][MaxN];
	IL int comb(RG int n, RG int m) {return (ll) fac[0][n] * fac[1][m] % mod * fac[1][n - m] % mod;}
	
	struct Pointer{int to, sum; Pointer *next;};
	Pointer *fir[MaxN], mem[MaxN << 1], *tot = mem;
	int len[MaxN];
	int vis[MaxN], timer;
	IL void add(RG int a, RG int b, RG int s)
	{
///*lgg*/printf("add [%d, %d] + [%d, %d] = %d\n", a, a + len[a] - 1, b, b + len[b] - 1, s);
		*++tot = (Pointer) {b, s, fir[a]}, fir[a] = tot;
	}
	
	int dfs(RG int i, RG int v)
	{
		if(v < 0 || v > len[i]) return 0;
		vis[i] = timer;
		RG int ans = comb(len[i], v);
		for(RG Pointer *k = fir[i]; k; k = k->next)
			if(vis[k->to] != timer && !(ans = (ll) ans * dfs(k->to, k->sum - v) % mod))
				return 0;
		return ans;
	}
	
	IL int solve(RG int n)
	{
		RG int last, Ran = 0;
		last = 0; For(i, 1, n) if(~lim_l[i]) {if(!(ran[++Ran] = (Range) {last + 1,			i, lim_l[i] - lim_l[last]}).check()) return 0; else last = i;} RG int Most_l = last;
		last = 0; For(i, 1, n) if(~lim_r[i]) {if(!(ran[++Ran] = (Range) {n - i + 1,	n - last, lim_r[i] - lim_r[last]}).check()) return 0; else last = i;} RG int Most_r = last;
		RG int ans = 1;
		For(i, 1, n - Most_l - Most_r) ans = inc(ans, ans);
///*lgg*/puts("Basic Passed!");
