		For(i, 1, Ran0) if(!Ran || ran[Ran] != ran[i]) ran[++Ran] = ran[i]; else if(ran[Ran].v != ran[i].v) return 0;
///*lgg*/For(i, 1, Ran) printf("ran[%d] = [%d, %d] v = %d\n", i, ran[i].l, ran[i].r, ran[i].v);

		tot = mem;
