		{
			RG int l = ran[i].l, r = ran[i].r, v = ran[i].v;
			RG int cov_l = MaxN, cov_r = -MaxN;
			For(j, 1, Ran) if(j != i)
			{
				if(l > ran[j].r || ran[j].l > r) continue;
				if(l <= ran[j].l && ran[j].r <= r) //Full covers j
					{v -= ran[j].v, cmin(cov_l, ran[j].l - 1), cmax(cov_r, ran[j].r + 1); /*printf("full_cover %d\n", j);*/ continue;}
				if(ran[j].l <= l && r <= ran[j].r) //Full covered
					{ans = (ll) ans * comb(r - l + 1, v) % mod; goto next_range;}
				if(ran[j].l <= l) cmin(cov_l, ran[j].r);
				if(r <= ran[j].r) cmax(cov_r, ran[j].l);			
			}
///*lgg*/printf("ran[%d] l = %d r = %d left_v = %d cov = %d, %d\n", i, l, r, v, cov_l, cov_r);
			if(cov_l == MaxN && cov_r == -MaxN)
