			else 
			{
				if(cov_r == -MaxN) cov_r = cov_l + 1;
				if(cov_l == MaxN) cov_l = cov_r - 1;
				len[l] = cov_l - l + 1;
				len[cov_r] = r - cov_r + 1;
				add(l, cov_r, v);
			}
				
			next_range: ;
		}
		timer = 0;
		For(i, 1, n) if(fir[i] && !vis[i])
		{
			RG int cur = 0;
			For(j, 0, len[i]) 
			{
				++timer;
				cur = inc(cur, dfs(i, j));
			}
			ans = (ll) ans * cur % mod;
		}
		return ans;	
	}

