	(x -= y) < 0 ? x += mod : 0;
}

int calc() {
	int ans = 0;
	for (int i = 0; i <= n; ++i) {
		memset(s, 0xff, sizeof s);
		s[0] = 0;
		s[n] = i;
		int flag = 0;
		for (int j = 1; j <= n; ++j) {
			if (need[j][0] > s[n] || need[j][1] > s[n]) flag = 1;
			int x = ~need[j][0] ? need[j][0] : -1;
			int y = ~need[j][1] ? s[n] - need[j][1] : -1;
			if (~x) {
				if (~s[j] && s[j] != x) flag = 1;
				else s[j] = x;
			}
			if (~y) {
				if (s[j - 1] != y && ~s[j - 1]) flag = 1;
				s[j - 1] = y;
			}
		}
		// for (int j = 1; j <= n; ++j)
		// 	cout << s[j] << ' ';
		// puts("");
		// cout << s[n] << ' ' << flag << endl;
		if (flag) continue;
		int tmp = 1;
		for (int j = 1, k = 0; j <= n; ++j) {
			if (s[j] == -1) continue;
			if (s[j] < s[k] || j - k < s[j] - s[k]) {
				tmp = 0;
				break;
			}
			tmp = 1LL * tmp * c[j - k][s[j] - s[k]] % mod;
			k = j;
		}
		add(ans, tmp);
	}
	return ans;
}

void solve() {
