		if (x == y) len = max(len, x);
		else {
			if (x > y) {
				if (~need[x][0] && need[x][0] != y) flag = 1;
				need[x][0] = y;	
			}
			else {
				if (~need[n - y + 1][1] && need[n - y + 1][1] != x) flag = 1;
				need[n - y + 1][1] = x;	
			}
		}
