namespace Tarjan
{
	const int N=800005;
	const int M=2000005;
	struct edge {int x,next;} b[M];
	int tot,a[N],stack[N],low[N],dfn[N],top,v[N];
	inline void addedge(int x,int y)
	{
		++tot;
		b[tot].x=y;
		b[tot].next=a[x];
		a[x]=tot;
	}
	void dfs(int x)
	{
		dfn[x]=low[x]=++tot; stack[++top]=x; v[x]=1;
		for (int p=a[x];p;p=b[p].next)
		{
			int pp=b[p].x;
			if (v[pp]==0) {dfs(pp); low[x]=min(low[x],low[pp]);}
			else if (v[pp]==1) low[x]=min(low[x],dfn[pp]);
		}
		if (dfn[x]!=low[x]) return; ++cnt;
		for (;stack[top+1]!=x;--top) belong[stack[top]]=cnt,v[stack[top]]=2;
	}
	bool solve()
	{
		tot=cnt=top=0; int num=S+S;
		for (int i=1; i<=num; i++) if (v[i]==0) dfs(i);
		for (int i=1; i<=S; i++) if (belong[i]==belong[conf[i]]) return false;
		for (int i=1; i<=num; i++)
			for (int p=a[i];p;p=b[p].next)
			if (belong[i]!=belong[b[p].x]) Graph::addedge(belong[b[p].x],belong[i]);
		return true;
	}
}
inline void addedge(int x,int y)
{
	Tarjan::addedge(x,y);
	Tarjan::addedge(conf[y],conf[x]);
}
void init()
{
	n=getint(); m=getint(); S=n;
	for (int i=1; i<=m; i++)
	{
		int x=getint(),y=getint(),z=getint();
		a[x].push_back((point){y,z,++S,++S,++S});
	}
	for (int i=1; i<=S; i++) conf[i]=i+S,conf[i+S]=i;
	for (int i=1; i<=n; i++)
	{
		int size=a[i].size();
		for (int j=0; j<size; j++) addedge(a[i][j].now,a[i][j].x+a[i][j].t*S);
		for (int j=0; j<size; j++) addedge(conf[a[i][j].now],conf[a[i][j].pre]);
		for (int j=1; j<size; j++) addedge(conf[a[i][j-1].pre],conf[a[i][j].pre]);
		for (int j=0; j<size; j++) addedge(conf[a[i][j].now],conf[a[i][j].suc]);
		for (int j=0; j<size-1; j++) addedge(conf[a[i][j+1].suc],conf[a[i][j].suc]);
		if (size!=0) addedge(i+S,a[i][0].suc);
		for (int j=1; j<size; j++) addedge(conf[a[i][j].now],a[i][j-1].pre);
		for (int j=0; j<size-1; j++) addedge(conf[a[i][j].now],a[i][j+1].suc);
	}
}
void solve()
{
	if (!Tarjan::solve()) {printf("Impossible\n"); return;}
	Graph::solve();
}
int main()
{
	init();
	solve();
	return 0;
}

