namespace w1{
	const int S = 22;
	int bin[S],st[S][N],log_2[N];
	LL ans[N];
	inline int query(int l,int r){
		int len=log_2[r-l+1];
		return max(st[len][l],st[len][r-bin[len]+1]);
	}
	void work(){
		for(int i=1;i<=n;i++)st[0][i]=a[i];
		bin[0]=1;
		for(int i=1;i<S;i++)bin[i]=bin[i-1]<<1;
		log_2[1]=0;
		for(int i=2;i<=n;i++)log_2[i]=log_2[i>>1]+1;
		for(int i=1;i<S;i++){
			for(int j=1;j+bin[i]<=n+1;j++)st[i][j]=max(st[i-1][j],st[i-1][j+bin[i-1]]);
		}
		for(int i=1;i<=n;i++){
			for(int j=i;j<=n;){
				int now=query(i,j);
				int l=j,r=n;
				while(l<r){
					int mid=(l+r+1)>>1;
					if(query(i,mid)!=now)r=mid-1;
					else l=mid;
				}
				(ans[l-i+1]+=now)%=Q;
				(ans[j-i]-=now)%=Q;
				//printf("i %d r %d %d\n",i,l,now);
				j=l+1;
			}
		}
		for(int i=n-1;i;i--)(ans[i]+=ans[i+1])%=Q;
		LL res=0;
		for(int i=1;i<=n;i++)res^=(ans[i]%Q+Q)%Q;//,printf("%lld\n",ans[i]);
		printf("%lld\n",res);
	}
}
bool check(){
	static int q[N];
	int top=0;
	for(int i=1;i<=n;i++){
		if(!top||a[i]>=q[top])q[++top]=a[i];
		else{
			int pos=upper_bound(q+1,q+top+1,a[i])-q;
			q[pos]=a[i];
		}
	}
	//printf("top %d\n",top);
	return top>=n/2;
}
