	s2[x]=(s2[x]+(ll)t[i].x*x%mod)%mod; s2[y+1]=(s2[y+1]-(ll)t[i].x*x%mod+mod)%mod;
	s3[y+1]=(s3[y+1]+t[i].x)%mod; s3[x+y]=(s3[x+y]-t[i].x+mod)%mod; s5[y]=(s5[y]+(ll)t[i].x*(x-1)%mod)%mod;
