	int get_sum(int S)
	{
		memset(need,0,sizeof(need));
		int ans=0;
		for(int i=1;i<=n-m+1;i++)
			if((S>>(i-1))&1)
			{
				for(int j=i;j<=i+m-1;j++)
				{
					if(!need[j][t[j-i+1]-'a'])
					{
						need[j][t[j-i+1]-'a']=true;
						ans++;
					}

					if(!can[j][t[j-i+1]-'a'])
						return -1;
				}
			}
		return ans;
	}

	void main()
	{
		for(int i=1;i<1<<(n-m+1);i++)
			popcnt[i]=popcnt[i-(i&-i)]+1;

		int sum=0;
		for(int i=1;i<=n;i++)
			sum += strlen(s[i]+1);

		for(int i=1;i<=sum;i++)
			val[i]=(val[i-1]+sum*qsm(i,Mod-2))%Mod;

		int ans=0;
		bool cant=true;
		for(int S=0;S<1<<(n-m+1);S++)
		{
			int x=get_sum(S);
			if(x!=-1)
			{
				if(S) //如果有一个非空集合是成功的，则答案就不是-1
					cant=false;

				if(popcnt[S]%2==0)
					ans=(ans+Mod-val[x])%Mod;
				else
					ans=(ans+val[x])%Mod;
			}
		}

		if(cant)
			printf("-1\n");
		else
			printf("%d\n",ans);
	}
}

namespace third //处理m<=15的情况
{
	const int S=(1<<11)+5;

	int xin[S][N*30],jiu[S][N*30];
	int val[N*30];

	void main()
	{
		int sum=0;
		for(int i=1;i<=n;i++)
			sum += strlen(s[i]+1);

		for(int i=1;i<=sum;i++)
			val[i]=(val[i-1]+sum*qsm(i,Mod-2))%Mod;

		memset(xin,0,sizeof(xin));
		xin[0][0]=Mod-1;
		for(int i=1;i<=n-m+1;i++)
		{
			memcpy(jiu,xin,sizeof(xin));
			memset(xin,0,sizeof(xin));
			for(int S=0;S<1<<m;S++) //第w位为1表示i-w选
			{
				if(S>>i) //S有>=i位的1
					continue;

				if(S%2==0) //这一位不选
				{
					for(int j=0;j<=sum;j++)
					{
						xin[S][j]+=jiu[S/2][j];
						if(xin[S][j]>=Mod) xin[S][j]-=Mod;
						if(i>m)
						{
							xin[S][j]+=jiu[S/2+(1<<(m-1))][j];
							if(xin[S][j]>=Mod) xin[S][j]-=Mod;
						}
					}
				}
				else
				{
					memset(need,0,sizeof(need));
					bool flag=true;
					for(int k=1;k<m;k++)
						if((S>>k)&1)
						{
							//第k位选
							for(int w=1;w<=m;w++)
							{
								need[i-k+w-1][t[w]-'a']=true;
								if(!can[i-k+w-1][t[w]-'a'])
								{
									flag=false;
									break;
								}
							}

							if(!flag)
								break;
						}

					if(!flag)
						continue;

					int cnt=0;
					for(int w=1;w<=m;w++)
					{
						if(!need[i+w-1][t[w]-'a']) //多需要一个
							cnt++;

						need[i+w-1][t[w]-'a']=true;
						if(!can[i+w-1][t[w]-'a'])
						{
							flag=false;
							break;
						}
					}

					if(!flag)
						continue;

					for(int j=cnt;j<=sum;j++)
					{
						xin[S][j]+=Mod-jiu[S/2][j-cnt];
						if(xin[S][j]>=Mod) xin[S][j]-=Mod;
						if(i>m)
						{
							xin[S][j]+=Mod-jiu[S/2+(1<<(m-1))][j-cnt];
							if(xin[S][j]>=Mod) xin[S][j]-=Mod;
						}
					}
				}
			}
		}

		int ans=0;
		for(int i=0;i<=sum;i++)
		{
			int cnt=0;
			for(int S=0;S<1<<m;S++)
				cnt=(cnt+xin[S][i])%Mod;
			ans=(ans+1ll*cnt*val[i])%Mod;
		}
		printf("%d\n",ans);
	}
}

