	A[++k]=a;B[k]=b;
}

void getgcd(LL a,LL b)
{
	if(a==g||b==g)
		return;
	if(a<b)
		swap(a,b);
	if(a<2*b)
		Add(a,b),getgcd(a-b,b);
	else if(a<3*b)
		Add(a,b),Add(a-b,b),getgcd(a-b-b,b);
	else
	{
		LL k=a/b;
		LL t=b,i=1,Now=a;
		while(i<=k)
		{
			while(k%(3*i))
				Add(Now,t),Now-=t,k-=i;
			i*=3;
			if(i>k)
				break;
			Add(a,t);Add(a-t,t);Add(a-t-t,t);Add(a,a-t-t-t);t*=3;
		}
		getgcd(Now,b);
	}
}

void solve()
{
	LL k=(a-c)/g,i=1,Now=a,t=g;
	while(i<=k)
	{
		while(k%(3*i))
			Add(Now,t),Now-=t,k-=i;
		i*=3;
		if(i>k)
			break;
		Add(a,t);Add(a-t,t);Add(a-t-t,t);Add(a,a-t-t-t);t*=3;
	}
}

