typedef unsigned long long LL;
const int maxn=577;

map<LL,bool> H;

LL V[maxn],C,D;
int cv=0;

int K=0;
LL A[maxn],B[maxn];

void done(){
	cout<<K<<endl;
	for(int i=0;i<K;++i) cout<<A[i]<<" "<<B[i]<<endl;
	exit(0);
}

LL work(LL a,LL b){
	LL v=a-b;
	if(!v) return 0;
	if(H[v]){
		return v;
	}
	H[v]=true;
	//cerr<<a*D<<" "<<b*D<<endl;
	//cout<<a*D<<" "<<b*D<<endl;
	A[K]=a*D;
	B[K]=b*D;
	++K;
	if(v==C){
		done();
	}
	return V[cv++]=v;
}

LL real_gcd(LL a,LL b){
	return b?real_gcd(b,a%b):a;
}

void gcd(LL a,LL b){
	//cerr<<"gcd "<<a<<" "<<b<<endl;
	if(b==1) return;
	LL t=work(a,b);
	if(t==1) return;
	if(t<b) gcd(b,t);
	else{
		LL tt=work(t,b);
		if(tt<b){
			gcd(b,tt);
			return;
		}
		LL bb=work(a,tt);
		while(bb<tt){
			tt=work(tt,bb);
			bb=work(a,tt);
		}
		a=tt;
		while(a>b){
			if(bb<a) a=work(a,bb);
			bb>>=1;
		}
		gcd(b,a);
	}
}

int main(){
