	if((C%D) || (C>V[1])){
		cout<<-1<<endl;
		return 0;
	}
	V[0]/=D;V[1]/=D;C/=D;
	gcd(V[1],V[0]);
	sort(V,V+cv);
	LL m=1E18+77;
	for(int i=0;i<cv;++i) if(V[i]>=C){
		m=V[i];
		break;
	}
	LL b=1,tt=work(m,b);
	while(b*2<=m-C){
		tt=work(tt,b);
		b=work(m,tt);
	}
	while(b){
		if(m-b>=C) m=work(m,b);
		b>>=1;
		if(m==C){
			break;
		}
	}
	cout<<K<<endl;
	for(int i=0;i<K;++i) cout<<A[i]<<" "<<B[i]<<endl;
	//cerr<<"K:"<<K<<endl;
}

