inline void down1(int me,int l,int r){
	if(cov[me]==-1)return;
	int mid=(l+r)>>1;
	tag1(me<<1,l,mid,cov[me]);
	tag1(me<<1|1,mid+1,r,cov[me]);
	cov[me]=-1;
}
void cover(int me,int l,int r,int x,int y,int v){
	if(l^r)down1(me,l,r);
	if(x<=l&&r<=y){
		tag1(me,l,r,v);
