	}
	int mid=(l+r)>>1;
	if(x<=mid)cover(me<<1,l,mid,x,y,v);
	if(y>mid)cover(me<<1|1,mid+1,r,x,y,v);
	sum[me]=sum[me<<1]+sum[me<<1|1];
}
int getans(int me,int l,int r,int x,int y){
	if(l^r)down1(me,l,r);
	if(x<=l&&r<=y)return sum[me];
