#include <bits/stdc++.h>
using namespace std;
#define N 510000
#define M 57000000
#define ls l,mid,ch[now][0]
#define rs mid+1,r,ch[now][1]
int n,m,ty,ans,cnt,root[N];
int ch[M][2],tim[M],bj[M];
struct Seg_tree
{
	int sum[N<<2],bj[N<<2];
	void pushdown(int l,int r,int now)
	{
		if(bj[now])
		{
			bj[now<<1]=bj[now];
			bj[now<<1|1]=bj[now];
			int mid=(l+r)>>1;
			sum[now<<1]=(mid-l+1)*bj[now];
			sum[now<<1|1]=(r-mid)*bj[now];
			bj[now]=0;
		}
	}
	void pushup(int x){sum[x]=sum[x<<1]+sum[x<<1|1];}
	void update(int l,int r,int now,int lq,int rq,int v)
	{
		if(lq<=l&&r<=rq)
		{
			bj[now]=v;sum[now]=(r-l+1)*v;
			return;
		}
		int mid=(l+r)>>1;
		pushdown(l,r,now);
		if(mid>=lq)update(l,mid,now<<1,lq,rq,v);
		if(mid<rq) update(mid+1,r,now<<1|1,lq,rq,v);
		pushup(now);
	}
	int query(int l,int r,int now,int lq,int rq)
	{
		if(lq<=l&&r<=rq)
			return sum[now];
		int mid=(l+r)>>1,ret=0;
		pushdown(l,r,now);
		if(mid>=lq)ret+=query(l,mid,now<<1,lq,rq);
		if(mid<rq) ret+=query(mid+1,r,now<<1|1,lq,rq);
		return ret;
	}
}tr;
int get(int x)
{return (x+ans*ty)%n+1;}
int build(int l,int r)
{
	int mid=(l+r)>>1,ret=++cnt;
	if(l==r)return ret;
	ch[ret][0]=build(l,mid);
	ch[ret][1]=build(mid+1,r);
	return ret;
}
int cop(int x)
{
	int ret=++cnt;
	ch[ret][0]=ch[x][0];ch[ret][1]=ch[x][1];
	bj[ret]=bj[x];tim[ret]=tim[x];
	return ret;
}
void add(int &x,int v,int tm)
{
	x=cop(x);
	bj[x]=v;tim[x]=tm;
}
void pushdown(int &now)
{
	if(bj[now])
	{
		add(ch[now][0],bj[now],tim[now]);
		add(ch[now][1],bj[now],tim[now]);
		bj[now]=0;
	}
}
void insert(int l,int r,int &now,int lq,int rq,int v,int tm)
{
	now=cop(now);
	if(lq<=l&&r<=rq)
	{add(now,v,tm);return;}
	int mid=(l+r)>>1;
	pushdown(now);
	if(mid>=lq)insert(ls,lq,rq,v,tm);
	if(mid<rq) insert(rs,lq,rq,v,tm);
}
int query(int l,int r,int &now,int pos)
{
	now=cop(now);
	if(l==r)return now;
	int mid=(l+r)>>1;
	pushdown(now);
	if(mid>=pos)return query(ls,pos);
	else return query(rs,pos);
}
void update(int l,int r,int &now,int pos)
{
	now=cop(now);
	if(l==r)
	{
		if(tim[now])
		{
			now=query(1,n,root[tim[now]-1],l);
			tr.update(1,n,1,l,l,bj[now]);
		}
		return;
	}
	int mid=(l+r)>>1;
	pushdown(now);
	if(mid>=pos)update(ls,pos);
	else update(rs,pos);
}
