#include<bits/stdc++.h>
using namespace std;
int root[500050];
int n, m, ty;
struct node
{
	int val;
	int lazy;
	int last;
	int ch[2];
	void noding(int vv, int ll, int rr, int lastt, int lazyy) {
		val = vv;
		ch[0] = ll;
		ch[1] = rr;
		last = lastt;
		lazy = lazyy;
	}
};
node pool[50333333];
int ti = 0;
void update(node &r)
{
	if (!r.ch[0] && !r.ch[1])
		return ;
	else
		r.val = pool[r.ch[0]].val + pool[r.ch[1]].val;
}

void down(node &r, int rst, int red)
{
	if (!r.ch[0] || !r.ch[1] || !r.lazy)
		return ;
	int ch0 = ++ti;
	int mid = (rst + red) >> 1;
	pool[ch0].noding(r.lazy * (mid - rst + 1),
	pool[r.ch[0]].ch[0], pool[r.ch[0]].ch[1], r.last, r.lazy);//////////////////////////
	int ch1 = ++ti;
	pool[ch1].noding(r.lazy * (red - mid),
	pool[r.ch[1]].ch[0], pool[r.ch[1]].ch[1], r.last, r.lazy);////////////////////////////
	r.ch[0] = ch0;
	r.ch[1] = ch1;
	r.lazy = 0;
}

int build(int st, int ed)
{
	if (st == ed) {
		int ne = ++ti;
		pool[ne].noding(0, 0, 0, 0, 0);
		return ne;
	}
	int mid = (st + ed) >> 1;
	int ne = ++ti;
	pool[ne].noding(0, build(st, mid), build(mid + 1, ed), 0, 0);
	return ne;
}

int add(int ol, int oltime, int st, int ed, int x, int rst, int red)
{
	if (st <= rst && red <= ed) {
		int ne = ++ti;
		pool[ne].noding(x * (red - rst + 1), pool[ol].ch[0], pool[ol].ch[1], oltime, x);
		return ne;
	}
	down(pool[ol], rst, red);
	int ne = ++ti;
	pool[ne] = pool[ol];
	int mid = (rst + red) >> 1;
	if (st <= mid)
		pool[ne].ch[0] = add(pool[ol].ch[0], oltime, st, ed, x, rst, mid);
	if (mid + 1 <= ed)
		pool[ne].ch[1] = add(pool[ol].ch[1], oltime, st, ed, x, mid + 1, red);
	update(pool[ne]);
	return ne;
}

node find(node r, int goal, int rst, int red)
{
	if (rst == red)
		return r;
	if (r.lazy) {
		node ne;
		ne.noding(r.lazy, 0, 0, r.last, r.lazy);
		return ne;//////////////////////////////ne;//////////////////////////////ne;//////////////////////////////
	}
	down(r, rst, red);
	int mid = (rst + red) >> 1;
	if (goal <= mid)
		return find(pool[r.ch[0]], goal, rst, mid);
	else
		return find(pool[r.ch[1]], goal, mid + 1, red);
}

void exit(node &r, int pos, int rst, int red)
{
	if (rst == red) {
		if (!r.last)
			r.val = 0, r.lazy = 0;
		else
			r = find(pool[root[r.last]], pos, 1, n);
		return ;
	}
	down(r, rst, red);
	int mid = (rst + red) >> 1;
	if (pos <= mid)
		exit(pool[r.ch[0]], pos, rst, mid);
	if (mid + 1 <= pos)
		exit(pool[r.ch[1]], pos, mid + 1, red);
	update(r);
}

int ask(node &r, int st, int ed, int rst, int red)
{
	if (st <= rst && red <= ed)
		return r.val;
	int pans = 0;
	if (r.lazy)
		return (min(red, ed) - max(rst, st) + 1) * r.lazy;
	int mid = (rst + red) >> 1;
	if (st <= mid)
		pans += ask(pool[r.ch[0]], st, ed, rst, mid);
	if (mid + 1 <= ed)
		pans += ask(pool[r.ch[1]], st, ed, mid + 1, red);
	return pans;
}

void order(int r, int st, int ed)
{
	if (!r)
		return ;
	int mid = (st + ed) >> 1;
	order(pool[r].ch[0], st, mid);
	order(pool[r].ch[1], mid + 1, ed);
	cout << "this is " << r << " , (" << st << " " << ed << ") " << pool[r].val << " " << pool[r].lazy << " {"
		 << pool[r].ch[0] << " " << pool[r].ch[1] << "} " << pool[r].last << endl;
}

