 *algorithm: functional segement tree
 *ac mark: @
 *note:
	important!
	this is an perfect example of functional segement tree.
	blocks editing, single editing, memory pool.
	be aware of when to down in add.
	the sign of "last" in FST is always a time sign, a root sign,
	and you need to use the "find" function to find the exact place of "last".

 */
#include<bits/stdc++.h>
using namespace std;
int root[500050];
int n, m, ty;
struct node
{
	int val;
	int lazy;
	int last;
	int ch[2];
	void noding(int vv, int ll, int rr, int lastt, int lazyy) {
		val = vv;
		ch[0] = ll;
		ch[1] = rr;
		last = lastt;
		lazy = lazyy;
	}
};
node pool[43333333];
bool flag[43333333] = {0};
int ti = 0;
int cnt = 0;
void update(node &r)
{
	if (!r.ch[0] && !r.ch[1])
		return ;
	else
		r.val = pool[r.ch[0]].val + pool[r.ch[1]].val;
}

void down(node &r, int rst, int red, int num)
{
	if (!r.ch[0] || !r.ch[1] || !r.lazy)
		return ;
//	cout << "there is a down" << endl;
	int ch0, ch1;
	if (flag[num]) {
//		cout << "seceed " << endl;
		ch0 = r.ch[0], ch1 = r.ch[1];
	}
	else {
//		cerr << "no" << endl;
		ch0 = ++ti, ch1 = ++ti;
	}
	int mid = (rst + red) >> 1;
	pool[ch0].noding(r.lazy * (mid - rst + 1),
	pool[r.ch[0]].ch[0], pool[r.ch[0]].ch[1], r.last, r.lazy);//////////////////////////
	pool[ch1].noding(r.lazy * (red - mid),
	pool[r.ch[1]].ch[0], pool[r.ch[1]].ch[1], r.last, r.lazy);////////////////////////////
	r.ch[0] = ch0;
	r.ch[1] = ch1;
 	r.lazy = 0;
// 	cout << "put flag " << num << endl;
 	flag[num] = 1;
}

int build(int st, int ed)
{
	if (st == ed) {
		int ne = ++ti;
		pool[ne].noding(0, 0, 0, 0, 0);
		return ne;
	}
	int mid = (st + ed) >> 1;
	int ne = ++ti;
	pool[ne].noding(0, build(st, mid), build(mid + 1, ed), 0, 0);
	//flag[ne] = 1;
	return ne;
}

int add(int ol, int oltime, int st, int ed, int x, int rst, int red, int num, bool dir)
{
//	cout << "in add " << rst << " " << red << " " << st << " " << ed << endl;
	if (st <= rst && red <= ed) {
		int ne = ++ti;
		pool[ne].noding(x * (red - rst + 1), pool[ol].ch[0], pool[ol].ch[1], oltime, x);
		return ne;
	}
	
	int ne;
	if (flag[num]) {
//		cout << "good  " << rst << " " << red << " " << st << " " << ed << " " << x << endl;
		ne = pool[num].ch[dir];
	}
	else {
//		cout << "create" << endl;
		ne = ++ti;
		pool[ne] = pool[ol];
	}
	
	int mid = (rst + red) >> 1;
	down(pool[ne], rst, red, ne);
	if (st <= mid) {
//		cout << "going " << rst << " " << red << " " 
//		<< pool[ol].ch[0] << " " << pool[ne].ch[0] << endl;
		pool[ne].ch[0] = add(pool[ol].ch[0], oltime, st, ed, x, rst, mid, ne, 0);
	}
	if (mid + 1 <= ed) {
//		cout << "going " << rst << " " << red << " " 
//		<< pool[ol].ch[0] << " " << pool[ne].ch[0] << endl;
		pool[ne].ch[1] = add(pool[ol].ch[1], oltime, st, ed, x, mid + 1, red, ne, 1);
	}
	update(pool[ne]);
	
	return ne;
}

void find(node r, int goal, int rst, int red, int num, node &rr)
{
	if (rst == red) {
		rr = r;
//		cout << "found ! " << r.val << " " << rst << " " << red << endl;
		return ;
	}
	if (r.lazy) {
		rr.noding(r.lazy, 0, 0, r.last, r.lazy);
		return ;
	}
	down(r, rst, red, num);
	int mid = (rst + red) >> 1;
	if (goal <= mid)
		find(pool[r.ch[0]], goal, rst, mid, r.ch[0], rr);
	else
		find(pool[r.ch[1]], goal, mid + 1, red, r.ch[1], rr);
}

void exit(node &r, int pos, int rst, int red, int num)
{
	if (rst == red) {
		if (!r.last)
			r.val = 0, r.lazy = 0;
		else {
//			cout << "pre find " << r.last << " " << pos << " " << pool[root[r.last]].val << endl; 
			find(pool[root[r.last]], pos, 1, n, root[cnt], r);
		}
		return ;
	}
	down(r, rst, red, num);
	int mid = (rst + red) >> 1;
	if (pos <= mid)
		exit(pool[r.ch[0]], pos, rst, mid, r.ch[0]);
	if (mid + 1 <= pos)
		exit(pool[r.ch[1]], pos, mid + 1, red, r.ch[1]);
	update(r);
}

int ask(node &r, int st, int ed, int rst, int red)
{
	if (st <= rst && red <= ed)
		return r.val;
	int pans = 0;
	if (r.lazy)
		return (min(red, ed) - max(rst, st) + 1) * r.lazy;
	int mid = (rst + red) >> 1;
	if (st <= mid)
		pans += ask(pool[r.ch[0]], st, ed, rst, mid);
	if (mid + 1 <= ed)
		pans += ask(pool[r.ch[1]], st, ed, mid + 1, red);
	return pans;
}

void order(int r, int st, int ed)
{
	if (!r)
		return ;
	int mid = (st + ed) >> 1;
	order(pool[r].ch[0], st, mid);
	order(pool[r].ch[1], mid + 1, ed);
	cout << "this is " << r << " , (" << st << " " << ed << ") " << pool[r].val << " " << pool[r].lazy << " {"
		 << pool[r].ch[0] << " " << pool[r].ch[1] << "} " << pool[r].last << endl;
}

