struct data {
	int s[2];
	int tag,sum;
}t[maxn*100];
int n,m,ty,cnt,last,tmp[maxn],rt[maxn];
void pushup(int o) {t[o].sum=t[t[o].s[0]].sum+t[t[o].s[1]].sum;}
void pushdown(int o,int l,int r) {
	if(!t[o].tag) return;
	int mid=(l+r)>>1;
	t[++cnt]=t[t[o].s[0]];
	t[cnt].tag=t[o].tag;t[cnt].sum=(mid-l+1)*tmp[t[o].tag];t[o].s[0]=cnt;
	t[++cnt]=t[t[o].s[1]];
	t[cnt].tag=t[o].tag;t[cnt].sum=(r-mid)*tmp[t[o].tag];t[o].s[1]=cnt;
	t[o].tag=0;
}
inline void add(int l,int r,int &o,int x,int L,int R,int ad){
	if(!o) o=++cnt,t[o]=t[x];
	if(L<=l&&R>=r){t[o].tag=ad;t[o].sum=(r-l+1)*tmp[ad];return;}
	int gg=t[o].tag;
	pushdown(o,l,r);
	int mid=(l+r)>>1;
	if(L<=mid) {if(!gg) t[o].s[0]=0; add(l,mid,t[o].s[0],t[x].s[0],L,R,ad);}
	if(R>mid) {if(!gg) t[o].s[1]=0; add(mid+1,r,t[o].s[1],t[x].s[1],L,R,ad);}
	pushup(o);
}
int query1(int l,int r,int o,int L,int R) {
    if(L<=l&&R>=r) return t[o].sum;
	int mid=(l+r)>>1;
    pushdown(o,l,r);
    int ans=0;
    if(L<=mid) ans+=query1(l,mid,t[o].s[0],L,R);
    if(R>mid) ans+=query1(mid+1,r,t[o].s[1],L,R);
    return ans;
}
int query2(int l,int r,int o,int x) {
    if(l==r) return t[o].tag;
	int mid=(l+r)>>1;
    pushdown(o,l,r);
    if(x<=mid) return query2(l,mid,t[o].s[0],x);
    else return query2(mid+1,r,t[o].s[1],x);
}
