struct node{
  int x, y, d;

  node() {}
  node(int _x,int _y,int _d)
    :x(_x), y(_y), d(_d) {}

  bool operator == (const node& rhs) const{
    return x == rhs.x && y == rhs.y;
  }
};

bool cmpx(const node& a,const node& b) {
  return a.x < b.x || (a.x == b.x && a.y < b.y);
}

bool cmpy(const node& a,const node& b) {
  return a.y < b.y || (a.y == b.y && a.x < b.x);
}

const int maxN = 1e5+5, maxL = 3e6, maxM = 1e7;

int N, M, C;

int arrx[maxL], totx;
int arry[maxL], toty;

int tot, cnt;
node A[maxN];
node B[maxL];

int L, R, U, D;

struct edge{
  int next, to;
  edge() {}
  edge(int x,int y):
    next(x), to(y) {}
};

edge E[maxM];
int head[maxL], totE;

void addedge(int u,int v) {
  E[++totE] = edge(head[u], v); head[u] = totE;
  E[++totE] = edge(head[v], u); head[v] = totE;
}

void connectx() {
  std::sort(A + 1, A + C + 1, cmpx);
  
  for(int a = 1,b = 1,i = 1;i <= tot; ++i) {
    node t = B[i];
    while(a <= C && cmpx(A[a], t)) ++a;
    if(a <= C && A[a] == t) continue;
    
    ++cnt, ++t.y;
    
    while(a <= C && cmpx(A[a], t)) ++a;
    while(b <= tot && cmpx(B[b], t)) ++b;
    
    if(b <= tot && B[b].x == B[i].x && B[b].y > B[i].y && (a > C || cmpx(B[b], A[a])))
      addedge(B[i].d, B[b].d);
  }
}

void connecty() {
  std::sort(A + 1, A + C + 1, cmpy);
  std::sort(B + 1, B + tot + 1, cmpy);
  
  for(int a = 1,b = 1,i = 1;i <= tot; ++i) {
    node t = B[i];
    while(a <= C && cmpy(A[a], t)) ++a;
    if(a <= C && A[a] == t) continue;
    
    ++t.x;
    
    while(a <= C && cmpy(A[a], t)) ++a;
    while(b <= tot && cmpy(B[b], t)) ++b;
    
    if(b <= tot && B[b].y == B[i].y && B[b].x > B[i].x && (a > C || cmpy(B[b], A[a])))
      addedge(B[i].d, B[b].d);
  }
}

int dft, cut;
int dfn[maxL];
int low[maxL];

void dfs(int u,int pre) {
  low[u] = dfn[u] = ++dft;

  int son = 0;
  for(int e = head[u], v; e; e = E[e].next) {
    v = E[e].to;
    if(v == pre) continue;
    if(!dfn[v]) {
      dfs(v, u); ++son;
      umin(low[u], low[v]);
      if(pre && dfn[u] <= low[v])
	cut = 1;
    }else 
      umin(low[u], dfn[v]);
  }

  if(!pre && son >= 2) cut = 1;
}

void exec() {
  read(N), read(M), read(C);

  totE = totx = toty = tot = cnt = dft = cut = 0;
  
  for(int i = 1;i <= C; ++i) {
    int x, y; read(x), read(y);
    
    A[i] = node(x, y, 0);
    arrx[++totx] = x; arry[++toty] = y;
    if(x > 1) arrx[++totx] = x-1, B[++tot] = node(x-1, y, i);
    if(y > 1) arry[++toty] = y-1, B[++tot] = node(x, y-1, i);
    if(x < N) arrx[++totx] = x+1, B[++tot] = node(x+1, y, i);
    if(y < M) arry[++toty] = y+1, B[++tot] = node(x, y+1, i);
    if(x > 1 && y > 1) B[++tot] = node(x-1, y-1, 0);
    if(x > 1 && y < M) B[++tot] = node(x-1, y+1, 0);
    if(x < N && y > 1) B[++tot] = node(x+1, y-1, 0);
    if(x < N && y < M) B[++tot] = node(x+1, y+1, 0);
  }

  if((i64) N * M - C <= 1) return (void) puts("-1");

  U = *std::min_element(arrx+1, arrx+totx+1);
  D = *std::max_element(arrx+1, arrx+totx+1);
  L = *std::min_element(arry+1, arry+toty+1);
  R = *std::max_element(arry+1, arry+toty+1);
  
  L > 1 && --L;
  U > 1 && --U;
  D < N && ++D;
  R < M && ++R;

  arrx[++totx] = U; arrx[++totx] = D;
  arry[++toty] = L; arry[++toty] = R;

  std::sort(arrx+1, arrx+totx+1);
  std::sort(arry+1, arry+toty+1);

  totx = std::unique(arrx+1, arrx+totx+1)-arrx-1;
  toty = std::unique(arry+1, arry+toty+1)-arry-1;

  for(int i = 1;i <= totx; ++i) {
    B[++tot] = node(arrx[i], arry[1], 0);
    B[++tot] = node(arrx[i], arry[toty], 0);
  }

  for(int i = 1;i <= toty; ++i) {
    B[++tot] = node(arrx[1], arry[i], 0);
    B[++tot] = node(arrx[totx], arry[i], 0);
  }
  
  for(int i = 1;i <= C; ++i) {
    A[i].x = std::lower_bound(arrx+1, arrx+totx+1, A[i].x)-arrx;
    A[i].y = std::lower_bound(arry+1, arry+toty+1, A[i].y)-arry;
  }

  std::sort(B + 1,B + tot + 1, cmpx);
  tot = std::unique(B + 1,B + tot + 1) - B - 1;
  
  for(int i = 1;i <= tot; ++i) {
    B[i].x = std::lower_bound(arrx+1, arrx+totx+1, B[i].x)-arrx;
    B[i].y = std::lower_bound(arry+1, arry+toty+1, B[i].y)-arry;
    B[i].d = i;
  }

  memset(head, 0, (tot + 5) * sizeof head[0]);
  memset(dfn, 0, (tot + 5) * sizeof dfn[0]);
  memset(low, 0, (tot + 5) * sizeof low[0]);
  connectx();
  connecty();
  
  if(E[1].to) dfs(E[1].to, 0);
  
  if((i64) N * M - C == 2 && (dft == 2 || !C)) return (void) puts("-1");
  if((i64) N * M - C >= 2 && dft < cnt) return (void) puts("0");
  if(N == 1 || M == 1 || (dft == cnt && cut)) return (void) puts("1");
  puts("2");
}

