		for (int i = fir[x]; ~i; i = nxt[i]) if (v == val[i]) return id[i]; 
		return 0; 
	} 
} mp; 
const int dx[] = {-1, 0, 1, 0, -1, 1, 1, -1}; 
const int dy[] = {0, 1, 0, -1, 1, 1, -1, -1}; 
int tag[MAX_N * 25]; 
int N, M, C, tot; 
bool chk1() { 
	if (1ll * N * M - C <= 1) return 1; 
	if (1ll * N * M - C >= 3) return 0; 
	for (int i = 1; i <= N; i++) 
		for (int j = 1; j <= M; j++) { 
			if (mp.find((node){i, j})) continue; 
			for (int k = 0; k < 4; k++) { 
				int x = i + dx[k], y = j + dy[k]; 
				if (x < 1 || x > N || y < 1 || y > M) continue; 
				if (!mp.find((node){x, y})) return 1; 
			} 
			return 0; 
		} 
	return 0; 
} 
int bel[MAX_N * 25], tim; 
node Q[MAX_N * 25];
int head, tail; 
void bfs1(node s, int sid) { 
	Q[head = tail = 1] = s, bel[sid] = tim; 
	while (head <= tail) { 
		node p = Q[head++]; 
		int x = p.x, y = p.y; 
		for (int i = 0; i < 4; i++) { 
			int _x = x + dx[i], _y = y + dy[i]; 
			if (_x < 1 || _x > N || _y < 1 || _y > M) continue; 
			int nxt = mp.find((node){_x, _y}); 
			if (!nxt || tag[nxt] == 2 || bel[nxt]) continue; 
			bel[nxt] = tim, Q[++tail] = (node){_x, _y}; 
		}  
	} 
} 
bool vis[MAX_N * 25]; 
void bfs2(node s, int sid) {
	Q[head = tail = 1] = s, vis[sid] = tim; 
	while (head <= tail) { 
		node p = Q[head++]; 
		int x = p.x, y = p.y; 
		for (int i = 0; i < 8; i++) { 
			int _x = x + dx[i], _y = y + dy[i]; 
			if (_x < 1 || _x > N || _y < 1 || _y > M) continue; 
			int nxt = mp.find((node){_x, _y}); 
			if (tag[nxt] != 2 || vis[nxt]) continue; 
			vis[nxt] = 1, Q[++tail] = (node){_x, _y}; 
		}  
	} 
} 
bool chk2() {
	tim = 0; 
	for (int i = 0; i < mp.cnt; i++) { 
		int id = mp.id[i]; 
		node p = mp.val[i]; 
		if (bel[id] || tag[id] == 2) continue; 
		++tim, bfs1(p, id); 
	} 
	for (int i = 0; i < mp.cnt; i++) { 
		int id = mp.id[i]; 
		node p = mp.val[i]; 
		if (vis[id] || tag[id] != 2) continue; 
		bfs2(p, id); 
		int col = 0; 
		for (int j = 1; j <= tail; j++) { 
			int x = Q[j].x, y = Q[j].y; 
			for (int k = 0; k < 4; k++) { 
				int _x = x + dx[k], _y = y + dy[k]; 
				if (_x < 1 || _x > N || _y < 1 || _y > M) continue; 
				int nxt = mp.find((node){_x, _y}); 
				if (!nxt || tag[nxt] == 2) continue; 
				if (col && bel[nxt] != col) return 1; 
				else col = bel[nxt]; 
			} 
		} 
	} 
	return 0; 
} 
struct Graph { int to, next; } e[MAX_N << 6]; 
int fir[MAX_N * 25], e_cnt; 
void Add_Edge(int u, int v) { e[e_cnt] = (Graph){v, fir[u]}, fir[u] = e_cnt++; } 
int dfn[MAX_N * 25], low[MAX_N * 25], cut[MAX_N * 25]; 
void tarjan(int x, int fa) { 
	cut[x] = 0, low[x] = dfn[x] = ++tim; 
	int sz = 0; 
	for (int i = fir[x]; ~i; i = e[i].next) { 
		int v = e[i].to; if (v == fa) continue; 
		if (!dfn[v]) { 
			++sz, tarjan(v, x); 
			if (low[v] >= dfn[x]) cut[x] = 1; 
			low[x] = min(low[x], low[v]); 
		} 
		else low[x] = min(low[x], dfn[v]); 
	} 
	if (!fa && sz == 1) cut[x] = 0; 
} 
bool chk3() { 
	e_cnt = 0; for (int i = 1; i <= tot; i++) fir[i] = -1; 
	tim = 0; for (int i = 1; i <= tot; i++) dfn[i] = low[i] = cut[i] = 0; 
	for (int i = 0; i < mp.cnt; i++) { 
		int x = mp.val[i].x, y = mp.val[i].y, id = mp.id[i];
		if (tag[id] == 2) continue; 
		for (int j = 0; j < 4; j++) { 
			int _x = x + dx[j], _y = y + dy[j]; 
			if (_x < 1 || _x > N || _y < 1 || _y > M) continue; 
			int nxt = mp.find((node){_x, _y}); 
			if (!nxt || tag[nxt] == 2) continue; 
			Add_Edge(id, nxt); 
		} 
	} 
	for (int i = 1; i <= tot; i++) 
		if (!dfn[i]) tarjan(i, 0); 
	for (int i = 1; i <= tot; i++) if (tag[i] == 1 && cut[i]) return 1; 
	return 0; 
} 
void solve() { 
	for (int i = 1; i <= C; i++) mp.insert(a[i], ++tot), tag[tot] = 2; 
	if (chk1()) return (void)puts("-1"); 
	for (int i = 1; i <= C; i++) 
		for (int j = -2; j <= 2; j++)
			for (int k = -2; k <= 2; k++) { 
				int x = a[i].x + j, y = a[i].y + k; 
				if (x < 1 || x > N || y < 1 || y > M || (!j && !k)) continue; 
				int res = mp.find((node){x, y}); 
				if (res) { 
					if (tag[res] != 2 && abs(j) < 2 && abs(k) < 2) tag[res] = 1; 
					continue; 
				} 
				mp.insert((node){x, y}, ++tot); 
				if (abs(j) < 2 && abs(k) < 2) tag[tot] = 1; 
			} 
	if (chk2()) return (void)puts("0"); 
	if (N == 1 || M == 1 || chk3()) return (void)puts("1"); 
	puts("2"); 
} 
int main () { 
	int T = gi(); 
	while (T--) { 
		mp.clear(); 
		N = gi(), M = gi(), C = gi(); 
		for (int i = 1; i <= C; i++) a[i] = (node){gi(), gi()}; 
		solve(); 
		for (int i = 1; i <= tot; i++) tag[i] = bel[i] = 0, vis[i] = 0; 
		tot = 0; 
	} 
    return 0; 
}

