enum {
  LINEUP = 5200000 + 5,
  MAXK = 2000 + 5,
  MAXSIZE = 100000 + 5,
  LIMIT = 40000
};

typedef long long i64;
typedef std::pair<int, int> pii;

#define MK(X,Y) ((i64) (X)*1000000000 + (Y))

int n, m, k;

std::tr1::unordered_map<i64, i64> map[MAXK], mmap;

int mu[LINEUP];
int mus[LINEUP];

struct MU {
  int N;

  int xn;
  int X[MAXSIZE];

  int pos(int p) {
    if ((i64) p*p <= N)
      return p - 1;
    else
      return xn - N/p;
  }
  
  int mus[MAXSIZE];
  
  void exec(int _N) {
    int d, last, i, p;
    N = _N;
    
    xn = 0;
    for (d=1; d<=N; d=last+1) {
      last = N/(N/d);
      X[xn++] = last;
    }

    for (i=0; i<xn; ++i) {
      p = pos(X[i]);
      if (X[i] < LINEUP)
	mus[p] = ::mus[X[i]];
      else {
	mus[p] = 1;
	for (d=2; d<=X[i]; d=last+1) {
	  last = X[i]/(X[i]/d);
	  mus[p] -= mus[pos(X[i]/d)] * (last-d+1);
	}
      }
    }
  }
} forN, forM;

// inline int calcmu(int x) {
//   if (n / (n/x) == x)
//     return forN.mus[forN.pos(x)];
//   else
//     return forM.mus[forM.pos(x)];
// }

i64 calc(int N, int M) {
  int d, last, lastv(0), nowv, lst1, lst2;
  i64 res(0);

  if (M < N) std::swap(N, M);
  if (mmap.count(MK(N, M))) return mmap[MK(N, M)];

  bool flag(n / (n / N) == N && m / (m / M) == M);
  
  for (d=1; d<=N; d=last+1) {
    lst1 = N / (N/d), lst2 = M / (M/d);
    last = std::min(lst1, lst2);
    if (last<LINEUP) nowv = mus[last];
    else if ((last == lst1) ^ flag)
      nowv = forM.mus[forM.pos(last)];
    else
      nowv = forN.mus[forN.pos(last)];
    res += (i64) (nowv - lastv) * (N/d) * (M/d);
    lastv = nowv;
  }

  return mmap[MK(N, M)] = res;
}

i64 F(int K, int N, int M) {
  int d;
  i64 res(0);
  
  if (N == 0 || M == 0) return 0;
  
  if (map[K].count(MK(N, M))) return map[K][MK(N, M)];

  if (K == 1)
    return map[K][MK(N, M)] = calc(N, M);
  
  for (d=1; d*d<=K; ++d)
    if (K % d == 0) {
      res += (i64) mu[d] * F(d, M/d, N);
      if (d*d != K)
	res += (i64) mu[K/d] * F(K/d, M/(K/d), N);
    }
  
  return map[K][MK(N, M)] = res;
}

bool ish[LINEUP];

int totp;
int pri[LINEUP];

void exec() {
  int i, j, x;

  scanf("%d%d%d", &n, &m, &k);

  mu[1] = 1;
  mus[1] = 1;
  
  for (i=2; i<LINEUP; ++i) {
    if (!ish[i]) {
      pri[totp++] = i;
      mu[i] = -1;
    }
    for (j=0; (x = i*pri[j]) < LINEUP; ++ j) {
      ish[x] = true;
      if (i%pri[j] == 0) {
	mu[x] = 0;
	break;
      } else
	mu[x] = -mu[i];
    }
    mus[i] = mus[i-1] + mu[i];
  }
  
  forN.exec(n), forM.exec(m);
  printf("%lld\n", F(k, n, m));
}

