class SegmentTree{
private:
    vi st;
    vi mark;
void rm(int p,int l ,int r) {
    if (l==r) {
        st[p] += mark[p];
        mark[p] = 0;
    }
    else {
        mark[(p<<1)] += mark[p];
        mark[(p<<1)|1] += mark[p];
        st[p] += mark[p];
        mark[p] = 0;
    }
}

    void range_update(int p,int l,int r,int a,int b,int v){
            rm(p,l,r);

            if (a>r || b<l) return;
		            if (l==r) {
                st[p]+=v;
                return;
            }
            if (a<=l && b>=r) {
                st[p] += v;
                mark[(p<<1)]+= v;
                mark[(p<<1)|1]+= v;
            }
            else {
                int mid = (l+r)/2;
                range_update((p<<1),l,mid,a,b,v);
                range_update((p<<1)|1,mid+1,r,a,b,v);
                st[p] = max(st[(p<<1)],st[(p<<1)|1]);
            }
    }

    int rmq(int p,int l,int r,int a,int b){
        rm(p,l,r);

        if (a>r || b<l) return 0;
		  	if (l==r) return st[p];
        if (a<=l && b>=r) {
           return st[p];
        }
        else {
            int mid = (l+r)/2;
            int lm = rmq((p<<1),l,mid,a,b);
            int rm = rmq((p<<1)|1,mid+1,r,a,b);
            st[p] = max(lm,rm);
            return st[p];
        }
    }
    
public:
    int N;
    void build(int x){
        st.assign(4*x,0);
        mark.assign(4*x,0);
        N = x;
    }
    int rmq(int a,int b){return rmq(1,0,N,a,b);}
    void range_update(int a,int b,int v){range_update(1,0,N,a,b,v);}
    
}st;

bool mycmp(node a,node b){
    return (a.len < b.len);
}

bool mycmp2(ii a,ii b){
    return (a.first < b.first);
}

void solve(int x, int y,int t){
    
    if (y == n)
    return;
    
    if (t)
    st.range_update(no[y].left,no[y].right,1);
    
    int a = st.rmq(no[y].left,no[y].right);
  // printf("x=%d y=%d a=%d\n",x,y,a);
    if (a >= m) {
    //	int diff= (no[y].len)-(no[x].len);
    //	cout << "diff = " << diff << endl;
        minlen = min(minlen,((no[y].len)-(no[x].len)));
        st.range_update(no[x].left,no[x].right,-1);
        solve(x+1,y,0);
    }
    else solve(x,y+1,1);
    
}

