int digit = 1000000000;
struct Decimal {
	int inte;
	int deci[ int( PREC * DIGIT / 9 ) ];

	void clear() {
		inte = 0; memset( deci, 0, sizeof( deci ) );
	}

	void operator -= ( const Decimal &A ) {
		inte -= A.inte;
		ROF ( i, p, 1 ) { deci[ i ] -= A.deci[ i ]; if ( deci[ i ] < 0 ) deci[ i ] += digit, deci[ i - 1 ]--; }
		deci[ 0 ] -= A.deci[ 0 ]; if ( deci[ 0 ] < 0 ) deci[ 0 ] += digit, inte--;
	}

	void operator /= ( int d ) {
		ll pre = deci[ 0 ] + ( inte % d ) * (ll)digit; inte /= d;
		FOR ( i, 0, p ) { deci[ i ] = pre / d; pre = deci[ i + 1 ] + ( pre % d ) * digit; }
	}
} ans, h1;

Decimal GetDec( int j, int i ) {
	if ( g[ j ][ i ] == 0 ) return h1;
	else {
		Decimal bef = GetDec( j - 1, g[ j ][ i ] ), ret;
		if ( g[ j ][ i ] != i ) {
			ret.clear(); ret.inte = s[ g[ j ][ i ] ]; ret -= bef; bef.clear(); bef.inte = s[ i ]; bef -= ret; ret = bef; ret /= i - ( g[ j ][ i ] - 1 );
		}
		else ret = bef;
		return ret;
	}
}

int main() {
	scanf( "%d%d%d", &n, &m, &d ); p = ( int( PREC * d ) + 8 ) / 9; m = min( n, m );
	FOR ( i, 1, n ) { scanf( "%d", &h[ i ] ); }
	sort( h + 2, h + n + 1 ); h1.inte = h[ 1 ];
	FOR ( i, 1, n ) { s[ i ] = s[ i - 1 ] + h[ i ]; }

	int LIM = 15, larg = min( m, LIM );

	FOR ( i, 1, n ) { f[ 0 ][ i ] = h[ 1 ]; }
	FOR ( j, 0, larg ) { f[ j ][ 1 ] = h[ 1 ]; }

	FOR ( j, 1, larg ) {
		int las = 1, tail = 0;
		x[ ++tail ] = 0; y[ tail ] = s[ 1 ] - f[ j - 1 ][ 1 ];
		FOR ( i, 2, n ) {
			st[ las ] = ( s[ i ] - y[ las ] ) / ( i - x[ las ] );
			while ( las < tail ) {
				st[ las + 1 ] = ( s[ i ] - y[ las + 1 ] ) / ( i - x[ las + 1 ] );
