			f[ j ][ i ] = st[ las ]; g[ j ][ i ] = x[ las ] + 1;
			if ( f[ j ][ i ] < f[ j - 1 ][ i ] ) f[ j ][ i ] = f[ j - 1 ][ i ], g[ j ][ i ] = i;
			y0 = s[ i ] - f[ j - 1 ][ i ]; x0 = i - 1;
			while ( tail > 1 ) {
