const int MAXN = 8000 + 5;
    
int n, K, p;

int h[MAXN];
pii fr[MAXN][MAXN];
pii ansfr;

static i64 pre[MAXN];

Decimal print(const pii &sta) {
    if (sta.y == 0) return Decimal(h[0]);
    pii from = fr[sta.x][sta.y];
    Decimal res = print(from);
    if (sta.y == from.y)
        return res;
    else {
        int i = sta.x, j = from.x;
        return (pre[i] - pre[j] + res) / (i - j + 1);
    }
}

void solve()
{
