	}
	sort(a+1,a+m+1);
	for(int i=1;i<=m;i++)s[i]=s[i-1]+a[i],f[i]=a[1];
	K=min(K,m-1);
	Decimal ans=0;
	for(int i=1;i<=min(5,K);i++){
		q[l=r=1]=i;
		for(int j=i+1;j<=m-(K-i);j++){
			long double lst=(s[j]-s[q[l]]+f[q[l]])/(j-q[l]+1);
