			for(int k=vec[j]+1;k<=vec[j-1];k++)tmp+=a[k];
			tmp/=vec[j-1]-vec[j]+1;
		}
		for(int j=m-(K-i)+1;j<=m;j++)tmp=(tmp+a[j])/2;
		ans=max(ans,tmp);
	}
