  return Point(lhs * rhs.x, lhs * rhs.y);
}

inline f80 cross(const Point &a, const Point &b) {
  return a.x * b.y - a.y * b.x;
}

inline f80 cross(const Point &o, const Point &a, const Point &b) {
  return (a.x - o.x) * (b.y - o.y) - (a.y - o.y) * (b.x - o.x);
}

int n;

struct Line {
  Point st, ed;
  Line() {}
  Line(const Point &_st, const Point &_ed): st(_st), ed(_ed) {}
} line[N];

inline Point intersection(const Line &u, const Line &v) {
  Point a = u.ed - u.st, b = v.ed - v.st, s = v.st - u.st;
  return u.st + cross(s, b) / cross(a, b) * a;
}

u64 mask[N];
std::set<u64> pool;

inline u64 calc(const Point &p) {
  u64 res = 0;
  for (int i = 0; i < n; ++i) if (cross(line[i].st, line[i].ed, p) >= 0.L) res ^= mask[i];
  return res;
}

void init() {
  static std::pair<f80, int> event[2 * N];
  for (int i = 0; i < n; ++i) {
    event[2 * i] = std::make_pair(line[i].st.arg(), i);
    event[2 * i + 1] = std::make_pair(line[i].ed.arg(), i);
  }
  std::sort(event, event + 2 * n);
  for (int i = 0; i < n; ++i) mask[i] = gen();
  u64 cur = calc(Point(L, -.5));
  pool.clear();
  pool.insert(cur);
  for (int i = 0; i < 2 * n; ++i) pool.insert(cur ^= mask[event[i].snd]);
}

int main() {
  srand(19937);
  scanf("%d", &n);
  for (int i = 0; i <= n; ++i) {
    int x1, y1, x2, y2;
    scanf("%d%d%d%d", &x1, &y1, &x2, &y2);
    if (x1 == x2) {
      line[i] = Line(Point(x1, -L), Point(x1, L));
      continue;
    }
    Point st(x1, y1), ed(x2, y2);
    Point p = st, v = ed - st;
    st = p + (-L - p.x) / v.x * v;
    ed = p + (L - p.x) / v.x * v;
    line[i] = Line(st, ed);
  }
  init();
  static std::pair<Point, int> query[N];
  for (int i = 0; i < n; ++i) query[i] = std::make_pair(intersection(line[n], line[i]), i);
  std::sort(query, query + n);
  static char ans[N];
  ans[0] = ans[n] = '0';
  u64 cur = calc(line[n].st);
  for (int i = 1; i < n; ++i) ans[i] = '1' - pool.count(cur ^= mask[query[i - 1].snd]);
  puts(ans);
  return 0;
}

