int Log[MAXN], mx[MAXN][LOG], mn[MAXN][LOG];
int n, a[MAXN], ans[MAXN];

void RMQ_init(){
	for(int j = 1; (1<<j) <= n; j++)
	  for(int i = 1; (i+(1<<j)-1) <= n; i++){
	      mx[i][j] = max(mx[i][j-1], mx[i+(1<<(j-1))][j-1]);
	      mn[i][j] = min(mn[i][j-1], mn[i+(1<<(j-1))][j-1]);
	    //  printf("mx[%d][%d] = %d mn[%d][%d] = %d\n", i, j, mx[i][j], i, j, mn[i][j]);
	  }
}

int query(int L, int R){
	int Max, Min, len = R-L, k = Log[len];
	
	Max = max(mx[L][k], mx[R-(1<<k)+1][k]);
	Min = min(mn[L][k], mn[R-(1<<k)+1][k]);
	
//	printf("L = %d R = %d Max = %d Min = %d\n", L, R, Max, Min);
	
	return Max-Min;
}

int cal(int k){
	int ans = INF;
    For(L, 1, n-k+1){
        int R = L+k-1;
		ans = min(ans, query(L, R));
	}
	return ans;
}

void solve(int L, int R){
	if(L >= R-1) return;
	
	if(ans[L] && 1.0*ans[R]/ans[L] <= 1.04){
		For(i, L+1, R-1) ans[i] = ans[L];
		return; 
	}
	
	int mid = (L+R)>>1;
	ans[mid] = cal(mid);
	solve(L, mid); solve(mid, R);
}

