	Set(mn, INF);
	For(i, 1, n){
		scanf("%d", &a[i]);
		if(i-1) Log[i] = Log[i/2]+1;
		mx[i][0] = mn[i][0] = a[i];
	}
	RMQ_init();

	bool ok = true;	
	int tmp = a[1];
	For(i, 2, n)
	  if(a[i] != tmp){
	      ok = false; break;
	  }
	
	if(!ok){
		ans[2] = cal(2); ans[n] = cal(n);
		solve(2, n);
	}
	For(i, 2, n) printf("%d\n", ans[i]);
	
	return 0;
}

