namespace fastCharStream{
	const int cacheSize=1<<12;
	char iCache[cacheSize];
	char *iHead=iCache+cacheSize;
	const char *iTail=iHead;
	opt char gc(){
		if(iHead==iTail){
			fread(iCache,1,cacheSize,stdin);
			iHead=iCache;
		}
		return *iHead++;
	}
	char oCache[cacheSize];
	const char *oTail=oCache+cacheSize;
	char *oHead=oCache;
	opt void pc(char x){
		if(oHead==oTail){
			fwrite(oCache,1,cacheSize,stdout);
			oHead=oCache;
		}
		*oHead++=x;
	}
	struct FileIOGuard{
		~FileIOGuard(){
			fwrite(oCache,1,oHead-oCache,stdout);
		}
	} fileIOGuard;
}
using fastCharStream::gc;
using fastCharStream::pc;
tpl opt void gd(T&ret){
	ret=0;char p=gc(),sig=1;
	for(;!isdigit(p)&&p!='-';p=gc());
	if(p=='-')sig=-1,p=gc();
	for(;isdigit(p);ret=ret*10-'0'+p,p=gc());
	ret*=sig;
}
tpl opt void pd(T v){
	static char x[26];
	char* i=x+24;
	*i=0;
	if(v==0)pc('0');
	else{
		for(;v;v/=10)*(--i)='0'+v%10;
		for(;*i;i++)pc(*i);
	}
}
#define N 300100
#define rep(i,f,l) for(int i=f,_=l;i<=_;i++)
#define repp(i,f,l) for(int i=f,_=l;i<_;i++)
#define clean(x) memset(x,0,sizeof x)
tpl struct EL{
	struct links{
		int nxt;T data;
	}*E;
	int*S,Et;
	opt EL(int n,int m){
		S=(int*)malloc(n*sizeof(int));
		memset(S,0,n*sizeof(int));
		E=(links*)malloc(m*sizeof(links));
	}
	opt void add(int x,T data){E[++Et]=(links){S[x],data};S[x]=Et;}
	opt T& operator[](int x){return E[x].data;}
#define repEL(i,X,s) for(int i=X.S[s];i;i=X.E[i].nxt)
};
EL<int>E(N,2*N),L(N,N),R(N,N),Sb(N,N);
int n,m,w[N];
struct QApair{
	int q;bool a;
};
EL<QApair>Q(N,2*N);
int u[N],dep[N];
bool vt[N];
opt int ufsFind(int x){
	if(u[x]==x)return x;
	return u[x]=ufsFind(u[x]);
}
opt void ufsUnion(int x,int y){
	if(x!=y){u[x]=y;}
}
opt void tlca(int u,int p,int dp){
	dep[u]=dp;
	repEL(i,E,u){
		int v=E[i];
		if(v!=p){
			tlca(v,u,dp+1);
			ufsUnion(v,u);
		}
	}
	vt[u]=1;
	repEL(i,Q,u){
		int v=Q[i].q;
		if(vt[v]){
			int lc=ufsFind(v),len=dep[u]+dep[v]-2*dep[lc]-(Q[i].a?dep[v]:dp);
			L.add(lc,Q[i].a?dp:dep[v]);
			R.add(lc,len);
			Sb.add(Q[i].a?v:u,len);
		}
	}
}
int lp[N],rp_[2*N],sig[N],ans[N];
int*rp=rp_+N;
opt void solve(int u,int p){
	int dp=dep[u];
	int la=lp[dp+w[u]],ra=rp[w[u]-dp];
	lp[dp]+=sig[u];
	repEL(i,Sb,u)rp[Sb[i]]++;
	repEL(i,E,u){
		int v=E[i];
		if(v!=p)solve(v,u);
	}
	repEL(i,R,u)rp[R[i]]--;
	ans[u]=lp[dp+w[u]]-la+rp[w[u]-dp]-ra;
	repEL(i,L,u)lp[L[i]]--;
}
void work(){
	gd(n);gd(m);
	repp(i,1,n){
		int x,y;
		gd(x);gd(y);
		E.add(x,y);E.add(y,x);
		u[i]=i;
	}
	rep(i,1,n)gd(w[i]);
	clean(sig);
	rep(i,1,m){
		int s,t;
		gd(s);gd(t);sig[s]++;
		Q.add(s,(QApair){t,1});if(s!=t)Q.add(t,(QApair){s,0});//If s==t,let lca only show once.
	}
	clean(vt);
	tlca(1,0,1);
	clean(ans);
	clean(lp);clean(rp_);
	solve(1,0);
	pd(ans[1]);
	rep(i,2,n){
		pc(' ');pd(ans[i]);
	}
}
int main(){
	work();
	return 0;
}

