procedure
  sort(l,r:longint);
var
  i,j,k,t:longint;
begin
  i:=l;j:=r;k:=a[(l+r) div 2];
  repeat
    while a[i]<k do inc(i);
    while k<a[j] do dec(j);
    if i<=j
    then begin
           t:=a[i];a[i]:=a[j];a[j]:=t;
           t:=b[i];b[i]:=b[j];b[j]:=t;
           inc(i);dec(j);
         end;
  until i>j;
  if l<j then sort(l,j);
  if i<r then sort(i,r);
end;

procedure
  travel(x:longint);
var
  i:longint;
begin
  d[x]:=d[f[x,0]]+1;
  for i:=p[x] to p[x+1]-1 do
    if b[i]<>f[x,0]
    then begin
           f[b[i],0]:=x;
           travel(b[i]);
         end;
end;

function
  get(x,y:longint):longint;
var
  i:longint;
begin
  for i:=18 downto 0 do
    if d[x]-d[y]>=1 shl i
    then x:=f[x,i];
  for i:=18 downto 0 do
    if d[y]-d[x]>=1 shl i
    then y:=f[y,i];
  for i:=18 downto 0 do
    if f[x,i]<>f[y,i]
    then begin
           x:=f[x,i];
           y:=f[y,i];
         end;
  if x<>y then x:=f[x,0];
  exit(x);
end;

procedure
  solve(x:longint);
var
  i:longint;
begin
  s[x]:=-(g[d[x]+w[x]]+h[d[x]-w[x]]);
  for i:=q[4*x] to q[4*x+1]-1 do inc(g[e[i]]);
  for i:=q[4*x+1] to q[4*x+2]-1 do dec(g[e[i]]);
  for i:=q[4*x+2] to q[4*x+3]-1 do inc(h[e[i]]);
  for i:=q[4*x+3] to q[4*x+4]-1 do dec(h[e[i]]);
  for i:=p[x] to p[x+1]-1 do
    if b[i]<>f[x,0]
    then solve(b[i]);
  inc(s[x],g[d[x]+w[x]]+h[d[x]-w[x]]);
end;

