int N, M, T, U, V, Q;
int inp[max_len];

#define Front(x) ((x).head == (x).tail ? -oo : (x).q[(x).head + 1])
#define Back(x) ((x).head == (x).tail ? +oo : (x).q[(x).tail])

int getmax() {
	register int ret = 0;
	rep(i, 1, 2) if(Front(q[ret]) < Front(q[i])) {
		ret = i;
	}

	return ret;
}

void throwinqueue(int x) {
	register int ret = -1;
	rep(i, 0, 2) {
		if(Back(q[i]) >= x) {
			if(ret == -1 || (~ret && Back(q[ret]) > Back(q[i])))
				ret = i;
		}
	}

	q[ret].q[++ q[ret].tail] = x;
}

