typedef pair<db,db> pdb;

const int N=18;

int n,m,bit[1<<N];
short dist[1<<N];
db X[N],Y[N];

pdb calc(int a,int b)
{
    if(X[a]==X[b])return pdb(1,1);
    db A,B;
    B=(X[b]*X[b]*Y[a]-X[a]*X[a]*Y[b])/(X[a]*X[b]*(X[b]-X[a]));
    A=(Y[a]-X[a]*B)/(X[a]*X[a]);
    return pdb(A,B);
}

int que[1<<N];

inline db fun(db a,db b,db x)
{
    return a*x*x+b*x;
}

int bfs()
{
    memset(dist,-1,(1<<n)*sizeof(short));
    dist[(1<<n)-1]=0;
    int L=0,R=0;
    for(que[R++]=((1<<n)-1);L<R;)
    {
        int mask=que[L++];
        int id=bit[lowbit(mask)];
        bool mark[N]={false};
        int tmp=mask^(1<<id);
        if(!tmp)return dist[mask]+1;
        if(dist[tmp]==-1)
        {
            que[R++]=tmp;
            dist[tmp]=dist[mask]+1;
        }
        rep(i,id+1,n)if(mask&1<<i&&!mark[i])
        {
            pdb tmp=calc(id,i);
            if(tmp.fi<-eps)
            {
                int tar_mask=mask^(1<<id)^(1<<i);
                rep(j,i+1,n)if(mask&1<<j&&!mark[j]&&fabs(fun(tmp.fi,tmp.se,X[j])-Y[j])<eps)
                {
                    mark[j]=true;
                    tar_mask^=1<<j;
                }
                if(!tar_mask)return dist[mask]+1;
                if(dist[tar_mask]==-1)
                {
                    que[R++]=tar_mask;
                    dist[tar_mask]=dist[mask]+1;
                }
            }
        }
    }
}

void solve()
{
    rd(n),rd(m);
    rep(i,0,n)scanf("%lf%lf",&X[i],&Y[i]);
    if(!n)
    {
        puts("0");
        return;
    }
    ptn(bfs());
}

int main()
{
	
