inline void tense(int &a, const int &b)
{
	if (b < a)
		a = b;
}

const int MaxN = 18;
const r32 eps = 3e-9;

int nT, n, dataType;
r32 fx[MaxN], fy[MaxN];

int hitset[MaxN][MaxN];

inline void solve_equation(r32 a, r32 b, r32 c, r32 d, r32 e, r32 f, r32 &x, r32 &y)
{
	r32 k = d / a;
	b *= k, c *= k;
	y = (c - f) / (b - e);
	x = (f - e * y) / d;
}

inline r32 myfabs(const r32 &x)
{
	return x < 0.0 ? -x : x;
}

inline bool get_graph(r32 x1, r32 y1, r32 x2, r32 y2, r32 &a, r32 &b)
{
	if (myfabs(x1 - x2) < eps)
		return false;
	solve_equation(x1 * x1, x1, y1, x2 * x2, x2, y2, a, b);
	return a < 0.0;
}

int f[1 << MaxN];

inline int solve()
{
	int all = 1 << n;
	for (int s = 1; s < all; ++s)
	{
		int i = 0;
		while (~s >> i & 1)
			++i;

		f[s] = f[s ^ (s & -s)] + 1;
		for (int j = i + 1; j < n; ++j)
			if (s >> j & 1)
			{
				int t = hitset[i][j] & s;
				tense(f[s], f[s ^ t] + 1);
			}
	}
	return f[all - 1];
}

