namespace input
{
	const int BufferSize = 1 << 16 | 1;

	char buffer[BufferSize];
	char *head = buffer + BufferSize;
	const char *tail = head;

	inline char nextChar()
	{
		if (head == tail)
		{
			fread(buffer, 1, BufferSize, stdin);
			head = buffer;
		}
		return *head++;
	}

	inline int getint()
	{
		static char c;
		while ((c = nextChar()) < '0' || c > '9');

		int res = c - '0';
		while ((c = nextChar()) >= '0' && c <= '9')
			res = res * 10 + c - '0';
		return res;
	}
}
using input::getint;

const int MaxN = 100005;
const int MaxM = 200005;
const int MaxLogN = 17;
const int MaxTN = MaxN * MaxLogN;

int nT, n, m;

struct halfEdge
{
	int v;
	halfEdge *next;
};
halfEdge adj_pool[MaxM * 2], *adj_tail = adj_pool;
halfEdge *adj[MaxN];

inline void addEdge(const int &u, const int &v)
{
	adj_tail->v = v, adj_tail->next = adj[u];
	adj[u] = adj_tail++;
}

struct node
{
	node *lc, *rc;
	int mark, dep;
	bool full;

	inline void update()
	{
		if (!lc)
			full = !rc;
		else
			full = lc->full && rc && rc->full;
	}

	inline void tag_xor(int d)
	{
		mark ^= d;
		if (d >> dep & 1)
			swap(lc, rc);
	}
	inline void tag_down()
	{
		if (mark)
		{
			if (lc)
				lc->tag_xor(mark);
			if (rc)
				rc->tag_xor(mark);

			mark = 0;
		}
	}
};
node pool[MaxTN], *tail = pool;
node *tr[MaxN];

inline void build(node *&x, const int &val)
{
	node *p = x = tail++;
	for (int l = 16; l >= 0; --l)
	{
		p->dep = l;
		p->mark = 0, p->full = false;

		if (val >> l & 1)
		{
			p->lc = NULL;
			p = p->rc = tail++;
		}
		else
		{
			p->rc = NULL;
			p = p->lc = tail++;
		}
	}
	p->mark = 0;
	p->full = true;
}

node *merge(node *x, node *y)
{
	if (!x)
		return y;
	if (!y)
		return x;

//	x->tag_down();
	y->tag_down();
	x->lc = merge(x->lc, y->lc);
	x->rc = merge(x->rc, y->rc);
	x->update();
	return x;
}

inline int query_mex(node *p)
{
	int res = 0;
	for (int l = 16; p; --l)
	{
		if (p->full)
			res += 2 << l, p = NULL;
		else if (!p->lc || !p->lc->full)
			p = p->lc;
		else
		{
			res |= 1 << l;
			p = p->rc;
		}
	}

	return res;
}

int f[MaxN];
bool vis[MaxN];

int calcF(const int &u, const int &prev)
{
	vis[u] = true;

	int sum = 0;
	for (halfEdge *e = adj[u]; e; e = e->next)
		if (!vis[e->v])
			sum ^= calcF(e->v, u);

	build(tr[u], sum);
	for (halfEdge *e = adj[u]; e; e = e->next)
		if (e->v != prev)
		{
			tr[e->v]->tag_xor(sum ^ f[e->v]);
			tr[u] = merge(tr[u], tr[e->v]);
		}

	return f[u] = query_mex(tr[u]);
}

int main()
{
//	freopen("game.in", "r", stdin);
//	freopen("game.out", "w", stdout);

	nT = getint();
	while (nT--)
	{
		n = getint(), m = getint();

		adj_tail = adj_pool;
		for (int u = 1; u <= n; ++u)
			adj[u] = NULL, vis[u] = false;
		for (int i = 0; i < m; ++i)
		{
			int u = getint(), v = getint();
			addEdge(u, v);
			addEdge(v, u);
		}

		tail = pool;

		int sum = 0;
		for (int u = 1; u <= n; ++u)
			if (!vis[u])
				sum ^= calcF(u, 0);

		puts(sum ? "Alice" : "Bob");
	}

	fclose(stdin);
	fclose(stdout);
	return 0;
}

