    if(x<=mid)addsa(me<<1,l,mid,x,y,v);
    if(y>mid)addsa(me<<1|1,mid+1,r,x,y,v);
    ss[me]=max(ss[me<<1],ss[me<<1|1]);
}
void gai(int me,int l,int r,int x,LL v){
    if(l^r)downsa(me);
    if(l==r){
        ss[me]=v;
        return;
    }
    int mid=(l+r)>>1;
    if(x<=mid)gai(me<<1,l,mid,x,v);
    else gai(me<<1|1,mid+1,r,x,v);
    ss[me]=max(ss[me<<1],ss[me<<1|1]);
}
