struct segment
{
    struct node
    {
        LL lc, rc, lb, rb, tag, mx;
        node ()
        {
            lc = rc = lb = rb = tag = mx = 0;
        }
    } O;
    vector <node> tr;
    LL tot;
    LL build(LL l, LL r)
    {
        LL t = ++ tot; tr[t] = O;
        tr[t].lb = l; tr[t].rb = r;
        if (l != r)
        {
            tr[t].lc = build(l, (l + r) / 2);
            tr[t].rc = build((l + r) / 2 + 1, r);
        }
        return t;
    }
    void make_tree(LL c)
    {
        tr.resize(c * 2); tot = 0;
        build(1, c);
    }
    void psdw(LL t)
    {
        tr[tr[t].lc].tag += tr[t].tag;
        tr[tr[t].lc].mx += tr[t].tag;
        tr[tr[t].rc].tag += tr[t].tag;
        tr[tr[t].rc].mx += tr[t].tag;
        tr[t].tag = 0;
    }
    void upd(LL t)
    {
        tr[t].mx = max(tr[tr[t].lc].mx, tr[tr[t].rc].mx);
    }
    LL query(LL t, LL l, LL r)
    {
        if (l <= tr[t].lb && tr[t].rb <= r) return tr[t].mx;
        psdw(t);
        LL v = 0;
        if (l <= tr[tr[t].lc].rb) v = max(v, query(tr[t].lc, l, r));
        if (r >= tr[tr[t].rc].lb) v = max(v, query(tr[t].rc, l, r));
        return v;
    }
    void modify(LL t, LL l, LL r, LL v)
    {
        if (l <= tr[t].lb && tr[t].rb <= r) {tr[t].mx += v; tr[t].tag += v; return;}
        psdw(t);
        if (l <= tr[tr[t].lc].rb) modify(tr[t].lc, l, r, v);
        if (r >= tr[tr[t].rc].lb) modify(tr[t].rc, l, r, v);
        upd(t);
    }
};

struct chain
{
    LL fa[N], fp[N], dep[N];
    LL siz[N], mxc[N];
    LL inl[N], lst[N], tot;

    segment tree;

    void dfs1(LL t = 1, LL f = 0, LL d = 1)
    {
        fa[t] = f; dep[t] = d; siz[t] = 1;
        for (LL i = 0; i < bi[t].size(); ++ i)
            if (bi[t][i] != fa[t])
            {
                dfs1(bi[t][i], t, d + 1);
                siz[t] += siz[bi[t][i]];
                if (siz[bi[t][i]] > siz[mxc[t]]) mxc[t] = bi[t][i];
            }
    }

    void dfs2(LL t = 1, LL p = 1)
    {
        fp[t] = p; inl[t] = ++ tot; lst[tot] = t;
        if (mxc[t]) dfs2(mxc[t], p);
        for (LL i = 0; i < bi[t].size(); ++ i)
            if (bi[t][i] != fa[t] && bi[t][i] != mxc[t])
                dfs2(bi[t][i], bi[t][i]);
    }

    LL lca(LL a, LL b)
    {
        while (1)
        {
            if (fp[a] == fp[b])
            {
                if (dep[a] > dep[b]) swap(a, b);
                return a;
            }
            else
            {
                if (dep[fp[a]] < dep[fp[b]]) swap(a, b);
                a = fa[fp[a]];
            }
        }
    }

    void modify(LL a, LL b, LL v)
    {
        while (1)
        {
            if (fp[a] == fp[b])
            {
                if (dep[a] > dep[b]) swap(a, b);
                tree.modify(1, inl[a], inl[b], v);
                return;
            }
            else
            {
                if (dep[fp[a]] < dep[fp[b]]) swap(a, b);
                tree.modify(1, inl[fp[a]], inl[a], v);
                a = fa[fp[a]];
            }
        }
    }

    LL closest(LL t, LL a, LL b)
    {
        LL la = lca(a, t), lb = lca(b, t);
        if (la == lb) return lca(a, b);
        if (la == t || lb == t) return t;
        if (dep[la] > dep[lb]) return la; else return lb;
    }
} C;

struct divide
{
    LL root;
    segment tree[N];
    LL siz[N], mxv[N], level[N];
    multiset <LL> value[N];

    LL dfs1(LL t, LL f, LL u, LL l)
    {
        siz[t] = 1; mxv[t] = 0; LL nw = 0;
        for (LL i = 0; i < bi[t].size(); ++ i)
            if (bi[t][i] != f && !level[bi[t][i]])
            {
                LL x = dfs1(bi[t][i], t, u, l);
                siz[t] += siz[bi[t][i]];
                if (mxv[x] < mxv[nw]) nw = x;
                mxv[t] = max(mxv[t], siz[bi[t][i]]);
            }
        mxv[t] = max(mxv[t], u - siz[t]);
        if (mxv[t] < mxv[nw]) nw = t;
        return nw;
    }

    vector <LL> lst[N];
    LL lb[M][N], rb[M][N], tp[M][N], tq[M][N]; // tp node, tq its child
    void dfs2(LL t, LL f, LL p, LL q, LL l)
    {
        lst[p].push_back(t);
        lb[l][t] = lst[p].size();
        tp[l][t] = p;
        tq[l][t] = q;
        for (LL i = 0; i < bi[t].size(); ++ i)
            if (bi[t][i] != f && !level[bi[t][i]])
                dfs2(bi[t][i], t, p, q, l);

        rb[l][t] = lst[p].size();
    }

    void dfs3(LL t, LL l)
    {
        level[t] = l; lst[t].push_back(t);
        tp[l][t] = t;
        for (LL i = 0; i < bi[t].size(); ++ i)
            if (!level[bi[t][i]])
            {
                dfs2(bi[t][i], t, t, bi[t][i], l);
                dfs3(dfs1(bi[t][i], t, rb[l][bi[t][i]] - lb[l][bi[t][i]] + 1, l), l + 1);
                value[t].insert(0);
            }
        tree[t].make_tree(lst[t].size());
    }

    void modify(LL t, LL a, LL b, LL v)
    {
        LL c = C.closest(t, a, b);
        if (c == t) return;

        LL nq = tq[level[t]][c];

        multiset <LL> :: iterator it;
        {
            LL s = 0;
            it = value[t].end(); it --; s += *it;
            if (it != value[t].begin()) it --, s += *it;
            C.modify(t, t, -s);
        }
        LL tmp;
        tmp = tree[t].query(1, lb[level[t]][nq], rb[level[t]][nq]);
        value[t].erase(value[t].lower_bound(tmp));

        tree[t].modify(1, lb[level[t]][c], rb[level[t]][c], v);

        tmp = tree[t].query(1, lb[level[t]][nq], rb[level[t]][nq]);
        value[t].insert(tmp);

        {
            LL s = 0;
            it = value[t].end(); it --; s += *it;
            if (it != value[t].begin()) it --, s += *it;
            C.modify(t, t, s);
        }
        modify(tp[level[t] + 1][c], a, b, v);
    }

    void init()
    {
        mxv[0] = 1e9;
        root = dfs1(1, 0, n, 1);
        dfs3(root, 1);
    }
} D;

LL U[N], V[N], W[N];
