struct edge{edge *nxt;int to;}pool[N<<1],*pt[N],*p=pool;
void addedge(int a,int b)
{
    *(++p)=(edge){pt[a],b},pt[a]=p;
    *(++p)=(edge){pt[b],a},pt[b]=p;
}
int son[N],wson[N],f[N],dep[N];
void init(int v,int fa=0)
{
    son[v]=1,f[v]=fa,dep[v]=dep[fa]+1;
    for (edge *i=pt[v];i;i=i->nxt)
        if (i->to!=fa)
        {
            init(i->to,v);
            son[v]+=son[i->to];
            if (son[i->to]>son[wson[v]])
                wson[v]=i->to;
        }
}
int top[N],bot[N],dfn[N],num[N],cnt;
int dfs(int v,int rt=0)
{
    if (!rt) rt=v;
    top[v]=rt,++cnt;
    dfn[v]=cnt,num[cnt]=v;
    bot[v]=v;
    if (wson[v]) bot[v]=dfs(wson[v],rt);
    for (edge *i=pt[v];i;i=i->nxt)
        if (i->to!=f[v]&&i->to!=wson[v])
            dfs(i->to);
    return bot[v];
}

struct P
{
    ll id,val;
    bool operator<(const P &b)const
    {
        return val<b.val||(val==b.val&&id<b.id);
    }
};
ll H_num[2][N];
struct Heap
{
    priority_queue<P> h;
    ll sz;
    Heap():sz(0){}
    void push(int i,ll v,ll val)
    {
        if (H_num[i][v]==val) return;
        if (H_num[i][v]==-1) sz++;
        h.push((P){v,val});
        H_num[i][v]=val;
    }
    ll top(int i,ll v=0)
    {
        if (!sz) return 0;
        P ret;
        for (ret=h.top();ret.val!=H_num[i][ret.id];ret=h.top())
            h.pop();
        if (ret.id==v)
        {
            if (sz==1) return 0;
            P now=ret;
            h.pop();
            for (ret=h.top();ret.val!=H_num[i][ret.id];ret=h.top())
                h.pop();
            h.push(now);
        }
        return ret.val;
    }
    ll sum(int i)
    {
        if (!sz) return 0;
        ll ret=top(i);
        ret+=top(i,h.top().id);
        return ret;
    }
}hp[N],hp2[N];
ll lsum[N],lans[N];

#define mid ((t[v].l+t[v].r)>>1)
struct segt
{
    ll tag,ls,rs,sum,cvr,now,ans,noc,noa;
    int l,r;
    segt():tag(0),ls(0),rs(0),sum(0),cvr(0),now(0),ans(0),noc(0),noa(0),l(0),r(0){}
}t[N<<2];
void build(int v,int l,int r)
{
    t[v].l=l,t[v].r=r;
    if (l==r) return;
    build(v<<1,l,mid);
    build(v<<1|1,mid+1,r);
}
void work(int v,ll val)
{
    t[v].tag+=val;
    t[v].sum+=val;
    t[v].noa+=val;
    t[v].ls+=val;
    t[v].rs+=val;
}
void pd(int v)
{
    if (t[v].l==t[v].r) t[v].tag=t[v].cvr=0;
    if (t[v].tag)
    {
        work(v<<1,t[v].tag);
        work(v<<1|1,t[v].tag);
        t[v].tag=0;
    }
}
void pu(segt &ret,segt l,segt r,ll c)
{
    ret.ls=max(l.ls,l.sum+r.ls-c);
    ret.rs=max(r.rs,r.sum+l.rs-c);
    ret.sum=l.sum+r.sum-c;
    ret.noa=max(max(l.noa,r.noa),l.rs+r.ls-c);
    ret.ans=max(l.ans,r.ans);
}
void add(int al,int ar,ll val,ll c=0,int v=1)
{
    pd(v);
    if (dfn[al]<=mid&&dfn[ar]>mid) t[v].noc+=val;
    if (dfn[al]<=t[v].l&&dfn[ar]>=t[v].r) work(v,val),t[v].cvr+=val,t[v].noc-=val;
    else
    {
        c+=t[v].cvr;
        if (dfn[al]<=mid) add(al,ar,val,c,v<<1);
        if (dfn[ar]>mid) add(al,ar,val,c,v<<1|1);
        pu(t[v],t[v<<1],t[v<<1|1],c+t[v].noc);
    }
}
segt query(int ql,int qr,ll c=0,int v=1)
{
    pd(v);
    segt ret;
    if (dfn[ql]<=t[v].l&&dfn[qr]>=t[v].r)
        ret=t[v];
    else
    {
        c+=t[v].cvr;
        if (dfn[qr]<=mid) ret=query(ql,qr,c,v<<1);
        else if (dfn[ql]>mid) ret=query(ql,qr,c,v<<1|1);
        else pu(ret,query(ql,qr,c,v<<1),query(ql,qr,c,v<<1|1),c+t[v].noc);
    }
    return ret;
}
ll lmrg[N];
void update(int loc,ll val,ll c=0,int v=1)
{
    pd(v);
    if (t[v].l==t[v].r)
    {
        t[v].now+=val;
        t[v].ls=t[v].rs=t[v].sum+t[v].now;
        t[v].noa=t[v].sum+lmrg[loc];
        t[v].ans=lans[loc];
    }
    else
    {
        c+=t[v].cvr;
        if (dfn[loc]<=mid) update(loc,val,c,v<<1);
        if (dfn[loc]>mid) update(loc,val,c,v<<1|1);
        pu(t[v],t[v<<1],t[v<<1|1],c+t[v].noc);
    }
}
#undef mid
ll cvr[N];
ll solve(int u,int v,int w)
{
    segt now;
    while (top[u]!=top[v])
        if (dep[top[u]]>dep[top[v]])
        {
            add(top[u],u,w);
            now=query(top[u],bot[u]);
            cvr[top[u]]+=w;
            hp[f[top[u]]].push(0,top[u],now.ls-cvr[top[u]]);
            hp2[f[top[u]]].push(1,top[u],max(now.ans,now.noa));
            u=f[top[u]];
            ll lst=lsum[u];
            lsum[u]=hp[u].top(0);
            lans[u]=hp2[u].top(1);
            lmrg[u]=hp[u].sum(0);
            update(u,lsum[u]-lst);
        }
        else
        {
            add(top[v],v,w);
            now=query(top[v],bot[v]);
            cvr[top[v]]+=w;
            hp[f[top[v]]].push(0,top[v],now.ls-cvr[top[v]]);
            hp2[f[top[v]]].push(1,top[v],max(now.ans,now.noa));
            v=f[top[v]];
            ll lst=lsum[v];
            lsum[v]=hp[v].top(0);
            lans[v]=hp2[v].top(1);
            lmrg[v]=hp[v].sum(0);
            update(v,lsum[v]-lst);
        }
    if (dep[u]>dep[v]) swap(u,v);
    add(u,v,w);
    now=query(top[v],bot[v]);
    while (f[top[v]])
    {
        hp[f[top[v]]].push(0,top[v],now.ls-cvr[top[v]]);
        hp2[f[top[v]]].push(1,top[v],max(now.ans,now.noa));
        v=f[top[v]];
        ll lst=lsum[v];
        lsum[v]=hp[v].top(0);
        lans[v]=max(hp2[v].top(1),hp[v].sum(0));
        lmrg[v]=hp[v].sum(0);
        update(v,lsum[v]-lst);
        now=query(top[v],bot[v]);
    }
    return max(now.ans,now.noa);
}

