}tree[N<<2];
inline node operator *(const node &x, const node &y){
	node z;
	z.a=x.a+y.a;
	z.c=max(x.c+y.a,x.d+y.c);
	z.d=x.d+y.d;
	z.e=max(max(x.e+y.a,x.f+y.c),y.e);
	z.f=max(x.f+y.d,y.f);
	return z;
