inline node buildmtr(int u){
	node res;
	res.a=b[u]+hh[u];
	res.c=a[u]+b[u]+hh[u]+gg[u];
	res.d=a[u]+b[u]+hh[u];
	res.e=a[u]+b[u]+hh[u]+ff2[u];
	res.f=a[u]+b[u]+hh[u]+ff1[u];
	return res;
}
void build(int k, int l, int r){
	if(l==r){tree[k]=buildmtr(dot[l]);return;}
	int mid=(l+r)>>1;build(k<<1,l,mid);build(k<<1|1,mid+1,r);
	tree[k]=tree[k<<1]*tree[k<<1|1];
}
void modify(int k, int p, int l, int r){
	if(l==r){tree[k]=buildmtr(dot[l]);return;}
	int mid=(l+r)>>1;if(p<=mid)modify(k<<1,p,l,mid);else modify(k<<1|1,p,mid+1,r);
	tree[k]=tree[k<<1]*tree[k<<1|1];
}
node query(int k, int l, int r, int L, int R){
	if(l==L&&r==R)return tree[k];
	int mid=(L+R)>>1;
	if(r<=mid)return query(k<<1,l,r,L,mid);
	if(l>mid)return query(k<<1|1,l,r,mid+1,R);
	return query(k<<1,l,mid,L,mid)*query(k<<1|1,mid+1,r,mid+1,R);
}
inline void modi(int u){
	modify(1,dfn[u],1,n);
	while(u){
		u=top[u];node tmp=query(1,dfn[u],dfn[bot[u]],1,n);
		hh[fa[u]]-=h[u];if(fa[u])sli[fa[u]].erase(sli[fa[u]].find(g[u]-h[u]));
		h[u]=tmp.a;g[u]=max(tmp.c,tmp.d);ans[u]=max(tmp.e,tmp.f);
		if(u==1)break;
		hh[fa[u]]+=h[u];sli[fa[u]].insert(g[u]-h[u]);
		ff1[fa[u]]=ff2[fa[u]]=gg[fa[u]]=*sli[fa[u]].rbegin();
		if(SZ(sli[fa[u]])>=2){
			ll x=*sli[fa[u]].rbegin();sli[fa[u]].erase(sli[fa[u]].find(x));
			ff2[fa[u]]+=*sli[fa[u]].rbegin();sli[fa[u]].insert(x);
		}
		modify(1,dfn[fa[u]],1,n);
		u=fa[u];
	}
}
