}
void update ( int x ) {
	p[x].minn = x; p[x].sum = p[x].l;
	if ( p[x].ch[0] ) {
		p[x].sum += p[p[x].ch[0]].sum;
		if ( p[p[p[x].ch[0]].minn].t < p[p[x].minn].t ) p[x].minn = p[p[x].ch[0]].minn;
	}
	if ( p[x].ch[1] ) {
		p[x].sum += p[p[x].ch[1]].sum;
		if ( p[p[p[x].ch[1]].minn].t < p[p[x].minn].t ) p[x].minn = p[p[x].ch[1]].minn;
	}
}
void pushdown ( int x ) {
	if ( p[x].rev ) {
		if ( p[x].ch[0] ) {
			p[p[x].ch[0]].rev ^= 1;
			swap ( p[p[x].ch[0]].ch[0] , p[p[x].ch[0]].ch[1] );
		}
		if ( p[x].ch[1] ) {
			p[p[x].ch[1]].rev ^= 1;
			swap ( p[p[x].ch[1]].ch[0] , p[p[x].ch[1]].ch[1] );
		}
		p[x].rev = 0;
	}
}
void cut ( int x , int kind ) {
	p[p[x].ch[kind]].fa *= -1;
	p[x].ch[kind] = 0;
	update ( x );
}
void down ( int x ) {
	if ( p[x].fa > 0 ) down ( p[x].fa );
	pushdown ( x );
}
void rotate ( int x , int kind ) {
	int y = p[x].fa;
	//printf ( "# %d %d %d\n" , x , kind , y );
	if ( p[y].fa > 0 ) p[p[y].fa].ch[y==p[p[y].fa].ch[1]] = x;
	p[x].fa = p[y].fa;
	if ( p[x].ch[kind^1] ) p[p[x].ch[kind^1]].fa = y;
	p[y].ch[kind] = p[x].ch[kind^1];
	p[x].ch[kind^1] = y;
	p[y].fa = x;
	update ( y ); update ( x );
}
void splay ( int x ) {
	down ( x );
	//printf ( "#%d\n" , x );
	//output ();
	//printf("\n");
	for ( ; p[x].fa > 0 ; rotate ( x , x==p[p[x].fa].ch[1] ) )
		if ( p[p[x].fa].fa > 0 && (x==p[p[x].fa].ch[1]) == (p[x].fa==p[p[p[x].fa].fa].ch[1]) )
			rotate ( p[x].fa , x==p[p[x].fa].ch[1] );
}
void access ( int x ) {
	//printf ( "%d\n" , x );
	//output ();
	splay ( x );
	//output ();
	//printf ( "\n" );
	cut ( x , 1 );
	for ( ; p[x].fa != 0 ; ) {
		splay ( -p[x].fa );
		cut ( -p[x].fa , 1 );
		p[-p[x].fa].ch[1] = x;
		update ( -p[x].fa );
		p[x].fa *= -1;
		splay ( x );
	}
}
void makeroot ( int x ) {
	access ( x );
	p[x].rev ^= 1;
	swap ( p[x].ch[0] , p[x].ch[1] );
}
int findroot ( int x ) {
	pushdown ( x );
	if ( p[x].ch[0] ) return findroot ( p[x].ch[0] );
	return x;
}
void link ( int x , int y ) {
	makeroot ( x ); makeroot ( y );
	access ( x ); access ( y );
	p[x].fa = -y;
}
