int n, m, u[MAXN], v[MAXN], f[MAXN], pos[MAXN], len[MAXN], val[MAXN], sum[MAXN], chd[MAXN][2];
bool rev[MAXN];

inline bool Isroot(int x)
{
	return chd[f[x]][0] != x && chd[f[x]][1] != x;
}

inline void Pushup(int x)
{
	sum[x] = len[x] + sum[chd[x][0]] + sum[chd[x][1]];
	pos[x] = x;
	if (chd[x][0] && val[pos[x]] > val[pos[chd[x][0]]])
		pos[x] = pos[chd[x][0]];
	if (chd[x][1] && val[pos[x]] > val[pos[chd[x][1]]])
		pos[x] = pos[chd[x][1]];
}

inline void Pushdown(int x)
{
	if (rev[x])
		rev[chd[x][0]] ^= 1, rev[chd[x][1]] ^= 1, swap(chd[x][0], chd[x][1]), rev[x] = 0;
}

inline void Rotate(int x)
{
	int y = f[x], z = f[y], k = chd[y][1] == x;
	if (!Isroot(y))
		chd[z][chd[z][1] == y] = x;
	f[chd[y][k] = chd[x][k ^ 1]] = y;
	f[f[chd[x][k ^ 1] = y] = x] = z;
	Pushup(y), Pushup(x);
}

inline void Splay(int x)
{
	static int sta[MAXN], top;
	sta[top = 1] = x;
	for (int i = x; !Isroot(i); i = f[i])
		sta[++ top] = f[i];
	while (top)
		Pushdown(sta[top --]);
	for (int y = f[x], z = f[y]; !Isroot(x); Rotate(x), y = f[x], z = f[y])
		if (!Isroot(y))
			Rotate(((chd[y][1] == x) == (chd[z][1] == y)) ? y : x);
}

inline void Access(int x)
{
	for (int t = 0; x; Splay(x), chd[x][1] = t, t = x, Pushup(x), x = f[x]);
}

inline void Makeroot(int x)
{
	Access(x), Splay(x), rev[x] ^= 1;
}

inline void Link(int x, int y)
{
	Makeroot(x), f[x] = y, Splay(y);
}

inline void Cut(int x, int y)
{
	Makeroot(x), Access(y), Splay(y), chd[y][0] = f[x] = 0, Pushup(y);
}

inline int Find(int x)
{
	for (Access(x), Splay(x), Pushdown(x); chd[x][0]; Pushdown(x = chd[x][0]));
	return x;
}

inline int Query(int x, int y)
{
	if (Find(x) ^ Find(y))
		return -1;
	Makeroot(x), Access(y), Splay(y);
	return sum[y];
}

