			if(ch[x][1]&&t[Mxson[ch[x][1]]]<t[Mxson[x]])Mxson[x]=Mxson[ch[x][1]];
		}
		void down(int p){
			if(flp[p]){
				swap(ch[p][0],ch[p][1]);
				flp[ch[p][0]]^=1,flp[ch[p][1]]^=1;
				flp[p]=0;
			}
