		void rot(int x){
			int f=fa[x],gf=fa[f];
			if(!is_root(f))ch[gf][ch[gf][1]==f]=x;
			bool ff=(ch[f][0]==x);
			fa[ch[x][ff]]=f;
			fa[f]=x,fa[x]=gf;
			ch[f][!ff]=ch[x][ff];
			ch[x][ff]=f;
			up(f);
		}
		void splay(int x){
			static int stk[MN],sz;sz=0;
			stk[sz++]=x;
			for(int i=x;!is_root(i);i=fa[i])stk[sz++]=fa[i];
			for(int i=sz-1;i>=0;i--)down(stk[i]);
			int p,gp;
			while(!is_root(x)){
