				if(is_root(p))rot(x);
				else {
					gp=fa[p];
					if((ch[p][0]==x)^(ch[gp][0]==p))rot(x);
					else rot(p);
					rot(x);
				}
			}
			up(x);
		}
		void acs(int x){
			int p=0;
			for(;x;x=fa[x]){
				splay(x);
				ch[x][1]=p;
				up(x);
				p=x;
			}
