			else if (getval (a[pter], x) < getval (rank2, x) && a[pter].from != rank1.from)
				rank2 = a[pter];
			pter--;
		}
		if (a[i].from != rank1.from && getval (a[i], x) + getval (rank1, x) < 0)
			return 1;
		else if (getval (a[i], x) + getval (rank2, x) < 0)
			return 1;
	}
	return 0;
}

bool ok_2 (long long x)
{
