inline void calc_and_merge(map<ll , int> &a , map<ll , int> &b , int fix_dep , ll fix_dist) {
    for(map<ll , int>::iterator it = b.begin(); it != b.end(); it++) {
        map<ll , int>::iterator it2 = a.lower_bound(2ll * fix_dist - it->F);
        if(it2 != a.end()) {
            ans = min(ans , abs(it->F + it2->F - 2ll * fix_dist) / (it->S + it2->S - 2 * fix_dep));
        }
        if(it2 != a.begin()) {
