void merge(int x, int y, ll dis, ll dep)
{
	for(mit it = X[x].begin(); it != X[x].end(); it++) {
		mit it2 = X[y].lower_bound(dis * 2 - it->F);
		if(it2 != X[y].end()) ans = min(ans, (it->F + it2->F - dis * 2) / (it->S + it2->S - dep * 2));
		if(it2 != X[y].begin()) it2--, ans = min(ans, -(it->F + it2->F - dis * 2) / (it->S + it2->S - dep * 2));
	}
	for(mit it = X[x].begin(); it != X[x].end(); it++) if(it->S > X[y][it->F]) X[y][it->F] = it->S;
}

