void Add(R int u, R int v, R long long w)
{
	Next[++q] = Point[u]; Point[u] = q; To[q] = v; W[q] = w;
	Next[++q] = Point[v]; Point[v] = q; To[q] = u; W[q] = w;
}
int Sum[MaxN], Most[MaxN];
bool vis[MaxN];
void DFS1(R int Now, R int From)
{
	Sum[Now] = 1; 
	for(R int j = Point[Now]; j; j = Next[j])
		if(To[j] != From && !vis[To[j]])
			DFS1(To[j], Now), Sum[Now] += Sum[To[j]];
}
int DFS2(R int Now, R int From, R int Size)
{
	Most[Now] = Size - Sum[Now];
	for(R int j = Point[Now]; j; j = Next[j])
	{
		if(To[j] != From && !vis[To[j]])
		{
			R int t = DFS2(To[j], Now, Size);
			if(t) return t;
			Most[Now] = Max(Most[Now], Sum[To[j]]);
		}
	}
	return Most[Now] <= (Size >> 1) ? Now : 0;
}
struct Data{ int Id, B; long long A; } a[MaxN]; int cnt, tot;
void DFS3(R int Now, R int From, R int K, R long long Tmp)
{
	a[++tot] = (Data) {cnt, K, Tmp};
	for(R int j = Point[Now]; j; j = Next[j])
		if(To[j] != From && !vis[To[j]])
			DFS3(To[j], Now, K + 1, Tmp + W[j]);
}
bool cmp(R Data i, R Data j){ return i.A < j.A; }
long long f3[MaxN], f4[MaxN], d[MaxN], B[MaxN], C[MaxN], l = -1, r = 50000000000000ll, M;
int p2[MaxN];
bool check()
{
	for(R int i = 1; i <= tot; i++) B[i] = a[i].A - a[i].B * M, C[i] = a[i].A + a[i].B * M;
	for(R int i = 1; i <= tot; i++) if((a[i].A >= 0 && B[i] < 0) || (a[i].A <= 0 && C[i] > 0)) return 1;
	R int r = tot;
	int p = 0;
	long long f1 = Inf, f2 = Inf;
	for(R int i = 1; i <= cnt; i++) d[i] = Inf;
	for(R int l = 1; l <= tot; l++)
	{
		while(r && a[r].A + a[l].A >= 0)
		{
			d[a[r].Id] = Min(d[a[r].Id], B[r]);
			if(f1 > d[a[r].Id]) 
			{
				if(p != a[r].Id) f2 = f1;
				f1 = d[p = a[r].Id];
			}
			else if(f2 > d[a[r].Id]) f2 = d[a[r].Id];
			r--;
		}
		if(l <= r)
		{
			R long long tmp = B[l] + (a[l].Id == p ? f2 : f1);
			if(tmp < 0) return 1;
		}
		else break;
	}
	for(R int i = 1; i <= cnt; i++) d[i] = -Inf;
	p2[0] = 0, f3[0] = f4[0] = -Inf;
	for(R int i = 1; i <= tot; i++)
	{
		f3[i] = f3[i - 1], f4[i] = f4[i - 1], p2[i] = p2[i - 1];
		d[a[i].Id] = Max(d[a[i].Id], C[i]);
		if(f3[i] < d[a[i].Id]) 
		{
			if(p2[i] != a[i].Id) f4[i] = f3[i];
			f3[i] = d[a[i].Id], p2[i] = a[i].Id;
		}
		else if(f4[i] < d[a[i].Id]) f3[i] = d[a[i].Id];
	}
	r = tot;
	for(R int l = 1; l <= tot; l++)
	{
		while(r && a[r].A + a[l].A > 0) r--;
		if(l < r)
		{
			R long long tmp = C[l] + (a[l].Id == p2[r] ? f4[r] : f3[r]);
			if(tmp > 0) return 1;
		}
		else break;
	}
	return 0;
}
void Divide(R int Now)
{
	DFS1(Now, 0);
	if(Sum[Now] == 1) return ;
	cnt = tot = 0;
	R int Pos = DFS2(Now, 0, Sum[Now]);
	for(R int j = Point[Pos]; j; j = Next[j])
		if(!vis[To[j]]) 
			++cnt, DFS3(To[j], Pos, 1, W[j]);
	std::sort(a + 1, a + 1 + tot, cmp);
