	{
		M = l + r >> 1;
		if(check()) r = M;
		else l = M;
	}
	vis[Pos] = 1;
	for(R int j = Point[Pos]; j; j = Next[j])
		if(!vis[To[j]])
			Divide(To[j]);	
	vis[Pos] = 0;
}
