#define GC (p1 == p2 && (p2 = (p1 = buf) + fread(buf, 1, 1000000, stdin), p1 == p2) ? 0 : *p1 ++)
inline ll _R() {
	ll d = 0; bool ty = 1; char t;
	while (t = GC, (t < '0' || t > '9') && t != '-');
	t == '-' ? (ty = 0) : (d = t - '0');
	while (t = GC, t >= '0' && t <= '9') d = (d << 3) + (d << 1) + t - '0';
	return ty ? d : -d;
}


int n;
db k;

int Tote, Last[N], Next[N << 1], End[N << 1];
db Len[N << 1], A[N << 1], B[N << 1];
void ADDE(int x, int y, ll z) {
	End[++ Tote] = y, Len[Tote] = z, Next[Tote] = Last[x], Last[x] = Tote;
	End[++ Tote] = x, Len[Tote] = z, Next[Tote] = Last[y], Last[y] = Tote;
}

bool vis[N];
int sz[N], mem[N], minn;
void getsz(int x, int fa) {
	sz[x] = 1;
	for (int i = Last[x], u; i; i = Next[i])
		if (u = End[i], u != fa && !vis[u]) getsz(u, x), sz[x] += sz[u];
}
void getrt(int x, int &rt, int tot, int fa) {
	int maxx = 0;
	sz[x] = 1;
	for (int i = Last[x], u; i; i = Next[i])
		if (u = End[i], u != fa && !vis[u]) getrt(u, rt, tot, x), maxx = max(maxx, sz[u]), sz[x] += sz[u];
	maxx = max(maxx, tot - sz[x]);
	if (maxx < minn) minn = maxx, rt = x;
}

int cnt;
struct sdata { int tp; db la, lb; } h[N];
bool operator < (const sdata& lhs, const sdata& rhs) { return lhs.la < rhs.la; }

void getpair(int x, int fa, db d1, db d2, int tp) {
	h[++ cnt] = (sdata) {tp, d1, d2};
	for (int i = Last[x], u; i; i = Next[i])
		if (u = End[i], u != fa && !vis[u]) getpair(u, x, d1 + A[i], d2 + B[i], tp);
}

bool getans(int x) {
	int i, j, u;
	cnt = 0;
	for (i = Last[x]; i; i = Next[i])
		if (u = End[i], !vis[u]) getpair(u, x, A[i], B[i], u);
	sort(h + 1, h + 1 + cnt);
	
	int id1 = -1, id2 = 0;
	db m1 = 1e18, m2 = 1e18;
	for (i = 1, j = cnt; i <= cnt; i ++) {
		if (h[i].la >= 0 && h[i].lb <= 0) return 1;
		while (h[j].la + h[i].la >= 0 && j > i) {
			if (h[j].lb <= m1) {
				if (id1 != h[j].tp) id2 = id1, m2 = m1;
				m1 = h[j].lb, id1 = h[j].tp;
			}
			else if (h[j].lb <= m2 && h[j].tp != id1) id2 = h[j].tp, m2 = h[j].lb;
			j --;
		}
		if (h[i].tp != id1 && h[i].lb + m1 <= 0) return 1;
		if (h[i].tp != id2 && h[i].lb + m2 <= 0) return 1;
	}
	return 0;
}

bool DC(int x, int tot) {
	int i, u, rt;
	
	minn = INF;
	if (mem[x]) rt = mem[x];
	else getrt(x, rt, tot, 0), mem[x] = rt;
	getrt(x, rt, tot, 0);
	getsz(rt, 0);

	if (tot == 1) return 0;
	if (tot == 2) {
		for (i = Last[x]; i; i = Next[i])
			if (u = End[i], !vis[u])
				if (A[i] >= 0 && B[i] <= 0) return 1;
		return 0;
	}

	if (getans(rt)) return 1;

	vis[rt] = 1;
	for (i = Last[rt]; i; i = Next[i])
		if (u = End[i], !vis[u])
			if (DC(u, sz[u])) return 1;
	return 0;
}

bool check(db mid) {
	for (int i = 1; i <= Tote; i ++) A[i] = Len[i] - k + mid;
	for (int i = 1; i <= Tote; i ++) B[i] = Len[i] - k - mid;
	fill(vis, vis + n + 1, 0);
	return DC(1, n);
}

