    for(;isdigit(c);c=getchar())x=(x<<1)+(x<<3)+(c^48);
    if(f)x=-x;return x;
}
struct edge
{
    int v,w,net;
}e[N<<1];
int head[N<<1],cnt;
inline void add(register int u,register int v,register int w) 
{
    e[++cnt].v=v;
    e[cnt].w=w;
    e[cnt].net=head[u];
    head[u]=cnt;
}
int m,sum,rt;
int siz[N],maxs[N];
bool vis[N];
int ans=1e18,n,k;
int dis[N],E[N],E1[N],dis1[N],E2[N],dis2[N];
inline void find(register int u,register int fa)
{
    siz[u]=1;maxs[u]=0;
    for(register int i(head[u]);i;i=e[i].net) 
    {
        int v=e[i].v;
        if(v==fa||vis[v]) continue;
        find(v,u);
        siz[u]+=siz[v];
        maxs[u]=max(maxs[u],siz[v]);
    }
    maxs[u]=max(maxs[u],sum-siz[u]);
    if(maxs[rt]>maxs[u]) rt=u;
}
inline void getdis(register int u,register int fa) 
{
	ans=min(ans,abs(dis[u]/E[u]));
    dis[u]>=0? (dis1[++dis1[0]]=dis[u],E1[dis1[0]]=E[u]):(dis2[++dis2[0]]=dis[u],E2[dis2[0]]=E[u]);
    for(register int i(head[u]);i;i=e[i].net) 
    {
        int v=e[i].v;
        if(vis[v]||v==fa) continue;
        dis[v]=dis[u]+e[i].w;E[v]=E[u]+1;
        getdis(v,u);
    }
}
inline void calu(register int u) 
{
    dis1[0]=dis2[0]=0;
    for(register int i(head[u]);i;i=e[i].net) 
    {
        int v=e[i].v,cur1=dis1[0],cur2=dis2[0];
        if(vis[v]) continue;
        E[v]=1;dis[v]=e[i].w;getdis(v,u);
        for(register int j(cur1+1);j<=dis1[0];++j) 
            for(register int k(1);k<=cur2;++k)
            ans=min(ans,abs((dis1[j]+dis2[k])/(E1[j]+E2[k])));
        for(register int j(cur2+1);j<=dis2[0];++j) 
            for(register int k(1);k<=cur1;++k)
            ans=min(ans,abs((dis2[j]+dis1[k])/(E2[j]+E1[k])));    
    }
}
inline void solve(register int u) 
{
    vis[u]=1;calu(u);
    for(register int i(head[u]);i;i=e[i].net) 
    {
        int v=e[i].v;
        if(vis[v]) continue;
        maxs[rt=0]=n;sum=siz[v];
        find(v,u);solve(rt);
    }
}
signed main() 
{
    ios::sync_with_stdio(0);
    n=read(),k=read();
    for(register int i(1),u,v,w;i<n;++i) 
    {
        u=read(),v=read(),w=read()-k;
        add(u,v,w);add(v,u,w);
    }
    sum=n;maxs[rt=0]=n;find(1,0);
    solve(rt);
    printf("%lld",ans);
    return 0;
}

