namespace Basic
{
    const double pi = acos(-1.0);
    const double eps = 1e-9;

    inline double sqr(double x)
    {
        return x * x;
    }

    inline int dcmp(double x)
    {
        return x > eps ? 1 : (x < -eps ? -1 : 0);
    }
}

namespace Geometry
{
    using namespace Basic;

    struct point
    {
        double x, y;
        point(double x = 0, double y = 0): x(x), y(y) {}
        friend bool operator <(const point& x, const point& y)
        {
            return x.x < y.x || (x.x == y.x && x.y < y.y);
        }
        friend point operator +(const point& x, const point& y)
        {
            return point(x.x + y.x, x.y + y.y);
        }
        friend point operator -(const point& x, const point& y)
        {
            return point(x.x - y.x, x.y - y.y);
        }
        friend point operator *(const point& x, double y)
        {
            return point(x.x * y, x.y * y);
        }
        friend point operator *(double y, const point& x)
        {
            return point(x.x * y, x.y * y);
        }
        friend point operator /(const point& x, double y)
        {
            return point(x.x / y, x.y / y);
        }
        friend bool operator ==(const point& x, const point& y)
        {
            return x.x == y.x && x.y == y.y;
        }
        void read()
        {
            scanf("%lf%lf", &x, &y);
        }
    };

    struct segment
    {
        point A, B;
        segment() {}
        segment(point A, point B): A(A), B(B) {}
    };

    struct circle
    {
        point O;
        double r;
        circle() {}
        circle(point O, double r): O(O), r(r) {}
        point getpoint(double ang)
        {
            return point(O.x + cos(ang) * r, O.y + sin(ang) * r);
        }
    };

    inline double dot(const point& x, const point& y)
    {
        return x.x * y.x + x.y * y.y;
    }

    inline double cross(point x, point y)
    {
        return x.x * y.y - x.y * y.x;
    }

    inline double dist(point x, point y)
    {
        return sqrt(sqr(x.x - y.x) + sqr(x.y - y.y));
    }

    inline double length(point x)
    {
        return sqrt(x.x * x.x + x.y * x.y);
    }

    inline point rotate(point x, double ang)
    {
        return point(x.x * cos(ang) - x.y * sin(ang), x.x * sin(ang) + x.y * cos(ang));
    }

    inline double angle(point x)
    {
        return atan2(x.y, x.x);
    }

    inline point normalize(point x)
    {
        double len = length(x);
        return x / len;
    }

    double lenv1;
    point v1;

    inline double distToSegment(const point& x, const segment& l)
    {
        point v1 = l.B - l.A;
        point v2 = x - l.A;
        point v3 = x - l.B;
        return (dcmp(dot(v1, v2)) < 0) ? length(v2) : ((dcmp(dot(v1, v3)) > 0) ? length(v3) : fabs(cross(v1, v2)) * lenv1);
    }

    inline int checkIntersect(segment l, circle c)
    {
        double d = distToSegment(c.O, l);
        return dcmp(d - c.r) < 0;
    }

    point tangent1[10];
    int tangent1_sz;

    point tangent21[10];
    point tangent22[10];
    int tangent2_sz;

    void getTangent(point p, circle c)
    {
        tangent1_sz = 0;
        point u = c.O - p;
        double dist = length(u);
        if (dist < c.r) {}
        else if (dcmp(dist - c.r) == 0)
        {
            tangent1[++tangent1_sz] = p + rotate(u, pi / 2);
        }
        else
        {
            double ang = asin(c.r / dist);
            double rdist = sqrt(sqr(dist) - sqr(c.r));
            u = normalize(u);
            u = rdist * u;
            tangent1[++tangent1_sz] = p + rotate(u, +ang);
            tangent1[++tangent1_sz] = p + rotate(u, -ang);
        }
    }

    void getTangent(circle a, circle b)
    {
        tangent2_sz = 0;
        if (a.r < b.r)
        {
            swap(a, b);
        }
        double d = dist(a.O, b.O);
        double base = angle(b.O - a.O);
        double ang = acos((a.r - b.r) / d);
        ++tangent2_sz;
        tangent21[tangent2_sz] = a.getpoint(base + ang);
        tangent22[tangent2_sz] = b.getpoint(base + ang);
        ++tangent2_sz;
        tangent21[tangent2_sz] = a.getpoint(base - ang);
        tangent22[tangent2_sz] = b.getpoint(base - ang);
        ang = acos((a.r + b.r) / d);
        ++tangent2_sz;
        tangent21[tangent2_sz] = a.getpoint(base + ang);
        tangent22[tangent2_sz] = b.getpoint(pi + base + ang);
        ++tangent2_sz;
        tangent21[tangent2_sz] = a.getpoint(base - ang);
        tangent22[tangent2_sz] = b.getpoint(pi + base - ang);
    }

}

