        {
            c[i].O.read();
            scanf("%lf", &c[i].r);
        }
    }

    vector<point> s[maxn];
    map<point, int> mp;
    point rec[maxv];

    inline int getPointid(point x)
    {
        if (mp.count(x))
        {
            return mp[x];
        }
        v++;
        rec[v] = x;
        return mp[x] = v;
    }

    inline bool checkCoincide(point x, point y)
    {
        segment l(x, y);
        lenv1 = 1.0 / dist(x, y);
        for (int i = 1; i <= n; i++)
        {
            if (checkIntersect(l, c[i]))
            {
                return true;
            }
        }
        return false;
    }

    inline void add_edge(int x, int y)
    {
        double d = dist(rec[x], rec[y]);
        g[x].push_back(make_pair(y, d));
        g[y].push_back(make_pair(x, d));
    }

    inline void add_edge(int x, int y, double d)
    {
        g[x].push_back(make_pair(y, d));
        g[y].push_back(make_pair(x, d));
    }

    void buildGraph()
    {
        int sp = 1, tp = 2;
        getPointid(st);
        getPointid(ed);
        if (!checkCoincide(st, ed))
        {
            add_edge(sp, tp);
        }
        for (int i = 1; i <= n; i++)
        {
            getTangent(st, c[i]);
            for (int k = 1; k <= tangent1_sz; k++)
            {
                if (checkCoincide(st, tangent1[k]))
                {
                    continue;
                }
                s[i].push_back(tangent1[k]);
                add_edge(sp, getPointid(tangent1[k]));
            }
        }
        for (int i = 1; i <= n; i++)
        {
            getTangent(ed, c[i]);
            for (int k = 1; k <= tangent1_sz; k++)
            {
                if (checkCoincide(ed, tangent1[k]))
                {
                    continue;
                }
                s[i].push_back(tangent1[k]);
                add_edge(tp, getPointid(tangent1[k]));
            }
        }
        for (int i = 1; i <= n; i++)
        {
            for (int j = i + 1; j <= n; j++)
            {
                getTangent(c[i], c[j]);
                bool f = 0;
                if (dcmp(dist(tangent21[1], c[i].O) - c[i].r) == 0)
                {
                    f = 1;
                }
                for (int k = 1; k <= tangent2_sz; k++)
                {
                    if (checkCoincide(tangent21[k], tangent22[k]))
                    {
                        continue;
                    }
                    if (f)
                    {
                        s[i].push_back(tangent21[k]);
                        s[j].push_back(tangent22[k]);
                    }
                    else
                    {
                        s[j].push_back(tangent21[k]);
                        s[i].push_back(tangent22[k]);
                    }
                    add_edge(getPointid(tangent21[k]), getPointid(tangent22[k]));
                }
            }
        }
        for (int i = 1; i <= n; i++)
        {
            vector<pair<double, int> > angs;
            for (int j = 0; j < s[i].size(); j++)
            {
                double ang = angle(s[i][j] - c[i].O);
                angs.push_back(make_pair(ang, getPointid(s[i][j])));
            }
            sort(angs.begin(), angs.end());
            for (int j = 0; j < angs.size(); j++)
            {
                int k = (j + 1) % angs.size();
                double angdiff = fabs(angs[j].first - angs[k].first);
                angdiff = min(pi * 2 - angdiff, angdiff);
                double arclen = c[i].r * angdiff;
                add_edge(angs[j].second, angs[k].second, arclen);
            }
        }
    }
}

namespace RandomHeap
{
    double val[maxv];
    int ls[maxv], rs[maxv];
    int fa[maxv];
    int root;

    int Merge(int p, int q)
    {
        if (p == 0 || q == 0)
        {
            return p + q;
        }
        if (val[p] > val[q])
        {
            swap(p, q);
        }
        if (rand() & 1)
        {
            fa[ls[p] = Merge(ls[p], q)] = p;
        }
        else
        {
            fa[rs[p] = Merge(rs[p], q)] = p;
        }
        return p;
    }

    void init(int v)
    {
        for (int i = 1; i <= v; i++)
        {
            val[i] = 1e100;
        }
        root = 1;
        for (int i = 2; i <= v; i++)
        {
            fa[i] = i >> 1;
            if (i & 1)
            {
                ls[fa[i]] = i;
            }
            else
            {
                rs[fa[i]] = i;
            }
        }
    }


    void upd(int x, double v)
    {
        if (ls[fa[x]] == x)
        {
            ls[fa[x]] = 0;
        }
        else
        {
            rs[fa[x]] = 0;
        }
        val[x] = v;
        if (x != root)
        {
            root = Merge(root, x);
        }
    }

    inline int pop()
    {
        int ret = root;
        root = Merge(ls[root], rs[root]);
        return ret;
    }
}

