            double d = val[v];
            if (v == 0)
            {
                break;
            }
            for (int i = 0; i < g[v].size(); i++)
            {
                int u = g[v][i].first;
                double nd = g[v][i].second;
                if (val[u] > d + nd)
                {
                    upd(u, d + nd);
                }
            }
        }
        printf("%.1lf\n", val[t]);
    }
}

