inline db operator * (const P &a,const P &b) { return fabs(a.x*b.y-a.y*b.x); }
inline db dis(const P &a,const P &b,const P &c) {
	if (dot(c-a,b-a)<0) return (c-a).mo();
	if (dot(c-b,a-b)<0) return (c-b).mo();
