inline void check(const P &t,int k,int id) {
	int i;db x;P to;
	db r=(t-p[k]).angle();
	db d=acos(R[k]/(t-p[k]).mo());
	
	x=dec(r,d);
	to=p[k]+make(x)*R[k];
	for (i=1;i<=n;i++)
		if (i!=k&&dis(t,to,p[i])<R[i]-eps) break;
	if (i>n)
		link(id,add(k,x),(to-t).mo());
	
	x=inc(r,d);
	to=p[k]+make(x)*R[k];
	for (i=1;i<=n;i++)
		if (i!=k&&dis(t,to,p[i])<R[i]-eps) break;
	if (i>n)
		link(id,add(k,x),(to-t).mo());
}

inline db get(int k) {
