}

namespace heap{
	int q[N],pos[N],top;
	inline void up(int k) {
		int a=pos[k],b=a>>1;
		while (b&&get(k)<get(q[b])) {
			pos[q[a]=q[b]]=a;
			a=b,b>>=1;
		}
		pos[q[a]=k]=a;
	}
	inline void down(int k) {
		int a=pos[k],b=a<<1;
		while (b<=top) {
			if (b<top&&get(q[b|1])<get(q[b])) b|=1;
			if (get(k)<get(q[b])) break;
			pos[q[a]=q[b]]=a;
			a=b,b<<=1;
		}
		pos[q[a]=k]=a;
	}
	inline void push(int k) {
		pos[k]=++top;
		up(k);
	}
	inline void del(int k) {
		if (--top&&pos[k]!=top+1) {
			int t=pos[k];
			pos[q[t]=q[top+1]]=t;
			down(q[t]);
		}
	}
}

struct Eve{
	db g1,g2; int k; bool o;
	inline bool operator < (const Eve &b) const {
		if (fabs(g1-b.g1)>eps) return g1<b.g1;
		if (o^b.o) return o>b.o;
		return (D[k]>D[b.k])^o;
	}
	inline void link(int C) {
		//P a=p[C]+make(g1)*R[C];
		//P b=p[k]+make(g2)*R[k];
		::link(add(C,g1),add(k,g2),((p[C]+make(g1)*R[C])-(p[k]+make(g2)*R[k])).mo());
	}
}eve[N];

inline void scan(int C,int len) {
	int i;
	sort(eve+1,eve+1+len);
	for (i=1;i<=len;i++)
		if (STD=eve[i].g1,!eve[i].o) {
			heap::push(eve[i].k);
			if (eve[i].k>C&&heap::pos[eve[i].k]==1)
				eve[i].link(C);
		} else {
			if (eve[i].k>C&&heap::pos[eve[i].k]==1)
				eve[i].link(C);
			heap::del(eve[i].k);
		}
}

inline void solve(int C) {
	int i,len;db g1,g2,t,a,b;P d;

	for (i=1,len=heap::top=0;i<=n;i++) if (i!=C) {
			d=p[i]-p[C];
			D[i]=d.mo();
			g1=cp[i]=d.angle();
			g2=d.rev().angle();
			t=asin((R[i]-R[C])/(p[i]-p[C]).mo());
			a=inc(g1,t+pi/2);
			b=dec(g2,pi/2-t);
			eve[++len]=(Eve){a,b,i,1};

			t=acos((R[C]+R[i])/(p[C]-p[i]).mo());
			a=inc(g1,t);
			b=inc(g2,t);
			eve[++len]=(Eve){a,b,i,0};

			if (eve[len-1].g1<eve[len].g1) heap::push(i);
		}
	scan(C,len);

	for (i=1,len=heap::top=0;i<=n;i++) if (i!=C) {
			d=p[i]-p[C];
			g1=d.angle();
			g2=d.rev().angle();
			t=asin((R[i]-R[C])/(p[i]-p[C]).mo());
			a=dec(g1,t+pi/2);
			b=inc(g2,pi/2-t);
			eve[++len]=(Eve){a,b,i,0};

			t=acos((R[C]+R[i])/(p[C]-p[i]).mo());
			a=dec(g1,t);
			b=dec(g2,t);
			eve[++len]=(Eve){a,b,i,1};

			if (eve[len-1].g1>eve[len].g1) heap::push(i);
		}
	scan(C,len);
}

inline bool cmp(const int &a,const int &b) { return arg[a]<arg[b]; }

inline void buildmap() {
	for (int i=1;i<=n;i++) check(S,i,0);
	for (int i=1;i<=n;i++) check(T,i,1);
	for (int i=1;i<=n;i++) solve(i);
	for (int i=1,j;i<=n;i++)
		if (cir[i].size()) {
			sort(cir[i].begin(),cir[i].end(),cmp);
			link(cir[i].front(),cir[i].back(),(pi*2-(arg[cir[i].back()]-arg[cir[i].front()]))*R[i]);
			for (j=cir[i].size()-1;j;j--)
				link(cir[i][j-1],cir[i][j],(arg[cir[i][j]]-arg[cir[i][j-1]])*R[i]);
		}
}

