using namespace std;
typedef long long LL;
const int N = 1e5+5, mod = 998244353, M = 226*N;
LL ans;

struct seg {
	int x, l, r;
}tr[M];

int root[N<<2], sz, n, m;

inline int pow(int a,int b) {
	LL res = 1;
	for(;b;b>>=1,a=(LL)a*a%mod)
		if(b&1) res = res * a % mod;
	return res;
}

inline int merge(int x,int y) {
	return ((LL)x*y+(LL)(1-x+mod)%mod*(1-y+mod)%mod)%mod;
}

inline void change2(int &k,int l,int r,int x,int y,int val) {
	if(!k) k = ++sz, tr[k].x = 1;
	if(l==x && r==y) {
		tr[k].x = merge(tr[k].x,val); return ;
	}
	int mid = (l+r) >> 1;
	if(y <= mid) change2(tr[k].l,l,mid,x,y,val);
	else if(x > mid) change2(tr[k].r,mid+1,r,x,y,val);
	else change2(tr[k].l,l,mid,x,mid,val), change2(tr[k].r,mid+1,r,mid+1,y,val);
}

inline void change1(int k,int l,int r,int x1,int y1,int x2,int y2,int val) {
	if(l==x1 && r==y1) {
		change2(root[k],0,n+1,x2,y2,val);
		return;
	}
	int mid = (l+r) >> 1;
	if(y1 <= mid) change1(k<<1,l,mid,x1,y1,x2,y2,val);
	else if(x1 > mid)change1(k<<1|1,mid+1,r,x1,y1,x2,y2,val);
	else change1(k<<1,l,mid,x1,mid,x2,y2,val), change1(k<<1|1,mid+1,r,mid+1,y1,x2,y2,val);
}

inline void ask2(int k,int l,int r,int pos) {
	if(!k) return;
	ans = merge(ans,tr[k].x);
	if(l==r) return;
	int mid = (l+r) >> 1;
	if(pos <= mid) ask2(tr[k].l,l,mid,pos);
	else ask2(tr[k].r,mid+1,r,pos);
}

inline void ask1(int k,int l,int r,int x,int y) {
	ask2(root[k],0,n+1,y);
	if(l==r) return;
	int mid = (l+r) >> 1;
	if(x <= mid) ask1(k<<1,l,mid,x,y);
	else ask1(k<<1|1,mid+1,r,x,y);
}

inline int read() {
	int x=0,f=1;char ch = getchar();
	while(ch < '0' || ch > '9'){if(ch == '-')f=-1;ch = getchar();}
	while(ch >='0' && ch <='9'){x=(x<<1)+(x<<3)+ch-'0';ch = getchar();}
	return x*f;
}

int main() {
	n = read(), m = read();
	for(int i=1;i<=m;++i) {
		int opt = read(), l = read() , r = read();
		if(opt == 1) {
			int len = r - l + 1;
			int inv = pow(len,mod-2);
			int cha = (1 - inv + mod) % mod;
			if(l > 1) change1(1,0,n+1,1,l-1,l,r,cha);
			if(r < n) change1(1,0,n+1,l,r,r+1,n,cha);
			cha = (1 - (inv)*2 % mod + mod ) % mod;
			change1(1,0,n+1,l,r,l,r,cha);
			change1(1,0,n+1,0,0,0,l-1,0);
			change1(1,0,n+1,0,0,r+1,n+1,0);
			cha = (1-(LL)inv*(len-1)%mod+mod)%mod;
			change1(1,0,n+1,0,0,l,r,cha);
		}
		else {
			ans = 1;
			ask1(1,0,n+1,l-1,r);
			printf("%d\n", ans);
		}
	}
}

