int mod_pow(int x,int y) {
	int t=1;
	for (;y;y>>=1,x=1ll*x*x%mod)
		if (y&1) t=1ll*t*x%mod;
	return t;
}

#define mid (l+r>>1)

pii merge(pii x,pii y) {
