struct Segment_node {
	int rt;
	int newnod() {
		pool++;
		p1[pool]=p2[pool]=mp(1,0);
		return pool;
	}
	void add(int &rt,int l,int r,int x,int len) {
		if (!rt) rt=newnod();
		if (l==r) {
			p1[rt]=merge(p1[rt],mp(1ll*(len-1)*inv[len]%mod,inv[len]));
			p2[rt]=merge(p2[rt],mp(1ll*(len-2)*inv[len]%mod,2ll*inv[len]%mod));
			return;
		}
		if (x<=mid) add(L[rt],l,mid,x,len);
		else add(R[rt],mid+1,r,x,len);
		
		if (!L[rt]) L[rt]=newnod();
		if (!R[rt]) R[rt]=newnod();
		p1[rt]=merge(p1[L[rt]],p1[R[rt]]);
		p2[rt]=merge(p2[L[rt]],p2[R[rt]]);
	}
	pii ask(int &rt,int l,int r,int x,int y,int opt) {
		if (!rt) return mp(1,0);
		if (l==x && r==y) return opt==1?p1[rt]:p2[rt];
		if (y<=mid) return ask(L[rt],l,mid,x,y,opt);
		else if (x>mid) return ask(R[rt],mid+1,r,x,y,opt);
