inline int lcp(int x,int y,int n)
{
	int l=1,r=n-max(x,y)+1,res=0;
	while(l<=r){
		int mid=l+r>>1;
		if(H(x,x+mid-1).x==H(y,y+mid-1).x)res=mid,l=mid+1;
		else r=mid-1;
	}return res;
}
inline int comp(int x,int y,int n){
	int len=n-max(x,y)+1,l=lcp(x,y,n);
	if(l==len)return 0;
	return askc(x+l)<askc(y+l)?-1:1; 
}

