{
	if(l>=nl&&r<=nr)return;
	int mid=(l+r-1)>>1;
	if(nl<=mid)modify(p<<1,l,mid,nl,nr);
	if(nr>mid)modify(p<<1|1,mid+1,r,nl,nr);
