{
	seed = ((seed * 12321) ^ 9999) % 32768;
	return seed;
}
void generateData()
{
	scanf("%d%d%d",&k,&seed,&S);
	int t = 0;
	n = k * 2 + 1;
	for (int i = 1; i <= n; i++)
	{
		p[i] = (getrand() / 128) % 2;
		t += p[i];
	}
	int i = 1;
	while (t > k)
	{
		while (p[i] == 0)
			i++;
		p[i] = 0;
		t--;
	}
	while (t < k)
	{
		while (p[i] == 1)
			i++;
		p[i] = 1;
		t++;
	}
}
main()
{
	generateData();
	int be,now,lazy,sum,delta;
	int ans[3];
	for (int i=1;i<=n;++i)
		if (!p[i]) {be=i;break;}
	now=id(be+1);sum=0;
	do
	{
		sum+=(p[now]?1:-1);
		if (p[now]) ++num[sum+n];
		now=id(now+1);
	}while(now!=be);
	now=be;
	sum=0;
	lazy=0;
	for (int i=1;i<=n;++i) sum+=num[i+n];
	do
	{
		if (sum==0) ans[0]=now;
		if (sum==S) ans[1]=now;
		delta=0;
		now=id(now+1);
		while (p[id(now+delta)]) ++delta; 
		for (int i=1;i<=delta;++i)
		{
			--num[lazy+i+n];
			--sum;
			++num[lazy+i+n-1];
			if (i>1) ++sum;
		}
		if (!delta) sum+=num[lazy+n];
		else
			for (int i=1;i<delta;++i) sum-=num[lazy+n+i];
		lazy+=delta-1;
		now=id(now+delta);
	}while(now!=be);
	memset(num,0,sizeof(num));
	
	now=id(be+1);sum=0;
	do
	{
		sum+=(p[now]?-1:1);
		if (!p[now]) ++num[sum+n];
		now=id(now+1);
	}while(now!=be);
	now=be;
	sum=0;
	lazy=0;
	for (int i=1;i<=n;++i) sum+=num[i+n];
	do
	{
		if (sum==S) {ans[2]=now;break;}
		delta=0;
		now=id(now+1);
		while (p[id(now+delta)]) ++delta;
		--num[lazy-delta+1+n];
		if (!delta) --sum;
		if (!delta) sum-=num[lazy+n+1];
		else
			for (int i=0;i<delta-1;++i) sum+=num[lazy+n-i];
		lazy-=delta-1;
		++num[lazy+delta+n];
		if (delta) ++sum;
		now=id(now+delta);
	}while(now!=be);
	
	for (int i=0;i<3;++i) printf("%d\n",ans[i]);
}

