inline void dfs(int x,int fa)
{
	ll ue=0;int up=x;lp[x]=x;le[x]=0;d[x]=0;
	for(edge*i=p[x];i;i=i->ne)
		if(i->to!=fa)
		{
			dfs(i->to,x);
			if(d[i->to]>d[x])d[x]=d[i->to],dx[x]=dx[i->to],dy[x]=dy[i->to];
			ll t=le[i->to]+i->w;
			if(t>le[x])ue=le[x],up=lp[x],le[x]=t,lp[x]=lp[i->to];
			else if(t>ue)ue=t,up=lp[i->to];
		}
	if(le[x]+ue>d[x])d[x]=le[x]+ue,dx[x]=up,dy[x]=lp[x];
}

inline ll dfs2(int x,int fa,int y)
{
	ll ma=0,v=0;
	if(x==y)v=-1;
	for(edge*i=p[x];i;i=i->ne)
		if(i->to!=fa)
		{
			ll t=dfs2(i->to,x,y);
			if(t>=0)repr(ma,t+i->w);
			else v=t-i->w;
		}
	//out,"dfs2:",x,' ',v,' ',ma,'\n';
	if(v<0)
	{
		d[m]=-v-1;
		le[m++]=ma;
		return v;
	}
	return ma;
}

