	{
		int t=get(x+d[i]-le[i]+1);
		ll u=query(f,t),v=query(g,t),r=le[i]-d[i];
		//out,':',t,' ',vm,' ',u,' ',v,'\n';
		repl(aa,x-L-r-v);
		repl(ab,x-L-r-u);
		//out,x,' ',L,' ',r,' ',v,' ',u,'\n';
		//out,x-L-r-v,' ',x-L-r-u,' ';
		r=le[i]+d[i];
		repl(ba,x-L-r-v);
		repl(bb,x-L-r-u);
		//out,x-L-r-v,' ',x-L-r-u,'\n';
		//out,v,' ',u,'\n';
		t=get(r);
		modify(f,t,r);
		modify(g,t,le[i]-d[i]);
	}
	//out,"judge:",x,' ',aa,' ',ab,' ',ba,' ',bb,'\n';
	bb=-bb;
	ab=-ab;
	if(aa<bb)return 0;
	if(ba<ab)return 0;
	fo0(i,m)
	{
		ll bl=max(bb-d[i],ab+d[i]),br=min(aa-d[i],ba+d[i]);
		//out,'/',bl,' ',br,'\n';
		if(bl>br)continue;
		if(std::lower_bound(d,d+m,bl)<std::upper_bound(d,d+m,br))return 1;
	}
	return 0;
}

