const int N=1e5+5;

int power(int x,int y,int mod) {
	int t=1;
	for (;y;y>>=1,x=1LL*x*x%mod)
		if (y&1) t=1LL*t*x%mod;
	return t;
}

int n,m,K,ans,v[N],fa[N],ok[N];

int getf(int x) {
	if (x==fa[x]) return x;
	int tmp=fa[x],t=getf(fa[x]);
	v[x]^=v[tmp]; return fa[x]=t;
}

void merge(int x,int y) {
	if (x==y) { ans=0; return; }
	int fx=getf(x),fy=getf(y);
	if (fx==fy) {
		if (v[x]==v[y]) ok[fx]=1;
		return;
	}
	fa[fx]=fy;
	v[fx]=v[x]^v[y]^1;
}

int main() {
	
	for (int cas=rd();cas--;) {
		
		n=rd(),m=rd(),K=rd(),ans=1;
		For (i,1,n) fa[i]=i,v[i]=ok[i]=0;
		For (i,1,m) merge(rd(),rd());
		
		if (!m)
			 ans=power(K,n,6);
		else {
			For (i,1,n) if (getf(i)==i)
				ans=K*(K-1)*ans*(ok[i]^1)%6;
		}
		
		printf("%d\n",ans);
	}
	
	return 0;
}

