template <class T> void read(T &x) {
	int f = 1;
	char c = getchar();
	x = 0;
	while(c < '0' || c > '9') {
		if(c == '-') f = -1;
		c = getchar();
	}
	while(c >= '0' && c <= '9') x = x * 10 + c - '0', c = getchar();
	x *= f;
}

template <class T> void write(T x) {
	int len = 0;
	char s[30];
	if(x < 0) putchar('-'), x = -x;
	do {
		s[++len] = x % 10;
		x /= 10;
	}while(x);
	while(len) putchar(s[len--] + '0');
}

