int cnt, fa[maxn], dep[maxn];
int ans;

inline int find(int p) { 
	if(p == fa[p]) return p;
	int f = find(fa[p]); 
	dep[p] ^= dep[f];
	return fa[p] = f;
}

inline int count() {
	int sum = 1;
	cnt = n;
	for(int i = 1; i <= n; i++) fa[i] = i, dep[i] = 0;
	for(int i = 1; i <= m; i++) {
		int u0 = find(u[i]), v0 = find(v[i]);
		int w = dep[u[i]] ^ dep[v[i]] ^ 1;
		if(u0 != v0) fa[v0] = u0, dep[v0] = w, cnt--;
		else if(w) return 0;
	}
	cnt--;
	for(int i = 1; i <= cnt; i++) sum = sum * 2 % 6;
	if(!m) (sum += 5) %= 6;
	return sum;
}

int main() {
		read(t);
		while(t--) {
			read(n); read(m); read(k);
			for(int i = 1; i <= m; i++)
				read(u[i]), read(v[i]);
			if(k >= 1) ans = (!m) * k % 6;
			if(k >= 2) (ans += count() * k % 6 * (k - 1) % 6) %= 6;
			write(ans); putchar('\n');
		}
	return 0;
}

