inline int Mod(int x) {return x >= mod ? x - mod : x;}
inline int Mod2(int x) {return x < 0 ? x + mod : x;}
inline void mult(int *a, int *b, int *c, int k) {
    memset(tmp, 0, sizeof tmp);
    for (int i = 0; i < k; i++)
        for (int j = 0; j < k; j++) tmp[i + j] = (tmp[i + j] + 1ll * a[i] * b[j]) % mod;
    for (int i = k + k - 2; i >= k; i--) {
        for (int j = 1; j <= k; j++) tmp[i - j] = (tmp[i - j] + 1ll * tmp[i] * trans[j]) % mod;
    }
    for (int i = 0; i < k; i++) c[i] = tmp[i];
}
inline int calc(int k) {
    if (k == 0) return power(q, n);
    memset(sum, 0, sizeof sum);
    memset(dp, 0, sizeof dp);
    for (int i = 0; i <= k + 1; i++) sum[0][i] = 1;
    for (int j = k; j > 0; j--) {
        for (int i = 1; i * j <= k; i++) {
            if (i * j <= k) {
                int res = 0;
                for (int t = 1; t <= i; t++) res = (res + 1ll * sum[t - 1][j + 1] * sum[i - t][j]) % mod;
                dp[i][j] = 1ll * res * qpower[j] % mod * p % mod;
            }
            sum[i][j] = Mod(sum[i][j + 1] + dp[i][j]);
        }
    }
    memset(st, 0, sizeof st);
    k++;
    int tmp = n + 1;
    st[0] = 1;
    for (int i = 1; i <= k; i++) trans[i] = 1ll * sum[i - 1][1] * p % mod;
    for (int i = 1; i < k; i++) {
        for (int j = 1; j <= k; j++) if (i - j >= 0) st[i] = (st[i] + 1ll * st[i - j] * trans[j]) % mod;
    }
    memset(ans, 0, sizeof ans);
    memset(res, 0, sizeof res);
    res[1] = 1, ans[0] = 1;
    for (; tmp; tmp >>= 1, mult(res, res, res, k)) if (tmp & 1) mult(ans, res, ans, k);
    int all = 0;
    for (int i = 0; i < k; i++) all = (all + 1ll * st[i] * ans[i]) % mod;
    return 1ll * all * power(p, mod - 2) % mod;
}
