			b[N++] = item(a[i].a, tmp + 1, res, i, res);
		}
	}
	sort(b, b + N);
	build(rt, 0, maxp + 1);
	seg_y = maxp + 1;
	LL sum = 0;
	int res = 0;
	int ptr = 0;
	REP(i, 1, maxp + 1)
	{
		res += m;
		while (ptr < N)
		{
			seg_x = b[ptr].lim;
			seg_ret = -oo;
			query(rt, 0, maxp + 1);
			int fill = min(min(-seg_ret, res), b[ptr].cnt);
			if (fill)
			{
				seg_z = fill;
				add(rt, 0, maxp + 1);
				sum += (LL)b[ptr].w * fill;
				res -= fill;
				b[ptr].cnt -= fill;
				if (!res) break;
			}
			if (seg_ret && ~b[ptr].id && b[ptr].sum < a[b[ptr].id].c)
			{
				--b[ptr].lim;
				b[ptr].sum += a[b[ptr].id].x;
				b[ptr].cnt = a[b[ptr].id].x;
			}
			else ++ptr;
		}
		ans[i] = sum;
	}
	REP(i, 0, K)
	{
		int x;
		scanf("%d", &x);
		printf("%" LLFORMAT "d\n", ans[x]);
	}
	return 0;
}

