const int maxn = 1e5 + 5;
const int M = 1 << 30;

struct Point
{
	int x, y;
	int id;
	
	bool operator < (const Point &a) const
	{
		return x < a.x || x == a.x && y < a.y;
	}
	
} ps[maxn * 2];

inline LL Calc_Area(Point &p, Point &q)
{
	return 1ll * (p.y + q.y) * (q.x - p.x);
}

inline LL Cross(Point &p, Point &q, Point &r)
{
	return 1ll * (p.x - r.x) * (q.y - r.y) - 1ll * (p.y - r.y) * (q.x - r.x);
}

inline double CroX(Point &a, Point &b, Point &c, Point &d)
{
	RG int dx1 = b.x - a.x, dy1 = b.y - a.y;
	RG int dx2 = d.x - c.x, dy2 = d.y - c.y;
	RG LL k1 = 1ll * dy1 * dx2, k2 = 1ll * dy2 * dx1;
	return ((double) k1 * a.x - (double) k2 * c.x + (double) (c.y - a.y) * dx1 * dx2) / (k1 - k2);
}

const int N = 13000000;

int pt[N], pl[N], pr[N];
int lc[N], rc[N];
LL area[N];
int key[N];

int tot = 0;

inline void Update(int x)
{
	pl[x] = pr[x] = pt[x];
	area[x] = 0;
	RG int Lc = lc[x], Rc = rc[x];
	if (Lc)
	{
		pl[x] = pl[Lc];
		area[x] += area[Lc] + Calc_Area(ps[pr[Lc]], ps[pt[x]]);
	}
	if (Rc)
	{
		pr[x] = pr[Rc];
		area[x] += area[Rc] + Calc_Area(ps[pt[x]], ps[pl[Rc]]);
	}
}

inline int New_Node(int p)
{
	RG int t = ++ tot;
	pt[t] = pl[t] = pr[t] = p;
	lc[t] = rc[t] = 0;
	area[t] = 0;
	key[t] = rand();
	return t;
}

inline int Merge(int x, int y)
{
	if (!x) return y;
	if (!y) return x;
	RG int t = ++ tot;
	if (key[x] < key[y])
	{
		pt[t] = pt[x];
		pl[t] = pl[x];
		pr[t] = pr[x];
		lc[t] = lc[x];
		area[t] = area[x];
		key[t] = key[x];
		rc[t] = Merge(rc[x], y);
	}
	else
	{
		pt[t] = pt[y];
		pl[t] = pl[y];
		pr[t] = pr[y];
		rc[t] = rc[y];
		area[t] = area[y];
		key[t] = key[y];
		lc[t] = Merge(x, lc[y]);
	}
	Update(t);
	return t;
}

inline int Split_Left(int x, int y)
{
	if (pt[y] > pt[x])
	{
		return Split_Left(rc[x], y);
	}
	else
	{
		if (x == y && !lc[x])
		{
			return x;
		}
		RG int t = ++ tot;
		pt[t] = pt[x];
		pl[t] = pl[x];
		pr[t] = pr[x];
		rc[t] = rc[x];
		area[t] = area[x];
		key[t] = key[x];
		lc[t] = x == y ? 0 : Split_Left(lc[x], y);
		Update(t);
		return t;
	}
}

inline int Split_Right(int x, int y)
{
	if (pt[y] < pt[x])
	{
		return Split_Right(lc[x], y);
	}
	else
	{
		if (x == y && !rc[x])
		{
			return x;
		}
		RG int t = ++ tot;
		pt[t] = pt[x];
		pl[t] = pl[x];
		pr[t] = pr[x];
		lc[t] = lc[x];
		area[t] = area[x];
		key[t] = key[x];
		rc[t] = x == y ? 0 : Split_Right(rc[x], y);
		Update(t);
		return t;
	}
}

inline void Find(int x, int y, int &a, int &b)
{
	RG int &lcx = lc[x], &rcx = rc[x];
	RG int &lcy = lc[y], &rcy = rc[y];
	RG int &ptx = pt[x], &pty = pt[y];
	RG bool fxl = lcx && Cross(ps[pr[lcx]], ps[pty], ps[ptx]) < 0;
	RG bool fxr = rcx && Cross(ps[pl[rcx]], ps[pty], ps[ptx]) < 0;
	RG bool fyl = lcy && Cross(ps[pr[lcy]], ps[ptx], ps[pty]) > 0;
	RG bool fyr = rcy && Cross(ps[pl[rcy]], ps[ptx], ps[pty]) > 0;
	if (!fxl && !fxr && !fyl && !fyr)
	{
		a = x;
		b = y;
		return;
	}
	if (!fxl && !fxr)
	{
		if (fyl)
		{
			return Find(x, lcy, a, b);
		}
		else
		{
			return Find(x, rcy, a, b);
		}
	}
	if (!fyl && !fyr)
	{
		if (fxl)
		{
			return Find(lcx, y, a, b);
		}
		else
		{
			return Find(rcx, y, a, b);
		}
	}
	if (fxl && fyl) return Find(lcx, y, a, b);
	if (fxr && fyr) return Find(x, rcy, a, b);
	if (fxl && fyr) return Find(lcx, rcy, a, b);
	if (CroX(ps[ptx], ps[pl[rcx]], ps[pty], ps[pr[lcy]]) > ps[pr[x]].x)
	{
		return Find(x, lcy, a, b);
	}
	else
	{
		return Find(rcx, y, a, b);
	}
}

inline int Join(int p, int q)
{
	if (!p) return q;
	if (!q) return p;
	RG int ppl = pl[p], qpl = pl[q];
	if (ps[ppl].x == ps[qpl].x && ps[ppl].y <= ps[qpl].y) return q;
	RG int ppr = pr[p], qpr = pr[q];
	if (ps[ppr].x == ps[qpr].x && ps[ppr].y >= ps[qpr].y) return p;
	RG int a, b;
	Find(p, q, a, b);
	RG int x = Split_Right(p, a);
	RG int y = Split_Left(q, b);
	return Merge(x, y);
}

