void Build(Seg *&now, int l, int r)
{
	if (r <= l + D)
	{
		return;
	}
	
	RG int mid = l + r >> 1;
	now = p_seg ++;
	
	now->hull_up = p;
	p += r - l + 1;
	now->hull_dn = p;
	p += r - l + 1;
	
	now->hull_up[mid - l] = New_Node(mid);
	now->hull_dn[mid - l] = New_Node(mid + n);
	
	for (int i = mid - 1; i >= l; -- i)
	{
		now->hull_up[i - l] = Join(New_Node(i), now->hull_up[i + 1 - l]);
		now->hull_dn[i - l] = Join(New_Node(i + n), now->hull_dn[i + 1 - l]);
	}
	
	now->hull_up[mid + 1 - l] = New_Node(mid + 1);
	now->hull_dn[mid + 1 - l] = New_Node(mid + 1 + n);
	
	for (int i = mid + 2; i <= r; ++ i)
	{
		now->hull_up[i - l] = Join(now->hull_up[i - 1 - l], New_Node(i));
		now->hull_dn[i - l] = Join(now->hull_dn[i - 1 - l], New_Node(i + n));
	}
	
	Build(now->lc, l, mid);
	Build(now->rc, mid + 1, r);	
		
}

void Query(Seg *now, int l, int r, int L, int R, int &up, int &dn)
{
	RG int mid = l + r >> 1;
	if (R <= mid)
	{
		return Query(now->lc, l, mid, L, R, up, dn);
	}
	if (L > mid)
	{
		return Query(now->rc, mid + 1, r, L, R, up, dn);
	}
	up = Join(now->hull_up[L - l], now->hull_up[R - l]);
	dn = Join(now->hull_dn[L - l], now->hull_dn[R - l]);
	return;
}

Seg *root;

void Qry(int L, int R, int &up, int &dn)
{
	if (L > R)
	{
		up = 0;
		dn = 0;
		return;
	}
	if (R <= L + D)
	{
		up = 0;
		dn = 0;
		for (RG int i = L; i <= R; ++ i)
		{
			up = Join(up, New_Node(i));
			dn = Join(dn, New_Node(i + n));
		}
		return;
	}
	Query(root, 0, n - 1, L, R, up, dn);
}

