inline int MG(int x,int y)
{
	//if (!(x&&y)) return x|y;
	if (!x) return y;
	if (!y) return x;
	int d=t++;
	if (a[x].v>a[y].v)
		a[d]=a[x],a[d].r=MG(a[x].r,y);
