inline bool operator < (const P &a,const P &b) { return a.x==b.x?a.y>b.y:a.x<b.x; }
inline P operator + (const P &a,const P &b) { return (P){a.x+b.x,a.y+b.y}; }
inline P operator - (const P &a,const P &b) { return (P){a.x-b.x,a.y-b.y}; }
