	for (i=1;i<=n;i++) p[i].y*=-1;
	seg1.build();
	const int TOT=Treap::tot;
	//fprintf(stderr,"%d\n",TOT);return 0;
	while (m--) {
		k=gi();
		for (i=1;i<=k;i++) del[i]=(ans+gi()+n)%n+1;
		ans=
			seg0.solve(k,upL,upR)+
			seg1.solve(k,downL,downR);
		downL.y*=-1;
		downR.y*=-1;
		ans+=downL*upL+upR*downR;
		printf("%lld\n",ans*=-1);
		Treap::tot=TOT;
	}
	return 0;
}

#include<cstdio>
