using namespace std;
typedef long long LL;
const int N=100005;

struct point
{
	int x,y,b;
	bool operator <(const point &b) const { return x<b.x; }
	bool operator ==(const point &b) const { return x==b.x&&y==b.y; }
} P[N<<1];

struct node
{
	int l,r;
	LL s;
	int v;
	int pd,pl,pr;
} a[N*155];

LL an;
int *D[N<<3];
int f[N],i,j,k,n,m,Q,K,A,l,r,t,B,rtu,rtd,S[N*40],d[N<<1],q[N],g;
char c;

inline char getc()
{
	#define BUF_SIZE 10000000
    static char s[BUF_SIZE],*l=s+BUF_SIZE,*r=s+BUF_SIZE;
	if (l==r)
		l=s,r=s+fread(s,1,BUF_SIZE,stdin);
    return *l++;
}

inline int read(){ int k=1,z=0; do c=getc(); while ((c<'0'||c>'9')&&c!='-'); if (c=='-') k=-1,c=getc(); while (c>='0'&&c<='9') z*=10,z+=c-'0',c=getc(); return k*z; }

inline LL calc(int a,int b)
{
	return (LL)(P[b].x-P[a].x)*(P[a].y+P[b].y);
}

inline void updata(int x)
{
	a[x].pl=a[x].pr=a[x].pd,
	a[x].s=0;
	if (a[x].l)
		a[x].pl=a[a[x].l].pl,
		a[x].s+=a[a[x].l].s+calc(a[a[x].l].pr,a[x].pd);
	if (a[x].r)
		a[x].pr=a[a[x].r].pr,
		a[x].s+=a[a[x].r].s+calc(a[x].pd,a[a[x].r].pl);
}

inline void new_node(node &t,int d)
{
	t.l=t.r=0,
	t.s=0,
	t.v=rand(),
	t.pd=t.pl=t.pr=d;
}

inline int MG(int x,int y)
{
	//if (!(x&&y)) return x|y;
	if (!x) return y;
	if (!y) return x;
	int d=t++;
	if (a[x].v>a[y].v)
		a[d]=a[x],a[d].r=MG(a[x].r,y);
	else
		a[d]=a[y],a[d].l=MG(x,a[y].l);
	updata(d);
	return d;
}

inline int SL(int x,int y)
{
	if (a[y].pd<a[x].pd)
		return SL(a[x].l,y);
	else
	{
		if (x==y&&!a[x].r)
			return x;
		int d=t++;
		a[d]=a[x],
		a[d].r=x==y?0:SL(a[x].r,y),
		updata(d);
		return d;
	}
}

inline int SR(int x,int y)
{
	if (a[y].pd>a[x].pd)
		return SR(a[x].r,y);
	else
	{
		if (x==y&&!a[x].l)
			return x;
		int d=t++;
		a[d]=a[x],
		a[d].l=x==y?0:SR(a[x].l,y),
		updata(d);
		return d;
	}
}

inline LL cross(int a,int b,int w)
{
	return (LL)(P[a].x-P[w].x)*(P[b].y-P[w].y)-(LL)(P[b].x-P[w].x)*(P[a].y-P[w].y);
}

inline double CC(point a,point b,point c,point d)
{
	int dx1=a.x-b.x,dy1=a.y-b.y;
	int dx2=c.x-d.x,dy2=c.y-d.y;
	LL k1=(LL)dy1*dx2,k2=(LL)dy2*dx1;
	return ((double)k1*a.x-(double)k2*c.x+(double)(c.y-a.y)*dx1*dx2)/(k1-k2);
}

inline void find(int x,int y,int &A,int &B)
{
	bool l1=a[x].l&&cross(a[a[x].l].pr,a[y].pd,a[x].pd)<0,
		 r1=a[x].r&&cross(a[a[x].r].pl,a[y].pd,a[x].pd)<0,
		 l2=a[y].l&&cross(a[a[y].l].pr,a[x].pd,a[y].pd)>0,
		 r2=a[y].r&&cross(a[a[y].r].pl,a[x].pd,a[y].pd)>0;
	if (!(l1||r1||l2||r2))
	{
		A=x,B=y;
		return;
	}
	if (!(l1||r1))
		if (l2)
			return (void) find(x,a[y].l,A,B);
		else
			return (void) find(x,a[y].r,A,B);
	if (!(l2||r2))
		if (l1)
			return (void) find(a[x].l,y,A,B);
		else
			return (void) find(a[x].r,y,A,B);
	if (l1&&l2) return (void) find(a[x].l,y,A,B);
	if (r1&&r2) return (void) find(x,a[y].r,A,B);
	if (l1&&r2) return (void) find(a[x].l,a[y].r,A,B);
	if (CC(P[a[x].pd],P[a[a[x].r].pl],P[a[y].pd],P[a[a[y].l].pr])>P[a[x].pr].x)
		return (void) find(x,a[y].l,A,B);
	else
		return (void) find(a[x].r,y,A,B);
}

inline int Del(int x)
{
	if (a[x].l) return a[x].r;
	int d=t++;
	a[d]=a[x];
	a[d].l=Del(a[d].l);
	return d;
}

inline int Merge(int p,int q)
{
	//if (!(p&&q)) return p|q;
	if (!p) return q;
	if (!q) return p;
	if (P[a[p].pl].x==P[a[q].pl].x&&P[a[p].pl].y<=P[a[q].pl].y)
		return q;
	if (P[a[p].pr].x==P[a[q].pr].x&&P[a[p].pr].y>=P[a[q].pr].y)
		return p;
	if (P[a[p].pr]==P[a[q].pl])
		q=Del(q);
	int a,b;
	find(p,q,a,b);
	int z=MG(SL(p,a),SR(q,b));
	return z;
}

inline void build(int w,int L,int R)
{
	if (R-L<=15) return;
	D[w]=S+g,g+=R-L+1,D[w+A]=S+g,g+=R-L+1;
	int mid=L+R>>1;
	if (L==R)
	{
		D[w][0]=d[L],D[w+A][0]=d[L+n];
		return;
	}
	build(w<<1,L,mid),build(w<<1|1,mid+1,R);
	int W=D[w]-S+mid-L;
	S[W]=d[mid],S[W+1]=d[mid+1],
	W=D[w+A]-S+mid-L,
	S[W]=d[mid+n],S[W+1]=d[mid+1+n];
	int p1=D[w]-S+mid-1-L,p2=D[w+A]-S+mid-1-L;
	for (register int i=mid-1;i>=L;--p1,--p2,i--)
		S[p1]=Merge(d[i],S[p1+1]),
		S[p2]=Merge(d[i+n],S[p2+1]);
	p1=D[w]-S+mid+2-L,p2=D[w+A]-S+mid+2-L;
	for (register int i=mid+2;i<=R;++p1,++p2,i++)
		S[p1]=Merge(S[p1-1],d[i]),
		S[p2]=Merge(S[p2-1],d[i+n]);
}

inline void qtree(int w,int L,int R)
{
	int mid=L+R>>1;
	if (l<=mid&&r>mid)
	{
		rtu=Merge(rtu,Merge(D[w][l-L],D[w][r-L])),
		rtd=Merge(rtd,Merge(D[w+A][l-L],D[w+A][r-L]));
		return;
	}
	l>mid?qtree(w<<1|1,mid+1,R):qtree(w<<1,L,mid);
}

inline void MM()
{
	if (r-l<=15)
		for (;l<=r;++l) rtu=Merge(rtu,d[l]),rtd=Merge(rtd,d[l+n]);
	else
		qtree(1,0,n-1);
}

