long long brute_force()
{
	int i,j,s,p,q,inx,id,id1,id2;
	cnt=0;
	for(i=0;i<n;i++)
	{
		if(vis[i]!=times)
			tmp[cnt++]=pt[i];
	}
	if(cnt<=2)
		return 0;
    inx=inf;
    for(i=0;i<cnt;i++)
    {
        if(inx>tmp[i].x)
        {
           inx=tmp[i].x;
           id=i;
        }
    }
    swap(tmp[0],tmp[id]);
    xx=tmp[0].x;
    yy=tmp[0].y;
    sort(tmp+1,tmp+cnt);
    vec[num_layer].clear();
    for(i=0;i<cnt;i++)
    {
       while(vec[num_layer].size()>=2)
       {
           id1=vec[num_layer][vec[num_layer].size()-2];
           id2=vec[num_layer][vec[num_layer].size()-1];
           id=tmp[i].id;
           if(1LL*(pt[id].y-pt[id1].y)*(pt[id2].x-pt[id1].x)<1LL*(pt[id2].y-pt[id1].y)*(pt[id].x-pt[id1].x))
               vec[num_layer].pop_back();
           else
               break;
       }
       vec[num_layer].push_back(tmp[i].id);
    }
    long long ret=0;
    for(i=0;i<vec[num_layer].size();i++)
    {
       id1=vec[num_layer][i];
       id2=vec[num_layer][(i+1)%vec[num_layer].size()];
       ret+=1LL*(pt[id2].y-my)*(pt[id1].x-mx)-1LL*(pt[id2].x-mx)*(pt[id1].y-my);
    }
    return ret;
}
int main()
{
   scanf("%d%d",&n,&m);
    int i,j,s,p,q,id,ip,ie,ll,rr,ip1,ip2;
    for(i=0;i<n;i++)
    { 
        scanf("%d%d",&pt[i].x,&pt[i].y);
        pt[i].id=i;
    }
    init();
    ans=-1;
    for(i=0;i<m;i++)
    {
      scanf("%d",&k);
        for(j=0;j<=k;j++)
            sg[j].clear();
        times++;
        int tr=ans%n;
        if(tr<0)
           tr+=n;
        int ma=0;
        for(j=0;j<k;j++)
        {
            scanf("%d",&list[j]);
            list[j]=(1LL*tr+1LL*list[j])%n;     
            vis[list[j]]=times;
        }
        if(1LL*m*n<1e7)
        {
        	ans=brute_force();
		}
		else
		{
        times++;
        int nn=0;
        for(j=0;j<k;j++)
        {
            if(at[list[j]]>=0)
               list[nn++]=list[j];
        }
        k=nn;
        sort(list,list+k,cmp);
        nn=0;
        for(j=0;j<k;j++)
        {
        	if(nn==0||list[nn-1]!=list[j])
        	   list[nn++]=list[j];
		}
		k=nn;
        for(j=0;j<k;j++)
        {
        	if(j==0&&at[list[j]]!=0)
        	   break;
        	if(j&&at[list[j-1]]<at[list[j]]-1)
        	   break;
		}
		k=j;
		ma=-1;
        for(j=0;j<k;j++)
        {
            id=at[list[j]]; 
            if(ma<id)
                ma=id;
        }
        for(j=0;j<=ma+1;j++)
           sg[j].clear();
        j=ma+1;
        now.l=0;
        now.r=vec[j].size();
        now.id_layer=j;
        now.r--;
        if(now.l<=now.r)
           sg[j].push_back(now);
        ans=tot; 
        times++;
        for(j=k-1;j>=-1;j--)
        {
        	if(j<k-1&&(j<0||at[list[j]]!=at[list[j+1]]))
        	{
        		for(s=j+1;s<k;s++)
        		{
        			if(at[list[s]]!=at[list[j+1]])
        			   break;
				}
				id=at[list[j+1]];
				if(s-j-1==vec[id].size())
				{
					for(s=0;s<sg[id+1].size();s++)
						sg[id].push_back(sg[id+1][s]);
					continue;
				}
				q=vec[at[list[j+1]]].size()-1;
				for(p=s-1;p>j;p--)
				{
					if(as[list[p]]!=q)
					   break;
					q--;
				}
				p++; 
				int dx,dy;
				for(q=j+1;q<s;q++)
				{
					if(q==j+1)
					  dx=0;
					else
					  dx=as[list[q-1]]+1;
					if(as[list[q]]!=dx)
					{
					    if(dx!=0)
					    {
					       if(p==s)
					          dy=vec[id].size()-1;
					        else
					          dy=as[list[p]]-1;
						   got(id,vec[id][dy],vec[id][dx]);
					    }
						now.id_layer=id;
					    now.l=dx;
					    now.r=as[list[q]]-1;
					    sg[id].push_back(now);
					    p=q;
					}
				}
				if(as[list[s-1]]+1<vec[id].size())
				{
				    if(p==s)
					   dy=vec[id].size()-1;
			        else
			           dy=as[list[p]]-1;
				    dx=as[list[s-1]]+1;
				    got(id,vec[id][dy],vec[id][dx]);
					now.id_layer=id;
					now.l=as[list[s-1]]+1;
					now.r=vec[id].size()-1;
					sg[id].push_back(now);
				}
				else if(as[list[j+1]]!=0)
					got(id,vec[id][as[list[p]]-1],vec[id][0]);
        	}
		}
		ans=0;
		for(int ii=0;ii<sg[0].size();ii++)
		{
			 id=sg[0][ii].id_layer;
			 ll=sg[0][ii].l;
			 rr=sg[0][ii].r;
			 ans+=sum[id][rr]-sum[id][ll];
			 ip1=vec[id][rr];
			 ie=sg[0][(ii+1)%sg[0].size()].id_layer;
			 ll=sg[0][(ii+1)%sg[0].size()].l;
			 ip2=vec[ie][ll];
			 ans+=1LL*(pt[ip2].y-my)*(pt[ip1].x-mx)-1LL*(pt[ip2].x-mx)*(pt[ip1].y-my);
		} 
	   }
        printf("%lld\n",ans);
    }
    return 0;
}

