    {
       if(abs(1LL*(y-yy)*(temp.x-xx)-1LL*(x-xx)*(temp.y-yy))==0)
          return abs(x-xx)+abs(y-yy)>abs(temp.x-xx)+abs(temp.y-yy);
       return 1LL*(y-yy)*(temp.x-xx)-1LL*(x-xx)*(temp.y-yy)<0;
    }
