		if (dist[x] != t.fi) continue;
		for (int i = head[x]; i; i = nxt[i]){
			int v = to[i], w = cost[i];
			if (dist[v] > dist[x] + w){
				dist[v] = dist[x] + w;
				q.push(mp(dist[v], v));
			}
		}
	}
}

