int DP(){
	memset(dp, 0, sizeof(dp));
	dp[1][0] = 1;
	memset(in, 0, sizeof(in));
	for (int i = 1; i <= n; i++){
		for (int j = head[i]; j; j = nxt[j]){
			int v = to[j], w = cost[j];
			if (dist[v] == dist[i] + w) in[v]++;
		}
	}
	memset(cur, 0, sizeof(cur));
	queue <int> q;
	vector <int> order;
	q.push(1);
	while (!q.empty()){
		int x = q.front(); q.pop();
		order.push_back(x);
		for (int i = head[x]; i; i = nxt[i]){
			int v = to[i], w = cost[i];
			if (dist[v] == dist[x] + w){
				cur[v]++;
				if (cur[v] == in[v]) q.push(v);
			}
		}
	}
	for (int i = 1; i <= n; i++){
		if (in[i] != cur[i] && dist[i] <= k) return -1;
	}
	for (int j = 0; j <= k; j++){
		for (int p = 0; p < order.size(); p++){
			int x = order[p];
			for (int i = head[x]; i; i = nxt[i]){
				int v = to[i], w = cost[i];
				if (dist[x] + j + w - dist[v] <= k) add(dp[v][dist[x] + j + w - dist[v]], dp[x][j]);
			}
		}
	}
	long long ans = 0;
	for (int i = 0; i <= k; i++){
		add(ans, dp[n][i]);
	}
	return ans;
}

