void DFS(int cur, int res) {
  if (res > ans)
    return;
  if (cur > cnt) {
    ans = res;
    return;
  }
  if (!pos[cur].F || !pos[cur].S) {
    ok[cur] = 0;
    DFS(cur + 1, res);
    return;
  }
  ok[cur] = 1;
  int f0 = 0, f1 = 0;
  dir[cur].S = 0;
  FOR(i, 1, cur) {
    if (!ok[i])
      continue;
    if (pos[i].S > pos[cur].S)
      ++ f1;
    else if (pos[i].S > pos[cur].F)
      f0 += !dir[i].S, f1 += dir[i].S;
  }
  dir[cur].F = f0 > f1;
  DFS(cur + 1, res + mymin(f0, f1));
  f0 = 0, f1 = 0;
  dir[cur].S = 1;
  FOR(i, 1, cur) {
    if (!ok[i])
      continue;
    if (pos[i].S > pos[cur].S)
      ++ f0;
    else if (pos[i].S > pos[cur].F)
      f0 += !dir[i].S, f1 += dir[i].S;
  }
  dir[cur].F = f0 > f1;
  DFS(cur + 1, res + mymin(f0, f1));
}

