void add (int x, int y) {
	e[x][++e[x][0]] = y;
}
void dfs (int x, int pre) {
	mn[x][0] = x;
	mn[x][1] = (e[x][0] < 3 ? x : 1e9);
	for (int i = 1; i <= e[x][0]; ++i) {
		if (e[x][i] != pre) {
			dfs(e[x][i], x);
			mn[x][0] = min(mn[x][0], mn[e[x][i]][0]);
			mn[x][1] = min(mn[x][1], mn[e[x][i]][1]);
		}
	}
}
void findnext (int x, int pre, bool rooted, int &s, int &t) {
	if (e[x][1] == pre) {
		s = e[x][2], t = e[x][3];
	} else
	if (e[x][2] == pre) {
		s = e[x][1], t = e[x][3];
	} else {
		s = e[x][1], t = e[x][2];
	}
	if (mn[s][rooted] > mn[t][rooted]) {
		swap(s, t);
	}
}
void solve (int x, int pre, bool rooted) {
	int s, t;
	if (!rooted) {
		if (e[x][0] == 1) {
			printf("%d ", x);
			return;
		} else
		if (e[x][0] == 2) {
			printf("%d ", x);
			s = (e[x][1] != pre ? e[x][1] : e[x][2]);
			if (s <= mn[s][1]) { // it can be proved that eihter <= or < is correct(like a form of induction).
				solve(s, x, 0);
			} else {
				solve(s, x, 1);
			}
		} else {
			printf("%d ", x);
			findnext(x, pre, 0, s, t);
			solve(s, x, 1);
			solve(t, x, 0);
		}
	} else {
		if (e[x][0] == 1) {
			printf("%d ", x);
			return;
		} else
		if (e[x][0] == 2) {
			s = (e[x][1] != pre ? e[x][1] : e[x][2]);
			if (x < mn[s][1]) {
				printf("%d ", x);
				solve(s, x, 1);
			} else {
				solve(s, x, 1);
				printf("%d ", x);
			}
		} else {
			findnext(x, pre, 1, s, t);
			solve(s, x, 1);
			printf("%d ", x);
			solve(t, x, 1);
		}
	}
}
