int qpow(int a, int p) {
	if (p < 0)
		p += M - 1;
	int rt = 1, pa = a;
	for ( ; p; p >>= 1, pa = mul(pa, pa))
		if (p & 1)
			rt = mul(rt, pa);
	return rt;
}

