int addServlant(int x, int y, int z) {
	if (x + y + z == K)
		return id[x][y][z];
	if (m == 1)
		return id[x + 1][y][z];
	else if (m == 2)
		return id[x][y + 1][z];
	return id[x][y][z + 1];
}

inline void init() {
	scanf("%d%d%d", &T, &m, &K);
	
	for (int i = 0; i <= K; i++)
		for (int j = 0; i + j <= K && (m >= 2 || !j); j++)
			for (int k = 0; i + j + k <= K && (m == 3 || !k); k++)
				id[i][j][k] = cS++;
	cS++;
	g.r = g.c = cS, f.r = 1, f.c = cS;

	for (int i = 0; i <= K; i++)
		for (int j = 0; i + j <= K && (m >= 2 || !j); j++)
