				}
			if (f[val[k]] == last) continue;
			loop (l, b[val[k]]) {
				if (cur[val[l]] && cur[val[l]] < cur[val[k]] && last + 1 == f[val[l]]) {
					flag[val[l]] = T;
				}
			}
			add(val[k], f[val[k]], last);
		}
