	while((ch<'0'||ch>'9')&&ch!='-')ch=getchar();
	if(ch=='-')w=0,ch=getchar();
	while(ch>='0'&&ch<='9')x=(x<<3)+(x<<1)+ch-'0',ch=getchar();
	return w?x:-x;
}
const int N=1e6+5;
int n,m,q,tmp[N],l=666667,r=666666,a[N],pos[N],dp[N],cnt[N][20],ans[20];
vector<int>vec[N];
void answer(){
	for(int i=19;i;--i)if(ans[i]){printf("%d %d\n",i,ans[i]);return;}
}
void push_front(int x){
	a[pos[x]=--l]=x;
	for(int i=x;i<=m;i+=x)if(pos[i])++cnt[x][dp[i]];
	for(int i=dp[x]=1;i<19;++i)if(cnt[x][i])dp[x]=i+1;++ans[dp[x]];
}
void pop_front(){
	int x=a[l++];--ans[dp[x]];pos[x]=dp[x]=0;
	memset(cnt[x],0,sizeof(cnt[x]));
}
void push_back(int x){
	a[pos[x]=++r]=x;++ans[dp[x]=1];
	for(int d:vec[x])
		if(pos[d]){
			++cnt[d][1];int nw=2;
			for(int i=2;i<19;++i)if(cnt[d][i])nw=i+1;
			if(nw>dp[d]){
				for(int i:vec[d])
					if(pos[i]&&pos[i]<pos[d])
						--cnt[i][dp[d]],++cnt[i][nw];
				--ans[dp[d]];++ans[dp[d]=nw];
			}
		}
}
void pop_back(){
	int x=a[r--];--ans[1];pos[x]=dp[x]=0;
	for(int d:vec[x])
		if(pos[d]){
			--cnt[d][1];int nw=1;
			for(int i=1;i<19;++i)if(cnt[d][i])nw=i+1;
			if(nw<dp[d]){
				for(int i:vec[d])
					if(pos[i]&&pos[i]<pos[d])
						--cnt[i][dp[d]],++cnt[i][nw];
				--ans[dp[d]];++ans[dp[d]=nw];
			}
		}
}
int main(){
	n=gi();m=gi();q=gi();
	for(int i=m;i;--i)for(int j=i+i;j<=m;j+=i)vec[j].push_back(i);
	for(int i=1;i<=n;++i)tmp[i]=gi();
	for(int i=n;i;--i)push_front(tmp[i]);answer();
	for(int i=1,op,x;i<=q;++i){
		op=gi();
		if(op<2)x=gi(),op&1?push_back(x):push_front(x);
		else op&1?pop_back():pop_front();
		answer();
	}
	return 0;
}

