const int N=1e6+5;
int a[N*20],nxt[N*20],head[N],cnt,total;
void add(int x, int y) {a[++cnt]=y,nxt[cnt]=head[x],head[x]=cnt;}
int q[N],vis[N],A[N],b[N],st[N],dp[N],pos[N],to[N],ed[N],tot[N],n,m,Q,L,R;

void trans(int x,int y)
{
	if(dp[y]+1>dp[x]||(dp[y]+1==dp[x]&&ed[y]<ed[x]))
		tot[dp[x]]--,ed[x]=ed[y],dp[x]=dp[y]+1,tot[dp[x]]++;
}

void push_f(int x)
{
	vis[x]=1,pos[x]=--L,q[L]=x;
	dp[x]=1,ed[x]=pos[x],tot[dp[x]]++;
	for(int i=x+x;i<=m;i+=x) 
		if(vis[i]) trans(x,i);
}

void pop_f() {int x=q[L++];vis[x]=0,tot[dp[x]]--;}

void push_b(int x)
{
	vis[x]=1,pos[x]=++R,q[R]=x;
	dp[x]=1,ed[x]=pos[x],tot[dp[x]]++;
	int cntt=0;
	for(int p=head[x];p;p=nxt[p]) 
		if(vis[a[p]]) A[++cntt]=a[p];
	int top=0;
	for(int i=1;i<=cntt;++i)
	{
		int x=A[i];
		for(int j=1;j<=top;++j)
			if(pos[st[j]]>pos[x]&&st[j]%x==0) trans(x,st[j]);
		if(ed[x]==R) st[++top]=x;
	}
}

void pop_b()
{
	int x=q[R--]; vis[x]=0,tot[dp[x]]--;
	for(int p=head[x];p;p=nxt[p])
	{ 
		if(a[p]==x) continue;
		if(vis[a[p]]&&ed[a[p]]==R+1)
		{
			tot[dp[a[p]]]--;
			dp[a[p]]=1,ed[a[p]]=pos[a[p]];
			tot[dp[a[p]]]++;
			for(int j=a[p];j<=m;j+=a[p])
				if(vis[j]&&pos[j]>pos[a[p]]) trans(a[p],j);
		}
	}
}

