const int mod=998244353;
inline int read(){
    int x=0,w=0;char ch=getchar();
    while (!isdigit(ch))w|=ch=='-',ch=getchar();
    while (isdigit(ch))x=(x<<1)+(x<<3)+ch-'0',ch=getchar();
    return w?-x:x;
}
int ksm(int x,int p){
    int res=1;
    for (;p;x=1ll*x*x%mod,p>>=1)if (p&1)res=1ll*res*x%mod;
    return res;
}
int ans,n,L,A,x,M,K,v[N],sum[N],b[N],w[N],lim[N],l[N],r[N],m[N],f[N][N],a[N];
int solve(int x){
    int k=0;
    for (int i=1;i<=M;++i){
        if (v[i]==x)w[++k]=i;
        sum[i]=k;
    }
    memset(lim,0,sizeof(lim));
    for (int i=1;i<=n;++i)
        if (m[i]==x){
            if (sum[r[i]]-sum[l[i]-1]==0)
                return -1;//如果一个区间可以被一些mi比它小的区间完全覆盖，那么一定无法构造，这里可以简化成判断这个区间包含的所有小块mi的最小值是否至少有一个等于这个区间的mi
            int R=lower_bound(w+1,w+1+k,r[i])-w-1,L=lower_bound(w+1,w+1+k,l[i])-w;
            lim[R]=max(lim[R],L);
        }
    for (int i=1;i<=M;++i)lim[i]=max(lim[i],lim[i-1]);
    f[0][0]=1;
    for (int i=1;i<=k;++i){
        f[i][i]=0;int A=ksm(x-1,a[w[i]+1]-a[w[i]]),B=ksm(x,a[w[i]+1]-a[w[i]]);
        for (int j=0;j<i;++j){
            if (j>=lim[i])f[i][j]=1ll*f[i-1][j]*A%mod;else f[i][j]=0;
            f[i][i]=(f[i][i]+1ll*f[i-1][j]*((B-A+mod)%mod)%mod)%mod;
        }
    }
    int res=0;
    for (int i=0;i<=k;++i)res=(res+f[k][i])%mod;
    return res;
}
void work(){
    a[n+n+1]=1;a[n+n+2]=L+1;sort(a+1,a+1+n+n+2);
    sort(b+1,b+1+n);
    ans=1;M=unique(a+1,a+1+n+n+2)-a-1,K=unique(b+1,b+1+n)-b-1;
    memset(v,0x3f,sizeof(v));
    for (int i=1;i<=n;++i){
        l[i]=lower_bound(a+1,a+1+M,l[i])-a;
        r[i]=lower_bound(a+1,a+1+M,r[i])-a;
        for (int j=l[i];j<r[i];++j)v[j]=min(v[j],m[i]);
    }
    for (int i=1;i<=K;++i){
        if (~(x=solve(b[i])))ans=1ll*ans*x%mod;
        else{puts("0");return;}
    }
    for (int i=1;i<M;++i){
        if (v[i]==inf)
            ans=1ll*ans*ksm(A,a[i+1]-a[i])%mod;
    }
    printf("%d\n",ans);
}
signed main(){
    int T=read();
    while (T--){
        L=read(),n=read(),A=read();
        for (int i=1;i<=n;++i)a[i]=l[i]=read(),a[i+n]=r[i]=read()+1,b[i]=m[i]=read();
        work();
    }
    return 0;
}

