    int x;
    LL w;
  } f[N][6];

  int tim, e_cnt, L[N], beg[N], dep[N], end[N], fat[N], hed[N], par[N], siz[N], h[M][N];
  vector <int> cur;
  LL dis[N];

  inline int Min(int x, int y) {
    return dep[x] < dep[y] ? x : y;
  }

  inline void DFS(int x) {
    beg[x] = ++tim, h[0][tim] = x;
    for (int i = hed[x]; i; i = e[i].v) {
      if (!beg[e[i].p]) {
        par[e[i].p] = x;
        dep[e[i].p] = dep[x] + 1;
        dis[e[i].p] = dis[x] + e[i].w;
        DFS(e[i].p);
      }
    }
    end[x] = tim;
  }

  inline int LCA(int x, int y) {
    if (beg[x] > beg[y]) {
      swap(x, y);
    }
    if (end[x] >= end[y]) {
      return x;
    }
    int k = L[beg[y] - beg[x] + 1];
    assert(k < M);
    return par[Min(h[k][beg[x]], h[k][beg[y] - (1 << k) + 1])];
  }

  inline void Init() {
    for (int i = 1; i < n; ++i) {
      int x, y;
      LL w;
      Read(x), Read(y), Read(w);
      e[++e_cnt] = {y, hed[x], w}, hed[x] = e_cnt;
      e[++e_cnt] = {x, hed[y], w}, hed[y] = e_cnt;
    }
    DFS(1);
    for (int i = 2; i <= n; ++i) {
      L[i] = L[i >> 1] + 1;
    }
    for (int j = 1; j < M; ++j) {
      for (int i = 1; i + (1 << j) - 1 <= n; ++i) {
        h[j][i] = Min(h[j - 1][i], h[j - 1][i + (1 << j - 1)]);
      }
    }
  }

  inline void FindRoot(int x, int p, int s, int &c) {
    bool f = true;
    siz[x] = 1;
    for (int i = hed[x]; i; i = e[i].v) {
      if (!vis[e[i].p] && e[i].p != p) {
        FindRoot(e[i].p, x, s, c);
        siz[x] += siz[e[i].p], f &= siz[e[i].p] <= s >> 1;
      }
    }
    f &= siz[x] >= s >> 1;
    if (f) {
      c = x;
    }
  }

  inline void FindSize(int x, int p) {
    siz[x] = 1;
    for (int i = hed[x]; i; i = e[i].v) {
      if (!vis[e[i].p] && e[i].p != p) {
        FindSize(e[i].p, x), siz[x] += siz[e[i].p];
      }
    }
  }

  inline void FindTree(int x, int p, int c, LL d) {
    seq[++cnt] = x, bel[x] = c, val[x] = d;
    for (int i = hed[x]; i; i = e[i].v) {
      if (!vis[e[i].p] && e[i].p != p) {
        FindTree(e[i].p, x, c, d + e[i].w);
      }
    }
  }

  inline LL Dis(int x, int y) {
    return dis[x] + dis[y] - (dis[LCA(x, y)] << 1);
  }

  inline LL Val(Node a, Node b) {
    return a.w + b.w + Dis(a.x, b.x);
  }

  inline void VisualTree(Tree &C) {
    sort(seq + 1, seq + cnt + 1, [&](int x, int y) { return beg[x] < beg[y]; });
    for (int i = 1; i <= cnt; ++i) {
      sta[i] = seq[i];
    }
    top = cnt;
    for (int i = 1; i < cnt; ++i) {
      sta[++top] = LCA(seq[i], seq[i + 1]);
    }
    sort(sta + 1, sta + top + 1, [&](int x, int y) { return beg[x] < beg[y]; });
    top = unique(sta + 1, sta + top + 1) - sta - 1;
    for (int i = 1; i <= top; ++i) {
      for (int j = 0; j < 6; ++j) {
        f[sta[i]][j].x = f[sta[i]][j].w = 0;
      }
    }
    for (int i = 1; i <= cnt; ++i) {
      for (int j = 0; j < 2; ++j) {
        f[seq[i]][j].x = seq[i], f[seq[i]][j].w = val[seq[i]];
      }
    }
    cur.clear();
    for (int i = 1; i <= top; ++i) {
      while (!cur.empty() && LCA(cur.back(), sta[i]) != cur.back()) {
        cur.pop_back();
      }
      if (!cur.empty()) {
        fat[sta[i]] = cur.back();
      }
      cur.pb(sta[i]);
    }
    for (int i = top; i > 1; --i) {
      int x = sta[i], p = fat[x];
      for (int j = 0; j < 6; ++j) {
        if (f[x][j].x) {
          f[x][j].w += dis[x] - dis[p];
        }
      }
      for (int j = 0; j < 6; ++j) {
        if (f[x][j].x) {
          if (bel[f[p][j].x] == bel[f[x][0].x]) {
            CheckMax(ans, C.Val(f[p][j], f[x][2]));
            CheckMax(ans, C.Val(f[p][j], f[x][3]));
          } else {
            CheckMax(ans, C.Val(f[p][j], f[x][0]));
          }
          if (bel[f[p][j].x] == bel[f[x][1].x]) {
            CheckMax(ans, C.Val(f[p][j], f[x][4]));
            CheckMax(ans, C.Val(f[p][j], f[x][5]));
          } else {
            CheckMax(ans, C.Val(f[p][j], f[x][1]));
          }
        }
      }
      if (!f[p][0].x) {
        for (int j = 0; j < 6; ++j) {
          f[p][j] = f[x][j];
        }
      } else {
        LL cur_max = C.Val(f[p][0], f[p][1]);
        for (int j = 0; j < 2; ++j) {
          if (CheckMax(cur_max, C.Val(f[p][0], f[x][j]))) {
            swap(f[p][1], f[x][j]);
          }
        }
        for (int j = 0; j < 2; ++j) {
          if (CheckMax(cur_max, C.Val(f[p][1], f[x][j]))) {
            swap(f[p][0], f[x][j]);
          }
        }
        for (int j = 0; j < 2; ++j) {
          cur_max = -1;
          for (int k = j + 1 << 1; k < 6; ++k) {
            if (f[p][k].x && bel[f[p][k].x] != bel[f[p][j].x] && CheckMax(cur_max, C.Val(f[p][k], f[p][j]))) {
              swap(f[p][j + 1 << 1], f[p][k]);
            }
          }
          for (int k = 0; k < 6; ++k) {
            if (f[x][k].x && bel[f[x][k].x] != bel[f[p][j].x] && CheckMax(cur_max, C.Val(f[x][k], f[p][j]))) {
              swap(f[p][j + 1 << 1], f[x][k]);
            }
          }
          if (!~cur_max) {
            f[p][j + 1 << 1].x = f[p][j + 1 << 1].w = f[p][j + 1 << 1 | 1].x = f[p][j + 1 << 1 | 1].w = 0;
          } else {
            cur_max = -1;
            for (int k = j + 1 << 1 | 1; k < 6; ++k) {
              if (f[p][k].x && bel[f[p][k].x] != bel[f[p][j].x] && CheckMax(cur_max, C.Val(f[p][k], f[p][j + 1 << 1]))) {
                swap(f[p][j + 1 << 1 | 1], f[p][k]);
              }
            }
            for (int k = 0; k < 6; ++k) {
              if (f[x][k].x && bel[f[x][k].x] != bel[f[p][j].x] && CheckMax(cur_max, C.Val(f[x][k], f[p][j + 1 << 1]))) {
                swap(f[p][j + 1 << 1 | 1], f[x][k]);
              }
            }
          }
        }
      }
    }
  }
} A, B, C;

inline void Solve(int x, int s) {
  int c;
  A.FindRoot(x, 0, s, c);
  vis[x = c] = true;
  A.FindSize(x, 0);
  seq[cnt = 1] = x, bel[x] = val[x] = 0;
  for (int i = A.hed[x]; i; i = A.e[i].v) {
    if (!vis[A.e[i].p]) {
      A.FindTree(A.e[i].p, 0, A.e[i].p, A.e[i].w);
    }
  }
  B.VisualTree(C);
  for (int i = A.hed[x]; i; i = A.e[i].v) {
    if (!vis[A.e[i].p]) {
      Solve(A.e[i].p, A.siz[A.e[i].p]);
    }
  }
}

