	int dep[N*4];
	long long d[N*4];
	int df,ln[N*4][21],po[N],ls[N*4];
	inline void init()
	{
		tot=1,df=0;
	}
	inline void ade(int u,int v,long long w)
	{
		++tot;
		x[tot]=h[u];
		h[u]=tot;
		t[tot]=v;
		z[tot]=w;
	}
	void dfs(int now,int fa)
	{
		++df;
		ln[df][0]=now,po[now]=df;
		dep[now]=dep[fa]+1;
		for(int j=h[now];j;j=x[j])
			if(nxt!=fa)
			{
				d[nxt]=d[now]+z[j];
				dfs(nxt,now);
				ln[++df][0]=now;
			}
	}
	inline void build_LCA()
	{
		dfs(1,0);
		for(int k=1,lth=1;k<=20;++k,lth<<=1)
		for(int i=1;i<=df;++i)
			if(i+lth>df||dep[ln[i][k-1]]<dep[ln[i+lth][k-1]])
				ln[i][k]=ln[i][k-1];
			else
				ln[i][k]=ln[i+lth][k-1];
		ls[1]=0;
		for(int i=2;i<=df;++i)
			ls[i]=ls[i>>1]+1;
	}
	inline int LCA(int u,int v)
	{
		u=po[u],v=po[v];
		if(u>v)	swap(u,v);
		int lth=ls[v-u+1];
		if(dep[ln[u][lth]]<dep[ln[v-(1<<lth)+1][lth]])
			return ln[u][lth];
		else
			return ln[v-(1<<lth)+1][lth];
	}
	inline long long dist(int u,int v)
	{
		if(u==0||v==0)
			return -INF;
		return d[u]+d[v]-2*d[LCA(u,v)];
	}
};
