	{
		long long mxd;
		int mxp;
		for(int t=1;t<=T_inner;++t)
		{
			if(vis[now])
				break;
			vis[now]=1;
			mxd=0,mxp=now;
			for(int i=1;i<=n;++i)
				if(mxd<Dist(i,now))
				{
					mxd=Dist(i,now);
					mxp=i;
				}
			ans=max(ans,mxd);
			now=mxp;
		}
	}
	void solve()
	{
		cnt=n;
		for(int i=1;i<=n;++i)
			ln[i]=i;
		for(int i=1,bg,tmp;i<=T_outter&&cnt;++i)
		{
			bg=rnd()%cnt+1;
			work(ln[bg]);
			//so("%d\n",i);
			tmp=0;
			for(int i=1;i<=cnt;++i)
				if(!vis[ln[i]])
					ln[++tmp]=ln[i];
			cnt=tmp;
		}
	}
