    vis[x] = 1;
    while (head <= tail) {
        int u = q[head];
        ++head;
        for (int i = t[id].head[u]; i; i = t[id].e[i].nxt)
            if (!vis[t[id].e[i].to]) {
                int v = t[id].e[i].to;
                vis[v] = 1;
                dis[v][id] = dis[u][id] + t[id].e[i].val;
                ++tail;
                q[tail] = v;
            }
    }
}
inline unsigned long long R() {
    unsigned long long ret = 0;
    for (int i = 1; i <= 4; ++i) ret = ret << 15 ^ rand();
    return ret;
}
int _vis[N];
void solve(int v1, int v2, int v3) {
    int rt = R() % n + 1;
    assert(rt >= 1 && rt <= n);
    for (int T = 1; T <= 5; ++T) {
        ll mx = 0;
        _vis[rt] = 1;
        for (int i = 0; i < 3; ++i) dis[rt][i] = 0, dfs(rt, i);
        for (int i = 1; i <= n; ++i) {
            ll tmp = dis[i][0] + dis[i][1] + dis[i][2];
            ans = max(ans, tmp);
            tmp = v1 * dis[i][0] + v2 * dis[i][1] + v3 * dis[i][2];
            if (!_vis[i] && tmp > mx)
                rt = i, mx = tmp;
        }
    }
}
inline ll rd() {
    ll x = 0;
    char ch = getchar();
    bool f = 0;
    for (; !isdigit(ch); ch = getchar())
        if (ch == '-')
            f = 1;
    for (; isdigit(ch); ch = getchar()) x = x * 10 + ch - '0';
    return f ? -x : x;
}
