namespace Tree1
{
	int lg[MAXN],s[MAXN],t[MAXN],dfn_cnt,dep[MAXN];
	pair<ll,int> st[20][MAXN];
	long long dis[MAXN];
	
	void dfs_pre(int x,int fa)
	{
		st[0][s[x]=t[x]=++dfn_cnt]=mp(dep[x],x);
		for(int i=head[x];i;i=e[i].nxt)
		{
			int y=e[i].to;
			if(y==fa) continue;
			dis[y]=dis[x]+e[i].val;
			dep[y]=dep[x]+1,dfs_pre(y,x);
			st[0][t[x]=++dfn_cnt]=mp(dep[x],x);
		}
	}
	
	inline void prepare()
	{
		dfs_pre(1,0);
		for(int i=2;i<=dfn_cnt;i++)
			lg[i]=lg[i>>1]+1;
		for(int j=1;j<=lg[dfn_cnt];j++)
			for(int i=1;i+(1<<j)-1<=dfn_cnt;i++)
				st[j][i]=min(st[j-1][i],st[j-1][i+(1<<(j-1))]);
	}
	
	inline int query_lca(int x,int y)
	{
		int l=min(s[x],s[y]);
		int r=max(t[x],t[y]);
		int len=lg[r-l+1];
		return min(st[len][l],st[len][r-(1<<(len))+1]).second;
	}
	
	inline long long query_dis(int x,int y)
	{
		int lca=query_lca(x,y);
		return dis[x]+dis[y]-dis[lca]*2;
	}
}

using Tree1::query_dis;

namespace Tree2
{
	int dep[MAXN],son[MAXN],fa[MAXN],siz[MAXN];
	int in[MAXN],out[MAXN],dfn_cnt,*col;
	int f[MAXN][2][2],top[MAXN];
	long long dis[MAXN],*val;
	vector<int> v[MAXN];
	
	void dfs_son(int x,int fath)
	{
		dep[x]=dep[fath]+1;
		siz[x]=1,fa[x]=fath;
		for(int i=head[x];i;i=e[i].nxt)
		{
			int y=e[i].to;
			if(y==fath) continue;
			dis[y]=dis[x]+e[i].val;
			dfs_son(y,x),siz[x]+=siz[y];
			if(siz[y]>siz[son[x]]) son[x]=y;
		}
	}
	
	void dfs_chain(int x,int tp)
	{
		top[x]=tp,in[x]=++dfn_cnt;
		if(son[x]) dfs_chain(son[x],tp);
		for(int i=head[x];i;i=e[i].nxt)
		{
			int y=e[i].to;
			if(y==fa[x]||y==son[x])
				continue;
			dfs_chain(y,y);
		}
		out[x]=dfn_cnt;
	}
	
	inline int query_lca(int x,int y)
	{
		while(top[x]!=top[y])
		{
			if(dep[top[x]]<dep[top[y]]) swap(x,y);
			x=fa[top[x]];
		}
		return dep[x]<dep[y]?x:y;
	}
	
	inline void prepare()
	{
		dfs_son(1,0);
		dfs_chain(1,1);
	}
	
	inline long long D(int x,int y)
	{
		return query_dis(x,y)+dis[x]+dis[y]+val[x]+val[y];
	}
	
	inline void merge(int *x,int *y)
	{
		long long tmp=0;
		int a=x[0],b=x[1],c=y[0],d=y[1];
		ll k1=D(a,b),k2=D(a,c),k3=D(a,d);
		ll k4=D(b,c),k5=D(b,d),k6=D(c,d);
		if(k1>tmp) tmp=k1,x[0]=a,x[1]=b;
		if(k2>tmp) tmp=k2,x[0]=a,x[1]=c;
		if(k3>tmp) tmp=k3,x[0]=a,x[1]=d;
		if(k4>tmp) tmp=k4,x[0]=b,x[1]=c;
		if(k5>tmp) tmp=k5,x[0]=b,x[1]=d;
		if(k6>tmp) tmp=k6,x[0]=c,x[1]=d;
		if(!a&&!b) x[0]=y[0],x[1]=y[1];
	}
	
	inline bool cmp(int x,int y)
	{
		return in[x]<in[y];
	}
	
	inline void add_edge(int x,int y)
	{
		v[x].push_back(y);
		v[y].push_back(x);
	}
	
	inline void build(int *s,int tot)
	{
		static int st[MAXN],top;
		sort(s+1,s+tot+1,cmp);
		for(int i=tot;i>1;i--)
			s[++tot]=query_lca(s[i-1],s[i]);
		sort(s+1,s+tot+1,cmp),top=0;
		tot=unique(s+1,s+tot+1)-s-1;
		for(int i=1;i<=tot;i++)
		{
			while(top&&out[st[top]]<in[s[i]]) top--;
			if(top) add_edge(s[i],st[top]);
			st[++top]=s[i];
		}
	}
	
	void dfs(int x,int fa)
	{
		memset(f[x],0,sizeof(f[x]));
		if(col[x]==1) f[x][0][0]=f[x][0][1]=x;
		if(col[x]==2) f[x][1][0]=f[x][1][1]=x;
		for(auto y:v[x])
			if(y!=fa)
			{
				dfs(y,x);
				for(int i=0;i<=1;i++)
					for(int j=0;j<=1;j++)
						for(int k=0;k<=1;k++)
							Max(ans,D(f[x][i][j],f[y][i^1][k])-dis[x]*2);
				merge(f[x][0],f[y][0]);
				merge(f[x][1],f[y][1]);
			}
		col[x]=0,v[x].clear();
	}
	
	inline void solve(int *s,int tot,int *c,ll *v)
	{
		col=c,val=v,build(s,tot),dfs(s[1],0);
	}
}

namespace Tree3
{
	struct Node
	{
		int to; ll dist;
		Node()=default;
		Node(int a,ll b)
			: to(a),dist(b) { }
	};
	vector<Node> v[MAXN];
	int cnt,mx,edge,top,tot,vis[MAXM];
	int col[MAXN],siz[MAXN],st[MAXN];
	long long dis[MAXN];
	
	inline void readin()
	{
		cnt=n;
		for(int i=2;i<=n;i++)
		{
			int x=read(),y=read(); ll z=read();
			v[x].emplace_back(y,z);
			v[y].emplace_back(x,z);
		}
	}
	
	void dfs_rebuild(int x,int fa)
	{
		int lst=0;
		for(auto y:v[x])
		{
			if(y.to==fa) continue;
			if(!lst) lst=x,add_edge(x,y.to,y.dist);
			else add_edge(++cnt,y.to,y.dist),
				add_edge(lst,cnt),lst=cnt;
			dfs_rebuild(y.to,x);
		}
	}
	
	void dfs_edge(int x,int fa)
	{
		siz[x]=1;
		for(int i=head[x];i;i=e[i].nxt)
		{
			int y=e[i].to;
			if(vis[i]||y==fa) continue;
			dfs_edge(y,x),siz[x]+=siz[y];
			int cur=max(siz[y],tot-siz[y]);
			if(cur<=mx) edge=i,mx=cur;
		}
	}
	
	void dfs_dis(int x,int fa,int opt)
	{
		col[x]=opt,siz[x]=1;
		if(x<=n) st[++top]=x;
		for(int i=head[x];i;i=e[i].nxt)
		{
			int y=e[i].to;
			if(y==fa) continue;
			if(vis[i]) continue;
			dis[y]=dis[x]+e[i].val;
			dfs_dis(y,x,opt),siz[x]+=siz[y];
		}
	}
	
	inline void calc()
	{
		int x=e[edge].to;
		int y=e[edge^1].to;
		dis[x]=0,dfs_dis(x,y,1);
		dis[y]=e[edge].val,dfs_dis(y,x,2);
		Tree2::solve(st,top,col,dis),top=0;
	}
	
	void dfs()
	{
		calc();
		int x=e[edge].to;
		int y=e[edge^1].to;
		vis[edge]=vis[edge^1]=1;
		if(siz[x]>1)
			mx=tot=siz[x],
			dfs_edge(x,y),dfs();
		if(siz[y]>1)
			mx=tot=siz[y],
			dfs_edge(y,x),dfs();
	}
	
	inline void solve()
	{
		readin();
		dfs_rebuild(1,0);
		mx=tot=cnt,dfs_edge(1,0),dfs();
	}
}

