bool sp[N];
int bfs(int s)
{
    memset(d,-1,sizeof(d));
    d[s] = 0;
    q.push(s);
    while(q.size()){
        int t = q.front();
        q.pop();
        for(int i = 0;i < E[t].size();i++){
            if(d[E[t][i]] == -1) {d[E[t][i]] = d[t] + 1;q.push(E[t][i]);last[E[t][i]] = t;}
        }
    }
    int ans = 1;
    for(int i = 1;i <= n;i++){
        if(d[i] > d[ans]) ans = i;
    }
    return ans;
}
inline int max(int a,int b)
{
    return a > b ? a : b;
}
void dfs(int fa,int u,int de)
{
    dep[u] = de;
    maxd = max(maxd , de);
    bool f = 1;
    for(int i = 0;i < E[u].size();i++){
        if(E[u][i] != fa) {dfs(u , E[u][i] , de + 1);f = 0;}
    }
    if(f) total++;
    return ;
}
void dfs2(int fa,int ch,int u)
{
    bool f = 1;
    for(int i = 0;i < E[u].size();i++){
        if(E[u][i] != fa){
            if(fa == 0) dfs2(u , E[u][i] , E[u][i]);
            else dfs2(u , ch , E[u][i]);
            siz[u] += siz[E[u][i]];
            f = 0;
        }
    }
    if(!f) return;
    if(Tr % 2 == 0 && dep[u] == maxd){
        siz[u] = 1;return;
    }
    else if(Tr % 2 && (dep[u] >= maxd - 1)){
        if(dep[u] == maxd) {even++; sp[ch] = 1;}
        else if(sp[ch] != 1) odd++;
        return;
    }
    return;
}
int exgcd(int a, int b,int &x, int &y){
    int d = a;
    if(b != 0){
        d = exgcd(b, a % b, y, x);
        y -= (a / b) * x;
    }
    else  x = 1, y = 0;
    return d;
}
