    int p = y;Tr = d[y];
    for(int i = 1;i <= d[y] / 2;i++) p = last[p];
    dfs(0,p,1);
    dfs2(0,0,p);
  //  printf("%d\n",p);
  //  printf("%d %d\n",even,odd);
    if(Tr % 2) {s.push_back(even);s.push_back(odd);ts = even + odd;}
    else{
        for(int i = 0;i < E[p].size();i++) {if(siz[E[p][i]] != 0){s.push_back(siz[E[p][i]]);ts += siz[E[p][i]];}}
    }
    h[0] = 0;
    for(int i = 1;i <= n;i++){
        int g = 0;exgcd(i , mod , h[i] , g);
        if(h[i] < mod) h[i] += mod;
        h[i] %= mod;
        h[i] = (h[i] + h[i - 1]) % mod;
    }
    for(int i = 0;i < s.size();i++){
        int g = (1LL * total * h[ts - s[i]]) % mod;
        ans = (ans + g) % mod;
    }
    int g = (1LL * total * h[ts]) % mod;g = (1LL * g * (s.size() - 1)) % mod;
    printf("%d\n",(ans - g + mod) % mod);
    return 0;
}

#include <bits/stdc++.h>
#define for1(a,b,i) for(int i=a,end_=b;i<=end_;++i)
#define FOR2(a,b,i) for(int i=a,end_=b;i>=end_;--i)
using namespace std;
typedef long long ll;

#define M 1000005
#define mod 998244353
int n,cnt;
bool vis[M];
int f[M],g[M],js[M],ni[M],inv[M];
int pos,root,e_size,head[M],du[M],dep[M],Max[M];

vector <int> sta;

struct node {int v,nxt;}e[M*2];

inline void e_add(int u,int v) {
	e[++e_size]=(node){v,head[u]};
	head[u]=e_size;
}

inline int qpow(int x,int ci) {
	int sum=1;
	for(;ci;ci>>=1,x=1ll*x*x%mod)
		if(ci&1) sum=1ll*x*sum%mod;
	return sum;
}

inline int get_C(int x,int y) {
	if(x<y) return 0;
	return 1ll*js[x]*ni[y]%mod*ni[x-y]%mod;
}

inline void inc(int &x,int y) {x+=y,x-=x>=mod?mod:0;}

inline void dfs(int x,int fa,int now) {
	dep[x]=Max[x]=dep[fa]+1;
	cnt+=now==dep[x]&&du[x]==1;
	for(int i=head[x];i;i=e[i].nxt) {
		int v=e[i].v;
		if(v==fa) continue;
		dfs(v,x,now);
		Max[x]=max(Max[x],Max[v]);
	}
}

int main () {
	//freopen("a.in","r",stdin);
	scanf("%d",&n);
	for1(2,n,i) {
		int x,y;
