		++du[x],++du[y];
		e_add(x,y),e_add(y,x);
	}
	dfs(1,0,0);
	for1(1,n,i) if(dep[i]>dep[pos]) pos=i;
	dfs(pos,0,0);
	for1(1,n,i) if(Max[i]>Max[root]&&(Max[i]+1>>1)==dep[i]) root=i;
	
	if(Max[pos]&1) {
		dfs(root,0,0);
		pos=0;
		for1(1,n,i) if(dep[i]>dep[pos]) pos=i;
		for(int i=head[root];i;i=e[i].nxt) {
			int v=e[i].v;
			cnt=0;
			dfs(v,root,dep[pos]);
			if(cnt) sta.push_back(cnt);
		}
	}
	else {
	//	cout<<root<<endl;
		dfs(root,0,0);
		pos=0;
		for1(1,n,i) if(dep[i]>dep[pos]) pos=i;
		//cout<<pos<<endl;
		
		cnt=0;
		dfs(root,0,dep[pos]);
		sta.push_back(cnt);
		cnt=0;
		dfs(root,0,dep[pos]-1);
		sta.push_back(cnt);
	}
	
	js[0]=1;
	for1(1,n,i) js[i]=1ll*i*js[i-1]%mod;
	ni[n]=qpow(js[n],mod-2);
	FOR2(n,1,i) ni[i-1]=1ll*i*ni[i]%mod;
	for1(1,n,i) inv[i]=1ll*ni[i]*js[i-1]%mod;
	
	int ans=0;
	int sum=0,tot_x=0;
	for1(1,n,i) tot_x+=du[i]==1;
	for1(1,sta.size(),i) sum+=sta[i-1];
	for1(1,tot_x,i) inc(f[i]=f[i-1],1ll*tot_x*inv[tot_x-i+1]%mod);
	tot_x-=sum;
	
	for1(1,sta.size(),i) {
		int sel=0;
		int t=sta[i-1];
		//cout<<-t<<" "<<tot_x-1<<endl;
		for1(-t,tot_x-1,j) {
			sel=get_C(t+tot_x,t+j);
			if(j>=0) inc(sel,mod-get_C(tot_x,j));
			if(!vis[sum+j]) {
				vis[sum+j]=1;
				g[sum+j]=1ll*js[sum+j]*inv[sum+j]%mod*f[sum+j]%mod*js[tot_x-j]%mod;
			}
			inc(ans,1ll*(sum-t)*g[sum+j]%mod*sel%mod);
		}
	}
	ans=1ll*ans*ni[sum+tot_x]%mod;
	cout<<ans<<endl;
}

