int mi(int x,int y){
	if (y==0)return 1;
	int t=mi(x,y>>1);
	t=1ll*t*t%mod;
	return y&1?(1ll*x*t%mod):t;
}
void getrt(int x,int fa){
	size[x]=1;
	for (int i=fi[x];i;i=ne[i])
		if (a[i]!=fa){
			getrt(a[i],x);
			size[x]+=size[a[i]];
			f[x]=max(f[x],size[a[i]]);
		}
	f[x]=max(f[x],n-size[x]);
	if (f[x]<f[rt])rt=x;
}
