int C(int x,int y){return 1ll*fac[x]*inv[y]%mod*inv[x-y]%mod;}
int getde(int x,int fa){
	if (du[x]==1)return d[x];
	int mx=0;
	for (int i=fi[x];i;i=ne[i])
		if (a[i]!=fa){
			mx=max(mx,getde(a[i],x));
		}
	return mx;
}
