inline int find(int x){
	if(fa[x]==x) return x;
	int u=fa[x];
	fa[x]=find(fa[x]);
	co[x]^=co[u]^1;
	return fa[x];
}
void merge(int x,int y,int flag){
	int u=find(x),v=find(y);
	if(u==v){
		if(co[x]^co[y]^flag){cerr<<co[x]<<' '<<co[y]<<' '<<x<<' '<<y<<' '<<u<<' '<<v<<' '<<flag<<endl,printf("0\n");exit(0);}
		return;
	}
	co[u]=co[x]^co[y]^1^flag;
	fa[u]=v;
}
set<int> st;
set<int>::iterator it,it1;
struct Segment_tree{
	int Max[maxn<<3];
	void update(int x,int L,int R,int q,int v){
		if(L==R){
			Max[x]=v;
			return;
		}
		int Mid=(L+R)>>1;
		if(q<=Mid) update(x<<1,L,Mid,q,v);
		else update(x<<1|1,Mid+1,R,q,v);
		Max[x]=max(Max[x<<1],Max[x<<1|1]);
	}
	int query(int x,int L,int R,int ql,int qr){
		if(ql<=L && R<=qr) return Max[x];
		int Mid=(L+R)>>1,res=0;
		if(ql<=Mid) chkmax(res,query(x<<1,L,Mid,ql,qr));
		if(qr>Mid) chkmax(res,query(x<<1|1,Mid+1,R,ql,qr));
		return res;
	}
}Seg;
