	sort(a+1,a+n+1);
	REP(i,1,n) p[a[i].r]=i,fa[i]=i,co[i]=1;
//	REP(i,1,2*n) printf("%d %d\n",i,p[i]);
	REP(i,1,n){
		it=st.lower_bound(a[i].l);
		if(it!=st.end() && (*it)<=a[i].r) f[i]=p[*it];
		it=st.lower_bound(a[i].r);
		if(it!=st.end() && (*it)>=a[i].r) g[i]=p[*it];
		st.insert(a[i].r);
	}
	st.clear();
	REP(i,1,n){
//		cout<<a[i].l<<' '<<a[i].r<<' '<<f[i]<<' '<<g[i]<<' '<<a[f[i]].l<<' '<<a[f[i]].r<<' '<<a[g[i]].l<<' '<<a[g[i]].r<<endl;
		if(f[i]) merge(f[i],i,1);
		it=st.lower_bound(a[i].l);
		while(it!=st.end()){
			if((*it)>a[i].r) break;
			merge(p[*it],i,1);
			if(a[g[p[*it]]].r>=a[i].r) break;
			merge(p[*it],g[p[*it]],0);
			it1=it;
			++it;
			st.erase(it1);
		}
		int u=Seg.query(1,1,2*n,a[i].l,a[i].r);
		if(u>=a[i].l){
//			cerr<<u<<' '<<a[i].l<<' '<<a[i].r<<"@%@#"<<endl;
			return printf("0\n"),0;
		}
		Seg.update(1,1,2*n,a[i].r,a[f[i]].r);
		if(g[i]) st.insert(a[i].r);
	}
	int ans=1;
	REP(i,1,n) if(fa[i]==i) ans=2*ans%mod;
	printf("%d\n",ans);
	return 0;
}

