inline double get_dis(node &a,node &b) {
	return sqrt((a.x-b.x)*(a.x-b.x)+(a.y-b.y)*(a.y-b.y));
}

inline node inter_(Line a,Line b) {
	double k1,k2,t;
	k1=(b.b-a.a)*(a.b-a.a);
	k2=(a.b-a.a)*(b.a-a.a);
	t=k1/(k1+k2);
	return (node) {b.b.x+(b.a.x-b.b.x)*t,b.b.y+(b.a.y-b.b.y)*t};
}

inline bool judge(int x,int y,double now) {
	int ax=e[y*2].v,ay=e[y*2-1].v;
	if(a[ax].y==a[ay].y) {
		if(a[ax].x>a[ay].x) swap(ax,ay);
		if(a[x].x<a[ax].x||a[x].x>a[ay].x) 
			return min(get_dis(a[x],a[ax]),get_dis(a[x],a[ay]))<=now;
		else 
			return fabs(a[x].y-a[ax].y)<=now;
	}
	
	else if(a[ax].x==a[ay].x) {
		if(a[ax].y>a[ay].y) swap(ax,ay);
		if(a[x].y<a[ax].y||a[x].y>a[ay].y) 
			return min(get_dis(a[x],a[ax]),get_dis(a[x],a[ay]))<=now;
		else 
			return fabs(a[x].x-a[ax].x)<=now; 
	}
	
	else {
		double k=(a[ay].x-a[ax].x)/(a[ax].y-a[ay].y);
		node p=inter_((Line){a[ax],a[ay]},(Line){a[x],(node){a[x].x+1,a[x].y+k}});
		if(a[ax].x>a[ay].x) swap(ax,ay); 
		if(p.x<a[ax].x||p.x>a[ay].x)
			return min(get_dis(a[x],a[ax]),get_dis(a[x],a[ay]))<=now;
		else 
			return get_dis(a[x],p)<=now;
	}
	
}

