	for1(1,n-1,i) if(f[sty][i]) cc.push(make_pair(sty,i));
	
	while (!cc.empty()) {
		pair<int,int> ha=cc.front(); cc.pop();
		int x=e[ha.second*2].v,y=e[ha.second*2-1].v;
		int r=ha.first;
		for(int i=head[r];i;i=e[i].nxt) {
			int v=e[i].v;
			if(!f[x][i+1>>1]&&judge(x,i+1>>1,now)) {
				f[x][i+1>>1]=1;
				cc.push(make_pair(x,i+1>>1));
			}
			if(!f[y][i+1>>1]&&judge(y,i+1>>1,now)) {
				f[y][i+1>>1]=1;
				cc.push(make_pair(y,i+1>>1));
			}
			if(!f[v][ha.second]&&judge(v,ha.second,now)) {
				f[v][ha.second]=1;
				cc.push(make_pair(v,ha.second));
			}
		}
	}
	for1(1,n,i) if(du[i]==1)
		for1(1,n-1,j) if(f[i][j]) {
			int x=e[j*2].v,y=e[j*2-1].v;
			if(du[x]==1&&get_dis(a[i],a[x])<=now) return 1;
			if(du[y]==1&&get_dis(a[i],a[y])<=now) return 1;
		}
	return 0;
}

