double minn(double x,double y)
{
	return x<y?x:y;
}
double abss(double x)
{
	return x>0?x:-x;
}
double di(point x,point y,point z)
{
	double d1=z.xa-y.xa,d2=z.ya-y.ya;
	if(d1==0)
	{
		if((x.ya-y.ya)*(x.ya-z.ya)<=0)
		    return abss(y.xa-x.xa);
		return minn(dis(x,z),dis(x,y));
	}
	if(d2==0)
	{
		if((x.xa-y.xa)*(x.xa-z.xa)<=0)
		    return abss(y.ya-x.ya);
		return minn(dis(x,z),dis(x,y));
	}
	double xi=(y.ya-d2/d1*y.xa-x.ya+d1/(-d2)*x.xa)/(d1/(-d2)-d2/d1);
	if((y.xa-xi)*(z.xa-xi)>0)  return minn(dis(x,z),dis(x,y));
	double dot=(y-x)*(z-x);
	if(dot<0)  dot=-dot;
	return dot/dis(y,z);
}
