inline bool isroot(int x){return t[t[x].fa].ch[0]!=x && t[t[x].fa].ch[1]!=x;}
inline void maintain(int x){t[x].s1=t[t[x].ch[0]].s1+t[t[x].ch[1]].s1+a[x]+t[x].s2;}
inline void rotate(int x){
	int y=t[x].fa,z=t[y].fa,o;
	if(!isroot(y))t[z].ch[t[z].lr(y)]=x;
	t[x].fa=z,t[y].fa=x;o=t[y].lr(x);
	t[y].ch[o]=t[x].ch[!o];t[t[x].ch[!o]].fa=y;
	t[x].ch[!o]=y;maintain(y);
}
inline void splay(int x){
	for(int y,z;x && !isroot(x);rotate(x)){
		z=t[y=t[x].fa].fa;
		if(!isroot(y))rotate(t[z].lr(y)==t[y].lr(x)?y:x);
	}maintain(x);
}
inline ll getsz(int x){splay(x);return t[x].s1-t[t[x].ch[0]].s1;}
inline void access(int x,int w){
