			splay(x),t[x].ch[1]=0,t[x].s2+=ss;
		}else ans+=w*2;
	}else ans+=(a[x]+w>(s+w+1)>>1?(s-a[x])*2:s+w-1)-(a[x]>(s+1)>>1?(s-a[x])*2:s-1);
