    priority_queue<edge> q;
    memset(dist, 0x3f, sizeof(dist));
    q.push((edge){1, 0, 0}), dist[1] = 0;
    while (!q.empty()) {
        edge v = q.top(); q.pop();
        for (int i = 0; i < G[v.to].size(); i++) {
            if (dist[G[v.to][i].to] > dist[v.to] + G[v.to][i].l) {
                dist[G[v.to][i].to] = dist[v.to] + G[v.to][i].l;
