    for (int i = 1; (1 << i) <= c; i++) {
        par[v][i] = par[par[v][i - 1]][i - 1];
    }
    for (int i = 1; (1 << i) <= c; i++) {
        mn[v][i] = min(mn[v][i - 1], mn[par[v][i - 1]][i - 1]);
