typedef long long ll;
const int N = 600064;
const ll MOD = 998244353;
inline ll inv(ll x) {
	ll s = 1;
	for (int k=MOD-2; k; k>>=1, x=x*x%MOD)
		if (k&1) s=s*x%MOD;
	return s;
}

ll fac[N*2], ifac[N];
bool vis[N];

inline void init(int l, int r) {
	for (int i = l<<1; ++i <= r<<1;)
		fac[i] = fac[i-1] * i %MOD;
	++l; ++r;
	ifac[r] = inv(fac[r]);
	for (int i = r; i > l; i--)
		ifac[i-1] = ifac[i] * i %MOD;
}

