		memset(vis+1, 0, n);
		ll ans = 0; int x = n;
		for (int r = 1, l = 1;; x--) {
			int a = gunt();
			if (a > r && (r = a) == n) break;
			int y = n-r-1;
			ans = (ans + fac[x+y] * ifac[x+1] %MOD * ifac[y] %MOD * (x+1 - y)) %MOD;
			vis[a] = 1;
			if (a == l) while (vis[++l]);
			else if (a != r) break;
		}
		while (--x) nint();
		printf("%lld\n",ans);
	}
	return 0;
}

