struct Tree {
	int Tote, totn, Last[N], End[N << 1], Next[N << 1];
	ll Len[N << 1], FLen[N << 1];
	void ADDE(int x, int y, ll z) {
		End[++ Tote] = y, Len[Tote] = z, Next[Tote] = Last[x], Last[x] = Tote;
		End[++ Tote] = x, Len[Tote] = z, Next[Tote] = Last[y], Last[y] = Tote;
	}

	void dfs_init(int x, int fa) {
		bool flag = 0;
		int now = x;
		for (vector<pair<int, ll> > :: iterator it = G[x].begin(); it != G[x].end(); it ++)
		if (it -> fi != fa) {
			if (flag) {
				ADDE(now, ++ totn, 0);
				now = totn;
			}
			ADDE(now, it -> fi, it -> se);
			dfs_init(it -> fi, x);
			flag = 1;
		}
	}
	void init(int ty) {
		int i, x, y; ll z;
		if (ty == 0) {
			for (i = 1; i < n; i ++) {
				x = _R(), y = _R(), z = _R();
				ADDE(x, y, z);
			}
		}
		else {
			for (i = 1; i < n; i ++) {
				x = _R(), y = _R(), z = _R();
				G[x].push_back(make_pair(y, z));
				G[y].push_back(make_pair(x, z));
			}
			totn = n;
			dfs_init(1, 0);
		}
	}

	int vtt, in[N], out[N], low[N], fa[N];
	ll dep[N];
	void dfs(int x) {
		in[x] = ++ vtt;
		low[vtt] = x;
		for (int i = Last[x], u; i; i = Next[i])
			if (u = End[i], u != fa[x]) {
				dep[u] = dep[x] + Len[i];
				fa[u] = x;
				FLen[u] = Len[i];
				dfs(u);
			}
		out[x] = vtt;
	}
	int lca(int x, int y) {
		while (x != y) in[x] > in[y] ? x = fa[x] : y = fa[y];
		return x;
	}
