ll ans;
void cmax(ll x) { ans = max(ans, x); }

int T[N], L[N];
int s[N], tmpt[N], tmpl[N];

bool vis[N];
int sz[N], fa[N], q[N];
ll f[N][2];

void gans(int x, int y) {
	cmax(max(f[x][0] + f[y][1], f[x][1] + f[y][0]) - B.dep[x]);
	f[x][0] = max(f[x][0], f[y][0]);
	f[x][1] = max(f[x][1], f[y][1]);
}

void DC(int rt, int l, int r) {		//对A分治
	if (l > r) return;
	if (l == r) { cmax(A.dep[T[l]] - B.dep[T[l]]); return; }

	int i, j, k, u, x, ct, top, hd = 1, tl = 1;

	ll minn = INF;
	q[tl] = rt;
	while (hd <= tl) {
		x = q[hd ++];
		for (i = A.Last[x]; i; i = A.Next[i])
			if (u = A.End[i], !vis[u] && u != fa[x])
				q[++ tl] = u;
		sz[x] = 1;
	}
	for (i = tl; i >= 1; i --) sz[fa[q[i]]] += sz[q[i]];
	for (i = 1; i <= tl; i ++) {
		x = max(sz[rt] - sz[q[i]], sz[q[i]]);
		if (x < minn) minn = x, ct = q[i];
	}

	for (i = l; i <= r; i ++) f[L[i]][0] = f[L[i]][1] = -INF;
	#define insub(a, b) (A.in[a] >= A.in[b] && A.in[a] <= A.out[b])
	for (i = 1; i <= tl; i ++) {
		u = q[i];
		if (!insub(u, ct)) {
			if (insub(ct, u)) f[u][0] = 0;
			else f[u][0] = f[fa[u]][0] + A.FLen[u];
			f[u][1] = -INF;
		}
		else f[u][0] = -INF, f[u][1] = A.dep[u];
	}

	//对B
	top = 0;
	s[++ top] = T[l], u = L[i];
	for (i = l + 1; i <= r; i ++) {
		while (top > 1 && B.in[s[top - 1]] >= B.in[u]) {
			gans(s[top - 1], s[top]);
			top --;
		}
		if (B.in[s[top]] > B.in[u]) gans(u, s[top]), s[top] = u;
		s[++ top] = T[i];
		u = L[i];
	}
	while (top > 1) gans(s[top - 1], s[top]), top --;

	top = 0;
	for (i = l; i <= r; i ++) {
		if (!insub(T[i], ct)) ++ top, tmpt[top] = tmpl[top] = T[i];
		if (top && B.in[tmpl[top]] > B.in[L[i]]) tmpl[top] = L[i];
	}
	int mid = top;
	for (i = l; i <= r; i ++) {
		if (insub(T[i], ct)) ++ top, tmpt[top] = tmpl[top] = T[i];
		if (top && B.in[tmpl[top]] > B.in[L[i]]) tmpl[top] = L[i];
	}

	copy(tmpt + 1, tmpt + top + 1, T + l);
	copy(tmpl + 1, tmpl + top + 1, L + l);
	vis[ct] = 1;
	DC(rt, l, l + mid - 1);
	vis[ct] = 0;
	DC(ct, l + mid, r);
}

int main() {
	n = _R();
	A.init(1), B.init(0);
	A.dfs(1), B.dfs(1);
	copy(B.low, B.low + n + 1, T);
	copy(A.fa, A.fa + A.totn + 1, fa);
	for (int i = 1; i < n; i ++) L[i] = B.lca(T[i], T[i + 1]);
	ans = -INF;
	DC(1, 1, n);
	printf("%lld\n", ans);
}

