template <class T>
inline T Min(const T &a, const T &b) {return a < b ? a : b;}

template <class T>
inline T Max(const T &a, const T &b) {return a > b ? a : b;}

const int N = 3e5 + 5;
const double eps = 1e-3;

int n, Root, which, ToT, ans[N];

struct circle
{
	double x, y; int r, id;
	
	friend inline bool operator < (circle a, circle b)
	{
		return (which ? a.y : a.x) < (which ? b.y : b.x);
	}
} a[N], b[N];

inline bool comp(circle a, circle b)
{
	return a.r > b.r || (a.r == b.r && a.id < b.id);
}

struct node
{
	double xl, xr, yl, yr;
	circle p;
	int lc, rc;
} T[N];

void upt(int p)
{
	T[p].xl = T[p].p.x - T[p].p.r;
	T[p].xr = T[p].p.x + T[p].p.r;
	T[p].yl = T[p].p.y - T[p].p.r;
	T[p].yr = T[p].p.y + T[p].p.r;
	if (T[p].lc)
	{
		T[p].xl = Min(T[p].xl, T[T[p].lc].xl);
		T[p].xr = Max(T[p].xr, T[T[p].lc].xr);
		T[p].yl = Min(T[p].yl, T[T[p].lc].yl);
		T[p].yr = Max(T[p].yr, T[T[p].lc].yr);
	}
	if (T[p].rc)
	{
		T[p].xl = Min(T[p].xl, T[T[p].rc].xl);
		T[p].xr = Max(T[p].xr, T[T[p].rc].xr);
		T[p].yl = Min(T[p].yl, T[T[p].rc].yl);
		T[p].yr = Max(T[p].yr, T[T[p].rc].yr);
	}
}

int build(int l, int r, int op)
{
	if (l > r) return 0;
	which = op;
	int mid = l + r >> 1, p = ++ToT;
	std::nth_element(a + l, a + mid, a + r + 1);
	T[p].p = a[mid];
	T[p].lc = build(l, mid - 1, op ^ 1);
	T[p].rc = build(mid + 1, r, op ^ 1);
	return upt(p), p;
}

bool outof(double xl, double xr, double yl, double yr, circle a)
{
	return xl - a.r - a.x > eps || a.x - xr - a.r > eps
		|| yl - a.r - a.y > eps || a.y - yr - a.r > eps;
}

bool intersect(circle a, circle b)
{
	return (a.x - b.x) * (a.x - b.x) + (a.y - b.y) * (a.y - b.y)
		- 1.0 * (a.r + b.r) * (a.r + b.r) <= eps;
}

void del(int u, circle a)
{
	if (outof(T[u].xl, T[u].xr, T[u].yl, T[u].yr, a)) return;
	if (!ans[T[u].p.id] && intersect(T[u].p, a))
		ans[T[u].p.id] = a.id;
	if (T[u].lc) del(T[u].lc, a);
	if (T[u].rc) del(T[u].rc, a);
}

