#define Mn(t) ((t)==NULL?inf:(t)->mn)
struct splay_t{
	ll v,mn,ad;
	splay_t *s[2],*f;
	splay_t():v(inf),mn(inf),ad(0),f(NULL){s[0]=s[1]=NULL;}
	int dir(){return f&&this==f->s[1];}
	splay_t* add(ll d){v+=d;mn+=d;ad+=d;return this;}
	void psup(){mn=min(v,min(Mn(s[0]),Mn(s[1])));}
	splay_t* add_single(ll d){v+=d;psup();return this;}
	void set(ll x){splay();v=x;psup();}
	void _psdw(){if(ad){if(s[0])s[0]->add(ad);if(s[1])s[1]->add(ad);ad=0;}}
	void psdw(){if(f)f->psdw();_psdw();}
	void rotate(){
		splay_t *t=f;int d=dir();
		f=t->f;if(t->f)t->f->s[t->dir()]=this;
		t->s[d]=s[d^1];if(s[d^1])s[d^1]->f=t;
		t->f=this;s[d^1]=t;
		t->psup(),psup();
	}
	splay_t* splay(splay_t* e=NULL){
		psdw();
		if(f==e)return this;
		if(f->f==e){rotate();return this;}
		else if(dir()==f->dir())f->rotate(),rotate();
		else rotate(),rotate();
		return splay(e);
	}
	splay_t* nxt(){
		splay();
		if(!s[1])return NULL;
		else{
			splay_t* t=s[1];
			while(t->s[0])t=t->s[0];
			return t->splay();
		}
	}
	splay_t* pre(){
		splay();
		if(!s[0])return NULL;
		else{
			splay_t* t=s[0];
			while(t->s[1])t=t->s[1];
			return t->splay();
		}
	}
};
struct splay_bracket_t{
	splay_t pol_splay[MX<<1],*nn_splay=pol_splay,*L[MX],*R[MX];
	splay_t* get(int x){
		if(!L[x]->pre())return L[x]->splay();
		splay_t *p=L[x]->pre(),*n=R[x]->nxt();
		p->splay();
		return n->splay(p)->s[0];
	}
	splay_t* suf(int x){
		if(!L[x]->pre())return L[x]->splay();
		return L[x]->pre()->splay()->s[1];
	}
	splay_t* cut(int x){
		if(!L[x]->pre())return L[x]->splay();
		splay_t *p=L[x]->pre(),*n=R[x]->nxt();
		p->splay();
		n->splay(p);
		splay_t *r=n->s[0];
		r->f=n->s[0]=NULL;n->psup(),p->psup();
		return r;
	}
	splay_t* all(){return L[1]->splay();}
	ll operator [](const int x){return L[x]->splay()->v;}
	void append(int u,int f,ll t){
		L[u]=nn_splay++,R[u]=nn_splay++;
		if(f){
			splay_t* rot=R[f]->pre()->splay();
			R[f]->splay(rot);
			R[f]->s[0]=R[u],R[u]->f=R[f];
		}
		R[u]->s[0]=L[u],L[u]->f=R[u];
		L[u]->splay();L[u]->set(t);
	}
	void dbgpr(){
		for(int i=1;i<=n;i++){
			cerr<<"L["<<i<<"  "<<i*2-1<<"  ]="<<(L[i]->s[0]==NULL?0:L[i]->s[0]-pol_splay+1)<<", "<<(L[i]->s[1]==NULL?0:L[i]->s[1]-pol_splay+1)<<",  "<<(L[i]->f==NULL?0:L[i]->f-pol_splay+1)<<endl;
			cerr<<"R["<<i<<"  "<<i*2<<"  ]="<<(R[i]->s[0]==NULL?0:R[i]->s[0]-pol_splay+1)<<", "<<(R[i]->s[1]==NULL?0:R[i]->s[1]-pol_splay+1)<<",  "<<(R[i]->f==NULL?0:R[i]->f-pol_splay+1)<<endl;
		}
		cerr<<endl;
	}
	void debug_eachv(){
		for(int i=1;i<=n;i++)cerr<<i<<' '<<L[i]->splay()->v<<endl;
	}
}F,H;


struct lct_splay_t{
	int id,sz,ad;
	lct_splay_t *s[2],*f;
	lct_splay_t():id(0),f(NULL){s[0]=s[1]=NULL;}
	int isrt(){return !f||(f->s[0]!=this&&f->s[1]!=this);}
	int dir(){return f&&this==f->s[1];}
	void add(int d){sz+=d;ad+=d;}
	void add_single(int d){sz+=d;}
	void psup(){}
	void _psdw(){if(ad){if(s[0])s[0]->add(ad);if(s[1])s[1]->add(ad);ad=0;}}
	void psdw(){if(f)f->psdw();_psdw();}
	int Sz(){return psdw(),sz;}
	void rotate(){
		lct_splay_t *t=f;int d=dir();
		f=t->f;if(!t->isrt())t->f->s[t->dir()]=this;
		t->s[d]=s[d^1];if(s[d^1])s[d^1]->f=t;
		t->f=this;s[d^1]=t;
		t->psup(),psup();
	}
	lct_splay_t* splay(){
		psdw();
		if(isrt())return this;
		if(f->isrt()){rotate();return this;}
		else if(dir()==f->dir())f->rotate(),rotate();
		else rotate(),rotate();
		return splay();
	}
	lct_splay_t* lmost(){return s[0]?s[0]->lmost():splay();}
	lct_splay_t* access(vector<pii> &a){ // return 2nd deepest
		splay();add_single(1);if(s[0])s[0]->add(1);
		lct_splay_t* l=lmost();
		splay();
		if(f){
			a.push_back(mp(f->id,l->id));
			// F.dbgpr();
			F.get(f->id)->add(-1)->splay(),H.get(f->id)->add(-1)->splay(),H.suf(f->id)->add(1)->splay();
			// F.dbgpr();
			F.get(l->id)->add(1)->splay();
			// H.dbgpr();
			H.get(l->id)->add(1)->splay();
			// H.dbgpr();
			H.suf(l->id)->add(-1)->splay();
			// F.dbgpr();
		}
		if(f){
			lct_splay_t* t=f->access(a);
			if(t)return t;
			else return l;
		}else{
			if(this!=l){
				lct_splay_t* x=l->splay()->s[1]->lmost();
				F.get(x->id)->add(1)->splay(),H.get(x->id)->add(1)->splay(),H.suf(x->id)->add(-1)->splay();
				return x;
			}else{
				F.get(l->id)->add(1)->splay(),H.get(l->id)->add(1)->splay(),H.suf(l->id)->add(-1)->splay();
				return NULL;
			}
		}
	}
	lct_splay_t* swt(){
		splay();
		if(f){
			f->splay();
			f->s[1]=this;
			f->psup();
		}
		return this;
	}
}pol_lct_splay[MX],*nn_lct_splay=pol_lct_splay,*tr[MX];

