};

bool sons_node_t::is_heaviest(){return this==bel->bel->h->h;}
int sons_node_t::pre_id(){return is_heaviest()?0:(pre?pre->id:bel->pre->t->id);}

void sons_node_t::rem(){
	if(bel->h==this)bel->h=nxt;
	if(bel->t==this)bel->t=pre;
	if(pre)pre->nxt=nxt;
	if(nxt)nxt->pre=pre;
	pre=nxt=NULL;bel=NULL;
}
int sons_node_t::inc(){
	sons_t *f=bel->bel;
	if(f->h==bel){
		// becoming the heaviest
		if(f->h->tid==f->bas){
			f->h->v++;
		}else{
			sons_v_node_t* l=new sons_v_node_t(f);
			l->v=bel->v+1;l->tid=f->bas;
			rem();bel=l;
			l->h=l->t=this;
			l->nxt=f->h,f->h->pre=l;
			f->h=l;
		}
	}else{
		if(bel->pre->v==bel->v+1){
			sons_v_node_t* b=bel,*p=bel->pre;
			rem();if(b->empty())b->rem();
			p->tid++;p->t->nxt=this,pre=p->t,p->t=this,bel=p;
		}else{
			sons_v_node_t* b=bel,*p=bel->pre;
			sons_v_node_t* l=new sons_v_node_t(f);
			l->v=b->v+1;l->tid=p->tid+1;
			rem();
			bel=l;l->h=l->t=this;
			l->pre=p,l->nxt=b,p->nxt=l,b->pre=l;
			if(b->empty())b->rem();
		}
	}
	return bel->tid-f->bas;
}

bool sons_v_node_t::empty(){return h==NULL;}
void sons_v_node_t::rem(){
	if(bel->h==this)bel->h=nxt;
	if(bel->t==this)bel->t=pre;
	if(pre)pre->nxt=nxt;
	if(nxt)nxt->pre=pre;
	v=tid=0;pre=nxt=NULL;h=t=NULL;bel=NULL;
}
void sons_v_node_t::insnew(sons_node_t *x){
	x->bel=this;
	++tid;
	if(!t)h=t=x;
	else t->nxt=x,x->pre=t,t=x;
}

bool sons_t::empty(){return h==NULL;}
void sons_t::insnew(sons_node_t *x){
	sons_v_node_t* l=new sons_v_node_t(this);
	if(empty())h=t=l,l->tid=bas-1;
	else t->nxt=l,l->pre=t,l->tid=t->tid,t=l;
	l->insnew(x);
}
void sons_t::remmx(){
	if(!empty()){
		if(h->tid-bas>0){
			h->h->rem();
		}else{
			h->rem();
		}
	}
	bas++;
}
void sons_t::insmx(sons_node_t *x,int v){
	if(empty()){
		sons_v_node_t *m=new sons_v_node_t(this);
		m->h=m->t=x;m->v=v;m->tid=bas;x->bel=m;
		h=t=m;
	}else{
		bas--;
		if(h->v==v){
			x->bel=h;
			x->nxt=h->h,h->h->pre=x,h->h=x;
		}else{
			sons_v_node_t *m=new sons_v_node_t(this);
			m->h=m->t=x;m->v=v;m->tid=bas;x->bel=m;
			m->nxt=h,h->pre=m,h=m;
		}
	}
}
// remember to update!!
void sons_t::updmx(){
	if(!empty()&&h->v){
		int v=tr[h->h->id]->Sz();
		if(h->v==v)return;
		if(h->tid-bas>0){
			sons_v_node_t *m=new sons_v_node_t(this);
			// create a new value list
			sons_node_t *x=h->h;
			// get the key item
			m->h=m->t=x,h->h=x->nxt,x->nxt->pre=NULL,x->pre=x->nxt=NULL,x->bel=m;
			// split the key item
			m->nxt=h,h->pre=m,m->v=v,m->tid=bas,h=m;
			// insert the new value list
		}else h->v=v;
	}
}
sons_node_t pol_sons_node_t[MX],*fnode[MX];
sons_t ssz[MX]; // pair(size, i)
void maintain_lgtedge(pii e){
	int f=e.fr,u=e.se; // f is u's parent
	ssz[f].updmx();
	int rnk=fnode[u]->inc();
	if(f==o)--rnk;
	int id=(fnode[u]->pre_id());
	splay_t *Fs=F.cut(u);
	splay_t *Ft=(id?F.R[id]:F.L[f]);
	splay_t* Ftn=Ft->nxt();Ft->splay();
	Ft->add(rnk);F.R[f]->splay(Ft);if(F.R[f]->s[0])F.R[f]->s[0]->add(1)->splay();
	F.L[f]->splay()->add_single(1);
	Ftn->splay(),Ft->splay(Ftn);
	Ft->s[1]=Fs,Fs->f=Ft;Ft->psup(),Ftn->psup();

	// if(n==6)H.dbgpr();
	splay_t *Hs=H.cut(u);
	// if(n==6)H.dbgpr();
	splay_t *Ht=(id?H.R[id]:H.L[f]);
	splay_t* Htn=Ht->nxt();Ht->splay();
	// if(n==6)H.dbgpr();
	Ht->add(rnk);H.R[f]->splay(Ht);if(H.R[f]->s[0])H.R[f]->s[0]->add(1)->splay();
	// if(n==6)H.dbgpr();
	H.L[f]->splay()->add_single((rnk+1)/2-rnk);
	// if(n==6)H.dbgpr();
	Htn->splay();
	// if(n==6){
		// H.dbgpr();
	// }
	Ht->splay(Htn);
	// if(n==6)H.dbgpr();
	Ht->s[1]=Hs,Hs->f=Ht;Ht->psup(),Htn->psup();

	if(fnode[u]->is_heaviest())tr[u]->swt();
}
void pivot(int x,int sz){
	ssz[x].updmx();
	ssz[o].remmx();
	ssz[x].insmx(fnode[o],n-sz);
	splay_t *tx=F.cut(x),*to=F.get(o);
	//F.dbgpr();
	F.L[x]->nxt()->splay(),F.L[x]->s[1]=to,to->f=F.L[x],to->splay();

	tx=H.cut(x),to=H.get(o);
	H.L[x]->nxt()->splay(),H.L[x]->s[1]=to,to->f=H.L[x],to->splay();

	tr[x]->splay();
	tr[x]->s[0]=NULL;tr[x]->psup();
	tr[o]->swt();
	if(!ssz[o].empty())tr[ssz[o].h->h->id]->swt();
	tr[x]->splay()->add_single(n-sz);
	tr[o]->splay()->add_single(-sz);

	o=x;
}
void upd(int f,int u){
	ll t=F[f];
	// insert u into F and H
	F.append(u,f,t),H.append(u,f,t);
	// if(n==6)H.dbgpr();
	// the cost of the new edge
	F.all()->add(1),H.all()->add(1);
	// if(n==6)H.dbgpr();
	// create the LCT node and calculate the contribution of the heavy sons.
	// They never change their brother-size-order.
	tr[u]=nn_lct_splay++;
	tr[u]->f=tr[f];tr[u]->id=u;
	F.get(u)->add(-1)->splay();
	H.get(u)->add(-1)->splay(),H.suf(u)->add(1)->splay();
	vector<pii>lgtedges;
	// if(n==6)H.dbgpr();
	// brother-size-order may change.
	lct_splay_t* snd=tr[u]->access(lgtedges);
	// if(n==6)H.dbgpr();
	// snd: the second vertice on the path(for gravity center)
	// calculate light edges: they may change their rank among the brothers. Or we regard so: their rank may be greater than 2.
	fnode[u]=pol_sons_node_t+u;
	fnode[u]->id=u;
	ssz[f].insnew(fnode[u]);
	for(auto i:lgtedges){
		// cerr<<"lgtedge:"<<i.fr<<' '<<i.se<<endl;
		maintain_lgtedge(i);
	}
	// if(n==6)H.dbgpr();
	int tsz=snd->Sz();
	//cerr<<"snd:"<<snd->id<<" "<<tsz<<endl;
	//F.dbgpr();
	if(tsz>n/2)pivot(snd->id,tsz);
	// if(n==6)H.dbgpr();
}
