struct Splay_Tree
{
	void *operator new(size_t size);
	void *operator new[](size_t size);
	void operator delete(void *ptr);
	
	static Splay_Tree *Null;
	
	Splay_Tree *ch[3], *parent;
	bool rev;
	int size, rake_count;
	int64 cost, semi_cost, path_min, subtree_min;
	int64 cpath_lazy, path_lazy, subtree_lazy;
	
	Splay_Tree() : rev(false), size(1), rake_count(0), cost(0), semi_cost(0), path_min(0), subtree_min(0), cpath_lazy(0), path_lazy(0), subtree_lazy(0)
	{
		static bool init = false;
		if (!init)
		{
			init = true;
			Null = new Splay_Tree;
			Null->ch[0] = Null->ch[1] = Null->ch[2] = Null->parent = Null;
			Null->size = 0;
			Null->cost = Null->semi_cost = Null->path_min = Null->subtree_min = 1LL << 60;
		}
		ch[0] = ch[1] = ch[2] = parent = Null;
	}
	
	bool dir()
	{ return parent->ch[1] == this; }
	
	Splay_Tree *sch(const int d, Splay_Tree *c)
	{ return ch[d] = c, c->parent = this; }
	
	bool isroot()
	{ return parent->ch[0] != this && parent->ch[1] != this; }
	
	void reverse()
	{ rev = !rev, std::swap(ch[0], ch[1]); }
	
	void cpath_modify(const int64 &l)
	{ cost += l, cpath_lazy += l; }
	
	void path_modify(const int64 &l)
	{ cost += l, semi_cost += l, path_min += l, path_lazy += l; }
	
	void subtree_modify(const int64 &l)
	{ subtree_min += l, subtree_lazy += l; }
	
	template<bool type>
	void pushup();
	
	template<bool type>
	void pushdown();
	
	template<bool type>
	void rotate()
	{
		bool d = dir();
		Splay_Tree *p = parent;
		p->pushdown<type>(), pushdown<type>();
		if (parent = p->parent, p->parent != Null)
			p->parent->ch[p->isroot() ? 2 : p->dir()] = this;
		p->sch(d, ch[!d])->pushup<type>(), sch(!d, p), pushup<type>();
	}
	
	template<bool type>
	Splay_Tree *splay(Splay_Tree *r = nullptr)
	{
		for (pushdown<type>(); !isroot() && parent != r; rotate<type>())
			if (!parent->isroot() && parent->parent != r)
				parent->parent->pushdown<type>(), (dir() == parent->dir() ? this : parent)->rotate<type>();
		return this;
	}
	
	template<bool d, bool type>
	Splay_Tree *splay_m()
	{
		Splay_Tree *o = this;
		while (o->ch[d] != Splay_Tree::Null)
			o = o->ch[d];
		return o->splay<type>(parent);
	}
};
