	path_min = std::min({ch[0]->path_min, ch[1]->path_min, semi_cost});
	subtree_min = std::min({ch[0]->subtree_min, ch[1]->subtree_min, ch[2]->subtree_min});
}

template<>
inline void Splay_Tree::pushdown<rake>()
{
	if (subtree_lazy) ch[0]->subtree_modify(subtree_lazy), ch[1]->subtree_modify(subtree_lazy), ch[2]->subtree_modify(subtree_lazy), ch[2]->path_modify(subtree_lazy), subtree_lazy = 0;
}

template<>
inline void Splay_Tree::pushdown<compress>()
{
	if (rev) ch[0]->reverse(), ch[1]->reverse(), rev = false;
	if (cpath_lazy) ch[0]->cpath_modify(cpath_lazy), ch[1]->cpath_modify(cpath_lazy), cpath_lazy = 0;
	if (path_lazy) ch[0]->path_modify(path_lazy), ch[1]->path_modify(path_lazy), path_lazy = 0;
	if (subtree_lazy) ch[0]->subtree_modify(subtree_lazy), ch[1]->subtree_modify(subtree_lazy), ch[2]->subtree_modify(subtree_lazy), subtree_lazy = 0;
}

bool lower_bound(Splay_Tree *o, const int x)
{
	Splay_Tree *res = o, *c = o;
	while (c->ch[c->ch[2]->size > x] != Splay_Tree::Null)
	{
		c = c->ch[c->ch[2]->size > x];
		if (c->ch[2]->size == x)
			res = c;
	}
	if (c != res)
		c->splay<rake>(res);
	res->splay<rake>(o->parent);
	return res->ch[2]->size == x;
}

void deal_with_structure(Splay_Tree *o)
{
	o->splay<compress>();
	while (o->parent != Splay_Tree::Null)
	{
		o = o->parent->splay<rake>();
		if (o->ch[0] != Splay_Tree::Null && lower_bound(o->ch[0], o->ch[2]->size))
			std::swap(o->ch[2]->parent, o->ch[0]->ch[2]->parent), std::swap(o->ch[2], o->ch[0]->ch[2]), o = o->ch[0], o->rotate<rake>();
		o = o->parent->splay<compress>();
		o->ch[2]->pushdown<rake>();
		if (o->ch[2]->ch[2]->size == o->ch[1]->size)
			std::swap(o->ch[2]->ch[2]->parent, o->ch[1]->parent), std::swap(o->ch[2]->ch[2], o->ch[1]);
		o->ch[2]->pushup<rake>(), o->pushup<compress>();
	}
	if (o->ch[0] != Splay_Tree::Null)
	{
		o = o->splay_m<0, compress>();
		if (o->size == o->ch[1]->size * 2)
		{
			Splay_Tree *c = o->ch[1]->splay_m<0, compress>();
			if (o->ch[2] != Splay_Tree::Null)
			{
				Splay_Tree *r = o->ch[2]->splay_m<0, rake>();
				o->sch(1, r->ch[2])->sch(2, r->ch[1])->pushup<compress>();
				delete r;
			}
			if (c->ch[1] != Splay_Tree::Null)
			{
				Splay_Tree *r = new Splay_Tree;
				r->sch(1, c->ch[2])->sch(2, c->ch[1])->pushup<rake>();
				c->sch(1, o)->sch(2, r)->pushup<compress>();
			}
			c->parent = Splay_Tree::Null;
		}
	}
}

template<bool type>
void path_pushdown(Splay_Tree *o)
{
	if (o->parent != Splay_Tree::Null)
		(o == o->parent->ch[2] ? path_pushdown<!type> : path_pushdown<type>)(o->parent);
	o->pushdown<type>();
}

int64 deal_with_information(Splay_Tree *p, Splay_Tree *o)
{
	path_pushdown<compress>(p->splay<compress>());
	
	o->cost = o->semi_cost = p->cost + 1, o->pushup<compress>();
	int64 sum = 0;
	if (p->ch[1] == Splay_Tree::Null)
	{
		p->sch(1, o);
		p->cost += (o->parent->ch[0] != Splay_Tree::Null || o->parent->parent != Splay_Tree::Null);
		o->path_modify(-1), sum += 1;
		o = p;
	}
	else
	{
		Splay_Tree *r = new Splay_Tree;
		r->sch(0, p->ch[2])->sch(2, o), p->sch(2, r);
		
		o = r;
		int x = o->ch[0]->rake_count + 1 + (o->parent->ch[0] != Splay_Tree::Null || o->parent->parent != Splay_Tree::Null);
		o->ch[2]->path_modify(-((x - 1) + 1)), sum += (x - 1) + 1;
		o->pushup<rake>(), o = o->parent;
		o->cost += x + 1 - ((x - 1) + 1), o->semi_cost += x / 2 + 1 - ((x - 1) + 1);
	}
	
	o->ch[0]->cpath_modify(1), o->ch[0]->subtree_modify(1), o->pushup<compress>();
	
	while (o->parent != Splay_Tree::Null)
	{
		o = o->parent->splay<rake>(), o->parent->splay<compress>();
		int x = o->ch[0]->rake_count + 1 + (o->parent->ch[0] != Splay_Tree::Null || o->parent->parent != Splay_Tree::Null);
		o->ch[1]->subtree_modify(1), o->ch[2]->path_modify(-(x - 1)), o->ch[2]->subtree_modify(-(x - 1)), sum += (x - 1);
		o->pushup<rake>(), o = o->parent;
		o->cost += x - (x - 1), o->semi_cost += x / 2 - (x - 1);
		o->ch[0]->cpath_modify(1), o->ch[0]->subtree_modify(1), o->pushup<compress>();
	}
	o->path_modify(sum), o->subtree_modify(sum); 
	if (o->ch[0] != Splay_Tree::Null)
	{
		o = o->splay_m<0, compress>();
		o->cost -= 1, o->ch[2]->subtree_modify(-1), o->pushup<compress>();
	}
	return std::min(o->path_min, o->subtree_min);
}


