int N, Q;
int first[Max_N], size[Max_N];
int ecnt = 2, Next[Max_N * 2], To[Max_N * 2], Ts[Max_N * 2];
std::vector<int> ordered[Max_N];
int64 Tcost[Max_N * 2], sTcost[Max_N];
int64 Ans;

//================ static ================


Splay_Tree *node0;
inline Splay_Tree *node(const int i) { return node0 + i; }

int centroid(const int v) { return N == 1 || Ts[ordered[v].front()] * 2 <= N ? v : centroid(To[ordered[v].front()]); }

void build_dfs(const int v, const int p = 0)
{
	for (auto e : ordered[v])
		if (To[e] != p)
		{
			build_dfs(To[e], v);
			if (node(v)->ch[1] == Splay_Tree::Null)
				node(v)->sch(1, node(To[e]));
			else
			{
				Splay_Tree *r = new Splay_Tree;
				r->sch(0, node(v)->ch[2])->sch(2, node(To[e]))->pushup<rake>();
				node(v)->sch(2, r);
			}
		}
	const auto &vec = ordered[v];
	node(v)->cost = node(v)->semi_cost = vec.size();
	for (size_t i = 0; i != vec.size(); ++i)
		node(v)->cost += Tcost[vec[i]] + static_cast<int64>(Ts[vec[i]]) * i, node(v)->semi_cost += Tcost[vec[i]] + static_cast<int64>(Ts[vec[i]]) * (i / 2);
	node(v)->pushup<compress>();
}

void build_structure() { build_dfs(centroid(1)); }

//================ static ================

void dfs0(const int v, const int p = 0)
{
	size[v] = 1;
	for (int e = first[v]; e; e = Next[e])
		if (To[e] != p)
			dfs0(To[e], v), size[v] += Ts[e] = size[To[e]];
}

void dfs1(const int v, const int ps = 0, const int p = 0)
{
	for (int e = first[v]; e; e = Next[e])
		if (To[e] != p)
			dfs1(To[e], ps + size[v] - size[To[e]], v);
		else
			Ts[e] = ps;
}

void dfs2(const int v, const int p = 0)
{
	for (auto e : ordered[v])
		if (To[e] != p)
			dfs2(To[e], v), sTcost[v] += Tcost[e] += sTcost[To[e]];
}

void dfs3(const int v, const int64 ps = 0, const int p = 0)
{
	for (auto e : ordered[v])
		if (To[e] != p)
			dfs3(To[e], ps + sTcost[v] - Tcost[e] + Tcost[e ^ 1], v);
		else
			Tcost[e] = ps;
}

int main(int argc, char **argv)
{
	IO >> N;
	for (int i = 1, v, w; i != N; ++i)
	{
		IO >> v >> w;
		Next[ecnt] = first[v], To[ecnt] = w, first[v] = ecnt++;
		Next[ecnt] = first[w], To[ecnt] = v, first[w] = ecnt++;
	}
	
	if (N != 1)
	{
		dfs0(1), dfs1(1);
		for (int v = 1; v <= N; ++v)
		{
			static int tmp[Max_N];
			int cnt = 0;
			for (int e = first[v]; e; e = Next[e])
				tmp[cnt++] = e;
			std::sort(tmp, tmp + cnt, [](const int e1, const int e2) { return Ts[e1] > Ts[e2]; });
			ordered[v] = std::vector<int>(tmp, tmp + cnt);

			const auto &vec = ordered[v];
			int64 cost = vec.size() - 1;
			for (size_t i = 0; i != vec.size() - 1; ++i)
				cost += static_cast<int64>(Ts[vec[i]]) * i;
			Tcost[vec.back() ^ 1] = cost;
			for (size_t i = vec.size() - 2; ~i; --i)
				Tcost[vec[i] ^ 1] = cost += static_cast<int64>(Ts[vec[i + 1]] - Ts[vec[i]]) * i;
		}
		dfs2(1), dfs3(1);
		Ans = 1LL << 60;
		for (int v = 1; v <= N; ++v)
		{
			const auto &vec = ordered[v];
			int64 res = vec.size();
			for (size_t i = 0; i != vec.size(); ++i)
				res += Tcost[vec[i]] + static_cast<int64>(Ts[vec[i]]) * (i / 2);
			Ans = std::min(Ans, res);
		}
	}
	
	IO << Ans << '\n';
	
//================ static ================
	
	
	IO >> Q;
	node0 = new Splay_Tree[N + Q + 1];
	build_structure();
	while (Q--)
	{
		int p;
		IO >> p;
		deal_with_structure(node(p));
		IO << deal_with_information(node(p), node(++N)) << '\n';
	}
	
	return 0;
}

