	for (int i = 1, v, w; i != N; ++i)
	{
		IO >> v >> w;
		Next[ecnt] = first[v], To[ecnt] = w, first[v] = ecnt++;
		Next[ecnt] = first[w], To[ecnt] = v, first[w] = ecnt++;
	}
	
	if (N != 1)
	{
		dfs0(1), dfs1(1);
		for (int v = 1; v <= N; ++v)
		{
			static int tmp[Max_N];
			int cnt = 0;
			for (int e = first[v]; e; e = Next[e])
				tmp[cnt++] = e;
			std::sort(tmp, tmp + cnt, [](const int e1, const int e2) { return Ts[e1] > Ts[e2]; });
			ordered[v] = std::vector<int>(tmp, tmp + cnt);

			const auto &vec = ordered[v];
			int64 cost = vec.size() - 1;
			for (size_t i = 0; i != vec.size() - 1; ++i)
				cost += static_cast<int64>(Ts[vec[i]]) * i;
			Tcost[vec.back() ^ 1] = cost;
			for (size_t i = vec.size() - 2; ~i; --i)
				Tcost[vec[i] ^ 1] = cost += static_cast<int64>(Ts[vec[i + 1]] - Ts[vec[i]]) * i;
