		for (int v = 1; v <= N; ++v)
		{
			const auto &vec = ordered[v];
			int64 res = vec.size();
			for (size_t i = 0; i != vec.size(); ++i)
				res += Tcost[vec[i]] + static_cast<int64>(Ts[vec[i]]) * (i / 2);
			Ans = std::min(Ans, res);
		}
	}
	
	IO << Ans << '\n';
	
