	IO >> Q;
	node0 = new Splay_Tree[N + Q + 1];
	build_structure();
	while (Q--)
	{
		int p;
		IO >> p;
		deal_with_structure(node(p));
		IO << deal_with_information(node(p), node(++N)) << '\n';
	}
	
	return 0;
}

