using ll = long long;
int MOD;
inline int quick_pow(int a, int n)
{
	int res = 1;
	while (n)
	{
		if (n & 1)
			res = (ll)res * a % MOD;
		a = (ll)a * a % MOD;
		n >>= 1;
	}
	return res;
}
constexpr int LIM = 1e6;
int fact[LIM + 5], inv[LIM + 5], sing[LIM + 5];
int arr[1000005], S1[1000005], S2[1000005], sum[1000005], val[1000005];
inline void get_S(int n, int m, int a, int *res)
{
	if (a == 1)
	{
		res[0] = m;
		for (int i = 1; i <= n; i++)
			res[i] = (ll)res[i - 1] * (m + i) % MOD * sing[i + 1] % MOD;
		return;
	}
	int cur = 1, x = quick_pow(a, m), y = quick_pow(a + MOD - 1, MOD - 2);
	res[0] = (ll)(x + MOD - 1) * y % MOD;
	for (int i = 1; i <= n; i++)
	{
		cur = (ll)cur * (m + i - 1) % MOD * sing[i] % MOD;
		res[i] = ((ll)cur * x - res[i - 1] + MOD) % MOD * y % MOD;
	}
}
