long long fac[1000010], inv[1000010];
int LIM;
long long dw[2000010], idw[2000010];
int zero[2000010];

long long Binom(int n, int k) {
	if (k < 0 || k > n) return 0;
	if (n <= 1000000) return fac[n] * inv[k] % mod * inv[n - k] % mod;
	if (n - k < k) k = n - k;
	assert(n <= LIM && LIM - n + k <= 2000005);
	int l = LIM - n, r = LIM - n + k;
	assert(l >= 0 && r <= 2000000);
	// long long ans = inv[k];
	// for (int i = 0; i < k; i++) {
