	// }
	// return ans;
	// cerr << "       dw:" << l << " " << r << " : " << dw[r] << " " << idw[l] << endl;
	return zero[l] != zero[r] ? 0 : dw[r] * idw[l] % mod * inv[k] % mod;
}

