				T = (T - 1ll * pwbm * Binom(i + m, i + 1) % mod * m % mod + mod + 1ll * b * S % mod) * invb % mod;
			}
			return ans;
		};
		// Solve(2, 1, 2, 3);
		// return 0;
		if (u == 1 && v == 1) {
			ADD(sum, Solve(n, m, a, b, 0) * n % mod * m % mod);
			SUB(sum, Solve(n, m, a, b, 1) * m % mod);
			SUB(sum, Solve(n, m, a, b, 2) * n % mod);
			ADD(sum, Solve(n, m, a, b, 3));
		} else if (u == 1) {
			ADD(sum, Solve(n, m, a, b, 0) * n % mod * power(v, m) % mod);
			SUB(sum, Solve(n, m, a, b, 1) * power(v, m) % mod);
			SUB(sum, Solve(n, m, a, 1ll * b * v % mod, 0) * n % mod);
			ADD(sum, Solve(n, m, a, 1ll * b * v % mod, 1));
		} else if (v == 1) {
			assert(0);
		} else {
			ADD(sum, Solve(n, m, a, b, 0) * power(u, n) % mod * power(v, m) % mod);
			SUB(sum, Solve(n, m, 1ll * a * u % mod, b, 0) * power(v, m) % mod);
			SUB(sum, Solve(n, m, a, 1ll * b * v % mod, 0) * power(u, n) % mod);
			ADD(sum, Solve(n, m, 1ll * a * u % mod, 1ll * b * v % mod, 0));
			MUL(sum, power(1 - u + mod, mod - 2));
			MUL(sum, power(1 - v + mod, mod - 2));
		}
		MUL(sum, c);
		ADD(ans, sum);
		// cerr << "   ans:" << ans << endl;
	}
	{ // part1 - f
		static int coef[1000010];
		{
			int val = 1ll * a * u % mod;
			int p = 1ll * b * v % mod;
			int pwpm = power(p, m);
			int invp = power(1 - p + mod, mod - 2);
			long long pw = 1, S = 1ll * (1 - pwpm + mod) * invp % mod;
			for (int i = 0; i < n; i++) {
				if (p == 1) S = Binom(m + i, i + 1);
				// {
				// 	int R = 0;
				// 	long long pw = 1;
				// 	for (int j = 0; j < m; j++) {
				// 		R = (R + 1ll * pw * Binom(i + j, j) % mod) % mod;
				// 		pw = pw * p % mod;
				// 	}
				// 	cerr << "    R:" << R << " " << S << endl;
				// }
				coef[i] = pw * b % mod * S % mod;
				pw = pw * val % mod;
				S = (S - 1ll * pwpm * Binom(i + m, i + 1) % mod + mod) * invp % mod;
			}
		}
		for (int i = 1; i < n; i++) {
			ADD(coef[i], coef[i - 1]);
		}
		int sum = 0;
		long long pw = 1;
		for (int i = 0; i < n; i++) {
			ADD(sum, 1ll * f[i] * pw % mod * coef[n - 1 - i] % mod);
			pw = pw * u % mod;
		}
		ADD(ans, sum);
	}
	printf("%d\n", ans);
	return 0;
}

#include <functional>
#include <cstdio>
#include <vector>
