using ll = long long;
struct point
{
	ll x, y;
	inline point operator -(const point &a) const { return {x - a.x, y - a.y}; }
	inline ll operator *(const point &a) const { return x * a.y - y * a.x; }
	inline bool operator <(const point &a) const { return std::tie(x, y) < std::tie(a.x, a.y); }
	inline ll calc(ll a) const { return y - x * a; }
};
std::vector<point> merge(std::vector<point> vec_l, std::vector<point> vec_r)
{
	std::vector<point> vec;
	int x = 0, y = 0;
	while (x < vec_l.size() || y < vec_r.size())
	{
		if (y >= vec_r.size() || (x < vec_l.size() && vec_l[x] < vec_r[y]))
			vec.push_back(vec_l[x++]);
		else
			vec.push_back(vec_r[y++]);
	}
	return vec;
}
template <typename T>
std::vector<point> convex_hull(std::vector<point> vec, const T &comp)
{
	std::vector<point> res;
	for (auto &p : vec)
	{
		if (!res.empty() && p.x == res.back().x)
			res.pop_back();
		while (res.size() > 1 && comp((p - res[res.size() - 2]) * (res.back() - res[res.size() - 2]), 0))
			res.pop_back();
		res.push_back(p);
	}
	return res;
}
int lp[100005], rp[100005];
ll len[100005], sum[100005];
bool ok[100005];
std::vector<point> solve_l(int l, int r)
{
	if (l >= r)
		return {{lp[l + 1], lp[l + 1] * len[l] - sum[l]}};
	int m = l + r >> 1;
	auto vec_l = solve_l(l, m), vec_r = solve_l(m + 1, r);
	for (int i = l, j = (int)vec_r.size() - 1; i <= m; i++)
	{
		while (j && vec_r[j].calc(len[i]) <= vec_r[j - 1].calc(len[i]))
			j--;
		if (vec_r[j].calc(len[i]) + sum[i] > 0)
			ok[i] = false;
	}
	return convex_hull(merge(vec_l, vec_r), std::less_equal<ll>());
}
std::vector<point> solve_r(int l, int r)
{
	if (l >= r)
		return {{rp[l + 1], rp[l + 1] * len[l] - sum[l]}};
	int m = l + r >> 1;
	auto vec_l = solve_r(l, m), vec_r = solve_r(m + 1, r);
	for (int i = l, j = 0; i <= m; i++)
	{
		while (j + 1 < vec_r.size() && vec_r[j].calc(len[i]) >= vec_r[j + 1].calc(len[i]))
			j++;
		if (vec_r[j].calc(len[i]) + sum[i] < 0)
			ok[i] = false;
	}
	return convex_hull(merge(vec_l, vec_r), std::greater_equal<ll>());
}
int main()
{
	// freopen("T2.in", "r", stdin);
	int n;
	scanf("%d", &n);
	for (int i = 0; i < n; i++)
	{
		scanf("%d%d", lp + i, rp + i);
		len[i] = (i ? len[i - 1] : 0) + (rp[i] - lp[i] << 1);
		sum[i] = (i ? sum[i - 1] : 0) + rp[i] * rp[i] - lp[i] * lp[i];
		ok[i] = true;
	}
	solve_l(0, n - 2);
	solve_r(0, n - 2);
	int lst = 0, ans = 0;
	for (int i = 0; i < n; i++)
	{
		if (!ok[i])
			continue;
		ans = std::max(ans, i - lst + 1);
		lst = i + 1;
	}
	printf("%d\n", ans);
	return 0;
}

