}
struct point {ll x, y; int home; } p[MAXN];
int cmptype, q[MAXN];
bool cmp(point a, point b) {
	if (cmptype == 0) return (a.x < b.x) || (a.x == b.x && a.y < b.y);
	else return (a.y < b.y) || (a.y == b.y && a.x < b.x);
}
int n, l[MAXN], r[MAXN], home[MAXN];
ll cnt[MAXN], sum[MAXN]; bool ans[MAXN];
struct KDTree {
	struct Node {
		int lc, rc, cnt, sum;
		ll x, y, lx, rx, ly, ry;
	} a[MAXN];
	int root, size, n;
	void update(int root) {
		a[root].sum = a[root].cnt;
		if (a[root].cnt) {
			a[root].lx = a[root].rx = a[root].x;
			a[root].ly = a[root].ry = a[root].y;
		} else {
			a[root].lx = a[root].ly = INF;
			a[root].rx = a[root].ry = -INF;
		}
		if (a[root].lc) {
			int tmp = a[root].lc;
			a[root].sum += a[tmp].sum;
			chkmin(a[root].lx, a[tmp].lx);
			chkmin(a[root].ly, a[tmp].ly);
			chkmax(a[root].rx, a[tmp].rx);
			chkmax(a[root].ry, a[tmp].ry);
		}
		if (a[root].rc) {
			int tmp = a[root].rc;
			a[root].sum += a[tmp].sum;
			chkmin(a[root].lx, a[tmp].lx);
			chkmin(a[root].ly, a[tmp].ly);
			chkmax(a[root].rx, a[tmp].rx);
			chkmax(a[root].ry, a[tmp].ry);
		}
	}
	void build(int &root, int l, int r, int type) {
		if (l > r) return;
		root = ++size, cmptype = type;
		int mid = (l + r) / 2;
		nth_element(p + l, p + mid, p + r + 1, cmp);
		a[root].x = p[mid].x;
		a[root].y = p[mid].y;
		home[p[mid].home] = root;
		a[root].cnt = 1;
		build(a[root].lc, l, mid - 1, type ^ 1);
		build(a[root].rc, mid + 1, r, type ^ 1);
		update(root);
	}
	void init(int x) {
		n = x, root = size = 0;
		build(root, 1, n, 0);
	}
	ll sum, cnt; int vl, vr;
	bool inside(ll x, ll y) {
		return (x * vl - y >= vl * cnt - sum) && (x * vr - y <= vr * cnt - sum);
	}
	bool intersect(int root) {
		if (a[root].sum == 0) return false;
		else return !inside(a[root].lx, a[root].ly) || !inside(a[root].lx, a[root].ry) || !inside(a[root].rx, a[root].ly) || !inside(a[root].rx, a[root].ry);
	}
	bool modify(int root) {
		bool flg = false;
		if (a[root].cnt && !inside(a[root].x, a[root].y)) {
			flg = true;
			a[root].cnt = 0;
		}
		if (intersect(a[root].lc)) flg |= modify(a[root].lc);
		if (intersect(a[root].rc)) flg |= modify(a[root].rc);
		if (flg) update(root);
		return flg;
	}
	void modify(ll tcnt, ll tsum, int tvl, int tvr) {
		cnt = tcnt, sum = tsum, vl = tvl, vr = tvr;
		if (intersect(root)) modify(root);
	}
} KDT;
int main() {
	read(n);
	for (int i = 1; i <= n; i++) {
		read(l[i]), read(r[i]);
		l[i] <<= 1, r[i] <<= 1;
	}
	for (int i = 1; i <= n; i++) {
		cnt[i] = cnt[i - 1] + (r[i] - l[i]);
		sum[i] = sum[i - 1] + (l[i] + r[i]) / 2ll * (r[i] - l[i]);
		p[i] = (point) {cnt[i - 1], sum[i - 1], i};
	}
	KDT.init(n);
	for (int i = n; i >= 1; i--) {
		ans[i] = KDT.a[home[i]].cnt;
		KDT.modify(cnt[i - 1], sum[i - 1], l[i], r[i]);
	}
	int finalans = 0, last = 0;
	for (int i = 1; i <= n; i++)
		if (ans[i]) {
			chkmax(finalans, i - last);
			last = i;
		}
	writeln(finalans);
	return 0;
}

#include<bits/stdc++.h>
using namespace std;
typedef double ldb;
typedef long long ll;
typedef pair<ll,ll> pll; 
const int maxn=1e5+10;
int mn[maxn<<2],L[maxn],R[maxn],n,dp[maxn];
ll A[maxn],B[maxn];
vector<pll>s[2][maxn<<2];
double get(pll a,pll b){
	return (ldb)(a.second-b.second)/(ldb)(b.first-a.first);
}
void build(int o,int l,int r){
	if(l==r){
		s[0][o].push_back(pll(-L[l],L[l]*A[l-1]-B[l-1]));
		s[1][o].push_back(pll(-R[l],R[l]*A[l-1]-B[l-1]));
		return ;
	}
	int mid=l+r>>1;
	build(o<<1,l,mid);
	build(o<<1|1,mid+1,r);
	for(int d=0;d<2;++d){
		auto cmp=[&](int i,int j){
			if(i==s[d][o<<1].size())return (bool)1;
			if(j==s[d][o<<1|1].size())return (bool)0;
			auto p1=s[d][o<<1][i],p2=s[d][o<<1|1][j];
			if(d==0)
				return p1.first==p2.first?p1.second<p2.second:p1.first>p2.first;
			else return p1.first==p2.first?p1.second>p2.second:p1.first<p2.first;
		};
		auto ins=[&](vector<pll>& A,pll p){
			if(A.size()&&A.back().first==p.first)return ;
			while(A.size()>=2){
				double d=get(A[A.size()-1],p);
				double d2=get(A[A.size()-2],A[A.size()-1]);
				if(d2>=d)A.pop_back();
				else break;
			}
			A.push_back(p);
		};
		for(int i=0,j=0;i<s[d][o<<1].size()||j<s[d][o<<1|1].size();){
			if(cmp(i,j))ins(s[d][o],s[d][o<<1|1][j++]);
			else ins(s[d][o],s[d][o<<1][i++]);
		}	
	}
}
ll cal(int o,int d,int x){
	int l=0,r=s[d][o].size()-2,ans=0;
	while(l<=r){
		int mid=l+r>>1;
		if(get(s[d][o][mid],s[d][o][mid+1])<=x)ans=mid+1,l=mid+1;
		else r=mid-1;
	}
	return s[d][o][ans].first*x+s[d][o][ans].second;
}
int chk(int o,ll x,ll y){
	ll p1=cal(o,0,x);
	if(p1>y)return 0;
	ll p2=cal(o,1,x);
	if(p2<y)return 0;
	return 1;
}
int qry(int o,int l,int r,int ql,int qr,ll x,ll y,int flg){
	if(ql>qr)return -1;
	if(ql<=l&&r<=qr&&chk(o,x,y))return -1;
	if(l==r)return l;
	int mid=l+r>>1,ans=-1;
	if(flg==0){
		if(ql<=mid)ans=qry(o<<1,l,mid,ql,qr,x,y,flg);
		if(qr>mid&&ans==-1)ans=qry(o<<1|1,mid+1,r,ql,qr,x,y,flg);
	} else {
		if(qr>mid)ans=qry(o<<1|1,mid+1,r,ql,qr,x,y,flg);
		if(ql<=mid&&ans==-1)ans=qry(o<<1,l,mid,ql,qr,x,y,flg);
	}
	return ans;
}
void mdy2(int o,int l,int r,int x,int y){
	if(l==r){
//		printf("mdy2:[%d,%d]",x,y);
		mn[o]=y;
		return ;
	}
	int mid=l+r>>1;
	if(x<=mid)mdy2(o<<1,l,mid,x,y);
	else mdy2(o<<1|1,mid+1,r,x,y);
	mn[o]=min(mn[o<<1],mn[o<<1|1]);
}
int qry2(int o,int l,int r,int ql,int qr){
	if(ql<=l&&r<=qr)return mn[o];
	int mid=l+r>>1,ans=1<<30;
	if(ql<=mid)ans=min(ans,qry2(o<<1,l,mid,ql,qr));
	if(qr>mid)ans=min(ans,qry2(o<<1|1,mid+1,r,ql,qr));
	return ans;
}
int main(){
