	scanf("%d",&n);
	for(int i=1;i<=n;++i)
		scanf("%d%d",&L[i],&R[i]);
	for(int i=1;i<=n;++i){
		A[i]=A[i-1]+R[i]-L[i];
		B[i]=B[i-1]+(ll)(R[i]-L[i])*(R[i]+L[i])/2;
	}
	build(1,1,n);
	for(int i=n;i>=1;--i){
		dp[i]=(i==n?1:(1<<30));
		int j=qry(1,1,n,i+1,n,A[i-1],-B[i-1],1);
		if(j==-1)j=i;
		int k=qry(1,1,n,i+1,n,A[i-1],-B[i-1],0);
		if(k==-1)k=n;
		else k--;
//		printf("[j=%d,k=%d]",j,k);
		//[j....n],[i....k]
		if(k<j){
			mdy2(1,1,n+1,i,dp[i]);
			continue;
		}
		int l=j-i+1,r=n,ans=(1<<30);
		while(l<=r){
			int mid=l+r>>1;
			int L=j,R=i+min(k-i+1,mid)-1;
//			printf("[%d,%d]:%d\n",L,R,qry2(1,1,n,L,R));
			if(qry2(1,1,n+1,L+1,R+1)<=mid)ans=mid,r=mid-1;
			else l=mid+1;
		}
//		printf("[%d]",ans);
		dp[i]=min(dp[i],ans);
		mdy2(1,1,n+1,i,dp[i]);
	}
	printf("%d",dp[1]);
}

