#define min(a,b) (a<b?a:b)
typedef long long ll;
using namespace std;
typedef vector<int> vt;
inline int read(){
	int n=0;char c;
	for(c=getchar();c<'0'||c>'9';c=getchar());
	for(;c>='0'&&c<='9';c=getchar()) n=n*10+c-48;
	return n;
