const int maxn=1e5+5;
int i,j,n,l,r,ans,now;
ll y[maxn],x[maxn],yl[maxn],xl[maxn],yr[maxn],xr[maxn];
int q[maxn],cnt;
bool bz[maxn];
bool cmp(int x,int y){return xl[x]<xl[y];}
bool cmp1(int x,int y){return xr[x]<xr[y];}
vt workl(int l,int r){
	if (l==r) return vt(1,l);
	int m=(l+r)>>1,i,j,k;
	vt L=workl(l,m),R=workl(m+1,r);
	int tail=R.size()-1;
	fo(i,l,m){
		ll X=x[i-1],Y=y[i-1];
		for(;tail;){
			j=R[tail],k=R[tail-1];
			if (yl[j]-yl[k]<=(xl[j]-xl[k])*X) tail--;else break;
		}j=R[tail];
		if (yl[j]-xl[j]*X+Y>0) bz[i]=1;
	}
	vt now(L.size()+R.size());
	merge(L.begin(),L.end(),R.begin(),R.end(),now.begin(),cmp);
	cnt=0;
	for(int i=0;i<now.size();i++){
		int x=now[i];
		for(;cnt>2;){
			j=q[cnt],k=q[cnt-1];
			if ((yl[x]-yl[j])*(xl[j]-xl[k])>=(yl[j]-yl[k])*(xl[x]-xl[j])) cnt--;else break;
		}
		if (!cnt||yl[q[cnt]]<yl[x]) q[++cnt]=x;
	}
	return vt(q+1,q+1+cnt);
}
vt workr(int l,int r){
	if (l==r) return vt(1,l);
	int m=(l+r)>>1,i,j,k;
	vt L=workr(l,m),R=workr(m+1,r);
	int head=0,tail=R.size()-1;
	fo(i,l,m){
		ll X=x[i-1],Y=y[i-1];
		for(;head<tail;){
			j=R[head+1],k=R[head];
			if (yr[j]-yr[k]<=(xr[j]-xr[k])*X) head++;else break;
		}j=R[head];
		if (!bz[i]&&yr[j]-xr[j]*X+Y<0) bz[i]=1;
	}
	vt now(L.size()+R.size());
	merge(L.begin(),L.end(),R.begin(),R.end(),now.begin(),cmp1);
	cnt=0;
	for(int i=0;i<now.size();i++){
		int x=now[i];
		for(;cnt>2;){
			j=q[cnt],k=q[cnt-1];
			if ((yr[x]-yr[j])*(xr[j]-xr[k])>=(yr[j]-yr[k])*(xr[x]-xr[j])) cnt--;else break;
		}
		if (!cnt||yr[q[cnt]]>yr[x]||xr[q[cnt]]<xr[x]) q[++cnt]=x;
	}
	return vt(q+1,q+1+cnt);
}
int main(){
	n=read();
	fo(i,1,n) {
		l=read(),r=read();
		x[i]=r-l,y[i]=(l+r)*x[i]+y[i-1];
		x[i]=(x[i]<<1)+x[i-1];
		yl[i]=l*x[i-1]-y[i-1],xl[i]=l;
		yr[i]=r*x[i-1]-y[i-1],xr[i]=r;
	}
	workl(1,n);
	workr(1,n);
	j=now=0;
	fo(i,1,n){
		now++,ans=max(ans,now);
		if (!bz[n-(j+now)]) j+=now,now=0;
	}printf("%d\n",ans);
}

