	return j.y*i.x>=i.y*j.x;
}
void prt() {
	std::set<point>::iterator it;
	for(it=st.begin();it!=st.end();it++) printf("(%d,%lld)\n",(*it).x,(*it).y);
	puts("");
}
void ins(point p) {
	std::set<point>::iterator it,pos,jt;
	if(st.empty()) {st.insert(p); return;}
	pos=st.lower_bound(p);
	if(pos!=st.end() && pos->x==p.x) {
		if(pos->y<=p.y) return;
		else st.erase(pos);
	}
	st.insert(p); pos=st.lower_bound(p);
	if(pos!=st.begin()) {
		for(it=pos,it--,jt=it,jt--;it!=st.begin() && jt!=st.begin();it=jt,jt--) {
			if((*it-p)*(*jt-p)>=0) st.erase(it);
			else break;
		}
		if(it!=st.begin() && jt==st.begin() && (*it-p)*(*jt-p)>=0) st.erase(it);
	}
	it=pos; it++;
	if(it!=st.end()) {
		for(jt=it,jt++;it!=st.end() && jt!=st.end();it=jt,jt++) {
			if((*it-p)*(*jt-p)<=0) st.erase(it);
			else break;
		}
	}
	
//	prt();
}
int main() {
	int n,i,las,ans=0;
	std::set<point>::iterator it,jt;
	scanf("%d",&n);
	for(i=1;i<=n;i++) scanf("%d%d",l+i,r+i);
	for(i=n;i>=1;i--) {
		A[i]=A[i+1]+1ll*r[i]*r[i]-1ll*l[i]*l[i];
		B[i]=B[i+1]+(r[i]-l[i])*2;
//		printf("No.%d(%d,%lld)\n",i,l[i],1ll*l[i]*B[i]-A[i]);
	}
	memset(ok,true,sizeof(ok));
	for(i=n;i>=1;i--) {
//		printf("%d\n",i);
		if(st.size()>1) {
			for(it=st.begin(),jt=it,jt++;st.size()>1 && jt->y-it->y<=1ll*B[i]*(jt->x-it->x);it=jt,jt++) st.erase(it);
		}
//		puts("--");
		it=st.begin();
		if(i<n && 1ll*B[i]*it->x-A[i]>it->y) ok[i]=false;
		ins((point){l[i],1ll*l[i]*B[i]-A[i]});
	}

	st.clear();
	for(i=n;i>=1;i--) {
		if(st.size()>1) {
			for(it=st.begin(),jt=it,jt++;st.size()>1 && jt->y-it->y<=1ll*B[i]*(jt->x-it->x);it=jt,jt++) st.erase(it);
		}
		it=st.begin();
		if(i<n && 1ll*B[i]*it->x+A[i]>it->y) ok[i]=false;
		ins((point){-r[i],A[i]-1ll*B[i]*r[i]});
	}
	for(i=n,las=n+1;i>=1;i--) {
		if(ok[i]) ans=max(ans,las-i), las=i;
	}
	printf("%d",max(ans,las));
	return 0;
}

