			if(in[y])chmin(low[x],low[y]);
			continue;
		}
		dfs(y);
		chmin(low[x],low[y]);
	}
	if(low[x]==dfn[x])
	{
		while(1)
		{
			int y=st[top--];
			in[y]=0;
			belong[y]=bcnt;
			if(y==x)break;	
