void merge(u32 f[],u32 f1[],u32 f2[])
{
	static u32 g[N],g1[N],g2[N];
	rep(x,0,n)
	{
		g1[x]=g2[x]=0;
		rep(i,0,x){g1[x]+=C[x][i]*f1[i];g2[x]+=C[x][i]*f2[i];}
	}
	rep(x,0,n)g[x]=g1[x]*g2[x];
	f[0]=g[0];
	rep(x,1,n)
	{
		f[x]=g[x];
		rep(i,0,x-1)f[x]-=f[i]*C[x][i];
	}
}
void Dp(int s);
void dfs_trans(int s,int x,int _s)
{
	if(x<0)
	{
		Dp(s-_s);
		rep(i,1,n)dp[s][i]+=dp[s-_s][i-1];
		return ;
	}
	dfs_trans(s,x-1,_s);
	if((s&(1<<x))&&((nlk[x]&s)|_s)==_s)dfs_trans(s,x-1,_s|(1<<x));
}
void Dp(int s)
{
	if(vis[s])return ;
	vis[s]=1;
	int in=s&-s,q=in;
	while(q)
	{
		int x=lo[q];
		q-=1<<x;
		int now=(lk[x]|nlk[x])&(s-in);
		in+=now;
		q+=now;
	}
	if(in!=s)
	{
		Dp(in);
		Dp(s-in);
		merge(dp[s],dp[in],dp[s-in]);
		return ;
	}
	dfs_trans(s,n-1,0);
}
