int Gcd[N][N];
u32 F(s64 m)
{
	u32 ans=0;
	static s64 a[N];
	rep(i,1,n)
	{
		if(i>m)break;
		a[i]=m-i+1;
		int x=i;
		for(int j=1;x>1;++j)
		{
			int d=Gcd[a[j]%x][x];
			a[j]/=d;x/=d;
		}
		u32 pro=1;
		rep(j,1,i)pro*=a[j];
		ans+=pro*dpu[i];
	}
	return ans;
}
namespace SHAI
{
const int T=2e5+5;
s64 n;int g;
s64 w[T];int top;
u32 s[T];
u32 a_g[40];

int pos(const s64 &x)
{
	return x<=g?x:top-n/x+1; 
}

int pr[T],pcnt;
const int T2=2e7;
int suf[T];
u32 mp[T2];
u32 G(const s64 &n,int m)
{
	if(n<=pr[m])return 0;
	if(s64(pr[m])*pr[m]>n)return a_g[1]*(s[pos(n)]-s[pr[m]]);
	int dy=suf[m+1]+(top-pos(n)+1);
	if(mp[dy])return mp[dy];
	u32 ans=a_g[1]*(s[pos(n)]-s[pr[m]]);
	for(int i=m+1;;++i)
	{
		s64 _n=n/pr[i];
		if(_n<pr[i])break;
		int e=1;
		while(_n>=pr[i])
		{
			ans+=a_g[e]*G(_n,i)+a_g[e+1];
			_n/=pr[i];++e;
		}
	}
	return mp[dy]=ans;
}
u32 G(s64 n)
{
	return G(n,0)+(n>0)*a_g[0];
}

void init(s64 _n)
{
	rep(i,0,39)a_g[i]=(3*i+1)*(3*i+1)*(3*i+1);
	per(i,39,0)a_g[i]-=a_g[i-1];
	
	n=_n;
	g=sqrtl(n);
	for(s64 i=1;i<=n;)
	{
		i=n/(n/i);
		w[++top]=i;
		s[top]=i-1;
		++i;
	}
//	int start_clock=clock();
	rep(i,2,g)
	{
		if(s[i]==s[i-1])continue;
		pr[++pcnt]=i;
		s64 i_2=s64(i)*i;
		for(int j=top;w[j]>=i_2;--j)s[j]-=(s[pos(w[j]/i)]-s[i-1]);
	}
//	fprintf(stderr,"%.2f\n",double(clock()-start_clock)/CLOCKS_PER_SEC);
	pr[pcnt+1]=g+1;
	per(i,pcnt,1)suf[i]=suf[i+1]+
	(top-(lower_bound(w+1,w+top+1,s64(pr[i])*pr[i])-w)+1);
//	cerr<<suf[1]<<endl;
}
};

