namespace LIB{
	const int N=30;
	int dim[N],dimcnt;
	template<class T>void dfs(int dep,T g,int x,int y,int z,int n){
		if(dep>dimcnt){
			g[x][y]=z;
			return;
		}
		int d=n/dim[dep];
		for(int i=0;i<n;i+=d)
			for(int j=0;j<n;j+=d)
				dfs(dep+1,g,x+i,y+j,z+(i+j)%n,d);
	}
	template<class T1,class T2>inline int put_reaction(int t,T1 a,T2 g){
		dimcnt=t;
		int n=1;
		for(int i=1;i<=t;i++){
			n*=dim[i]=a[i];
		}
		dfs(1,g,1,1,1,n);
		return n;
	}
}
