				if(gcd[ig][A[i]]<gcd[ih][A[i]]){
					ans/=A[i]/gcd[ih][A[i]];
					ans*=A[i]/gcd[ig][A[i]];
					re=1;swap(ig,ih);
					for(j=i;j<=tot;j++)swap(nw[j],h[i][j]);
