using LL = __int128;
using ll = long long;
struct line
{
	int k;
	LL b;
	inline LL operator ()(const LL &x) const { return k * x + b; }
	inline ll operator &(const line &a) const
	{
		ll l = 0, r = 1e18, res = -1;
		while (l <= r)
		{
			ll m = l + r >> 1;
			if ((*this)(m) < a(m))
			{
				res = m;
				r = m - 1;
			}
			else
				l = m + 1;
		}
		return res;
	}
} st[100005];
LL dp[100005], mn[100005];
ll sum[100005], stp[100005];
int pre[100005], suf[100005], lim[100005], val[100005], seq[100005];
void work(int l, int r)
{
	if (l == r)
	{
		dp[l] = std::min(dp[l], dp[l - 1] + sum[l + 1] * val[l]);
		return;
	}
	int m = l + r >> 1, cnt = 0, pos = m, tp = 0;
	work(l, m);
	pre[m] = suf[m + 1] = 0;
	mn[m + 1] = 1e30;
	for (int i = m + 1; i <= r; i++)
	{
		if (lim[i] < m)
			seq[cnt++] = i;
		pre[i] = std::max(pre[i - 1], val[i]);
	}
	for (int i = m; i >= l; i--)
	{
		suf[i] = std::max(suf[i + 1], val[i]);
		mn[i] = std::min(mn[i + 1], dp[i - 1]);
	}
	std::sort(seq, seq + cnt, [&] (int x, int y) { return lim[x] > lim[y]; });
	for (int i = 0; i < cnt; i++)
	{
		int x = seq[i];
		while (pos >= l && lim[x] < pos)
		{
			line cur = {suf[pos], dp[pos - 1]};
			while (tp && st[tp](stp[tp]) >= cur(stp[tp]))
				tp--;
			st[++tp] = cur;
			stp[tp] = cur & st[tp - 1];
			if (stp[tp] == -1)
				tp--;
			pos--;
		}
		int mnp = std::upper_bound(stp + 1, stp + tp + 1, sum[x + 1]) - stp - 1;
		if (st[mnp].k > pre[x])
			dp[x] = std::min(dp[x], st[mnp](sum[x + 1]));
	}
	for (int i = 0; i < cnt; i++)
	{
		int cur = seq[i], x = std::max(lim[cur] + 1, l), y = m, res = m + 1;
		while (x <= y)
		{
			int t = x + y >> 1;
			if (suf[t] <= pre[cur])
			{
				res = t;
				y = t - 1;
			}
			else
				x = t + 1;
		}
		dp[cur] = std::min(dp[cur], mn[res] + (LL)sum[cur + 1] * pre[cur]);
	}
	work(m + 1, r);
}
int main()
{
	// freopen("T1.in", "r", stdin);
	int n;
	scanf("%d", &n);
	for (int i = 1; i <= n; i++)
		scanf("%d%d%lld", lim + i, val + i, sum + i);
	for (int i = n; i; i--)
		sum[i] += sum[i + 1];
	memset(dp, 0x3f, sizeof(dp));
	dp[0] = 0;
	st[0] = {(int)1e9, (LL)1e25};
	work(1, n);
	printf("%lld\n", (ll)dp[n]);
	return 0;
}

