vector<pll> mh(vector<pll> a,vector<pll> b)
{
	vector<pll> c,d;
	c.resize(a.size()+b.size()); d.reserve(c.size());
	merge(a.begin(),a.end(),b.begin(),b.end(),c.begin(),greater<pll>());
	for(int i=0;i<int(c.size());++i)
	{
		if(i+1<int(c.size())&&c[i].fi==c[i+1].fi) continue;
