void init(int root,int left,int right)
{
	if(left==right)
	{
		if(left!=0)
			tree[root].mn=1000000000000000007,tree[root].mx=t[left];
		tree[root].pl=left;
		return;
	}
	int mid=left+right>>1;
	init(root*2,left,mid);
	init(root*2+1,mid+1,right);
	tree[root].mn=min(tree[root*2].mn,tree[root*2+1].mn);
	if(tree[root].mn==tree[root*2].mn) tree[root].pl=tree[root*2].pl;
	else tree[root].pl=tree[root*2+1].pl;
	tree[root].mx=max(tree[root*2].mx,tree[root*2+1].mx);
}
void update(int root,int left,int right,int x,long long w)
{
	if(left==right)
	{
		tree[root].mn=w;
		return;
	}
	int mid=left+right>>1;
	if(mid>=x)
		update(root*2,left,mid,x,w);
	else
		update(root*2+1,mid+1,right,x,w);
	tree[root].mn=min(tree[root*2].mn,tree[root*2+1].mn);
	if(tree[root].mn==tree[root*2].mn) tree[root].pl=tree[root*2].pl;
	else tree[root].pl=tree[root*2+1].pl;
}
int querymx(int root,int left,int right,int x,int y)
{
	if(x<=left&&y>=right)
		return tree[root].mx;
	int mid=left+right>>1,ans=0;
	if(mid>=x)
		ans=max(ans,querymx(root*2,left,mid,x,y));
	if(mid<y)
		ans=max(ans,querymx(root*2+1,mid+1,right,x,y));
	return ans;
}
