			if(tree[i].t.Val(suf[L])>p.Val(suf[L]))tree[i].t=p;
			return;
		}
		int mid=(L+R)>>1;
		if(tree[i].t.k>p.k){
			if(p.Val(suf[mid])<tree[i].t.Val(suf[mid])){
				Insert(rs,mid+1,R,tree[i].t);
				tree[i].t=p;
			}
