	}tree[N<<2];
	#define ls i<<1
	#define rs i<<1|1
	void build(int i,int l,int r){
		tree[i].l=l;
		tree[i].r=r;
		if(l==r)return;
		int mid=(l+r)>>1;
		build(ls,l,mid);
		build(rs,mid+1,r);
	}
	void Clear(int i,int l,int r){
		Li::clear(tree[i].root);
		tree[i].root=0;
		if(l==r)return;
		int mid=(l+r)>>1;
		Clear(ls,l,mid);
		Clear(rs,mid+1,r);
	}
	void clear(int l,int r){
		Clear(1,l,r);
		Li::cnt=0;
	}
	void Insert(int i,int p,Line qwq){
		Li::Insert(tree[i].root,1,n,qwq);
		if(tree[i].l==tree[i].r)return;
		int mid=(tree[i].l+tree[i].r)>>1;
		if(p<=mid)Insert(ls,p,qwq);
		else Insert(rs,p,qwq);
	}
	ll Query(int i,int l,int r,int p){
		if(tree[i].l>=l&&tree[i].r<=r){
			return Li::Query(tree[i].root,1,n,p);
		}
		int mid=(tree[i].l+tree[i].r)>>1;
		ll mn=inf;
		if(l<=mid){
			mn=min(mn,Query(ls,l,r,p));
		}
		if(r>mid){
			mn=min(mn,Query(rs,l,r,p));
		}
		return mn;
	}
}
void Solve(int l,int r){
	if(l==r)return;
	int mid=(l+r)>>1;
	Solve(l,mid);
	ll mx=-inf;	
	static int pmx[N],smx[N],z[N],a[N];
	for(int i=mid+1;i<=r;++i){
		smx[i]=(mx=max(mx,t[i]));
	}
	mx=-inf;
	for(int i=mid;i>=l;--i){
		pmx[i]=(mx=max(mx,t[i]));
	}
	for(int i=mid+1,j=mid;i<=r;++i){
		while(j>=l&&t[j]<=smx[i])--j;
		z[i]=j;
	}
	for(int i=mid+1;i<=r;++i){
		z[i]=max(z[i],max(lim[i],l));
		a[i]=i;
	}
	sort(a+mid+1,a+r+1,[&](int i,int j){return z[i]>z[j];});
	ll mn=inf;
	for(int i=mid+1,j=mid;i<=r;++i){
		while(j>=l&&j>=z[a[i]])mn=min(mn,dp[j--]);
		dp[a[i]]=min(dp[a[i]],smx[a[i]]*suf[a[i]]+mn);
	}
	Seg::build(1,l,mid);
	for(int i=l;i<mid;++i){
		Seg::Insert(1,i,Line(pmx[i+1],dp[i]));
	}
	for(int i=mid+1;i<=r;++i){
		if(z[i]>max(lim[i],l)){
			dp[i]=min(dp[i],Seg::Query(1,max(lim[i],l),z[i]-1,i));
		}
	}
	Seg::clear(l,mid);
	Solve(mid+1,r);
}
