		res+=c[t[x]].query(w[x]-w[t[x]]+1,w[y]-w[t[y]]+1);
	else
		res+=c[t[x]].query(w[y]-w[t[y]]+1,w[x]-w[t[x]]+1);
	return res;
}
int subtree_query(int x)
{
