inline void add_(int x,int w) {
	if(b[x]+data[be[x]]>0) --ans[be[x]];
	if(b[x]+data[be[x]]+w>0) ++ans[be[x]];
	
	if(max(b[x],-b[x])<=M) --sta[be[x]][b[x]+M];
	b[x]+=w;
	if(max(b[x],-b[x])<=M) ++sta[be[x]][b[x]+M];
}

inline void T_add(int l,int r,int w) {
	if(be[l]==be[r]) {
		for1(l,r,i) add_(i,w);
		return;
	}
	else {
		for1(l,be[l]*len,i) add_(i,w);
		for1(be[l]+1,be[r]-1,i) {
			if(w==1) {
				ans[i]+=sta[i][M-data[i]];
				++data[i];
			}
			else {
				--data[i];
				ans[i]-=sta[i][M-data[i]];
			}
		}
		for1((be[r]-1)*len+1,r,i) add_(i,w);
	}
}

inline int query(int l,int r) {
	int tot=0;
	if(be[l]==be[r]) {
		for1(l,r,i) tot+=b[i]+data[be[i]]>0;
	}
	else {
		for1(l,be[l]*len,i) tot+=b[i]+data[be[i]]>0;
		for1(be[l]+1,be[r]-1,i) tot+=ans[i];
		for1((be[r]-1)*len+1,r,i) tot+=b[i]+data[be[i]]>0;
	}
	return tot;
}

