			mn.FF += L;
			lz += L;
		}
	}a[maxn*4];
	#define ls p<<1
	#define rs p<<1|1
	void update(int p)
	{
		a[p].mn = min(a[ls].mn, a[rs].mn);
	}
	void pushdown(int p)
	{
		if (a[p].lz!=0)
		{
			a[ls].addlz(a[p].lz);
			a[rs].addlz(a[p].lz);
			a[p].lz = 0;
		}
	}
	void modi(int x, pair<ll,int> v, int l, int r, int p)
	{
		if (l==r)
		{
			a[p].mn = v;
			return;
		}
		pushdown(p);
		int m = l+r>>1;
		if (x<=m) modi(x, v, l, m, ls);
		else modi(x, v, m+1, r, rs);
		update(p);
	}
	void add(int x, int y, ll v, int l, int r, int p)
	{
		if (y<l||r<x) return;
		if (x<=l&&r<=y)
		{
			a[p].addlz(v);
			return;
		}
		pushdown(p);
		int m = l+r>>1;
		if (x<=m) add(x, y, v, l, m, ls);
		if (m<y) add(x, y, v, m+1, r, rs);
		update(p);
	}
	pair<ll,int> query(int x, int y, int l, int r, int p)
	{
		if (r<x||y<l) return MP(1e18, -1);
		if (x<=l&&r<=y) return a[p].mn;
		pushdown(p);
		int m = l+r>>1;
		return min(query(x, y, l, m, ls),query(x,y,m+1,r,rs));
