#define maxn 200005
#define inf 0x3f3f3f3f

int n,m;

#define ls(x) ch[x][0]
#define rs(x) ch[x][1]
bool ext[maxn];
int rt,ch[maxn][2],fa[maxn],top[maxn];
int par[maxn],ls[maxn],rs[maxn];

bool nrt(int p){
	return rs(fa[p])==p||ls(fa[p])==p;
}
bool chk(int p){
	return rs(fa[p])==p;
}

int sum[maxn],suml[maxn],si[maxn],sil[maxn],len[maxn];
void up(int p){
	int l=ch[p][0],r=ch[p][1];
	ext[p]=ext[l]|ext[r]|((p<par[p])^(par[p]<par[par[p]]));
	top[p]=(l?top[l]:p);
	
	sum[p]=sum[l]+sum[r]+si[p];
	suml[p]=suml[l]+suml[r]+sil[p];
	len[p]=len[l]+len[r]+1;
}

void rot(int x){
	int y=fa[x],z=fa[y],k=chk(x),s=ch[x][!k];
	fa[x]=z; if(nrt(y)) ch[z][chk(y)]=x;
	if(s)fa[s]=y; ch[y][k]=s;
	ch[x][!k]=y; fa[y]=x;
	up(y);
}
void splay(int x){
	if(!x||!nrt(x))return;
	while(nrt(x)){
		if(nrt(fa[x]))rot(chk(x)==chk(fa[x])?fa[x]:x);
		rot(x); 
	}up(x);
}
void dfs(int x){
	if(ls(x))dfs(ls(x));
	if(rs(x))dfs(rs(x));
	up(x);
}

int st[maxn],tp;
void ins(int x,int y){
	si[x]+=sum[y];
	if(y<x)sil[x]+=sum[y];
}
void del(int x,int y){
	si[x]-=sum[y];
	if(y<x)sil[x]-=sum[y];
}
void make(int x,int y){
    if(rs(x)) ins(x,rs(x));
    splay(y);
    if(rs(x)=y) del(x,y);
    up(x);
}
void acc(int x){
    tp=0;
    for(int y=0;x;x=fa[y=x])splay(x),st[++tp]=x;
    Rep(i,tp,1){
        splay(st[i]);
        make(st[i],st[i-1]);
    }
}

void cut(int x){
	if(!par[x])return;
//	cerr<<"cut "<<x<<" "<<par[x]<<"\n";
	acc(x),splay(x);
	fa[ls(x)]=0,ls(x)=0,up(x);
	if(x<par[x]) ls[par[x]]=0; else rs[par[x]]=0;
	par[x]=0;
}
void link(int x,int y){
//	cerr<<"link "<<x<<" "<<y<<"\n";
	if(!x||!y)return;
	if(x<y)ls[y]=x; else rs[y]=x;
	acc(x),splay(ls[x]),splay(rs[x]),acc(y),splay(y);
	fa[x]=par[x]=y;
	ins(y,x);
	up(y);
}

vi stk;
void find(int x){
	if(!x||!ext[x])return;
	find(ch[x][1]);
	if((x<par[x])!=(par[x]<par[par[x]]))stk.pb(par[x]);
	find(ch[x][0]);
}
void splay_up(int x,int y)
{
	if(par[x]==y)return;
//	cout<<"splay_up "<<x<<"\n";
	stk.clear();
	cut(x<y?ls[y]:rs[y]);
	acc(x),splay(x),stk.clear(),find(x);
	if(!stk.size() || stk.back()!=top[x]) stk.pb(top[x]);
	
	int lim=stk.size(),z,q=par[stk[0]];
	For(i,0,lim-1){
		z=par[stk[i]],cut(stk[i]);
		if(i>0) link(stk[i-1],z);
	}
	int p=par[x],d=(rs[p]==x);
	cut(x);
	z=d?ls[x]:rs[x];
	cut(z),link(z,p);
	if(q){
		z=d?rs[x]:ls[x];
		cut(z),link(z,q);
	}
	link(stk[lim-1],x);
	if(lim>1) link(stk[lim-2],x);
	link(x,y);
}
void build(int x){
//	cout<<"x: "<<x<<" "<<ls[x]<<" "<<rs[x]<<endl;
	if(ls[x])build(ls[x]);
	if(rs[x])build(rs[x]);
	si[x]=si[ls[x]]+si[rs[x]]+1;
	sil[x]=si[ls[x]]+1;
//	cout<<"build "<<x<<" "<<si[x]<<" "<<sil[x]<<endl;
	up(x);
}

int ask1(int x,int k){
	assert(x);
	if(len[rs(x)]>=k)return ask1(rs(x),k);
	if(len[rs(x)]+1==k)return x;
	return ask1(ls(x),k-len[rs(x)]-1);
}
int ask2(int x,int k){
//	cout<<"ask2 "<<x<<" "<<k<<endl;
	if(suml[ls(x)]>=k)return ask2(ls(x),k);
	k-=suml[ls(x)];
	if(1>=k)return x;
	k-=1;
	if(sil[x]-1>=k)return splay(ls[x]),ask2(ls[x],k);
	k-=sil[x]-1;
	if(sum[rs(x)]>=k)return ask2(rs(x),k);
	k-=sum[rs(x)];
	if(si[x]-sil[x]>=k)return splay(rs[x]),ask2(rs[x],k);
	k-=si[x]-sil[x];
	return ask2(ls(x),k+suml[ls(x)]);
}

signed main()
{
	n=read();
	For(i,1,n){
		par[i]=fa[i]=read();
		if(par[i])i<par[i]?(ls[par[i]]=i):(rs[par[i]]=i);
		else rt=i;
	}
	build(rt);
	m=read();
	For(_,1,m){
		int op=read(),x=read(),y,k;
		if(op==1)y=read(),splay_up(x,y);
		if(op==2){
			k=read();
			acc(x),splay(x);
			y=ask1(x,k+1),splay(y);
			printf("%d\n",y);
		}
		if(op==3){
			splay(rt);
			y=ask2(rt,x);
			splay(y);
			printf("%d\n",y);
		}
	}
	return 0;
}
