#include<bits/stdc++.h>
using namespace std;
const int N=1e5+5,inf=1<<29,MM=1e7;
int n,i,x,y,g[N],sz[N],dep[N],dad[N],dfn[N],xb,md;
vector<int>e[N];
int rt[N];
struct node{
	int l,r,a,b;//min(x+a,b)
	inline void add(int na,int nb){b=min(b+na,nb);a+=na;}
	inline void add2(int v){a+=v;b+=v;}
	inline void add3(int v){if(b>v)b=v;}
	inline int getv(int v=0){return min(v+a,b);}
	inline bool emp(){return !l && !r;}
}t[MM];
struct mmp{
	int st[MM],w;
	inline void ini(){
		for(;w<MM-5;++w,st[w]=w);
	}
	inline int gn(){int x=st[w--];t[x].b=inf;return x;}
	inline void del(int x){st[++w]=x;t[x].l=t[x].r=t[x].a=t[x].b=0;}
}M;
inline void pushdown(int x){
	if(!t[x].l)t[x].l=M.gn();
	if(!t[x].r)t[x].r=M.gn();
	t[t[x].l].add(t[x].a,t[x].b);
	t[t[x].r].add(t[x].a,t[x].b);t[x].a=0;t[x].b=inf;
}
void add(int&x,int l,int r,int k,int v){
	if(!x)x=M.gn(),t[x].b=inf;
	if(k==r){t[x].add2(v);return;}
	int m=(l+r)>>1;pushdown(x);
	if(k>m)t[t[x].l].add2(v),add(t[x].r,m+1,r,k,v);else add(t[x].l,l,m,k,v);
}
int merge(int x,int y){
	if(!x || !y)return x|y;
	if(t[y].emp())swap(x,y);
	if(t[x].emp()){
		t[y].add3(t[x].getv());M.del(x);
		return y;
	}
	pushdown(x);pushdown(y);
	t[x].l=merge(t[x].l,t[y].l);t[x].r=merge(t[x].r,t[y].r);
	return x;
}
int query(int x,int l,int r,int k){
	if(t[x].emp())return t[x].getv();
	int m=(l+r)>>1;return t[x].getv(k<=m?query(t[x].l,l,m,k):query(t[x].r,m+1,r,k));
}
void dfs1(int u,int fa){
	dfn[++xb]=u;dad[u]=fa;sz[u]=1;md=max(md,dep[u]);
	for(int i:e[u])if(i!=fa)dep[i]=dep[u]+1,dfs1(i,u),sz[u]+=sz[i];
}
void dfs(int u,int fa){
	int i,gsum=0;
	for(int v:e[u])if(v!=fa){
		dfs(v,u);gsum+=g[v];
		for(i=0;dep[u]-(1<<i)/2-1>=0;++i)add(rt[v],0,md,dep[u]-(1<<i)/2-1,-sz[v]);
		add(rt[v],0,md,md,-sz[v]-g[v]);
		rt[u]=merge(rt[u],rt[v]);
	}
	add(rt[u],0,md,md,gsum+sz[u]-1);
	for(i=0;dep[u]-(1<<i)/2-1>=0;++i)add(rt[u],0,md,dep[u]-(1<<i)/2-1,sz[u]);
	g[u]=query(rt[u],0,md,dep[u]);
}
int main(){
	M.ini();
	ios::sync_with_stdio(0);cin.tie(0);
	cin>>n;for(i=1;i<n;++i)cin>>x>>y,e[x].push_back(y),e[y].push_back(x);
	dfs1(1,0);
	dfs(1,0);
	cout<<g[1]<<'\n';
	return 0;
}

