using namespace std;
const int N=210000,mo=998244353;
struct tree{
	int l,r,w[2],A[2];
}t[N*50];
int len,n,L,R;
vector<int> go[N];
int f[N],preans,root[N];
void treedp(int k1,int k2,int depth){
	int flag=0;
	if (depth==1) f[k1]=-1e9; else f[k1]=1e9;
	for (int i=0;i<go[k1].size();i++){
		int j=go[k1][i];
		if (j!=k2){
			flag=1; treedp(j,k1,depth^1);
			if (depth) f[k1]=max(f[k1],f[j]); else f[k1]=min(f[k1],f[j]);
		}
	}
	if (flag==0) f[k1]=k1;
}
void change(int k1){
	for (int i=0;i<2;i++)
		t[k1].w[i]=(t[t[k1].l].w[i]+t[t[k1].r].w[i])%mo;
}
int getnew(){
	len++; t[len].A[0]=t[len].A[1]=1; return len;
}
void insert(int k1,int k2,int k3,int k4,int tag){
	if (k2==k3){
		t[k1].w[tag]=1; return;
	}
	int mid=k2+k3>>1;
	if (mid>=k4){
		if (t[k1].l==0) t[k1].l=getnew();
		insert(t[k1].l,k2,mid,k4,tag);
	} else{
		if (t[k1].r==0) t[k1].r=getnew();
		insert(t[k1].r,mid+1,k3,k4,tag);
	}
	change(k1);
}
void mul(int k1,int k2,int k3){
	if (k1==0) return;
	t[k1].w[k3]=1ll*t[k1].w[k3]*k2%mo;
	t[k1].A[k3]=1ll*t[k1].A[k3]*k2%mo;
}
void pushdown(int k1){
	for (int i=0;i<2;i++)
		if (t[k1].A[i]!=1){
			mul(t[k1].l,t[k1].A[i],i);
			mul(t[k1].r,t[k1].A[i],i);
		}
	t[k1].A[0]=t[k1].A[1]=1;
}
void reverseall(int k){
	if (t[k].l==0&&t[k].r==0){
		t[k].w[0]=(t[k].w[0]+t[k].w[1])%mo;
		t[k].w[1]=0;
		return;
	}
	pushdown(k);
	if (t[k].l) reverseall(t[k].l);
	if (t[k].r) reverseall(t[k].r);
	change(k);
}
int merge1(int k1,int k2){
	if (k1==0||k2==0){
		return k1+k2;
	}
	int now=getnew(); pushdown(k1); pushdown(k2);
	t[now].l=merge1(t[k1].l,t[k2].l);
	t[now].r=merge1(t[k1].r,t[k2].r);
	change(now);
	return now;
}
int lw,rw,lsum,rsum;
void putans(int node,int lnode,int rnode,int k2,int k3,int tag){
	if (node==0) return;
	if (rnode==0){
		assert(lnode==node);
		lsum=(lsum+t[lnode].w[tag])%mo;
		mul(node,(rw+rsum)%mo,tag);
		return;
	}
	if (lnode==0){
		assert(rnode==node);
		rsum=(rsum+t[rnode].w[tag])%mo;
		mul(node,(lw+lsum)%mo,tag);
		return;
	}
	if (k2==k3){
		int w1=t[lnode].w[tag],w2=t[rnode].w[tag];
		t[node].w[tag]=(1ll*w1*(rsum+rw)%mo+1ll*w2*(lsum+lw)%mo+1ll*w1*w2)%mo;
		lsum=(lsum+w1)%mo;
		rsum=(rsum+w2)%mo;
		return;
	}
	int mid=k2+k3>>1;
	putans(t[node].l,t[lnode].l,t[rnode].l,k2,mid,tag);
	putans(t[node].r,t[lnode].r,t[rnode].r,mid+1,k3,tag);
	change(node);
	assert(t[node].A[0]==t[node].A[1]&&t[node].A[0]==1);
}
void reverse(int node,int lnode,int rnode,int k2,int k3,int ltag,int rtag,int flag=0){
	if (node==0) return;
	if (rnode==0){
		lsum=(lsum+t[lnode].w[ltag])%mo;
		mul(node,rsum,ltag);
		return;
	}
	if (lnode==0){
		rsum=(rsum+t[rnode].w[rtag])%mo;
		if (flag) reverseall(node);
		mul(node,lsum,ltag);
		return;
	}
	if (k2==k3){
		int w1=t[lnode].w[ltag],w2=t[rnode].w[rtag];
		t[node].w[ltag]=(1ll*w1*rsum+1ll*w2*lsum+1ll*w1*w2)%mo;
		lsum=(lsum+w1)%mo;
		rsum=(rsum+w2)%mo;
		return;
	}
