	change(node);
}
int merge(int k1,int k2,int tag){
	if (f[k1]!=preans&&f[k2]!=preans){
		int nextroot=merge1(root[k1],root[k2]);
		lw=t[root[k1]].w[tag^1];
		rw=t[root[k2]].w[tag^1];
		lsum=rsum=0;
		putans(nextroot,root[k1],root[k2],1,n,tag);
		lsum=rsum=0;
		reverse(nextroot,root[k1],root[k2],1,n,tag^1,tag^1);
		root[k1]=nextroot;
	} else {
		if (f[k2]==preans){
			swap(root[k1],root[k2]);
			swap(f[k1],f[k2]);
		}
		assert(t[root[k2]].w[tag]==0);
		lsum=rsum=0;
		int nextroot=merge1(root[k1],root[k2]);
		reverse(nextroot,root[k1],root[k2],1,n,0,tag^1,1);
		root[k1]=nextroot;
	}
}
