void getans(int k1,int k2,int depth){
	int flag=0;
	if (depth==1) f[k1]=-1e9; else f[k1]=1e9;
	for (int i=0;i<go[k1].size();i++){
		int j=go[k1][i];
		if (j!=k2){
			flag=1; getans(j,k1,depth^1);
			if (root[k1]==0) root[k1]=root[j]; else merge(k1,j,depth);
			if (depth) f[k1]=max(f[k1],f[j]);
			else f[k1]=min(f[k1],f[j]);
		}
	}
	if (flag==0){
		f[k1]=k1;
		if (f[k1]==preans){
			root[k1]=getnew();
			insert(root[k1],1,n,1,0);
			insert(root[k1],1,n,n,0);
		} else {
			root[k1]=getnew();
			insert(root[k1],1,n,abs(k1-preans)+1,k1>=preans);
			insert(root[k1],1,n,n,k1>=preans);
		}
	}
}
