  for (int r = 1; r <= m; r++) {
    int tp = 0;
    ll lsa = 0;
    fill(ban + 1, ban + n + 1, false);
    for (int i = 1; i <= n; i++) {
      if (ans[li[i].id] == -1 && li[i].a != lsa) {
        lsa = li[i].a;
        while (tp >= 2 && stk[tp].intersect(li[i]) < stk[tp - 1].intersect(stk[tp]))
          tp--;
        stk[++tp] = li[i];
      } else if (li[i].a == lsa) {
        ban[i] = true;
      }
    }
    if (!tp) {
      break;
    }

    E.clear();
    int cov = 0;
    for (int i = 1; i <= n; i++) {
      if (ban[i]) {
        continue;
      }
      int l = 2, r = tp, mid;
      Line& lc = li[i];
      int id = li[i].id;
      while (l <= r) {
        mid = (l + r) >> 1;
        if (stk[mid].a < lc.a && stk[mid].intersect(stk[mid - 1]) < lc.intersect(stk[mid])) {
          l = mid + 1;
        } else {
          r = mid - 1;
        }
      }
      --l;
      if (stk[l].a >= lc.a) {
        fl[i] = Fraction(-llf, 1);
      } else {
        fl[i] = stk[l].intersect(lc);
      }

      l = 1, r = tp - 1;
      while (l <= r) {
        mid = (l + r) >> 1;
        if (stk[mid].a > lc.a && lc.intersect(stk[mid]) < stk[mid].intersect(stk[mid + 1])) {
          r = mid - 1;
        } else {
          l = mid + 1;
        }
      }
      ++r;
      if (stk[r].a <= lc.a) {
        fr[i] = Fraction(llf, 1);
      } else {
        fr[i] = lc.intersect(stk[r]);
      }
      if (fr[i] < fl[i] || fr[i] < f0) {
        continue;
      }
      if (ans[id] != -1) {
        if (fl[i] < f0) {
          cov++;
        } else {
          E.emplace_back(1, 1, fl[i]);
        }
        if (fr[i].a != llf) {
          E.emplace_back(1, -1, fr[i]);
        }
      } else {
        E.emplace_back(0, i, fl[i]);
      }
    }
    sort(E.begin(), E.end());
    Fraction lsf = f0;
    bool have_first = cov < r;
    for (auto it = E.begin(), nit = it, _it = E.end(); it != _it; it = nit) {
      while (nit != _it && (*nit).p == (*it).p) {
        auto e = *nit;
        if (!e.op) {
          candidate.push_back(e.v);
        } else {
          cov += e.v;
        }
        nit++;
      }
      auto p = (*it).p;
      if (cov < r) {
        if (!have_first) {
          have_first = true;
          lsf = p;
        }
      } else if (have_first) {
        if (p.floor() >= lsf.ceil()) {
          ncand.clear();
          for (auto x : candidate) {
            auto L = max(fl[x], lsf);
            auto R = min(fr[x], p);
            if (L.ceil() <= R.floor()) {
              ans[li[x].id] = r;
            } else if (lsf < fl[x] && p <= fr[x]) {
              ncand.push_back(x);
            }
          }
          candidate = ncand;
        }
        have_first = false;
      }
    }
    if (cov < r) {
      for (auto x : candidate) {
        auto L = max(fl[x], lsf);
        auto R = fr[x];
        if (L.ceil() <= R.floor()) {
          ans[li[x].id] = r;
        }
      }
    }
    candidate.clear();
  }
  for (int i = 1; i <= n; i++) {
    printf("%d%c", ans[i], " \n"[i == n]);
  }
  return 0;
}

