void pinv(int *a,int *b,int n) {
	if(n==1) { b[0]=1;return; }
	pinv(a,b,n>>1);
	for(int i=0;i<n;i++) A[i]=a[i],B[i]=b[i];
	NTT(A,n<<1,1),NTT(B,n<<1,1);
	for(int i=0;i<(n<<1);i++) A[i]=1ll*A[i]*B[i]%mod*B[i]%mod;
	NTT(A,n<<1,-1);
	for(int i=0;i<n;i++) b[i]=(1ll*b[i]+b[i]-A[i])%mod;
	for(int i=0;i<(n<<1);i++) A[i]=B[i]=0;
}

