int ured() {
	int re = 0;
	char ch;
	do {
		ch = getchar();
	} while('9' < ch || ch < '0');
	do {
		re = re * 10 + (ch ^ '0');
	} while('0' <= (ch = getchar()) && ch <= '9');
	return re;
}
void uwit(long long da) {
	int ch[21], cn = 0;
	do {
		ch[++cn] = da - da / 10 * 10;
	} while(da /= 10);
	do {
		putchar('0' ^ ch[cn]);
	} while(--cn);
}
const int _maxn = 100011, _maxm = 1000011;
const long long _zinf = 1000000000000000000;
struct opts {
	int op, at, ti;
} arry[_maxm << 1];
int n, m, a, b, c, x[_maxm], y[_maxm], p[_maxm], q[_maxm], head[_maxn], tail[_maxn], atno, datk;
long long dpot[_maxm], rans = _zinf, datb;
std :: vector<int> quek[_maxn];
std :: vector<long long> queb[_maxn];
int main() {
	n = ured(), m = ured(), a = ured(), b = ured(), c = ured();
	rep(i, 1, m) {
		x[i] = ured(), y[i] = ured(), p[i] = ured(), q[i] = ured();
		arry[(i << 1) - 1] . op = 0, arry[(i << 1) - 1] . at = i, arry[(i << 1) - 1] . ti = p[i];
		arry[i << 1] . op = 1, arry[i << 1] . at = i, arry[i << 1] . ti = q[i];
	}
	std :: sort(arry + 1, arry + (m << 1 | 1), [](opts le, opts ri) {
		return le . ti == ri . ti ? le . op > ri . op : le . ti < ri . ti;
	});
	quek[1] . push_back(0), queb[1] . push_back(0), ++tail[1];
	rep(i, 1, m << 1) {
		if(arry[i] . op) {
			atno = y[arry[i] . at];
		} else {
			atno = x[arry[i] . at];
		}
		while(head[atno] + 1 < tail[atno] && queb[atno][head[atno] + 1] - queb[atno][head[atno]] <=
		1ll * (quek[atno][head[atno]] - quek[atno][head[atno] + 1]) * arry[i] . ti) {
			++head[atno];
		}
		if(arry[i] . op) {
			if(dpot[arry[i] . at] > -_zinf) {
				if(atno == n){
					if( rans > dpot[arry[i] . at] + arry[i] . ti) {
					rans = dpot[arry[i] . at] + arry[i] . ti;
				}
			}
				datk = -2 * a * arry[i] . ti;
				datb = 1ll * a * arry[i] . ti * arry[i] . ti - 1ll * b * arry[i] . ti + dpot[arry[i] . at];
				while(head[atno] < tail[atno] && (quek[atno][tail[atno] - 1] == datk ? datb <= queb[atno][tail[atno] - 1] :
				head[atno] + 1 < tail[atno] &&
				(__int128)(datb - queb[atno][tail[atno] - 2]) * (quek[atno][tail[atno] - 2] - quek[atno][tail[atno] - 1]) <=
				(__int128)(queb[atno][tail[atno] - 1] - queb[atno][tail[atno] - 2]) * (quek[atno][tail[atno] - 1] - datk))) {
					quek[atno] . pop_back(), queb[atno] . pop_back(), --tail[atno];
				}
				if(head[atno] == tail[atno] || quek[atno][tail[atno] - 1] > datk || queb[atno][tail[atno] - 1] > datb) {
					quek[atno] . push_back(datk), queb[atno] . push_back(datb), ++tail[atno];
				}
			}
		} else {
			if(head[atno] < tail[atno]) {
				dpot[arry[i] . at] = 1ll * quek[atno][head[atno]] * arry[i] . ti + queb[atno][head[atno]]
				+ 1ll * a * arry[i] . ti * arry[i] . ti + 1ll * b * arry[i] . ti + c;
			} else {
				dpot[arry[i] . at] = -_zinf;
			}
		}
	}
	uwit(rans), putchar('\n');
	return 0;
}

