namespace YYY{
	const int N = 1e6 + 10, INF = 1e18;
	int n, cnt, K;
	int a[N], b[N], to1[N], to2[N];
	struct Node1{int x, d; };
	inline bool operator<(Node1 a, Node1 b){return a.d < b.d; }
	priority_queue<Node1> q1, q2, q3; //q3:求和
	struct Node2{int x, y, d; };
	inline bool operator<(Node2 a, Node2 b){return a.d < b.d; }
	priority_queue<Node2> h; //处理第二种情况
	priority_queue<Node2> h2, h3; //分别处理第三四种情况
	inline Node1 find_q1(){
		while(q1.size()){
			Node1 t = q1.top();
			if(to1[t.x] == -1 && to2[t.x] == -1) return t;
			q1.pop();
		}
		return {-1, -INF};
	}
	inline Node1 find_q2(){
		while(q2.size()){
			Node1 t = q2.top();
			if(to1[t.x] == -1 && to2[t.x] == -1) return t;
			q2.pop();
		}
		return {-1, -INF};
	}
	inline Node1 find_q3(){
		while(q3.size()){
			Node1 t = q3.top();
			if(to1[t.x] == -1 && to2[t.x] == -1) return t;
			q3.pop();
		}
		return {-1, -INF};
	}
	inline Node2 find_h(){
		while(h.size()){
			Node2 t = h.top();
			if(to1[t.x] == t.y && to1[t.y] == -1 && to2[t.x] == -1) return t;
			h.pop();
		}
		return {-1, -1, -INF};
	}
	inline Node2 find_h2(){
		while(h2.size()){
			Node2 t = h2.top();
			if(to1[t.x] == t.y && to1[t.y] == -1) return t;
			h2.pop();
		}
		return {-1, -1, -INF};
	}
	inline Node2 find_h3(){
		while(h3.size()){
			Node2 t = h3.top();
			if(to1[t.x] == t.y && to2[t.x] == -1) return t;
			h3.pop();
		}
		return {-1, -1, -INF};
	}
	inline int sol1(){
		return find_q3().d;
	}
	inline int sol2(){
		return find_h().d;
	}
	inline int sol3(){
		return find_h2().d + find_q2().d;
	}
	inline int sol4(){
		return find_h3().d + find_q1().d;
	}
	inline int sol5(){
		if(K == 0) return -INF;
		return find_q1().d + find_q2().d;
	}
	inline void mer(int x, int y){
		to1[x] = y; to2[y] = x;
		if(x != y){
			h.push({x, y, b[x] + a[y]});
			h2.push({x, y, a[y]}); h3.push({x, y, b[x]});
		}
	}
	void sol(){ //多测清空!!!
		while(q1.size()) q1.pop();
		while(q2.size()) q2.pop();
		while(q3.size()) q3.pop();
		while(h.size()) h.pop();
		while(h2.size()) h2.pop();
		while(h3.size()) h3.pop();
		n = read(), cnt = read(), K = read(); K = cnt - K;
		for(int i = 1; i <= n; i ++ ) to1[i] = to2[i] = -1;
		for(int i = 1; i <= n; i ++ ) a[i] = read();
		for(int i = 1; i <= n; i ++ ) b[i] = read();
		for(int i = 1; i <= n; i ++ ){
			q1.push({i, a[i]}); q2.push({i, b[i]}); q3.push({i, a[i] + b[i]});
		}
		int ans = 0;
		while(cnt -- ){
			int maxx = sol1(), g = 1, res;
			res = sol2(); if(res > maxx) maxx = res, g = 2;
			res = sol3(); if(res > maxx) maxx = res, g = 3;
			res = sol4(); if(res > maxx) maxx = res, g = 4;
			res = sol5(); if(res > maxx) maxx = res, g = 5;
			ans += maxx;
			if(g == 1){
				Node1 t = find_q3();
				mer(t.x, t.x);
			}
			else if(g == 2){
				Node2 t = find_h(); mer(t.x, t.x); mer(t.y, t.y); K ++ ;
			}
			else if(g == 3){
				Node2 t1 = find_h2(); Node1 t2 = find_q2();
				mer(t1.x, t2.x); mer(t1.y, t1.y);
			}
			else if(g == 4){
				Node2 t1 = find_h3(); Node1 t2 = find_q1();
				mer(t2.x, t1.y); mer(t1.x, t1.x);
			}
			else if(g == 5){
				Node1 t1 = find_q1(), t2 = find_q2();
				mer(t1.x, t2.x); K -- ;
			}
			// for(int i = 1; i <= n; i ++ ){
			// 	if(to1[i] != -1 && to2[i] != -1 && to1[i] != to2[i]){
			// 		cout<<g<<'\n';
			// 	}
			// }
		}
		cout << ans << '\n';
	}
	signed main(){
		int T; T = read();
		while(T -- ){
			sol();
		}
		return 0;
	}
}
signed main(){
	return YYY::main();
}

#include<bits/stdc++.h>
using namespace std;
const int N=2e5+10;
typedef pair<int,int> pii;
#define fi first
#define se second
#define pb push_back
const int inf=2e9;

int gi() {
	int x=0,o=1;char ch=getchar();
	while((ch<'0'||ch>'9')&&ch!='-') ch=getchar();
	if(ch=='-') o=-1,ch=getchar();
	while(ch>='0'&&ch<='9') x=x*10+ch-'0',ch=getchar();
	return x*o;
}

int cur;

struct edge {
	int w,l,r,d,u;
};

struct point {
	int d[2],id;
	bool operator<(const point &A) const {
		return d[cur]<A.d[cur];
	}
} p[N];

int n,m,w,h,dis[N],ls[N],rs[N],mnd[N],mnp[N],fa[N],ans[N],lim[2][2],mn[N][2],mx[N][2],tag[N],st[N],tp=0,siz[N],ban[N];
vector<edge> E[N];

void update(int x,int y) {
	if(mnd[y]<mnd[x]) mnd[x]=mnd[y],mnp[x]=mnp[y];
}

void pushup(int x) {
	mnd[x]=dis[x],mnp[x]=x;
	if(ls[x]) update(x,ls[x]);
	if(rs[x]) update(x,rs[x]);
	if(siz[x]!=ban[x]) mnd[x]=min(mnd[x],tag[x]);
}

int build(int l,int r,int d) {
	if(l>r) return 0;
	cur=d;int x=(l+r)>>1;
	nth_element(p+l,p+x,p+r+1);
	ls[x]=build(l,x-1,d^1);fa[ls[x]]=x;
	rs[x]=build(x+1,r,d^1);fa[rs[x]]=x;
	siz[x]=siz[ls[x]]+siz[rs[x]]+1;
	for(int i=0;i<2;i++) {
		mn[x][i]=mx[x][i]=p[x].d[i];
		if(ls[x]) mn[x][i]=min(mn[x][i],mn[ls[x]][i]),mx[x][i]=max(mx[x][i],mx[ls[x]][i]);
		if(rs[x]) mn[x][i]=min(mn[x][i],mn[rs[x]][i]),mx[x][i]=max(mx[x][i],mx[rs[x]][i]);
	}
	if(p[x].id==1) dis[x]=0;
	else dis[x]=inf;
	pushup(x);return x;
}

void modify(int x,int y) {
	if(dis[x]!=inf+1) dis[x]=min(dis[x],y);
	if(siz[x]!=ban[x]) mnd[x]=min(mnd[x],y);
	tag[x]=min(tag[x],y);
}

void pushdown(int x) {
	if(tag[x]!=inf) modify(ls[x],tag[x]),modify(rs[x],tag[x]),tag[x]=inf;
}

bool all(int x) {
	for(int i=0;i<2;i++) if(!(lim[i][0]<=mn[x][i]&&mx[x][i]<=lim[i][1])) return 0;
	return 1;
}

bool empty(int x) {
	for(int i=0;i<2;i++) if(mx[x][i]<lim[i][0]||lim[i][1]<mn[x][i]) return 1;
	return 0;
}

bool in(int x) {
	for(int i=0;i<2;i++) if(p[x].d[i]<lim[i][0]||p[x].d[i]>lim[i][1]) return 0;
	return 1;
}

void cover(int x,int y) {
	if(!x||empty(x)||siz[x]==ban[x]) return;
	if(all(x)) { modify(x,y);return; }
	if(dis[x]!=inf+1&&in(x)) dis[x]=min(dis[x],y);
	pushdown(x);
	cover(ls[x],y),cover(rs[x],y);
	pushup(x);
}

void vis(int x) {
	dis[x]=inf+1;
	while(x) ++ban[x],pushup(x),x=fa[x];
}

int main() {
	cin>>n>>m>>w>>h;
	for(int i=1;i<=n;i++) tag[i]=inf;
	for(int i=1;i<=n;i++) p[i].d[0]=gi(),p[i].d[1]=gi(),p[i].id=i;
	for(int i=1,x,w,l,r,d,u;i<=m;i++) x=gi(),w=gi(),l=gi(),r=gi(),d=gi(),u=gi(),E[x].pb((edge){w,l,r,d,u});
	int rt=build(1,n,0);
	while(mnd[rt]<inf) {
		int x=mnp[rt];ans[p[x].id]=mnd[rt];vis(x);
		for(auto e:E[p[x].id]) {
			lim[0][0]=e.l,lim[0][1]=e.r,lim[1][0]=e.d,lim[1][1]=e.u;
			cover(rt,ans[p[x].id]+e.w);
		}
	}
	for(int i=2;i<=n;i++) cout<<ans[i]<<'\n';
	return 0;
}

