using io :: print; 
const int N=7e4+5,inf=2e9;
int ans[N];
inline int max(ri x,ri y){
	return x>y ? x:y; 
}
inline int min(ri x,ri y){
	return x<y ? x:y;
}
struct edge{
	int t,lx,rx,ly,ry;
};
vector<edge> a[N];
int dir;
struct point{
	int x,y,num,id;
	inline bool operator <(const point &rhs)const{
		return dir ? x<rhs.x : y<rhs.y; 
	}
}p[N];
struct node{
	point p,r1,r2;
	node(){}
	node(point p):p(p),r1(p),r2(p){} 
}t[N];
int rt,size,ch[N][2],tag[N],dis[N],mn[N],num[N],col[N],fa[N],sz[N];
#define lc ch[x][0]
#define rc ch[x][1]
inline void up(ri x){
	mn[x]=dis[x];
	num[x]=x;
	if(mn[lc]<mn[x]) mn[x]=mn[lc],num[x]=num[lc];
	if(mn[rc]<mn[x]) mn[x]=mn[rc],num[x]=num[rc];
}
inline void push(ri x,ri w){
	if(sz[x]){
		tag[x]=min(tag[x],w);
		mn[x]=min(mn[x],w);
		if(!col[x]) dis[x]=min(dis[x],w);
	}
}
inline void down(ri x){
	if(tag[x]!=inf){
		if(lc) push(lc,tag[x]);
		if(rc) push(rc,tag[x]);
		tag[x]=inf;
	}
}
inline void build(int &x,ri l,ri r){
	if(l>r) return;
	ri mid=l+r>>1;
	dir^=1;
	nth_element(p+l,p+mid,p+r+1);
	x=++size;
	t[x]=node(p[mid]);
	sz[x]=r-l+1;
	if(p[mid].id==1)
		dis[x]=0;
	else
		dis[x]=inf;
	tag[x]=inf;
	num[x]=x;
	build(lc,l,mid-1);
	build(rc,mid+1,r);
	dir^=1;
	if(lc){
		fa[lc]=x;
		t[x].r1.x=min(t[x].r1.x,t[lc].r1.x);
		t[x].r1.y=min(t[x].r1.y,t[lc].r1.y);
		t[x].r2.x=max(t[x].r2.x,t[lc].r2.x);
		t[x].r2.y=max(t[x].r2.y,t[lc].r2.y);
	}
	if(rc){
		fa[rc]=x;
		t[x].r1.x=min(t[x].r1.x,t[rc].r1.x);
		t[x].r1.y=min(t[x].r1.y,t[rc].r1.y);
		t[x].r2.x=max(t[x].r2.x,t[rc].r2.x);
		t[x].r2.y=max(t[x].r2.y,t[rc].r2.y);
	}
	up(x);
}
inline void upd(ri x,ri lx,ri rx,ri ly,ri ry,ri w){
	if(!sz[x]||t[x].r2.x<lx||rx<t[x].r1.x||t[x].r2.y<ly||ry<t[x].r1.y) return;
	if(lx<=t[x].r1.x&&t[x].r2.x<=rx&&ly<=t[x].r1.y&&t[x].r2.y<=ry){
		push(x,w);
		return;
	}
	if(lx<=t[x].p.x&&t[x].p.x<=rx&&ly<=t[x].p.y&&t[x].p.y<=ry&&!col[x])
		dis[x]=min(dis[x],w),mn[x]=min(mn[x],w);
	down(x);
	upd(lc,lx,rx,ly,ry,w);
	upd(rc,lx,rx,ly,ry,w);
	up(x);
}
int st[N],top;
int main(){
	ri n,m,w,h,i,x,ti,lx,rx,ly,ry;
	gi(n);gi(m);gi(w);gi(h);
	for(i=1;i<=n;++i) gi(p[i].x),gi(p[i].y),p[i].id=i;
	while(m--) gi(x),gi(ti),gi(lx),gi(rx),gi(ly),gi(ry),a[x].push_back((edge){ti,lx,rx,ly,ry});
	mn[0]=inf;
	build(rt,1,n);
	while(mn[rt]!=inf){
		x=num[rt];
		ans[i=t[x].p.id]=mn[rt];
		st[top=1]=x;
		while(fa[x]) st[++top]=x=fa[x];
		while(top) down(st[top--]);
		x=st[1];
		col[x]=1;
		dis[x]=inf;
		while(x) --sz[x],up(x),x=fa[x];
		for(auto o:a[i]) upd(rt,o.lx,o.rx,o.ly,o.ry,ans[i]+o.t);
	}
	for(i=2;i<=n;++i) print(ans[i]),putc('\n'); 
	return 0;
