i64 a[N], b[N], sum[N], c;
int n, m;
bool check(i64 *v, i64 cost){
	sum[1] = cost - c;
	for (int i = m + 1; i <= n; i += m) {
		sum[i] = sum[i - m] + ((sum[i - m] - 1) / (i - m) + 1) * m - c;
	}
	for (int i = 1; i <= n; i += m) {
		int l = 1, r = i, mid = (l + r) >> 1;
		while (l < r) {
			i64 inc = (v[mid] - v[mid - 1]) * (i - mid) - (v[i] - v[mid]);
			i64 can = ((mid - 1) / m + 1) * c;
			if (inc > can) {
				l = mid + 1;
			} else {
				r = mid;
			}
			mid = (l + r) >> 1;
		}
		if (mid < i) {
			int loc = ((mid - 1) / m + 1) * m;
			int len = i - loc;
			i64 cur = v[i] - v[mid - 1] + ((mid - 1) / m + 1) * c;
			int cnt = loc - mid + 1;
			cur -= min((i64)cnt, cur % (len + cnt));
			cur -= cur / (len + cnt) * cnt;
			if (sum[len] <= cur) {
				return true;
			}
		} else if (sum[1] <= v[i] - v[i - 1] + (i - 1) / m * c) {
			return true;
		}
	}
	return false;
}
