{
	eqT ( LL _mv = 0, LL _cm = 0 ) : mv ( _mv ), cm ( _cm ) {}
	
	bool operator < ( const eqT &a ) const
	{
		return ( mv ^ a.mv ) ? ( mv < a.mv ) : ( cm > a.cm );
	}
	
	eqT next ( int len ) const
	{
		eqT ans;
		len -= B;
		ans.mv = mv + A / len;
		ans.cm = qmax ( cm - B, 0 ) + A % len;
		ans.mv += ans.cm / len;
		ans.cm %= len;
		return ans;
	}
	
	friend ostream & operator << ( ostream &output, const eqT &a )
	{
		output << "(" << a.mv << "," << a.cm << ")";
