			cur = eqT ( base + rem / rlen, rem % rlen );
//			cerr << i << " " << nc << " : type 1 : " << ndr << " " << rlen << " " << base << " " << rem << " " << cur << endl;
			chkmax ( dp[i-ndr], cur );
		}else{
			rlen = B * ( i - ndr ) + 1 + ( B - ndp );
