inline int calc(int l,int r){
	return a[l]*(r-l+1)-(sum[r]-sum[l-1]);
}

pii getnxt(pii o,int len){
	int x=o.fi,y=o.se;
	if(c<len-y){
		y=max(0ll,y+c-m);
		return mkp(x,y);
	}
	int now=c;
	++x,now-=(len-y),y=0;
	x+=now/len,y=now%len;
	y=max(0ll,y-m);
	return mkp(x,y);
}

/*
1 2 .. m+1 m+2   
0 1 1  1   2
*/

void solve(bool bo=0)
{
	For(i,1,n)sum[i]=sum[i-1]+a[i];
//	For(i,1,n)cout<<a[i]<<" ";puts("");
	For(i,0,(n-1)/m){
//		cout<<"solve "<<i<<endl;
		if(bo&&i<(n-1)/m)continue;
		int l=1,r=i*m+1,p=r;
		while(l<=r){
			int mid=l+r>>1;
			int nd=calc(mid,i*m+1);
			int hav=c*(mid==1?0:(mid-2)/m+1);
			if(hav>=nd)p=mid,r=mid-1;
			else l=mid+1;
		}
		
		int pos=(p==1?0:(p-2)/m+1);
		int hav=c*pos; 
		int p2=p;
		
		l=1,r=p;
		while(l<=r){
			int mid=l+r>>1;
			if(calc(mid,i*m+1)<=hav)p2=mid,r=mid-1;
			else l=mid+1; 
		}
		
		p2=max(p2,(pos-1)*m+1);
		
		hav-=calc(p2,i*m+1);
		int x=a[p2],len=(i*m+1)-p2+1;
		x+=hav/len; hav%=len;
		hav=max(0ll,hav-(pos*m-p2+1));
		f[i-pos]=max(f[i-pos],mkp(x,hav));
		
//		cout<<"F: "<<i-pos<<" "<<x<<" "<<hav<<endl;
	}
	Rep(i,(n-1)/m,1) f[i-1]=max(f[i-1],getnxt(f[i],i*m+1));
//	cout<<"f0 "<<f[0].fi<<" "<<f[0].se<<endl;
	res=max(res,f[0].fi+(f[0].se>0)+c);
//	cout<<"RES: "<<res<<endl;
}

