	For(i,1,n){
		int nd=b[i]*(n-i)-(sum[n]-sum[i]);
		if(now>=nd){
			int d=(now-nd-1)/(n-i+1)+1;
			b[i]+=d;
			now-=d; 
		}
		if(i<=m)b[i]=0;
		if(!now)break; 
	}
	For(i,1,n)a[i]=b[i];
	sort(a+1,a+n+1,greater<int>());
