	For(i,1,n)a[i]=(c-1)/m;
	For(i,1,(c-1)%m)a[i]++;
	For(i,1,m)a[i]=0;
	sort(a+1,a+n+1,greater<int>());
	solve();
	cout<<res;
    return 0;
}

