typedef long long LL;
typedef unsigned long long ULL;

const int N = 2000050;
const int mod = 998244353;

LL pow_mod(LL a, LL b) {
  LL ans = 1;
  for (; b; b >>= 1, a = a * a % mod)
    if (b & 1) ans = ans * a % mod;
  return ans;
}

int L, rev[N];
LL fac[N], ifac[N], inv[N], omega[N];

void Init(int n) {
  L = 1;
  while (L <= n) L <<= 1;
  inv[1] = 1;
  for (int i = 2; i < L; ++i) inv[i] = -(mod / i) * inv[mod % i] % mod;
  fac[0] = ifac[0] = 1;
  for (int i = 1; i < L; ++i) {
    fac[i] = fac[i - 1] * i % mod;
    ifac[i] = ifac[i - 1] * inv[i] % mod;
  }
  for (int i = 1; i < L; ++i)
    rev[i] = (rev[i >> 1] >> 1) | ((i & 1) * (L / 2));
  LL w = pow_mod(3, (mod - 1) / L);
  omega[L / 2] = 1;
  for (int i = L / 2; i + 1 < L; ++i)
    omega[i + 1] = omega[i] * w % mod;
  for (int i = L / 2 - 1; i > 0; --i)
    omega[i] = omega[i << 1];
}

void DFT(LL *A, int len) {
  static ULL T[N];
  int t = __builtin_ctz(L) - __builtin_ctz(len);
  for (int i = 0; i < len; ++i) T[rev[i] >> t] = (A[i] + mod) % mod;
  for (int h = 1; h < len; h <<= 1)
    for (int i = 0; i < len; i += h << 1)
      for (int j = 0; j < h; ++j) {
        ULL &t1 = T[j + i], t2 = T[j + i + h] * omega[h + j] % mod;
        T[j + i + h] = t1 + mod - t2;
        t1 += t2;
      }
  for (int i = 0; i < len; ++i) A[i] = T[i] % mod;
}

void IDFT(LL *A, int len) {
  std::reverse(A + 1, A + len);
  DFT(A, len);
  for (int i = 0, v = -(mod - 1) / len; i < len; ++i)
    A[i] = A[i] * v % mod;
}

void PolyInv(const LL *A, int n, LL *B) {
  if (n == 1) { B[0] = pow_mod(A[0], mod - 2); return; }
  int m = (n + 1) / 2;
  PolyInv(A, m, B);

  static LL tA[N], tB[N];
  int len = 1; while (len < n + m) len <<= 1;
  for (int i = 0; i < n; ++i) tA[i] = A[i];
  for (int i = n; i < len; ++i) tA[i] = 0;
  for (int i = 0; i < m; ++i) tB[i] = B[i];
  for (int i = m; i < len; ++i) tB[i] = 0;
  DFT(tA, len); DFT(tB, len);
  for (int i = 0; i < len; ++i)
    tB[i] = (2 - tA[i] * tB[i]) % mod * tB[i] % mod;
  IDFT(tB, len);
  for (int i = m; i < n; ++i) B[i] = tB[i];
}

void PolyLn(const LL *A, int n, LL *B) {
  static LL tA[N], tB[N];
  int len = 1; while (len < n * 2) len <<= 1;
  PolyInv(A, n, tA);
  for (int i = n; i < len; ++i) tA[i] = 0;
  for (int i = 1; i < n; ++i) tB[i - 1] = A[i] * i % mod;
  for (int i = n - 1; i < len; ++i) tB[i] = 0;
  DFT(tA, len); DFT(tB, len);
  for (int i = 0; i < len; ++i)
    tB[i] = tA[i] * tB[i] % mod;
  IDFT(tB, len);
  B[0] = 0;
  for (int i = 1; i < n; ++i) B[i] = tB[i - 1] * inv[i] % mod;
}

void PolyExp(const LL *A, int n, LL *B) {
  if (n == 1) { B[0] = 1; return; }
  int m = (n + 1) / 2;
  PolyExp(A, m, B);
  for (int i = m; i < n; ++i) B[i] = 0;

  static LL tA[N], tB[N];
  int len = 1; while (len < n) len <<= 1;
  PolyLn(B, n, tA);
  for (int i = 0; i < n; ++i) tA[i] = ((i == 0) + A[i] - tA[i]) % mod;
  for (int i = n; i < len; ++i) tA[i] = 0;
  for (int i = 0; i < m; ++i) tB[i] = B[i];
  for (int i = m; i < len; ++i) tB[i] = 0;
  DFT(tA, len); DFT(tB, len);
  for (int i = 0; i < len; ++i) tB[i] = tA[i] * tB[i] % mod;
  IDFT(tB, len);
  for (int i = m; i < n; ++i) B[i] = tB[i];
}

LL _F[N], *F[N], _G[N], *G[N], T[N];

LL Solve(int n, int m, int k) {
  if (n > m) std::swap(n, m);
  LL p = 12LL * k % mod * (k - 1) % mod * (k - 2) % mod * (k - 3) % mod;
  LL q = ((72LL * (k - 2) % mod + 34) * (k - 1) % mod + 1) * k % mod;
  p = p * pow_mod(q, mod - 2) % mod;
  Init((m + 1) * 2);
  int l = 1; while (l <= (m + 1) * 2) l <<= 1;
  for (int i = 0; i <= n; ++i)
    F[i] = _F + i * l * 2, G[i] = _G + i * l * 2;
  for (int i = 0; i <= n; ++i)
    for (int j = 0; j <= m; ++j)
      F[i][j] = pow_mod(1 + p, i * j) * ifac[i] % mod * ifac[j] % mod;
  PolyLn(F[0], m + 1, T);
  for (int i = 0; i <= m; ++i) T[i] = T[i] * (mod + 1) / 2 % mod;
  PolyExp(T, m + 1, G[0]);
  PolyInv(G[0], m + 1, T);
  if (n) DFT(G[0], l); DFT(T, l);
  for (int i = 1; i <= n; ++i) {
    LL *ans = G[i];
    for (int j = 0; j <= m; ++j) ans[j] = F[i][j];
    DFT(ans, l);
    for (int j = 1; j < i; ++j)
      for (int k = 0; k < l; ++k)
        ans[k] = (ans[k] - G[j][k] * G[i - j][k]) % mod;

    IDFT(ans, l);
    for (int j = m + 1; j < l; ++j) ans[j] = 0;
    DFT(ans, l);

    for (int j = 0; j < l; ++j) ans[j] = ans[j] * T[j] % mod;

    IDFT(ans, l);
    for (int j = m + 1; j < l; ++j) ans[j] = 0;
    for (int j = 0; j <= m; ++j) ans[j] = ans[j] * (mod + 1) / 2 % mod;
    if (i != n) DFT(ans, l);
  }
  return G[n][m] * fac[n] % mod * fac[m] % mod * pow_mod(q, n * m) % mod * pow_mod(2, n + m) % mod;
}

int main() {
  int n, m, k; scanf("%d%d%d", &n, &m, &k);
  LL ans = Solve(n / 2, m / 2, k);
  if (n & 1) {
    LL q = pow_mod(k, m / 2);
    ans = ans * (2 * q * q % mod - q) % mod;
  }
  if (m & 1) {
    LL q = pow_mod(k, n / 2);
    ans = ans * (2 * q * q % mod - q) % mod;
  }
  if (n & m & 1) ans = ans * k % mod;
  printf("%lld\n", (ans + mod) % mod);
}

