void add(int x,int y){
	to[++edge]=y;
	Next[edge]=last[x];
	last[x]=edge;
}
void dfs(int x,int fa){
	size[x]=1,f[x]=fa;
	for (int i=last[x];i;i=Next[i])
	if (to[i]!=fa){
		dfs(to[i],x);
		size[x]=size[x]+size[to[i]];
		if (size[to[i]]>size[son[x]])
			son[x]=to[i];
	}
	if (size[son[x]]<=n/2 && n-size[x]<=n/2) g=x;
}
bool chk(int x,int n){
	if (n<size[x]) return 0;
	int t=size[son[x]];
	if (t<=n/2 && n-size[x]<=n/2) return 1;
	return 0;
}
void dfs2(int x){
	for (int i=last[x];i;i=Next[i]){
		int u=to[i];
		if (u==f[x]) continue;
		dfs2(u);
	}
	if (son[x]){
		int j=G[son[x]];
		for (;!chk(j,size[x]);j=f[j]);
		G[x]=j;	
	}else G[x]=x;
	ans+=G[x];
	if (chk(f[G[x]],size[x])) ans+=f[G[x]]; 
}
void dfs3(int x){
	int siz=size[x];
	ans=ans+a[siz];
	if (!a[siz]) ans=ans+g;
	if (f[a[siz]]==g && size[son[g]]<=(n-siz)/2) ans=ans+g; 
	if (f[a[siz]]!=g && chk(f[a[siz]],n-siz)) ans=ans+f[a[siz]];
	for (int i=last[x];i;i=Next[i])
		if (to[i]!=f[x]) dfs3(to[i]);
}
void dfs4(int x){
	if (size[son[g]]-size[x]>=size[sson]) ans=ans+g;
	else{
		int siz=size[x];
		if (!a[siz]) ans=ans+g;
		else{
			ans=ans+a[siz];
			if (f[a[siz]]==g && size[sson]<=(n-siz)/2) ans=ans+g; 
			if (chk(f[a[siz]],n-siz)) ans=ans+f[a[siz]];		
		}
	}
	for (int i=last[x];i;i=Next[i]) 
		if(to[i]!=f[x])dfs4(to[i]);
}
