	inline ll query(int l,int r){
		int k=lg[r-l+1];
		return gcd(g[k][l],g[k][r-(1<<k)+1]);
	}
	inline int binrx(int r,ll k){
		int _=r,l=1,pos=0;
		while(l<=r){
			int mid=l+r>>1;
			if(query(mid,_)%k) pos=mid,l=mid+1;
			else r=mid-1;
		}
		return pos;
	}
	inline int binry(int l,ll k){
		int _=l,r=n,pos=n+1;
		while(l<=r){
			int mid=l+r>>1;
			if(query(_,mid)%k) pos=mid,r=mid-1;
			else l=mid+1;
		}
		return pos;
	}
	inline ll calc(int pos){
		int le=pos,ri=pos; ll k=a[pos]; ll ret=-a[pos];
		while(le>1||ri<n){
			int x=binrx(le-1,k),y=binry(ri+1,k);
			if(x<1&&y>n){
				ret+=((le-1)+(n-ri))*k;
				break;
			}
			if(y>n) ret+=(le-x)*k,le=x;
			else if(x<1) ret+=(y-ri)*k,ri=y;
			else if((le-x)*k+(y-ri)*query(x,ri)<=(y-ri)*k+(le-x)*query(le,y))
			 	ret+=(le-x)*k,le=x;
			else
			 	ret+=(y-ri)*k,ri=y;
			k=query(le,ri);
		}
		return ret;
	}
