{
	int x1, y1, x2, y2;
	
	Answer() : x1(1), y1(1), x2(1e9), y2(1e9) {}
	
	void add(Node x)
	{
		up(x1, x.x1);
		up(y1, x.y1);
		dn(x2, x.x2);
		dn(y2, x.y2);
	}
	
	int s() const
	{
		return max(0, x2 - x1 + 1) * max(0, y2 - y1 + 1);
	}
	
	double calc(Node x)
	{
		Answer tmp = *this;
		tmp.add(x);
		int tmps = tmp.s();
		if (tmps == 0) return inf;
		return 1.0 * s() / tmps;
	}
};

