			if (~k) add(R[j].second, pre[k]);
		}
		for (int j = R.size() - 1; ~j; j--) {
			suf[j] = ++tot;
			if (j < R.size() - 1) add(suf[j], suf[j + 1]);
			add(suf[j], R[j].second ^ 1);
		}
		for (int j = L.size() - 1, k = R.size(); ~j; j--) {
