int binom(int a , int b){return 1ll * fac[a] * ifac[b] % MOD * ifac[a - b] % MOD;}

int w[_] , dir[_] , need , invnd;
void init(int len){
	need = 1; while(need < len) need <<= 1;
	for(int i = 1 ; i < need ; ++i) dir[i] = (dir[i >> 1] >> 1) | (i & 1 ? need >> 1 : 0);
	static int L = 1; invnd = poww(need , MOD - 2);
	for(int &i = L ; i < need ; i <<= 1){
		w[i] = 1; int wn = poww(G , MOD / 2 / i);
		for(int j = 1 ; j < i ; ++j) w[i + j] = 1ll * w[i + j - 1] * wn % MOD;
	}
