void DFT(int* arr , int tp){
	for(int i = 1 ; i < need ; ++i)
		if(i < dir[i]) swap(arr[i] , arr[dir[i]]);
	for(int i = 1 ; i < need ; i <<= 1)
		for(int j = 0 ; j < need ; j += i << 1)
			for(int k = 0 ; k < i ; ++k){
				int x = arr[j + k] , y = 1ll * arr[i + j + k] * w[i + k] % MOD;
				arr[j + k] = upd(x + y - MOD); arr[i + j + k] = upd(x - y);
			}
	if(tp == -1){
		reverse(arr + 1 , arr + need);
		for(int i = 0 ; i < need ; ++i) arr[i] = 1ll * arr[i] * invnd % MOD;
	}
}

void divide(int len){
	if(len == 1){
		for(int j = 0 ; j < B ; ++j) pol[1][j] = ifac[j];
		return;
	}
	divide(len >> 1); init(len * B);
	static int tmp1[_] , tmp2[_];
	memset(tmp1 , 0 , sizeof(tmp1)); memcpy(tmp1 , pol[len >> 1] , sizeof(tmp1)); DFT(tmp1 , 1);
	for(int i = 1 ; i <= len >> 1 ; ++i){
		memset(tmp2 , 0 , sizeof(tmp2)); memcpy(tmp2 , pol[i] , sizeof(pol[i]));
		DFT(tmp2 , 1); for(int j = 0 ; j < need ; ++j) tmp2[j] = 1ll * tmp2[j] * tmp1[j] % MOD;
		DFT(tmp2 , -1); memcpy(pol[(len >> 1) + i] , tmp2 , sizeof(tmp2));
	}
}

