};
node operator+(const node &l, const node &r) {
	return (node){l.a + r.a >= P ? l.a + r.a - P : l.a + r.a, l.b + r.b >= P ? l.b + r.b - P : l.b + r.b};
}
node operator-(const node &r) {
	return (node){P - r.a, P - r.b};
