			cnt[i] += a[i][j].a || a[i][j].b;
	}
	register node res = (node){1, 0};
	for (register int i = 1; i <= n; ++i) {
		register int r = i;
		for (register int j = i + 1; j <= n; ++j)
			if ((!a[r][i].a && (!a[r][i].b || a[j][i].a)) || (a[j][i].a && cnt[j] < cnt[r])) r = j;
		if (r != i) {
			res = -res;
			for (int j = i; j <= n; ++j)
				swap(a[i][j], a[r][j]);
		}
		res = res * a[i][i];
		register node tmp = inv(a[i][i]);
		for (register int j = i + 1; j <= n; ++j)
			if (a[j][i].a || a[j][i].b) {
				register node ttmp = a[j][i] * tmp;
				cnt[j] = 0;
				for (register int k = i; k <= n; ++k) {
					a[j][k] = a[j][k] - ttmp * a[i][k];
					cnt[j] += a[j][k].a || a[j][k].b;
				}
			}
	}
	return res;
}

