const int Mod = 998244353; 
int fpow(int x, int y) { 
	int res = 1; 
	while (y) {
		if (y & 1) res = 1ll * res * x % Mod; 
		x = 1ll * x * x % Mod; 
		y >>= 1; 
	} 
	return res; 
} 
int Inc(int x, int y) { x += y; return x >= Mod ? x - Mod : x; } 
struct node { int x, y; } ; 
node operator + (const node &l, const node &r) { return (node){Inc(l.x, r.x), Inc(l.y, r.y)}; } 
node operator - (const node &l, const node &r) { return (node){Inc(l.x, Mod - r.x), Inc(l.y, Mod - r.y)}; } 
node operator * (const node &l, const node &r) { 
	node res; 
	res.x = 1ll * l.x * r.x % Mod; 
	res.y = (1ll * l.x * r.y + 1ll * l.y * r.x) % Mod; 
	return res; 
} 
node operator / (const node &l, const node &r) { 
	node res; 
	int inv = fpow(r.x, Mod - 2); 
	res.x = 1ll * l.x * inv % Mod; 
	res.y = 1ll * inv * inv % Mod * Inc((1ll * l.y * r.x - 1ll * l.x * r.y) % Mod, Mod) % Mod; 
	return res; 
} 
const int MAX_N = 35, MAX_V = 2e5 + 5; 
