void sieve() { 
	phi[1] = 1; 
	for (int i = 2; i <= N; i++) { 
		if (!nprime[i]) prime[++num] = i, phi[i] = i - 1; 
		for (int j = 1; j <= num && prime[j] * i <= N; j++) {
			nprime[prime[j] * i] = 1; 
			if (i % prime[j] == 0) { 
				phi[i * prime[j]] = phi[i] * prime[j]; 
				break; 
			} 
			phi[i * prime[j]] = phi[i] * phi[prime[j]]; 
		} 
	} 
}
node A[MAX_N][MAX_N]; 
int gauss(int n) { 
	node res = (node){1, 0}; 
	for (int i = 1; i <= n; i++) { 
		int l = i; 
		for (int j = i; j <= n && !A[l][i].x; j++) l = j; 
		if (l != i) {
			for (int j = i; j <= n; j++) 
				swap(A[i][j], A[l][j]); 
			res = (node){0, 0} - res; 
		}
		res = res * A[i][i]; 
		node inv = (node){1, 0} / A[i][i]; 
		for (int j = i + 1; j <= n; j++) { 
			node t = A[j][i] * inv; 
			for (int k = i; k <= n; k++) 
				A[j][k] = A[j][k] - t * A[i][k]; 
		} 
	} 
//	for (int i = 1; i <= n; i++) res = res * A[i][i]; 
//	return op ? res.y : Mod - res.y;
	return res.y; 
} 
int solve(int d) { 
	for (int i = 1; i <= N; i++)
		for (int j = 1; j <= N; j++) A[i][j] = (node){0, 0}; 
	for (int i = 1; i <= M; i++) {
		if (w[i] % d) continue; 
		A[u[i]][u[i]] = A[u[i]][u[i]] + (node){1, w[i]}; 
		A[v[i]][v[i]] = A[v[i]][v[i]] + (node){1, w[i]}; 
		A[u[i]][v[i]] = A[u[i]][v[i]] - (node){1, w[i]}; 
		A[v[i]][u[i]] = A[v[i]][u[i]] - (node){1, w[i]}; 
	} 
	return gauss(N - 1); 
} 
