typedef unsigned long long u64; 

template <class T>
inline void read(T &x) {
	static char ch; 
	while (!isdigit(ch = getchar())); 
	x = ch - '0'; 
	while (isdigit(ch = getchar()))
		x = x * 10 + ch - '0'; 
}

template <class T>
inline void readAlpha(T &x) {
	static char ch; 
	while (!islower(ch = getchar())); 
	x = ch - 'a'; 
}

const int MaxN = 500 + 5; 
const int MaxE = 3000 + 5; 
const u64 mod[] = {998244353, 1004535809, 1919810, 1000000009, 1000000007}; 

int base[MaxE][26][5]; 

inline bool isPrime(int n) {
	for (int i = 2; i * i <= n; ++i)
		if (n % i == 0) return false; 
	return true; 
}

struct edge {
	int u, v, w; 
	inline void scan() {
		read(u), read(v), readAlpha(w); 
	}
}; 

struct graph {
	int n, m; 
	edge e[MaxE]; 
	u64 f[MaxE][MaxN][5]; 

	inline void scan() {
		read(n), read(m); 
		for (int i = 1; i <= m; ++i) e[i].scan(); 
		for (int i = 1; i <= n; ++i) {
			for (int opt = 0; opt < 5; ++opt)
				f[0][i][opt] = 1; 
		}
	}

	inline void extend(int len, int lim = -1) {
		memset(f[len], 0, sizeof(f[len])); 

		for (int i = 1; i <= m; ++i) {
			int u = e[i].u, v = e[i].v, w = e[i].w; 
			if (lim != -1 && w != lim) continue; 

			for (int opt = 0; opt < 2; ++opt) {
				(f[len][u][opt] += base[len][w][opt] * f[len - 1][v][opt]) %= mod[opt]; 
			}
		}
	}
}G1, G2; 

void solve(int len) {
	static int ans[MaxE]; 
	for (int i = 1; i <= len; ++i) {
		for (int ch = 0; ch < 26; ++ch) {
			ans[i] = ch; 

			for (int j = i; j >= 1; --j) {
				G1.extend(len - j + 1, ans[j]); 
				G2.extend(len - j + 1, ans[j]); 
			}

			bool flg = false; 
			for (int opt = 0; opt < 2; ++opt) {
				u64 sumA = 0, sumB = 0; 
				for (int i = 1; i <= G1.n; ++i) {
					(sumA += G1.f[len][i][opt]) %= mod[opt]; 
				}
				for (int i = 1; i <= G2.n; ++i) {
					(sumB += G2.f[len][i][opt]) %= mod[opt]; 
				}

				if (sumA != sumB) {
					flg = true; 
					break; 
				}
			}

			if (flg) break; 
		}
	}

	for (int i = 1; i <= len; ++i)
		putchar(ans[i] + 'a'); 
	puts(""); 
}

inline u64 randU64() {
	u64 res = 0; 
	for (int i = 0; i < 64; ++i)
		res = res << 1 | (rand() & 1); 
	
	return res; 
}

