#endif

	for (int i = 0; i <= 502; ++i)
		for (int w = 0; w < 26; ++w)
			for (int opt = 0; opt < 2; ++opt)
				base[i][w][opt] = randU64() % mod[opt]; 

	G1.scan(), G2.scan(); 

	for (int len = 1; len <= 502; ++len) {
		G1.extend(len), G2.extend(len); 

		for (int opt = 0; opt < 2; ++opt) {
			u64 sumA = 0, sumB = 0; 
			for (int i = 1; i <= G1.n; ++i) {
				(sumA += G1.f[len][i][opt]) %= mod[opt]; 
			}
			for (int i = 1; i <= G2.n; ++i) {
				(sumB += G2.f[len][i][opt]) %= mod[opt]; 
			}

			if (sumA != sumB) {
				solve(len); 
				return 0; 
			}
		}
	}

	puts("Same"); 

	return 0; 
}

