#define N 500000
#define P 998244353
#define INF 999999999
int n, m, dep[N], a[N];
std::vector<int> G[N];
void dfsT(int u, int lim) {
	for (int v : G[u]) {
		if (v == lim) continue;
		dep[v] = dep[u] + 1;
		dfsT(v, u);
	}
}
std::vector<int> R[N], S[N]; int pt[N];
void dfsS(int u) {
	R[u].push_back(a[u]);
	for (int v : G[u]) {
		if (dep[v] < dep[u]) continue;
		if (a[v] < a[u]) a[v] = a[u];
		dfsS(v);
		for (int x : R[v])
			if (a[u] < x && x < dep[u]) R[u].push_back(x);
	}
	std::sort(R[u].begin(), R[u].end());
	int sz = std::unique(R[u].begin(), R[u].end())-R[u].begin();
	R[u].resize(sz);
	for (int x : R[u]) {
		int ret = 1;
		for (int v : G[u]) {
			if (dep[v] < dep[u]) continue;
			while (pt[v]+1 < R[v].size() && R[v][pt[v]+1] <= x) pt[v]++;
			int t = S[v].back();
			if (R[v][pt[v]] <= x) t += S[v][pt[v]];
			ret = 1ll*ret*t % P;
		}
		S[u].push_back(ret);
	}
}
int main() {
	scanf("%d", &n);
	for (int i = 1, x, y; i < n; i++) {
		scanf("%d%d", &x, &y); x--; y--;
		G[x].push_back(y);
		G[y].push_back(x);
	}
	dep[0] = 0;	
	dfsT(0, -1);
	scanf("%d", &m);
	for (int i = 0; i < n; i++) a[i] = -INF;
	while (m--) {
		int u, v;
		scanf("%d%d", &u, &v); u--; v--;
		if (dep[u] > a[v]) a[v] = dep[u];
	}
	dfsS(0);
	printf("%d\n", S[0].back());
}

