pair<int, int> get_max() {
	pair<int, int> p1 = q1.empty() ? make_pair(0, 0) : q1.back();
	pair<int, int> p2 = q2.empty() ? make_pair(0, 0) : q2.back();
	pair<int, int> p3 = q3.empty() ? make_pair(0, 0) : q3.back();
	pair<int, int> p4 = max(p1, max(p2, p3));
	if (p1 == p4) q1.pop_back();
	else if (p2 == p4) q2.pop_back();
	else q3.pop_back();
	return p4;
}

pair<int, int> get_min() {
	pair<int, int> p1 = q1.empty() ? make_pair(INT_MAX, 0) : q1.front();
	pair<int, int> p2 = q2.empty() ? make_pair(INT_MAX, 0) : q2.front();
	pair<int, int> p3 = q3.empty() ? make_pair(INT_MAX, 0) : q3.front();
	pair<int, int> p4 = min(p1, min(p2, p3));
	if (p1 == p4) q1.pop_front();
	else if (p2 == p4) q2.pop_front();
	else q3.pop_front();
	return p4;
}

int solve() {
	q1.clear(), q2.clear(), q3.clear();
	for (int i = 1; i <= n; i++) {
		q1.push_back(make_pair(a[i], i)), c[i] = 0;
	}
	while (q1.size() + q2.size() + q3.size() >= 2) {
		int sz = q1.size() + q2.size() + q3.size();
		pair<int, int> mx = get_max(), mn = get_min();
		b[sz] = mx.second;
		c[mn.second] = sz;
		if (sz & 1) q2.push_front(make_pair(mx.first - mn.first, mx.second));
		else q3.push_front(make_pair(mx.first - mn.first, mx.second));
	}
