using namespace std;

const int K = 12;
const int N = 567890;
const int mod = 1e9 + 7;

void add(int& x, int y) {
  x += y;
  if (x >= mod) {
    x -= mod;
  }
}

void sub(int& x, int y) {
  x -= y;
  if (x < 0) {
    x += mod;
  }
}

int mul(int x, int y) {
  return (long long)x * y % mod;
}

int power(int x, int y) {
  int result = 1;
  while (y) {
    if (y & 1) {
      result = mul(result, x);
    }
    x = mul(x, x);
    y >>= 1;
  }
  return result;
}

struct info_t {
  int l, r, p;

  info_t() {
    l = r = p = 0;
  }

  info_t(int l, int r, int p): l(l), r(r), p(p) {
  }

  int length() {
    return r - l;
  }

  void modify() {
    l = min(l, p);
    r = max(r, p);
  }

  info_t operator + (const info_t& a) {
    return info_t(min(l, p + a.l), max(r, p + a.r), p + a.p);
  }
} pre[K][N];

int n, k, w[K], coef[K][N], value[K], inv[K], invfac[K];

int calc(int x) {
  int result = 0;
  for (int i = 1; i <= n; ++i) {
    int foo = 1;
    for (int j = 1; j <= k; ++j) {
      int bar = w[j];
      sub(bar, coef[j][i]);
      sub(bar, mul(coef[j][n], x));
      foo = mul(foo, bar);
    }
    add(result, foo);
  }
  return result;
}

int lagrange(int x) {
  vector<int> pre(k + 3), suf(k + 3);
  pre[0] = suf[k + 2] = 1;
  for (int i = 1; i <= k + 1; ++i) {
    pre[i] = mul(pre[i - 1], x - i + mod);
  }
  for (int i = k + 1; i; --i) {
    suf[i] = mul(suf[i + 1], x - i + mod);
  }
  int result = 0;
  for (int i = 1; i <= k + 1; ++i) {
    int den = mul(invfac[i - 1], invfac[k + 1 - i]);
    if (k + 1 - i & 1) {
      den = mul(den, mod - 1);
    }
    add(result, mul(mul(value[i], den), mul(pre[i - 1], suf[i + 1])));
  }
  return result;
}

