      if (j == x) {
        pre[j][i].p += y;
        pre[j][i].modify();
        if (pre[j][i].length() != pre[j][i - 1].length()) {
          foobar = mul(foobar, power(w[j], mod - 2));
          foobar = mul(foobar, w[j] - 1);
          if (--w[j] == 0) {
