      ++infty;
    }
  }
  if (infty == k) {
    cout << -1 << '\n';
    return 0;
  }
  for (int i = 1; i <= n; ++i) {
    for (int j = 1; j <= k; ++j) {
      coef[j][i] = coef[j][i - 1];
      if ((pre[j][n] + pre[j][i]).length() != (pre[j][n] + pre[j][i - 1]).length()) {
        ++coef[j][i];
      }
    }
  }
  for (int i = 1; i <= k + 1; ++i) {
    value[i] = calc(i);
  }
  int need = w[1];
  for (int i = 1; i <= k; ++i) {
    if (coef[i][n]) {
      need = min(need, w[i] / coef[i][n]);
    }
  }
  for (int i = 1; i <= k; ++i) {
    w[i] -= need * coef[i][n];
  }
  for (int i = 0; i < need; ++i) {
    add(answer, lagrange(i));
  }
  foobar = 1;
  for (int i = 1; i <= k; ++i) {
    foobar = mul(foobar, w[i]);
