		return ans;
	}
	int t = lnk[r];
	if (s[t - 1] == '<') return op_min(solve(l, t - 2), solve(t, r));
	if (s[t - 1] == '>') return op_max(solve(l, t - 2), solve(t, r));
	return op_unknown(solve(l, t - 2), solve(t, r));
}

