	return a[0]+((b[0]-a[0])%(b[1]-a[0]))/((a[1]-a[0])%(b[1]-b[0]))*(a[1]-a[0]);
}
inline bool isCross(Line a,Line b){
	Point t=Cross(a,b);
	if(t.x>=min(a[0].x,a[1].x)&&t.x<=max(a[0].x,a[1].x)&&t.x>=min(b[0].x,b[1].x)&&t.x<=max(b[0].x,b[1].x))return true;
	return false;
}
inline bool check(int x,int m){
	for(int i=1;i<m;++i){
		if(x-1==i||x==i)continue;
		if((i+1!=x-1&&isCross(Line(a[p[i]],a[p[i+1]]),Line(a[p[x-1]],a[p[x]])))||(i!=x+1&&isCross(Line(a[p[i]],a[p[i+1]]),Line(a[p[x]],a[p[x+1]])))){
			return false;
		}
	}
	return true;
}
void Solve(){
