using namespace std;
typedef long long ll;
typedef pair<int,int> pii;
const int MAXN = 5e2 + 5;

int sgn(ll x){ return x < 0? -1: x > 0? 1: 0;}

struct Vector
{
	ll x,y;
	Vector(void){}
	Vector(ll _x,ll _y): x(_x), y(_y) {}
	void readself(void){ scanf("%lld%lld",&x,&y);}
};
typedef Vector Point;

Vector operator + (const Vector &p,const Vector &q){ return Vector(p.x + q.x, p.y + q.y);}
Vector operator - (const Vector &p,const Vector &q){ return Vector(p.x - q.x, p.y - q.y);}
ll cross(const Vector &p,const Vector &q){ return p.x * q.y - p.y * q.x;}

struct Seg
{
	Point p,q;
	Seg(void){}
	Seg(const Point &_p,const Point &_q): p(_p), q(_q) {}
	bool twoside(const Seg &oth) const
	{
		int t1 = sgn(cross(q - p, oth.p - p));
		int t2 = sgn(cross(q - p, oth.q - p));
		return t1 && t2 && t1 != t2;
	}
};

bool iscross(const Seg &a,const Seg &b)
{
	return a.twoside(b) && b.twoside(a);
}

Point pt[MAXN];
vector<int> ans;

bool insert(int k)
{
	for(int i=0; i+1<(int)ans.size(); ++i)
	{
		auto chk = [&] (const Seg &a)
		{
			for(int j=0; j+1<(int)ans.size(); ++j)
				if(j != i && iscross(a, Seg(pt[ans[j]], pt[ans[j+1]])))
					return false;
			return true;
		};
		
		if(chk(Seg(pt[ans[i]], pt[k])) && chk(Seg(pt[ans[i+1]], pt[k])))
		{
			ans.insert(ans.begin() + i + 1, k);
			return true;
		}
	}
	return false;
}

void solve(void)
{
	int n;
	scanf("%d",&n);
	for(int i=1; i<=n; ++i) pt[i].readself();
	
	vector<int> id(n-2);
	iota(id.begin(), id.end(), 2);
	while(1)
	{
		ans = {1,n};
		random_shuffle(id.begin(), id.end());
		
		bool ok = 1;
		for(int x: id)
			if(!insert(x))
			{
				ok = 0;
				break;
			}
		if(ok) break;
	}
	
	for(int x: ans) printf("%d ",x);
	printf("\n");
}

