#include<bits/stdc++.h>
using namespace std;
typedef long long ll;
const int maxn = 1e5 + 5;
int n;
int px[maxn], py[maxn];
typedef pair<int, int> pii;
#define fi first
#define sc second
#define mkp make_pair
int tmp[4][maxn]; int len = 0;
vector<pair<int, int>> adj[4][maxn];
int pf[maxn];
int id[4][maxn];
int ww[4][maxn];
int rk[4][maxn];
int dis[4][maxn];
const int inf = 0x3f3f3f3f;
int res[maxn];
int ans = 0;
priority_queue<pair<int, pii>, vector<pair<int, pii>>, greater<pair<int, pii>>> pq;
bool vis[4][maxn]; bool fl[maxn];
void upd(int fp, int fu, int ww){
	if(ww < dis[fp][fu]){
		dis[fp][fu] = ww; pq.push(mkp(ww, mkp(fp, fu)));
	}
	return ;
}
void updnd(int fu){
	int pos = 0; int tid = 0;
	if(pf[fu] == 0){
		tid = id[0][fu];
		pos = lower_bound(adj[0][tid].begin(), adj[0][tid].end(), mkp(max(1, py[fu] + 2 * res[fu]), -inf)) - 
		adj[0][tid].begin();
		if(pos < adj[0][tid].size()) upd(0, adj[0][tid][pos].sc, (py[adj[0][tid][pos].sc] - py[fu]) / 2);
		// 
		tid = id[1][fu];
		pos = lower_bound(adj[1][tid].begin(), adj[1][tid].end(), mkp(max(1 + (px[fu] - py[fu]) / 2, 
		px[fu] + res[fu]), -inf)) - adj[1][tid].begin();
		if(pos < adj[1][tid].size()) upd(1, adj[1][tid][pos].sc, px[adj[1][tid][pos].sc] - px[fu]);
		//
		tid = id[3][fu];
		pos = upper_bound(adj[3][tid].begin(), adj[3][tid].end(), mkp(min(-1 + (px[fu] + py[fu]) / 2, 
		px[fu] - res[fu]), inf)) - adj[3][tid].begin() - 1;
		if(pos >= 0) upd(3, adj[3][tid][pos].sc, px[fu] - px[adj[3][tid][pos].sc]);
	} else if(pf[fu] == 1){
		tid = id[2][fu];
		pos = lower_bound(adj[2][tid].begin(), adj[2][tid].end(), mkp(max(1, px[fu] + 2 * res[fu]), -inf)) - 
		adj[2][tid].begin();
		if(pos < adj[2][tid].size()) upd(2, adj[2][tid][pos].sc, (px[adj[2][tid][pos].sc] - px[fu]) / 2);
		// 
		tid = id[1][fu];
		pos = lower_bound(adj[1][tid].begin(), adj[1][tid].end(), mkp(max(1 + (px[fu] - py[fu]) / 2, 
		px[fu] + res[fu]), -inf)) - adj[1][tid].begin();
		if(pos < adj[1][tid].size()) upd(1, adj[1][tid][pos].sc, px[adj[1][tid][pos].sc] - px[fu]);
		// 
		tid = id[3][fu];
		pos = lower_bound(adj[3][tid].begin(), adj[3][tid].end(), mkp(max((px[fu] + py[fu]) / 2, 
		px[fu] + res[fu]), -inf)) - adj[3][tid].begin();
		if(pos < adj[3][tid].size()) upd(3, adj[3][tid][pos].sc, px[adj[3][tid][pos].sc] - px[fu]);
	} else if(pf[fu] == 2){
		tid = id[0][fu];
		pos = upper_bound(adj[0][tid].begin(), adj[0][tid].end(), mkp(min(0, py[fu] - 2 * res[fu]), inf)) - 
		adj[0][tid].begin() - 1;
		if(pos >= 0) upd(0, adj[0][tid][pos].sc, (py[fu] - py[adj[0][tid][pos].sc]) / 2);
		// 
		tid = id[1][fu];
		pos = upper_bound(adj[1][tid].begin(), adj[1][tid].end(), mkp(min((px[fu] - py[fu]) / 2, 
		px[fu] - res[fu]), inf)) - adj[1][tid].begin() - 1;
		if(pos >= 0) upd(1, adj[1][tid][pos].sc, px[fu] - px[adj[1][tid][pos].sc]);
		//
		tid = id[3][fu];
		pos = lower_bound(adj[3][tid].begin(), adj[3][tid].end(), mkp(max((px[fu] + py[fu]) / 2, 
		px[fu] + res[fu]), -inf)) - adj[3][tid].begin();
		if(pos < adj[3][tid].size()) upd(3, adj[3][tid][pos].sc, px[adj[3][tid][pos].sc] - px[fu]);
	} else if(pf[fu] == 3){
		tid = id[2][fu];
		pos = upper_bound(adj[2][tid].begin(), adj[2][tid].end(), mkp(min(-1, px[fu] - 2 * res[fu]), inf)) - 
		adj[2][tid].begin() - 1;
		if(pos >= 0) upd(2, adj[2][tid][pos].sc, (px[fu] - px[adj[2][tid][pos].sc]) / 2);
		//
		tid = id[1][fu];
		pos = upper_bound(adj[1][tid].begin(), adj[1][tid].end(), mkp(min((px[fu] - py[fu]) / 2, 
		px[fu] - res[fu]), inf)) - adj[1][tid].begin() - 1;
		// cerr << ": " << adj[1][tid][pos].sc << " " << dis[1][1] << endl;
		if(pos >= 0) upd(1, adj[1][tid][pos].sc, px[fu] - px[adj[1][tid][pos].sc]);
		//
		tid = id[3][fu];
		pos = upper_bound(adj[3][tid].begin(), adj[3][tid].end(), mkp(min(-1 + (px[fu] + py[fu]) / 2, 
		px[fu] - res[fu]), inf)) - adj[3][tid].begin() - 1;
		if(pos >= 0) upd(3, adj[3][tid][pos].sc, px[fu] - px[adj[3][tid][pos].sc]);
	}
	return ;
}
void solve(){
	for(int i = 1;i <= n;i++){
		int p0 = px[i] + py[i]; int p1 = py[i] - px[i];
		if(p0 > 0 && p1 > 0) pf[i] = 2;
		else if(p0 <= 0 && p1 > 0) pf[i] = 1;
		else if(p0 > 0 && p1 <= 0) pf[i] = 3;
		else if(p0 <= 0 && p1 <= 0) pf[i] = 0;
		tmp[0][i] = px[i]; tmp[1][i] = p1; tmp[2][i] = py[i]; tmp[3][i] = p0;
	}
	for(int i = 0;i < 4;i++){
		for(int j = 1;j <= n;j++) ww[i][j] = tmp[i][j];
		sort(tmp[i] + 1, tmp[i] + n + 1);
		len = unique(tmp[i] + 1, tmp[i] + n + 1) - tmp[i] - 1;
		for(int j = 1;j <= len;j++) adj[i][j].clear();
		for(int j = 1;j <= n;j++){
			int pid = lower_bound(tmp[i] + 1, tmp[i] + len + 1, ww[i][j]) - tmp[i];
			if(i == 0 && (pf[j] == 1 || pf[j] == 3)) continue;
			if(i == 2 && (pf[j] == 0 || pf[j] == 2)) continue;
			adj[i][pid].emplace_back((i == 0 ? py[j] : px[j]), j);
			id[i][j] = pid;
		}
		for(int j = 1;j <= len;j++){
			sort(adj[i][j].begin(), adj[i][j].end());
			for(int k = 0;k < adj[i][j].size();k++) rk[i][adj[i][j][k].sc] = k;
		}
	}
	memset(dis, 0x3f, sizeof(dis)); memset(vis, 0, sizeof(vis)); memset(fl, 0, sizeof(fl));
	memset(res, 0x3f, sizeof(res));
	pq.push(mkp(0, mkp(4, 1)));
	while(!pq.empty()){
		pii fr = pq.top().sc; pq.pop(); int fp = fr.fi; int fu = fr.sc;
		if(fu == 1 && fp == 4){
			res[fu] = 0; updnd(fu); continue;
		}
		if(vis[fp][fu]) continue;
		// cerr << fp << " " << fu << endl;
		vis[fp][fu] = 1;
		if(fp == 0){
			int tid = id[0][fu];
			if(pf[fu] == 2){
				if(rk[fp][fu] + 1 < adj[fp][tid].size()){
					int pw = adj[fp][tid][rk[fp][fu] + 1].sc;
					upd(fp, pw, dis[fp][fu] + (py[pw] - py[fu]) / 2);
				}
			} else if(pf[fu] == 0){
				if(rk[fp][fu] - 1 >= 0){
					int pw = adj[fp][tid][rk[fp][fu] - 1].sc;
					upd(fp, pw, dis[fp][fu] + (py[fu] - py[pw]) / 2);
				}
			}
		} else if(fp == 2){
			int tid = id[2][fu];
			if(pf[fu] == 3){
				if(rk[fp][fu] + 1 < adj[fp][tid].size()){
					int pw = adj[fp][tid][rk[fp][fu] + 1].sc;
					upd(fp, pw, dis[fp][fu] + (px[pw] - px[fu]) / 2);
				}
			} else if(pf[fu] == 1){
				if(rk[fp][fu] - 1 >= 0){
					int pw = adj[fp][tid][rk[fp][fu] - 1].sc;
					upd(fp, pw, dis[fp][fu] + (px[fu] - px[pw]) / 2);
				}
			}
		} else if(fp == 1 || fp == 3){
			int tid = id[fp][fu];
			if((fp == 1 && (pf[fu] == 2 || pf[fu] == 3)) || (fp == 3 && (pf[fu] == 0 || pf[fu] == 3))){
				if(rk[fp][fu] + 1 < adj[fp][tid].size()){
					int pw = adj[fp][tid][rk[fp][fu] + 1].sc;
					upd(fp, pw, dis[fp][fu] + (px[pw] - px[fu]));
				}
			} else {
				if(rk[fp][fu] - 1 >= 0){
					int pw = adj[fp][tid][rk[fp][fu] - 1].sc;
					upd(fp, pw, dis[fp][fu] + (px[fu] - px[pw]));
				}
			}
		}
		if(fl[fu]) continue;
		res[fu] = dis[fp][fu]; updnd(fu); fl[fu] = 1;
	}
	int cnt = 0;
	for(int i = 1;i <= n;i++){
		cnt += (res[i] < inf);
	}
	// cerr << "? " << cnt << endl;
	ans = max(ans, cnt); return ;
}
