int id_tot;
int new_node(){
	int id=++id_tot;
	seg[id].lson=seg[id].rson=seg[id].sum=0;
	return id;
}
int Root;
void push_up(int root){
	seg[root].sum=seg[seg[root].lson].sum+seg[seg[root].rson].sum;
}
void update(int x,int a,int &root=Root,int left=0,int right=Maxv){
	if(root==0){
		root=new_node();
	}
	seg[root].sum+=a;
	if(left==right){
		return;
	}
	int mid=(left+right)>>1;
	if(x<=mid){
		update(x,a,seg[root].lson,left,mid);
	}
	else{
		update(x,a,seg[root].rson,mid+1,right);
	}
	push_up(root);
}
int query(int l,int r,int root=Root,int left=0,int right=Maxv){
	if(root==0||l>right||r<left||seg[root].sum==0||l>r){
		return -1;
	}
	if(left==right){
		return left;
	}
	int mid=(left+right)>>1;
	int t=query(l,r,seg[root].rson,mid+1,right);
	if(t!=-1){
		return t;
	}
	return query(l,r,seg[root].lson,left,mid);
}
