void radix_sort(int *a, int n) {
  static int sum[256];
  static int t[N];
  const int low = (1 << 8) - 1;
  for (int round = 0; round <= 3; ++round) {
    memset(sum, 0, sizeof(sum));
    int sh = round * 8;
    for (int i = 1; i <= n; ++i) ++sum[(a[i] >> sh) & low];
    partial_sum(sum, sum + 256, sum);
    for (int i = n; i >= 1; --i) t[sum[(a[i] >> sh) & low]--] = a[i];
    memcpy(a + 1, t + 1, sizeof(int) * n);
  }
}

