int siz[N],vis[N],minn,rt,tot;
void getrt(int u,int f)
{
	siz[u]=1; int maxn=0;
	for(int i=fir[u];i!=0;i=edge[i].nxt)
	{
		int v=edge[i].v;
		if(vis[v]||v==f) continue;
		getrt(v,u),siz[u]+=siz[v];
		maxn=max(maxn,siz[v]);
	}
	maxn=max(maxn,tot-siz[u]);
	if(maxn<minn) minn=maxn,rt=u;
}
