	{
		int v=edge[i].v;
		if(vis[v]||v==f) continue;
		dfs(v,u,d),siz[u]+=siz[v];
	}
}
int las[N],to[N],fa[N],st[N][19];
void dfs1(int u,int f)
{
	int qaq=las[a[u]]; las[a[u]]=u;
	to[u]=las[1],fa[u]=las[a[u]+1];
	st[u][0]=fa[u];
	for(int i=1;i<19;i++) st[u][i]=st[st[u][i-1]][i-1];
	siz[u]=1;
	for(int i=fir[u];i!=0;i=edge[i].nxt)
	{
		int v=edge[i].v;
		if(v==f||vis[v]) continue;
		dfs1(v,u),siz[u]+=siz[v];
	}
	las[a[u]]=qaq;
}
vector<Query> qry[N];
vector<int> qid[N];
void clr(int u,int f)
{
	las[a[u]]=0;
	for(int i=fir[u];i!=0;i=edge[i].nxt)
	{
		int v=edge[i].v;
		if(!vis[v]&&v!=f) clr(v,u);
