void clr2(int u,int f)
{
	qid[u].clear();
	for(int i=fir[u];i!=0;i=edge[i].nxt)
	{
		int v=edge[i].v;
		if(!vis[v]&&v!=f) clr2(v,u);
	}
}
int chk(int u,int mid)
{
	if(!las[mid]) return inf;
	int tmp=las[mid],res=1;
	for(int i=18;i>=0;i--)
	{
		if(st[tmp][i]) res+=1<<i,tmp=st[tmp][i];
	}
	return mid-res;
}
void dfs2(int u,int f)
{
	int qaq=las[a[u]]; las[a[u]]=u;
	if(a[u]) fa[u]=las[a[u]-1];
	st[u][0]=fa[u];
	for(int i=1;i<19;i++) st[u][i]=st[st[u][i-1]][i-1];
	for(int i=0;i<(int)qid[u].size();i++)
	{
		int id=qid[u][i];
		int l=tmp[id]+1,r=c,as=tmp[id];
		while(l<=r)
		{
			int mid=(l+r)/2;
			if(chk(u,mid)<=tmp[id]) l=mid+1,as=mid;
			else r=mid-1;
		}
		ans[id]=as;
	}
	for(int i=fir[u];i!=0;i=edge[i].nxt)
	{
		int v=edge[i].v;
		if(v==f||vis[v]) continue;
		dfs2(v,u);
	}
	las[a[u]]=qaq;
}
