void getsiz(int u,int f)
{
	siz[u]=1;
	for(int i=fir[u];i!=0;i=edge[i].nxt)
	{
		int v=edge[i].v;
		if(vis[v]||v==f) continue;
		getsiz(v,u),siz[u]+=siz[v];
	}
}
void solve(int u,vector<Query> q)
{
	dep++;
//	printf("----- %d %d\n",u,dep);
//	for(int i=0;i<(int)q.size();i++) printf("%d%c",q[i].id," \n"[i==q.size()-1]);
//	cout<<"+++\n";
	cnt=0;
	for(int i=fir[u];i!=0;i=edge[i].nxt)
	{
		int v=edge[i].v;
		if(!vis[v]) dfs(v,u,v),nd[++cnt]=v;
	}
//	for(int i=1;i<=n;i++) printf("%d%c",id[i]," \n"[i==n]);
//	for(int i=1;i<=cnt;i++) printf("%d%c",nd[i]," \n"[i==cnt]);
	for(int i=1;i<=cnt;i++) qry[nd[i]].clear();
	dfs1(u,0);
	for(int i=0;i<(int)q.size();i++)
	{
		int u=q[i].u,v=q[i].v;
		if(id[u]==id[v]) qry[id[u]].pb(q[i]);
		else if(to[u])
		{
			int res=1,_tmp=to[u];
			for(int j=18;j>=0;j--)
			{
				if(st[_tmp][j]) res+=1<<j,_tmp=st[_tmp][j];
			}
			tmp[q[i].id]=res,qid[v].pb(q[i].id);
		}
		else tmp[q[i].id]=0,qid[v].pb(q[i].id);
	}
	for(int i=0;i<(int)qid[u].size();i++) ans[qid[u][i]]=tmp[qid[u][i]];
	clr(u,0);
	for(int i=1;i<=cnt;i++)
	{
		dfs2(nd[i],u);
		clr(nd[i],u);
	}
	vis[u]=1,clr2(u,0);
	getsiz(u,0);
	for(int i=fir[u];i!=0;i=edge[i].nxt)
	{
		int cur=edge[i].v; if(vis[cur]) continue;
		tot=siz[cur],minn=inf;
		getrt(cur,0);
		solve(rt,qry[cur]);
	}
	dep--;
}
