int tops;
int modi(int at, int le, int ri, int po, int da) {
	int re = ++tops;
	if(le == ri) {
		tree[re] . data = da;
	} else if(po <= (le + ri) >> 1) {
		tree[re] . left = modi(tree[at] . left, le, (le + ri) >> 1, po, da);
		tree[re] . righ = tree[at] . righ;
	} else {
		tree[re] . left = tree[at] . left;
		tree[re] . righ = modi(tree[at] . righ, ((le + ri) >> 1) + 1, ri, po, da);
	}
	return re;
}
int quer(int at, int le, int ri, int po) {
	if(!at) {
		return 0;
	} else if(le == ri) {
		return tree[at] . data;
	} else if(po <= (le + ri) >> 1) {
		return quer(tree[at] . left, le, (le + ri) >> 1, po);
	} else {
		return quer(tree[at] . righ, ((le + ri) >> 1) + 1, ri, po);
	}
}
void dfs1(int at, int fa) {
	size[at] = 1;
	fath[at] = fa;
	dept[at] = dept[fa] + 1;
	gep(i, at) {
		if(arri[i] != fa) {
			dfs1(arri[i], at);
			size[at] += size[arri[i]];
			if(size[hson[at]] < size[arri[i]]) {
				hson[at] = arri[i];
			}
		}
	}
}
void dfs2(int at, int fa) {
	ltot[ttol[at] = ++dfsn] = at;
	if(hson[at]) {
		htop[hson[at]] = htop[at];
		dfs2(hson[at], at);
	}
	gep(i, at) {
		if(arri[i] != fa && arri[i] != hson[at]) {
			htop[arri[i]] = arri[i];
			dfs2(arri[i], at);
		}
	}
}
