	return x;
}
int n,m,C,w[200005],pos[200005],tot,c[6000005][2],val[6000005],size[200005],ans[200005],used[200005];
int root[200005],cnt,h[200005],bel[200005];
struct E{
	int to,next;
}e[400005];
struct Query{
	int x,y,id;
};
void Add(int x,int y){
	e[++cnt]=(E){y,h[x]},h[x]=cnt;
}
void Clear(){
	//cerr<<tot<<'\n';
	for(int i=1;i<=tot;i++)c[i][0]=c[i][1]=val[i]=0;
	tot=0;
}
void Upd(int &p,int l,int r,int x,int y){
	int q=++tot;
	c[q][0]=c[p][0],c[q][1]=c[p][1],p=q;
	if(l==r)return val[p]=y,void();
	int mid=(l+r)/2;
	if(x<=mid)Upd(c[p][0],l,mid,x,y);
	else Upd(c[p][1],mid+1,r,x,y);
}
int Get(int p,int l,int r,int x){
	if(!p)return x;
	if(l==r)return val[p];
	int mid=(l+r)/2;
	if(x<=mid)return Get(c[p][0],l,mid,x);
	else return Get(c[p][1],mid+1,r,x);
}
void dfs1(int x,int fa){
	root[x]=root[fa];
	if(w[x])Upd(root[x],0,C,w[x]-1,Get(root[x],0,C,w[x]));
	for(int i=h[x];i;i=e[i].next){
		int y=e[i].to;
		if(!used[y]&&y!=fa)dfs1(y,x);
	}
}
void dfs2(int x,int fa){
	root[x]=root[fa];
	if(w[x])Upd(root[x],0,C,w[x],Get(root[x],0,C,w[x]-1));
	for(int i=h[x];i;i=e[i].next){
		int y=e[i].to;
		if(!used[y]&&y!=fa)dfs2(y,x);
	}
}
void dfsbel(int x,int fa,int b){
	bel[x]=b;
	for(int i=h[x];i;i=e[i].next){
		int y=e[i].to;
		if(!used[y]&&y!=fa)dfsbel(y,x,b);
	}
}
void Getsize(int x,int fa){
	size[x]=1;
	for(int i=h[x];i;i=e[i].next){
		int y=e[i].to;
		if(!used[y]&&y!=fa)Getsize(y,x),size[x]+=size[y];
	}
}
void Findcenter(int x,int fa,int all,int &mn,int &ct){
	int mx=all-size[x];
	for(int i=h[x];i;i=e[i].next){
		int y=e[i].to;
		if(!used[y]&&y!=fa)Findcenter(y,x,all,mn,ct),mx=max(mx,size[y]);
	}
	if(mx<mn)mn=mx,ct=x;
}
void Dianfenzhi(int cur,vector<Query> q){
	if(!q.size())return ;
	int mn=1e9,x=0;
	Getsize(cur,0),Findcenter(cur,0,size[cur],mn,x),used[x]=1,bel[x]=0;
	int cc=0;
	vector<vector<Query> > qq;
	for(int i=h[x];i;i=e[i].next){
		int y=e[i].to;
		if(!used[y])dfsbel(y,x,++cc);
	}
	qq.resize(cc+1),dfs1(x,0);
	for(int i=0;i<q.size();i++){
		if(bel[q[i].x]==bel[q[i].y]){
			qq[bel[q[i].x]].push_back(q[i]);
			continue;
		}
		ans[q[i].id]=Get(root[q[i].x],0,C,0);
	}
	Clear(),dfs2(x,0);
	for(int i=0;i<q.size();i++){
		if(bel[q[i].x]==bel[q[i].y])continue;
		int l=0,r=C,f=0;
		while(l<=r){
			int mid=(l+r)/2;
			if(Get(root[q[i].y],0,C,mid)<=ans[q[i].id])f=mid,l=mid+1;
			else r=mid-1;
		}
		ans[q[i].id]=f;
	}
	Clear();
	for(int i=h[x];i;i=e[i].next)if(!used[e[i].to])Dianfenzhi(e[i].to,qq[bel[e[i].to]]);
}
int main(){
	n=rd(),m=rd(),C=rd();
	for(int i=1,x;i<=C;i++)x=rd(),pos[x]=i;
	for(int i=1;i<=n;i++)w[i]=rd(),w[i]=pos[w[i]];
	for(int i=1,x,y;i<n;i++)x=rd(),y=rd(),Add(x,y),Add(y,x);
	int Q=rd();
	vector<Query> q;
	for(int i=1,x,y;i<=Q;i++)x=rd(),y=rd(),q.push_back((Query){x,y,i});
	Dianfenzhi(1,q);
