#include<bits/stdc++.h>
using namespace std;
const int N=3003;
bitset<N>c,d[N],ans[20005];
int n,m,head[N],cnt,q,dfn[N],low[N],idx,U[20005],V[20005];
int sta[N],top,bel[N],SCC;
bool vis[N];
struct edge{
	int to,nxt;
}e[N<<1];
vector<int>G[N];
void dfs(int u){
	c.set(u);
	for(int i=head[u];i;i=e[i].nxt)if(!c.test(e[i].to))
	dfs(e[i].to);
}
void dfs2(int u){
	low[u]=dfn[u]=++idx;
	vis[u]=1;
	sta[++top]=u;
	for(int i=head[u];i;i=e[i].nxt)if(!c.test(e[i].to)){
		if(!dfn[e[i].to]){
			dfs2(e[i].to);
				low[u]=min(low[u],low[e[i].to]);
		}else if(vis[e[i].to])low[u]=min(low[u],dfn[e[i].to]);
	}
	if(low[u]==dfn[u]){
		++SCC;
		int v;
		do{
			v=sta[top--];
			vis[v]=0;
			bel[v]=SCC;
		}while(v!=u);
	}
}
void DFS(int u){
	vis[u]=1;
	for(int i=0;i<(int)G[u].size();++i){
		int v=G[u][i];
		if(!vis[v])DFS(v);
		d[u]|=d[v];
	}
}
void qwq(){
	for(int i=1;i<=SCC;++i)if(!vis[i])DFS(i);
}
void work(int u){
	c.reset();
	c.set(u);
	dfs(1);
	memset(dfn,0,sizeof dfn);
	memset(low,0,sizeof low);
	memset(vis,0,sizeof vis);
	idx=top=SCC=0;
	for(int i=1;i<=n;++i)if(!c.test(i)&&!dfn[i])
	dfs2(i);
	for(int x=1;x<=n;++x)if(!c.test(x)){
		d[bel[x]].set(x);
		for(int i=head[x];i;i=e[i].nxt)if(bel[x]!=bel[e[i].to]&&!c.test(e[i].to))
		G[bel[x]].push_back(bel[e[i].to]);
	}
	qwq();
	for(int i=1;i<=q;++i){
		int x=U[i],y=V[i];
		if(c.test(x)&&!c.test(y)&&x!=u&&y!=u)ans[i]|=d[bel[y]];
	}
	for(int i=1;i<=SCC;++i)G[i].clear(),d[i].reset();
}
void doit(){
	for(int i=1;i<=m;++i){
		int u,v;
		cin>>u>>v;
		e[++cnt]=(edge){v,head[u]},head[u]=cnt;
	}
	for(int i=1;i<=q;++i)cin>>U[i]>>V[i];
	for(int i=2;i<=n;++i)work(i);
	for(int i=1;i<=q;++i)cout<<ans[i].count()<<'\n';
}
int main(){
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>m>>q;
	doit();
	return 0;
}

