__int128 A[maxn];

std::vector<int> solve(std::vector<int> &d,int sub){
	int n=d.size();
	if(n==1)return {1,1};
	now.reset();
	for(auto u:d)now[u]=1;
    auto p=std::minmax_element(d.begin(),d.end(),[&](int a,int b){
		return deg[a]<deg[b];
	});
	bool o=0;
	std::vector<int> L,R,fl,fr;
	int x=*(p.first),y=*(p.second);
	if(deg[x]-sub<=n-(deg[y]-sub))
		if(!(o=Find(x,1,d)))Find(y,0,d);
    if(Find(y,0,d));
	else o=Find(x,1,d);
	for(auto u:d)
		(vis[u]?L:R).push_back(u);
	fl=solve(L,sub+(o?0:R.size()));
	fr=solve(R,sub+(o?0:L.size()));
	if(o){
		if(fl.size()<fr.size())std::swap(fl,fr);
		for(int i=1;i<(int)fr.size();i++)
			if((fl[i]+=fr[i])>=mod)fl[i]-=mod;
		return fl;
	}
	for(int i=0;i<(int)fl.size();i++)
		for(int j=0;j<(int)fr.size();j++)
			A[i+j]+=1ull*fl[i]*fr[j];
	std::vector<int> f(fl.size()+fr.size()-1);
	for(int i=0;i<(int)f.size();i++)f[i]=A[i]%mod,A[i]=0;
	return f;
}

