		}
	}
	fac[0]=1;
	for(int i=1;i<=len;i++) fac[i]=1ll*fac[i-1]*i%mod;
	ifac[len]=ksm(fac[len],mod-2);
	for(int i=len;i;i--) ifac[i-1]=1ll*ifac[i]*i%mod;
	for(int i=1;i<=len;i++) invi[i]=1ll*ifac[i]*fac[i-1]%mod;
}
int sqr(int ta){ return 1ll*ta*ta%mod; }
