	inv2=inv2*2%mod;
	for(int i=0,tmp;2*i<k;i++){
		tmp=1ll*ifac[i]*ifac[k-1-i]%mod*inv2%mod;
		g[k-1-2*i]=i&1?-tmp:tmp;
	}
	for(int i=k+1;i>=2;i-=2) g[i]=(g[i]+g[i-2])%mod;
	for(int i=2;i<=k+2;i++) g[i]=(g[i]-2ll*(i+k)*f[i]-2ll*(i-k-2)*f[i-2])%mod;
	ll ts=0;
	for(int j=1,tmp;j<=k;j++){
		tmp=1ll*ifac[k-j]*ifac[j]%mod*invi[j]%mod;
		ts+=j&1?-tmp:tmp;
	}
	f[k]=ts%mod*inv2%mod*invi[2]%mod;
	for(int i=k-1;i>0;i--)
		f[i]=1ll*(g[i+2]-1ll*sqr(i+k+2)*f[i+2])%mod*sqr(invi[k-i])%mod;
	for(int i=k;i;i--) ans+=1ll*kp[i]*f[i]%mod*i%mod;
