int d[maxn];
int lb(int x) {
    return x & -x;
}
void ins(int pl, int h) {
    while (pl < maxn) {
        d[pl] += h;
        pl += lb(pl);
    }
}
int q(int pl) {
    int ans = 0;
    while (pl) {
        ans += d[pl];
        pl -= lb(pl);
    }
    return ans;
}
void ac(int l, int r, int tp) {
    ins(l, tp), ins(r + 1, -tp);
