  int nt = a[y][0] ^ a[y][1] ^ x;
  findpath(y, nt);
}
inline void dfs(int i, int x, int tp) {
  int y = *q[x].begin();
  l_ins(i, y), qwq[++top] = make_pair(i, x), del(y);
  int nt = a[y][0] ^ a[y][1] ^ x;
  if (nt == tp) return;
  dfs(y, nt, tp);
}
