        while (a) {
            int h = bsz(a); a ^= (uni << h); sm[h % T] += (uni << h);
        }
    }
    void dec(ll a) {
        while (a) {
            int h = bsz(a); a ^= (uni << h); sm[h % T] -= (uni << h);
        }
    }
