typedef __uint128_t u128;
inline u128 read() {
    static char buf[100];
    scanf("%s", buf);
    u128 res = 0;
    for(int i = 0; buf[i]; ++i) {
        res = res << 4 | (buf[i] <= '9' ? buf[i] - '0' : buf[i] - 'a' + 10);
    }
    return res;
}
inline void write(u128 res) {
    if(res >= 16) write(res / 16);
    putchar(res % 16 >= 10 ? 'a' + res % 16 - 10 : '0' + res % 16);
}
const int N = 3e5 + 5, B = 253, V = 1 << 7;
const u128 U = ~0;
int n, q, bel[N], S[N / B + 5], zero[N / B + 5], tag[N / B + 5];
u128 a[N], sum[N / B + 5], mask[N / B + 5], cnt[N / B + 5][V];
void down(int id) {
	if (zero[id] || mask[id] == U) return;
	for (int i = S[id]; i < S[id + 1]; i++) a[i] &= mask[id];
	mask[id] = U; tag[id] = 0;
}
void up(int id) {
	if (zero[id]) return;
	zero[id] = 1; mask[id] = U, tag[id] = sum[id] = 0;
	for (int i = S[id]; i < S[id + 1]; i++) {
		sum[id] += a[i];
		if (a[i]) zero[id] = 0;
	}
}
void calc(int id) {
	sum[id] = 0;
	for (int j = 0; j < V; j++) {
		cnt[id][j] = 0;
		if (mask[id] >> j & 1)
			for (int i = S[id]; i < S[id + 1]; i++)
				cnt[id][j] += a[i] & ((u128)1 << j);
		sum[id] += cnt[id][j];
	}
	tag[id] = 1;
}
u128 qry(int l, int r) {
	int bl = bel[l], br = bel[r];
	u128 ans = 0;
	if (bl == br) {
		if (!zero[bl]) for (int i = l; i <= r; i++) ans += a[i] & mask[bl];
	} else {
		if (!zero[bl]) for (int i = l; i < S[bl + 1]; i++) ans += a[i] & mask[bl];
		if (!zero[br]) for (int i = S[br]; i <= r; i++) ans += a[i] & mask[br];
		for (int i = bl + 1; i <= br - 1; i++) {
			if (zero[i]) continue;
			if (!tag[i] && mask[i] != U) calc(i);
			ans += sum[i];
		}
	}
	return ans;
}
void chg1(int l, int r, u128 v) {
	int bl = bel[l], br = bel[r];
	for (int i = bl; i <= br; i++) {
		if (zero[i]) continue;
		down(i);
		for (int j = max(l, S[i]), ed = min(r + 1, S[i + 1]); j < ed; j++) a[j] /= v;
		up(i);
	}
}
int getbit(u128 v) {
	unsigned long long x;
	if (x = v & 0xffffffffffffffff) return __builtin_ctzll(x);
	else if (x = v >> 64) return __builtin_ctzll(x) + 64;
	else return 0;
}
void chg2(int l, int r, u128 v) {
	int bl = bel[l], br = bel[r];
	if (bl == br) {
		if (mask[bl] & (~v)) {
			down(bl);
			for (int i = l; i <= r; i++) a[i] &= v;
			up(bl);
		}
	} else {
		if (mask[bl] & (~v)) {
			down(bl);
			for (int i = l; i < S[bl + 1]; i++) a[i] &= v;
			up(bl);
		}
		if (mask[br] & (~v)) {
			down(br);
			for (int i = S[br]; i <= r; i++) a[i] &= v;
			up(br);
		}
		for (int i = bl + 1; i <= br - 1; i++) {
			if (zero[i]) continue;
			if (tag[i])
				for (u128 x = mask[i] & (~v); x; x &= x - 1)
					sum[i] -= cnt[i][getbit(x)];
			mask[i] &= v;
		}
	}
}
int main() {
	scanf("%d%d", &n, &q);
	for (int i = 1; i <= n; i++) a[i] = read();
	for (int i = 1; i <= n; i++)
		bel[i] = (i + B - 1) / B;
	for (int i = 1; i <= bel[n]; i++)
		mask[i] = U, S[i] = (i - 1) * B + 1;
	S[bel[n] + 1] = n + 1;
	for (int i = 1; i <= bel[n]; i++) up(i);
	while (q--) {
		int op, l, r;
		scanf("%d%d%d", &op, &l, &r);
		if (op == 3) write(qry(l, r)), putchar('\n');
		else {
			u128 v = read();
			if (op == 1) {
				if (v != 1) chg1(l, r, v);
			}
			else chg2(l, r, v);
		}
	}
	return 0;
}

