void build(int k=1,int l=1,int r=n){
	if (r-l+1<=B){
		for (int i=l;i<=r;++i)	
			o[k]|=a[i],s[k]+=a[i];
		return;
	}
	int md=l+r>>1;
	build(k<<1,l,md);
	build(k<<1|1,md+1,r);
	s[k]=s[k<<1]+s[k<<1|1];
	o[k]=o[k<<1]|o[k<<1|1];
}
void mdf_div(int k=1,int l=1,int r=n){
