		return;
	}
	int md=l+r>>1;
	if (st<=md) mdf_div(k<<1,l,md);
	if (md<en) mdf_div(k<<1|1,md+1,r);
	s[k]=s[k<<1]+s[k<<1|1];
	o[k]=o[k<<1]|o[k<<1|1];
}
void mdf_and(int k=1,int l=1,int r=n){
	if ((o[k]|c)==c) return;
	if (r-l+1<=B){
		for (int i=max(l,st);i<=min(r,en);++i)
			a[i]&=c;
		o[k]=0,s[k]=0;
		for (int i=l;i<=r;++i)	
