	int md=l+r>>1;
	if (st<=md) mdf_and(k<<1,l,md);
	if (md<en) mdf_and(k<<1|1,md+1,r);
	s[k]=s[k<<1]+s[k<<1|1];
	o[k]=o[k<<1]|o[k<<1|1];
}
