void update(int p)
{
    ans(p)=ans(p << 1)+ans(p << 1 | 1);
    os(p)=os(p << 1) | os(p << 1 | 1);
}
void build(int p,int l,int r)
{
    if (r-l+1<=256)
    {
        for (int i=l;i<=r;++i)
            ans(p)+=a[i],os(p)|=a[i];
        return;
    }
    int mid(l+r >> 1);
    build(p << 1,l,mid);
    build(p << 1 | 1,mid+1,r);
    update(p);
}
void modify1(int p,int l,int r,int x,int y,u128 z)
{
    if (!os(p))
        return;
    if (r-l+1<=256)
    {
        ans(p)=os(p)=0;
        for (int i=x;i<=y;++i)
            a[i]/=z;
        for (int i=l;i<=r;++i)
            ans(p)+=a[i],os(p)|=a[i];
        return;
    }
    int mid(l+r >> 1);
    if (y<=mid)
        modify1(p << 1,l,mid,x,y,z); else
    if (x>mid)
        modify1(p << 1 | 1,mid+1,r,x,y,z); else
        {
            modify1(p << 1,l,mid,x,mid,z);
            modify1(p << 1 | 1,mid+1,r,mid+1,y,z);
        }
    update(p);
}
void modify2(int p,int l,int r,int x,int y,u128 z)
{
    if ((os(p) & z)==os(p))
        return;
    if (r-l+1<=256)
    {
        ans(p)=os(p)=0;
        for (int i=x;i<=y;++i)
            a[i]&=z;
        for (int i=l;i<=r;++i)
            ans(p)+=a[i],os(p)|=a[i];
        return;
    }
    int mid(l+r >> 1);
    if (y<=mid)
        modify2(p << 1,l,mid,x,y,z); else
    if (x>mid)
        modify2(p << 1 | 1,mid+1,r,x,y,z); else
        {
            modify2(p << 1,l,mid,x,mid,z);
            modify2(p << 1 | 1,mid+1,r,mid+1,y,z);
        }
    update(p);
}
u128 calc(int p,int l,int r,int x,int y)
{
    if (l==x && r==y)
        return ans(p);
    if (r-l+1<=256)
    {
        u128 g(0);
        for (int i=x;i<=y;++i)
            g+=a[i];
        return g;
    }
    int mid(l+r >> 1);
    if (y<=mid)
        return calc(p << 1,l,mid,x,y); else
    if (x>mid)
        return calc(p << 1 | 1,mid+1,r,x,y); else
        return calc(p << 1,l,mid,x,mid)+calc(p << 1 | 1,mid+1,r,mid+1,y);
}
