  int mid = (l + r) >> 1;
  pushdown(i, __lg(r - l + 1));
  if (x <= mid && e[i << 1]) _div(i << 1, l, mid, x, y, z);
  if (y > mid && e[i << 1 | 1]) _div(i << 1 | 1, mid + 1, r, x, y, z);
  update(i, __lg(r - l + 1));
