  int mid = (l + r) >> 1;
  pushdown(i, __lg(r - l + 1));
  if (y <= mid) return query(i << 1, l, mid, x, y);
  if (x > mid) return query(i << 1 | 1, mid + 1, r, x, y);
  return query(i << 1, l, mid, x, y) + query(i << 1 | 1, mid + 1, r, x, y);
