      for (int i = l, li = L * B; i < li; ++i)
        a[i] &= val;
      for (int i = R * B; i < r; ++i)
        a[i] &= val;
      up(L - 1); up(R);
    }
    else {
      u128 res = reduce(sum + L, sum + R) + reduce(a + l, a + L * B) + reduce(a + R * B, a + r);
      hex_write(res), putc('\n');
    }
  }
  return 0;
}

