	il void PushUp(int id,int ls,int rs){
		int S=ans[rs].size();lll op=0,tmp,A,B;
		for(int i=0;i<S;i++)A=ans[ls][i],B=ans[rs][i],tmp=A^B,ans[id][i]=tmp^op,op=(op&tmp)|(A&B);
		ans[id][S]=op,opt[id]=opt[ls]|opt[rs];
