	il void Build(int id=1,int l=1,int r=n){
		tag[id]=-1,ans[id].resize(__lg(r-l+1)+1);
		if(l==r)return opt[id]=(bool)(ans[id][0]=a[l]),void();
		int mid=(l+r)>>1,ls=id<<1,rs=id<<1|1;
		Build(ls,l,mid),Build(rs,mid+1,r),PushUp(id,ls,rs);
	}
	il void PushTag(int id,lll v){tag[id]&=v;for(int i=0,S=ans[id].size();i<S;i++)ans[id][i]&=v;}
	il void PushDown(int id,int ls,int rs){if(~tag[id])PushTag(ls,tag[id]),PushTag(rs,tag[id]),tag[id]=-1;}
	il void Div(int p,int q,lll v,int id=1,int l=1,int r=n){
		if(!opt[id])return ;
		if(l==r)return opt[id]=(bool)(ans[id][0]/=v),void();
		int mid=(l+r)>>1,ls=id<<1,rs=id<<1|1;PushDown(id,ls,rs);
		if(p<=mid)Div(p,q,v,ls,l,mid);
		if(q>mid)Div(p,q,v,rs,mid+1,r);
		PushUp(id,ls,rs);
	}
	il void Ddiv(int p,int q,lll v){if(v!=1)Div(p,q,v);}
	il void And(int p,int q,lll v,int id=1,int l=1,int r=n){
		if(!opt[id])return ;
		if(p<=l&&r<=q)return PushTag(id,v);
		int mid=(l+r)>>1,ls=id<<1,rs=id<<1|1;PushDown(id,ls,rs);
		if(p<=mid)And(p,q,v,ls,l,mid);
		if(q>mid)And(p,q,v,rs,mid+1,r);
		PushUp(id,ls,rs); 
	}
	il void Dand(int p,int q,lll v){if(v)And(p,q,v);}
	il lll Sum(int p,int q,int id=1,int l=1,int r=n){
		if(!opt[id])return 0;
		if(p<=l&&r<=q){
			lll sum=0;
			for(int i=ans[id].size()-1;i>=0;i--)sum=(sum<<1)+ans[id][i];
			return sum;
		}
		int mid=(l+r)>>1,ls=id<<1,rs=id<<1|1;PushDown(id,ls,rs);
		if(q<=mid)return Sum(p,q,ls,l,mid);
		if(p>mid)return Sum(p,q,rs,mid+1,r);
		return Sum(p,q,ls,l,mid)+Sum(p,q,rs,mid+1,r);
	}
}

