#define mid ((l + r) >> 1)
#define lson (p + 1)
#define rson (p + ((mid - l + 1) << 1))

using namespace std;
const int N = 1e5 + 10;
int T, n, m, pa[N], dep[N];
int dfn[N], rev[N], dfc = 0, top[N], son[N], sze[N];
int edge[N][2];
int sta[N], pos[N << 1], sum[N << 1];
vector<int> g[N];

void dfs1(int u, int fa) {
	pa[u] = fa;
	dep[u] = dep[fa] + 1;
	sze[u] = 1;
	son[u] = 0;
	for(int &v : g[u]) {
		if(v == fa) continue;
		dfs1(v, u);
		sze[u] += sze[v];
		if(sze[v] > sze[son[u]]) {
			son[u] = v;
		}
	}
	return;
}

void dfs2(int u, int tp) {
	dfn[u] = ++dfc;
	rev[dfc] = u;
	top[u] = tp;
	if(son[u]) {
		dfs2(son[u], tp);
	}
	for(int &v : g[u]) {
		if(v == pa[u] || v == son[u]) continue;
		dfs2(v, v);
	}
	return;
}


int LCA(int u, int v) {
	for(; top[u] != top[v]; ) {
		if(dep[top[u]] < dep[top[v]]) swap(u, v);
		u = pa[top[u]];
	}
	if(dep[u] > dep[v]) swap(u, v);
	return u;
}

void upd(int p, int l, int r) {
	if(sta[pos[rson]]) pos[p] = pos[rson];
	else if(sta[pos[lson]]) pos[p] = pos[lson];
	else pos[p] = 0;
	sum[p] = sum[lson] + sum[rson];
	return;
}

void build(int p, int l, int r) {
	sum[p] = 0;
	pos[p] = r;
	if(l == r) return sta[l] = 1, void();
	build(lson, l, mid), build(rson, mid + 1, r);
}

void modify(int p, int l, int r, int x, int v, int s) {
	if(l == r) {
		sum[p] = v;
		sta[l] = s;
		if(s) {
			pos[p] = l;
		} else {
			pos[p] = 0;
		}
		return;
	}
	if(x <= mid) modify(lson, l, mid, x, v, s);
	else modify(rson, mid + 1, r, x, v, s);
	upd(p, l, r);
}

int query(int p, int l, int r, int L, int R) {
	if(L <= l && r <= R) {
		return pos[p];
	}
	int res = 0;
	if(R > mid && !res) res = query(rson, mid + 1, r, L, R);
	if(L <= mid && !res) res = query(lson, l, mid, L, R);
	return res;
}

int Ask(int p, int l, int r, int L, int R) {
	if(L <= l && r <= R) {
		return sum[p];
	}
	int res = 0;
	if(L <= mid) res += Ask(lson, l, mid, L, R);
	if(R > mid) res += Ask(rson, mid + 1, r, L, R);
	return res;
}

void clear(int f) {
	if(edge[f][0]) {
		modify(1, 1, n, dfn[edge[f][0]], 0, 1);
	}
	if(edge[f][1]) {
		modify(1, 1, n, dfn[edge[f][1]], 0, 1);
	}
	edge[f][0] = edge[f][1] = 0;
	return;
}

void Add(int f, int u) {
	if(edge[f][0] == 0) edge[f][0] = u, modify(1, 1, n, dfn[u], 1, 0);
	else {
		assert(edge[f][1] == 0);
		edge[f][1] = u, modify(1, 1, n, dfn[u], 1, 1), modify(1, 1, n, dfn[edge[f][0]], 1, 1);
	}
	return;
}

int change(int u, int anc) {
	for(; top[u] != top[anc];) {
		int pos = query(1, 1, n, dfn[top[u]], dfn[u]);
		if(!pos) u = pa[top[u]];
		else {
			int a = pa[rev[pos]];
			if(a == anc) return rev[pos];
			clear(a);
			Add(a, rev[pos]);
		}
	}
	while(1) {
		int pos = query(1, 1, n, dfn[anc] + 1, dfn[u]);
		if(!pos || pa[rev[pos]] == anc) {
			return rev[pos];
		}
		clear(pa[rev[pos]]);
		Add(pa[rev[pos]], rev[pos]);
	}
	assert(0);
}

void Change(int u, int v) {
	int lca = LCA(u, v);
	if(dep[u] > dep[v]) swap(u, v);
	if(u != lca) clear(u);
	if(v != lca) clear(v);
	clear(lca);
	if(u != lca) {
		int f = change(u, lca);
		Add(lca, f);
	}
	if(v != lca) {
		int f = change(v, lca);
		Add(lca, f);
	}
	int f = pa[lca];
	if(edge[f][0] == lca) swap(edge[f][0], edge[f][1]);
	if(edge[f][1] == lca) {
		int v = edge[f][0];
		clear(f);
		if(v) {
			Add(f, v);
		}
	}
	return;
} 

int Query(int u, int v) {
	int res = 0;
	for(; top[u] != top[v]; ) {
		if(dep[top[u]] < dep[top[v]]) swap(u, v);
		res += Ask(1, 1, n, dfn[top[u]], dfn[u]);
		u = pa[top[u]];
	}
	if(dep[u] < dep[v]) swap(u, v);
	res += Ask(1, 1, n, dfn[v] + 1, dfn[u]);
	return res;
}

void init(int n) {
	dfc = 0;
	for(int i = 0; i <= n; i++) {
		edge[i][0] = edge[i][1] = 0;
	}
	build(1, 1, n);
	for(int i = 1; i <= n; i++) {
		g[i].clear();
	}
	return;
}

void solve() {
	scanf("%d%d", &n, &m);
	init(n);
	for(int i = 1, u, v; i < n; i++) {
		scanf("%d%d", &u, &v);
		g[u].push_back(v), g[v].push_back(u);
	}
	dfs1(1, 0);
	dfs2(1, 1);
	for(int i = 1, opt, a, b; i <= m; i++) {
		scanf("%d%d%d", &opt, &a, &b);
		if(opt == 1) {
			Change(a, b);
		} else {
			printf("%d\n", Query(a, b));
		}
//		cout << Ask(1, 1, n, 1, n) << endl;
	}
	return;
}

