int merge(int u,int v)
{
	if(!u||!v)
		return u|v;
	if(u[pri]>v[pri])
	{
		pushdown(u);
		u[rs]=merge(u[rs],v);
		pushup(u);
		return u;
	}
	else
	{
		pushdown(v);
		v[ls]=merge(u,v[ls]);
		pushup(v);
		return v;
	}
}
void split(int rt,int k,int &x,int &y)
{
	if(!rt)
		x=y=0;
	else if(!k)
		x=0,y=rt;
	else if(k==rt[sz])
		x=rt,y=0;
	else if(k<=rt[ls][sz])
	{
		pushdown(y=rt);
		split(rt[ls],k,x,y[ls]);
		pushup(y);
	}
	else
	{
		pushdown(x=rt);
		split(rt[rs],k-rt[ls][sz]-1,x[rs],y);
		pushup(x);
	}
}
