inline bool wlef(int pos) {return (st[pos] == '(' || st[pos] == '?');}
inline bool wrig(int pos) {return (st[pos] == ')' || st[pos] == '?');}
inline bool wsta(int pos) {return (st[pos] == '*' || st[pos] == '?');}
inline void add(int &x, int y) {x += y; if (x >= mod) x -= mod;}
int f(int l, int r) {
    //if (l == 1 && r == 8) {
    //    cout << 1 << endl;
    //}
    if (l >= r) return 0; 
    if (dp[l][r] != -1) return dp[l][r];
    dp[l][r] = 0;

    // 1 : () (S) // 3 : (A) (AS) (SA)
    int tot, res = 0;
    if (lef[l] && rig[r]) { 
        bool all = true;
        for (int i = l + 1; i <= r - 1; i ++) {
            if (!sta[i]) {
                all = false;
                break;
            }
        }
        if (all && r - l - 1 <= k) {
            dp[l][r] = 1;
            s[l][r] = 1;
        }
        add(dp[l][r], f(l + 1, r - 1));
        tot = 0;
        for (int i = l + 1; i <= r - 3; i ++) {
            if (!sta[i]) break;
            tot ++;
            if (tot > k) break;
            res = f(i + 1, r - 1);
            add(dp[l][r], res);
            add(sa[l][r], res);
        }
        tot = 0;
        for (int i = r - 1; i >= l + 3; i --) {
            if (!sta[i]) break;
            tot ++;
            if (tot > k) break;
            res = f(l + 1, i - 1);
            add(dp[l][r], res);
            add(sa[l][r], res);
        }
    }
    
    

    // 2 : AB ASB
    int val = 0;
    for (int li = l + 1; li <= r - 2; li ++) {
        val = 0;
        if (lef[l] && rig[li] && f(l, li) > 0) {
            add(val, sa[l][li]);
            add(val, s[l][li]); add(val, f(l + 1, li - 1));
            add(dp[l][r], 1ll * val * f(li + 1, r) % mod);
        }
    }
    for (int i = r; i >= l; i --) {
        dp[i][r] = f(i, r);
    }
    tmp[r + 2] = tmp[r + 1] = 0;
    for (int i = r; i >= l; i --) {
        if (sta[i]) tmp[i] = tmp[i + 1] + 1;
        else tmp[i] = 0;
    }
    tnp[r + 2] = tnp[r + 1] = 0;
    for (int i = r; i >= l; i --) {
        tnp[i] = tnp[i + 1];
        add(tnp[i], f(i, r));
    }
    for (int li = l + 1; li <= r - 2; li ++) {
        val = 0;
        if (lef[l] && rig[li] && f(l, li) > 0) {
            add(val, sa[l][li]);
            add(val, s[l][li]); add(val, f(l + 1, li - 1));
        }
        if (f(l, li) > 0) {
/*            tot = 0;
            for (int j = li + 1; j <= r - 2; j ++) {
                if (!sta(j)) break;
                tot ++;
                if (tot > k) break;
                add(gb, 1ll * val * f(j + 1, r) % mod);
            }
*/
            int lim = li + ((tmp[li + 1] > k) ? k : tmp[li + 1]);
            res = tnp[li + 1 + 1] - tnp[lim + 1 + 1];
            if (res < 0) res += mod;
            add(dp[l][r], 1ll * val * res % mod);
        }
    }
    return dp[l][r];
}
