		for(int i=1;i<=c;++i)dis[i]=inf,vis[i]=0;
		dis[x]=0;
		pq.push({dis[x],x});
		while(!pq.empty()){
			int x=pq.top().y;
			pq.pop();
			if(vis[x])continue;
			vis[x]=1;
			for(auto i:to[x])if(chkmin(dis[i.x],dis[x]+i.y))pq.push({dis[i.x],i.x});
		}
	}
