		for(int i=1;i<=t;++i)v[i+t]=v[i+t+t]=v[i];
		v[0]=v[t];
		for(int i=t+t;i;--i){
			f[i][i]=0;
			g[i]=0;
			for(int j=i+1;j<=t+t;++j){
				if((j^i)&1){
					g[j]=inf;
					for(int k=j;k>i;k-=2){
						chkmin(g[j],g[k-2]+f[k][j]+d[v[k]][v[j+1]]);
					}
				}
				else f[i][j]=g[j-1];
			}
		}
		int ans=inf;
		for(int i=1;i<=t;++i){
			for(int j=i;j<=t;j+=2){
				chkmin(ans,d[v[i]][v[j+1]]+f[i][j]+f[j+1][i+t-1]);
			}
		}
		printf("%d\n",ans);
	}
