inline int dfs(int x,int y){
	if(x==T)return y;
	int dlt=0,mn=tot+1;
	for(int i=head[x];i;i=e[i].next){
		int w=e[i].w,v=e[i].to;
		if(w&&dis[x]==dis[v]+1){
			int tt=dfs(v,min(w,y));
			y-=tt,dlt+=tt,e[i].w-=tt,e[i^1].w+=tt;
			if(e[i].w)mn=min(mn,dis[v]+1);
			if(!y||dis[S]>tot){
				if(!y){
					i=e[i].next;
					while(i){
						if(e[i].w)mn=min(mn,dis[e[i].to]+1);
						i=e[i].next;
					}
					if(mn^dis[x]){
						if(!(--gap[dis[x]]))dis[S]=tot+1;
						++gap[dis[x]=mn];
					}
				}
				return dlt;	
			}
		}
		else if(w)mn=min(mn,dis[v]+1);
	}
	int v,w;
	if(w1[x]&&dis[x+m]+1==dis[x]){
		v=x+m,w=w1[x];
		int tt=dfs(v,min(w,y));
		w1[x]-=tt,w3[x+m]+=tt,y-=tt,dlt+=tt;
		if(w1[x])mn=min(mn,dis[v]+1);
		if(!y||dis[S]>tot)return dlt;
	}
	else if(w1[x])mn=min(mn,dis[x+m]+1);
	if(w2[x]&&dis[x+1]+1==dis[x]){
		v=x+1,w=w2[x];
		int tt=dfs(v,min(w,y));
		w2[x]-=tt,w4[x+1]+=tt,y-=tt,dlt+=tt;
		if(w2[x])mn=min(mn,dis[v]+1);
		if(!y||dis[S]>tot)return dlt;
	}
	else if(w2[x])mn=min(mn,dis[x+1]+1);
	if(w3[x]&&dis[x-m]+1==dis[x]){
		v=x-m,w=w3[x];
		int tt=dfs(v,min(w,y));
		w3[x]-=tt,w1[x-m]+=tt,y-=tt,dlt+=tt;
		if(w3[x])mn=min(mn,dis[v]+1);
		if(!y||dis[S]>tot)return dlt;
	}
	else if(w3[x])mn=min(mn,dis[x-m]+1);
	if(w4[x]&&dis[x-1]+1==dis[x]){
		v=x-1,w=w4[x];
		int tt=dfs(v,min(w,y));
		w4[x]-=tt,w2[x-1]+=tt,y-=tt,dlt+=tt;
		if(w4[x])mn=min(mn,dis[v]+1);
		if(!y||dis[S]>tot)return dlt;
	}
	else if(w4[x])mn=min(mn,dis[x-1]+1);
	if(!(--gap[dis[x]]))dis[S]=tot+1;
	++gap[dis[x]=mn];
	return dlt;
}
