bool pd(int x)
{
    while(x)
    {
        if(x % 10 == 7) return 1;
        x /= 10;
    }
    return 0;
}
void init(int mx)
{
    int wq = 0;
    for(int i = 1; i <= mx + 70; i++)
    {
        if(pd(i)) used[i] = 1;
        if(used[i] && !qwq[i]) for(int j = 2; i * j <= mx + 70; j++)
        {
            //if(used[i * j]) break;
            used[i * j] = 1;
            qwq[i * j] = 1;
            //if(i % prim[j] == 0) break;
        }
        if(i > mx && !used[i])
        {
            wq = i;
            break;
        }
    }
    for(int i = wq + 1; i >= 1; i--)
    {
        if(used[i + 1]) ans[i] = ans[i + 1];
        else ans[i] = i + 1;
    }
    //for(int i = 1; i <= 11000000; i++) if(!used[i]) cout << i << ", ";
}
