inline bool check(int x) {
	while(x) {
		if(x % 10 == 7) return 1;
		x /= 10;
	}
	return 0;
}
inline void solve() {
	for(int i = 1; i < M; i ++) {
		if(tag[i]) continue;
		if(i % 7 == 0 || check(i)) {
			tag[i] = 1;
			for(int j = 1; ; j ++) {
				if(i * j < M)tag[i * j] = 1;
				if(i * j > mx) break;
			}
		}
		if(!tag[i] && i > mx) break;
	}
}
inline void read(int &x) {
	x = 0;
	char s= getchar();
	while(s < '0' || s > '9') s = getchar();
	while(s <= '9' && s >= '0') x = x * 10 + s - '0', s = getchar();
}
inline void write(int x) {
	if(x < 0) x = -x, putchar('-');
	if(x > 9) write(x / 10), x %= 10;
	putchar(x + '0');
}
