template<int MOD>
struct Modint {
	typedef long long LL;
	int val;
	Modint() { val = 0; }
	Modint(int x) { val = x % MOD; Adjust(); }
	inline Modint Pow(LL b) {
		Modint a = *this, ret = 1;
		for (; b != 0; b >>= 1, a *= a)
			if (b & 1)
				ret *= a;
		return ret;
	}
	// inline friend Modint operator+(Modint u, Modint v) { int ret = u.val + v.val; return ret >= MOD ? ret - MOD : ret; }
	inline friend Modint operator+(Modint u, Modint v) { return Modint(u.val + v.val - MOD).Adjust(); }
	// inline friend Modint operator-(Modint u, Modint v) { int ret = u.val - v.val; return ret < 0 ? ret + MOD : ret; }
	inline friend Modint operator-(Modint u, Modint v) { return Modint(u.val - v.val).Adjust(); }
	inline friend Modint operator*(Modint u, Modint v) { return (int) (((LL) u.val * v.val) % MOD); }
	inline friend Modint operator/(Modint u, Modint v) { return u * v.Pow(MOD - 2); }
	inline friend Modint &operator+=(Modint &u, Modint v) { return u = u + v; }
	inline friend Modint &operator-=(Modint &u, Modint v) { return u = u - v; }
	inline friend Modint &operator*=(Modint &u, Modint v) { return u = u * v; }
	inline friend Modint &operator/=(Modint &u, Modint v) { return u = u / v; }
	inline friend Modint operator-(Modint u) { return MOD - u; }
	inline friend bool operator==(const Modint &u, const Modint &v) { return u.val == v.val; }
	// inline Modint &Adjust() { if (val < 0) val += MOD; return *this; }
	inline Modint &Adjust() { val = val + ((val >> 31) & MOD); return *this; }
};
typedef Modint<998244353> Int;

int n, m, K;
