inline Int C(int n, int m) {
	static bool init = false;
	static Int fct[MAXM], fnv[MAXM];
	if (!init) {
		init = true;
		fct[0] = 1;
		for (int i = 1; i < MAXM; ++i)
			fct[i] = fct[i - 1] * i;
		fnv[MAXM - 1] = 1 / fct[MAXM - 1];
		for (int i = MAXM - 1; i > 0; --i)
			fnv[i - 1] = fnv[i] * i;
	}
	if (m < 0 || m > n)
		return 0;
	return fct[n] * fnv[m] * fnv[n - m];
}

int main() {
