		f[0][i][i & 1][i >> 1] = v[0].Pow(i);
	for (int i = 1; i <= m; ++i) {  // i - 1 => i
		for (int j = 0; j <= n; ++j) {
			for (int k = 0; k <= K; ++k) {
				for (int l = 0; l <= n; ++l) {
					for (int x = 0; j + x <= n; ++x) {
						f[i][j + x][k + (l + x) % 2][(l + x) / 2] += f[i - 1][j][k][l] * C(j + x, x) * v[i].Pow(x);
					}
				}
			}
		}
	}
	Int ans = 0;
	for (int k = 0; k <= K; ++k) {
		for (int l = 0; l <= n; ++l) {
			if (k + __builtin_popcount(l) <= K) {
				ans += f[m][n][k][l];
			}
		}
	}
	printf("%d\n", ans.val);
	return 0;
}

