struct node{
	int x,sl,sr;
	long long ave,SS;
	long long pred;
	bool operator <(const node &a)const{
		return pred>a.pred;
	}
};
priority_queue<node> Q;
long long Pred(int x,int sl,int sr,long long ave,long long SS){
	for (int i=x;i<=*q;i++)
		for (int j=1;j<=S[q[i]];j++){
			if (ave<0){
				sl+=q[i]; ave+=sl; SS+=sl*sl;
			}
			else{
				sr+=q[i]; ave-=sr; SS+=sr*sr;
			}
		}
	return SS*n-ave*ave;
}
int main(){
	ans=1ll<<60;
	scanf("%d",&n);
	for (int i=1;i<=n;i++)
		scanf("%d",&a[i]);
	for (int i=2;i<=n;i++)
		++S[a[i]-a[i-1]];
	for (int i=1;i<=a[n];i++)
		if (S[i]) q[++*q]=i;
	Q.push((node){1,0,0,0,0,Pred(1,0,0,0,0)});
	while (!Q.empty()&&clock()<0.96*CLOCKS_PER_SEC){
		node x=Q.top(); Q.pop();
		ans=min(ans,x.pred);
		if (x.x==(*q)+1) continue;
		for (int i=0;i<=S[q[x.x]];i++){
			node nx=x;
			int pl=i,pr=S[q[x.x]]-i,sl=x.sl,sr=x.sr;
			nx.SS+=1ll*sl*sl*pl+1ll*sl*q[x.x]*pl*(pl+1)+1ll*q[x.x]*q[x.x]*pl*(pl+1)*(2*pl+1)/6;
			nx.SS+=1ll*sr*sr*pr+1ll*sr*q[x.x]*pr*(pr+1)+1ll*q[x.x]*q[x.x]*pr*(pr+1)*(2*pr+1)/6;
			nx.ave+=1ll*sl*pl+1ll*q[x.x]*pl*(pl+1)/2;
			nx.ave-=1ll*sr*pr+1ll*q[x.x]*pr*(pr+1)/2;
			nx.sl+=q[x.x]*pl;
			nx.sr+=q[x.x]*pr;
			++nx.x;
			nx.pred=Pred(nx.x,nx.sl,nx.sr,nx.ave,nx.SS);
			Q.push(nx); 
		}
	} 
	cout<<ans<<endl;
}

