  std::vector<int> a(n), b(n - 1);
  for (int i = 0; i < n; i++) std::cin >> a[i];
  for (int i = 1; i < n; i++) b[i - 1] = a[i] - a[i - 1];
  std::sort(b.rbegin(), b.rend());
  while (b.size() && b.back() == 0) b.pop_back();

  if (b.empty()) {
    std::cout << "0\n";
    return 0;
  }
  
  int m = b.size();
  std::vector<int> c(m);
  auto cal = [&] {
    LL x = 0, y = a.back() - a[0], s1 = 0, s2 = 0;
    for (int i = 0; i < m; i++) {
      if (c[i]) {
        s1 += x += b[i];
        s2 += x * x;
      } else {
        s1 += y, s2 += y * y;
        y -= b[i];
      }
    }
    s1 += x * (n - 1 - m);
    s2 += x * x * (n - 1 - m);
    return n * s2 - s1 * s1;
  };
  

  
  LL ans = 1e18;
  while ((double)clock() / CLOCKS_PER_SEC < 0.98) {
    for (int i = 0; i < m; i++) {
      c[i] = rng() & 1;
    }
    LL now = cal();
    ans = std::min(ans, now);
    double t = 1e9, coef = 0.99;
    while (t > 0.1) {
      int i = rng() % m;
      c[i] ^= 1;
      LL x = cal();
      if (exp((now - x) / t) > randDouble()) {
        now = x;
        ans = std::min(ans, x);
      } else {
        c[i] ^= 1;
      }
      t *= coef;
    }
  }
  
  std::cout << ans << "\n";
  return 0;
}

