#define insert_ asjdfhsjfgdfgs
void insert_(int &rt,int l,int r,int x,int z)
{
    if(rt==0) rt=++tot,sz[rt]=lc[rt]=rc[rt]=0;
    if(l==r) { sz[rt]=(z==1)?1:0; return; }
    int mid=(l+r)>>1;
