void merge(int &rt,int rt_,int l,int r)
{
    if(!rt || !rt_) { rt=rt|rt_; return; }
    if(l==r) { sz[rt]=/*1*/min(sz[rt]+sz[rt_],1); return; }
    int mid=(l+r)>>1;
    merge(lc[rt],lc[rt_],l,mid),merge(rc[rt],rc[rt_],mid+1,r);
    pushup(rt);
}
int query(int rt,int l,int r,int x,int y)
{
    if(!rt || x>y) return 0;
    if(x<=l && r<=y) return sz[rt];
    int mid=(l+r)>>1,res=0;
    if(x<=mid) res+=query(lc[rt],l,mid,x,y);
    if(mid<y) res+=query(rc[rt],mid+1,r,x,y);
    return res;
}
void merge_(int xa,int ya,int xb,int yb)
{
    int u=father(get_id(xa,ya)),v=father(get_id(xb,yb));
