const int N=8005;

bool bfsed[N];int carry[N];
bitset<N>adj[N];
vector<int>G[N];
int n,m,Q;

int dis[N][N];

void brute(int S){
    queue<int>q;
    rep(i,0,n-1)dis[S][i]=-1;
    q.push(S),dis[S][S]=0;
    while(!q.empty()){
        int u=q.front();q.pop();
        for(auto v:G[u]){
            if(!~dis[S][v]){
                dis[S][v]=dis[S][u]+1;
                q.push(v);
            }
        }
    }
}
void fast(int S){
    static bitset<N>alive;
    queue<int>q;
    alive.set();
    q.push(S),dis[S][S]=0,alive.reset(S);
    while(!q.empty()){
        int u=q.front();q.pop();
        bitset<N>go=adj[u]&alive;
        for(int i=go._Find_first();i!=N;i=go._Find_next(i)){
            alive.reset(i),dis[S][i]=dis[S][u]+1;
            q.push(i);
        }
    }
}
void bfs(int u){
    if(m<=1e6)brute(u);
    else fast(u);
}

