template <class T> void read(T &x) {
  char ch; x = 0;
  int f = 1;
  while (isspace(ch = getchar()));
  if (ch == '-') ch = getchar(), f = -1;
  do x = x * 10 + (ch - '0'); while(isdigit(ch = getchar()));
  x *= f;
}
template <class T, class ...A> void read(T &x, A&... args) { read(x); read(args...); }

const int N = 8005;

mt19937 rng(452346435);

int ans[N][N];
int adj[N][65], cnt[N];
bitset<N> G[N];
int deg[N], ord[N];
bitset<N> nvis, undet, upd;
int q[N], ql = 0, qr = 0;

void link(int u, int v) {
  G[u][v] = G[v][u] = true;
  if (cnt[u] <= 64) adj[u][cnt[u]++] = v;
  if (cnt[v] <= 64) adj[v][cnt[v]++] = u;
}

int main() {
#ifdef LOCAL
  freopen("input.txt", "r", stdin);
  freopen("output.txt", "w", stdout);
#endif
  int n, qc;
  read(n, qc);
  for (int i = 1; i < n; ++i) {
    static char s[N / 4 + 3];
    scanf("%s", s);
    for (int j = 0; s[j]; ++j) {
      int v = (s[j] >= 'A') ? 10 + s[j] - 'A' : s[j] - '0';
      for (int k = 0; k < 4; ++k) {
        int p = j * 4 + k;
        if (p < i && ((v >> k) & 1))
          link(i, p);
      }
    }
  }
  for (int i = 0; i < n; ++i)
    sort(adj[i], adj[i] + cnt[i]);
  iota(ord, ord + n, 0);
  shuffle(ord, ord + n, rng);
  for (int i = 0; i < n; ++i)
    deg[i] = G[i].count();
  sort(ord, ord + n, [](int x, int y) { return deg[x] > deg[y]; });

  undet.set();
  int _siz = 0;
  for (int i = 0; i < n; ++i) {
    int u = ord[i];
    if (!undet[u]) continue;
    ++_siz;
    nvis.set();

    int cnt = 1;
    nvis[u] = false;
    ql = 0; qr = 0;
    q[++qr] = u;
    ans[u][u] = 0;
    while (cnt < n) {
      int v = q[++ql];
      if (deg[v] >= 64) {
        upd = nvis & G[v];
        for (int w = upd._Find_first(); w != N; w = upd._Find_next(w)) {
          nvis[w] = false;
          ++cnt;
          q[++qr] = w;
          ans[u][w] = ans[u][v] + 1;
        }
      }
      else {
        for (int idx = 0, li = deg[v]; idx < li; ++idx) {
          int w = adj[v][idx];
          if (nvis[w]) {
            nvis[w] = false;
            ++cnt;
            q[++qr] = w;
            ans[u][w] = ans[u][v] + 1;
          }
        }
      }
    }

    undet[u] = false;
    upd = G[u] & undet;
    for (int j = upd._Find_first(); j != N; j = upd._Find_next(j)) {
      undet[j] = false;
      memcpy(ans[j], ans[u], sizeof(ans[0]));
    }
  }

  while (qc--) {
    int u, v;
    read(u, v);
    --u; --v;
    printf("%d\n", ans[u][v]);
  }
  return 0;
}

