					l[v].zt[j][1ull<<k]=l[v].b[j*T+k];
				for(int k=1;k<(1<<T);++k)if(k&(k-1)){
					int yw=k&-k;
					l[v].zt[j][k]=l[v].zt[j][k^yw]^l[v].zt[j][yw];
				}
			}
		}
	}
	wz[v+1]=n+1;
