#include<bits/stdc++.h>
using namespace std;
const int M=998244353;
const int N=100005,E=262144;
int R[N*4];
long long qpow(long long a,long long b)
{
	long long ans=1;
	while(b)
	{
		if(b&1)
			ans=ans*a%M;
		a=a*a%M;
		b>>=1;
	}
	return ans;
}
long long wn[N*4],iwn[N*4],ifac[N*4];
void init()
{
	int i;
	iwn[E/2]=wn[E/2]=1;
	long long s1=qpow(3,(M-1)/E);
	long long s2=qpow(s1,M-2);
	ifac[0]=ifac[1]=1;
	for(i=2;i<E;++i)
		ifac[i]=ifac[M%i]*(M-M/i)%M;
	for(i=1;i<E;++i)
		ifac[i]=ifac[i-1]*ifac[i]%M;
	for(i=E/2+1;i<E;++i)
	{
		wn[i]=wn[i-1]*s1%M;
		iwn[i]=iwn[i-1]*s2%M;
	}
	for(i=E/2-1;i;--i)
	{
		wn[i]=wn[i<<1];
		iwn[i]=iwn[i<<1];
	}
}
void NTT(long long *f,int lim,int op)
{
	int i,j,k;
	for(i=0;i<lim;++i)
	{
		R[i]=(R[i>>1]>>1)|(i&1?lim>>1:0);
		if(R[i]<i)
			swap(f[R[i]],f[i]);
	}
	for(i=1;i<lim;i<<=1)
		for(j=0;j<lim;j+=(i<<1))
			for(k=j;k<j+i;++k)
			{
				long long a=f[k],b=f[k+i];
				long long w=(op==1?wn[k-j+i]:iwn[k-j+i]);
				f[k]=(a+b*w)%M;
				f[k+i]=(a-b*w)%M;
			}
	if(op==-1)
	{
		long long inv=qpow(lim,M-2);
		for(i=0;i<lim;++i)
			f[i]=f[i]*inv%M;
	}
}
void mult(long long *a,int n,long long *b,int m)
{
    
	if(n+m<=300)
	{
		long long t[n+m-1];
		memset(t,0,sizeof(t));
		for(int i=0;i<n;++i)
		{
            int j;
            for(j=0;j+4<=m;j+=4)
			{
                t[i+j]=(t[i+j]+a[i]*b[j])%M;
                t[i+j+1]=(t[i+j+1]+a[i]*b[j+1])%M;
                t[i+j+2]=(t[i+j+2]+a[i]*b[j+2])%M;
                t[i+j+3]=(t[i+j+3]+a[i]*b[j+3])%M;
            }
            for(;j<m;++j)
                t[i+j]=(t[i+j]+a[i]*b[j])%M;
        }
		for(int i=0;i<n+m-1;++i)
			a[i]=t[i];
		return;
	}
	int lim=1;
	while(lim<n+m)
		lim<<=1;
	for(int i=n;i<lim;++i)
		a[i]=0;
	for(int i=m;i<lim;++i)
		b[i]=0;
	NTT(a,lim,1);
	NTT(b,lim,1);
	for(int i=0;i<lim;++i)
		a[i]=a[i]*b[i]%M;
	NTT(a,lim,-1);
}
long long tmp[N*4],tans[N*4];
void Getinv(long long *a,long long *ans,int lim)
{
	ans[0]=qpow(a[0],M-2);
	for(int i=1;i<lim;i<<=1)
	{
		for(int j=i;j<(i<<2);++j)
			ans[j]=tans[j]=tmp[j]=0;
		for(int j=0;j<(i<<1);++j)
			tmp[j]=a[j];
		for(int j=0;j<i;++j)
			tans[j]=ans[j];
		NTT(tmp,i<<2,1);
		NTT(tans,i<<2,1);
		for(int j=0;j<(i<<2);++j)
			tmp[j]=tmp[j]*tans[j]%M*tans[j]%M;
		NTT(tmp,i<<2,-1);
		for(int j=0;j<(i<<1);++j)
			ans[j]=(2*ans[j]-tmp[j])%M;
	}
}
long long tb[N*4],tv[N*4],ta[N*4],inv[N*4];
void Getmod(long long *a,int n,long long *b,int m,long long *ans,long long *r)
{
	for(int i=0;i<n;++i)
		ans[i]=a[i];
	for(int i=0;i<m;++i)
		tb[i]=b[i];
	for(int i=m;i<n;++i)
		tb[i]=0;
	for(int i=0;i<n;++i)
		tv[i]=inv[i];
	reverse(ans,ans+n);
	mult(ans,n-m+2,tv,n);
	reverse(ans,ans+n-m+1);
	for(int i=0;i<=n-m;++i)
		ta[i]=ans[i];
	mult(ta,n-m+1,tb,m);
	for(int i=0;i<m-1;++i)
		r[i]=a[i]-ta[i];
}
long long C(int n,int m){
	if(n<0)
		return 0;
	long long s=1;
	for(int i=n;i>n-m;--i)
		s=s*i%M;
	return s*ifac[m]%M;
}
long long a[N*4],f[N*4],s[N*4],ans[N*4],g[N*4],newans[N*4],rub[N*4],fans;
int n,m,k,e;
int main()
{
	init();
	scanf("%d %d %d",&n,&m,&e);
	if(e==0){
		cout<<m;
		return 0;
	}
	if(n<=10000){
		int k=e;
		for(int i=1;i<=n;++i)
			f[i]=C(m-k*(i-1),i)*(i&1?-1:1)%M;
		f[0]=1;
		Getinv(f,g,n+1);
		long long ans=0;
		for(int i=1;i<=n;++i)
			ans=(ans-f[i]*i%M*g[n-i])%M;
		cout<<(ans%M+M)%M;
		return 0;
	}
	--n;
	int i;
	a[0]=1;
	for(i=1;i<=n&&(i-1)*e<=m;++i){
		a[i]=C(m-e*(i-1),i)*(i&1?-1:1)%M;
		f[i-1]=-a[i]*i%M;
	}
	int k=i;
	Getinv(a,inv,k+1);
	copy(inv,inv+k,rub);
	mult(f,k,rub,k);
	reverse(a,a+k+1);
	int y=n;
	ans[0]=1;
	s[1]=1;
	int lim=1;
	while(lim<2*k)
		lim<<=1;
	while(y)
	{
		if(y&1)
		{
			for(int i=0;i<k;++i)
				g[i]=s[i];
			mult(ans,k,g,k);
			Getmod(ans,2*k,a,k+1,rub,newans);
			for(int i=0;i<k;++i)
				ans[i]=newans[i];
		}
		for(int i=k;i<lim;++i)
			s[i]=0;
		NTT(s,lim,1);
		for(int i=0;i<lim;++i)
			s[i]=s[i]*s[i]%M;
		NTT(s,lim,-1);
		Getmod(s,2*k,a,k+1,rub,newans);
		for(int i=0;i<k;++i)
			s[i]=newans[i];
		y>>=1;
	}
	for(int i=0;i<k;++i)
		fans=(fans+ans[i]*f[i])%M;
	cout<<(fans%M+M)%M;
}

