struct fhq_treap
{
	struct node
	{
		long long ls,rs,rd,rk,data,sz,smz,delta;
		bool operator < (const node &t)const
		{
			if (rk!=t.rk) return rk<t.rk;
			return rd<t.rd;
		}
	};
	node tree[N+1];
	int length;
	int new_node(int x,int d)
	{
		tree[++length]=(node){0,0,rd[x],d,a[x],1,a[x],1};
		return length;
	}
	void push_up(int x)
	{
		tree[x].sz=tree[tree[x].ls].sz+tree[tree[x].rs].sz+1,tree[x].smz=tree[tree[x].ls].smz+tree[tree[x].rs].smz+tree[x].data,tree[x].delta=1;
		if (tree[tree[x].ls].smz>=tree[x].data) tree[x].delta+=tree[tree[x].ls].delta;
		if (tree[tree[x].rs].smz>=tree[x].data) tree[x].delta+=tree[tree[x].rs].delta;
		return;
	}
	void split(int k,int d,long long &x,long long &y)
	{
		if (!k)
		{
			x=y=0;
			return;
		}
		if (d<=tree[tree[k].ls].sz) split(tree[k].ls,d,x,tree[k].ls),y=k;
		else split(tree[k].rs,d-tree[tree[k].ls].sz-1,tree[k].rs,y),x=k;
		push_up(k);
		return;
	}
	int merge(int x,int y)
	{
		if (!x||!y) return x^y;
		if (tree[x]<tree[y])
		{
			tree[y].ls=merge(x,tree[y].ls),push_up(y);
			return y;
		}
		else
		{
			tree[x].rs=merge(tree[x].rs,y),push_up(x);
			return x;
		}
	}
};
