string work(string s) {
    if (on.count(s)) return s;
    string ans = "";
    for (int i = 0, j; i < sz(s); ) {
        if (!check(s[i])) {
            ans += s[i];
            i += 1;
            continue;
        }
        j = i;
        while (j + 1 < sz(s) && check(s[j + 1])) ++j;
