        if (on.count(tmp)) {
            ans += tmp;
            i = j + 1;
            continue;
        }
        on.insert(tmp);
        if (Map.count(tmp)) {
            ans += work(Map[tmp]);
        } else {
            ans += tmp;
        }
        on.erase(tmp);
        i = j + 1;
    }
    return ans;
}

