inline void Replace(const uint_fast8_t id)
{
	visit[id] = 1;
	for (const char* p_replace = replace[id]; *p_replace >= ' ';)
	{
		if (is_identifier[*p_replace])
		{
			const char* const identifier_start = p_replace;
			unsigned short p_trie = trie_root.child[mapping[*p_replace]];
			if (p_trie)
			{
				while (is_identifier[*(++p_replace)])
				{
					if ((p_trie = trie[p_trie].child[mapping[*p_replace]]) == 0)
					{
						goto Output;
					}
				}
				if (trie[p_trie].def_id == 0 || visit[trie[p_trie].def_id])
				{
					goto Output;
				}
				Replace(trie[p_trie].def_id);
			}
			else
			{
			Output:
				for (p_replace = identifier_start; is_identifier[*p_replace]; *(p_transfer++) = *(p_replace++));
			}
		}
		else
		{
			*(p_transfer++) = *(p_replace++);
		}
	}
	visit[id] = 0;
	return;
}
