				for (replace[trie[p_trie].def_id = (++siz_def)] = (++p_text); *p_text >= ' '; ++p_text);
			}
			else
			{
				p_text += 7;
				unsigned short p_trie = 1;
				for (; *p_text > ' '; p_trie = trie[p_trie].child[mapping[*(p_text++)]]);
