const int N=207,mod=1e9+7;
inline void inc(int &x,int y){
	x+=y-mod,x+=x>>31&mod;
}
inline void dec(int &x,int y){
	x-=y,x+=x>>31&mod;
}
inline int Sum(int l,int r){
	if(l>r)return 0;
	return (1ll*(l+r)*(r-l+1)>>1)%mod;
}
struct Edge{int to,nxt;}e[N<<1];
int s_e,head[N];
