int res1,res2,f[N],g[N];
int inv[N],ifac[N];
void dfs(int x,int fa,int L){
	int F=max(0,min(a[x].r,L+K)-max(L,a[x].l)+1);
	int G=Sum(max(L,a[x].l),min(a[x].r,L+K));
	inc(res1,F),inc(res2,G),f[x]=1,g[x]=0;
	for(int i=head[x];i;i=e[i].nxt){
		int y=e[i].to;
		if(y==fa)continue;
		dfs(y,x,L);
		inc(res1,1ll*f[x]*F%mod*f[y]%mod);
		inc(res2,(1ll*F*f[y]%mod*g[x]+1ll*f[x]*f[y]%mod*G+1ll*F*f[x]%mod*g[y])%mod);
		inc(f[x],f[y]),inc(g[x],g[y]);
	}
	g[x]=(1ll*f[x]*G+1ll*g[x]*F)%mod,f[x]=1ll*f[x]*F%mod;
}
struct qwq{
	int tot,x[N],y[N];
	int suf[N];
	inline void init(){tot=0;}
	inline void add(int X,int Y){++tot,x[tot]=X,y[tot]=Y;}
	inline int calc(int k){
		int ans=0;
		suf[tot+1]=1;
		for(int i=tot;i;i--)
			suf[i]=1ll*suf[i+1]*(k-x[i])%mod;
		int pre=1;
		for(int i=1;i<=tot;i++){
			int tmp=1ll*y[i]*pre%mod*suf[i+1]%mod*ifac[i-1]%mod*ifac[tot-i]%mod;
			if((tot-i)&1)tmp=mod-tmp;
			inc(ans,tmp),pre=1ll*pre*(k-x[i])%mod;
		}
		return ans;
	}
}t1,t2;
inline void work(int L,int o){
	vector<int>vec={L,m+1};
	auto ins=[&](int x){if(L<=x && x<=m)vec.push_back(x);};
	for(int i=1;i<=n;i++)ins(a[i].l),ins(a[i].r),ins(a[i].l-K),ins(a[i].r-K);
	sort(vec.begin(),vec.end());
	vec.erase(unique(vec.begin(),vec.end()),vec.end());
	int tmp1=0,tmp2=0;
	for(int i=0;i+1<(int)vec.size();i++){
		int l=vec[i],r=vec[i+1]-1;
		if(l+n+1>=r){
			res1=res2=0;
			for(int j=l;j<=r;j++)
				dfs(1,0,j);
			inc(tmp1,res1),inc(tmp2,res2);
		}else{
			t1.init(),t2.init(),res1=res2=0;
			for(int j=l;j<=l+n+1;j++)
				dfs(1,0,j),t1.add(j,res1),t2.add(j,res2);
			inc(tmp1,t1.calc(r)),inc(tmp2,t2.calc(r));
		}
	}
	if(o)inc(ans1,tmp1),inc(ans2,tmp2);
	else dec(ans1,tmp1),dec(ans2,tmp2);
}
