    void calc(vector <int> ans[]) {
        for (int i = 1; i <= n; i++) {
            for (auto j : son[i]) rson[j.first].push_back({i, j.second});
            for (auto j : endid[i]) rson[0].push_back({i, -j});
        }
        for (int i = 1; i <= n; i++) {
            assert(rson[i].size() <= son[i].size() + endid[i].size());
            while (rson[i].size() < son[i].size() + endid[i].size()) rson[i].push_back({0, 0});
        }
        dfs(0);
        for (int l = 2, r; l <= len; l = r + 2) {
            for (r = l; ansl[r] > 0; r++);
            vector <int> &to = ans[-ansl[r]];
            for (int i = l; i < r; i++) to.push_back(ansl[i]);
        }
    }
