void adde(int u,int v,int w){
    edg eu{v,w,(int)adj[v].size()},ev{u,0,(int)adj[u].size()};
    adj[u].push_back(eu);adj[v].push_back(ev);
}
int sz;
int dis[maxn*4],cur[maxn*4];

bool bfs(int s,int t){
    for(int i=1;i<=sz;i++)dis[i]=-1;
    for(int i=1;i<=sz;i++)cur[i]=0;
    static queue<int> q;
    while(!q.empty())q.pop();
    q.push(s);
    dis[s]=0;
    while(!q.empty()){
        int u=q.front();q.pop();
        for(auto&x:adj[u]){
            if(x.w&&dis[x.v]==-1){
                dis[x.v]=dis[u]+1;
                q.push(x.v);
                if(x.v==t)break;
            }
        }
    }
    return dis[t]!=-1;
}
int dfs(int u,int t,int lim){
    if(u==t||lim==0)return lim;
    int flow=0;
    for(int&i=cur[u];i<(int)adj[u].size();i++){
        auto&x=adj[u][i];
        if(x.w&&dis[x.v]==dis[u]+1){
            int cur=dfs(x.v,t,min(lim,x.w));
            adj[u][i].w-=cur;
            adj[x.v][x.b].w+=cur;
            lim-=cur;flow+=cur;
            if(!lim)break;
        }
    }
    if(lim)dis[u]=-1;
    return flow;
}
int dinic(int s,int t){
    int ans=0;
    while(bfs(s,t))ans+=dfs(s,t,INT_MAX);
    return ans;
}
