        if(c=="loushang"&&mp.count(b)){
            nxt[i]=mp[b];typ[i]=0;
        }else if(c=="louxia"&&mp.count(b)){
            nxt[i]=mp[b];typ[i]=1;
        }else{
            typ[i]=-1;
            ei[mp[a]]=i;
        }
    }
    int ans=0;
    multimap<pair<int,int>,int> mp1;
    for(int i=1;i<=n;i++){
        for(int j:f[i]){
            if(typ[j]==0){
                mp1.insert(make_pair(make_pair(i,nxt[j]),j));
            }
        }
    }
    for(int i=1;i<=n;i++){
        for(int j:f[i]){
            if(typ[j]==1){
                auto it=mp1.find(make_pair(nxt[j],i));
                if(it!=mp1.end()){
                    ans+=2;
                    vis[j][0]=1;
                    vis[it->second][1]=1;
                    pnxt[it->second]=j;//cerr<<it->second<<"->"<<j<<endl;
                    mp1.erase(it);
                }
            }
        }
    }
    for(int i=1;i<=m+n*2;i++)bdj[i].clear(),cdj[i].clear();
    for(int i=1;i<=sz;i++)adj[i].clear();
    for(int i=1;i<=n;i++){
        for(int j:f[i]){
            if(!vis[j][0])adde(m*2+i,m+j,1);
            if(!vis[j][1])adde(j,m*2+n+i,1);
        }
    }
    for(int i=1;i<=m;i++){
        if(!vis[i][1])adde(s,i,1);
        if(!vis[i][0])adde(i+m,t,1);
        if(typ[i]==0){
            if(!vis[i][1])adde(i,m*2+nxt[i],1);
        }else if(typ[i]==1){
            if(!vis[i][0])adde(m*2+n+nxt[i],m+i,1);
        }
    }
    ans+=dinic(s,t);
    for(int i=1;i<=n;i++){
        vector<int> cp;
        for(auto&e:adj[m*2+i])if(!e.w&&e.v>m&&e.v<=m*2)cp.push_back(e.v-m);
        if(find(cp.begin(),cp.end(),ei[i])==cp.end()&&!cp.empty())cp.pop_back(),cp.push_back(ei[i]);
        bdj[m+i]=cp;
        cp.clear();
        for(auto&e:adj[m*2+n+i])if(e.w&&e.v>0&&e.v<=m)cp.push_back(e.v);
        if(find(cp.begin(),cp.end(),ei[i])==cp.end()&&!cp.empty())cp.pop_back(),cp.push_back(ei[i]);
        for(int&x:cp)bdj[x].push_back(m+n+i);
    }
    for(int i=1;i<=m;i++){
        for(auto&e:adj[i])if(!e.w&&e.v>m*2&&e.v<=m*2+n)bdj[i].push_back(e.v-m);
        for(auto&e:adj[i+m])if(e.w&&e.v>m*2+n&&e.v<=m*2+n*2)bdj[e.v-m].push_back(i);
    }
    for(int i=1;i<=m+n*2;i++){
        for(auto&j:bdj[i])cdj[i].push_back(j),cdj[j].push_back(-i);
    }
    for(int i=1;i<=m+n*2;i++)bvis[i]=0;
    for(int i=1;i<=m;i++){
        if(!bvis[i]){
            rp.clear();
            efs(i);
            if(rp.size()==1)continue;
            vector<int> vp,vm;
            for(int u:rp){
                if(cdj[u].size()==1){
                    if(cdj[u][0]>0)vp.push_back(u);
                    else vm.push_back(u);
                }
            }
            assert(vm.size()==vp.size()&&vp.size()>=1);
            map<int,int> rmp;
            for(int i=0;i<(int)vp.size();i++){
                rmp[vp[i]]=vm[i];
                bdj[vm[i]].push_back(vp[i]);
            }
            pth.clear();
            euler(i);
            int v=-1;
            for(int i=pth.size()-1;i>=0;i--){
                if(pth[i]<=m){
                    if(v!=-1){
                        if(!rmp.count(pth[i])||rmp[pth[i]]!=v)pnxt[v]=pth[i];
                    }
                    v=pth[i];
                }
            }
        }
    }
    qio<<ans<<'\n';
    int pcc=0;
    for(int i=1;i<=m;i++)pcnt[i]=0;
    for(int i=1;i<=m;i++)pcnt[pnxt[i]]=1;
    for(int i=1;i<=m;i++){
        if(!pcnt[i]){
            for(int j=i;j;j=pnxt[j]){
                rperm[++pcc]=j;
            }
        }
    }
    assert(pcc==m);
    for(int i=1;i<=m;i++)qio<<rperm[i]<<' ';
    qio<<'\n';
}
