				rep(j,0,F_Lim[v_1][y])
					Phi[y]=min(Phi[y],F[v_1][y][j]+((long long)(j+1)*vt[u].w));
			int que_Tot=0;
			rep(p,1,n)
			{
				if(!((vt[v_1].Inn<=Miu[p])&&(Miu[p]<=vt[v_1].Out)))
					continue;
				if(que_Tot&&(w_que[que_Tot]==vt[arr[Miu[p]]].w)&&(Phi[Miu[p]]<=Phi_que[que_Tot]))
					--que_Tot;
				while((que_Tot>=2)&&(((__int128)(Phi[Miu[p]]-Phi_que[que_Tot])*(w_que[que_Tot]-w_que[que_Tot-1]))<=
					((__int128)(Phi_que[que_Tot]-Phi_que[que_Tot-1])*(vt[arr[Miu[p]]].w-w_que[que_Tot]))))
					--que_Tot;
				++que_Tot,w_que[que_Tot]=vt[arr[Miu[p]]].w,Phi_que[que_Tot]=Phi[Miu[p]];
			}
			rep(x,vt[v_0].Inn,vt[v_0].Out)
			{
				int que_The=que_Tot;
				rep(i,0,F_Lim[v_0][x])
				{
					while((que_The>=2)&&((Phi_que[que_The-1]+((long long)(i+1)*w_que[que_The-1]))<=
						(Phi_que[que_The]+((long long)(i+1)*w_que[que_The])))) --que_The;
					F[u][x][0]=min(F[u][x][0],
						F[v_0][x][i]+vt[arr[x]].w+Phi_que[que_The]+((long long)(i+1)*w_que[que_The]));
				}
			}
			rep(i,0,vt[v_0].lvl) X[i]=(+Inf_LL);
			rep(x,vt[v_0].Inn,vt[v_0].Out)
				rep(i,0,F_Lim[v_0][x])
					X[i]=min(X[i],F[v_0][x][i]);
			rep(y,vt[v_1].Inn,vt[v_1].Out) Y[y]=(+Inf_LL);
			rep(y,vt[v_1].Inn,vt[v_1].Out)
				rep(j,0,F_Lim[v_1][y])
					Y[y]=min(Y[y],F[v_1][y][j]+vt[arr[y]].w+((long long)(j+1)*vt[u].w));
			rep(y,vt[v_1].Inn,vt[v_1].Out)
				rep(i,0,vt[v_0].lvl)
					F[u][y][i+1]=min(F[u][y][i+1],X[i]+Y[y]);
			rep(y,vt[v_1].Inn,vt[v_1].Out) Y[y]=(+Inf_LL);
			rep(y,vt[v_1].Inn,vt[v_1].Out)
				rep(i,0,vt[v_0].lvl)
					Y[y]=min(Y[y],X[i]+((long long)(i+1)*vt[arr[y]].w));
			rep(y,vt[v_1].Inn,vt[v_1].Out)
				rep(j,0,F_Lim[v_1][y])
					F[u][vt[u].Inn][j+1]=min(F[u][vt[u].Inn][j+1],F[v_1][y][j]+vt[u].w+Y[y]);
			swap(v_0,v_1);
		}
	}
