#include <bits/stdc++.h>
using namespace std;

const int N = 2e5 + 10, M = 155, S = 150;

int n, m, a[N], b[N], c[N];
int pre[N], las[N], rk[N], g[N], f[N][M], ans;
int id[N], cnt, mx1[N], mx2[N];

void init_() {
    scanf("%d", &n);

    for (int i = 1; i <= n; i++) {
        scanf("%d", &a[i]);
        b[i] = a[i];
    }

    sort(b + 1, b + n + 1);
    m = unique(b + 1, b + n + 1) - b - 1;

    for (int i = 1; i <= m; i++) {
        g[i] = c[i] = 0;
        las[i] = 0;
    }

    for (int i = 1; i <= n; i++) {
        a[i] = lower_bound(b + 1, b + m + 1, a[i]) - b;
        c[a[i]]++;
        pre[i] = las[a[i]];
        las[a[i]] = i;
        rk[i] = rk[pre[i]] + 1;
    }

    for (int i = 1; i <= n; i++) {
        for (int j = 1; j < S; j++) {
            f[i][j] = f[i - 1][j];
        }

        f[i][0] = i + 1;

        for (int j = 1, x = i; j < S; j++, x = pre[x]) {
            f[i][j] = max(f[i][j], x);
        }
    }
}

void upd_(int x, int y) {
    g[x] = max(g[x], y);
    ans = max(ans, y);
}

void solve1_(int x) {
    int cur = 0;

    for (int i = 1; i <= n; i++) {
        if (a[i] == x) {
            cur++;
            continue;
        }

        mx1[i] = c[x] + cur - rk[i] + 1;
        mx2[i] = -cur + c[a[i]] + rk[i] + 1;

        if (pre[i]) {
            mx1[i] = max(mx1[i], mx1[pre[i]]);
            mx2[i] = max(mx2[i], mx2[pre[i]]);
        }

        upd_(x, mx1[i] - cur + rk[i]);
        upd_(a[i], mx2[i] + cur - rk[i]);
    }
}

void solve2_(int x) {
    cnt = c[x];
    id[cnt] = las[x];

    for (int i = cnt - 1; i; i--) {
        id[i] = pre[id[i + 1]];
    }

    for (int i = 1; i <= cnt; i++) {
        int r = id[i] - 1;

        for (int j = 1, k = S - 1; j < i; j++) {
            while (k > 0 && f[r][k] <= id[j]) {
                k--;
            }

            upd_(x, k + c[x] - (i - j - 1));
        }
    }
}

void work_() {
    ans = 0;

    for (int i = 1; i <= m; i++) {
        if (c[i] >= S) {
            solve1_(i);
        } else {
            solve2_(i);
        }
    }

    int mx = 0;

    for (int i = 1; i <= n; i++) {
        upd_(a[i], mx + c[a[i]] - rk[i] + 1);
        mx = max(mx, rk[i]);
    }

    mx = 0;

    for (int i = n; i; i--) {
        upd_(a[i], rk[i] + mx);
        mx = max(mx, c[a[i]] - rk[i] + 1);
    }

    printf("%d\n", ans);

    for (int i = 1; i <= m; i++) {
        if (g[i] == ans) {
            printf("%d\n", b[i]);
        }
    }
}

int main() {
    int T;
    scanf("%d", &T);

    while (T--) {
        init_();
        work_();
    }
}

#include<bits/stdc++.h>
using namespace std;
typedef long long ll;
typedef pair<int,int> pr;
const int B=400;
int n,a[200005],b[200005],s[200005],ans[200005],cnt[200005],sz[200005];
int cnt_[200005],R,T,mx,mx_,nxt[200005],c[200005];
vector<int> pos[200005];
void Inc_(int y){
	while(mx_<y)cnt_[a[mx_]]--,mx_++;
}
void Inc(int x,int id){
	cnt[x]++,cnt_[x]++;
	if(!c[x])c[x]=id;
	if(cnt[x]==T)mx=cnt[x],Inc_(c[x]);
}
void Dec(int x){
	cnt[x]--,c[x]=nxt[c[x]];
	if(cnt[x]==T)Inc_(c[x]);
}
void Solve(){
	scanf("%d",&n);
	for(int i=1;i<=n;i++)scanf("%d",&a[i]),b[i]=a[i];
	sort(b+1,b+n+1);
	int m=unique(b+1,b+n+1)-b-1;
	for(int i=1;i<=n;i++)a[i]=lower_bound(b+1,b+m+1,a[i])-b;
	for(int i=n;i>=1;i--){
		if(pos[a[i]].size())nxt[i]=pos[a[i]].back();
		else nxt[i]=0;
		pos[a[i]].push_back(i);
	}
	for(int i=1;i<=m;i++)ans[i]=sz[i]=pos[i].size(),reverse(pos[i].begin(),pos[i].end());
	for(int i=1;i<=m;i++){
		if(sz[i]>=B){
			for(int j=1;j<=n;j++)s[j]=s[j-1]+(a[j]==i);
			for(int j=1;j<=m;j++){
				int lst=0,f=0;
				for(int k:pos[j]){
					ans[j]=max(ans[j],s[k-1]-s[lst]+sz[j]+f);
					f=max(0,f-1+s[k-1]-s[lst]);
					lst=k;
				}
				ans[j]=max(ans[j],s[n]-s[lst]+sz[j]+f);
			}
		}
	}
	for(T=1;T<B;T++){
		for(int i=1;i<=m;i++)cnt[i]=cnt_[i]=c[i]=0;
		mx=0,mx_=1;
		for(int i=1,j=1;i<=n;i++){
			Inc(a[i],i);
			while(cnt[a[i]]>T)Dec(a[j]),j++;
			if(mx==T){
				if(i<n)ans[a[i+1]]=max(ans[a[i+1]],sz[a[i+1]]+T-cnt_[a[i+1]]);
				else for(int k=1;k<=m;k++)ans[k]=max(ans[k],sz[k]+T-cnt_[k]);
			}
		}
	}
	int o=0;
	cout<<(o=*max_element(ans+1,ans+m+1))<<'\n';
	for(int i=1;i<=m;i++)if(ans[i]==o)cout<<b[i]<<'\n';
	for(int i=1;i<=n;i++)pos[i].clear();
}
int main(){
	int t;
	scanf("%d",&t);
	while(t--)Solve();
}

