	for(int i=1;i<=n;++i)
		pos[a[i]=lower_bound(b+1,b+tot+1,a[i])-b].push_back(i);
	for(int i=1;i<=tot;++i)
	{
		if(pos[i].size()<B)continue;
		for(int t:pos[i])s[t]=1;
		for(int t=1;t<=n+1;++t)s[t]+=s[t-1];
		for(int j=1;j<=tot;++j)if(i^j)
		{
			pos[j].push_back(n+1);
			int mx=s[pos[j].front()];
			upd(b[j],mx+pos[j].size()-1);
			for(int t=1;t<pos[j].size();++t)
			{
				mx=max(mx,t)+s[pos[j][t]]-s[pos[j][t-1]];
				upd(b[j],mx+pos[j].size()-1-t);
			}
			mx=s[pos[j].front()];
			upd(b[i],1+pos[i].size());
			for(int t=1;t<pos[j].size();++t)
			{
				mx=max(mx+(t!=pos[j].size()-1),1+s[pos[j][t]]);
				upd(b[i],mx+s[n]-s[pos[j][t]]);
			}
			pos[j].pop_back();
		}
		fill(s+1,s+n+2,0);
	}
	pre();
	for(int i=1;i<=n;++i)++ct[a[i]];
	for(int i=n;i;--i)
	{
		upd(b[a[i]],ask(n)+ct[a[i]]);
		for(int t=pos[a[i]].size()-1,co=1;t>=0&&co<=B;--t,++co)
		{
			int now=pos[a[i]][t];if(now<i)break;
			upd(b[a[i]],ask(now)+co+ct[a[i]]);
		}
		for(int t=lower_bound(pos[a[i]].begin(),pos[a[i]].end(),i)-pos[a[i]].begin(),co=1;t<pos[a[i]].size()&&co<=B;++t,++co)
			ins(pos[a[i]][t],co);
		--ct[a[i]];
	}
	for(int i=1;i<=n;++i)++ct[a[i]];
	for(int i=1;i<=n;++i)
		upd(b[a[i]],ask(i)+ct[a[i]]),--ct[a[i]];
	printf("%d\n",ans);
	sort(res.begin(),res.end());
	res.erase(unique(res.begin(),res.end()),res.end());
	for(int u:res)printf("%d\n",u);
	clear();
}
