struct Lpow {
	ll pw1[B + 5], pw2[B + 5];
	inline constexpr Lpow(ll x) {
		pw1[0] = 1;
		for(int i = 1; i <= B; ++i) pw1[i] = pw1[i - 1] * x % mod;
		pw2[0] = 1, x = pw1[B];
		for(int i = 1; i <= B; ++i) pw2[i] = pw2[i - 1] * x % mod;
	}
	inline ll lp(ll x) { x %= mod - 1; return pw1[x % B] * pw2[x / B] % mod; }
};
