void Solve( ll l , ll r ) {
    if( l == r ) {
        // printf("%lld\n", l );
        ll S = 0 , T = 0;
        for( int i = 0 , p = c2 , q = c2 - 1 ; i < c1 ; i ++ ) {
            for( ; p - 1 >= 0 && S1[ i ].fi + S2[ p - 1 ].fi >= l ; p -- ); //s[i]+s[l] >= l
            for( ; q >= 0 && S1[ i ].fi + S2[ q ].fi > l ; q -- ); //s[i]+s[r]<=md
            for( int j = p ; j <= q ; j ++ ) {
                if( !S ) {
                    S = S1[ i ].sc + ( S2[ j ].sc << n / 2 );
                }
                else {
                    T = S1[ i ].sc + ( S2[ j ].sc << n / 2 );
                    putans( S , T );
                }
            }
        } 
        for( int i = 0 , p = c2 , q = c2 - 1 ; i < c1 ; i ++ ) {
            for( ; p - 1 >= 0 && S1[ i ].fi + S2[ p - 1 ].fi >= l + P ; p -- ); //s[i]+s[l] >= l
            for( ; q >= 0 && S1[ i ].fi + S2[ q ].fi > l + P ; q -- ); //s[i]+s[r]<=md
            for( int j = p ; j <= q ; j ++ ) {
                if( !S ) {
                    S = S1[ i ].sc + ( S2[ j ].sc << n / 2 );
                }
                else {
                    T = S1[ i ].sc + ( S2[ j ].sc << n / 2 );
                    putans( S , T );
                }
            }
        }
    }

    ll md = l + r >> 1;
    
    ll s = 0;
    for( int i = 0 , p = c2 , q = c2 - 1 ; i < c1 ; i ++ ) {
        for( ; p - 1 >= 0 && S1[ i ].fi + S2[ p - 1 ].fi >= l ; p -- ); //s[i]+s[l] >= l
        for( ; q >= 0 && S1[ i ].fi + S2[ q ].fi > md ; q -- ); //s[i]+s[r]<=md
        if( p <= q ) s += q - p + 1;
    } 
    for( int i = 0 , p = c2 , q = c2 - 1 ; i < c1 ; i ++ ) {
        for( ; p - 1 >= 0 && S1[ i ].fi + S2[ p - 1 ].fi >= l + P ; p -- ); //s[i]+s[l] >= l
        for( ; q >= 0 && S1[ i ].fi + S2[ q ].fi > md + P ; q -- ); //s[i]+s[r]<=md
        if( p <= q ) s += q - p + 1;
    }

    if( s > md - l + 1 ) Solve( l , md );
    else Solve( md + 1 , r );
}

