	int extend(int p,int c){
		int z=++tot; mxl[z]=mxl[p]+1;
		while(p&&!ch[p][c]) ch[p][c]=z,p=lk[p];
		if(!p) lk[z]=1;
		else{
			int x=ch[p][c];
			if(mxl[x]==mxl[p]+1) lk[z]=x;
			else{
				int y=++tot; mxl[y]=mxl[p]+1;
				memcpy(ch[y],ch[x],sizeof ch[y]);
				while(p&&ch[p][c]==x) ch[p][c]=y,p=lk[p];
				lk[y]=lk[x]; lk[z]=lk[x]=y;
