						son[u]=v,top[v]=top[u];
		}
		for(int i=tot;i;i--){
			int u=ord[i];
			if(!son[u]) stp[u]=endp[u]+1;
			else stp[u]=stp[son[u]]-1;
		}
		for(int i=1;i<=tot;i++)
			if(top[i]==i){
				for(int j=i;j;j=son[j]){
