using namespace SAM;
namespace SA{
	int sa[N+5],rk[N+5],tp[N+5];
	int ht[20][N+5];
	void rsort(int m){
		static int cnt[N+5];
		memset(cnt+1,0,m*sizeof(int));
		for(int i=1;i<=n;i++) cnt[rk[i]]++;
		for(int i=1;i<=m;i++) cnt[i]+=cnt[i-1];
		for(int *i=tp+n;i!=tp;--i) sa[cnt[rk[*i]]--]=*i;
	}
	bool chk(int x,int y,int l){
		return tp[x]==tp[y]&&tp[x+l]==tp[y+l];
	}
	void get_sa(){
		int m=26;
		for(int i=1;i<=n;i++){
			rk[i]=s[i]-'a'; tp[i]=i;
		}
		rsort(m);
		for(int l=1,p=0;p<n;l<<=1){
			p=0;
			for(int i=0;i<l;i++) tp[++p]=n-i;
			for(int i=1;i<=n;i++)
				if(sa[i]>l) tp[++p]=sa[i]-l;
			rsort(m);
			swap(rk,tp);
			rk[sa[1]]=p=1;
			for(int i=2;i<=n;i++)
				rk[sa[i]]=p+=!chk(sa[i],sa[i-1],l);
			m=p;
		}
		for(int i=1,j=0;i<=n;i++){
			if(j) j--;
			if(rk[i]==n) continue;
			int k=sa[rk[i]+1];
			while(s[i+j]==s[k+j]) j++;
			ht[0][rk[i]]=j;
		}
		for(int i=1;n>>i;i++)
			for(int j=1;n-j+1>>i;j++)
				ht[i][j]=min(ht[i-1][j],ht[i-1][j+(1<<i-1)]);
	}
	int lcp(int x,int y){
		if(x==y) return n-x+1;
		x=rk[x]; y=rk[y];
		if(x>y) swap(x,y);
		int k=__lg(y-x);
		return min(ht[k][x],ht[k][y-(1<<k)]);
	}
}
