int ok(int x,int y) {
	if (siz1[x]<siz2[y]) return 0; 
	if (siz1[x]==siz2[y]) return gf[x]==hf[y]; 
	if (siz1[x]>siz2[y]+k) return 0; 
	vector<int> nx,ny; nx.clear(),ny.clear();
	int pos1=0,pos2=0;
	while (pos1<G[x].size() && pos2<H[y].size()) {
		if (gf[G[x][pos1]]==hf[H[y][pos2]]) {
			pos1++,pos2++;
		}
		else if (gf[G[x][pos1]]<hf[H[y][pos2]]) {
			nx.push_back(G[x][pos1]); pos1++; 
		} else ny.push_back(H[y][pos2]),pos2++; 
	} 
	while (pos1<G[x].size()) nx.push_back(G[x][pos1]),pos1++; 
	while (pos2<H[y].size()) ny.push_back(H[y][pos2]),pos2++;
	 
 	if (nx.size()<ny.size()) return 0; 
	 if (nx.size()==0 && ny.size()==0) return 1; 
	if (nx.size()>k || ny.size()>k) return 0; 
	int can[6][6]={};
	
	// cerr<<nx.size()<<' '<<ny.size()<<'\n'; 
	for (int i=0;i<nx.size();i++) for (int j=0;j<ny.size();j++) {
		can[i][j]=ok(nx[i],ny[j]); 
	}
	for (int i=0;i<nx.size();i++) {
		id[i]=i; 
	}
	
	do {
		int ok=1; 
		for (int i=0;i<ny.size();i++) {
			ok&=can[id[i]][i]; 
		}		
		if (ok) return 1; 
	} while (next_permutation(id,id+nx.size())); 
	return 0; 
}
