		});
	}
	for (int i=1;i<=n2;i++) {
		sort(H[i].begin(),H[i].end(),[&](int x,int y) {
			return hf[x]<hf[y]; 
		}); 
	}
	if (ok(rt1,rt2)) puts("Yes"); else puts("No"); 
}
