ULL get(ULL x)
{
    x^=msk;
    x^=x<<13; x^=x>>7; x^=x<<17;
    x^=msk;
    return x;
}
int id,T,k;
int n1,n2;
int rt1,rt2;
vector<int>E[mn],G[mn];
unordered_map<int,bool>ANS[mn];
void reset()
{
    for(int i=1;i<=n1;i++)E[i].clear();
    for(int i=1;i<=n2;i++)G[i].clear();
    for(int i=1;i<=n1;i++)ANS[i].clear();
}
int s1[mn],s2[mn];
ULL w1[mn],w2[mn];
void init(int u,vector<int>E[],int s[],ULL w[])
{
    s[u]=1; w[u]=0;
    for(auto v:E[u])
    {
        init(v,E,s,w);
        s[u]+=s[v];
        w[u]+=get(w[v]);
    }
    w[u]+=C;
}
int x;
struct state
{
    int u;
    ULL x;
};
bool operator <(const state &A,const state &B)
{
    return A.x<B.x;
}
bool check(int U,int V)
{
    if(w1[U]==w2[V])return 1;
    if(s1[U]<=s2[V])return 0;
    if(V==0)return 1;
    if(ANS[U].count(V))return ANS[U][V];

    unordered_map<ULL,int>cntA,cntB;
    for(auto v:E[U])cntA[w1[v]]++;
    for(auto v:G[V])cntB[w2[v]]++;

    vector<state>vecA,vecB;
    for(auto v:E[U])
    {
        ULL x=w1[v];
        if(cntA[x]>cntB[x])
        {
            cntA[x]--;
            vecA.push_back({v,x});
        }
    }
    for(auto v:G[V])
    {
        ULL x=w2[v];
        if(cntB[x]>cntA[x])
        {
            cntB[x]--;
            vecB.push_back({v,x});
        }
    }
    if(vecB.size()>vecA.size())return ANS[U][V]=0;
    while(vecB.size()<vecA.size())vecB.push_back({0,0});
    sort(vecA.begin(),vecA.end());
    sort(vecB.begin(),vecB.end());
    int N=vecA.size();

    do
    {
        bool flag=1;
        for(int i=0;i<N;i++)
        {
            if(!check(vecA[i].u,vecB[i].u))
            {
                flag=0;
                break;
            }
        }
        if(flag)return ANS[U][V]=1;
    }while(next_permutation(vecB.begin(),vecB.end()));

    return ANS[U][V]=0;
}
