queue<int> que;
inline bool Dinic_Bfs(const int S,const int T)
{
	int u,v,w;
	For(i,1,vt_Tot) vt[i].lvl=INT_MAX;
	while(!que.empty()) que.pop();
	vt[S].lvl=0,que.push(S),vt[S].cur=vt[S].head;
	while(!que.empty())
	{
		u=que.front(),que.pop();
		for(int e=vt[u].head;e;e=ed[e].next)
		{
			v=ed[e].v,w=ed[e].w;
			if(!w||(vt[v].lvl!=INT_MAX)) continue;
			vt[v].lvl=(vt[u].lvl+1),que.push(v),vt[v].cur=vt[v].head;
			if(v==T) return true;
		}
	}
	return false;
}
inline int Dinic_Dfs(const int u,int Remain,const int T)
{
	if(u==T) return Remain;
	int v,w,Flow=0;
	for(int &e=vt[u].cur;e;e=ed[e].next)
	{
		v=ed[e].v,w=ed[e].w;
		if(!w||(vt[v].lvl!=(vt[u].lvl+1))) continue;
		const int Delta=Dinic_Dfs(v,min(Remain,w),T);
		ed[e].w-=Delta,ed[e^1].w+=Delta,Remain-=Delta,Flow+=Delta;
		if(!Remain) break;
	}
	return Flow;
}
inline void Dfs_get_Type(const int u)
{
	int v,w;
	vt[u].typ='S';
	for(int e=vt[u].head;e;e=ed[e].next)
	{
		v=ed[e].v,w=ed[e].w;
		if(w&&(vt[v].typ=='T')) Dfs_get_Type(v);
	}
}
inline pair<int,int> Solve(const int S,const int T,const int mul_A,const int mul_B)
{
	for(int e=2;e<=ed_Tot;e+=2)
	{
		const pair<int,int> Pair=ed[e].Pair;
		if(Pair.first=='A') ed[e].w=(mul_A*Pair.second),ed[e^1].w=0;
		else if(Pair.first=='B') ed[e].w=(mul_B*Pair.second),ed[e^1].w=0;
		else ed[e].w=INT_MAX,ed[e^1].w=0;
	}
	int max_Flow=0;
	while(Dinic_Bfs(S,T)) max_Flow+=Dinic_Dfs(S,INT_MAX,T);
	For(i,1,vt_Tot) vt[i].typ='T';
	Dfs_get_Type(S);
	int u,v,A_cnt=0,B_cnt=0;
	for(int e=2;e<=ed_Tot;e+=2)
	{
		u=ed[e].u,v=ed[e].v;
		if(ed[e].Pair.first=='A') if(vt[v].typ=='S') A_cnt+=ed[e].Pair.second;
		if(ed[e].Pair.first=='B') if(vt[u].typ=='T') B_cnt+=ed[e].Pair.second;
	}
	return make_pair(A_cnt,B_cnt);
}
vector<pair<int,int>> arr;
inline void Solve_Divide_Conquer(const int S,const int T,const pair<int,int> F,const pair<int,int> G)
{
	const pair<int,int> P=Solve(S,T,F.second-G.second,G.first-F.first);
	if(((F.second-P.second)*(G.first-P.first))==((P.second-G.second)*(P.first-F.first)))
		{arr.push_back(G);return;}
	Solve_Divide_Conquer(S,T,F,P),Solve_Divide_Conquer(S,T,P,G);
}
