void sim(){
	int suml = 0, sumr = 0;
	std::set <std::pair <int, int>> L, R;
	std::vector <int> ans;
	for(int i = 1; i < 2 * n; ++i) p[i] = i;
	std::shuffle(p + 1, p + 2 * n, std::default_random_engine(rng()));
	for(int i = 1; i <= n; ++i) L.insert({a[p[i]], p[i]}), suml = (suml + a[p[i]]) % n;
	if(suml == 0){
		for(auto P : L) ans.push_back(P.second);
		std::sort(ans.begin(), ans.end());
		for(auto p : ans) wt(p, ' ');
		putchar('\n');
		return void();
	}
	for(int i = n + 1; i < 2 * n; ++i) R.insert({a[p[i]], p[i]}), sumr = (sumr + a[p[i]]) % n;
	while(1){
		++_;
		int fl = 0;
		auto it = L.lower_bound({0, 0});
		while(it != L.end()){
			int x = it->first, nw = (suml - x + n) % n;
			auto rit = R.lower_bound({n - nw, 0});
			if(rit != R.end() && rit->first == n - nw){
				ans.push_back(rit->second);
				for(auto Q : L) if(Q.second != it->second) ans.push_back(Q.second);
				fl = 1; break;
			}
			it = L.lower_bound({(it->first) + 1, 0});
		}
		if(fl) break;
		for(int T = 1; T <= 1; ++T){
			int sl = rnd(0, n - 1), sr = rnd(0, n - 1);
			std::pair <int, int> pl = {0, 0}, pr = {0, 0};
			auto nl = L.lower_bound({sl, 0});
			if(nl == L.end()) --nl;
			pl = *nl;
			auto nr = R.lower_bound({sr, 0});
			if(nr == R.end()) --nr;
			pr = *nr;
			while(pr.first == pl.first){
				sr = rnd(0, n - 1);
				nr = R.lower_bound({sr, 0});
				if(nr == R.end()) --nr;
				pr = *nr;
			}
			L.erase(pl), L.insert(pr), suml -= pl.first, suml += pr.first, suml = (suml + n) % n;
			R.erase(pr), R.insert(pl);
			if(suml == 0){
				for(auto P : L) ans.push_back(P.second);
				std::sort(ans.begin(), ans.end());
				for(auto p : ans) wt(p, ' ');
				putchar('\n');
				return void();
			}
		}
		if(_ % 100000 == 0) std::cerr << _ << '\n';
	}
	std::sort(ans.begin(), ans.end());
	for(auto p : ans) wt(p, ' ');
	putchar('\n');
}

