template <typename T>
class nextsum_calculation
{
	private:
		struct Node{
			T sum;
			int *sus;
			bool operator <(const Node &rhs) const
			{
				return rhs.sum<sum;
			}
		};
		int k;
		vector <T> data;
		vector <Node> Ans;
		priority_queue <Node> q;
		bool check(int *arr,int pos)
		{
			if(pos<0||pos>=k) return false;
			if(pos==k-1) return arr[pos]+1!=data.size();
			return arr[pos]+1!=arr[pos+1];
		}
		void insert(int *arr,int pos)
		{
			Node tmp;
			tmp.sus=new int[k];
			for(int i=0;i<k;++i)
				tmp.sus[i]=arr[i];
			++tmp.sus[pos];
			tmp.sum=data.at(tmp.sus[0]);
			for(int i=1;i<k;++i)
				tmp.sum=tmp.sum+data.at(tmp.sus[i]);
			q.push(tmp);
		}
	public:
		template <typename Iter>
		nextsum_calculation(Iter Begin,Iter End,int outside_k)
		{
			k=outside_k;
			for(;Begin!=End;++Begin)
				data.push_back(*Begin);
			sort(data.begin(),data.end());
			Node tmp;
			tmp.sum=data.at(0);
			tmp.sus=new int[k];
			tmp.sus[0]=0;
			for(int i=1;i<k;++i)
				tmp.sum=tmp.sum+data.at(i),tmp.sus[i]=i;
			q.push(tmp);
		}
		bool query_next(T *arr=NULL)
		{
			if(q.empty()) return false;
			Node cur=q.top();
			q.pop();
			Ans.push_back(cur);
			int inter=k-1;
			if(cur.sus[0]>0) inter=-1;
			else
				for(int i=0;i<k-1;++i)
					if(cur.sus[i]+1!=cur.sus[i+1]) {inter=i;break;}
			if(check(cur.sus,inter)) insert(cur.sus,inter);
			++inter;
			if(check(cur.sus,inter)) insert(cur.sus,inter);
			if(arr!=NULL)
			{
				T *p=arr;
				for(int i=0;i<k;++i,++p)
					*p=data.at(cur.sus[i]);
			}
			return true;
