void add_edge(int from,int to)
{
	++cnt_edge;
	E[cnt_edge].nxt=head[from];
	head[from]=cnt_edge;
	E[cnt_edge].to=to;
}
void cal_dis(int t)
{
	if(dis[t][t]==0) return;
	memset(vis,false,sizeof vis);
	queue <pair <int,int> > q;
	q.push(make_pair(t,0));
	while(!q.empty())
	{
		auto tmp=q.front();
		q.pop();
		if(vis[tmp.first]) continue;
		dis[t][tmp.first]=tmp.second;
		vis[tmp.first]=true;
		for(int i=head[tmp.first];i;i=E[i].nxt)
		{
			int v=E[i].to;
			if(vis[v]) continue;
			q.push(make_pair(v,tmp.second+1));
		}
	}
}
bool check(int *p)
{
	if(dis[1][p[0]]>k||dis[1][p[3]]>k) return false;
	for(int i=0;i<=2;++i)
	{
		cal_dis(p[i]);
		if(dis[p[i]][p[i+1]]>k) return false;
	}
	return true;
}
bool dfs(int cur,int t)
{
	if(t==4) return dis[1][cur]<=k;
	cal_dis(cur);
	for(int i=0;i<4;++i)
	{
		if(gone[i]) continue;
		if(dis[cur][p[i]]<=k)
		{
			gone[i]=true;
			bool tmp=dfs(p[i],t+1);
			gone[i]=false;
			if(tmp) return true;
		}
	}
	return false;
}
