int lg[N];
ll f[N][19], F[N][19], af[N][19], aF[N][19];
ll g[N][19], G[N][19];
int n, m, q;

void init()
{
	for(int i = 1; i <= n; i ++)
	{
		f[i][0] = F[i][0] = a[i];
		if(a[i] == 0)af[i][0] = aF[i][0] = 0; 
		if(a[i] < 0)af[i][0] = a[i], aF[i][0] = inf;
		if(a[i] > 0)af[i][0] = -inf, aF[i][0] = a[i];
	}
	for(int i = 1; i <= m; i ++)
	{
		g[i][0] = G[i][0] = b[i];
	}
	
	for(int j = 1; j <= 18; j ++)
	{
		for(int i = 1; i + (1 << j) - 1 <= n; i ++)
		{
			f[i][j] = max(f[i][j - 1], f[i + (1 << (j - 1))][j - 1]);
			F[i][j] = min(F[i][j - 1], F[i + (1 << (j - 1))][j - 1]);
			af[i][j] = max(af[i][j - 1], af[i + (1 << (j - 1))][j - 1]);
			aF[i][j] = min(aF[i][j - 1], aF[i + (1 << (j - 1))][j - 1]);
		}
	}
	
	for(int j = 1; j <= 18; j ++)
	{
		for(int i = 1; (i + (1 << j) - 1) <= m; i ++)
		{
			g[i][j] = max(g[i][j - 1], g[i + (1 << (j - 1))][j - 1]);
			G[i][j] = min(G[i][j - 1], G[i + (1 << (j - 1))][j - 1]);
		}
	}
	return;
}

ll askG(int l, int r, int op)
{
	int k = lg[r - l + 1];
	if(op == 1)return max(g[l][k], g[r - (1 << k) + 1][k]);
	else return min(G[l][k], G[r - (1 << k) + 1][k]);
}
ll askF(int l, int r, int op)
{
	int k = lg[r - l + 1];
	if(op == 1)return max(f[l][k], f[r - (1 << k) + 1][k]);
	else if(op == 2)return min(F[l][k], F[r - (1 << k) + 1][k]);
	else if(op == 3)return max(af[l][k], af[r - (1 << k) + 1][k]);
	else return min(aF[l][k], aF[r - (1 << k) + 1][k]);
}

ll calc(ll x, ll y, ll z)
{
	if(x == 2e9 || x == -2e9)return -inf * inf;
	return min(x * y, x * z);
}
int main()
{
//	freopen("game.in", "r", stdin);
//	freopen("game.out", "w", stdout);
	scanf("%d%d%d", &n, &m, &q);
	for(int i = 1; i <= n; i ++)
	{
		scanf("%lld", &a[i]);
	}
	lg[0] = -1; for(int i = 1; i <= n + 10; i ++)lg[i] = lg[i >> 1] + 1;
	for(int i = 1; i <= m; i ++)
	{
		scanf("%lld", &b[i]);
	}
	
	init();
	
	for(int i = 1; i <= q; i ++)
	{
		int l, r, L, R;
		scanf("%d%d%d%d", &l, &r, &L, &R);
		ll c = askG(L, R, 2), d = askG(L, R, 1);
		ll ans = -2e18;
		ll a = askF(l, r, 2), b = askF(l, r, 1);
		ans = max(ans, calc(a, c, d));
		ans = max(ans, calc(b, c, d));
		a = askF(l, r, 3), b = askF(l, r, 4);
		ans = max(ans, calc(a, c, d));
		ans = max(ans, calc(b, c, d));
		printf("%lld\n", ans);
	}
	return 0;
}

