inline int ls(int x) { return x << 1; }
inline int rs(int x) { return (x << 1) | 1; }

inline void updata(int x, int l, int r, int v)
{
	if (v)
	{
		sm[x] = (pf[r + 1] ^ pf[l]);
		cnt[x] = r - l + 1;
	}
	else
		sm[x] = 0, cnt[x] = 0;
	tag[x] = v;
}

inline void pushdown(int id, int l, int r)
{
	if (tag[id] != -1)
	{
		int mid = (l + r) >> 1;
		updata(ls(id), l, mid, tag[id]);
		updata(rs(id), mid + 1, r, tag[id]);
		tag[id] = -1;
	}
}

void modify(int L, int R, int l, int r, int id, int val)
{
	if (L <= l && r <= R)
	{
		updata(id, l, r, val);
		return;
	}
	int mid = (l + r) >> 1;
	
	pushdown(id, l, r);
	if (L <= mid)
		modify(L, R, l, mid, ls(id), val);
	if (mid < R)
		modify(L, R, mid + 1, r, rs(id), val);
	cnt[id] = cnt[ls(id)] + cnt[rs(id)];
	sm[id] = (sm[ls(id)] ^ sm[rs(id)]);
}

inline int read()
{
	int ch = getchar(), t = 1, n = 0;
	while (isspace(ch)) ch = getchar();
	if (ch == '-') t = -1, ch = getchar();
	while (isdigit(ch)) n = n * 10 + ch - '0', ch = getchar();
	return n * t;
}

