template <typename T>
void ri(T& x)
{
    x = 0;
    int neg = 1;
    char c = getchar();
    for (; !isdigit(c) && c != '-'; c = getchar())
        ;
    if (c == '-') {
        c = getchar();
        neg = -1;
    }
    for (; isdigit(c); c = getchar())
        x = x * 10 + c - 48;
    x *= neg;
}
template <typename T, typename... Args>
void ri(T& x, Args&... args)
{
    ri(x), ri(args...);
}

