    while (q--) {
        int op, u, v = 0;
        ri(op, u);
        if (op == 1 || op == 3)
            ri(v);
        --u, --v;
        ops.emplace_back(op, u, v);
        switch (op) {
        case 1:
            edgeCnt--;
            inOk[v]--;
            break;
        case 2:
            edgeCnt -= inOk[u];
            inOk[u] = 0;
            break;
        case 3:
            edgeCnt++;
            inOk[v]++;
            break;
        case 4:
            edgeCnt += belong[u].size() - inOk[u];
            inOk[u] = belong[u].size();
            break;
        default:
            break;
        }
        // cerr << edgeCnt << " " << q << endl;
        if (edgeCnt == n) {
            opCnt++;
            reverse(ALL(ops));
            for (auto&& i : ops) {
                int op, u, v;
                tie(op, u, v) = i;
                if (op == 2 || op == 4) {
                    if (modified[u] == opCnt)
                        continue;
                    modified[u] = opCnt;
                    for (auto&& j : belong[u]) {
                        if (modifiedE[j] == opCnt)
                            continue;
                        modifiedE[j] = opCnt;
                        if (op == 4) {
                            if (!okE[j]) {
                                validCnt[edges[j].first]++;
                                if (validCnt[edges[j].first] == 1) {
                                    okCnt++;
                                } else if (validCnt[edges[j].first] == 2) {
                                    okCnt--;
                                }
                            }
                            okE[j] = 1;
                        } else {
                            if (okE[j]) {
                                validCnt[edges[j].first]--;
                                if (validCnt[edges[j].first] == 0) {
                                    okCnt--;
                                } else if (validCnt[edges[j].first] == 1) {
                                    okCnt++;
                                }
                            }
                            okE[j] = 0;
                        }
                    }
                } else {
                    int e = id[{ u, v }];
                    if (modifiedE[e] == opCnt)
                        continue;
                    modifiedE[e] = opCnt;
                    if (op == 3) {
                        if (!okE[e]) {
                            validCnt[edges[e].first]++;
                            if (validCnt[edges[e].first] == 1) {
                                okCnt++;
                            } else if (validCnt[edges[e].first] == 2) {
                                okCnt--;
                            }
                        }
                        okE[e] = 1;
                    } else {
                        if (okE[e]) {
                            validCnt[edges[e].first]--;
                            if (validCnt[edges[e].first] == 0) {
                                okCnt--;
                            } else if (validCnt[edges[e].first] == 1) {
                                okCnt++;
                            }
                        }
                        okE[e] = 0;
                    }
                }
            }
            ops.clear();
            cout << (okCnt == n ? "YES" : "NO") << "\n";
            // cerr << edgeCnt << " " << okCnt << " " << q << endl;
        } else
            cout << "NO\n";
    }
    return 0;
}

