inline void dfs1(int u,int fa){
	g[u][0]=a[u];
	FOR(i,1,k) g[u][i]=inf;
	for (auto v:e[u]) if (v!=fa){
		dfs1(v,u);
		FOR(i,1,k){
			if (g[v][i-1]<g[u][i]) g2[u][i]=g[u][i],g[u][i]=g[v][i-1],pos[u][i]=v;
				else g2[u][i]=min(g2[u][i],g[v][i-1]); 
		}
	}
}
ll G[N][5];
inline void dfs2(int u,int fa,vector<ll> t){
	t[0]=a[u];
	FOR(i,1,k) G[u][i]=min(g[u][i],t[i]);
	G[u][0]=a[u];
	for (auto v:e[u]) if (v!=fa){
		vector<ll> tmp(k);
		For(i,1,k-1) tmp[i]=t[i-1];
		For(i,1,k-2){
			if (v==pos[u][i]) tmp[i+1]=min(tmp[i+1],g2[u][i]);
				else tmp[i+1]=min(tmp[i+1],g[u][i]);
		}
		dfs2(v,u,tmp);
	}
}

struct mat{
	ll v[3][3];
	inline mat operator *(const mat &p)const{
		mat ret;
		FOR(i,0,k) FOR(j,0,k){
			ret.v[i][j]=inf;
			FOR(l,0,k) ret.v[i][j]=min(ret.v[i][j],v[i][l]+p.v[l][j]);
		}
		return ret;
	}
};
int dep[N],anc[N][21];
mat up[N][21],dn[N][21];
inline void dfs3(int u,int fa){
	dep[u]=dep[fa]+1;
	anc[u][0]=fa;
	FOR(i,0,k) FOR(j,0,k) up[u][0].v[i][j]=inf;
	For(i,0,k-2){
		up[u][0].v[i][i+1]=0;
	}
	For(i,0,k-1) For(j,0,k-1) if (i+1+j<=k){
		up[u][0].v[i][j]=min(up[u][0].v[i][j],G[u][j]);
	}
	dn[u][0]=up[u][0];
	For(i,1,20){
		anc[u][i]=anc[anc[u][i-1]][i-1];
		up[u][i]=up[u][i-1]*up[anc[u][i-1]][i-1];
		dn[u][i]=dn[anc[u][i-1]][i-1]*dn[u][i-1];
	}
	for (auto v:e[u]) if (v!=fa){
		dfs3(v,u);
	}
}

inline int LCA(int x,int y){
	if (dep[x]>dep[y]) swap(x,y);
	if (dep[y]>dep[x]) Dow(i,20,0) if (dep[anc[y][i]]>=dep[x]) y=anc[y][i];
	if (x==y) return x;
	Dow(i,20,0) if (anc[x][i]!=anc[y][i]) x=anc[x][i],y=anc[y][i];
	return anc[x][0];
}
inline mat UP(int x,int k){
	mat ret;
	bool flag=0;
	For(i,0,20) if (k>>i&1){
		if (!flag) ret=up[x][i],flag=1;
			else ret=ret*up[x][i];
		x=anc[x][i];
	}
	return ret;
}
inline mat DN(int x,int k){
	mat ret;
	bool flag=0;
	For(i,0,20) if (k>>i&1){
		if (!flag) ret=dn[x][i],flag=1;
			else ret=dn[x][i]*ret;
		x=anc[x][i];
	}
	return ret;
}

