inline void build(LL u,LL c)
{
	B[u].init();
	if(K==1)	B[u][0][0]=c,C[u]=B[u];
	else if(K==2)
	{
		B[u][0][0]=B[u][1][0]=c;
		B[u][0][1]=0;
		C[u]=B[u];
	}
	else
	{
		if(!G[u].empty())
		{
			C[u].init();
			B[u][0][0]=B[u][1][0]=B[u][2][0]=c;
			B[u][0][1]=B[u][1][2]=0;
			B[u][1][1]=a[f[u]];
			if(LL(G[u].size())>=2)
			{
				C[u][0][0]=C[u][1][0]=C[u][2][0]=c;
				C[u][0][1]=C[u][1][2]=0;
				C[u][1][1]=a[g[u]];
			}
		}
	}
}
LL lgs[200005];
LL LCA(LL u,LL v)
{
	if(dep[u]>dep[v])	swap(u,v);
	while(dep[u]<dep[v])	v=fa[lgs[dep[v]-dep[u]]][v];
	if(u==v)	return u;
	for(LL i=17;~i;--i)	if(fa[i][u]^fa[i][v])	u=fa[i][u],v=fa[i][v];
