void jmpup(LL u,LL v,Matrix& ans)
{
	if(dep[u]<dep[v])	swap(u,v);
	LL d=dep[u]-dep[v];
	for(LL i=17;~i;--i)	if((d>>i)&1)	ans=ans*up[i][u],u=fa[i][u];
}
void jmpdn(LL u,LL v,Matrix& ans)
{
	if(dep[u]<dep[v])	swap(u,v);
	vector<Matrix> Seq;
	LL d=dep[u]-dep[v];
	for(LL i=17;~i;--i)	if((d>>i)&1)	Seq.push_back(dn[i][u]),u=fa[i][u];
	reverse(Seq.begin(),Seq.end());
	for(auto c:Seq)	ans=ans*c;
}
LL jmp(LL u,LL d)
{
	for(LL i=17;~i;--i)	if((d>>i)&1)	u=fa[i][u];
	return u;
}
