#include<bits/stdc++.h>
#define ll long long
using namespace std;
const int N=1e5+5;

int n,Q,fa[N],deep[N],ans[N];
vector<int>e[N];
vector<vector<int>>v;
vector<tuple<int,int,int>>q;
int dis[N],vis[N],cnt=0,col[N];
void bfs(vector<vector<int>>&v,int S) {
	for (auto &a:v) {
		for (int &i:a) {
			dis[i]=-1;
		}
	}
	queue<int>q;
	q.emplace(S);
	dis[S]=0;
	while (!q.empty()) {
		int now=q.front(); q.pop();
		for (int to:e[now]) {
			if (dis[to]<0) {
				dis[to]=dis[now]+1;
				q.emplace(to);
			}
		}
	}
}
int dp[N],is[N];
vector<int>getpos(vector<vector<int>>&v) {
	int n=0;
	vector<int>b;
	for (auto &a:v) {
		for (int &i:a) {
			n++;
			b.emplace_back(i);
		}
	}
	sort(b.begin(),b.end());
	for (int i=0;i<(int)b.size();i++) {
		dp[b[i]]=i;
	}
	for (int i=0;i<(int)v.size();i++) {
		for (int j=0;j<(int)v[i].size();j++) {
			if (vis[fa[v[i][j]]]==cnt) {
				is[fa[v[i][j]]]=cnt;
			}
		}
	}
	int p=0,mx=0;
	for (auto &a:v) {
		for (int &i:a) {
			if (is[i]<cnt&&dp[i]<=n/2&&dp[i]>mx) {
				p=i;
				mx=dp[i];
			}
		}
	}
	int d=-1,tmp=p;
	vector<int>pos(v.size());
	for (int i=(int)v.size()-1;i>=0;i--) {
		int x=p;
		for (int j=0;j<(int)v[i].size();j++) {
			if (v[i][j]==p) {
				if (d<0) {
					d=i;
				}
				pos[i]=j;
				p=fa[p];
				break;
			}
		}
		if (x==p) {
			if (v[i].size()&&v[i].back()<p) {
				pos[i]=(int)v[i].size()-1;
			}
		}
	}
	for (int i=d+1;i<(int)v.size();i++) {
		bool flag=0;
		for (int j=0;j<(int)v[i].size();j++) {
			if (fa[v[i][j]]==tmp) {
				pos[i]=j;
				flag=1;
				tmp=v[i][j];
				break;
			}
		}
		if (!flag) {
			int x=-1;
			for (int j=0;j<(int)v[i].size();j++) {
				x=j;
				if (v[i][j]>tmp) {
					break;
				}
			}
			if (x>=0) {
				pos[i]=x;
				tmp=v[i][x];
			}
		}
	}
	return pos;
}
void solve(vector<vector<int>>&v,vector<tuple<int,int,int>>&q) {
	if (v.empty()||q.empty()) {
		return;
	}
	cnt++;
	for (auto &a:v) {
		for (int &i:a) {
			vis[i]=cnt;
			e[i].clear();
		}
	}
	for (auto &a:v) {
		for (int &i:a) {
			if (vis[fa[i]]==cnt) {
				e[i].emplace_back(fa[i]);
				e[fa[i]].emplace_back(i);
			}
		}
		for (int i=0;i+1<(int)a.size();i++) {
			e[a[i]].emplace_back(a[i+1]);
			e[a[i+1]].emplace_back(a[i]);
		}
	}
	if (v[v.size()/2].size()<v.size()) {
		int mid=v.size()/2;
		for (int j:v[mid]) {
			bfs(v,j);
			for (auto [id,x,y]:q) {
				if (dis[x]<0||dis[y]<0) {
					continue;
				}
				ans[id]=min(ans[id],dis[x]+dis[y]);
			}
		}
		
		vector<vector<int>>a,b;
		vector<tuple<int,int,int>>q1,q2;
		for (int i=0;i<mid;i++) {
			a.emplace_back(v[i]);
			for (int j:v[i]) {
				col[j]=1;
			}
		}
		for (int j:v[mid]) {
			col[j]=0;
		}
		for (int i=mid+1;i<(int)v.size();i++) {
			b.emplace_back(v[i]);
			for (int j:v[i]) {
				col[j]=2;
			}
		}
		for (auto [id,x,y]:q) {
			if (col[x]==1&&col[y]==1) {
				q1.emplace_back(id,x,y);
			}
			if (col[x]==2&&col[y]==2) {
				q2.emplace_back(id,x,y);
			}
		}
		solve(a,q1);
		solve(b,q2);
	} else {
		auto pos=getpos(v);
		
		for (int i=0;i<(int)v.size();i++) {
			if (v[i].empty()) {
				continue;
			}
			int j=v[i][pos[i]];
			bfs(v,j);
			for (auto [id,x,y]:q) {
				if (dis[x]<0||dis[y]<0) {
					continue;
				}
				ans[id]=min(ans[id],dis[x]+dis[y]);
			}
		}
		
		vector<vector<int>>a(v.size()),b(v.size());
		vector<tuple<int,int,int>>q1,q2;
		for (int i=0;i<(int)v.size();i++) {
			if (v[i].empty()) {
				continue;
			}
			int mid=pos[i];
			for (int j=0;j<(int)v[i].size();j++) {
				col[v[i][j]]=0;
				if (j<mid) {
					col[v[i][j]]=1;
					a[i].emplace_back(v[i][j]);
				}
				if (j>mid) {
					col[v[i][j]]=2;
					b[i].emplace_back(v[i][j]);
				}
			}
		}
		while (!a.empty()&&a.back().empty()) {
			a.pop_back();
		}
		while (!b.empty()&&b.back().empty()) {
			b.pop_back();
		}
		for (auto [id,x,y]:q) {
			if (col[x]==1&&col[y]==1) {
				q1.emplace_back(id,x,y);
			}
			if (col[x]==2&&col[y]==2) {
				q2.emplace_back(id,x,y);
			}
		}
		solve(a,q1);
		solve(b,q2);
	}
}

