#include <bits/stdc++.h>
using namespace std;

constexpr int inf = 1e9;

int main() {
	ios::sync_with_stdio(0), cin.tie(0);
	int n, q;
	cin >> n >> q;
	vector<int> fa(n), dep(n), ord(n);
	vector<vector<int>> group(n);
	group[0] = {0};
	for (int i = 1; i < n; i++) {
		cin >> fa[i];
		dep[i] = dep[--fa[i]] + 1;
		ord[i] = group[dep[i]].size();
		group[dep[i]].push_back(i);
	}
	vector<tuple<int, int, int>> qs;
	for (int i = 0; i < q; i++) {
		int x, y;
		cin >> x >> y;
		x--, y--;
		qs.emplace_back(x, y, i);
	}
	vector<int> res(q, inf);
	vector<int> tag(n), dist(n), vis(n, -1);
	vector<vector<int>> adj(n);
	auto rec = [&](auto self, auto ver, auto qs) {
		if (ver.empty() || qs.empty()) return;
		int lo = inf, hi = -inf;
		for (int u : ver) {
			lo = min(lo, dep[u]);
			hi = max(hi, dep[u]);
		}
		vector<int> lb(hi - lo + 1, inf), rb(hi - lo + 1, -inf);
		for (int u : ver) {
			lb[dep[u] - lo] = min(lb[dep[u] - lo], ord[u]);
			rb[dep[u] - lo] = max(rb[dep[u] - lo], ord[u]);
		}
		int len = -inf;
		for (int i = 0; i <= hi - lo; i++) {
			len = max(len, rb[i] - lb[i] + 1);
		}
		if (len < hi - lo + 1) {
			int cur = 0;
			for (int i = 0; i <= hi - lo; i++) {
				cur += rb[i] - lb[i] + 1;
				if (2 * cur > ver.size()) {
					for (int j = 0; j < i; j++) {
						for (int k = lb[j]; k <= rb[j]; k++) {
							tag[group[lo + j][k]] = 0;
						}
					}
					for (int j = lb[i]; j <= rb[i]; j++) {
						tag[group[lo + i][j]] = -1;
					}
					for (int j = i + 1; j <= hi - lo; j++) {
						for (int k = lb[j]; k <= rb[j]; k++) {
							tag[group[lo + j][k]] = 1;
						}
					}
					break;
				}
			}
		} else {
			sort(ver.begin(), ver.end());
			int mid = ver[ver.size() / 2];
			for (int u : ver) {
				tag[u] = -2;
			}
			vector<bool> vis(hi - lo + 1);
			for (int u : vector(ver.rbegin(), ver.rend())) {
				if (u <= mid && !vis[dep[u] - lo]) {
					tag[u] = -1;
					vis[dep[u] - lo] = 1;
				}
			}
			for (int u : ver) {
				if (tag[u] == -2) {
					tag[u] = u > mid;
				}
			}
		}
		for (int u : ver) {
			adj[u].clear();
		}
		for (int u : ver) {
			int d = dep[u] - lo - 1;
			if (0 <= d && lb[d] <= ord[fa[u]] && ord[fa[u]] <= rb[d]) {
				adj[u].push_back(fa[u]);
				adj[fa[u]].push_back(u);
			}
		}
		for (int i = 0; i <= hi - lo; i++) {
			for (int j = lb[i]; j < rb[i]; j++) {
				int u = group[lo + i][j], v = group[lo + i][j + 1];
				adj[u].push_back(v);
				adj[v].push_back(u);
			}
		}
		static int tim = 0;
		for (int u : ver) {
			if (tag[u] != -1) continue;
			tim++;
			queue<int> q;
			q.push(u);
			dist[u] = 0;
			vis[u] = tim;
			while (!q.empty()) {
				int u = q.front();
				q.pop();
				for (int v : adj[u]) {
					if (vis[v] == tim) continue;
					q.push(v);
					dist[v] = dist[u] + 1;
					vis[v] = tim;
				}
			}
			for (auto [u, v, id] : qs) {
				if (vis[u] != tim || vis[v] != tim) continue;
				res[id] = min(res[id], dist[u] + dist[v]);
			}
		}
		decltype(ver) vl, vr;
		for (int u : ver) {
			if (tag[u] == 0) {
				vl.push_back(u);
			} else if (tag[u] == 1) {
				vr.push_back(u);
			}
		}
		decltype(qs) ql, qr;
		for (auto [u, v, id] : qs) {
			if (tag[u] == 0 && tag[v] == 0) {
				ql.emplace_back(u, v, id);
			} else if (tag[u] == 1 && tag[v] == 1) {
				qr.emplace_back(u, v, id);
			}
		}
		self(self, vl, ql);
		self(self, vr, qr);
	};
	vector<int> ver(n);
	iota(ver.begin(), ver.end(), 0);
	rec(rec, ver, qs);
	for (int x : res) {
		cout << x << "\n";
	}
	return 0;
}

