void init(int mx)
{
    for(int i=2;i<=mx;i++)
    {
        if(!flag[i]) p[++cnt]=i;
        for(int j=1;j<=cnt&&i*p[j]<=mx;j++)
        {
            flag[i*p[j]]=1;mn[i*p[j]]=p[j];
            if(i%p[j]==0) break;
        }
    }
}
bool check(int n,int k,int lim)
{
    __int128 res=1;
    for(int i=1;i<=k;i++)
    {
        if(lim/res<n-1) return 0;
        res*=n;
        if(res>(__int128)lim) return 0;
    }
    return 1;
}
int search(int b,int lim)
{
    int l=1,r=lim;
    while(l<r)
    {
        int mid=(l+r+1)>>1;
        if(check(mid,b,lim)) l=mid;
        else r=mid-1;
    }
    //cout<<l<<endl;
    return l;
}
