using namespace std;

typedef long long ll;
typedef vector<int> vint;
typedef vector<vint> vvint;

int read() {
	int a = 0, b = 0; char c = getchar();
	while (c < '0' || c > '9') b ^= (c == '-'), c = getchar();
	while (c >= '0' && c <= '9') a = a * 10 - 48 + c, c = getchar();
	return b ? -a : a;
}

const int N = 50005, A = 30005;
int n, k;
int a[N][4];
int b[N * 4];
int MX, MN, ct;

bool chk(int mid) {
	for (int R = 0; R < k - 1; ++R) {
		static vint c[A];
		auto chk = [&]() {
			static int t[N];
			memset(t + 1, 0, n << 2);
			int l = 1, cnt = 0;
			auto add = [&](int k) {
				for (int v : c[k]) cnt += (++t[v]) == 1;
			};
			auto era = [&](int k) {
				for (int v : c[k]) cnt -= (--t[v]) == 0;
			};
			for (int r = 1; r <= ct; ++r) {
				add(r);
				while (b[r] - mid > b[l]) era(l++);
				if (cnt == n) return 1;
			}
			return 0;
		};
		if (k == 3) {
			for (int i = 1; i <= ct; ++i) c[i].clear();
			for (int i = 1; i <= n; ++i) {
				int v[3]; memcpy(v, a[i], 3 << 2);
				for (int r = 0; r < 3; ++r) {
					int u[3] = {v[r], v[(r + 1) % 3], v[(r + 2) % 3]};
					if (MX - mid <= b[u[R]] && b[u[R]] <= MX && MN <= b[u[2]] && b[u[2]] <= MN + mid) {
						c[u[1 - R]].push_back(i);
					}
				}
			}
			if (chk()) return 1;
		} else {
			struct pot {
				int x, y, c;
			};
			vector<pot> d; d.clear(); d.reserve(n * k);
			static int t[N];
			memset(t + 1, 0, n << 2);
			int cnt = 0;
			for (int i = 1; i <= n; ++i) {
				int v[4]; memcpy(v, a[i], 4 << 2);
				for (int r = 0; r < k; ++r) {
					int u[4] = {v[r], v[(r + 1) % k], v[(r + 2) % k], v[(r + 3) % k]};
					if (MX - mid <= b[u[R]] && b[u[R]] <= MX && MN <= b[u[3]] && b[u[3]] <= MN + mid) {
						int x = (R == 0 ? u[1] : u[0]), y = (R == 2 ? u[1] : u[2]);
						d.push_back(pot{x, y, i});
						cnt += (++t[i]) == 1;
					}
				}
			}
			if (cnt != n) continue;
			sort(d.begin(), d.end(), [&](pot a, pot b) { return a.x < b.x; });
			
			for (int i = 1; i <= ct; ++i) c[i].clear();
			cnt = 0; memset(t + 1, 0, n << 2);
			int j = 0;
			for (int i = 0; i < d.size(); ++i) {
				cnt += (++t[d[i].c] == 1), c[d[i].y].push_back(d[i].c);
				while (b[d[i].x] - b[d[j].x] > mid) cnt -= (--t[d[j].c] == 0), c[d[j].y].erase(c[d[j].y].begin()), ++j;
				if (cnt == n && chk()) return 1;
			}
			
		}
	}
	return 0;
}

void sol() {
	n = read();
	for (int i = 0; i < k; ++i) for (int j = 1; j <= n; ++j) a[j][i] = read();
	if (k == 1) {
		int mx = 0, mn = 1e9;
		for (int i = 1; i <= n; ++i) mx = max(mx, a[i][0]), mn = min(mn, a[i][0]);
		cout << mx - mn << '\n';
		return;
	}
	if (k == 2) {
		int x1 = 0, x2 = 0, n1 = 1e9, n2 = 1e9;
		for (int i = 1; i <= n; ++i) {
			int v1 = a[i][0], v2 = a[i][1];
			if (v1 < v2) swap(v1, v2);
			x1 = max(x1, v1), x2 = max(x2, v2);
			n1 = min(n1, v1), n2 = min(n2, v2);
		}
		cout << max(x1 - n1, x2 - n2) << '\n';
		return;
	}
	ct = 0;
	for (int i = 1; i <= n; ++i) for (int j = 0; j < k; ++j) b[++ct] = a[i][j];
	sort(b + 1, b + ct + 1);
	ct = unique(b + 1, b + ct + 1) - b - 1;
	MN = b[1], MX = b[ct];
	for (int i = 1; i <= n; ++i) for (int j = 0; j < k; ++j) a[i][j] = lower_bound(b + 1, b + 1 + ct, a[i][j]) - b;
	int l = 0, r = 30000, mid, ans = -1;
	while (l <= r) {
		mid = (l + r) / 2;
		if (chk(mid)) ans = mid, r = mid - 1;
		else l = mid + 1;
	}
	cout << ans << '\n';
}

int main() {
	int T = read(); k = read();
	while (T--) sol();
	return 0;
}

