int fa[N], sz[N], son[N], dep[N];
int dn, dfn[N], top[N], rev[N];
void dfs1(int id) {
  sz[id] = 1, dep[id] = dep[fa[id]] + 1;
  for(int it : e[id]) {
    dfs1(it), sz[id] += sz[it];
    if(sz[son[id]] < sz[it]) son[id] = it;
  }
}
void dfs2(int id, int tp) {
  dfn[id] = ++dn, rev[dn] = id, top[id] = tp;
  if(son[id]) dfs2(son[id], tp);
  for(int it : e[id]) {
    if(it != son[id]) dfs2(it, it);
  }
}

struct dat {
  int mn, pos;
  dat operator + (const dat &z) const {
    if(mn < z.mn) return *this;
    if(mn > z.mn) return z;
    return {mn, z.pos};
  }
};

struct SegTree {
  int laz[N << 2];
  dat val[N << 2];
  set<pair<int, int>> st[N];
  void build(int l, int r, int x, bool tp) {
    if(l == r) return val[x] = tp ? (dat) {N, 0} : (dat) {sz[rev[l]], rev[l]}, void();
    int m = l + r >> 1;
    build(l, m, x << 1, tp);
    build(m + 1, r, x << 1 | 1, tp);
    val[x] = val[x << 1] + val[x << 1 | 1];
  }
  void tag(int x, int v) {
    laz[x] += v, val[x].mn += v;
  }
  void down(int x) {
    if(laz[x]) {
      tag(x << 1, laz[x]);
      tag(x << 1 | 1, laz[x]);
      laz[x] = 0;
    }
  }
  void modify(int l, int r, int ql, int qr, int x, int v) {
    if(ql <= l && r <= qr) return tag(x, v);
    int m = l + r >> 1;
    down(x);
    if(ql <= m) modify(l, m, ql, qr, x << 1, v);
    if(m < qr) modify(m + 1, r, ql, qr, x << 1 | 1, v);
    val[x] = val[x << 1] + val[x << 1 | 1];
  }
  void modify(int l, int r, int p, int x, auto v) {
    if(l == r) {
      if(v.first < 0) {
        v.first = -v.first;
        st[l].erase(v);
      }
      else st[l].insert(v);
      if(st[l].empty()) val[x] = {N, 0};
      else {
        auto it = st[l].begin();
        val[x] = {it->first, it->second};
      }
      return;
    }
    int m = l + r >> 1;
    if(p <= m) modify(l, m, p, x << 1, v);
    else modify(m + 1, r, p, x << 1 | 1, v);
    val[x] = val[x << 1] + val[x << 1 | 1];
  }
  dat query(int l, int r, int ql, int qr, int x) {
    if(ql <= l && r <= qr) return val[x];
    int m = l + r >> 1;
    dat ans = {N, 0};
    down(x);
    if(ql <= m) ans = ans + query(l, m, ql, qr, x << 1);
    if(m < qr) ans = ans + query(m + 1, r, ql, qr, x << 1 | 1);
    return ans;
  }
} tr1, tr2;

set<pair<int, int>> st[N];
vector<int> buc[N << 2];
void modify(int l, int r, int ql, int qr, int x, int v) {
  if(ql <= l && r <= qr) return buc[x].push_back(v), void();
  int m = l + r >> 1;
  if(ql <= m) modify(l, m, ql, qr, x << 1, v);
  if(m < qr) modify(m + 1, r, ql, qr, x << 1 | 1, v);
}
void solve(int l, int r, int x) {
  auto add = [&](int id, int coe) {
    int x = emp[id].first, val = emp[id].second;
    ans += val * coe;
    tr2.modify(1, n, dfn[x], 1, make_pair(val * coe, id));
    while(x) {
      tr1.modify(1, n, dfn[top[x]], dfn[x], 1, -coe);
      x = fa[top[x]];
    }
  };
  vector<pair<int, int>> op;
  for(int it : buc[x]) {
    add(it, 1);
    int x = emp[it].first, y = -1;
    while(x) {
      dat res = tr1.query(1, n, dfn[top[x]], dfn[x], 1);
      if(res.mn == -1) {
        y = res.pos;
        break;
      }
      x = fa[top[x]];
    }
    if(y == -1) {
      op.push_back({it, -1});
      continue;
    }
    dat res = tr2.query(1, n, dfn[y], dfn[y] + sz[y] - 1, 1);
    int alt = res.pos;
    add(alt, -1), op.push_back({it, alt});
  }
  if(l == r) cout << ans << " ";
  else {
    int m = l + r >> 1;
    solve(l, m, x << 1);
    solve(m + 1, r, x << 1 | 1);
  }
  reverse(op.begin(), op.end());
  for(auto it : op) {
    if(it.second != -1) add(it.second, 1);
    add(it.first, -1);
  }
}

