	inline int get(int x){
		if(s[x].empty()) return 1e9;
		return *(s[x].begin());
	}
	inline void build(int p, int l, int r){
		if(l==r){
			tr[p].mn1=sz[pos[l]]; tr[p].mn2=get(l); tr[p].id=l; tr[p].fr=pos[l];
			return ;
		}
		int mid=(l+r)>>1;
		build(p<<1, l, mid); build(p<<1|1, mid+1, r);
		tr[p].mn1=min(tr[p<<1].mn1, tr[p<<1|1].mn1);
		tr[p].mn2=min(tr[p<<1].mn2, tr[p<<1|1].mn2);
		if(tr[p].mn2==tr[p<<1].mn2) tr[p].fr=tr[p<<1].fr;
		else if(tr[p].mn2==tr[p<<1|1].mn2) tr[p].fr=tr[p<<1|1].fr;
	}
	inline void mem(int d, int p){
		if(!tag[d][p]){
			tag[d][p]=1;
			bin[d][++top[d]]=tr[p];
			idx[d][top[d]]=p;
			if(tr[p].id) _s[d][tr[p].id]=s[tr[p].id];
		}
	}
	inline void push_down(int d, int p){
		if(tr[p].add){
			mem(d, p<<1); mem(d, p<<1|1);
			tr[p<<1].mn1+=tr[p].add;
			tr[p<<1|1].mn1+=tr[p].add;
			tr[p<<1].add+=tr[p].add;
			tr[p<<1|1].add+=tr[p].add;
			tr[p].add=0;
		}
	}
	inline void add1(int d, int p, int l, int r, int L, int R, int v){
		mem(d, p);
		if(L<=l&&r<=R){
			tr[p].mn1+=v;
			tr[p].add+=v;
			return ;
		}
		push_down(d, p);
		int mid=(l+r)>>1;
		if(L<=mid) add1(d, p<<1, l, mid, L, R, v);
		if(R>mid) add1(d, p<<1|1, mid+1, r, L, R, v);
		tr[p].mn1=min(tr[p<<1].mn1, tr[p<<1|1].mn1);
	}
	inline void add2(int d, int p, int l, int r, int x, int v){
		mem(d, p);
		if(l==r){
			s[l].insert(v);
			tr[p].mn2=get(l);
			return ;
		}
		push_down(d, p);
		int mid=(l+r)>>1;
		if(x<=mid) add2(d, p<<1, l, mid, x, v);
		else add2(d, p<<1|1, mid+1, r, x, v);
		tr[p].mn2=min(tr[p<<1].mn2, tr[p<<1|1].mn2);
		if(tr[p].mn2==tr[p<<1].mn2) tr[p].fr=tr[p<<1].fr;
		else if(tr[p].mn2==tr[p<<1|1].mn2) tr[p].fr=tr[p<<1|1].fr;
	}
	inline void del(int d, int p, int l, int r, int x, int v){
		mem(d, p);
		if(l==r){
			s[l].erase(s[l].find(v));
			tr[p].mn2=get(l);
			return ;
		}
		push_down(d, p);
		int mid=(l+r)>>1;
		if(x<=mid) del(d, p<<1, l, mid, x, v);
		else del(d, p<<1|1, mid+1, r, x, v);
		tr[p].mn2=min(tr[p<<1].mn2, tr[p<<1|1].mn2);
		if(tr[p].mn2==tr[p<<1].mn2) tr[p].fr=tr[p<<1].fr;
		else if(tr[p].mn2==tr[p<<1|1].mn2) tr[p].fr=tr[p<<1|1].fr;
	}
	inline pii get2(int p, int l, int r, int L, int R){
		if(L<=l&&r<=R) return mapa(tr[p].mn2, tr[p].fr);
		int mid=(l+r)>>1; pii ret=mapa(1e9, 1e9);
		if(L<=mid) ret=get2(p<<1, l, mid, L, R);
		if(R>mid) ret=min(ret, get2(p<<1|1, mid+1, r, L, R));
		return ret;
	}
	inline int get1(int d, int p, int l, int r, int L, int R){
		mem(d, p);
		if(tr[p].mn1!=0) return 0;
		if(l==r) return pos[l];
		int mid=(l+r)>>1, ret=0;
		push_down(d, p);
		if(L<=l&&r<=R){
			if(tr[p<<1|1].mn1==0) return get1(d, p<<1|1, mid+1, r, L, R);
			else return get1(d, p<<1, l, mid, L, R);
		}
		if(R>mid) ret=get1(d, p<<1|1, mid+1, r, L, R);
		if(!ret&&L<=mid) ret=get1(d, p<<1, l, mid, L, R);
		return ret;
	}
	inline void back(int d){
		while(top[d]){
			int p=idx[d][top[d]];
			tr[p]=bin[d][top[d]];
			if(tr[p].id) s[tr[p].id]=_s[d][tr[p].id], _s[d][tr[p].id].clear();
			tag[d][p]=0;
			--top[d];
		}
	}
