inline int get1_c(int d, int x){
	int ret=0;
	while(x){
		ret=T.get1(d, 1, 1, n, in[top[x]], in[x]);
		if(ret) return ret;
		x=fa[top[x]];
	}
	return 0;
}
inline void add1_c(int d, int x, int v){
	while(x){
		T.add1(d, 1, 1, n, in[top[x]], in[x], v);
		x=fa[top[x]];
	}
}
ll ans;
inline void calc(int d, int p, int l, int r){
	ll _ans=ans;
	for(auto t:vec[p]){
		int cur=get1_c(d, t.fi);
		if(cur){
			pii tem=T.get2(1, 1, n, in[cur], out[cur]);
			if(tem.fi>=t.se) continue;
			ans+=t.se-tem.fi;
			add1_c(d, tem.se, 1);
			add1_c(d, t.fi, -1);
			T.add2(d, 1, 1, n, in[t.fi], t.se);
			T.del(d, 1, 1, n, in[tem.se], tem.fi);
		}
		else{
			ans+=t.se;
			T.add2(d, 1, 1, n, in[t.fi], t.se);
			add1_c(d, t.fi, -1);
		}
	}
	if(l==r){
		printf("%lld ", ans);
		T.back(d);
		ans=_ans;
		return ;
	}
	int mid=(l+r)>>1;
	calc(d+1, p<<1, l, mid);
	calc(d+1, p<<1|1, mid+1, r);
	T.back(d);
	ans=_ans;
}
