		if(a1==b1||a1==b2)a1=0;
	}else{
		if(a1==b1)b1=0;
		if(a1==b2)b2=0;
	}
	if(b1==b2)b1=b2=0;
	if(b1>b2)swap(b1,b2);
	
	if(id[a1][b1][b2][bo])return id[a1][b1][b2][bo];
	int u=id[a1][b1][b2][bo]=newn();
	if(!bo){
		// X move
		if(!a1)return u;
		For(i,0,2){
			int v=move(a1,i);
			if(!v)continue;
			add(u,build(v,b1,b2,1));
		}
		return u;
	}else{
		if(!b1||!b2)return u;
		if(X(a1)==1)return u;
		for(auto t:{b1,b2}){
			if(!t)continue;
			For(i,0,3){
