				if(v==(b1^b2^t))continue;
				add(u,build(a1,v,(b1^b2^t),0));
			}
		}
		return u;
	}
	return u;
}

int q[maxn],hd,tl;
void topo(){
	// g: 1 win 0 lose
	// f: rest steps
	hd=1,tl=0;
	For(i,0,cnt)g[i]=-1,f[i]=inf;
	For(i,1,cnt){
		if(!deg[i]){
			q[++tl]=i;
			g[i]=0,f[i]=0;
		}
	}
	while(hd<=tl){
		int u=q[hd++];
	//	cout<<"lose "<<u<<endl;
		assert(g[u]==0);
		f[u]=0;
		for(int i=head[u];i;i=e[i].nxt) f[u]=max(f[u],f[e[i].to]+1);
		for(int i=head2[u];i;i=e2[i].nxt){ int v=e2[i].to,w;
			if(g[v]==-1){
				f[v]=inf,g[v]=1;
				for(int j=head2[v];j;j=e2[j].nxt)if(g[w=e2[j].to]==-1){
					--deg[w];
					if(!deg[w])g[w]=0,q[++tl]=w;
				}
			}
			g[v]=1,f[v]=min(f[v],f[u]+1);
		}
	}
}

