constexpr int n_MAX=50+5,m_MAX=200+5,mod=998244353;
inline int norm(const int x){return (x<mod)?x:(x-mod);}
inline void add(int &x,const int y){((x+=y)>=mod)&&(x-=mod);}
inline int mul(const int x,const int y){return ((long long)x*y)%mod;}
int n,m,k,a[n_MAX];
int score(const int i,const char col)
{
    int ans=0;
    if(col=='R'||col=='?'){int cnt=0; For(j,1,i-1) if(a[j]>a[i]) ++cnt; ans=(cnt*(m-a[i]+1));}
    if(col=='G'||col=='?'){int cnt=0; For(j,1,i-1) if(a[j]<a[i]) ++cnt; ans=max(ans,cnt*a[i]);}
    return ans;
}
struct atom{bool non_empty; int n,x[n_MAX],y[4]; atom(){memset(this,0,sizeof(atom));}};
int C[m_MAX][m_MAX]; atom F[2][m_MAX][m_MAX]; array<int,6> G[2][m_MAX][m_MAX][2][2];
atom update(const atom &A,const int i,const char col,const bool incl)
{
    atom B; B.non_empty=true,B.n=(A.n+incl); unsigned long long y[4]={A.y[0],A.y[1],A.y[2],A.y[3]};
    For(r,0,A.n)
    {
        if(!A.x[r]) continue; const long long x=A.x[r]; const int if_R=((A.n-r)*(m-a[i]+1)),if_G=(r*a[i]);
        if(col=='R'||(col=='?'&&if_R>=if_G)){add(B.x[r+incl],A.x[r]),y[1]+=(x*if_R); if(incl) y[2]+=(x*C[a[i]+1][2]);}
        else{add(B.x[r],A.x[r]),y[1]+=(x*if_G); if(incl) y[3]+=(x*C[m-a[i]+2][2]);}
    }
    For(i,0,3) B.y[i]=(y[i]%mod); return B;
}
void operator += (atom &A,const atom &B)
{
    if(!B.non_empty) return;
    A.non_empty=true; For(i,0,A.n) add(A.x[i],B.x[i]); For(i,0,3) add(A.y[i],B.y[i]);
}
void convert(const atom &A,array<int,6> &B)
{
    if(!A.non_empty) return;
    For(i,0,3) add(B[i],A.y[i]); For(r,0,A.n) if(A.x[r]) add(B[4],mul(A.x[r],r)),add(B[5],mul(A.x[r],A.n-r));
}
