vector<info> seq;
void pushup(int k)
{
	seq.push_back((info){k,sum[k],cov[k]});
	sum[k]=sum[k<<1]+sum[k<<1|1];
}
void pushtag(int k,int v)
{
	seq.push_back((info){k,sum[k],cov[k]});
	sum[k]=v*len[k];
	cov[k]=v;
}
void pushdown(int k)
{
	if(cov[k]!=-1)
	{
		seq.push_back((info){k,sum[k],cov[k]});
		pushtag(k<<1,cov[k]);
		pushtag(k<<1|1,cov[k]);
		cov[k]=-1;
	}
}
const int Mx = 2e5;
void build(int k,int l,int r)
{
	len[k]=r-l+1;
	sum[k]=0;
	cov[k]=-1;
	if(l==r)return;
	int mid=(l+r)>>1;
	build(k<<1,l,mid);
	build(k<<1|1,mid+1,r);
}
int ask(int k,int l,int r,int L,int R)
{
	if(L<=l&&r<=R) return sum[k];
	pushdown(k);
	int mid=(l+r)>>1;
	int res=0;
	if(L<=mid)res+=ask(k<<1,l,mid,L,R);
	if(R>mid) res+=ask(k<<1|1,mid+1,r,L,R);
	return res;
}
void modify(int k,int l,int r,int L,int R,int v)
{
	if(L<=l&&r<=R)
	{
		pushtag(k,v);
		return;
	}
	int mid=(l+r)>>1;
	if(L<=mid)modify(k<<1,l,mid,L,R,v);
	if(R>mid) modify(k<<1|1,mid+1,r,L,R,v);
	pushup(k);
}
int det[N];
void Upd(int x,int l,int r,int v)
{
	if(l>r) return;
	l-=det[x];r-=det[x];
	modify(S,l,r,v);
}
int Sum(int x,int l,int r)
{
	if(l>r) return 0;
	l-=det[x];r-=det[x];
	return ask(S,l,r);
}
