void get_V(int p,int s){
	int mx=0,sum=0;
	for(int q=0;q<5;q++)
		if (p!=q)mx=max(mx,sa[q]),sum+=sa[q];
	mx=min((sum>>1),sum-mx);
	int l=sa[p]-sum+M,r=l+(mx<<1);
	if (r<0)return;
	if (l<0)s+=(l-1>>1),l&=1;
	V.push_back(Node{p,l,r,s+sum+(l>>1)});
}
void trans(int k){
	V.clear();
	for(int p=0;p<5;p++)
		for(int s=0;s<M;s++){
			if (g[p][s]!=oo){
				int u=s+sa[p],v=0;
				for(int q=0;q<5;q++)
					if (p!=q)u-=sa[q],v+=sa[q];
				if (u>=0)f[k][p][u]=min(f[k][p][u],g[p][s]+v);
			}
			if (g[p][s+M]!=oo){
				sa[p]+=s;
				for(int q=0;q<5;q++)get_V(q,g[p][s+M]);
				sa[p]-=s;
			}
		}
	sort(V.begin(),V.end());
	for(int p=0;p<5;p++)
		for(int s=0;s<(M<<1);s++)fa[p][s]=s;
	for(Node i:V){
		int s=find(i.p,i.r);
		while (s>=i.l){
			f[k][i.p][s]=min(f[k][i.p][s],i.s-(s>>1));
			if (s<2)break;
			fa[i.p][s]=s-2,s=find(i.p,s);
		}
	}
}
