		cost+=sum;
		for(int j=l;j<=r;j+=2)
			if(j>=0 && j<=V*2)
				f[x][j]=min(f[x][j],cost-((j-l)/2));
	};
	For(x,0,4){
		For(i,0,V)if(g[x][i]<inf){
			int now=i+A[x],cost=g[x][i];
			For(y,0,4) if(x!=y) cost+=A[y],now-=A[y];
			if(now>=0) f[x][now]=min(f[x][now],cost);
		}
		For(i,0,V)if(g[x][i+V]<inf){
			A[x]+=i;
			For(y,0,4)get(y,g[x][i+V]);
			A[x]-=i;
		}
	}
}

