    #define len(p) tr[p].len
    #define cnt(p) tr[p].cnt
    struct node {
        int l, r, len, cnt;
    } tr[MAXN<<2];
    void build(int l, int r, int p=1) {
        ll(p)=l, rr(p)=r; len(p)=cnt(p)=0;
        if (l==r) return;
        int mid=(l+r)>>1; build(l,mid,ls(p)); build(mid+1,r,rs(p));
    }

    void change(int l, int r, int c, int p=1) {
        int cl=ll(p), cr=rr(p);
        if (l<=cl && cr<=r) {
            cnt(p)+=c;
            if (cnt(p)) 
                len(p)=(raw[cr+1]-raw[cl]);
            else 
                len(p)=cl==cr?0:len(ls(p))+len(rs(p));
            return;
        }
        int mid=(cl+cr)>>1;

        if (l<=mid) change(l,r,c,ls(p));
        if (r>mid) change(l,r,c,rs(p));

        if (cnt(p)) 
            len(p)=raw[cr+1]-raw[cl];
        else 
            len(p)=len(ls(p))+len(rs(p));
    }

    int get() {
        return tr[1].len;
    }
} sg;

