int check(int u, int v) { // c>d
	int j = 1;
	U (i, 1, v) {
		if (d[i] < c[j]) {
			while (j < u && d[i] < c[j + 1])
				++j;
		} else {
			while (j && d[i] >= c[j])
				--j;
			if (!j)
				return 0;
		}
	}
	return j == u;
}
int solve(int n, int m) {
	if (a[1] < b[1]) swap(a, b), swap(n, m);
	if (a[1] == b[1]) return 0;
	if (a[n] <= b[m]) return 0;

	int ma = max_element(a + 1, a + n + 1) - a,
		mb = min_element(b + 1, b + m + 1) - b;
		
	U (i, 1, ma) c[i] = a[i];
	U (i, 1, mb) d[i] = b[i];
	int f1 = check(ma, mb);
	if (!f1) return 0;
	D (i, n, ma) c[n - i + 1] = a[i];
	D (i, m, mb) d[m - i + 1] = b[i];
	int f2 = check(n - ma + 1, m - mb + 1);
	return f2;
}

int main() {

	int n, m, q; rd(ID, n, m, q);
	int x[N] {}, y[N] {};
	U (i, 1, n) rd(x[i]);
	U (i, 1, m) rd(y[i]);

	memcpy(a, x, sizeof(x)); memcpy(b, y, sizeof(y));
	cout << solve(n, m);
	for (_ = 1; _ <= q; ++_) {
		memcpy(a, x, sizeof(x)); memcpy(b, y, sizeof(y));
		int u, v; rd(u, v);
		while (u--) { int p, z; rd(p, z); a[p] = z; }
		while (v--) { int p, z; rd(p, z); b[p] = z; }
		cout << solve(n, m);
	}
	puts("");
}

