void prepare()
{
	inv[1]=1; For(i,2,m) inv[i]=mul(mod-(mod/i),inv[mod%i]);
	fac[0]=ifac[0]=1; For(i,1,m) fac[i]=mul(fac[i-1],i),ifac[i]=mul(ifac[i-1],inv[i]);
