{
	For_down(i,m,2) add(cur[i],mod-cur[i-2]);
	For(i,n+1,m) add(cur[i],cur[i-(n+1)]);
}
void multiply_G()
{
	vector<int> name;
	if(par=="even") name={(n+1)>>1,(n+2)>>1,n+1};
	else name={n>>1,(n+1)>>1,n};
	For_down(i,m,0) for(const int j:name) if(i>=j) add(cur[i],cur[i-j]);
	For(i,n+1,m) add(cur[i],cur[i-(n+1)]);
	For(i,1,m) add(cur[i],cur[i-1]);
	For_down(i,m,1) add(cur[i],cur[i-1]);
