modint cata_k(int i,int j){
	// split j ()s into i .
	// k multiple of catalan.
	return C(i-1+j*2,j)-C(i-1+j*2,j-1);
}
modint calcF(int i,int j){
	if((i&1)!=(j&1))return 0;
	// (0,0) -> (i,j) sub (0,-2) -> (i,j)
	return C(i,(i+j)/2)-C(i,(i+j)/2+1);
}

int t[maxn],k;
modint dp[maxn];

poly res,tmp;

void solve1(int n){
	tmp=res;
	For(i,0,m)res[i]=0;
	For(i,0,m){
		if(i+((n+1)*2)<=m) tmp[i+((n+1)*2)]+=tmp[i];
		if(i<=m) res[i]+=tmp[i];
		if(i+2<=m) res[i+2]-=tmp[i]+tmp[i];
		if(i+4<=m) res[i+4]+=tmp[i];
	}
}

void solve2(int n){
	tmp=res;
	For(i,0,m)res[i]=-tmp[i];
	For(i,0,m){
		if(i+((n+1)*2)<=m) tmp[i+((n+1)*2)]+=tmp[i];
		res[i]+=tmp[i]+tmp[i];
		if(i+1<=m) res[i+1]+=tmp[i];
		if(i+n<=m) res[i+n]+=tmp[i];
		if(i+n+1<=m) res[i+n+1]+=tmp[i]+tmp[i];
		if(i+n+2<=m) res[i+n+2]+=tmp[i];
		if(i+n+n+1<=m) res[i+n+n+1]+=tmp[i];
	}
}

void Trs(poly&f){
	For(i,0,m-2) f[i+2]+=f[i];
}

