int n,m;
int a[maxn];
vi e[maxn];

int fa[maxn];

int h[maxn];
int L[maxn],R[maxn],que[maxn],idx;
void dfs0(int u){
	L[u]=++idx,que[idx]=u;
	h[u]+=a[u];
	for(int v:e[u]) h[v]=h[u],dfs0(v);
	R[u]=idx;
