int tre[maxn];

set<int>s;

struct node{
	int mx,mn,pre,suf;
	pii res;
	void add(int x){
		if(mx!=-1)mx+=x;
		if(mn!=-1)mn+=x;
		if(pre!=-1)pre+=x;
		if(suf!=-1)suf+=x;
		res.fi+=res.se*x;
	}
};
node t[maxn<<2];
int tag[maxn<<2];
int leaf[maxn<<2];

pii operator +(pii a,pii b){
	return mkp(a.fi+b.fi,a.se+b.se);
}
pii operator -(pii a,pii b){
	return mkp(a.fi-b.fi,a.se-b.se);
}

void pt(int p,int v){
	tag[p]+=v;
	t[p].add(v);
}
void down(int p){
	if(tag[p]) pt(p<<1,tag[p]),pt(p<<1|1,tag[p]),tag[p]=0;
}

pii calc(int p,int mx,int mn,int pre){
//	cout<<"calc "<<p<<" "<<leaf[p]<<" "<<mx<<" "<<mn<<" "<<pre<<"\n";
	node&s=t[p];
	if(s.mx==-1) return mkp(0,0);
	if(s.mn!=mn) {
		if(!(s.mn>mn)) exit(233);
		pre=max(pre,s.mx),mx=max(mx,s.mx);
		return mkp(0,0);
	}
	if(leaf[p]) {
//		cout<<"leaf "<<pre<<" "<<mx<<"\n";
		int u=que[leaf[p]];
		if(pre>=mx) return mkp(pre,1);
		return mkp(0,0);
	}
	
	down(p);
	node&l=t[p<<1],&r=t[p<<1|1];
	if(l.mx==-1) return calc(p<<1|1,mx,mn,pre);
	if(r.mx==-1) return calc(p<<1,mx,mn,pre);
	
	if(l.mn>r.mn){
		pre=max(pre,l.mx),mx=max(mx,l.mx);
		return calc(p<<1|1,mx,mn,pre);
	}
	if(l.mn<r.mn){
		pii res=calc(p<<1,mx,mn,pre);
		return res;
	}
	
	// l.mn==r.mn
//	cout<<"QWQ "<<mx<<" "<<l.mx<<"\n";
//	cout<<"RES "<<t[p].res.fi<<" "<<t[p].res.se<<"\n";
	if(mx<=l.mx) return calc(p<<1,mx,mn,pre)+t[p].res;
	pii ans=calc(p<<1|1,mx,mn,l.suf);
	if(pre>=mx) ans=ans+mkp(pre,1);
	return ans;
}

void up(int p){
	node&s=::t[p],&l=::t[p<<1],&r=::t[p<<1|1];
	if(l.mn==-1) return s=r,void();
	if(r.mn==-1) return s=l,void();
	s.mx=max(l.mx,r.mx);
	s.mn=min(l.mn,r.mn);
	s.pre=l.pre;
	s.suf=r.suf;
	
	if(l.mn>r.mn){
		s.pre=max(s.pre,max(l.mx,r.pre));
	}
	else if(l.mn<r.mn){
		s.suf=max(s.suf,max(r.mx,l.suf));
	}
	else{
		s.res=calc(p<<1|1,l.mx,l.mn,l.suf);
	}
}

void init(node&s,int A,int T){
	if(!A) s.mx=s.mn=T,s.pre=s.suf=-1;
	else s.mx=T,s.mn=T-1,s.pre=-1,s.suf=T;
	s.res=mkp(0,0);
	return;
}
void build(int p,int l,int r){
	if(l==r){
		leaf[p]=l;
	//	cout<<"leaf "<<p<<" "<<l<<"\n";
		int u=que[l];
		tag[p]=h[u];
		init(t[p],a[u],tag[p]);
		return;
	}
	int mid=l+r>>1;
	build(p<<1,l,mid),build(p<<1|1,mid+1,r),up(p);
//	cout<<"p: "<<l<<" "<<r<<"\n";
//	cout<<t[p].mx<<" "<<t[p].mn<<" "<<t[p].pre<<" "<<t[p].suf<<"\n";
//	cout<<t[p].res.fi<<" "<<t[p].res.se<<"\n";
}
void mdf(int p,int l,int r,int x){
	if(l==r){
		int u=que[l];
//		cout<<"tag: "<<p<<" "<<tag[p]<<"\n";
		assert(tag[p]==t[p].mx);
		init(t[p],a[u],tag[p]);
		return;
	}
	int mid=l+r>>1; down(p);
	if(x<=mid)mdf(p<<1,l,mid,x);
	else mdf(p<<1|1,mid+1,r,x); up(p);
//	cout<<"Min "<<l<<" "<<r<<" "<<" "<<t[p].mn<<"\n";
}
void add(int p,int l,int r,int ql,int qr,int v){
	if(l>=ql&&r<=qr)return pt(p,v),void();
	int mid=l+r>>1; down(p);
	if(ql<=mid)add(p<<1,l,mid,ql,qr,v);
	if(qr>mid)add(p<<1|1,mid+1,r,ql,qr,v);
	up(p);
//	cout<<"min "<<l<<" "<<r<<" "<<t[p].mn<<"\n";
}

int mxv,pres,mnv;
pii res;
void ask(int p,int l,int r,int ql,int qr){
	if(t[p].mx==-1) return;
	if(l>=ql&&r<=qr){
//		cout<<"p: "<<l<<" "<<r<<"\n";
//		cout<<"mn&mnv "<<t[p].mn<<" "<<mnv<<"\n";
		if(t[p].mn!=mnv){
			if(!(t[p].mn>mnv)) exit(234);
			mxv=max(mxv,t[p].mx);
			pres=max(pres,t[p].mx);
			return;
		}
		res=res+calc(p,mxv,mnv,pres);
		mxv=max(mxv,t[p].mx);
		pres=t[p].suf;
	//	cout<<"now: "<<res.fi<<" "<<res.se<<" "<<mxv<<" "<<pres<<"\n";
		return;
	}
	int mid=l+r>>1; down(p);
	if(ql<=mid)ask(p<<1,l,mid,ql,qr);
	if(qr>mid)ask(p<<1|1,mid+1,r,ql,qr);
}

int qdep(int p,int l,int r,int x){
	if(l==r) return /*cout<<"mn,mx "<<t[p].mn<<" "<<t[p].mx<<"\n",*/t[p].mn;
	int mid=l+r>>1; down(p);
	if(x<=mid)return qdep(p<<1,l,mid,x);
	return qdep(p<<1|1,mid+1,r,x);
}

void modify(int u){
	a[u]^=1;
	int o=(a[u]?1:-1);
	add(1,1,n,L[u],R[u],o);
	if(a[u])s.insert(L[u]);
	else s.erase(L[u]);
	
	mdf(1,1,n,L[u]);
}

int query(int u){
//	For(i,1,n)cout<<a[i]<<" "; cout<<"\n";
//	cout<<"dep "; For(i,1,n)cout<<qdep(1,1,n,i)<<" "; cout<<"\n";
	int d=qdep(1,1,n,L[u]);
	res=mkp(0,0);
	mxv=-1,mnv=d,pres=-2;
//	cout<<"d; "<<d<<"\n";
	ask(1,1,n,L[u],R[u]);
	if(pres>=mxv) res=res+mkp(pres,1);
	res.fi-=res.se*d;
//	cout<<"ress "<<res.fi<<" "<<res.se<<"\n";
	
	int it=*s.lower_bound(L[u]);
	int cc=tre[it-1]-tre[L[u]-1];
//	cout<<"cc "<<cc<<"\n";
	res.fi+=cc,res.se+=cc;
	
//	cout<<"res "<<res.fi<<" "<<res.se<<"\n";
	
	int ans=res.fi+1-(res.se==1);
	return ans;
}

int mx[maxn];
void dfs00(int u){
	mx[u]=0;
	for(int v:e[u])dfs00(v),mx[u]=max(mx[u],mx[v]);
	mx[u]+=a[u];
}

namespace br{


int dfn[maxn],que[maxn],idx,out[maxn];
	void dfs1(int u){
		que[++idx]=u,dfn[u]=idx;
		for(int v:e[u]) dfs1(v);
		out[u]=idx;
	}
void upd(int u){
	mx[u]-=a[u];
	a[u]^=1;
	mx[u]+=a[u];
//	if(!fl)return;
	for(int x=fa[u];x;x=fa[x]){
//		if(mx[y]+a[x]>mx[x])mx[x]=mx[y]+a[x];
//		else break;
		mx[x]=0;
		for(int v:e[x]) mx[x]=max(mx[x],mx[v]);
		mx[x]+=a[x];
	}
}


struct info{
		int c;
		ll sum;
		info (int x=0,ll y=0){
			c=x,sum=y;
		}
	}tr[maxn<<2];
	
	info operator +(info a,info b){
		return info(a.c+b.c,a.sum+b.sum);
	}
	int mx[maxn<<2];
	bool leaf[maxn<<2];
	info calc(int p,int v){
		if(v>mx[p])return info();
		if(leaf[p]){
			if(mx[p]>=v)return info(1,max(mx[p],1));
			return info();
		}
		if(v>mx[p<<1]) return calc(p<<1|1,v);
		return calc(p<<1,v)+tr[p];
	}
	void up(int p){
		mx[p]=max(mx[p<<1],mx[p<<1|1]);
		tr[p]=calc(p<<1|1,mx[p<<1]);
	}
	int gval(int x){
		x=que[x];
		if(!a[x] && e[x].size()) return -1;
		else return ::mx[x];
	}
	void build(int p,int l,int r){
		if(l==r){
			leaf[p]=1,mx[p]=gval(l);
	//		cout<<"qwq "<<gval(l)<<"\n";
			return;
		}
		int mid=l+r>>1;
		build(p<<1,l,mid);
		build(p<<1|1,mid+1,r);
		up(p);
	}
	void mdf(int p,int l,int r,int x){
		if(l==r)return mx[p]=gval(l),void();
		int mid=l+r>>1;
		if(x<=mid)mdf(p<<1,l,mid,x);
		else mdf(p<<1|1,mid+1,r,x);
		up(p);
	}
	
	info res;
	int nowmx;
	void ask(int p,int l,int r,int ql,int qr){
		if(nowmx>mx[p])return;
		if(l>=ql&&r<=qr){
			res=res+calc(p,nowmx);
			nowmx=max(nowmx,mx[p]);
			return;
		}
		int mid=l+r>>1;
		if(ql<=mid)ask(p<<1,l,mid,ql,qr);
		if(qr>mid)ask(p<<1|1,mid+1,r,ql,qr);
	}
	
	void flsol()
	{
//		info tmp=info();cout<<"tmp "<<tmp.c<<' '<<tmp.sum<<"\n";
		dfs00(1);
		dfs1(1);
		build(1,1,n);
		For(_,1,m){
			int o=read(),u=read();
			if(o==1){
				upd(u);
				int x=u;
				while(x){
					mdf(1,1,n,dfn[x]);
					x=fa[x];
				}
			}
			else {
				res=info();
				nowmx=0;
				ask(1,1,n,dfn[u],out[u]);
		//		For(i,dfn[u],out[u]) cout<<gval(i)<<" "; cout<<" vals\n";
				int out=res.sum;
				if(res.c==1) out--;
				cout<<out+1<<"\n";
			}
		}
	}

}

