template<typename T> inline void chmax(T &a, const T &b){ (b>a) ? (a=b) : a; }
template<typename T> inline void chmin(T &a, const T &b){ (b<a) ? (a=b) : a; }

namespace sa{
	int n;
	int _rnk[2][1500150], sa[1500150], h[1500150], sa_k;
	int qlog[1500150], st[22][1500150];
	int *rnk = _rnk[0], *pre_rnk = _rnk[1];
	inline bool sa_same(int i, int j){
		return pre_rnk[i] == pre_rnk[j] && pre_rnk[i + sa_k] == pre_rnk[j + sa_k];
	}
	void build(string &s){
		static int t[1500150];
		int m = 300;
		n = (int)s.size();
		rep(i, n) ++t[rnk[i] = s[i]];
		rep(i, m) t[i + 1] += t[i];
		for(int i = n-1; i >= 0; --i) sa[--t[rnk[i]]] = i;
		if(m == n) ++m;
		for(int &k = sa_k = 1; m != n; k <<= 1){
			//cout << "----- " << k << " -----" << endl;
			//rep(i, n) cout << sa[i] << " ";
			//cout << endl;
			//rep(i, n) cout << rnk[i] << " ";
			//cout << endl;
			static int ord[1500150]; int cn = 0;
			for(int i = n - k; i < n; ++i) ord[cn++] = i;
			rep(i, n) if(sa[i] >= k) ord[cn++] = sa[i] - k;
			fill(t, t + m + 1, 0);
			rep(i, n) ++t[rnk[i]];
			rep(i, m) t[i + 1] += t[i];
			for(int i = n - 1; i >= 0; --i) sa[--t[rnk[ord[i]]]] = ord[i];
			swap(rnk, pre_rnk);
			m = 0;
			rep(i, n){
				rnk[sa[i]] = m;
				m += (i == n - 1) || !sa_same(sa[i], sa[i + 1]);
			}
		}
		//rep(i, n) cout << sa[i] << " ";
		//cout << endl;
		//rep(i, n) cout << rnk[i] << " ";
		//cout << endl;
		{
			int j = 0;
			rep(i, n){
				if(rnk[i] < n - 1){
					int k = sa[rnk[i] + 1];
					while(i + j < n && k + j < n && s[i + j] == s[k + j]) ++j;
					h[rnk[i]] = j;
				}
				if(j) --j;
			}
		}
		
		for(int i = 2; i <= n; ++i) qlog[i] = qlog[i >> 1] + 1;
		rep(i, n) st[0][i] = h[i];
		rep(i, 21) rep(j, n){
			st[i + 1][j] = st[i][j];
			if(j + (1<<i) < n) chmin(st[i + 1][j], st[i][j + (1<<i)]);
		}
	}

	int qry(int a, int b){
		if(a == b) return inf;
		a = rnk[a], b = rnk[b];
		if(a > b) swap(a, b);
		--b;
		//cout << a << " " << b << endl;
		//for(int i = a; i <= b; ++i) cout << h[i] << " ";
		//cout << endl;
		int lvl = qlog[b - a];
		return min(st[lvl][a], st[lvl][b - (1<<lvl) + 1]);
	}
}

int L, n, m, q;
string s, t[12];
bool can[12][12][50050];
int canst[12][12][50050];

int getr(int id, int x, int l){
	return l + min({L - id, m - l, sa::qry(id, L + x * m + l)});
}

int solve(int id, int x, int l){
	if(s[id] != t[x][l]) return x + l - 1;
	int r = getr(id, x, l);
	int ret = x + r - 1;
	//cout << "solve " << id << " " << x << " " << l << ": " << r << endl;
	int go = 1, lb = l;
	for(int j = 1; x + j < n; ++j){
		lb = canst[x][j][lb];
		//cout << j << ": " << lb << endl;
		if(lb >= r - j) break;
		go |= (can[x][j][r - j - 1] << j);
		//cout << go[j] << endl;
	}
	for(int j = 1; x + j < n; ++j) if((go >> (j-1)) & 3)
		chmax(ret, solve(id + (r - l), x + j, r - j));
	return ret;
}

