bool choose[N];

double myabs(double x)
{
	return (x<0?-x:x);
}

void Gaus()
{
	for(int i=1;i<=n;i++)
	{
		if(myabs(A[i][i])<=eps)
			for(int j=i+1;j<=n;j++)
				if(myabs(A[j][i])>eps)
					swap(A[i],A[j]);
		
		for(int j=1;j<=n;j++)
			if(i!=j && myabs(A[j][i])>eps)
			{
				double v=A[j][i]/A[i][i];
				for(int k=1;k<=n+1;k++)
					A[j][k] -= A[i][k]*v;
			}
	}
}

double calc()
{
