	for(int i=1;i<n;i++)
		if(choose[i])
			A[i][i]=1, A[i][1]=-1;
		else
		{
			int sum=0;
			for(int j=1;j<=n;j++)
				sum += a[i][j];

			for(int j=1;j<=n;j++)
				A[i][j]=(double)a[i][j]/sum;
			A[i][i] -= 1, A[i][n+1]=-1;
		}
	A[n][n]=1;

	Gaus();

	return A[1][n+1]/A[1][1];
}

