			A[i][j]=(double)a[i][j]/sum[i];
		A[i][i] -= 1, A[i][n+1]=-1;
	}
	A[n][n]=1;

	Gaus();

	for(int i=1;i<=n;i++)
		val[i]=A[i][n+1]/A[i][i];

	memset(choose,0,sizeof(choose));
	while(1)
	{
