using namespace std;
int n, a[N][N];
int cho[N], s[N];
db ans, d[N][N], z[N];
bool work()
{
	for(int i = 1; i <= n; i++)
	{
		if(cho[i])
		{
			d[i][1] = 1;
			for(int j = 2; j <= n + 1; j++)d[i][j] = 0;
		}
		else if(i == n)
		{
			for(int j = 1; j <= n + 1; j++)d[i][j] = 0;
		}
		else
		{
			for(int j = 1; j <= n; j++)d[i][j] = 1.0 * a[i][j] / s[i];
			d[i][n + 1] = -1;
		}
		d[i][i] -= 1;
	}
	for(int i=1;i<=n;i++){
	int r=i;
	for(int j=i+1;j<=n;j++)
	    if(fabs(d[r][i])<fabs(d[j][i]))
		r=j;
	if(i!=r)swap(d[i],d[r]);
	double div=d[i][i];
	for(int j=i;j<=n+1;j++)
	    d[i][j]/=div;
	for(int j=i+1;j<=n;j++){
	    div=d[j][i];
	    for(int k=i;k<=n+1;k++)
		d[j][k]-=d[i][k]*div;
	}
	}
	z[n]=d[n][n+1];
	for(int i=n-1;i>=1;i--){
	z[i]=d[i][n+1];
	for(int j=i+1;j<=n;j++)
	    z[i]-=(d[i][j]*z[j]);
	}
	ans = z[1];
	int f = 1;
	for(int i = 2; i < n; i++)
	{
		double tm = 1.0 / (1 - 1.0 * a[i][i] / s[i]);
		for(int j = 1; j <= n; j++)
			if(j != i)tm += 1.0 * a[i][j] / (s[i] - a[i][i]) * z[j];
		if(cho[i] == 1 && tm < z[1] - 1e-13)f = 0;
		if(cho[i] == 0 && tm > z[1] + 1e-13)f = 0;
	}
	for(int i = 2; i < n; i++)
	{
		double tm = 1.0 / (1 - 1.0 * a[i][i] / s[i]);
		for(int j = 1; j <= n; j++)
			if(j != i)tm += 1.0 * a[i][j] / (s[i] - a[i][i]) * z[j];
		if(tm < z[1] - 1e-13)cho[i] = 0;
		else if(tm > z[1] + 1e-13)cho[i] = 1;
		else cho[i] = 2;
	}
	return f;
}
