const int N=205;
const double eps=1e-8;

int a[N][N], yuana[N][N], sum[N], id[N], n;
double A[N][N], val[N], newval[N];
bool choose[N];

inline double myabs(double x)
{
	return (x<0?-x:x);
}

void Gaus()
{
	for(int i=1;i<=n;i++)
	{
		if(myabs(A[i][i])<=eps)
			for(int j=i+1;j<=n;j++)
				if(myabs(A[j][i])>eps)
					swap(A[i],A[j]);
		
		for(int j=1;j<=n;j++)
			if(i!=j && myabs(A[j][i])>eps)
			{
				double v=A[j][i]/A[i][i];
				for(int k=i;k<=n+1;k++)
					A[j][k] -= A[i][k]*v;
			}
	}
}

double calc()
{
	memset(A,0,sizeof(A));

	for(int i=1;i<n;i++)
		if(choose[i])
			A[i][i]=1, A[i][1]=-1;
		else
		{
			int sum=0;
			for(int j=1;j<=n;j++)
				sum += a[i][j];

			for(int j=1;j<=n;j++)
				A[i][j]=(double)a[i][j]/sum;
			A[i][i] -= 1, A[i][n+1]=-1;
		}
	A[n][n]=1;

	Gaus();

	return A[1][n+1]/A[1][1];
}

void work()
{
	n=read();
	memset(sum,0,sizeof(sum));
	for(int i=1;i<=n;i++)
		for(int j=1;j<=n;j++)
