					newval[id[i]] += 1;
				}

				for(register int i=1;i<=cnt;i++)
					val[id[i]]=newval[id[i]], newval[id[i]]=0;
			}
		}
		else if(n<=100)
		{
			for(register int t=1;t<=60;t++)
			{
				for(register int i=1;i<=cnt;i++)
				{
					for(int j=1;j<=cnt;j++)
						newval[id[i]] += A[i][j]*val[id[j]];
					newval[id[i]] += 1;
				}

				for(register int i=1;i<=cnt;i++)
					val[id[i]]=newval[id[i]], newval[id[i]]=0;
			}
		}
		else
		{
			for(register int t=1;t<=6;t++)
