					val[id[i]]=newval[id[i]], newval[id[i]]=0;
			}
		}
	}

	for(int i=1;i<=n;i++)
		for(int j=1;j<=n;j++)
			a[i][j]=yuana[i][j];

	printf("%lf\n",calc());
}

