void dfs(int n,int f) {
	siz[n]=1;m[n]=0;
	siz2[n]=0;
	int su=0;
	for(int i=hd[n];i;i=nxt[i]) {
		if(to[i]==f) continue;
		dfs(to[i],n);
		siz[n]+=siz[to[i]];
		siz2[n]+=siz2[to[i]];
		m[n]=std::max(m[n],m[to[i]]+1);
		su+=2*siz[to[i]];
		su+=2*siz2[to[i]];
	}
	if(m[n]>=K) siz2[n]++;
	dp[n]=0x3f3f3f3f;
