using int64 = long long;
using u64  = unsigned long long;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T;
    if(!(cin >> T)) return 0;
    while (T--) {
        int n;  cin >> n;
        vector<u64> a(n);
        for (int i = 0; i < n; ++i) cin >> a[i];

        /* 去重并排序 */
        sort(a.begin(), a.end());
        a.erase(unique(a.begin(), a.end()), a.end());
        const int m = (int)a.size();
        const u64 M = a.back();

        u64 ans = 0;

        /* 逆序枚举 y */
        for (int idx = m - 1; idx >= 0; --idx) {
            u64 y = a[idx];
            if (y <= ans) break;               // 剪枝

            /* 候选 x₁ = M */
            if (M != y) ans = max(ans, M % y);

            /* mult = 最大 ≤M 的 y 的倍数 */
            u64 mult = (M / y) * y;

            /* 找到严格小于 mult 的最大元素 */
            auto it = lower_bound(a.begin(), a.end(), mult);
            if (it != a.begin()) {
                --it;                          // *it < mult
                u64 x2 = *it;
                if (x2 != y && x2 > y)         // 需保证 x > y
                    ans = max(ans, x2 % y);
            }
        }
        cout << ans << '\n';
    }
    return 0;
}

