void findrt(int u, int fa)
{
    sz[u] = 1; int mx = 0;
    for (auto v : e[u])
        if (v ^ fa) findrt(v, u), sz[u] += sz[v], mx = max(mx, sz[v]);
    mx = max(mx, n - sz[u]);
    if (2 * mx <= n) rt = u;
}
void dfs(int u, int fa) { sz[u] = 1; for (auto v : e[u]) if (v ^ fa) dfs(v, u), sz[u] += sz[v]; }
int st[MAXN], top; bool vis[MAXN];
void get(int u, int fa) { st[++top] = u, vis[u] = 1; for (auto v : e[u]) if (v ^ fa) get(v, u); }
int rst[MAXN], tt;
int find(int u, int fa) { if (e[u].size() > 2) return u; for (auto v : e[u]) if (v ^ fa) return find(v, u); return -1; }

