                if (mx < sz[v]) mx = sz[v], u = v;
            // cout << rt << " " << u << "\n";
            int lmt = min(sz[u], n - sz[u] - 1);
            for (int i = 2 * lmt + 2; i <= 2 * sz[u]; i += 2) fl &= (s[i] == '0');
            for (int i = 2 * sz[u] + 2; i <= n; i += 2) fl &= (s[i] == '1');
            if (!fl) goto NO;
