using namespace std;

const int N = 2e5 + 5;

int n;
char s[N];
int la[N], ne[N * 2], en[N * 2], idx;
int deg[N];
int siz[N];
vector<int> q1, q2;
int p[N];

inline void Add(int a, int b)
{
    ne[ ++ idx] = la[a];
    la[a] = idx;
    en[idx] = b;
    deg[b] ++ ;
}
inline void DFS1(int u, int fa, int &rt, int &ss)
{
    siz[u] = 1;
    int mx = 0;
    for(int i = la[u]; i; i = ne[i])
    {
        int v = en[i];
        if(v != fa)
        {
            DFS1(v, u, rt, ss);
            siz[u] += siz[v];
            mx = max(mx, siz[v]);
        }
    }
    mx = max(mx, n - siz[u]);
    if(mx < ss && deg[u] >= 3)
    {
        rt = u;
        ss = mx;
    }
}
inline void DFS2(int u, int fa, vector<int> &q)
{
    for(int i = la[u]; i; i = ne[i])
    {
        int v = en[i];
        if(v != fa) q.push_back(v);
    }
    for(int i = la[u]; i; i = ne[i])
    {
        int v = en[i];
        if(v != fa) DFS2(v, u, q);
    }
}

inline void Solve()
{
    scanf("%d", &n);
    for(int i = 1; i <= n; i ++ )
    {
        la[i] = deg[i] = 0;
    }
    idx = 0;
    q1.clear(), q2.clear();
    for(int i = 1; i < n; i ++ )
    {
        int a, b;
        scanf("%d%d", &a, &b);
        Add(a, b);
        Add(b, a);
    }
    scanf("%s", s + 1);
    for(int i = 1; i <= n; i ++ ) s[i] ^= 48;

    if(n == 1)
    {
        if(s[1])
        {
            puts("YES\n1");
        }
        else
        {
            puts("NO");
        }
        return ;
    }

    int u = 1, ss = n + 1;
    DFS1(1, 0, u, ss);
    int son = 0;
    for(int i = la[u]; i; i = ne[i])
    {
        int v = en[i];
        if(siz[v] > siz[u]) siz[v] = n - siz[u];
        if(siz[v] > siz[son]) son = v;
    }
    int v = son;
    q1.push_back(v);
    DFS2(v, u, q1);
    q2.push_back(u);
    DFS2(u, v, q2);
    // printf("*%d %d\n", u, v);
    
    for(int i = 1; i <= n; i += 2)
        if(!s[i])
        {
            puts("NO");
            return ;
        }
    if(s[2])
    {
        puts("NO");
        return ;
    }
    p[1] = q1[0], p[2] = q2[0];
    int j = 1, k = 1;
    for(int i = 4; i <= n; i += 2)
    {
        // printf("*%d %d %d\n", i, j, k);
        if(!s[i])
        {
            if(!s[i - 2])
            {
                if(j < (int)q1.size() && k < (int)q2.size())
                {
                    p[i - 1] = q1[j ++ ];
                    p[i] = q2[k ++ ];
                }
                else if(j + 1 < (int)q1.size())
                {
                    p[i - 1] = q1[j ++ ];
                    p[i] = q1[j ++ ];
                }
                else
                {
                    puts("NO");
                    return ;
                }
            }
            else
            {
                if(j + 1 < (int)q1.size())
                {
                    p[i - 1] = q1[j ++ ];
                    p[i] = q1[j ++ ];
                }
                else
                {
                    puts("NO");
                    return ;
                }
            }
        }
        else
        {
            if(s[i - 2])
            {
                if(j < (int)q1.size() && k < (int)q2.size())
                {
                    p[i - 1] = q1[j ++ ];
                    p[i] = q2[k ++ ];
                }
                else if(k + 1 < (int)q2.size())
                {
                    p[i - 1] = q2[k ++ ];
                    p[i] = q2[k ++ ];
                }
                else
                {
                    puts("NO");
                    return ;
                }
            }
            else
            {
                if(k + 1 < (int)q2.size())
                {
                    p[i - 1] = q2[k ++ ];
                    p[i] = q2[k ++ ];
                }
                else
                {
                    puts("NO");
                    return ;
                }
            }
        }
    }
    if(j < (int)q1.size()) p[n] = q1[j];
    if(k < (int)q2.size()) p[n] = q2[k];

    puts("YES");
    for(int i = 1; i <= n; i ++ ) printf("%d ", p[i]);
    puts("");
}

int main()
{
    int T;
    scanf("%d%*d", &T);
    while(T -- ) Solve();
    return 0;
}

