		while (c0<v0.size()&&c1<v1.size()) {
			if (str[c0+c1+2]=='0') {
				if (c0==c1+2) {
					if (c1+1==v1.size()) break;
					ans.pb(v1[c1++]),ans.pb(v1[c1++]);
				}
				else if (c0==c1) ans.pb(v0[c0++]),ans.pb(v1[c1++]);
				else assert(0);
			}
			else {
