int fa[N],dfn[N],seg[N],dfstime,num[N],dep[N],up[N][20];
void pre(ci x,ci f){
	fa[x]=f,seg[dfn[x]=++dfstime]=x,siz[x]=1,dep[x]=dep[f]+1,up[x][0]=f;
	for(int i=1;i<20;++i)up[x][i]=up[up[x][i-1]][i-1];
	for(int y:g[x])if(y!=f)pre(y,x),siz[x]+=siz[y];
