bool In(ci x,ci y){
	return dfn[x]<=dfn[y]&&dfn[y]<dfn[x]+siz[x];
}
int jp(int x,int F){
	if(x==F)return x;
	for(int i=19;~i;--i)if(dep[up[x][i]]>dep[F])x=up[x][i];
	return x;
	// while(fa[x]!=F)x=fa[x];
	// return x;
}
struct BIT{
	int s[N];
	void add(int x,ci v){
		while(x<=n)s[x]+=v,x+=x&-x;
	}
	int qry(int x){
		int ans=0;
		while(x)ans+=s[x],x-=x&-x;
		return ans;
	}
	void Init(){
		for(int i=1;i<=n;++i)s[i]=0;
	}
}B;
int calc(ci x){
	if(!x)return 0;
	return B.qry(dfn[x]+siz[x]-1)-B.qry(dfn[x]-1);
