    int cnt{};
    void pushup(int rt) { tr[rt].tr = tr[tr[rt].lc].tr+tr[tr[rt].rc].tr; }
    void update(int &rt, int l, int r, int k, int c)
    {
        int d = ++cnt;
        tr[d].tr = tr[rt].tr, tr[d].lc = tr[rt].lc, tr[d].rc = tr[rt].rc;
        rt = d;
        tr[rt].tr += c;
        if(l == r) return;
        if(k <= mid) update(tr[rt].lc, l, mid, k, c);
        else update(tr[rt].rc, mid+1, r, k, c);
        pushup(rt);
    }
    ll query(int rt, int l, int r, int L, int R)
    {
        if(L <= l && r <= R) return tr[rt].tr;
        ll ret = 0;
        if(L <= mid) ret = query(tr[rt].lc, l, mid, L, R);
        if(R > mid) ret += query(tr[rt].rc, mid+1, r, L, R);
        return ret;
    }
} tr;
