template<typename T>
struct myque {
    priority_queue<T,vector<T>,greater<T>> a, b;
    void emplace(const T &x) { a.emplace(x); }
    void erase(const T &x) { b.emplace(x); }
    void d() { while(!b.empty() && a.top() == b.top()) a.pop(), b.pop(); }
    decltype(auto) top() { d(); return a.top(); }
    void pop() { d(); a.pop(); }
};
myque<pair<ll,pair<int,int>>> s;
