void emp(int l, int r)
{
    if(l < 1 || r > n*2 || p[l].second == p[r].second) return;
    auto co = calc(l, r)-calc(l+1, r-1);
    s.emplace({co, mkp(l, r)});
}
void era(int l, int r)
{
    if(l < 1 || r > n*2 || p[l].second == p[r].second) return;
    auto co = calc(l, r)-calc(l+1, r-1);
    s.erase({co, mkp(l, r)});
}
