    for(int i = 1; i <= n*2; i++)
    {
        if(p[i].second == 0) q[i] = {nh++, i};
        else q[i] = {--nh, i};
        h[i] = nh;
    }
    sort(q+1, q+n*2+1);
    for(int i = 1; i <= n*2; i++) tr.update(root[-n], 1, n*2, i, (p[i].second? 1: -1)*p[i].first);
    int c = 1;
    for(int i = -n; i <= n; i++)
    {
        root[i+1] = root[i];
        while(c <= n*2 && q[c].first <= i)
        {
            int pos = q[c].second;
            tr.update(root[i+1], 1, n*2, pos, (p[pos].second? -2: 2)*p[pos].first);
            c++;
        }
    }
    for(int i = 0; i <= n*2+1; i++) rem.emplace_hint(rem.end(), i);
    ll ans = 0;
    for(int i = 2; i <= n*2; i++) if(p[i].second != p[i-1].second) emp(i-1, i);
    // return 0;
    for(int t = 1; t <= n; t++)
    {
        auto ch = s.top();
        auto [a, b] = ch.second;
        ans += ch.first;
        int pr = pre(a), nx = nxt(b);
        era(pr, a);
        era(b, nx);
        rem.erase(a);
        rem.erase(b);
        s.pop();
        emp(pr, nx);
        printf("%lld ", ans);
    }
    printf("\n");
    // cerr << calc(1, n*2) << endl;
    return 0;
}

#include<bits/stdc++.h>
#define mod 998244353
using namespace std;
int powdv(int x,int y=mod-2){
	int ans=1;
	while(y){
		if(y&1)ans=1ll*ans*x%mod;
		y>>=1,x=1ll*x*x%mod;
	}
	return ans;
}
int a[8005],di[8005],id[8005],v[8005];
int f[7950][8005],S[8005][8005];
int f1[8005],f2[8005];
int main(){
	int T,O;
	scanf("%d%d",&T,&O);
	while(T--){
		int n,k;
		scanf("%d%d",&n,&k);
		for(int i=0;i<=n;++i)v[i]=0;
		for(int i=1;i<=n;++i)scanf("%d",&a[i]),++v[a[i]];
		int fl=1;
		for(int i=1;i<=n;++i)if(v[i]>=2){
			fl=0;break;
		}
		if(!fl){
			puts("0");continue;
		}
		for(int i=0;i<=n;++i)S[n+1][i]=0;
		for(int i=n;i>=1;--i)for(int j=0;j<=n;++j)
			S[i][j]=S[i+1][j]+(a[i]&&a[i]<=j);
		di[0]=1;
		for(int i=1;i<=n;++i)di[i]=1ll*i*di[i-1]%mod;
		id[n]=powdv(di[n]);
		for(int i=n-1;i>=0;--i)id[i]=1ll*id[i+1]*(i+1)%mod;
		for(int i=0;i<=n;++i)memset(f[i],0,sizeof(f[i]));
		for(int i=1;i<=n;++i)if((a[1]==0&&!v[i])||a[1]==i)f[1][i]=1;
		int ans=0;
		for(int i=0;i<=n;++i)f1[i]=0,f2[i]=0;
		for(int i=1;i<=n;++i){
			for(int p=1;p<=n;++p)if(f1[p]){
				if((f2[p+1]+=f1[p])>=mod)f2[p+1]-=mod;
				if(!a[i])f1[p]=1ll*f1[p]*(p-i+1-S[i+1][p])%mod;
				else f1[p]*=(a[i]<=p);
			}
			int ls=0;
			for(int q=1;q<=n;++q){
				if((ls+=f2[q])>=mod)ls-=mod;
				if((a[i]==0&&!v[q])||a[i]==q){
					if((f[i][q]+=ls)>=mod)f[i][q]-=mod;
				}
				f2[q]=0;
			}
			int cj=1;
			for(int p=i;p<=n;++p){
				if(p<=i+k){
					if((f1[p]+=f[i][p])>=mod)f1[p]-=mod;
				}else{
					f[i][p]=1ll*f[i][p]*cj%mod;
					int j=p-k;
					if(!a[j])cj=1ll*cj*(i+k-j+2-S[j+1][i+k])%mod;
					else cj*=(a[j]<=i+k);
				}
			}
			if(i+k+1<=n){
				int p=i+k+1;long long h=f1[p];
				for(int w=1;w<=i;++w)h+=f[w][p];
				f1[p]=h%mod;
			}
		}
		for(int p=1;p<=n;++p)ans=(ans+f1[p])%mod;
		ans=(ans+mod)%mod;
		printf("%d\n",ans);
	}
	return 0;
}

